import { createHash } from 'node:crypto';
import { hostname, platform, arch, userInfo } from 'node:os';
import type { AccountState } from './types.js';

const DEFAULT_ACCOUNTS_URL = 'https://accounts.optalocal.com';
const CLOUD_KEY_TTL_MS = 5 * 60 * 1000;

type CacheEntry = { value: string; expiresAt: number };
const cloudKeyCache = new Map<string, CacheEntry>();

function accountsBaseUrl(): string {
  const value = process.env['OPTA_ACCOUNTS_URL']?.trim();
  if (!value) return DEFAULT_ACCOUNTS_URL;
  try {
    const parsed = new URL(value);
    return parsed.origin;
  } catch {
    return DEFAULT_ACCOUNTS_URL;
  }
}

function supabaseRestBaseFromProject(project: string): string {
  return `https://${project}.supabase.co/rest/v1`;
}

function authHeaders(token: string): Record<string, string> {
  return {
    Authorization: `Bearer ${token}`,
    apikey: process.env['OPTA_SUPABASE_ANON_KEY'] ?? process.env['NEXT_PUBLIC_SUPABASE_ANON_KEY'] ?? '',
  };
}

function normalizeProvider(provider: string): string {
  return provider.trim().toLowerCase();
}

export interface CloudApiKeyEntry {
  id: string;
  provider: string;
  label: string | null;
  keyValue: string;
  updatedAt: string;
}

/** Fetch all active cloud keys for a provider (or all providers if omitted). */
export async function listCloudApiKeys(
  state: AccountState | null,
  provider?: string,
): Promise<CloudApiKeyEntry[]> {
  const accessToken = state?.session?.access_token?.trim();
  if (!accessToken) return [];

  const url = new URL('/api/keys', accountsBaseUrl());
  if (provider) url.searchParams.set('provider', normalizeProvider(provider));

  try {
    const response = await fetch(url.toString(), {
      method: 'GET',
      headers: authHeaders(accessToken),
    });
    if (!response.ok) return [];
    const payload = (await response.json().catch(() => null)) as
      | { keys?: Array<{ id?: string; provider?: string; label?: string | null; key_value?: string; updated_at?: string }> }
      | null;
    return (payload?.keys ?? [])
      .filter((k) => k.id && k.key_value)
      .map((k) => ({
        id: k.id!,
        provider: k.provider ?? provider ?? '',
        label: k.label ?? null,
        keyValue: k.key_value!,
        updatedAt: k.updated_at ?? '',
      }));
  } catch {
    return [];
  }
}

/**
 * Resolve the best active cloud API key for a provider.
 * Prefers the most-recently updated key (GET /api/keys already sorts by updated_at DESC).
 * Result is cached for CLOUD_KEY_TTL_MS to avoid repeated round-trips.
 */
export async function resolveCloudApiKey(
  state: AccountState | null,
  provider: string,
): Promise<string | null> {
  const accessToken = state?.session?.access_token?.trim();
  const project = state?.project?.trim();
  if (!accessToken || !project) return null;

  const p = normalizeProvider(provider);
  const cacheKey = `${project}:${p}`;
  const cached = cloudKeyCache.get(cacheKey);
  if (cached && cached.expiresAt > Date.now()) return cached.value;

  const keys = await listCloudApiKeys(state, p);
  // GET /api/keys returns active keys sorted by updated_at DESC — first entry is most recent.
  const key = keys[0]?.keyValue?.trim();
  if (!key) return null;

  cloudKeyCache.set(cacheKey, { value: key, expiresAt: Date.now() + CLOUD_KEY_TTL_MS });
  return key;
}

/**
 * Store (or update) an API key in the user's Opta Accounts cloud.
 * Uses POST /api/keys which upserts on (user_id, provider, label) conflict.
 * Returns true on success, false on auth failure or network error.
 */
export async function storeCloudApiKey(
  state: AccountState | null,
  provider: string,
  keyValue: string,
  label = 'default',
): Promise<boolean> {
  const accessToken = state?.session?.access_token?.trim();
  if (!accessToken) return false;

  const url = new URL('/api/keys', accountsBaseUrl());
  try {
    const response = await fetch(url.toString(), {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        ...authHeaders(accessToken),
      },
      body: JSON.stringify({ provider: normalizeProvider(provider), keyValue: keyValue.trim(), label }),
    });
    if (response.ok) {
      // Invalidate cache so the next resolve picks up the new key immediately.
      const project = state?.project?.trim();
      if (project) cloudKeyCache.delete(`${project}:${normalizeProvider(provider)}`);
    }
    return response.ok;
  } catch {
    return false;
  }
}

/**
 * Delete a cloud API key by its UUID.
 * Returns true on success, false on auth failure or network error.
 */
export async function deleteCloudApiKey(
  state: AccountState | null,
  keyId: string,
  provider?: string,
): Promise<boolean> {
  const accessToken = state?.session?.access_token?.trim();
  if (!accessToken) return false;

  const url = new URL(`/api/keys/${encodeURIComponent(keyId)}`, accountsBaseUrl());
  try {
    const response = await fetch(url.toString(), {
      method: 'DELETE',
      headers: authHeaders(accessToken),
    });
    if (response.ok && provider) {
      const project = state?.project?.trim();
      if (project) cloudKeyCache.delete(`${project}:${normalizeProvider(provider)}`);
    }
    return response.ok;
  } catch {
    return false;
  }
}

function buildDeviceFingerprint(userId: string): string {
  const source = [hostname(), platform(), arch(), userInfo().username, userId].join('|');
  return createHash('sha256').update(source).digest('hex');
}

export async function registerCliDevice(state: AccountState): Promise<string | null> {
  const accessToken = state.session?.access_token?.trim();
  const userId = state.user?.id?.trim();
  if (!accessToken || !userId) return null;

  const fingerprintHash = buildDeviceFingerprint(userId);
  const headers = { 'content-type': 'application/json', ...authHeaders(accessToken) };

  // Check if a device with this fingerprint already exists (prevents duplicates
  // when users re-login after deleting account.json).
  try {
    const fpUrl = new URL('/api/devices/fingerprint', accountsBaseUrl());
    fpUrl.searchParams.set('hash', fingerprintHash);
    const fpResponse = await fetch(fpUrl.toString(), { method: 'GET', headers: authHeaders(accessToken) });
    if (fpResponse.ok) {
      const fpBody = (await fpResponse.json().catch(() => null)) as { deviceId?: string | null } | null;
      if (fpBody?.deviceId) return fpBody.deviceId;
    }
  } catch {
    // Fingerprint lookup failed — fall through to registration.
  }

  const url = new URL('/api/devices/register', accountsBaseUrl());
  const payload = {
    platform: platform(),
    deviceLabel: hostname(),
    fingerprintHash,
    trustState: 'trusted',
  };

  try {
    const response = await fetch(url.toString(), {
      method: 'POST',
      headers,
      body: JSON.stringify(payload),
    });
    if (!response.ok) return null;
    const body = (await response.json().catch(() => null)) as { deviceId?: string } | null;
    return body?.deviceId ?? null;
  } catch {
    return null;
  }
}

export async function evaluateCapability(
  state: AccountState | null,
  scope: string,
  deviceId?: string | null,
): Promise<{ allow: boolean; reason?: string }> {
  const accessToken = state?.session?.access_token?.trim();
  if (!accessToken) return { allow: false, reason: 'not_authenticated' };

  const url = new URL('/api/capabilities/evaluate', accountsBaseUrl());
  try {
    const response = await fetch(url.toString(), {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        ...authHeaders(accessToken),
      },
      body: JSON.stringify({ scope, deviceId: deviceId ?? undefined }),
    });

    const payload = (await response.json().catch(() => null)) as { allow?: boolean; reason?: string } | null;
    return {
      allow: Boolean(payload?.allow),
      reason: payload?.reason,
    };
  } catch {
    return { allow: false, reason: 'capability_check_unavailable' };
  }
}

/**
 * Update the `last_seen_at` timestamp for the current CLI session in the cloud.
 *
 * Intended to be called periodically (e.g., every 30 minutes) while the TUI
 * is active, so that cloud-side activity tracking stays current after login.
 * Silently no-ops if the user is unauthenticated or the request fails.
 */
export async function touchSessionRecord(state: AccountState | null): Promise<void> {
  const accessToken = state?.session?.access_token?.trim();
  const userId = state?.user?.id?.trim();
  if (!accessToken || !userId || !state?.project) return;

  const base = supabaseRestBaseFromProject(state.project);
  await fetch(`${base}/accounts_sessions?user_id=eq.${encodeURIComponent(userId)}&session_type=eq.cli`, {
    method: 'PATCH',
    headers: {
      'content-type': 'application/json',
      ...authHeaders(accessToken),
    },
    body: JSON.stringify({ last_seen_at: new Date().toISOString() }),
  }).catch(() => undefined);
}

export async function upsertSessionRecord(
  state: AccountState,
  sessionType: 'cli' | 'web' | 'api' = 'cli',
): Promise<void> {
  const accessToken = state.session?.access_token?.trim();
  const userId = state.user?.id?.trim();
  if (!accessToken || !userId) return;

  const base = supabaseRestBaseFromProject(state.project);
  const now = new Date().toISOString();
  const expiresAt =
    typeof state.session?.expires_at === 'number'
      ? new Date((state.session.expires_at > 10_000_000_000 ? state.session.expires_at : state.session.expires_at * 1000)).toISOString()
      : null;

  await fetch(`${base}/accounts_sessions`, {
    method: 'POST',
    headers: {
      'content-type': 'application/json',
      Prefer: 'resolution=merge-duplicates',
      ...authHeaders(accessToken),
    },
    body: JSON.stringify([
      {
        user_id: userId,
        session_type: sessionType,
        created_at: now,
        last_seen_at: now,
        expires_at: expiresAt,
      },
    ]),
  }).catch(() => undefined);
}

import { loadConfig } from '../../core/config.js';
import { agentLoop } from '../../core/agent.js';
import { computeAutonomyConfigUpdates } from '../../core/autonomy.js';
import { join } from 'node:path';
import { mkdtemp, rm } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import chalk from 'chalk';
import { execa } from 'execa';

export interface CeoBenchTask {
  id: string;
  description: string;
  setupScript?: string;
  verifyScript: string;
}

export interface CeoBenchResult {
  id: string;
  passed: boolean;
  turns: number;
  durationMs: number;
  error?: string;
}

const DEFAULT_TASKS: CeoBenchTask[] = [
  {
    id: 'math-function',
    description: 'Create a file named math.js that exports a function `add(a, b)` that returns the sum of a and b.',
    verifyScript: `node -e "const { add } = require('./math.js'); if (add(2, 3) !== 5) process.exit(1);"`
  },
  {
    id: 'failing-test',
    description: 'There is a failing test in test.js. Fix the bug in target.js so the test passes.',
    setupScript: `
      echo "module.exports = { multiply: (a, b) => a + b };" > target.js
      echo "const { multiply } = require('./target.js'); if (multiply(3, 4) !== 12) process.exit(1);" > test.js
    `,
    verifyScript: 'node test.js'
  }
];

function applyDotPathUpdate(target: Record<string, unknown>, key: string, value: unknown): void {
  const segments = key.split('.').filter(Boolean);
  if (segments.length === 0) return;

  let cursor: Record<string, unknown> = target;
  for (let i = 0; i < segments.length - 1; i += 1) {
    const segment = segments[i]!;
    const next = cursor[segment];
    if (!next || typeof next !== 'object' || Array.isArray(next)) {
      const replacement: Record<string, unknown> = {};
      cursor[segment] = replacement;
      cursor = replacement;
      continue;
    }
    cursor = next as Record<string, unknown>;
  }

  cursor[segments[segments.length - 1]!] = value;
}

export async function runCeoBenchmark(
  options: { filter?: string; model?: string; json?: boolean }
): Promise<void> {
  const config = await loadConfig();

  // Force CEO mode config
  const ceoUpdates = computeAutonomyConfigUpdates(5, 'ceo');
  for (const [key, value] of Object.entries(ceoUpdates)) {
    applyDotPathUpdate(config as unknown as Record<string, unknown>, key, value);
  }
  // Ensure we can auto-write
  config.defaultMode = 'dangerous';
  config.autonomy.headlessContinue = true;

  const modelId = options.model ?? config.model.default;
  if (!modelId) {
    throw new Error('No model specified and no default model set.');
  }
  config.model.default = modelId;

  const tasks = options.filter 
    ? DEFAULT_TASKS.filter(t => t.id.includes(options.filter!))
    : DEFAULT_TASKS;

  if (!options.json) {
    console.log(chalk.bold(`
Starting CEO Autonomy Benchmark`));
    console.log(chalk.dim(`Model: ${modelId}`));
    console.log(chalk.dim(`Tasks: ${tasks.length}
`));
  }

  const results: CeoBenchResult[] = [];
  const originalCwd = process.cwd();

  for (const task of tasks) {
    if (!options.json) console.log(chalk.cyan(`Running task: ${task.id}`));
    const startMs = Date.now();
    let passed = false;
    let turns = 0;
    let error: string | undefined;

    const testDir = await mkdtemp(join(tmpdir(), `opta-ceo-bench-${task.id}-`));
    process.chdir(testDir);

    try {
      if (task.setupScript) {
        await execa('bash', ['-c', task.setupScript]);
      }

      // We give the agent a system prompt telling it to solve the task and verify.
      const prompt = `You are in a CEO benchmark test environment.
Your task: ${task.description}

Once you believe you have completed the task, you MUST run this verification script to ensure it works:
\`\`\`bash
${task.verifyScript}
\`\`\`

If the script fails, keep iterating until it passes. Do not stop until the script exits with 0.`;

      const result = await agentLoop(prompt, config, {
        sessionId: `bench-${task.id}`,
        silent: false
      });

      turns = result.toolCallCount;

      // Final verification
      try {
        await execa('bash', ['-c', task.verifyScript]);
        passed = true;
      } catch {
        passed = false;
        error = 'Verification script failed after agent completion.';
      }

    } catch (err) {
      passed = false;
      error = err instanceof Error ? err.message : String(err);
    } finally {
      process.chdir(originalCwd);
      try { await rm(testDir, { recursive: true, force: true }); } catch {}
    }

    const durationMs = Date.now() - startMs;
    results.push({ id: task.id, passed, turns, durationMs, error });

    if (!options.json) {
      if (passed) {
        console.log(chalk.green(`  ✓ Passed in ${turns} turns (${(durationMs / 1000).toFixed(1)}s)`));
      } else {
        console.log(chalk.red(`  ✗ Failed in ${turns} turns (${(durationMs / 1000).toFixed(1)}s)`));
        if (error) console.log(chalk.dim(`    Error: ${error}`));
      }
    }
  }

  if (options.json) {
    console.log(JSON.stringify(results, null, 2));
  } else {
    const passedCount = results.filter(r => r.passed).length;
    console.log(chalk.bold(`
Benchmark Complete: ${passedCount}/${results.length} passed`));
  }
}

import {
  readLatestBrowserRunCorpusSummary,
  type BrowserRunCorpusSummary,
} from './run-corpus.js';
import { clamp } from '../utils/common.js';

export interface BrowserAdaptationConfig {
  enabled: boolean;
  minAssessedSessions: number;
  regressionPressureThreshold: number;
  meanRegressionScoreThreshold: number;
  failureRateThreshold: number;
  investigateWeight: number;
  intentRoutePenalty: number;
  /** Additional pressure contribution per session that involved high-risk MCP tools and had failures. Default: 0.5 */
  highRiskMcpWeight: number;
}

export interface BrowserPolicyAdaptationHint {
  escalateRisk: boolean;
  reason?: string;
  regressionPressure: number;
  meanRegressionScore: number;
  failureRate: number;
}

export interface BrowserIntentAdaptationHint {
  routePenalty: number;
  reason?: string;
  regressionPressure: number;
  meanRegressionScore: number;
  failureRate: number;
}

export interface BrowserRunCorpusAdaptationHint {
  enabled: boolean;
  source: 'disabled' | 'run-corpus';
  generatedAt?: string;
  assessedSessionCount: number;
  regressionPressure: number;
  meanRegressionScore: number;
  maxRegressionScore: number;
  failureRate: number;
  intent: BrowserIntentAdaptationHint;
  policy: BrowserPolicyAdaptationHint;
  rationale: string[];
}

/**
 * MCP-only tool names that carry elevated intrinsic risk in the adaptation
 * signal vocabulary. Sessions containing these tools contribute additional
 * weight to the high-risk adaptation signal during corpus scoring.
 *
 * - browser_evaluate: arbitrary JS execution — can exfiltrate data or mutate DOM
 * - browser_file_upload: filesystem access — interacts with local files
 */
export const MCP_HIGH_RISK_TOOL_NAMES: ReadonlySet<string> = new Set([
  'browser_evaluate',
  'browser_file_upload',
]);

/**
 * MCP-only tool names that carry medium intrinsic risk.
 * These tools interact with page state in ways that may have side-effects
 * (form submission, drag operations, keyboard input) but do not directly
 * access the filesystem or execute arbitrary code.
 */
export const MCP_MEDIUM_RISK_TOOL_NAMES: ReadonlySet<string> = new Set([
  'browser_select_option',
  'browser_drag',
  'browser_press_key',
  'browser_keyboard_type',
]);

/** Returns true if `toolName` is a high-risk MCP-only browser tool. */
export function isMcpHighRiskTool(toolName: string): boolean {
  return MCP_HIGH_RISK_TOOL_NAMES.has(toolName);
}

/** Returns true if `toolName` is a medium-risk MCP-only browser tool. */
export function isMcpMediumRiskTool(toolName: string): boolean {
  return MCP_MEDIUM_RISK_TOOL_NAMES.has(toolName);
}

export const DEFAULT_BROWSER_ADAPTATION_CONFIG: BrowserAdaptationConfig = {
  enabled: false,
  minAssessedSessions: 3,
  regressionPressureThreshold: 0.35,
  meanRegressionScoreThreshold: 0.25,
  failureRateThreshold: 0.2,
  investigateWeight: 0.5,
  intentRoutePenalty: 2,
  highRiskMcpWeight: 0.5,
};

function normalizedRatio(value: number): number {
  if (!Number.isFinite(value)) return 0;
  return Number(clamp(value, 0, 1).toFixed(4));
}

function toSafeNumber(value: number): number {
  return Number.isFinite(value) ? value : 0;
}

function aggregateFailureRate(summary: BrowserRunCorpusSummary | null): number {
  if (!summary || summary.entries.length === 0) return 0;
  const totals = summary.entries.reduce(
    (state, entry) => {
      state.actions += Math.max(entry.actionCount, 0);
      state.failures += Math.max(entry.failureCount, 0);
      return state;
    },
    { actions: 0, failures: 0 },
  );

  if (totals.actions <= 0) return 0;
  return normalizedRatio(totals.failures / totals.actions);
}

export function normalizeBrowserAdaptationConfig(
  input: Partial<BrowserAdaptationConfig> | undefined,
): BrowserAdaptationConfig {
  const fallback = DEFAULT_BROWSER_ADAPTATION_CONFIG;
  return {
    enabled: input?.enabled === true,
    minAssessedSessions: Math.max(1, Math.floor(input?.minAssessedSessions ?? fallback.minAssessedSessions)),
    regressionPressureThreshold: normalizedRatio(input?.regressionPressureThreshold ?? fallback.regressionPressureThreshold),
    meanRegressionScoreThreshold: normalizedRatio(input?.meanRegressionScoreThreshold ?? fallback.meanRegressionScoreThreshold),
    failureRateThreshold: normalizedRatio(input?.failureRateThreshold ?? fallback.failureRateThreshold),
    investigateWeight: normalizedRatio(input?.investigateWeight ?? fallback.investigateWeight),
    intentRoutePenalty: Math.max(0, Math.floor(input?.intentRoutePenalty ?? fallback.intentRoutePenalty)),
    highRiskMcpWeight: normalizedRatio(input?.highRiskMcpWeight ?? fallback.highRiskMcpWeight),
  };
}

export function deriveBrowserRunCorpusAdaptationHint(
  summary: BrowserRunCorpusSummary | null,
  configInput: Partial<BrowserAdaptationConfig> | undefined,
): BrowserRunCorpusAdaptationHint {
  const config = normalizeBrowserAdaptationConfig(configInput);

  const assessedSessionCount = summary?.assessedSessionCount ?? 0;
  const highRiskFailureSessions = (summary?.entries ?? [])
    .filter((e) => e.highRiskMcpToolsPresent && (e.failureCount ?? 0) > 0)
    .length;
  const regressionPressure = assessedSessionCount > 0
    ? normalizedRatio(
      (
        (summary?.regressionSessionCount ?? 0)
        + ((summary?.investigateSessionCount ?? 0) * config.investigateWeight)
        + (highRiskFailureSessions * config.highRiskMcpWeight)
      )
      / assessedSessionCount,
    )
    : 0;
  const meanRegressionScore = normalizedRatio(toSafeNumber(summary?.meanRegressionScore ?? 0));
  const maxRegressionScore = normalizedRatio(toSafeNumber(summary?.maxRegressionScore ?? 0));
  const failureRate = aggregateFailureRate(summary);

  if (!config.enabled) {
    return {
      enabled: false,
      source: 'disabled',
      assessedSessionCount,
      generatedAt: summary?.generatedAt,
      regressionPressure,
      meanRegressionScore,
      maxRegressionScore,
      failureRate,
      intent: {
        routePenalty: 0,
        regressionPressure,
        meanRegressionScore,
        failureRate,
      },
      policy: {
        escalateRisk: false,
        regressionPressure,
        meanRegressionScore,
        failureRate,
      },
      rationale: ['browser.adaptation.enabled=false'],
    };
  }

  const enoughSamples = assessedSessionCount >= config.minAssessedSessions;
  const pressureExceeded = regressionPressure >= config.regressionPressureThreshold;
  const meanExceeded = meanRegressionScore >= config.meanRegressionScoreThreshold;
  const failureExceeded = failureRate >= config.failureRateThreshold;
  const escalate = enoughSamples && (pressureExceeded || meanExceeded || failureExceeded);
  const reasonParts: string[] = [
    `assessed=${assessedSessionCount}`,
    `regressionPressure=${regressionPressure.toFixed(4)}>=${config.regressionPressureThreshold.toFixed(4)}:${String(pressureExceeded)}`,
    `meanRegressionScore=${meanRegressionScore.toFixed(4)}>=${config.meanRegressionScoreThreshold.toFixed(4)}:${String(meanExceeded)}`,
    `failureRate=${failureRate.toFixed(4)}>=${config.failureRateThreshold.toFixed(4)}:${String(failureExceeded)}`,
    `minAssessedSessions=${config.minAssessedSessions}:${String(enoughSamples)}`,
  ];

  const reason = `run-corpus adaptation (${reasonParts.join('; ')})`;

  return {
    enabled: true,
    source: 'run-corpus',
    generatedAt: summary?.generatedAt,
    assessedSessionCount,
    regressionPressure,
    meanRegressionScore,
    maxRegressionScore,
    failureRate,
    intent: {
      routePenalty: escalate ? config.intentRoutePenalty : 0,
      reason: escalate ? reason : undefined,
      regressionPressure,
      meanRegressionScore,
      failureRate,
    },
    policy: {
      escalateRisk: escalate,
      reason: escalate ? reason : undefined,
      regressionPressure,
      meanRegressionScore,
      failureRate,
    },
    rationale: reasonParts,
  };
}

export async function loadBrowserRunCorpusAdaptationHint(
  cwd: string,
  configInput: Partial<BrowserAdaptationConfig> | undefined,
): Promise<BrowserRunCorpusAdaptationHint> {
  const summary = await readLatestBrowserRunCorpusSummary(cwd);
  return deriveBrowserRunCorpusAdaptationHint(summary, configInput);
}

import type { BrowserIntentAdaptationHint } from './adaptation.js';
import { clamp } from '../utils/common.js';

export type BrowserIntentConfidence = 'low' | 'medium' | 'high';

export interface BrowserIntentDecision {
  shouldRoute: boolean;
  confidence: BrowserIntentConfidence;
  confidenceScore?: number;
  reason: string;
  rationale?: string;
  signals: string[];
  suggestedUrl?: string;
  adaptationPenalty?: number;
  adaptationReason?: string;
}

const URL_PATTERN = /\bhttps?:\/\/[^\s<>"'`)]+/gi;

const STRONG_SIGNALS = [
  'open website',
  'open this site',
  'browser',
  'web page',
  'website',
  'navigate',
  'fill form',
  'submit form',
  'click',
  'screenshot',
  'login',
  'sign in',
  'checkout',
];

const WEAK_SIGNALS = [
  'scrape',
  'crawl',
  'web',
  'url',
  'search online',
  'online',
  'dashboard',
];

const LOCAL_ONLY_SIGNALS = [
  'refactor',
  'unit test',
  'typecheck',
  'tsconfig',
  'eslint',
  'local file',
  'repository',
  'git',
];

const ROUTE_SCORE_THRESHOLD = 3;
const HIGH_CONFIDENCE_SCORE_THRESHOLD = 6;
const NORMALIZED_SCORE_MIN = -4;
const NORMALIZED_SCORE_MAX = 8;

function firstUrl(task: string): string | undefined {
  const match = task.match(URL_PATTERN);
  if (!match || match.length === 0) return undefined;
  return match[0]?.replace(/[),.;:!?]+$/, '');
}

function includesSignal(taskLower: string, signal: string): boolean {
  return taskLower.includes(signal);
}

function normalizeConfidenceScore(score: number): number {
  const normalized = (score - NORMALIZED_SCORE_MIN) / (NORMALIZED_SCORE_MAX - NORMALIZED_SCORE_MIN);
  return Number(clamp(normalized, 0, 1).toFixed(2));
}

function stableSignals(signals: string[]): string[] {
  return [...new Set(signals)].sort((a, b) => a.localeCompare(b));
}

export function routeBrowserIntent(
  task: string,
  options: {
    adaptationHint?: BrowserIntentAdaptationHint;
  } = {},
): BrowserIntentDecision {
  const normalized = task.trim();
  const adaptationPenalty = Math.max(0, Math.floor(options.adaptationHint?.routePenalty ?? 0));
  const adaptationReason = options.adaptationHint?.reason;

  if (!normalized) {
    return {
      shouldRoute: false,
      confidence: 'low',
      confidenceScore: 0,
      reason: 'Empty task did not contain browser intent.',
      rationale: `route=false; score=0; threshold=${ROUTE_SCORE_THRESHOLD}; positive=0; negative=0; adaptation_penalty=${adaptationPenalty}; matched=none`,
      signals: [],
      adaptationPenalty,
      adaptationReason,
    };
  }

  const lower = normalized.toLowerCase();
  const positiveSignals: string[] = [];
  const negativeSignals: string[] = [];
  let positiveScore = 0;
  let negativeScore = 0;

  const suggestedUrl = firstUrl(normalized);
  if (suggestedUrl) {
    positiveSignals.push('explicit:url');
    positiveScore += 3;
  }

  for (const signal of STRONG_SIGNALS) {
    if (includesSignal(lower, signal)) {
      positiveSignals.push(`strong:${signal}`);
      positiveScore += 2;
    }
  }

  for (const signal of WEAK_SIGNALS) {
    if (includesSignal(lower, signal)) {
      positiveSignals.push(`weak:${signal}`);
      positiveScore += 1;
    }
  }

  for (const signal of LOCAL_ONLY_SIGNALS) {
    if (includesSignal(lower, signal)) {
      negativeSignals.push(`local:${signal}`);
      negativeScore += 1;
    }
  }

  if (adaptationPenalty > 0) {
    negativeSignals.push('adaptive:route-penalty');
    negativeScore += adaptationPenalty;
  }

  const score = positiveScore - negativeScore;
  const shouldRoute = score >= ROUTE_SCORE_THRESHOLD;
  const confidenceScore = normalizeConfidenceScore(score);
  const signals = stableSignals([...positiveSignals, ...negativeSignals]);
  const rationale = [
    `route=${shouldRoute}`,
    `score=${score}`,
    `threshold=${ROUTE_SCORE_THRESHOLD}`,
    `positive=${positiveScore}`,
    `negative=${negativeScore}`,
    `adaptation_penalty=${adaptationPenalty}`,
    `matched=${signals.join('|') || 'none'}`,
  ].join('; ');

  let confidence: BrowserIntentConfidence = 'low';
  if (shouldRoute && (score >= HIGH_CONFIDENCE_SCORE_THRESHOLD || confidenceScore >= 0.8)) {
    confidence = 'high';
  } else if (shouldRoute) {
    confidence = 'medium';
  }

  return {
    shouldRoute,
    confidence,
    confidenceScore,
    reason: shouldRoute
      ? `Intent router matched browser workflow signals with score ${score} (threshold ${ROUTE_SCORE_THRESHOLD}).`
      : `Intent router did not meet browser routing threshold (score ${score}, threshold ${ROUTE_SCORE_THRESHOLD}).`,
    rationale,
    signals,
    suggestedUrl,
    adaptationPenalty,
    adaptationReason,
  };
}

/**
 * Returns a brief system-prompt injection informing the agent which browser tools are available.
 * Returns null when the request is not browser-related and MCP is not enabled.
 */
export function buildBrowserAvailabilityInstruction(
  explicitRequest: boolean,
  mcpEnabled: boolean = false,
): string | null {
  if (!explicitRequest && !mcpEnabled) return null;

  const toolList = mcpEnabled
    ? 'browser_navigate, browser_click, browser_type, browser_select_option, browser_hover, browser_scroll, browser_snapshot, browser_screenshot, browser_evaluate, browser_go_back, browser_go_forward, browser_tab_new, browser_press_key, browser_handle_dialog, browser_wait_for_element'
    : 'browser_open, browser_navigate, browser_click, browser_type, browser_snapshot, browser_screenshot, browser_close';

  return `### Browser Tools Available\n\nUse ${toolList} for browser automation tasks. Always snapshot first to understand page state.`;
}

export function buildBrowserRoutingInstruction(
  decision: BrowserIntentDecision,
  sessionId?: string,
): string {
  if (!decision.shouldRoute) return '';

  const lines: string[] = [
    '### Browser Auto-Routing',
    `Detected browser-capable intent (${decision.confidence} confidence${typeof decision.confidenceScore === 'number' ? `, score ${decision.confidenceScore.toFixed(2)}` : ''}). ${decision.reason}`,
    'Prefer browser tools for web interaction steps in this task.',
  ];

  if (decision.rationale) {
    lines.push(`Routing rationale: ${decision.rationale}`);
  }

  if (decision.adaptationReason) {
    lines.push(`Routing adaptation: ${decision.adaptationReason}`);
  }

  if (sessionId) {
    lines.push(
      `Use browser session_id "${sessionId}" for browser_navigate/browser_click/browser_type/browser_snapshot/browser_screenshot.`,
    );
  } else {
    lines.push('Open a browser session first with browser_open before browser interactions.');
  }

  lines.push('Policy reminder: blocked hosts are denied and high-risk actions require approval.');
  return lines.join('\n');
}

