  async snapshot(
    sessionId: string,
    options?: NativeSessionActionOptions,
  ): Promise<BrowserActionResult<BrowserSnapshotData>> {
    const action = this.createAction(sessionId, 'snapshot', {});
    const managed = this.sessions.get(sessionId);
    if (!managed) {
      return this.fail(action, 'SESSION_NOT_FOUND', `Browser session "${sessionId}" was not found.`);
    }

    const gate = this.ensurePage(managed);
    if (gate) {
      await this.recordAction(managed, action, false, gate);
      await this.persist(managed);
      return { ok: false, action, error: gate };
    }

    try {
      const html = await this.withActionSignal(managed, options, async () => managed.page!.content());
      const artifact = await this.createArtifact(managed, action.id, 'snapshot', 'html', 'text/html', html);
      managed.session.updatedAt = this.timestamp();
      await this.recordAction(managed, action, true, undefined, artifact);
      await this.persist(managed);
      return {
        ok: true,
        action,
        data: {
          html,
          artifact,
        },
      };
    } catch (err) {
      const error = this.isAbortError(err)
        ? this.error('ACTION_CANCELLED', ACTION_CANCELLED_MESSAGE)
        : this.error('SNAPSHOT_FAILED', `Snapshot failed: ${errorMessage(err)}`);
      managed.session.updatedAt = this.timestamp();
      await this.recordAction(managed, action, false, error);
      await this.persist(managed);
      return { ok: false, action, error };
    }
  }

  async screenshot(
    sessionId: string,
    input: BrowserScreenshotInput = {},
    options?: NativeSessionActionOptions,
  ): Promise<BrowserActionResult<BrowserScreenshotData>> {
    const action = this.createAction(sessionId, 'screenshot', input as Record<string, unknown>);
    const managed = this.sessions.get(sessionId);
    if (!managed) {
      return this.fail(action, 'SESSION_NOT_FOUND', `Browser session "${sessionId}" was not found.`);
    }

    const gate = this.ensurePage(managed);
    if (gate) {
      await this.recordAction(managed, action, false, gate);
      await this.persist(managed);
      return { ok: false, action, error: gate };
    }

    try {
      const type = input.type ?? 'png';
      const screenshotOptions: Record<string, unknown> = {
        fullPage: input.fullPage ?? true,
        type,
      };

      if (typeof input.quality === 'number') {
        screenshotOptions.quality = input.quality;
      }

      const image = await this.withActionSignal(managed, options, async () =>
        managed.page!.screenshot(screenshotOptions));
      const artifact = await this.createArtifact(
        managed,
        action.id,
        'screenshot',
        type === 'jpeg' ? 'jpg' : 'png',
        type === 'jpeg' ? 'image/jpeg' : 'image/png',
        image,
      );

      managed.session.updatedAt = this.timestamp();
      await this.recordAction(managed, action, true, undefined, artifact);
      await this.persist(managed);

      return {
        ok: true,
        action,
        data: {
          artifact,
        },
      };
    } catch (err) {
      const error = this.isAbortError(err)
        ? this.error('ACTION_CANCELLED', ACTION_CANCELLED_MESSAGE)
        : this.error('SCREENSHOT_FAILED', `Screenshot failed: ${errorMessage(err)}`);
      managed.session.updatedAt = this.timestamp();
      await this.recordAction(managed, action, false, error);
      await this.persist(managed);
      return { ok: false, action, error };
    }
  }

  private async openRuntimeSession(
    runtime: PlaywrightRuntimeLike,
    mode: BrowserOpenSessionInput['mode'],
    wsEndpoint: string | undefined,
    headless: boolean,
    profileDir: string | undefined,
  ): Promise<{
    browser?: PlaywrightBrowserLike;
    context: PlaywrightContextLike;
    page: PlaywrightPageLike;
  }> {
    if (mode === 'attach') {
      if (!wsEndpoint) {
        throw new Error('Attach mode requires wsEndpoint.');
      }
      const normalizedEndpoint = normalizeAttachWsEndpoint(wsEndpoint);
      const browser = await runtime.chromium.connectOverCDP(normalizedEndpoint);
      const context = browser.contexts()[0] ?? await browser.newContext();

      await this.injectChromeOverlay(context);

      const page = context.pages()[0] ?? await context.newPage();
      return { browser, context, page };
    }

    if (profileDir && typeof runtime.chromium.launchPersistentContext === 'function') {
      const context = await runtime.chromium.launchPersistentContext(profileDir, { headless });

      await this.injectChromeOverlay(context);

      const page = context.pages()[0] ?? await context.newPage();
      return { context, page };
    }

    const browser = await runtime.chromium.launch({ headless });
    const context = await browser.newContext();

    await this.injectChromeOverlay(context);

    const page = await context.newPage();
    return { browser, context, page };
  }

  private async injectChromeOverlay(context: PlaywrightContextLike): Promise<void> {
    try {
      const overlayPath = join(__dirname, 'chrome-overlay.js'); // Assuming transpile output
      await context.addInitScript({ path: overlayPath });
    } catch {
      // Best effort fallback if running uncompiled (development)
      try {
        const overlayPathTs = join(__dirname, 'chrome-overlay.ts');
        await context.addInitScript({ path: overlayPathTs });
      } catch {
        // Silently fail if overlay injection fails so we don't block the browser
      }
    }
  }

  private ensurePage(managed: ManagedSession): BrowserActionError | null {
    if (managed.session.status !== 'open') {
      return this.error('SESSION_CLOSED', `Browser session "${managed.session.id}" is closed.`);
    }

    if (!managed.page || managed.session.runtime !== 'playwright') {
      return { ...PLAYWRIGHT_UNAVAILABLE_ERROR };
    }

    return null;
  }

  private async createArtifact(
    managed: ManagedSession,
    actionId: string,
    kind: 'snapshot' | 'screenshot',
    extension: string,
    mimeType: string,
    content: string | Uint8Array,
  ): Promise<BrowserArtifactMetadata> {
    managed.artifactSequence += 1;

    return writeBrowserArtifact({
      cwd: this.cwd,
      sessionId: managed.session.id,
      actionId,
      sequence: managed.artifactSequence,
      kind,
      extension,
      mimeType,
      content,
      createdAt: this.timestamp(),
    });
  }

  private async persist(managed: ManagedSession): Promise<void> {
    const metadata: BrowserSessionMetadata = {
      schemaVersion: 1,
      sessionId: managed.session.id,
      runId: managed.session.runId,
      mode: managed.session.mode,
      status: managed.session.status,
      runtime: managed.session.runtime,
      createdAt: managed.session.createdAt,
      updatedAt: managed.session.updatedAt,
      currentUrl: managed.session.currentUrl,
      wsEndpoint: managed.session.wsEndpoint,
      profileDir: managed.session.profileDir,
      lastError: managed.session.lastError,
      artifacts: [...managed.artifacts],
      actions: [...managed.actions],
    };

    const recordings: BrowserSessionRecordingIndex = {
      schemaVersion: 1,
      sessionId: managed.session.id,
      runId: managed.session.runId,
      createdAt: managed.session.createdAt,
      updatedAt: managed.session.updatedAt,
      recordings: [...managed.recordings].sort((left, right) => left.sequence - right.sequence),
    };

    await writeBrowserSessionMetadata(this.cwd, metadata);
    await writeBrowserSessionRecordings(this.cwd, recordings);
  }

  private async recordAction(
    managed: ManagedSession,
    action: BrowserAction,
    ok: boolean,
    error?: BrowserActionError,
    artifact?: BrowserArtifactMetadata,
  ): Promise<void> {
    const artifactIds: string[] = [];
    const artifactPaths: string[] = [];
    if (artifact) {
      managed.artifacts.push(artifact);
      artifactIds.push(artifact.id);
      artifactPaths.push(artifact.relativePath);
    }

    managed.actions.push({
      action,
      ok,
      error,
      artifactIds,
    });

    managed.timelineSequence += 1;
    const timestamp = this.timestamp();
    const step: BrowserSessionStepRecord = {
      sequence: managed.timelineSequence,
      sessionId: managed.session.id,
      runId: managed.session.runId,
      actionId: action.id,
      actionType: action.type,
      timestamp,
      ok,
      error,
      artifactIds: [...artifactIds],
      artifactPaths: [...artifactPaths],
    };

    managed.recordings.push({
      sequence: step.sequence,
      sessionId: step.sessionId,
      runId: step.runId,
      actionId: step.actionId,
      actionType: step.actionType,
      timestamp: step.timestamp,
      ok: step.ok,
      error: step.error,
      artifactIds: [...step.artifactIds],
      artifactPaths: [...step.artifactPaths],
    });

    managed.timelineWrite = managed.timelineWrite
      .catch(() => undefined)
      .then(async () => {
        await appendBrowserSessionStep(this.cwd, step);
        await appendBrowserVisualDiffManifestEntry(this.cwd, {
          schemaVersion: 1,
          sessionId: step.sessionId,
          runId: step.runId,
          sequence: step.sequence,
          actionId: step.actionId,
          actionType: step.actionType,
          timestamp: step.timestamp,
          status: 'pending',
          artifactIds: [...step.artifactIds],
          artifactPaths: [...step.artifactPaths],
        });

        const previousStep = managed.recordings.at(-2);
        if (previousStep) {
          const {
            status,
            fromScreenshotPath,
            toScreenshotPath,
            changedByteRatio,
            perceptualDiffScore,
            severity,
            regressionScore,
            regressionSignal,
          } = await this.computeVisualDiffStatus(
            previousStep,
            step,
          );
          await appendBrowserVisualDiffResultEntry(this.cwd, {
            schemaVersion: 1,
            sessionId: step.sessionId,
            runId: step.runId,
            index: step.sequence - 2,
            fromSequence: previousStep.sequence,
            fromActionId: previousStep.actionId,
            fromActionType: previousStep.actionType,
            toSequence: step.sequence,
            toActionId: step.actionId,
            toActionType: step.actionType,
            fromScreenshotPath,
            toScreenshotPath,
            status,
            changedByteRatio,
            perceptualDiffScore,
            severity,
            regressionScore,
            regressionSignal,
          });
        }
      })
      .then(() => undefined);
    await managed.timelineWrite;

    managed.session.updatedAt = timestamp;
    managed.session.lastError = error;
  }

  private resolveArtifactAbsolutePath(sessionId: string, artifactPath: string): string {
    if (isAbsolute(artifactPath)) return artifactPath;
    if (artifactPath.startsWith('.opta/')) {
      return join(this.cwd, artifactPath);
    }
    return join(browserSessionArtifactsDir(this.cwd, sessionId), artifactPath);
  }

  private isScreenshotArtifactPath(artifactPath: string): boolean {
    const lower = artifactPath.toLowerCase();
    return (
      lower.endsWith('.png') ||
      lower.endsWith('.jpg') ||
      lower.endsWith('.jpeg') ||
      lower.endsWith('.webp') ||
      lower.endsWith('.gif') ||
      lower.endsWith('.bmp')
    );
  }

  private findStepScreenshotPath(step: Pick<BrowserSessionStepRecord, 'sessionId' | 'artifactPaths'>): string | undefined {
    return step.artifactPaths.find((path) => this.isScreenshotArtifactPath(path));
  }

  private async computeVisualDiffStatus(
    fromStep: BrowserSessionStepRecord,
    toStep: BrowserSessionStepRecord,
  ): Promise<{
    status: 'changed' | 'unchanged' | 'missing';
    fromScreenshotPath?: string;
    toScreenshotPath?: string;
    changedByteRatio?: number;
    perceptualDiffScore?: number;
    severity: BrowserVisualDiffSeverity;
    regressionScore: number;
    regressionSignal: BrowserVisualDiffRegressionSignal;
  }> {
    const fromScreenshotPath = this.findStepScreenshotPath(fromStep);
    const toScreenshotPath = this.findStepScreenshotPath(toStep);
    if (!fromScreenshotPath || !toScreenshotPath) {
      const status = 'missing';
      const severity = inferVisualDiffSeverity(status);
      const regression = inferVisualDiffRegression(status, severity);
      return {
        status,
        fromScreenshotPath,
        toScreenshotPath,
        severity,
        ...regression,
      };
    }

    try {
      const [fromBytes, toBytes] = await Promise.all([
        readFile(this.resolveArtifactAbsolutePath(fromStep.sessionId, fromScreenshotPath)),
        readFile(this.resolveArtifactAbsolutePath(toStep.sessionId, toScreenshotPath)),
      ]);
      const assessment = assessVisualDiffPair(fromBytes, toBytes);

      return {
        status: assessment.status,
        fromScreenshotPath,
        toScreenshotPath,
        changedByteRatio: assessment.changedByteRatio,
        perceptualDiffScore: assessment.perceptualDiffScore,
        severity: assessment.severity,
        regressionScore: assessment.regressionScore,
        regressionSignal: assessment.regressionSignal,
      };
    } catch {
      const status = 'missing';
      const severity = inferVisualDiffSeverity(status);
      const regression = inferVisualDiffRegression(status, severity);
      return {
        status,
        fromScreenshotPath,
        toScreenshotPath,
        severity,
        ...regression,
      };
    }
  }

  private createAction(
    sessionId: string,
    type: BrowserAction['type'],
    input: Record<string, unknown>,
  ): BrowserAction {
    this.globalActionSequence += 1;
    return {
      id: `action-${String(this.globalActionSequence).padStart(6, '0')}`,
      sessionId,
      type,
      createdAt: this.timestamp(),
      input,
    };
  }

  private fail<T>(
    action: BrowserAction,
    code: string,
    message: string,
  ): BrowserActionResult<T> {
    return {
      ok: false,
      action,
      error: this.error(code, message),
    };
  }

  private error(code: string, message: string): BrowserActionError {
    return withRetryTaxonomy(code, message);
  }

  private isAbortError(err: unknown): boolean {
    return err instanceof Error && err.name === 'AbortError';
  }

  private makeAbortError(): Error {
    const err = new Error(ACTION_CANCELLED_MESSAGE);
    err.name = 'AbortError';
    return err;
  }

  private async withActionSignal<T>(
    managed: ManagedSession,
    options: NativeSessionActionOptions | undefined,
    execute: () => Promise<T>,
  ): Promise<T> {
    const signal = options?.signal;
    if (!signal) return execute();
    if (signal.aborted) {
      await this.safeCloseRuntime(managed);
      throw this.makeAbortError();
    }

    let onAbort: (() => void) | null = null;
    const abortPromise = new Promise<never>((_, reject) => {
      onAbort = () => {
        void this.safeCloseRuntime(managed);
        reject(this.makeAbortError());
      };
      signal.addEventListener('abort', onAbort, { once: true });
    });

    try {
      return await Promise.race([execute(), abortPromise]);
    } finally {
      if (onAbort) {
        signal.removeEventListener('abort', onAbort);
      }
    }
  }

  private timestamp(): string {
    return this.now().toISOString();
  }

  private async safeCloseRuntime(managed: ManagedSession): Promise<void> {
    const context = managed.context;
    if (context) {
      try {
        await context.close();
      } catch {
        // Best-effort cleanup
      }
    }

    const browser = managed.browser;
    if (browser) {
      try {
        await browser.close();
      } catch {
        // Best-effort cleanup
      }
    }

    managed.page = undefined;
    managed.context = undefined;
    managed.browser = undefined;
  }
}

import type { BrowserPolicyAdaptationHint } from './adaptation.js';

const DEFAULT_SENSITIVE_ACTIONS = ['auth_submit', 'post', 'checkout', 'delete'] as const;

export type BrowserRiskLevel = 'low' | 'medium' | 'high';
export type BrowserPolicyDecisionType = 'allow' | 'gate' | 'deny';

export interface BrowserPolicyConfig {
  requireApprovalForHighRisk: boolean;
  allowedHosts: string[];
  blockedOrigins: string[];
  sensitiveActions: string[];
  credentialIsolation: boolean;
}

export interface BrowserPolicyRequest {
  toolName: string;
  args: Record<string, unknown>;
  approved?: boolean;
  adaptationHint?: BrowserPolicyAdaptationHint;
  /** Origin of the page currently loaded in the browser session. */
  currentOrigin?: string;
  /** Whether the current page contains credential-related elements (login forms, auth cookies, etc.). */
  currentPageHasCredentials?: boolean;
}

export interface BrowserRiskEvidence {
  classifier: 'static' | 'adaptive-escalation';
  matchedSignals: string[];
  adaptationReason?: string;
}

export interface BrowserPolicyDecision {
  decision: BrowserPolicyDecisionType;
  risk: BrowserRiskLevel;
  reason: string;
  actionKey: string;
  targetHost?: string;
  targetOrigin?: string;
  riskEvidence: BrowserRiskEvidence;
}

function normalizeList(values: string[] | undefined): string[] {
  if (!values || values.length === 0) return [];
  const seen = new Set<string>();
  const normalized: string[] = [];
  for (const value of values) {
    const candidate = value.trim().toLowerCase();
    if (!candidate || seen.has(candidate)) continue;
    seen.add(candidate);
    normalized.push(candidate);
  }
  return normalized;
}

function uniqueSorted(values: string[]): string[] {
  return [...new Set(values)].sort((left, right) => left.localeCompare(right));
}

export function normalizeBrowserPolicyConfig(
  input?: Partial<BrowserPolicyConfig> | null,
): BrowserPolicyConfig {
  return {
    requireApprovalForHighRisk: input?.requireApprovalForHighRisk !== false,
    allowedHosts: normalizeList(input?.allowedHosts ?? []),
    blockedOrigins: normalizeList(input?.blockedOrigins ?? []),
    sensitiveActions: normalizeList(
      input?.sensitiveActions?.length
        ? input.sensitiveActions
        : [...DEFAULT_SENSITIVE_ACTIONS],
    ),
    credentialIsolation: input?.credentialIsolation !== false,
  };
}

function wildcardHostMatch(host: string, pattern: string): boolean {
  if (pattern === '*') return true;
  if (pattern.startsWith('*.')) {
    const suffix = pattern.slice(1);
    return host.endsWith(suffix);
  }
  return host === pattern;
}

function normalizePatternInput(pattern: string): string {
  return pattern.trim().toLowerCase();
}

function parseHostPattern(pattern: string): string {
  const normalized = normalizePatternInput(pattern);
  if (!normalized) return '';
  if (normalized === '*') return '*';

  if (normalized.startsWith('*.')) {
    const wildcardHost = normalized.split('/')[0] ?? '';
    return wildcardHost.replace(/:\d+$/, '');
  }

  const candidate = normalized.includes('://') ? normalized : `https://${normalized}`;
  try {
    const parsed = new URL(candidate);
    return parsed.hostname.toLowerCase();
  } catch {
    return '';
  }
}

function parseOriginPattern(pattern: string): string | null {
  const normalized = normalizePatternInput(pattern);
  if (!normalized) return null;
  if (normalized.includes('://')) {
    try {
      const parsed = new URL(normalized);
      return `${parsed.protocol}//${parsed.host}`.toLowerCase();
    } catch {
      return null;
    }
  }
  return null;
}

/** Try to parse an allowedHosts entry as a JSON object with a "regex" field. */
function tryParseRegexPattern(pattern: string): RegExp | null {
  const trimmed = pattern.trim();
  if (!trimmed.startsWith('{')) return null;
  try {
    const obj = JSON.parse(trimmed) as unknown;
    if (typeof obj !== 'object' || obj === null) return null;
    const regexStr = (obj as Record<string, unknown>).regex;
    if (typeof regexStr !== 'string') return null;
    return new RegExp(regexStr);
  } catch {
    return null;
  }
}

function hostAllowed(host: string, allowedHosts: string[]): boolean {
  if (allowedHosts.length === 0) return false;
  for (const pattern of allowedHosts) {
    const regex = tryParseRegexPattern(pattern);
    if (regex !== null) {
      try {
        if (regex.test(host)) return true;
      } catch {
        // invalid regex — skip this pattern
      }
      continue;
    }
    const parsedPattern = parseHostPattern(pattern);
    if (!parsedPattern) continue;
    if (wildcardHostMatch(host, parsedPattern)) return true;
  }
  return false;
}

function originBlocked(origin: string, host: string, blockedOrigins: string[]): boolean {
  for (const pattern of blockedOrigins) {
    const parsedOrigin = parseOriginPattern(pattern);
    if (parsedOrigin) {
      if (origin === parsedOrigin) return true;
      continue;
    }
    const hostPattern = parseHostPattern(pattern);
    if (!hostPattern) continue;
    if (wildcardHostMatch(host, hostPattern)) return true;
  }
  return false;
}

function extractUrlTarget(args: Record<string, unknown>): {
  url?: URL;
  host?: string;
  origin?: string;
} {
  const raw = String(args['url'] ?? '').trim();
  if (!raw) return {};
  try {
    const parsed = new URL(raw);
    if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
      return {};
    }
    return {
      url: parsed,
      host: parsed.hostname.toLowerCase(),
      origin: `${parsed.protocol}//${parsed.host}`.toLowerCase(),
    };
  } catch {
    return {};
  }
}

interface SensitiveSignalMatch {
  actionKey: string;
  signal: string;
}

function signalContainsSensitiveKeyword(value: string): SensitiveSignalMatch | null {
  const text = value.toLowerCase();
  if (/(login|sign[-_\s]?in|auth|password|otp|2fa)/.test(text)) {
    return { actionKey: 'auth_submit', signal: 'keyword:auth' };
  }
  if (/(checkout|payment|billing|purchase|buy|order)/.test(text)) {
    return { actionKey: 'checkout', signal: 'keyword:checkout' };
  }
  if (/(delete|remove|destroy|erase|deactivate)/.test(text)) {
    return { actionKey: 'delete', signal: 'keyword:delete' };
  }
  if (/(post|publish|submit|send|comment|tweet)/.test(text)) {
    return { actionKey: 'post', signal: 'keyword:post' };
  }
  return null;
}

const SENSITIVE_TEXT_ARG_KEYS = [
  'selector',
  'text',
  'element',
  'name',
  'label',
  'title',
  'value',
  'promptText',
  'url',
  'href',
] as const;

function collectSensitiveSignalText(args: Record<string, unknown>): string {
  const parts: string[] = [];
  for (const key of SENSITIVE_TEXT_ARG_KEYS) {
    const candidate = args[key];
    if (typeof candidate === 'string' && candidate.trim()) {
      parts.push(candidate);
    }
  }
  return parts.join(' ');
}

function isTruthyFlag(value: unknown): boolean {
  if (value === true || value === 1) return true;
  if (typeof value === 'string') {
    const normalized = value.trim().toLowerCase();
    return normalized === 'true' || normalized === '1' || normalized === 'yes' || normalized === 'on';
  }
  return false;
}

function classifyAction(
  toolName: string,
  args: Record<string, unknown>,
  sensitiveActions: Set<string>,
): { risk: BrowserRiskLevel; actionKey: string; matchedSignals: string[] } {
  if (toolName === 'browser_snapshot' || toolName === 'browser_screenshot' || toolName === 'browser_close') {
    return { risk: 'low', actionKey: 'observe', matchedSignals: [`tool:${toolName}`] };
  }

  if (toolName === 'browser_open') {
    const mode = String(args['mode'] ?? 'isolated').toLowerCase();
    return mode === 'attach'
      ? { risk: 'medium', actionKey: 'attach', matchedSignals: ['tool:browser_open', 'mode:attach'] }
      : { risk: 'low', actionKey: 'open', matchedSignals: ['tool:browser_open', 'mode:isolated'] };
  }

  if (toolName === 'browser_navigate') {
    const target = extractUrlTarget(args);
    const matchedSignals = ['tool:browser_navigate'];
    if (target.url) {
      const candidate = signalContainsSensitiveKeyword(
        `${target.url.pathname} ${target.url.search} ${target.url.hash}`,
      );
      if (candidate && sensitiveActions.has(candidate.actionKey)) {
        matchedSignals.push(`url:${candidate.signal}`);
        return { risk: 'high', actionKey: candidate.actionKey, matchedSignals };
      }
    }
    return { risk: 'medium', actionKey: 'navigate', matchedSignals };
  }

  if (toolName === 'browser_click' || toolName === 'browser_type') {
    const matchedSignals = [`tool:${toolName}`];
    const keywordMatch = signalContainsSensitiveKeyword(collectSensitiveSignalText(args));
    if (keywordMatch && sensitiveActions.has(keywordMatch.actionKey)) {
      matchedSignals.push(`args:${keywordMatch.signal}`);
      return { risk: 'high', actionKey: keywordMatch.actionKey, matchedSignals };
    }

    if (toolName === 'browser_type' && isTruthyFlag(args['submit']) && sensitiveActions.has('post')) {
      matchedSignals.push('flag:submit');
      return { risk: 'high', actionKey: 'post', matchedSignals };
    }

    return {
      risk: 'medium',
      actionKey: toolName === 'browser_click' ? 'click' : 'type',
      matchedSignals,
    };
  }

  if (toolName === 'browser_handle_dialog') {
    const accepted = isTruthyFlag(args['accept']);
    const matchedSignals = ['tool:browser_handle_dialog', accepted ? 'dialog:accept' : 'dialog:dismiss'];
    const keywordMatch = signalContainsSensitiveKeyword(collectSensitiveSignalText(args));

    if (accepted && keywordMatch && sensitiveActions.has(keywordMatch.actionKey)) {
      matchedSignals.push(`dialog:${keywordMatch.signal}`);
      return { risk: 'high', actionKey: keywordMatch.actionKey, matchedSignals };
    }

    return accepted
      ? { risk: 'medium', actionKey: 'confirm', matchedSignals }
      : { risk: 'low', actionKey: 'dismiss', matchedSignals };
  }

  // MCP-only high-risk tools
  if (toolName === 'browser_evaluate') {
    return { risk: 'high', actionKey: 'execute', matchedSignals: ['tool:browser_evaluate', 'risk:js-execution'] };
  }

  if (toolName === 'browser_file_upload') {
    return { risk: 'high', actionKey: 'upload', matchedSignals: ['tool:browser_file_upload', 'risk:filesystem'] };
  }

  // MCP-only medium-risk interaction tools
  if (toolName === 'browser_select_option') {
    const matchedSignals = ['tool:browser_select_option'];
    const keywordMatch = signalContainsSensitiveKeyword(collectSensitiveSignalText(args));
    if (keywordMatch && sensitiveActions.has(keywordMatch.actionKey)) {
      matchedSignals.push(`args:${keywordMatch.signal}`);
      return { risk: 'high', actionKey: keywordMatch.actionKey, matchedSignals };
    }
    return { risk: 'medium', actionKey: 'select', matchedSignals };
  }

  if (toolName === 'browser_drag') {
    return { risk: 'medium', actionKey: 'click', matchedSignals: ['tool:browser_drag'] };
  }

  if (toolName === 'browser_press_key' || toolName === 'browser_keyboard_type') {
    const matchedSignals = [`tool:${toolName}`];
    const keywordMatch = signalContainsSensitiveKeyword(collectSensitiveSignalText(args));
    if (keywordMatch && sensitiveActions.has(keywordMatch.actionKey)) {
      matchedSignals.push(`args:${keywordMatch.signal}`);
      return { risk: 'high', actionKey: keywordMatch.actionKey, matchedSignals };
    }
    return { risk: 'medium', actionKey: 'type', matchedSignals };
  }

  if (toolName === 'browser_go_back' || toolName === 'browser_go_forward' || toolName === 'browser_reload') {
    return { risk: 'medium', actionKey: 'navigate', matchedSignals: [`tool:${toolName}`] };
  }

  if (toolName === 'browser_tab_new' || toolName === 'browser_tab_close' || toolName === 'browser_tab_switch') {
    return { risk: 'medium', actionKey: 'navigate', matchedSignals: [`tool:${toolName}`] };
  }

  return { risk: 'low', actionKey: 'other', matchedSignals: [`tool:${toolName}`] };
}

export function isBrowserToolName(toolName: string): boolean {
  return toolName.startsWith('browser_');
}

export function evaluateBrowserPolicyAction(
  configInput: Partial<BrowserPolicyConfig> | undefined,
  request: BrowserPolicyRequest,
): BrowserPolicyDecision {
  const config = normalizeBrowserPolicyConfig(configInput);
  const target = extractUrlTarget(request.args);
  const hasTarget = Boolean(target.url && target.host && target.origin);

  if (request.toolName === 'browser_navigate') {
    if (!hasTarget || !target.host || !target.origin) {
      return {
        decision: 'deny',
        risk: 'high',
        actionKey: 'navigate',
        reason: 'Policy denied browser navigate action due to missing/invalid URL.',
        riskEvidence: {
          classifier: 'static',
          matchedSignals: ['url:invalid'],
        },
      };
    }
  }

  // Determine the effective host/origin for policy evaluation.
  // URL-bearing actions use args.url; non-URL actions (click, type, handle_dialog)
  // fall back to request.currentOrigin so they're checked against the same allowlist.
  let effectiveHost = target.host;
  let effectiveOrigin = target.origin;
  if (!effectiveHost && request.currentOrigin) {
    try {
      const parsed = new URL(request.currentOrigin);
      effectiveHost = parsed.hostname.toLowerCase();
      effectiveOrigin = `${parsed.protocol}//${parsed.host}`.toLowerCase();
    } catch {
      // malformed currentOrigin — handled below
    }
  }

  const hasEffectiveTarget = Boolean(effectiveHost && effectiveOrigin);
  const isInteractiveAction =
    request.toolName === 'browser_click'
    || request.toolName === 'browser_type'
    || request.toolName === 'browser_handle_dialog'
    || request.toolName === 'browser_navigate';

  if (hasEffectiveTarget && effectiveHost && effectiveOrigin) {
    if (originBlocked(effectiveOrigin, effectiveHost, config.blockedOrigins)) {
      return {
        decision: 'deny',
        risk: 'high',
        actionKey: request.toolName === 'browser_navigate' ? 'navigate' : 'interaction',
        reason: `Policy denied browser action due to blocked origin: ${effectiveOrigin}`,
        targetHost: effectiveHost,
        targetOrigin: effectiveOrigin,
        riskEvidence: {
          classifier: 'static',
          matchedSignals: ['policy:blocked-origin'],
        },
      };
    }

    if (!hostAllowed(effectiveHost, config.allowedHosts)) {
      return {
        decision: 'deny',
        risk: 'high',
        actionKey: request.toolName === 'browser_navigate' ? 'navigate' : 'interaction',
        reason: `Policy denied browser action due to host allowlist mismatch: ${effectiveHost}`,
        targetHost: effectiveHost,
        targetOrigin: effectiveOrigin,
        riskEvidence: {
          classifier: 'static',
          matchedSignals: ['policy:allowlist-mismatch'],
        },
      };
    }

    if (
      config.credentialIsolation
      && request.currentPageHasCredentials
      && request.currentOrigin
      && effectiveOrigin !== request.currentOrigin.toLowerCase()
    ) {
      return {
        decision: 'deny',
        risk: 'high',
        actionKey: request.toolName === 'browser_navigate' ? 'navigate' : 'interaction',
        reason: `Policy denied cross-origin action from credential page: ${request.currentOrigin} -> ${effectiveOrigin}`,
        targetHost: effectiveHost,
        targetOrigin: effectiveOrigin,
        riskEvidence: {
          classifier: 'static',
          matchedSignals: ['policy:credential-isolation'],
        },
      };
    }
  } else if (
    !hasEffectiveTarget
    && isInteractiveAction
    && config.allowedHosts.length > 0
    && !config.allowedHosts.includes('*')
  ) {
    // Restrictive allowlist is configured but we have no origin to validate against.
    // Deny rather than allow unchecked interaction on an unknown page.
    // Wildcard ('*') is excluded because it explicitly means "allow all hosts".
    return {
      decision: 'deny',
      risk: 'high',
      actionKey: 'interaction',
      reason: 'Policy denied browser action: restrictive allowlist configured but no origin available to validate.',
      riskEvidence: {
        classifier: 'static',
        matchedSignals: ['policy:no-origin-for-allowlist'],
      },
    };
  }

  const sensitiveActions = new Set(config.sensitiveActions);
  const classified = classifyAction(request.toolName, request.args, sensitiveActions);

  let risk = classified.risk;
  let classifier: BrowserRiskEvidence['classifier'] = 'static';
  const matchedSignals = [...classified.matchedSignals];
  let adaptationReason: string | undefined;

  if (
    request.adaptationHint?.escalateRisk === true
    && (classified.risk === 'medium' || classified.risk === 'low')
    && request.toolName !== 'browser_snapshot'
    && request.toolName !== 'browser_screenshot'
    && request.toolName !== 'browser_close'
  ) {
    classifier = 'adaptive-escalation';
    matchedSignals.push('adaptive:risk-escalation');
    adaptationReason = request.adaptationHint.reason;
    if (classified.risk === 'medium') {
      risk = 'high';
    } else {
      risk = 'medium';
    }
  }

  const riskEvidence: BrowserRiskEvidence = {
    classifier,
    matchedSignals: uniqueSorted(matchedSignals),
    adaptationReason,
  };

  if (risk === 'high' && config.requireApprovalForHighRisk && !request.approved) {
    return {
      decision: 'gate',
      risk,
      actionKey: classified.actionKey,
      reason: adaptationReason
        ? `Policy requires explicit approval for high-risk browser action: ${classified.actionKey}. ${adaptationReason}`
        : `Policy requires explicit approval for high-risk browser action: ${classified.actionKey}.`,
      targetHost: target.host,
      targetOrigin: target.origin,
      riskEvidence,
    };
  }

  return {
    decision: 'allow',
    risk,
    actionKey: classified.actionKey,
    reason: adaptationReason
      ? `Allowed by browser policy checks with adaptive risk context. ${adaptationReason}`
      : 'Allowed by browser policy checks.',
    targetHost: target.host,
    targetOrigin: target.origin,
    riskEvidence,
  };
}

import { access, readFile } from 'node:fs/promises';
import { isAbsolute, join } from 'node:path';
import {
  BROWSER_SESSION_METADATA_FILE,
  BROWSER_SESSION_RECORDINGS_FILE,
  BROWSER_SESSION_STEPS_FILE,
  BROWSER_VISUAL_DIFF_MANIFEST_FILE,
  browserSessionMetadataPath,
  browserSessionRecordingsPath,
  browserSessionStepsPath,
  browserSessionVisualDiffManifestPath,
} from './artifacts.js';
import type {
  BrowserArtifactMetadata,
  BrowserSessionMetadata,
  BrowserSessionRecordingEntry,
  BrowserSessionRecordingIndex,
  BrowserSessionStepRecord,
  BrowserVisualDiffManifestEntry,
} from './types.js';

export interface BrowserArtifactCompletenessCounts {
  metadataActions: number;
  metadataArtifacts: number;
  stepEntries: number;
  recordingEntries: number;
  visualDiffEntries: number;
  stepArtifactRefs: number;
  recordingArtifactRefs: number;
  visualDiffArtifactRefs: number;
}

export interface BrowserArtifactCompletenessResult {
  ok: boolean;
  sessionId: string;
  missingFiles: string[];
  issues: string[];
  counts: BrowserArtifactCompletenessCounts;
}

export interface BrowserBenchmarkMetrics {
  successRate: number;
  medianActionLatencyMs: number;
  recoveryMs: number;
}

export interface BrowserBenchmarkThresholds {
  minSuccessRate: number;
  maxMedianActionLatencyMs: number;
  maxRecoveryMs: number;
}

export interface BrowserBenchmarkThresholdResult {
  ok: boolean;
  failures: string[];
  metrics: BrowserBenchmarkMetrics;
  thresholds: BrowserBenchmarkThresholds;
}

export interface BrowserBenchmarkTelemetryIngestionResult {
  ok: boolean;
  sessionId: string;
  issues: string[];
  actionCount: number;
  successCount: number;
  failureCount: number;
  latencySamplesMs: number[];
  recoverySamplesMs: number[];
  metrics: BrowserBenchmarkMetrics;
}

export interface BrowserBenchmarkThresholdFeedResult extends BrowserBenchmarkThresholdResult {
  sessionId: string;
  ingestion: BrowserBenchmarkTelemetryIngestionResult;
}

export const DEFAULT_BROWSER_BENCHMARK_THRESHOLDS: BrowserBenchmarkThresholds = {
  minSuccessRate: 0.95,
  maxMedianActionLatencyMs: 1200,
  maxRecoveryMs: 3000,
};

function formatNumber(value: number): string {
  if (Number.isInteger(value)) return String(value);
  return value.toFixed(6).replace(/0+$/, '').replace(/\.$/, '');
}

function uniqueSorted(values: Iterable<string>): string[] {
  return [...new Set(values)].sort((left, right) => left.localeCompare(right));
}

function sumArtifactRefs(entries: Array<{ artifactIds: string[] }>): number {
  return entries.reduce((sum, entry) => sum + entry.artifactIds.length, 0);
}

function median(values: number[]): number {
  if (values.length === 0) return 0;
  const sorted = [...values].sort((left, right) => left - right);
  const midpoint = Math.floor(sorted.length / 2);
  if (sorted.length % 2 === 1) return sorted[midpoint] ?? 0;
  return ((sorted[midpoint - 1] ?? 0) + (sorted[midpoint] ?? 0)) / 2;
}

function flattenArtifactIds(entries: Array<{ artifactIds: string[] }>): string[] {
  return entries.flatMap((entry) => entry.artifactIds);
}

function flattenArtifactPaths(entries: Array<{ artifactPaths: string[] }>): string[] {
  return entries.flatMap((entry) => entry.artifactPaths);
}

function resolveMetadataArtifactPath(cwd: string, artifact: BrowserArtifactMetadata): string {
  if (artifact.absolutePath.trim().length > 0) {
    return artifact.absolutePath;
  }
  return isAbsolute(artifact.relativePath)
    ? artifact.relativePath
    : join(cwd, artifact.relativePath);
}

function compareStringSets(
  expected: string[],
  actual: string[],
  expectedLabel: string,
  actualLabel: string,
  issues: string[]
): void {
  const missing = expected.filter((value) => !actual.includes(value));
  const unexpected = actual.filter((value) => !expected.includes(value));

  if (missing.length > 0 || unexpected.length > 0) {
    const missingList = missing.length > 0 ? missing.join(', ') : 'none';
    const unexpectedList = unexpected.length > 0 ? unexpected.join(', ') : 'none';
    issues.push(
      `${actualLabel} does not match ${expectedLabel} (missing: ${missingList}; unexpected: ${unexpectedList}).`
    );
  }
}

function verifySequence(
  sourceLabel: string,
  entries: Array<{ sequence: number }>,
  issues: string[]
): void {
  for (let index = 0; index < entries.length; index += 1) {
    const expectedSequence = index + 1;
    const actualSequence = entries[index]?.sequence;
    if (actualSequence !== expectedSequence) {
      issues.push(
        `${sourceLabel} has non-contiguous sequence at index ${index} (expected ${expectedSequence}, got ${String(actualSequence)}).`
      );
      return;
    }
  }
}

function verifySessionIds(
  sourceLabel: string,
  entries: Array<{ sessionId: string }>,
  expectedSessionId: string,
  issues: string[]
): void {
  for (const [index, entry] of entries.entries()) {
    if (entry.sessionId !== expectedSessionId) {
      issues.push(
        `${sourceLabel} entry ${index} has sessionId ${entry.sessionId} but expected ${expectedSessionId}.`
      );
      return;
    }
  }
}

async function fileExists(path: string): Promise<boolean> {
  try {
    await access(path);
    return true;
  } catch (error) {
    const err = error as NodeJS.ErrnoException;
    if (err.code === 'ENOENT') return false;
    throw error;
  }
}

function parseJsonl<T>(raw: string, sourceLabel: string, issues: string[]): T[] {
  const entries: T[] = [];
  const lines = raw.split(/\r?\n/);

  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index]?.trim();
    if (!line) continue;

    try {
      entries.push(JSON.parse(line) as T);
    } catch {
      issues.push(`${sourceLabel} contains invalid JSON at line ${index + 1}.`);
      return [];
    }
  }

  return entries;
}

function parseTimestampMs(label: string, timestamp: string, issues: string[]): number | null {
  const value = Date.parse(timestamp);
  if (Number.isFinite(value)) return value;
  issues.push(`${label} has invalid timestamp "${timestamp}".`);
  return null;
}

function toCounts(
  metadata: BrowserSessionMetadata | null,
  steps: BrowserSessionStepRecord[],
  recordings: BrowserSessionRecordingEntry[],
  visualDiffEntries: BrowserVisualDiffManifestEntry[]
): BrowserArtifactCompletenessCounts {
  return {
    metadataActions: metadata?.actions.length ?? 0,
    metadataArtifacts: metadata?.artifacts.length ?? 0,
    stepEntries: steps.length,
    recordingEntries: recordings.length,
    visualDiffEntries: visualDiffEntries.length,
    stepArtifactRefs: sumArtifactRefs(steps),
    recordingArtifactRefs: sumArtifactRefs(recordings),
    visualDiffArtifactRefs: sumArtifactRefs(visualDiffEntries),
  };
}

function compareActionCounts(
  metadata: BrowserSessionMetadata | null,
  steps: BrowserSessionStepRecord[],
  recordings: BrowserSessionRecordingEntry[],
  visualDiffEntries: BrowserVisualDiffManifestEntry[],
  issues: string[]
): void {
  const metadataActions = metadata?.actions.length;

  if (metadataActions !== undefined && metadataActions !== steps.length) {
    issues.push(
      `metadata.json action count (${metadataActions}) does not match steps.jsonl count (${steps.length}).`
    );
  }

  if (metadataActions !== undefined && metadataActions !== recordings.length) {
    issues.push(
      `metadata.json action count (${metadataActions}) does not match recordings.json count (${recordings.length}).`
    );
  }

  if (steps.length !== recordings.length) {
    issues.push(
      `steps.jsonl count (${steps.length}) does not match recordings.json count (${recordings.length}).`
    );
  }

  if (steps.length !== visualDiffEntries.length) {
    issues.push(
      `steps.jsonl count (${steps.length}) does not match visual-diff-manifest.jsonl count (${visualDiffEntries.length}).`
    );
  }
}

function compareArtifactReferenceCounts(
  metadata: BrowserSessionMetadata | null,
  counts: BrowserArtifactCompletenessCounts,
  issues: string[]
): void {
  if (!metadata) return;

  if (counts.stepArtifactRefs !== counts.metadataArtifacts) {
    issues.push(
      `steps.jsonl artifact reference count (${counts.stepArtifactRefs}) does not match metadata.json artifact count (${counts.metadataArtifacts}).`
    );
  }

  if (counts.recordingArtifactRefs !== counts.metadataArtifacts) {
    issues.push(
      `recordings.json artifact reference count (${counts.recordingArtifactRefs}) does not match metadata.json artifact count (${counts.metadataArtifacts}).`
    );
  }

  if (counts.visualDiffArtifactRefs !== counts.metadataArtifacts) {
    issues.push(
      `visual-diff-manifest.jsonl artifact reference count (${counts.visualDiffArtifactRefs}) does not match metadata.json artifact count (${counts.metadataArtifacts}).`
    );
  }
}

async function verifyArtifactPathsExist(
  cwd: string,
  metadata: BrowserSessionMetadata | null,
  steps: BrowserSessionStepRecord[],
  recordings: BrowserSessionRecordingEntry[],
  visualDiffEntries: BrowserVisualDiffManifestEntry[],
  issues: string[]
): Promise<void> {
  if (metadata) {
    for (const artifact of metadata.artifacts) {
      const absolutePath = resolveMetadataArtifactPath(cwd, artifact);
      if (!(await fileExists(absolutePath))) {
        issues.push(`metadata.json artifact file is missing: ${absolutePath}.`);
      }
    }
  }

  const referencedPaths = uniqueSorted([
    ...flattenArtifactPaths(steps),
    ...flattenArtifactPaths(recordings),
    ...flattenArtifactPaths(visualDiffEntries),
  ]);

  for (const relativePath of referencedPaths) {
    const absolutePath = isAbsolute(relativePath) ? relativePath : join(cwd, relativePath);
    if (!(await fileExists(absolutePath))) {
      issues.push(`Referenced artifact path does not exist: ${relativePath}.`);
    }
  }
}

export async function validateBrowserSessionArtifactCompleteness(
  cwd: string,
  sessionId: string
): Promise<BrowserArtifactCompletenessResult> {
  const missingFiles: string[] = [];
  const issues: string[] = [];

  const metadataPath = browserSessionMetadataPath(cwd, sessionId);
  const stepsPath = browserSessionStepsPath(cwd, sessionId);
  const recordingsPath = browserSessionRecordingsPath(cwd, sessionId);
  const visualDiffPath = browserSessionVisualDiffManifestPath(cwd, sessionId);

  const requiredFiles = [
    { label: BROWSER_SESSION_METADATA_FILE, path: metadataPath },
    { label: BROWSER_SESSION_STEPS_FILE, path: stepsPath },
    { label: BROWSER_SESSION_RECORDINGS_FILE, path: recordingsPath },
    { label: BROWSER_VISUAL_DIFF_MANIFEST_FILE, path: visualDiffPath },
  ];

  const filePresence = new Map<string, boolean>();
  for (const file of requiredFiles) {
    const exists = await fileExists(file.path);
    filePresence.set(file.label, exists);
    if (!exists) {
      missingFiles.push(file.label);
      issues.push(`Missing required artifact file: ${file.label}.`);
    }
  }

  let metadata: BrowserSessionMetadata | null = null;
  let steps: BrowserSessionStepRecord[] = [];
  let recordings: BrowserSessionRecordingEntry[] = [];
  let visualDiffEntries: BrowserVisualDiffManifestEntry[] = [];

  if (filePresence.get(BROWSER_SESSION_METADATA_FILE)) {
    try {
      const parsed = JSON.parse(
        await readFile(metadataPath, 'utf-8')
      ) as Partial<BrowserSessionMetadata>;
      if (!Array.isArray(parsed.actions) || !Array.isArray(parsed.artifacts)) {
        issues.push('metadata.json must include "actions" and "artifacts" arrays.');
      } else {
        metadata = parsed as BrowserSessionMetadata;
      }
    } catch {
      issues.push('metadata.json is not valid JSON.');
    }
  }

  if (filePresence.get(BROWSER_SESSION_STEPS_FILE)) {
    try {
      steps = parseJsonl<BrowserSessionStepRecord>(
        await readFile(stepsPath, 'utf-8'),
        'steps.jsonl',
        issues
      );
    } catch {
      issues.push('steps.jsonl could not be read.');
    }
  }

  if (filePresence.get(BROWSER_SESSION_RECORDINGS_FILE)) {
    try {
      const parsed = JSON.parse(
        await readFile(recordingsPath, 'utf-8')
      ) as Partial<BrowserSessionRecordingIndex>;
      if (!Array.isArray(parsed.recordings)) {
        issues.push('recordings.json must include a "recordings" array.');
      } else {
        recordings = parsed.recordings;
      }
    } catch {
      issues.push('recordings.json is not valid JSON.');
    }
  }

  if (filePresence.get(BROWSER_VISUAL_DIFF_MANIFEST_FILE)) {
    try {
      visualDiffEntries = parseJsonl<BrowserVisualDiffManifestEntry>(
        await readFile(visualDiffPath, 'utf-8'),
        'visual-diff-manifest.jsonl',
        issues
      );
    } catch {
      issues.push('visual-diff-manifest.jsonl could not be read.');
    }
  }

  const counts = toCounts(metadata, steps, recordings, visualDiffEntries);

  if (metadata && metadata.sessionId !== sessionId) {
    issues.push(
      `metadata.json sessionId ${metadata.sessionId} does not match expected sessionId ${sessionId}.`
    );
  }

  verifySessionIds('steps.jsonl', steps, sessionId, issues);
  verifySessionIds('recordings.json', recordings, sessionId, issues);
  verifySessionIds('visual-diff-manifest.jsonl', visualDiffEntries, sessionId, issues);

  verifySequence('steps.jsonl', steps, issues);
  verifySequence('recordings.json', recordings, issues);
  verifySequence('visual-diff-manifest.jsonl', visualDiffEntries, issues);

  compareActionCounts(metadata, steps, recordings, visualDiffEntries, issues);
  compareArtifactReferenceCounts(metadata, counts, issues);

  const metadataArtifactIds = uniqueSorted(
    metadata?.artifacts.map((artifact) => artifact.id) ?? []
  );
  const stepArtifactIds = uniqueSorted(flattenArtifactIds(steps));
  const recordingArtifactIds = uniqueSorted(flattenArtifactIds(recordings));
  const visualArtifactIds = uniqueSorted(flattenArtifactIds(visualDiffEntries));

  if (metadata) {
    compareStringSets(
      metadataArtifactIds,
      stepArtifactIds,
      'metadata.json artifact IDs',
      'steps.jsonl artifact IDs',
      issues
    );
    compareStringSets(
      metadataArtifactIds,
      recordingArtifactIds,
      'metadata.json artifact IDs',
      'recordings.json artifact IDs',
      issues
    );
    compareStringSets(
      metadataArtifactIds,
      visualArtifactIds,
      'metadata.json artifact IDs',
      'visual-diff-manifest.jsonl artifact IDs',
      issues
    );
  }

  compareStringSets(
    stepArtifactIds,
    recordingArtifactIds,
    'steps.jsonl artifact IDs',
    'recordings.json artifact IDs',
    issues
  );
  compareStringSets(
    stepArtifactIds,
    visualArtifactIds,
    'steps.jsonl artifact IDs',
    'visual-diff-manifest.jsonl artifact IDs',
    issues
  );

  const metadataArtifactPaths = uniqueSorted(
    metadata?.artifacts.map((artifact) => artifact.relativePath) ?? []
  );
  const stepArtifactPaths = uniqueSorted(flattenArtifactPaths(steps));
  const recordingArtifactPaths = uniqueSorted(flattenArtifactPaths(recordings));
  const visualArtifactPaths = uniqueSorted(flattenArtifactPaths(visualDiffEntries));

  if (metadata) {
    compareStringSets(
      metadataArtifactPaths,
      stepArtifactPaths,
      'metadata.json artifact paths',
      'steps.jsonl artifact paths',
      issues
    );
    compareStringSets(
      metadataArtifactPaths,
      recordingArtifactPaths,
      'metadata.json artifact paths',
      'recordings.json artifact paths',
      issues
    );
    compareStringSets(
      metadataArtifactPaths,
      visualArtifactPaths,
      'metadata.json artifact paths',
      'visual-diff-manifest.jsonl artifact paths',
      issues
    );
  }

  compareStringSets(
    stepArtifactPaths,
    recordingArtifactPaths,
    'steps.jsonl artifact paths',
    'recordings.json artifact paths',
    issues
  );
  compareStringSets(
    stepArtifactPaths,
    visualArtifactPaths,
    'steps.jsonl artifact paths',
    'visual-diff-manifest.jsonl artifact paths',
    issues
  );

  await verifyArtifactPathsExist(cwd, metadata, steps, recordings, visualDiffEntries, issues);

  return {
    ok: issues.length === 0,
    sessionId,
    missingFiles,
    issues,
    counts,
  };
}

export async function ingestBrowserBenchmarkTelemetry(
  cwd: string,
  sessionId: string
): Promise<BrowserBenchmarkTelemetryIngestionResult> {
  const issues: string[] = [];

  const metadataPath = browserSessionMetadataPath(cwd, sessionId);
  const stepsPath = browserSessionStepsPath(cwd, sessionId);

  let metadataActions: BrowserSessionMetadata['actions'] = [];
  let metadataUpdatedAtMs: number | null = null;
  if (await fileExists(metadataPath)) {
    try {
      const parsed = JSON.parse(
        await readFile(metadataPath, 'utf-8')
      ) as Partial<BrowserSessionMetadata>;
      if (!Array.isArray(parsed.actions)) {
        issues.push(
          'metadata.json must include an "actions" array for benchmark telemetry ingestion.'
        );
      } else {
        metadataActions = parsed.actions;
      }

      if (typeof parsed.updatedAt === 'string') {
        metadataUpdatedAtMs = parseTimestampMs('metadata.json updatedAt', parsed.updatedAt, issues);
      } else {
        issues.push('metadata.json must include "updatedAt" for benchmark telemetry ingestion.');
      }
    } catch {
      issues.push('metadata.json is not valid JSON.');
    }
  } else {
    issues.push('Missing required telemetry file: metadata.json.');
  }

  let steps: BrowserSessionStepRecord[] = [];
  if (await fileExists(stepsPath)) {
    try {
      steps = parseJsonl<BrowserSessionStepRecord>(
        await readFile(stepsPath, 'utf-8'),
        'steps.jsonl',
        issues
      );
    } catch {
      issues.push('steps.jsonl could not be read.');
    }
  } else {
    issues.push('Missing required telemetry file: steps.jsonl.');
  }

  const actionCreatedAtMs = new Map<string, number>();
  for (const [index, actionRecord] of metadataActions.entries()) {
    const action = actionRecord?.action;
    if (!action || typeof action.id !== 'string' || typeof action.createdAt !== 'string') {
      issues.push(
        `metadata.json action record at index ${index} is missing a valid action id or createdAt timestamp.`
      );
      continue;
    }

    if (actionCreatedAtMs.has(action.id)) {
      issues.push(`metadata.json contains duplicate action id ${action.id}.`);
      continue;
    }

    const createdAtMs = parseTimestampMs(
      `metadata.json action ${action.id}`,
      action.createdAt,
      issues
    );
    if (createdAtMs !== null) {
      actionCreatedAtMs.set(action.id, createdAtMs);
    }
  }

  const orderedSteps = [...steps].sort((left, right) => {
    if (left.sequence !== right.sequence) return left.sequence - right.sequence;
    return left.actionId.localeCompare(right.actionId);
  });

  const latencySamplesMs: number[] = [];
  const recoverySamplesMs: number[] = [];

  let successCount = 0;
  let failureCount = 0;
  let failureStartMs: number | null = null;
  let lastStepTimestampMs: number | null = null;

  for (const step of orderedSteps) {
    if (step.ok) successCount += 1;
    else failureCount += 1;

    const stepTimestampMs = parseTimestampMs(
      `steps.jsonl action ${step.actionId}`,
      step.timestamp,
      issues
    );
    if (stepTimestampMs !== null) {
      lastStepTimestampMs = stepTimestampMs;
    }

    const createdAtMs = actionCreatedAtMs.get(step.actionId);
    if (createdAtMs === undefined) {
      issues.push(`steps.jsonl action ${step.actionId} is missing in metadata.json actions.`);
    } else if (stepTimestampMs !== null) {
      const latencyMs = stepTimestampMs - createdAtMs;
      if (!Number.isFinite(latencyMs) || latencyMs < 0) {
        issues.push(`Action latency for ${step.actionId} is invalid (${String(latencyMs)}ms).`);
      } else {
        latencySamplesMs.push(latencyMs);
      }
    }

    if (!step.ok) {
      if (failureStartMs === null && stepTimestampMs !== null) {
        failureStartMs = stepTimestampMs;
      }
      continue;
    }

    if (failureStartMs !== null && stepTimestampMs !== null) {
      const recoveryMs = stepTimestampMs - failureStartMs;
      if (!Number.isFinite(recoveryMs) || recoveryMs < 0) {
        issues.push(`Recovery duration is invalid around action ${step.actionId}.`);
      } else {
        recoverySamplesMs.push(recoveryMs);
      }
      failureStartMs = null;
    }
  }

  if (failureStartMs !== null) {
    const recoveryEndMs = lastStepTimestampMs ?? metadataUpdatedAtMs;
    if (recoveryEndMs !== null) {
      const unresolvedRecoveryMs = recoveryEndMs - failureStartMs;
      if (Number.isFinite(unresolvedRecoveryMs) && unresolvedRecoveryMs >= 0) {
        recoverySamplesMs.push(unresolvedRecoveryMs);
      } else {
        issues.push('Unresolved failure recovery duration is invalid.');
      }
    } else {
      issues.push('Unable to compute unresolved failure recovery duration.');
    }
    issues.push('Session ended with an unrecovered failure sequence.');
  }

  const actionCount = orderedSteps.length;
  const metrics: BrowserBenchmarkMetrics = {
    successRate: actionCount === 0 ? 0 : successCount / actionCount,
    medianActionLatencyMs: median(latencySamplesMs),
    recoveryMs: median(recoverySamplesMs),
  };

  validateFiniteMetric('successRate', metrics.successRate, issues);
  validateFiniteMetric('medianActionLatencyMs', metrics.medianActionLatencyMs, issues);
  validateFiniteMetric('recoveryMs', metrics.recoveryMs, issues);

  return {
    ok: issues.length === 0,
    sessionId,
    issues,
    actionCount,
    successCount,
    failureCount,
    latencySamplesMs,
    recoverySamplesMs,
    metrics,
  };
}

function validateFiniteMetric(
  label: keyof BrowserBenchmarkMetrics,
  value: number,
  failures: string[]
): boolean {
  if (Number.isFinite(value)) return true;
  failures.push(`Metric ${label} must be a finite number.`);
  return false;
}

function validateFiniteThreshold(
  label: keyof BrowserBenchmarkThresholds,
  value: number,
  failures: string[]
): boolean {
  if (Number.isFinite(value)) return true;
  failures.push(`Threshold ${label} must be a finite number.`);
  return false;
}

export function validateBrowserBenchmarkThresholds(
  metrics: BrowserBenchmarkMetrics,
  thresholds: BrowserBenchmarkThresholds = DEFAULT_BROWSER_BENCHMARK_THRESHOLDS
): BrowserBenchmarkThresholdResult {
  const failures: string[] = [];

  const hasSuccessRate = validateFiniteMetric('successRate', metrics.successRate, failures);
  const hasMedianLatency = validateFiniteMetric(
    'medianActionLatencyMs',
    metrics.medianActionLatencyMs,
    failures
  );
  const hasRecovery = validateFiniteMetric('recoveryMs', metrics.recoveryMs, failures);

  const hasMinSuccessRate = validateFiniteThreshold(
    'minSuccessRate',
    thresholds.minSuccessRate,
    failures
  );
  const hasMaxMedianLatency = validateFiniteThreshold(
    'maxMedianActionLatencyMs',
    thresholds.maxMedianActionLatencyMs,
    failures
  );
  const hasMaxRecovery = validateFiniteThreshold(
    'maxRecoveryMs',
    thresholds.maxRecoveryMs,
    failures
  );

  if (hasSuccessRate && hasMinSuccessRate && metrics.successRate < thresholds.minSuccessRate) {
    failures.push(
      `successRate ${formatNumber(metrics.successRate)} is below minimum ${formatNumber(thresholds.minSuccessRate)}.`
    );
  }

  if (
    hasMedianLatency &&
    hasMaxMedianLatency &&
    metrics.medianActionLatencyMs > thresholds.maxMedianActionLatencyMs
  ) {
    failures.push(
      `medianActionLatencyMs ${formatNumber(metrics.medianActionLatencyMs)} exceeds maximum ${formatNumber(thresholds.maxMedianActionLatencyMs)}.`
    );
  }

  if (hasRecovery && hasMaxRecovery && metrics.recoveryMs > thresholds.maxRecoveryMs) {
    failures.push(
      `recoveryMs ${formatNumber(metrics.recoveryMs)} exceeds maximum ${formatNumber(thresholds.maxRecoveryMs)}.`
    );
  }

  return {
    ok: failures.length === 0,
    failures,
    metrics,
    thresholds,
  };
}

export async function validateBrowserBenchmarkThresholdFeed(
  cwd: string,
  sessionId: string,
  thresholds: BrowserBenchmarkThresholds = DEFAULT_BROWSER_BENCHMARK_THRESHOLDS
): Promise<BrowserBenchmarkThresholdFeedResult> {
  const ingestion = await ingestBrowserBenchmarkTelemetry(cwd, sessionId);
  const thresholdResult = validateBrowserBenchmarkThresholds(ingestion.metrics, thresholds);
  const failures = [
    ...thresholdResult.failures,
    ...ingestion.issues.map((issue) => `Telemetry ingestion issue: ${issue}`),
  ];

  return {
    ok: failures.length === 0,
    failures,
    metrics: ingestion.metrics,
    thresholds,
    sessionId,
    ingestion,
  };
}

import { readFile, stat } from 'node:fs/promises';
import { isAbsolute, join } from 'node:path';
import {
  browserSessionArtifactsDir,
  browserSessionMetadataPath,
  browserSessionRecordingsPath,
  browserSessionStepsPath,
  browserSessionVisualDiffManifestPath,
  readBrowserVisualDiffResults as readPersistedBrowserVisualDiffResults,
} from './artifacts.js';
import {
  assessVisualDiffPair,
  inferVisualDiffRegression,
  inferVisualDiffSeverity,
} from './visual-diff.js';
import type {
  BrowserArtifactMetadata,
  BrowserSessionMetadata,
  BrowserSessionRecordingEntry,
  BrowserSessionRecordingIndex,
  BrowserSessionStepRecord,
  BrowserVisualDiffManifestEntry,
  BrowserVisualDiffRegressionSignal,
  BrowserVisualDiffResultEntry,
  BrowserVisualDiffResultStatus,
  BrowserVisualDiffSeverity,
} from './types.js';

export interface BrowserReplaySummary {
  sessionId: string;
  runId?: string;
  status: BrowserSessionMetadata['status'];
  runtime: BrowserSessionMetadata['runtime'];
  actionCount: number;
  artifactCount: number;
  failureCount: number;
  lastActionAt: string;
  lastUpdatedAt: string;
  regressionScore: number;
  regressionSignal: BrowserVisualDiffRegressionSignal;
  regressionPairCount: number;
}

export interface BrowserReplayArtifactPreview {
  path: string;
  mimeType?: string;
  sizeBytes?: number;
  htmlSnippet?: string;
  textSnippet?: string;
  inlinePreview?: string[];
  imageWidth?: number;
  imageHeight?: number;
}

export interface BrowserReplayStepArtifactPreview {
  sequence: number;
  artifacts: BrowserReplayArtifactPreview[];
}

export type BrowserReplayVisualDiffStatus = BrowserVisualDiffResultStatus;

export interface BrowserReplayVisualDiffPair {
  index: number;
  fromSequence: number;
  fromActionType: BrowserSessionStepRecord['actionType'];
  toSequence: number;
  toActionType: BrowserSessionStepRecord['actionType'];
  fromScreenshotPath?: string;
  toScreenshotPath?: string;
  status: BrowserReplayVisualDiffStatus;
  changedByteRatio?: number;
  perceptualDiffScore?: number;
  severity: BrowserVisualDiffSeverity;
  regressionScore?: number;
  regressionSignal?: BrowserVisualDiffRegressionSignal;
}

interface BrowserReplayArtifactIndexes {
  byId: Map<string, BrowserArtifactMetadata>;
  byPath: Map<string, BrowserArtifactMetadata>;
  byActionId: Map<string, BrowserArtifactMetadata[]>;
}

interface ResolvedReplayArtifact {
  key: string;
  path: string;
  absolutePath: string;
  kind?: BrowserArtifactMetadata['kind'];
  mimeType?: string;
  sizeBytes?: number;
}

const HTML_SNIPPET_LIMIT = 180;
const TEXT_SNIPPET_LIMIT = 180;
const INLINE_PREVIEW_COLUMNS = 24;
const INLINE_PREVIEW_ROWS = 6;
const INLINE_PREVIEW_PALETTE = ' .:-=+*#%@';

function buildReplayArtifactIndexes(
  metadata: BrowserSessionMetadata | null,
): BrowserReplayArtifactIndexes {
  const byId = new Map<string, BrowserArtifactMetadata>();
  const byPath = new Map<string, BrowserArtifactMetadata>();
  const byActionId = new Map<string, BrowserArtifactMetadata[]>();

  for (const artifact of metadata?.artifacts ?? []) {
    byId.set(artifact.id, artifact);
    byPath.set(artifact.relativePath, artifact);
    byPath.set(artifact.absolutePath, artifact);
    const entries = byActionId.get(artifact.actionId) ?? [];
    entries.push(artifact);
    byActionId.set(artifact.actionId, entries);
  }

  return { byId, byPath, byActionId };
}

function resolveReplayArtifactAbsolutePath(
  cwd: string,
  sessionId: string,
  artifactPath: string,
  absolutePath?: string,
): string {
  if (absolutePath && absolutePath.length > 0) {
    return absolutePath;
  }
  if (isAbsolute(artifactPath)) {
    return artifactPath;
  }
  if (artifactPath.startsWith('.opta/')) {
    return join(cwd, artifactPath);
  }
  return join(browserSessionArtifactsDir(cwd, sessionId), artifactPath);
}

function normalizeHtmlSnippet(value: string): string {
  const compact = value.replace(/\s+/g, ' ').trim();
  if (compact.length <= HTML_SNIPPET_LIMIT) {
    return compact;
  }
  return `${compact.slice(0, HTML_SNIPPET_LIMIT - 3)}...`;
}

function normalizeTextSnippet(value: string): string {
  const compact = value.replace(/\s+/g, ' ').trim();
  if (compact.length <= TEXT_SNIPPET_LIMIT) {
    return compact;
  }
  return `${compact.slice(0, TEXT_SNIPPET_LIMIT - 3)}...`;
}

function isHtmlArtifact(path: string, mimeType?: string): boolean {
  if (mimeType?.toLowerCase() === 'text/html') {
    return true;
  }
  return path.toLowerCase().endsWith('.html');
}

function isScreenshotArtifact(artifact: ResolvedReplayArtifact): boolean {
  if (artifact.kind === 'screenshot') {
    return true;
  }
  if (artifact.mimeType?.toLowerCase().startsWith('image/')) {
    return true;
  }
  const lowerPath = artifact.path.toLowerCase();
  return (
    lowerPath.endsWith('.png') ||
    lowerPath.endsWith('.jpg') ||
    lowerPath.endsWith('.jpeg') ||
    lowerPath.endsWith('.webp') ||
    lowerPath.endsWith('.gif') ||
    lowerPath.endsWith('.bmp')
  );
}

function extractHtmlTextSnippet(html: string): string {
  const withoutScripts = html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ');
  const textOnly = withoutScripts
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
  return normalizeTextSnippet(textOnly);
}

function parsePngDimensions(bytes: Uint8Array): { width: number; height: number } | null {
  if (bytes.length < 24) return null;
  const signature = [0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a];
  for (let index = 0; index < signature.length; index += 1) {
    if (bytes[index] !== signature[index]) return null;
  }
  // PNG IHDR: width/height begin at byte offsets 16/20.
  const view = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);
  const width = view.getUint32(16);
  const height = view.getUint32(20);
  if (width <= 0 || height <= 0) return null;
  return { width, height };
}

function buildInlineBytePreview(
  bytes: Uint8Array,
  columns = INLINE_PREVIEW_COLUMNS,
  rows = INLINE_PREVIEW_ROWS,
): string[] {
  if (bytes.length === 0 || columns <= 0 || rows <= 0) return [];
  const cells = columns * rows;
  const lines: string[] = [];
  for (let row = 0; row < rows; row += 1) {
    let line = '';
    for (let col = 0; col < columns; col += 1) {
      const cellIndex = row * columns + col;
      const start = Math.floor((cellIndex * bytes.length) / cells);
      const end = Math.max(start + 1, Math.floor(((cellIndex + 1) * bytes.length) / cells));
      let sum = 0;
      for (let index = start; index < end && index < bytes.length; index += 1) {
        sum += bytes[index] ?? 0;
      }
      const avg = sum / Math.max(1, end - start);
      const paletteIndex = Math.max(
        0,
        Math.min(
          INLINE_PREVIEW_PALETTE.length - 1,
          Math.floor((avg / 255) * (INLINE_PREVIEW_PALETTE.length - 1)),
        ),
      );
      line += INLINE_PREVIEW_PALETTE[paletteIndex] ?? ' ';
    }
    lines.push(line);
  }
  return lines;
}

function buildVisualDiffPairKey(
  pair: Pick<BrowserVisualDiffResultEntry, 'fromSequence' | 'fromActionId' | 'toSequence' | 'toActionId'>,
): string {
  return `${pair.fromSequence}:${pair.fromActionId}:${pair.toSequence}:${pair.toActionId}`;
}

function resolveReplayStepArtifacts(
  cwd: string,
  step: BrowserSessionStepRecord,
  indexes: BrowserReplayArtifactIndexes,
): ResolvedReplayArtifact[] {
  const resolved: ResolvedReplayArtifact[] = [];
  const seen = new Set<string>();

  const pushArtifact = (artifact: BrowserArtifactMetadata) => {
    const key = artifact.id || artifact.relativePath || artifact.absolutePath;
    if (!key || seen.has(key)) return;
    seen.add(key);
    resolved.push({
      key,
      path: artifact.relativePath || artifact.absolutePath,
      absolutePath: artifact.absolutePath || resolveReplayArtifactAbsolutePath(cwd, step.sessionId, artifact.relativePath),
      kind: artifact.kind,
      mimeType: artifact.mimeType,
      sizeBytes: artifact.sizeBytes,
    });
  };

  const pushPath = (artifactPath: string) => {
    const fromIndex = indexes.byPath.get(artifactPath);
    if (fromIndex) {
      pushArtifact(fromIndex);
      return;
    }
    const key = artifactPath;
    if (seen.has(key)) return;
    seen.add(key);
    resolved.push({
      key,
      path: artifactPath,
      absolutePath: resolveReplayArtifactAbsolutePath(cwd, step.sessionId, artifactPath),
    });
  };

  for (const artifactId of step.artifactIds) {
    const artifact = indexes.byId.get(artifactId);
    if (artifact) {
      pushArtifact(artifact);
    }
  }

  for (const artifactPath of step.artifactPaths) {
    pushPath(artifactPath);
  }

  for (const artifact of indexes.byActionId.get(step.actionId) ?? []) {
    pushArtifact(artifact);
  }

  return resolved;
}

export async function readBrowserReplayStepArtifactPreview(
  cwd: string,
  sessionId: string,
  step: BrowserSessionStepRecord,
  metadata: BrowserSessionMetadata | null = null,
): Promise<BrowserReplayStepArtifactPreview> {
  const replayMetadata = metadata ?? await readBrowserReplay(cwd, sessionId);
  const indexes = buildReplayArtifactIndexes(replayMetadata);
  const artifacts = resolveReplayStepArtifacts(cwd, step, indexes);
  const previews: BrowserReplayArtifactPreview[] = [];

  for (const artifact of artifacts) {
    let sizeBytes = artifact.sizeBytes;
    if (typeof sizeBytes !== 'number') {
      try {
        const fileStat = await stat(artifact.absolutePath);
        sizeBytes = fileStat.size;
      } catch {
        // Keep size undefined when unknown
      }
    }

    let htmlSnippet: string | undefined;
    let textSnippet: string | undefined;
    let inlinePreview: string[] | undefined;
    let imageWidth: number | undefined;
    let imageHeight: number | undefined;

    if (isHtmlArtifact(artifact.path, artifact.mimeType)) {
      try {
        const html = await readFile(artifact.absolutePath, 'utf-8');
        htmlSnippet = normalizeHtmlSnippet(html);
        textSnippet = extractHtmlTextSnippet(html);
      } catch {
        // Keep snippet undefined when file is unreadable
      }
    } else if (isScreenshotArtifact(artifact)) {
      try {
        const bytes = await readFile(artifact.absolutePath);
        inlinePreview = buildInlineBytePreview(bytes);
        const pngDimensions = parsePngDimensions(bytes);
        if (pngDimensions) {
          imageWidth = pngDimensions.width;
          imageHeight = pngDimensions.height;
        }
      } catch {
        // Keep preview undefined when file is unreadable
      }
    }

    previews.push({
      path: artifact.path,
      mimeType: artifact.mimeType,
      sizeBytes,
      htmlSnippet,
      textSnippet,
      inlinePreview,
      imageWidth,
      imageHeight,
    });
  }

  return {
    sequence: step.sequence,
    artifacts: previews,
  };
}

export async function deriveBrowserReplayVisualDiffPairs(
  cwd: string,
  sessionId: string,
  steps: BrowserSessionStepRecord[],
  metadata: BrowserSessionMetadata | null = null,
): Promise<BrowserReplayVisualDiffPair[]> {
  if (steps.length <= 1) {
    return [];
  }

  const persistedResults = await readBrowserReplayVisualDiffResults(cwd, sessionId);
  const persistedResultByKey = new Map<string, BrowserVisualDiffResultEntry>();
  for (const entry of persistedResults) {
    persistedResultByKey.set(buildVisualDiffPairKey(entry), entry);
  }

  const replayMetadata = metadata ?? await readBrowserReplay(cwd, sessionId);
  const indexes = buildReplayArtifactIndexes(replayMetadata);
  const screenshotsByStep = steps.map((step) => {
    const artifacts = resolveReplayStepArtifacts(cwd, step, indexes);
    return artifacts.find((artifact) => isScreenshotArtifact(artifact));
  });
  const bytesByPath = new Map<string, Uint8Array | null>();

  const loadBytes = async (path: string): Promise<Uint8Array | null> => {
    if (bytesByPath.has(path)) {
      return bytesByPath.get(path) ?? null;
    }
    try {
      const bytes = await readFile(path);
      bytesByPath.set(path, bytes);
      return bytes;
    } catch {
      bytesByPath.set(path, null);
      return null;
    }
  };

  const diffs: BrowserReplayVisualDiffPair[] = [];

  for (let index = 1; index < steps.length; index += 1) {
    const fromStep = steps[index - 1]!;
    const toStep = steps[index]!;
    const fromScreenshot = screenshotsByStep[index - 1];
    const toScreenshot = screenshotsByStep[index];
    const persisted = persistedResultByKey.get(
      buildVisualDiffPairKey({
        fromSequence: fromStep.sequence,
        fromActionId: fromStep.actionId,
        toSequence: toStep.sequence,
        toActionId: toStep.actionId,
      }),
    );
    let status: BrowserReplayVisualDiffStatus = persisted?.status ?? 'missing';
    let changedByteRatio = persisted?.changedByteRatio;
    let perceptualDiffScore = persisted?.perceptualDiffScore;
    let severity = persisted?.severity;
    let regressionScore = persisted?.regressionScore;
    let regressionSignal = persisted?.regressionSignal;

    const shouldComputeAssessment = (
      (!persisted) ||
      (
        status === 'changed' &&
        (
          (typeof changedByteRatio !== 'number' || !Number.isFinite(changedByteRatio)) ||
          (typeof perceptualDiffScore !== 'number' || !Number.isFinite(perceptualDiffScore))
        )
      ) ||
      !severity ||
      (typeof regressionScore !== 'number' || !Number.isFinite(regressionScore)) ||
      !regressionSignal
    ) && fromScreenshot && toScreenshot;

    if (shouldComputeAssessment) {
      const [fromBytes, toBytes] = await Promise.all([
        loadBytes(fromScreenshot.absolutePath),
        loadBytes(toScreenshot.absolutePath),
      ]);
      if (fromBytes && toBytes) {
        const assessment = assessVisualDiffPair(fromBytes, toBytes);
        if (!persisted) {
          status = assessment.status;
          changedByteRatio = assessment.changedByteRatio;
          perceptualDiffScore = assessment.perceptualDiffScore;
          severity = assessment.severity;
          regressionScore = assessment.regressionScore;
          regressionSignal = assessment.regressionSignal;
        } else if (assessment.status === status) {
          if (typeof changedByteRatio !== 'number' || !Number.isFinite(changedByteRatio)) {
            changedByteRatio = assessment.changedByteRatio;
          }
          if (typeof perceptualDiffScore !== 'number' || !Number.isFinite(perceptualDiffScore)) {
            perceptualDiffScore = assessment.perceptualDiffScore;
          }
          if (!severity) {
            severity = assessment.severity;
          }
          if (typeof regressionScore !== 'number' || !Number.isFinite(regressionScore)) {
            regressionScore = assessment.regressionScore;
          }
          if (!regressionSignal) {
            regressionSignal = assessment.regressionSignal;
          }
        }
      }
    }

    severity ??= inferVisualDiffSeverity(status, changedByteRatio);
    const regression = inferVisualDiffRegression(
      status,
      severity,
      changedByteRatio,
      perceptualDiffScore,
      regressionScore,
    );
    regressionScore = regression.regressionScore;
    regressionSignal ??= regression.regressionSignal;

    diffs.push({
      index: diffs.length,
      fromSequence: fromStep.sequence,
      fromActionType: fromStep.actionType,
      toSequence: toStep.sequence,
      toActionType: toStep.actionType,
      fromScreenshotPath: fromScreenshot?.path ?? persisted?.fromScreenshotPath,
      toScreenshotPath: toScreenshot?.path ?? persisted?.toScreenshotPath,
      status,
      changedByteRatio,
      perceptualDiffScore,
      severity,
      regressionScore,
      regressionSignal,
    });
  }

  return diffs;
}

export async function readBrowserReplay(
  cwd: string,
  sessionId: string,
): Promise<BrowserSessionMetadata | null> {
  const path = browserSessionMetadataPath(cwd, sessionId);
  try {
    const raw = await readFile(path, 'utf-8');
    const parsed = JSON.parse(raw) as BrowserSessionMetadata;
    return parsed;
  } catch (error) {
    const err = error as NodeJS.ErrnoException;
    if (err.code === 'ENOENT') return null;
    throw error;
  }
}

export async function summarizeBrowserReplay(
  cwd: string,
  sessionId: string,
): Promise<BrowserReplaySummary | null> {
  const metadata = await readBrowserReplay(cwd, sessionId);
  if (!metadata) return null;

  const steps = await readBrowserReplaySteps(cwd, sessionId);
  const recordings = steps.length === 0 || !metadata.runId
    ? await readBrowserReplayRecordings(cwd, sessionId)
    : [];
  const timeline: Array<Pick<BrowserSessionStepRecord, 'timestamp' | 'ok'>> = steps.length > 0
    ? steps
    : recordings;

  const actionCount = timeline.length > 0 ? timeline.length : metadata.actions.length;
  const failureCount = timeline.length > 0
    ? timeline.filter((step) => !step.ok).length
    : metadata.actions.filter((action) => !action.ok).length;
  const lastActionAt = timeline.length > 0
    ? timeline.at(-1)?.timestamp ?? metadata.updatedAt
    : metadata.actions.at(-1)?.action.createdAt ?? metadata.updatedAt;
  const runId = metadata.runId
    ?? steps.find((step) => typeof step.runId === 'string' && step.runId.length > 0)?.runId
    ?? recordings.find((recording) => typeof recording.runId === 'string' && recording.runId.length > 0)?.runId;
  const visualDiffs = steps.length > 1
    ? await deriveBrowserReplayVisualDiffPairs(cwd, sessionId, steps, metadata)
    : [];
  const visualPairs = visualDiffs.filter((pair) => Boolean(pair.fromScreenshotPath || pair.toScreenshotPath));
  const regressionPairCount = visualPairs.filter((pair) => pair.regressionSignal === 'regression').length;
  const regressionScore = visualPairs.reduce((max, pair) => (
    typeof pair.regressionScore === 'number' && Number.isFinite(pair.regressionScore)
      ? Math.max(max, pair.regressionScore)
      : max
  ), 0);
  const regressionSignal: BrowserVisualDiffRegressionSignal = regressionPairCount > 0
    ? 'regression'
    : visualPairs.some((pair) => pair.regressionSignal === 'investigate')
      ? 'investigate'
      : 'none';

  return {
    sessionId: metadata.sessionId,
    runId,
    status: metadata.status,
    runtime: metadata.runtime,
    actionCount,
    artifactCount: metadata.artifacts.length,
    failureCount,
    lastActionAt,
    lastUpdatedAt: metadata.updatedAt,
    regressionScore,
    regressionSignal,
    regressionPairCount,
  };
}

export async function readBrowserReplaySteps(
  cwd: string,
  sessionId: string,
): Promise<BrowserSessionStepRecord[]> {
  const path = browserSessionStepsPath(cwd, sessionId);
  try {
    const raw = await readFile(path, 'utf-8');
    const lines = raw.split(/\r?\n/);
    const entries: BrowserSessionStepRecord[] = [];

    for (let index = 0; index < lines.length; index += 1) {
      const line = lines[index]?.trim();
      if (!line) continue;

      try {
        const parsed = JSON.parse(line) as BrowserSessionStepRecord;
        entries.push(parsed);
      } catch (error) {
        const isTrailingLine = index === lines.length - 1;
        if (isTrailingLine) {
          continue;
        }
        throw error;
      }
    }

    return entries;
  } catch (error) {
    const err = error as NodeJS.ErrnoException;
    if (err.code === 'ENOENT') {
      const recordings = await readBrowserReplayRecordings(cwd, sessionId);
      return recordings.map((recording) => ({
        sequence: recording.sequence,
        sessionId: recording.sessionId,
        runId: recording.runId,
        actionId: recording.actionId,
        actionType: recording.actionType,
        timestamp: recording.timestamp,
        ok: recording.ok,
        error: recording.error,
        artifactIds: recording.artifactIds,
        artifactPaths: recording.artifactPaths,
      }));
    }
    throw error;
  }
}

export async function readBrowserReplayRecordings(
  cwd: string,
  sessionId: string,
): Promise<BrowserSessionRecordingEntry[]> {
  const path = browserSessionRecordingsPath(cwd, sessionId);
  try {
    const raw = await readFile(path, 'utf-8');
    const parsed = JSON.parse(raw) as BrowserSessionRecordingIndex;
    if (!Array.isArray(parsed.recordings)) {
      return [];
    }

    return [...parsed.recordings].sort((left, right) => left.sequence - right.sequence);
  } catch (error) {
    const err = error as NodeJS.ErrnoException;
    if (err.code === 'ENOENT') return [];
    throw error;
  }
}

