}

function toTuiTurnError(payload: unknown): TuiErrorEvent {
  if (typeof payload === 'string' && payload.length > 0) {
    return payload;
  }

  const record =
    payload && typeof payload === 'object' ? (payload as Record<string, unknown>) : undefined;
  const message =
    typeof record?.['message'] === 'string' && record['message'].length > 0
      ? record['message']
      : 'Turn failed';
  const code =
    typeof record?.['code'] === 'string' && record['code'].length > 0 ? record['code'] : undefined;

  const structured: TuiErrorPayload = code ? { message, code } : { message };
  return structured;
}

type LmxClientOptions = {
  host: string;
  fallbackHosts: string[];
  port: number;
  adminKey: string | undefined;
  adminKeysByHost?: Record<string, string>;
  timeoutMs: number;
  maxRetries: number;
};

type LmxClientLike = {
  models: (options?: {
    timeoutMs?: number;
    maxRetries?: number;
  }) => Promise<{ models: Array<{ model_id: string }> }>;
};

async function createLmxClient(options: LmxClientOptions): Promise<LmxClientLike> {
  const { LmxClient } = await import('../lmx/client.js');
  try {
    return new (LmxClient as unknown as new (options: LmxClientOptions) => LmxClientLike)(options);
  } catch (err) {
    if (
      err instanceof TypeError &&
      typeof err.message === 'string' &&
      err.message.includes('is not a constructor')
    ) {
      return (LmxClient as unknown as (options: LmxClientOptions) => LmxClientLike)(options);
    }
    throw err;
  }
}

async function ensureModelLoadedOnLmxStartup(
  config: Awaited<ReturnType<typeof loadConfig>>,
  modelId: string,
  preflight: ModelPreflightStatus
): Promise<ModelPreflightStatus> {
  if ((config.provider?.active ?? 'lmx') === 'anthropic') {
    return preflight;
  }

  if (preflight.modelLoaded) return preflight;

  try {
    const lifecycleModule = await import('../lmx/model-lifecycle.js');
    const lmxClient = (await createLmxClient({
      host: config.connection.host,
      fallbackHosts: config.connection.fallbackHosts,
      port: config.connection.port,
      adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
      timeoutMs: 8_000,
      maxRetries: 0,
    })) as LmxLifecycleClient;

    const preloadedModelId = preflight.loadedModelIds.find((candidate) =>
      modelIdsEqual(candidate, modelId)
    );
    const ensureId = await lifecycleModule.ensureModelLoaded(lmxClient as never, modelId, {
      preloadedModelId,
      timeoutMs: 120_000,
      onProgress: () => {},
    });

    return {
      modelLoaded: true,
      loadedModelIds: [...new Set([ensureId, ...preflight.loadedModelIds])],
    };
  } catch (err) {
    const previousError = preflight.error;
    const nextError = errorMessage(err);
    return {
      ...preflight,
      modelLoaded: false,
      loadedModelIds: preflight.loadedModelIds,
      error: previousError ? `${previousError} | ${nextError}` : nextError,
    };
  }
}

async function probeModelPreflight(
  config: Awaited<ReturnType<typeof loadConfig>>,
  modelId: string
): Promise<ModelPreflightStatus> {
  // When running on Anthropic (zero-config fallback or explicit config), the
  // model is always "loaded" from the CLI's perspective — no LMX probe needed.
  if ((config.provider?.active ?? 'lmx') === 'anthropic') {
    return { modelLoaded: true, loadedModelIds: [modelId] };
  }

  try {
    const lmx = await createLmxClient({
      host: config.connection.host,
      fallbackHosts: config.connection.fallbackHosts,
      port: config.connection.port,
      adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
      timeoutMs: 8_000,
      maxRetries: 0,
    });
    const loaded = await lmx.models();
    const loadedModelIds = loaded.models.map((item) => item.model_id);
    const modelLoaded = loadedModelIds.some((candidate) => modelIdsEqual(candidate, modelId));
    return { modelLoaded, loadedModelIds };
  } catch (err) {
    return { modelLoaded: false, loadedModelIds: [], error: errorMessage(err) };
  }
}

async function runChatDiskPreflight(
  config: Awaited<ReturnType<typeof loadConfig>>,
  jsonMode: boolean
): Promise<void> {
  try {
    await ensureDiskHeadroom(OPTA_CONFIG_DIR, {
      minFreeBytes: diskHeadroomMbToBytes(config.safety?.diskHeadroomMb),
    });
  } catch (err) {
    if (!isStorageRelatedError(err)) throw err;
    const message = errorMessage(err);
    if (!jsonMode) {
      console.error(chalk.red('✗') + ` ${message}`);
      console.error(chalk.dim('  Free disk space and rerun the command.'));
    }
    throw new ExitError(EXIT.ERROR);
  }
}

export async function startChat(opts: ChatOptions): Promise<void> {
  const overrides = buildConfigOverrides(opts);

  const jsonMode = opts.format === 'json';
  let config = await loadConfig(overrides);
  await runChatDiskPreflight(config, jsonMode);

  // First-run onboarding + project scaffold.
  if (!jsonMode) {
    const { isFirstRun, runOnboarding } = await import('./onboard.js');
    if (await isFirstRun()) {
      await runOnboarding();
      const { ensureInitScaffold } = await import('./init.js');
      await ensureInitScaffold(
        {
          yes: true,
          force: false,
          createApp: true,
        },
        process.cwd(),
      );

      // Reload config in case onboarding changed connection settings
      config = await loadConfig(overrides);
    }
  }

  // Zero-config fallback: probe LMX before the first turn.
  // If LMX is unreachable and ANTHROPIC_API_KEY is set, silently switch to
  // Anthropic so fresh installs with only an API key work out of the box.
  // Only probe when provider is 'lmx' (default) — skip if user explicitly
  // configured Anthropic or if we're in JSON (pipe) mode where silence matters.
  if ((config.provider?.active ?? 'lmx') === 'lmx') {
    try {
      const { probeProvider } = await import('../providers/manager.js');
      const probed = await probeProvider(config);
      if (probed.name === 'anthropic') {
        // LMX unreachable — route the whole session through Anthropic.
        // Always derive the model from provider.anthropic.model (or the
        // well-known default) so we don't keep an LMX model string.
        const anthropicDefault = config.provider.anthropic?.model || 'claude-sonnet-4-5-20250929';
        config = {
          ...config,
          provider: {
            ...config.provider,
            active: 'anthropic',
          },
          model: {
            ...config.model,
            default: anthropicDefault,
            contextLimit: 200_000,
          },
        };
      }
    } catch (err) {
      // probeProvider threw — means both LMX unreachable AND no ANTHROPIC_API_KEY.
      // Re-throw so the CLI framework handles graceful exit with cleanup.
      throw err;
    }
  }

  let effectiveModel = normalizeConfiguredModelId(config.model.default);
  if (effectiveModel !== config.model.default) {
    await saveConfig({
      'model.default': effectiveModel,
      'model.contextLimit': effectiveModel ? config.model.contextLimit : 32768,
    }).catch(() => {});
    config = {
      ...config,
      model: {
        ...config.model,
        default: effectiveModel,
        contextLimit: effectiveModel ? config.model.contextLimit : 32768,
      },
    };
  }

  if (!effectiveModel) {
    try {
      const { lookupContextLimit } = await import('../lmx/client.js');
      const lmx = await createLmxClient({
        host: config.connection.host,
        fallbackHosts: config.connection.fallbackHosts,
        port: config.connection.port,
        adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
        timeoutMs: 5_000,
        maxRetries: 0,
      });
      const loaded = await lmx.models();
      const fallback = loaded.models[0]?.model_id;
      if (fallback) {
        effectiveModel = fallback;
        await saveConfig({
          'model.default': fallback,
          'model.contextLimit': lookupContextLimit(fallback),
        }).catch(() => {});
        config = {
          ...config,
          model: {
            ...config.model,
            default: fallback,
            contextLimit: lookupContextLimit(fallback),
          },
        };
        if (!jsonMode) {
          console.log(chalk.yellow('!') + ` No default model set; using loaded model ${fallback}`);
        }
      }
    } catch {
      // Ignore model discovery failures; we'll show actionable guidance below.
    }
  }

  ensureModel(effectiveModel);

  // Capability gate — mirrors opta do's cli.run check for chat access control.
  // Only applies when the user is authenticated; unauthenticated users are allowed
  // through so local-only setups without an Opta Account are never blocked.
  // Gracefully allows access when the capability check itself is unavailable (offline).
  {
    const { loadAccountState } = await import('../accounts/storage.js');
    const { evaluateCapability } = await import('../accounts/cloud.js');
    const accountState = await loadAccountState();
    if (accountState?.session) {
      const gate = await evaluateCapability(accountState, 'cli.chat', accountState.deviceId);
      if (!gate.allow && gate.reason !== 'capability_check_unavailable') {
        const message = `Capability denied for cli.chat${gate.reason ? ` (${gate.reason})` : ''}`;
        if (jsonMode) {
          console.log(JSON.stringify({ error: message, exit_code: EXIT.PERMISSION }));
        } else {
          console.error(chalk.red('✗') + ` ${message}`);
        }
        throw new ExitError(EXIT.PERMISSION);
      }
    }
  }

  // Create or resume session
  let session: Session;
  let startupModelLoaded = false;
  let startupPreflightError: string | undefined;
  if (opts.resume) {
    try {
      session = await loadSession(opts.resume);
    } catch {
      // Exact ID not found — try fuzzy search
      const matches = await searchSessions(opts.resume);
      if (matches.length === 1) {
        session = await loadSession(matches[0]!.id);
      } else if (matches.length > 1) {
        try {
          const { select } = await import('@inquirer/prompts');
          const choice = await runMenuPrompt(
            (context) =>
              select(
                {
                  message: chalk.dim(`Multiple sessions match "${opts.resume}"`),
                  choices: matches.slice(0, 10).map((m) => ({
                    name: `${m.title || m.id.slice(0, 8)}  ${chalk.dim(m.model || '')}  ${chalk.dim(new Date(m.created).toLocaleDateString())}${m.tags?.length ? '  ' + chalk.cyan(m.tags.join(', ')) : ''}`,
                    value: m.id,
                  })),
                },
                context
              ),
            'select'
          );
          if (!choice) return;
          session = await loadSession(choice);
        } catch {
          // Ctrl+C — exit gracefully
          return;
        }
      } else {
        console.error(
          chalk.red('✗') +
            ` Session not found: ${opts.resume}\n\n` +
            chalk.dim('Run ') +
            chalk.cyan('opta sessions') +
            chalk.dim(' to list available sessions')
        );
        throw new ExitError(EXIT.NOT_FOUND);
      }
    }
    const startupPreflight = await ensureModelLoadedOnLmxStartup(
      config,
      session.model,
      await probeModelPreflight(config, session.model),
    );
    startupModelLoaded = startupPreflight.modelLoaded;
    startupPreflightError = startupPreflight.error;

    if (!jsonMode) {
      const msgCount = session.messages.filter((m) => m.role !== 'system').length;
      const providerLabel =
        (config.provider?.active ?? 'lmx') === 'anthropic' ? 'Anthropic' : 'LMX';
      const providerValue =
        (config.provider?.active ?? 'lmx') === 'anthropic'
          ? `api.anthropic.com ${statusDot(startupModelLoaded)}`
          : `${config.connection.host}:${config.connection.port} ${statusDot(startupModelLoaded)}`;
      console.log(
        '\n' +
          box('Opta', [
            kv(providerLabel, providerValue),
            kv('Model', session.model),
            kv('Session', `${session.id.slice(0, 8)} ${chalk.dim('(resumed)')}`),
            ...(session.title ? [kv('Title', chalk.italic(session.title.slice(0, 40)))] : []),
            kv('Messages', String(msgCount)),
          ])
      );
    }
  } else {
    session = await createSession(config.model.default);
    // Initialize system prompt for new session
    const systemPrompt = await buildSystemPrompt(config);
    session.messages = [{ role: 'system', content: systemPrompt }];
    await saveSession(session);

    const startupPreflight = await ensureModelLoadedOnLmxStartup(
      config,
      session.model,
      await probeModelPreflight(config, session.model),
    );
    startupModelLoaded = startupPreflight.modelLoaded;
    startupPreflightError = startupPreflight.error;

    if (!jsonMode) {
      const providerLabel =
        (config.provider?.active ?? 'lmx') === 'anthropic' ? 'Anthropic' : 'LMX';
      const providerValue =
        (config.provider?.active ?? 'lmx') === 'anthropic'
          ? `api.anthropic.com ${statusDot(startupModelLoaded)}`
          : `${config.connection.host}:${config.connection.port} ${statusDot(startupModelLoaded)}`;
      console.log(
        '\n' +
          box('Opta', [
            kv(providerLabel, providerValue),
            kv('Model', session.model),
            kv('Session', `${session.id.slice(0, 8)} ${chalk.dim('(new)')}`),
          ])
      );
    }
  }

  if (!jsonMode) {
    console.log(chalk.dim('  Type /help for commands, / to browse, /exit to quit\n'));
  }

  // Non-blocking startup connection check (fire-and-forget)
  if (!jsonMode) {
    const { host, port } = config.connection;
    runConnectionDiagnostics(host, port)
      .then((results) => {
        const hasError = results.some((r) => r.status === 'error');
        const hasWarning = results.some((r) => r.status === 'warning');
        if (hasError || hasWarning) {
          console.log(formatDiagnostics(results));
          console.log('');
        }
      })
      .catch(() => {
        // Silently ignore diagnostic failures — don't disrupt the REPL
      });
  }

  // Mode state (shared by both TUI and REPL modes)
  const chatState: ChatState = {
    currentMode: opts.plan
      ? 'plan'
      : opts.review
        ? 'review'
        : opts.research
          ? 'research'
          : opts.auto
            ? 'auto-accept'
            : 'normal',
    agentProfile: 'default',
  };
  if (opts.dangerous || opts.yolo) chatState.currentMode = 'normal'; // dangerous handled by config mode

  async function saveSessionWithJournal(): Promise<string | null> {
    await saveSession(session);

    const journal = config.journal;
    // loadConfig returns defaults in production, but treat missing journal config
    // as enabled to preserve backward-compatible session logging in partial test stubs.
    if (!(journal?.enabled ?? true)) return null;

    try {
      const written = await writeSessionLog(session, {
        cwd: session.cwd || process.cwd(),
        logsDir: journal?.sessionLogsDir,
        timezone: journal?.timezone,
        user: journal?.author,
      });
      return written.path;
    } catch {
      return null;
    }
  }

  // TUI mode: full-screen Ink rendering (--tui flag or tui.default config)
  if (opts.tui || config.tui.default) {
    const { renderTUI } = await import('../tui/render.js');
    const { createTuiEmitter } = await import('../tui/adapter.js');
    const { captureConsoleOutput } = await import('../tui/capture.js');
    const { DaemonClient } = await import('../daemon/client.js');
    const { nanoid } = await import('nanoid');

    const emitter = createTuiEmitter();
    const daemon = await DaemonClient.connect();
    const clientId = `tui-${process.pid}-${nanoid(6)}`;
    const writerId = `writer-${nanoid(6)}`;
    const nonSystemMessageCount = session.messages.filter((m) => m.role !== 'system').length;
    const startupMessages: TuiMessage[] = startupModelLoaded
      ? [
          {
            role: 'assistant',
            content: buildStartupIntro(session.model, Boolean(opts.resume), nonSystemMessageCount),
            createdAt: Date.now(),
          },
        ]
      : [
          {
            role: 'error',
            content: startupPreflightError
              ? `No Model Loaded - Use Opta Menu to begin.\nLMX preflight failed: ${startupPreflightError}`
              : 'No Model Loaded - Use Opta Menu to begin.',
            createdAt: Date.now(),
          },
        ];
    await daemon.createSession({
      sessionId: session.id,
      model: session.model,
      title: session.title,
      messages: session.messages,
    });

    // Track the current workflow mode set by the TUI (Shift+Tab).
    // Updated via onModeChange callback and used on next agent call.
    let currentTuiMode = 'normal';
    let turnInFlight = false;
    let activeTurnId: string | undefined;
    let localCancelRequested = false;
    let lastSeq = 0;
    let closed = false;
    let closeSocket = () => {};
    let reconnectDelayMs = 500;
    let reconnectTimerId: ReturnType<typeof setTimeout> | undefined;
    const MAX_RECONNECT_DELAY_MS = 5000;

    const reconnect = () => {
      emitter.emit('connection:status', 'reconnecting');
      if (closed) return;
      const conn = daemon.connectWebSocket(session.id, lastSeq, {
        onOpen: () => {
          reconnectDelayMs = 500;
          if (reconnectTimerId !== undefined) {
            clearTimeout(reconnectTimerId);
            reconnectTimerId = undefined;
          }
          emitter.emit('connection:status', 'connected');
        },
        onClose: () => {
          if (closed) return;
          emitter.emit('connection:status', 'disconnected');
          const delay = reconnectDelayMs;
          reconnectDelayMs = Math.min(Math.floor(reconnectDelayMs * 1.6), MAX_RECONNECT_DELAY_MS);
          if (reconnectTimerId !== undefined) {
            clearTimeout(reconnectTimerId);
          }
          reconnectTimerId = setTimeout(reconnect, delay);
        },
        onError: (err) => {
          emitter.emit('error', `Daemon stream error: ${errorMessage(err)}`);
        },
        onEvent: (event) => {
          lastSeq = Math.max(lastSeq, event.seq);
          const payload = event.payload as Record<string, unknown>;
          switch (event.event) {
            case 'turn.queued': {
              const turnId = typeof payload['turnId'] === 'string' ? payload['turnId'] : undefined;
              if (turnId) activeTurnId = turnId;
              break;
            }
            case 'turn.start':
              if (localCancelRequested) break;
              activeTurnId =
                typeof payload['turnId'] === 'string' ? payload['turnId'] : activeTurnId;
              emitter.emit('turn:start');
              break;
            case 'turn.token':
              if (localCancelRequested) break;
              if (typeof payload['text'] === 'string') {
                emitter.emit('token', payload['text']);
              }
              break;
            case 'turn.thinking':
              if (localCancelRequested) break;
              if (typeof payload['text'] === 'string') {
                emitter.emit('thinking', payload['text']);
              }
              break;
            case 'tool.start':
              if (localCancelRequested) break;
              emitter.emit(
                'tool:start',
                typeof payload['name'] === 'string' ? payload['name'] : 'tool',
                typeof payload['id'] === 'string' ? payload['id'] : 'tool',
                typeof payload['args'] === 'string' ? payload['args'] : '{}'
              );
              break;
            case 'tool.end':
              if (localCancelRequested) break;
              emitter.emit(
                'tool:end',
                typeof payload['name'] === 'string' ? payload['name'] : 'tool',
                typeof payload['id'] === 'string' ? payload['id'] : 'tool',
                typeof payload['result'] === 'string' ? payload['result'] : ''
              );
              break;
            case 'permission.request':
              emitter.emit('permission:request', {
                id: typeof payload['requestId'] === 'string' ? payload['requestId'] : '',
                toolName: typeof payload['toolName'] === 'string' ? payload['toolName'] : 'tool',
                args: (payload['args'] as Record<string, unknown>) ?? {},
              });
              break;
            case 'turn.done': {
              localCancelRequested = false;
              turnInFlight = false;
              activeTurnId = undefined;
              const stats = payload['stats'] as Record<string, unknown> | undefined;
              emitter.emit('turn:end', {
                tokens: Number(stats?.['tokens'] ?? 0),
                promptTokens: Number(stats?.['promptTokens'] ?? 0),
                completionTokens: Number(stats?.['completionTokens'] ?? 0),
                toolCalls: Number(stats?.['toolCalls'] ?? 0),
                elapsed: Number(stats?.['elapsed'] ?? 0),
                speed: Number(stats?.['speed'] ?? 0),
                firstTokenLatencyMs:
                  stats?.['firstTokenLatencyMs'] == null
                    ? null
                    : Number(stats['firstTokenLatencyMs']),
              });
              void daemon
                .getSession(session.id)
                .then((remote) => {
                  const remoteMessages = (remote.messages ?? []) as AgentMessage[];
                  session.messages = remoteMessages;
                  session.toolCallCount = remote.toolCallCount ?? session.toolCallCount;
                  return saveSession(session);
                })
                .catch(() => {});
              break;
            }
            case 'turn.error':
              turnInFlight = false;
              activeTurnId = undefined;
              if (!localCancelRequested) {
                emitter.emit('error', toTuiTurnError(payload));
              }
              localCancelRequested = false;
              break;
            case 'session.cancelled':
              turnInFlight = false;
              activeTurnId = undefined;
              if (!localCancelRequested) {
                emitter.emit('error', '⏹ Turn cancelled');
              }
              localCancelRequested = false;
              break;
            default:
              break;
          }
        },
      });
      closeSocket = conn.close;
    };

    reconnect();

    const onPermissionResponse = (
      id: string,
      decision: import('../tui/PermissionPrompt.js').PermissionDecision
    ) => {
      const mapped = decision === 'deny' ? 'deny' : 'allow';
      void daemon
        .resolvePermission(session.id, {
          requestId: id,
          decision: mapped,
          decidedBy: clientId,
        })
        .catch((err: unknown) => {
          emitter.emit('error', `Permission resolution failed: ${errorMessage(err)}`);
        });
    };
    emitter.on('permission:response', onPermissionResponse);

    await renderTUI({
      model: session.model,
      sessionId: session.id,
      emitter,
      initialMessages: startupMessages,
      requireLoadedModel: true,
      initialModelLoaded: startupModelLoaded,
      title: session.title,
      onModeChange: (mode) => {
        currentTuiMode = mode;
      },
      onCancelTurn: () => {
        if (!turnInFlight) return;
        const turnIdToCancel = activeTurnId;
        turnInFlight = false;
        activeTurnId = undefined;
        localCancelRequested = true;
        emitter.emit('error', '⏹ Turn cancelled');
        void daemon
          .cancel(session.id, { turnId: turnIdToCancel, writerId })
          .catch((err: unknown) => {
            localCancelRequested = false;
            emitter.emit('error', `Cancel failed: ${errorMessage(err)}`);
          });
      },
      onSubmit: (text: string) => {
        if (turnInFlight) {
          emitter.emit(
            'error',
            'A turn is already running. Wait for it to finish before sending another message.'
          );
          return;
        }
        // Fire-and-forget: the emitter events drive the TUI updates
        (async () => {
          turnInFlight = true;
          // Resolve @file and @image references before sending to agent
          const { refs } = await resolveFileRefs(text);
          const { cleanMessage, images } = await resolveImageRefs(text);
          const enrichedInput = buildContextWithRefs(images.length > 0 ? cleanMessage : text, refs);

          // Generate session title from first user message
          if (!session.title) {
            session.title = generateTitle(text);
            emitter.emit('title', session.title);
          }

          const queued = await daemon.submitTurn(session.id, {
            clientId,
            writerId,
            content: enrichedInput,
            mode: 'chat',
            metadata: {
              workflowMode: currentTuiMode,
              imageCount: images.length,
            },
          });
          activeTurnId = queued.turnId;
        })()
          .catch(() => {
            turnInFlight = false;
            emitter.emit('error', 'Failed to submit turn to daemon');
          })
          .finally(() => {
            // Reset happens on turn.done / turn.error to preserve in-flight guard.
          });
      },
      onSlashCommand: async (input: string) => {
        // Bare `/` opens interactive browser in REPL mode, but in TUI mode
        // redirect to /help since @inquirer/prompts doesn't work here.
        const effectiveInput = input.trim() === '/' ? '/help' : input;

        const { result, output } = await captureConsoleOutput(async () => {
          return dispatchSlashCommand(effectiveInput, { session, config, chatState });
        });

        // Persist session after slash command (some modify session state)
        await saveSession(session);

        // If model was switched, reload config
        let newModel: string | undefined;
        if (result === 'model-switched') {
          config = await loadConfig(overrides);
          newModel = config.model.default;
        }

        return { result, output, newModel };
      },
    });
    closed = true;
    emitter.off('permission:response', onPermissionResponse);
    closeSocket();

    const logPath = await saveSessionWithJournal();
    if (!jsonMode) {
      const msgCount = session.messages.filter((m) => m.role !== 'system').length;
      console.log(
        '\n' +
          chalk.green('✓') +
          chalk.dim(` Session saved: ${session.id.slice(0, 8)} · ${msgCount} msgs`)
      );
      if (logPath) {
        console.log(chalk.dim(`  Session log: ${logPath}`));
      }
    }
    return;
  }

  /** Map OptaMode to InputEditor mode string. */
  function toEditorMode(mode: OptaMode): 'normal' | 'plan' | 'auto' {
    if (mode === 'plan' || mode === 'review' || mode === 'research') return 'plan';
    if (mode === 'auto-accept') return 'auto';
    return 'normal';
  }

  // InputEditor for buffer management and mode detection
  const editor = new InputEditor({
    prompt: '>',
    mode: toEditorMode(chatState.currentMode),
  });

  // Input history with deduplication
  const history = new InputHistory();

  function getPromptMessage(): string {
    // Sync editor mode with chat state
    editor.setMode(toEditorMode(chatState.currentMode));
    return editor.getPromptDisplay();
  }

  // Start periodic connection monitor for REPL prompt indicator (text REPL only)
  const stopConnectionMonitor = jsonMode
    ? () => {}
    : startConnectionMonitor(
        config.connection.host,
        config.connection.port,
        config.connection.fallbackHosts,
        config.connection.adminKey
      );

  // Initialize slash command TAB completion cache (non-blocking)
  import('../ui/autocomplete.js')
    .then(({ initSlashCompletionCache }) => {
      initSlashCompletionCache().catch(() => {});
    })
    .catch(() => {});

  // REPL loop
  const { input } = await import('@inquirer/prompts');
  let queuedInput = opts.initialPrompt?.trim() ?? '';

  while (true) {
    let userInput: string;
    if (queuedInput) {
      userInput = queuedInput;
      queuedInput = '';
      if (!jsonMode) {
        console.log(chalk.dim(`${getPromptMessage()} ${userInput}`));
      }
    } else {
      try {
        userInput = await input({ message: getPromptMessage() });
      } catch {
        // Ctrl+C or EOF
        stopConnectionMonitor();
        const logPath = await saveSessionWithJournal();
        if (!jsonMode) {
          const msgCount = session.messages.filter((m) => m.role !== 'system').length;
          console.log(
            '\n' +
              chalk.green('✓') +
              chalk.dim(` Session saved: ${session.id.slice(0, 8)} · ${msgCount} msgs`)
          );
          if (logPath) {
            console.log(chalk.dim(`  Session log: ${logPath}`));
          }
        }
        break;
      }
    }

    if (!userInput.trim()) continue;

    // Track input in history
    history.push(userInput);

    // Slash commands
    if (userInput.startsWith('/')) {
      const handled = await dispatchSlashCommand(userInput, { session, config, chatState });
      if (handled === 'exit') {
        stopConnectionMonitor();
        const logPath = await saveSessionWithJournal();
        if (!jsonMode) {
          const msgCount = session.messages.filter((m) => m.role !== 'system').length;
          console.log(
            chalk.green('✓') +
              chalk.dim(` Session saved: ${session.id.slice(0, 8)}`) +
              (session.title ? chalk.dim(` "${session.title}"`) : '') +
              chalk.dim(` · ${msgCount} msgs`)
          );
          if (logPath) {
            console.log(chalk.dim(`  Session log: ${logPath}`));
          }
        }
        break;
      }
      if (handled === 'model-switched') {
        // Reload config to pick up model change
        config = await loadConfig(overrides);
        continue;
      }
      if (typeof handled === 'object' && handled !== null && 'type' in handled && handled.type === 'generate') {
        userInput = handled.prompt;
      } else {
        continue;
      }
    }

    // Shell mode: !command executes directly
    if (userInput.startsWith('!')) {
      const cmd = userInput.slice(1).trim();
      if (!cmd) continue;
      console.log(chalk.dim(`  $ ${cmd}`));
      try {
        const { execSync } = await import('node:child_process');
        const output = execSync(cmd, { encoding: 'utf-8', cwd: process.cwd(), timeout: 30000 });
        if (output.trim()) console.log(output);
        console.log(chalk.green('✓') + chalk.dim(' exit 0'));
      } catch (err: unknown) {
        const e = err as { status?: number; stderr?: string; stdout?: string };
        if (e.stdout) console.log(e.stdout);
        if (e.stderr) {
          let stderr = e.stderr;
          // Strip ANSI codes if output is not a TTY
          if (!process.stdout.isTTY) {
            stderr = stderr.replace(/\x1B\[[0-9;]*[a-zA-Z]/g, '');
          }
          console.error(chalk.red(truncateStderr(stderr)));
        }
        console.log(chalk.red('✗') + chalk.dim(` exit ${e.status ?? 1}`));
      }
      continue;
    }

    // Show @ file autocomplete hints (lightweight — full interactive autocomplete in Phase 2)
    if (userInput.includes('@') && !userInput.startsWith('/')) {
      const { getProjectFiles, getCompletions } = await import('../ui/autocomplete.js');
      const atMatch = userInput.match(/@(\S*)$/);
      if (atMatch?.[1]) {
        const files = await getProjectFiles(process.cwd());
        const matches = getCompletions(atMatch[1], files, 5);
        if (matches.length > 0 && matches[0] !== atMatch[1]) {
          console.log(
            chalk.dim('  Matches: ') + matches.map((f) => chalk.cyan(`@${f}`)).join(chalk.dim(', '))
          );
        }
      }
    }

    // Resolve @file and @image references
    const { refs } = await resolveFileRefs(userInput);
    const { cleanMessage, images } = await resolveImageRefs(userInput);
    const enrichedInput = buildContextWithRefs(images.length > 0 ? cleanMessage : userInput, refs);

    // Set title from first user message
    if (!session.title) {
      session.title = generateTitle(userInput);
    }

    try {
      const result = await agentLoop(enrichedInput, config, {
        existingMessages: session.messages,
        sessionId: session.id,
        silent: jsonMode,
        mode:
          chatState.currentMode !== 'normal' && chatState.currentMode !== 'auto-accept'
            ? chatState.currentMode
            : undefined,
        profile: chatState.agentProfile !== 'default' ? chatState.agentProfile : undefined,
        images:
          images.length > 0
            ? images.map((img) => ({ base64: img.base64, mimeType: img.mimeType, name: img.name }))
            : undefined,
      });

      session.messages = result.messages;
      session.toolCallCount += result.toolCallCount;
      // Track thinking renderer for /expand toggle
      if (result.lastThinkingRenderer) {
        chatState.lastThinkingRenderer = result.lastThinkingRenderer;
        chatState.thinkingExpanded = false;
      }
      await saveSession(session);

      const assistantMessage = result.messages[result.messages.length - 1];
      if (assistantMessage?.role === 'assistant' && typeof assistantMessage.content === 'string') {
        const { handleGenUIResponse } = await import('../ui/genui-manager.js');
        const genuiEnabled = config.genui?.enabled !== false;
        const autoOpen = config.genui?.autoOpenBrowser !== false;

        if (genuiEnabled) {
          const genuiResult = await handleGenUIResponse(assistantMessage.content, 'genui', autoOpen);
          if (genuiResult) {
            console.log(chalk.dim(`\n  GenUI Artifact saved: ${genuiResult.filePath}`));
            if (genuiResult.opened) {
              console.log(chalk.dim(`  Opened automatically in browser.`));
            }
          }
        }
      }

      if (jsonMode) {
        console.log(formatChatJsonLine(result.messages));
      }
    } catch (err) {
      if (err instanceof OptaError) {
        console.error(formatError(err));
      } else {
        console.error(chalk.red('✗') + ` ${errorMessage(err)}`);
      }
    }
  }
}

import chalk from 'chalk';
import { loadConfig, getConfigStore, OptaConfigSchema } from '../core/config.js';
import { EXIT, ExitError, OptaError } from '../core/errors.js';
import { parseAdminKeysByHost } from '../lmx/admin-keys.js';
import { errorMessage } from '../utils/errors.js';
import { box, kv } from '../ui/box.js';
import type { PaneMenuSection } from '../ui/pane-menu.js';
import { runMenuPrompt } from '../ui/prompt-nav.js';

interface ConfigOptions {
  json?: boolean;
}

function isSensitiveConfigKey(key: string): boolean {
  const k = key.toLowerCase();
  return (
    k.includes('apikey') ||
    k.includes('api_key') ||
    k.includes('token') ||
    k.includes('secret') ||
    k.includes('password') ||
    k.endsWith('.key') ||
    k.includes('adminkey')
  );
}

function unknownToStr(v: unknown, fallback = ''): string {
  if (v === null || v === undefined) return fallback;
  if (typeof v === 'string') return v;
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v as number | boolean | bigint);
}

function maskSensitiveConfigValue(value: unknown): string {
  const raw = unknownToStr(value);
  if (!raw || raw === 'undefined') return chalk.dim('(none)');
  if (raw.length <= 6) return '******';
  return `${'*'.repeat(Math.max(0, raw.length - 4))}${raw.slice(-4)}`;
}

export async function config(
  action?: string,
  key?: string,
  value?: string,
  opts?: ConfigOptions
): Promise<void> {
  // Default: list
  if (!action || action === 'list') {
    await listConfig(opts);
    return;
  }

  switch (action) {
    case 'get':
      await getConfig(key);
      break;

    case 'set':
      await setConfig(key, value);
      break;

    case 'reset':
      await resetConfig();
      break;

    case 'menu':
    case 'interactive':
      await configMenu();
      break;

    case 'settings':
      console.log('To open settings:');
      console.log('  1. Run: opta');
      console.log('  2. Press Ctrl+S to open Opta Menu');
      console.log('  3. Select Settings from the Operations page');
      console.log('');
      console.log('Or press Ctrl+Shift+S directly to open settings.');
      break;

    default:
      console.error(chalk.red('✗') + ` Unknown action: ${action}\n`);
      console.log(chalk.dim('Available actions: list, get, set, reset, menu, settings'));
      throw new ExitError(EXIT.MISUSE);
  }
}

// --- List ---

async function listConfig(opts?: ConfigOptions): Promise<void> {
  const cfg = await loadConfig();

  if (opts?.json) {
    console.log(JSON.stringify(cfg, null, 2));
    return;
  }

  const flat = flattenObject(cfg);

  for (const [key, val] of Object.entries(flat)) {
    const display = isSensitiveConfigKey(key) ? maskSensitiveConfigValue(val) : String(val);
    console.log(`  ${chalk.cyan(key.padEnd(30))} ${display}`);
  }
}

// --- Get ---

async function getConfig(key?: string): Promise<void> {
  if (!key) {
    console.error(chalk.red('✗') + ' Key required\n');
    console.log(chalk.dim('Usage: opta config get <key>'));
    console.log(chalk.dim('Example: opta config get connection.host'));
    throw new ExitError(EXIT.MISUSE);
  }

  const cfg = await loadConfig();
  const flat = flattenObject(cfg);
  const val = flat[key];

  if (val === undefined) {
    console.error(chalk.red('✗') + ` Unknown key: ${key}\n`);
    console.log(chalk.dim('Available keys:'));
    for (const k of Object.keys(flat)) {
      console.log(chalk.dim(`  ${k}`));
    }
    throw new ExitError(EXIT.NOT_FOUND);
  }

  console.log(unknownToStr(val));
}

// --- Set ---

async function setConfig(key?: string, value?: string): Promise<void> {
  if (!key || value === undefined) {
    console.error(chalk.red('✗') + ' Key and value required\n');
    console.log(chalk.dim('Usage: opta config set <key> <value>'));
    console.log(chalk.dim('Example: opta config set permissions.edit_file allow'));
    throw new ExitError(EXIT.MISUSE);
  }

  const store = await getConfigStore();

  // Capture old value for display
  const oldRaw = store.get(key);
  const oldValue = oldRaw !== undefined ? unknownToStr(oldRaw) : chalk.dim('(default)');

  // Parse value type
  let parsed: unknown = value;
  if (key === 'connection.fallbackHosts') {
    const trimmed = value.trim();
    if (trimmed.startsWith('[')) {
      try {
        parsed = JSON.parse(trimmed);
      } catch {
        throw new OptaError(
          `Invalid value for "${key}": expected a JSON array or comma-separated host list`,
          EXIT.MISUSE
        );
      }
    } else if (trimmed.length === 0) {
      parsed = [];
    } else {
      parsed = trimmed
        .split(',')
        .map((item) => item.trim())
        .filter((item) => item.length > 0);
    }
  } else if (key === 'connection.adminKeysByHost') {
    const parsedMap = parseAdminKeysByHost(value);
    if (parsedMap === null) {
      throw new OptaError(
        `Invalid value for "${key}": expected JSON object or host=key pairs`,
        EXIT.MISUSE
      );
    }
    parsed = parsedMap;
  } else if (value === 'true') parsed = true;
  else if (value === 'false') parsed = false;
  else if (/^\d+$/.test(value)) parsed = parseInt(value, 10);
  else if (/^\d+\.\d+$/.test(value)) parsed = parseFloat(value);

  store.set(key, parsed);

  // Validate the full merged config against the Zod schema
  try {
    const fullConfig = store.store;
    OptaConfigSchema.parse(fullConfig);
  } catch (e) {
    // Revert the change — the value is invalid
    store.delete(key);
    throw new OptaError(`Invalid value for "${key}": ${errorMessage(e)}`, EXIT.MISUSE);
  }

  console.log(chalk.green('✓') + ` ${chalk.cyan(key)}: ${chalk.dim(oldValue)} → ${String(parsed)}`);
}

// --- Reset ---

async function resetConfig(): Promise<void> {
  const store = await getConfigStore();
  store.clear();
  console.log(chalk.green('✓') + ' Config reset to defaults');
}

async function configMenu(): Promise<void> {
  if (!process.stdin.isTTY || !process.stdout.isTTY) {
    await listConfig();
    return;
  }

  const { runPaneMenu } = await import('../ui/pane-menu.js');
  const { select, input } = await import('@inquirer/prompts');

  let sectionIndex = 0;
  let itemIndex = 0;

  while (true) {
    const cfg = await loadConfig();
    const flat = flattenObject(cfg as unknown as Record<string, unknown>);
    const sections = buildConfigMenuSections(flat);
    const selection = await runPaneMenu({
      title: 'Opta Config Menu',
      subtitle: 'Browse keys with arrows, set values with Enter',
      instructions: '←/→ panes · ↑/↓ loop · Enter select · q exit',
      sections,
      initialSectionIndex: sectionIndex,
      initialItemIndex: itemIndex,
      loop: true,
    });

    if (!selection) return;
    sectionIndex = selection.sectionIndex;
    itemIndex = selection.itemIndex;

    const selectedKey = selection.itemId;
    const current = flat[selectedKey];

    console.log(
      '\n' +
        box(`Config ${chalk.cyan(selectedKey)}`, [
          kv('Key', selectedKey, 16),
          kv(
            'Value',
            isSensitiveConfigKey(selectedKey)
              ? maskSensitiveConfigValue(current)
              : current !== undefined && current !== null
                ? unknownToStr(current)
                : chalk.dim('(unset)'),
            16
          ),
          '',
          chalk.dim(`Set with: opta config set ${selectedKey} <value>`),
        ]) +
        '\n'
    );

    let action: 'back' | 'set' | 'reset' | 'exit';
    try {
      const picked = await runMenuPrompt(
        (context) =>
          select<'back' | 'set' | 'reset' | 'exit'>(
            {
              message: chalk.dim('Next'),
              choices: [
                { name: 'Back to config menu', value: 'back' },
                { name: `Set ${selectedKey}`, value: 'set' },
                { name: `Reset ${selectedKey} to default`, value: 'reset' },
                { name: 'Exit config menu', value: 'exit' },
              ],
            },
            context
          ),
        'select'
      );
      if (!picked) continue;
      action = picked;
    } catch {
      return;
    }

    if (action === 'exit') return;
    if (action === 'back') continue;

    if (action === 'set') {
      let nextValue = '';
      try {
        nextValue = await input({
          message: chalk.dim(`Set ${selectedKey}`),
          default: isSensitiveConfigKey(selectedKey)
            ? ''
            : current === undefined
              ? ''
              : unknownToStr(current),
        });
      } catch {
        continue;
      }
      try {
        await setConfig(selectedKey, nextValue);
      } catch (err) {
        console.error(chalk.red('✗') + ` ${errorMessage(err)}`);
      }
      continue;
    }

    const store = await getConfigStore();
    store.delete(selectedKey);
    console.log(chalk.green('✓') + ` ${selectedKey} reset to default`);
  }
}

// --- Helpers ---

function flattenObject(obj: Record<string, unknown>, prefix = ''): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [key, val] of Object.entries(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    if (val !== null && typeof val === 'object' && !Array.isArray(val)) {
      Object.assign(result, flattenObject(val as Record<string, unknown>, fullKey));
    } else {
      result[fullKey] = val;
    }
  }

  return result;
}

function buildConfigMenuSections(flat: Record<string, unknown>): PaneMenuSection[] {
  const grouped = new Map<string, Array<{ key: string; value: unknown }>>();

  for (const [key, value] of Object.entries(flat)) {
    const section = key.split('.')[0] ?? 'other';
    const items = grouped.get(section) ?? [];
    items.push({ key, value });
    grouped.set(section, items);
  }

  return [...grouped.entries()]
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([section, items]) => ({
      id: section,
      label: section.charAt(0).toUpperCase() + section.slice(1),
      color: '#a855f7',
      items: items
        .sort((a, b) => a.key.localeCompare(b.key))
        .map((item) => ({
          id: item.key,
          label: item.key,
          description: String(item.value).slice(0, 36),
        })),
    }));
}

import chalk from 'chalk';
import { readFile } from 'node:fs/promises';
import { daemonLogsPath } from '../daemon/telemetry.js';
import { daemonStatus, ensureDaemonRunning, stopDaemon } from '../daemon/lifecycle.js';
import { runDaemon } from '../daemon/main.js';
import {
  installDaemonService,
  uninstallDaemonService,
} from '../daemon/installer.js';

interface DaemonCmdOptions {
  host?: string;
  port?: string;
  json?: boolean;
  token?: string;
  model?: string;
}

export async function daemonStart(opts: DaemonCmdOptions): Promise<void> {
  const host = opts.host;
  const port = opts.port ? Number.parseInt(opts.port, 10) : undefined;
  const state = await ensureDaemonRunning({ host, port });
  if (opts.json) {
    console.log(JSON.stringify(state, null, 2));
    return;
  }
  console.log(chalk.green('✓') + ` daemon running at http://${state.host}:${state.port}`);
  console.log(chalk.dim(`  pid: ${state.pid}`));
  console.log(chalk.dim(`  logs: ${state.logsPath}`));
}

export async function daemonRun(opts: DaemonCmdOptions): Promise<void> {
  const host = opts.host;
  const port = opts.port ? Number.parseInt(opts.port, 10) : undefined;
  await runDaemon({
    host,
    port,
    token: opts.token,
    model: opts.model,
  });
}

export async function daemonStop(_opts: DaemonCmdOptions): Promise<void> {
  const stopped = await stopDaemon();
  if (stopped) {
    console.log(chalk.green('✓') + ' daemon stopped');
  } else {
    console.log(chalk.dim('daemon is not running'));
  }
}

export async function daemonStatusCommand(opts: DaemonCmdOptions): Promise<void> {
  const status = await daemonStatus();
  if (opts.json) {
    console.log(JSON.stringify(status, null, 2));
    return;
  }
  if (!status.running || !status.state) {
    console.log(chalk.yellow('•') + ' daemon is not running');
    return;
  }
  console.log(chalk.green('✓') + ` daemon running at http://${status.state.host}:${status.state.port}`);
  console.log(chalk.dim(`  pid: ${status.state.pid}`));
  console.log(chalk.dim(`  started: ${status.state.startedAt}`));
  console.log(chalk.dim(`  logs: ${status.logsPath}`));
}

export async function daemonLogs(opts: DaemonCmdOptions): Promise<void> {
  const path = daemonLogsPath();
  try {
    const raw = await readFile(path, 'utf-8');
    const lines = raw.trim().split('\n').filter(Boolean);
    const tail = lines.slice(-200);
    if (opts.json) {
      const parsed = tail.map((line) => {
        try {
          return JSON.parse(line);
        } catch {
          return { raw: line };
        }
      });
      console.log(JSON.stringify(parsed, null, 2));
      return;
    }
    console.log(tail.join('\n'));
  } catch {
    if (opts.json) {
      console.log(JSON.stringify({ logs: [] }));
      return;
    }
    console.log(chalk.dim('No daemon logs yet.'));
  }
}

export async function daemonInstall(_opts: DaemonCmdOptions): Promise<void> {
  await installDaemonService();
  console.log(chalk.green('✓') + ' daemon service installed and registered');
}

export async function daemonUninstall(_opts: DaemonCmdOptions): Promise<void> {
  await uninstallDaemonService();
  console.log(chalk.green('✓') + ' daemon service uninstalled');
}

import chalk from 'chalk';
import { loadConfig } from '../core/config.js';
import { agentLoop } from '../core/agent.js';
import { formatError, OptaError, ExitError, EXIT, ensureModel } from '../core/errors.js';
import { buildConfigOverrides } from '../utils/config-helpers.js';
import { DaemonClient } from '../daemon/client.js';
import { loadAccountState } from '../accounts/storage.js';
import { evaluateCapability } from '../accounts/cloud.js';
import { runPreFlightOrchestration } from '../core/pre-flight.js';
import { runPostFlightReview } from '../core/post-flight.js';
import type { ClientSubmitTurn, TurnOutputFormat } from '../protocol/v3/types.js';

// --- Types ---

export type OutputFormat = 'json' | 'text' | 'quiet';

export interface DoResult {
  response: string;
  toolCallCount: number;
  model: string;
  exitCode: number;
  error?: string;
}

interface DoOptions {
  model?: string;
  provider?: string;
  device?: string;
  commit?: boolean;
  checkpoints?: boolean;
  format?: string;
  quiet?: boolean;
  output?: string;
  auto?: boolean;
  dangerous?: boolean;
  yolo?: boolean;
  mode?: string;
}

type DaemonSessionMode = ClientSubmitTurn['mode'];

function normalizeDaemonSessionMode(mode?: string): DaemonSessionMode {
  const normalized = mode?.trim().toLowerCase();
  switch (normalized) {
    case 'chat':
      return 'chat';
    case 'plan':
      return 'plan';
    case 'review':
      return 'review';
    case 'research':
      return 'research';
    case 'do':
    case 'ceo':
    default:
      return 'do';
  }
}

function normalizeTurnFormat(format?: string): TurnOutputFormat | undefined {
  const normalized = format?.trim().toLowerCase();
  if (normalized === 'markdown' || normalized === 'text' || normalized === 'json') {
    return normalized;
  }
  return undefined;
}

function buildDaemonTurnOverrides(opts: DoOptions): ClientSubmitTurn['overrides'] | undefined {
  const candidates: NonNullable<ClientSubmitTurn['overrides']> = {
    model: opts.model?.trim() || undefined,
    provider: opts.provider?.trim() || undefined,
    dangerous: opts.dangerous || opts.yolo ? true : undefined,
    auto: opts.auto ? true : undefined,
    noCommit: opts.commit === false ? true : undefined,
    noCheckpoints: opts.checkpoints === false ? true : undefined,
    format: normalizeTurnFormat(opts.format),
    autonomyMode: (opts.mode?.trim().toLowerCase() === 'ceo' ? 'ceo' : undefined) as any,
  };

  const overrides = Object.fromEntries(
    Object.entries(candidates).filter(([, value]) => value !== undefined)
  ) as NonNullable<ClientSubmitTurn['overrides']>;

  return Object.keys(overrides).length > 0 ? overrides : undefined;
}

// --- Output Formatting (testable) ---

/**
 * Determine the output format from CLI flags.
 * Priority: --quiet > --format > default (text)
 */
export function parseDoOutput(opts: { format?: string; quiet?: boolean }): OutputFormat {
  if (opts.quiet) return 'quiet';
  if (opts.format === 'json') return 'json';
  return 'text';
}

/**
 * Format the result based on the output mode.
 */
export function formatDoResult(result: DoResult, format: OutputFormat): string {
  switch (format) {
    case 'json':
      return JSON.stringify({
        result: result.response,
        tool_calls: result.toolCallCount,
        model: result.model,
        exit_code: result.exitCode,
        ...(result.error ? { error: result.error } : {}),
      });

    case 'quiet':
      // In quiet mode, only output errors
      if (result.error) return result.error;
      return '';

    case 'text':
    default:
      return result.response;
  }
}

// --- Command Implementation ---

export async function executeTask(task: string[], opts: DoOptions): Promise<void> {
  const taskStr = task.join(' ');

  const outputFormat = parseDoOutput(opts);

  if (!taskStr.trim()) {
    if (outputFormat === 'json') {
      console.log(JSON.stringify({ error: 'No task specified', exit_code: EXIT.MISUSE }));
    } else if (outputFormat !== 'quiet') {
      console.error(chalk.red('\u2717') + ' No task specified\n');
      console.log(chalk.dim('Usage: opta do <task...>'));
      console.log(chalk.dim('Example: opta do "fix the authentication bug"'));
    }
    throw new ExitError(EXIT.MISUSE);
  }

  const overrides = buildConfigOverrides(opts);

  const silent = outputFormat === 'json' || outputFormat === 'quiet';

  const accountState = await loadAccountState();
  if (accountState?.session) {
    const gate = await evaluateCapability(accountState, 'cli.run', accountState.deviceId);
    if (!gate.allow) {
      const message = `Capability denied for cli.run${gate.reason ? ` (${gate.reason})` : ''}`;
      if (outputFormat === 'json') {
        console.log(JSON.stringify({ error: message, exit_code: EXIT.PERMISSION }));
      } else {
        console.error(chalk.red('✗') + ` ${message}`);
      }
      throw new ExitError(EXIT.PERMISSION);
    }
  }

  try {
    const config = await loadConfig(overrides);

    ensureModel(config.model.default);

    if (!silent) {
      console.log(
        chalk.dim(`opta \u00b7 ${config.model.default} \u00b7 ${config.connection.host}`)
      );
    }

    let activeTaskStr = taskStr;
    const isCeoMode = config.autonomy?.mode === 'ceo' || opts.mode === 'ceo';

    if (isCeoMode && !silent) {
      const preFlight = await runPreFlightOrchestration(config, taskStr);
      if (!preFlight.proceed) {
        console.log(chalk.yellow('\nCEO Mode cancelled by user.'));
        return;
      }
      activeTaskStr = preFlight.refinedObjective;
      console.log(chalk.green('\nStarting Autonomous CEO Run...\n'));
    }

    const taskStart = Date.now();
    let doResult: DoResult;
    const shouldBypassDaemon = Boolean(opts.device && opts.device.trim().length > 0);

    try {
      if (shouldBypassDaemon) {
        throw new Error('Bypassing daemon for explicit --device override');
      }
      const daemon = await DaemonClient.connect();
      const daemonResp = await daemon.legacyChat(activeTaskStr, undefined, {
        mode: normalizeDaemonSessionMode(opts.mode),
        overrides: buildDaemonTurnOverrides(opts),
      });
      const stats = daemonResp.stats;
      doResult = {
        response: daemonResp.response ?? '',
        toolCallCount: stats?.toolCalls ?? 0,
        model: daemonResp.model ?? config.model.default,
        exitCode: 0,
      };
    } catch (error) {
      // Compatibility fallback in case daemon bootstrap fails.
      if (!silent) {
        const reason = error instanceof Error ? error.message : String(error);
        console.error(chalk.yellow(`⚠ daemon path unavailable: ${reason}`));
        console.error(chalk.dim('  Falling back to local agent loop for this run.'));
      }
      const result = await agentLoop(activeTaskStr, config, { silent, mode: opts.mode });
      const assistantMsgs = result.messages.filter((m) => m.role === 'assistant');
      const finalMsg = assistantMsgs[assistantMsgs.length - 1];
      doResult = {
        response: typeof finalMsg?.content === 'string' ? finalMsg.content : '',
        toolCallCount: result.toolCallCount,
        model: config.model.default,
        exitCode: 0,
      };

      if (isCeoMode && !silent) {
        await runPostFlightReview(config, result.messages, activeTaskStr);
      }
    }

    const output = formatDoResult(doResult, outputFormat);
    if (output) console.log(output);

    // Elapsed time footer in text mode
    if (outputFormat === 'text') {
      const elapsed = ((Date.now() - taskStart) / 1000).toFixed(1);
      const toolStr =
        doResult.toolCallCount > 0
          ? chalk.dim(
            ` · ${doResult.toolCallCount} tool call${doResult.toolCallCount !== 1 ? 's' : ''}`
          )
          : '';
      console.log(chalk.dim(`\n  Done in ${elapsed}s${toolStr}`));
    }

    // Write to file if --output specified
    if (opts.output) {
      const { writeFile } = await import('node:fs/promises');
      const fullOutput =
        outputFormat === 'json' ? formatDoResult(doResult, 'json') : doResult.response;
      await writeFile(opts.output, fullOutput, 'utf-8');
      if (!silent) {
        console.log(chalk.dim(`  Output written to ${opts.output}`));
      }
    }
  } catch (err) {
    if (err instanceof OptaError) {
      if (outputFormat === 'json') {
        console.log(JSON.stringify({ error: err.message, exit_code: err.code }));
      } else if (outputFormat !== 'quiet') {
        console.error(formatError(err));
      } else {
        console.error(err.message);
      }
      throw new ExitError(err.code);
    }
    throw err;
  }
}

import chalk from 'chalk';
