// --- Types ---

export interface DoctorOptions {
  format?: string;
  fix?: boolean;
}

export interface CheckResult {
  name: string;
  status: 'pass' | 'warn' | 'fail';
  message: string;
  detail?: string;
  fix?: () => Promise<string>;
}

interface LmxDoctorSnapshot {
  reachable: boolean;
  host: string;
  source: 'primary' | 'fallback';
  latencyMs: number;
  loadedModelIds: string[];
  adminAccess: 'ok' | 'unauthorized' | 'unknown';
  adminError?: string;
  error?: string;
}

const FAST_DOCTOR_REQUEST_OPTS = { timeoutMs: 2_500, maxRetries: 0 } as const;

function buildFailoverHint(fallbackHosts: string[]): string {
  const normalized = fallbackHosts.map((value) => value.trim()).filter((value) => value.length > 0);
  return normalized.length > 0
    ? `Configured fallback hosts: ${normalized.join(', ')}.`
    : "Configure failover hosts: 'opta config set connection.fallbackHosts hostA,hostB'.";
}

export async function checkLmxDiscovery(): Promise<CheckResult> {
  try {
    const { discoverLmxHosts } = await import('../lmx/mdns-discovery.js');
    const discovered = await discoverLmxHosts(2000);
    if (discovered.length === 0) {
      return {
        name: 'LMX Discovery',
        status: 'warn',
        message: 'No LMX servers found on LAN',
        detail: "Ensure Opta-LMX is running and reachable on port 1234. Run 'opta onboard' to configure manually.",
      };
    }
    const hostList = discovered.map((d) => `${d.host}:${d.port} (${d.latencyMs}ms)`).join(', ');
    return {
      name: 'LMX Discovery',
      status: 'pass',
      message: `LAN discovery: ${discovered.length} LMX server${discovered.length !== 1 ? 's' : ''} found — ${hostList}`,
    };
  } catch (err) {
    return {
      name: 'LMX Discovery',
      status: 'warn',
      message: `LMX discovery unavailable (${errorMessage(err)})`,
    };
  }
}

async function collectLmxDoctorSnapshot(
  host: string,
  port: number,
  adminKey?: string,
  fallbackHosts: string[] = [],
  adminKeysByHost: Record<string, string> = {}
): Promise<LmxDoctorSnapshot> {
  const start = Date.now();
  try {
    const [{ resolveLmxEndpoint }, { LmxApiError, LmxClient }] = await Promise.all([
      import('../lmx/endpoints.js'),
      import('../lmx/client.js'),
    ]);
    const resolved = await resolveLmxEndpoint(
      {
        host,
        port,
        adminKey,
        adminKeysByHost,
        fallbackHosts,
      },
      {
        timeoutMs: 1_500,
      }
    );
    const lmx = new LmxClient({
      host: resolved.host,
      port,
      adminKey,
      adminKeysByHost,
      fallbackHosts: [],
      timeoutMs: 2_500,
      maxRetries: 0,
    });
    await lmx.health(FAST_DOCTOR_REQUEST_OPTS);
    let loadedModelIds: string[] = [];
    let adminAccess: LmxDoctorSnapshot['adminAccess'] = 'ok';
    let adminError: string | undefined;
    try {
      const models = await lmx.models(FAST_DOCTOR_REQUEST_OPTS);
      loadedModelIds = models.models.map((model) => model.model_id);
    } catch (err) {
      if (
        err instanceof LmxApiError &&
        (err.code === 'unauthorized' || err.status === 401 || err.status === 403)
      ) {
        adminAccess = 'unauthorized';
        adminError = errorMessage(err);
      } else {
        adminAccess = 'unknown';
        adminError = errorMessage(err);
      }
    }
    return {
      reachable: true,
      host: resolved.host,
      source: resolved.source,
      latencyMs: Date.now() - start,
      loadedModelIds,
      adminAccess,
      adminError,
    };
  } catch (err) {
    return {
      reachable: false,
      host,
      source: 'primary',
      latencyMs: Date.now() - start,
      loadedModelIds: [],
      adminAccess: 'unknown',
      error: errorMessage(err),
    };
  }
}

function lmxConnectionResultFromSnapshot(
  snapshot: LmxDoctorSnapshot,
  host: string,
  port: number,
  fallbackHosts: string[] = []
): CheckResult {
  if (snapshot.reachable) {
    if (snapshot.adminAccess === 'unauthorized') {
      return {
        name: 'LMX Connection',
        status: 'warn',
        message: `LMX reachable at ${snapshot.host}:${port} (${snapshot.latencyMs}ms) but admin endpoints are unauthorized`,
        detail: [
          `Auth detail: ${snapshot.adminError ?? 'invalid or missing admin key'}.`,
          "Check key: 'opta config get connection.adminKey'.",
          "Check host-key map: 'opta config get connection.adminKeysByHost'.",
          "Set/clear key: 'opta config set connection.adminKey <key>' or 'opta config delete connection.adminKey'.",
          "Set host-key map: opta config set connection.adminKeysByHost '{\"host\":\"key\"}'.",
        ].join(' '),
      };
    }

    const modelCount = snapshot.loadedModelIds.length;
    const modelSuffix =
      modelCount > 0 ? `, ${modelCount} model${modelCount !== 1 ? 's' : ''} loaded` : '';
    const failoverSuffix =
      snapshot.source === 'fallback' ? chalk.dim(` via fallback ${snapshot.host}`) : '';
    return {
      name: 'LMX Connection',
      status: 'pass',
      message: `LMX connected at ${snapshot.host}:${port} (${snapshot.latencyMs}ms${modelSuffix})${failoverSuffix}`,
    };
  }

  const reason = snapshot.error && snapshot.error.length > 0 ? snapshot.error : 'unknown error';
  const failoverHint = buildFailoverHint(fallbackHosts);
  return {
    name: 'LMX Connection',
    status: 'fail',
    message: `LMX unreachable at ${host}:${port} (${reason})`,
    detail: [
      `Check that LMX is running at ${host}:${port}.`,
      "For authenticated inference set 'connection.apiKey' (or OPTA_API_KEY).",
      failoverHint,
      "Run 'opta status' or 'opta config set connection.host <host>' to reconfigure.",
    ].join(' '),
    fix: async () => 'Ensure LMX server is running on Mono512 (192.168.188.11:1234). Cannot auto-start remote server.',
  };
}

function activeModelResultFromSnapshot(
  configModel: string,
  snapshot: LmxDoctorSnapshot
): CheckResult {
  if (snapshot.reachable && snapshot.adminAccess === 'unauthorized') {
    return {
      name: 'Active Model',
      status: 'warn',
      message: configModel
        ? `Cannot verify model "${configModel}" (admin auth required)`
        : 'Cannot verify active model (admin auth required)',
      detail:
        "Grant admin access first: set 'connection.adminKey' to the LMX admin key (or clear stale key).",
    };
  }

  if (!configModel) {
    return {
      name: 'Active Model',
      status: 'warn',
      message: 'No default model configured',
      detail: "Run 'opta models use <model>' to set a default",
    };
  }

  if (!snapshot.reachable) {
    return {
      name: 'Active Model',
      status: 'pass',
      message: `Model: ${configModel} (LMX offline, cannot verify)`,
    };
  }

  const loadedIds = snapshot.loadedModelIds;
  const modelCount = loadedIds.length;
  if (loadedIds.some((id) => id === configModel || id.includes(configModel))) {
    return {
      name: 'Active Model',
      status: 'pass',
      message: `Model: ${configModel} (${modelCount} model${modelCount !== 1 ? 's' : ''} loaded)`,
    };
  }

  return {
    name: 'Active Model',
    status: 'warn',
    message: `Model "${configModel}" not found in loaded models`,
    detail: `Loaded models: ${loadedIds.join(', ') || 'none'}. Run 'opta models' to see available models.`,
  };
}

// --- Individual Checks ---

export function checkNode(): CheckResult {
  const version = process.version;
  const major = parseInt(version.slice(1).split('.')[0] ?? '0', 10);

  if (major >= 20) {
    return {
      name: 'Node.js',
      status: 'pass',
      message: `Node.js ${version} (>= 20.0.0 required)`,
    };
  }

  return {
    name: 'Node.js',
    status: 'fail',
    message: `Node.js ${version} is below minimum (>= 20.0.0 required)`,
    detail: 'Upgrade Node.js to 20+ for ESM support and native fetch',
  };
}

export async function checkLmxConnection(
  host: string,
  port: number,
  adminKey?: string,
  fallbackHosts: string[] = [],
  adminKeysByHost: Record<string, string> = {}
): Promise<CheckResult> {
  const snapshot = await collectLmxDoctorSnapshot(
    host,
    port,
    adminKey,
    fallbackHosts,
    adminKeysByHost
  );
  return lmxConnectionResultFromSnapshot(snapshot, host, port, fallbackHosts);
}

export async function checkActiveModel(
  configModel: string,
  host: string,
  port: number,
  adminKey?: string,
  fallbackHosts: string[] = [],
  adminKeysByHost: Record<string, string> = {}
): Promise<CheckResult> {
  const snapshot = await collectLmxDoctorSnapshot(
    host,
    port,
    adminKey,
    fallbackHosts,
    adminKeysByHost
  );
  if (!snapshot.reachable) {
    debug('doctor: could not verify model against LMX');
  }
  return activeModelResultFromSnapshot(configModel, snapshot);
}

export async function checkConfig(
  preloadedConfig?: Awaited<ReturnType<typeof loadConfig>>
): Promise<CheckResult> {
  try {
    const config = preloadedConfig ?? (await loadConfig());

    // Check for common misconfigurations
    const issues: string[] = [];

    if (!config.connection.host) {
      issues.push('connection.host is empty');
    }
    if (config.connection.port === 0) {
      issues.push('connection.port is 0');
    }

    if (issues.length > 0) {
      return {
        name: 'Config',
        status: 'warn',
        message: `Config has issues: ${issues.join(', ')}`,
        detail: "Run 'opta config list' to review current settings",
      };
    }

    return {
      name: 'Config',
      status: 'pass',
      message: 'Config valid',
    };
  } catch (err) {
    const msg = errorMessage(err);
    return {
      name: 'Config',
      status: 'fail',
      message: `Config validation failed: ${msg}`,
      detail: "Run 'opta config reset' to restore defaults",
    };
  }
}

export async function checkOpis(cwd: string): Promise<CheckResult> {
  const appMdPath = join(cwd, 'APP.md');

  try {
    await access(appMdPath);
  } catch {
    return {
      name: 'OPIS',
      status: 'warn',
      message: 'OPIS not initialized (no APP.md found)',
      detail: "Run 'opta init' to scaffold project intelligence docs",
    };
  }

  // Count available OPIS docs
  const opisFiles = [
    'ARCHITECTURE.md',
    'GUARDRAILS.md',
    'DECISIONS.md',
    'ECOSYSTEM.md',
    'KNOWLEDGE.md',
    'WORKFLOWS.md',
    'ROADMAP.md',
    'INDEX.md',
  ];

  let docCount = 1; // APP.md counts
  const docsDir = join(cwd, 'docs');

  for (const file of opisFiles) {
    try {
      await access(join(docsDir, file));
      docCount++;
    } catch {
      // File doesn't exist
    }
  }

  return {
    name: 'OPIS',
    status: 'pass',
    message: `OPIS initialized (${docCount} doc${docCount !== 1 ? 's' : ''})`,
  };
}

export async function checkMcpServers(
  servers: Record<
    string,
    {
      transport: string;
      command?: string;
      url?: string;
      args?: string[];
      env?: Record<string, string>;
    }
  >
): Promise<CheckResult> {
  const names = Object.keys(servers);

  if (names.length === 0) {
    return {
      name: 'MCP',
      status: 'pass',
      message: 'No MCP servers configured',
    };
  }

  const probeStdioServers = process.env['OPTA_DOCTOR_PROBE_STDIO_MCP'] === '1';
  const probeTargets = names.filter((name) => {
    const server = servers[name]!;
    if (server.transport === 'http') return true;
    if (server.transport === 'stdio') return probeStdioServers;
    return false;
  });
  const skippedStdio = names.filter((name) => servers[name]!.transport === 'stdio' && !probeStdioServers);

  const { connectMcpServer } = await import('../mcp/client.js');
  const settled = await Promise.all(
    probeTargets.map(async (name) => {
      const serverConfig = servers[name]!;
      const connectPromise = connectMcpServer(
        name,
        serverConfig as Parameters<typeof connectMcpServer>[1]
      );
      let timedOut = false;
      let timeoutId: ReturnType<typeof setTimeout> | undefined;

      try {
        const timeout = new Promise<never>((_, reject) => {
          timeoutId = setTimeout(() => {
            timedOut = true;
            reject(new Error('timeout'));
          }, 5000);
        });
        const conn = await Promise.race([connectPromise, timeout]);
        const toolCount = conn.tools.length;
        await conn.close();
        return { name, ok: true as const, toolCount };
      } catch {
        if (timedOut) {
          // Best-effort late cleanup if the connect promise resolves after timeout.
          void connectPromise
            .then(async (conn) => {
              await conn.close();
            })
            .catch(() => {});
        }
        return { name, ok: false as const, toolCount: 0 };
      } finally {
        if (timeoutId) clearTimeout(timeoutId);
      }
    })
  );

  const connected = settled.filter((entry) => entry.ok).length;
  const totalTools = settled.reduce((sum, entry) => sum + entry.toolCount, 0);
  const failed = settled.filter((entry) => !entry.ok).map((entry) => entry.name);

  if (failed.length === 0 && skippedStdio.length === 0) {
    return {
      name: 'MCP',
      status: 'pass',
      message: `MCP: ${connected}/${probeTargets.length} servers connected (${totalTools} tool${totalTools !== 1 ? 's' : ''})`,
    };
  }

  if (failed.length === 0 && skippedStdio.length > 0) {
    return {
      name: 'MCP',
      status: 'warn',
      message: `MCP: ${connected}/${probeTargets.length} probed (${skippedStdio.length} stdio server${skippedStdio.length !== 1 ? 's' : ''} skipped)`,
      detail:
        "Deep stdio MCP probing is skipped in doctor mode to avoid hanging transports. Set OPTA_DOCTOR_PROBE_STDIO_MCP=1 or run 'opta mcp test <name>'.",
    };
  }

  if (connected > 0 || skippedStdio.length > 0) {
    return {
      name: 'MCP',
      status: 'warn',
      message: `MCP: ${connected}/${probeTargets.length} probed (${failed.length} failed, ${skippedStdio.length} skipped)`,
      detail: [
        failed.length > 0 ? `Failed servers: ${failed.join(', ')}.` : '',
        skippedStdio.length > 0
          ? "Skipped stdio servers require manual probe: run 'opta mcp test <name>' or set OPTA_DOCTOR_PROBE_STDIO_MCP=1."
          : '',
      ]
        .filter(Boolean)
        .join(' '),
    };
  }

  return {
    name: 'MCP',
    status: 'fail',
    message: `MCP: 0/${probeTargets.length} probed servers connected`,
    detail: `All probed MCP servers failed: ${failed.join(', ')}`,
  };
}

export async function checkGit(cwd: string): Promise<CheckResult> {
  try {
    await access(join(cwd, '.git'));
  } catch {
    return {
      name: 'Git',
      status: 'warn',
      message: 'Not a git repository',
      detail: "Run 'git init' to initialize version control",
    };
  }

  // Check for uncommitted changes
  try {
    const { execaCommand } = await import('execa');
    const result = await execaCommand('git status --porcelain', {
      cwd,
      timeout: 5000,
    });

    const lines = result.stdout.split('\n').filter((l) => l.trim().length > 0);
    const changeCount = lines.length;

    // Check for checkpoints directory
    let hasCheckpoints = false;
    try {
      await access(join(cwd, '.opta', 'checkpoints'));
      hasCheckpoints = true;
    } catch {
      // No checkpoints dir
    }

    const checkpointNote = hasCheckpoints ? ', checkpoints enabled' : '';

    if (changeCount === 0) {
      return {
        name: 'Git',
        status: 'pass',
        message: `Git repository (clean${checkpointNote})`,
      };
    }

    if (changeCount > 20) {
      return {
        name: 'Git',
        status: 'warn',
        message: `Git repository (${changeCount} uncommitted changes${checkpointNote})`,
        detail: 'Consider committing or stashing changes',
      };
    }

    return {
      name: 'Git',
      status: 'pass',
      message: `Git repository (${changeCount} change${changeCount !== 1 ? 's' : ''}${checkpointNote})`,
    };
  } catch {
    return {
      name: 'Git',
      status: 'pass',
      message: 'Git repository (could not check status)',
    };
  }
}

export async function checkAccount(): Promise<CheckResult> {
  // Step 1: check whether Supabase is configured at all
  const { resolveSupabaseAuthConfig } = await import('../accounts/supabase.js');
  const config = resolveSupabaseAuthConfig();

  if (!config) {
    return {
      name: 'Account',
      status: 'warn',
      message: 'OPTA_SUPABASE_URL not configured (account features disabled)',
      detail:
        'Set OPTA_SUPABASE_URL and OPTA_SUPABASE_ANON_KEY environment variables to enable account features.',
    };
  }

  // Step 2: load persisted account state
  const { loadAccountState } = await import('../accounts/storage.js');
  const state = await loadAccountState();

  if (!state) {
    return {
      name: 'Account',
      status: 'pass',
      message: 'Not logged in (run opta account login)',
    };
  }

  // Step 3: check session / token validity
  if (!state.session) {
    return {
      name: 'Account',
      status: 'warn',
      message: 'Account state found but no active session',
      detail: "The saved token is missing or expired. Run 'opta account login' to re-authenticate.",
    };
  }

  const expiresAt = state.session.expires_at;
  const identifier = state.user?.email ?? state.user?.phone ?? 'unknown user';

  if (expiresAt !== undefined) {
    const nowSecs = Date.now() / 1000;
    const diffSecs = expiresAt - nowSecs;

    if (diffSecs <= 0) {
      return {
        name: 'Account',
        status: 'warn',
        message: `Token expired (run opta account login)`,
        detail: `Last authenticated as ${identifier} on project ${state.project}.`,
      };
    }

    const hours = Math.floor(diffSecs / 3600);
    const mins = Math.ceil((diffSecs % 3600) / 60);
    const expiresSuffix = hours > 0 ? `expires in ${hours}h` : `expires in ${mins}m`;

    return {
      name: 'Account',
      status: 'pass',
      message: `Logged in as ${identifier} (${expiresSuffix})`,
    };
  }

  // No expires_at — treat as valid but indeterminate expiry
  return {
    name: 'Account',
    status: 'pass',
    message: `Logged in as ${identifier}`,
  };
}

export async function checkDiskUsage(): Promise<CheckResult> {
  const sessionsDir = getSessionsDir();

  let sessionCount = 0;
  let totalBytes = 0;

  try {
    const files = await readdir(sessionsDir);
    const jsonFiles = files.filter((f) => f.endsWith('.json'));
    sessionCount = jsonFiles.length;

    const stats = await Promise.all(
      jsonFiles.map(async (file) => {
        try {
          const s = await stat(join(sessionsDir, file));
          return s.size;
        } catch {
          return 0;
        }
      })
    );
    totalBytes = stats.reduce((sum, size) => sum + size, 0);
  } catch {
    // Sessions dir doesn't exist — that's fine
    return {
      name: 'Sessions',
      status: 'pass',
      message: 'Sessions: 0 (0 B)',
    };
  }

  const sizeStr = formatBytes(totalBytes);

  if (totalBytes > 100 * 1024 * 1024) {
    return {
      name: 'Sessions',
      status: 'warn',
      message: `Sessions: ${sessionCount} (${sizeStr})`,
      detail:
        "Session storage exceeds 100 MB. Run 'opta sessions' to review and delete old sessions.",
    };
  }

  return {
    name: 'Sessions',
    status: 'pass',
    message: `Sessions: ${sessionCount} (${sizeStr})`,
  };
}

export async function checkDiskHeadroom(
  minFreeBytes = diskHeadroomMbToBytes()
): Promise<CheckResult> {
  try {
    const disk = await readDiskHeadroom(getConfigDir());
    const available = formatBytes(disk.availableBytes);
    const required = formatBytes(minFreeBytes);

    if (disk.availableBytes < minFreeBytes) {
      return {
        name: 'Disk Headroom',
        status: 'fail',
        message: `Disk headroom below required minimum (${available} available, ${required} required)`,
        detail: 'Free disk space on the filesystem backing ~/.config/opta and rerun opta doctor.',
        fix: async () => 'Disk space is low — free space manually. Cannot auto-fix.',
      };
    }

    return {
      name: 'Disk Headroom',
      status: 'pass',
      message: `Disk headroom: ${available} available`,
    };
  } catch (err) {
    return {
      name: 'Disk Headroom',
      status: 'warn',
      message: `Disk headroom check unavailable (${errorMessage(err)})`,
    };
  }
}

export async function checkDaemon(): Promise<CheckResult> {
  const { isDaemonRunning, readDaemonState } = await import('../daemon/lifecycle.js');
  const state = await readDaemonState();
  const running = await isDaemonRunning(state);

  if (running) {
    return {
      name: 'Daemon',
      status: 'pass',
      message: `Daemon running (pid=${state!.pid}, port=${state!.port})`,
    };
  }

  return {
    name: 'Daemon',
    status: 'warn',
    message: 'Daemon not running',
    detail: "Run 'opta daemon start' to start the background daemon.",
    fix: async () => {
      const { ensureDaemonRunning } = await import('../daemon/lifecycle.js');
      const daemonState = await ensureDaemonRunning();
      return `Daemon started (pid=${daemonState.pid}, port=${daemonState.port})`;
    },
  };
}

export async function checkConfigDirs(): Promise<CheckResult> {
  const configDir = getConfigDir();
  const requiredDirs = [
    configDir,
    getSessionsDir(),
    getDaemonDir(),
  ];

  const missing: string[] = [];
  for (const dir of requiredDirs) {
    try {
      await access(dir);
    } catch {
      missing.push(dir);
    }
  }

  if (missing.length === 0) {
    return {
      name: 'Config Dirs',
      status: 'pass',
      message: 'Config directories exist',
    };
  }

  return {
    name: 'Config Dirs',
    status: 'warn',
    message: `Missing config directories (${missing.length})`,
    detail: missing.join(', '),
    fix: async () => {
      for (const dir of missing) {
        await mkdir(dir, { recursive: true });
      }
      return `Created ${missing.length} missing director${missing.length !== 1 ? 'ies' : 'y'}`;
    },
  };
}

// --- Formatting Helpers ---

function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  return `${(bytes / (1024 * 1024 * 1024)).toFixed(1)} GB`;
}

function statusIcon(status: 'pass' | 'warn' | 'fail'): string {
  switch (status) {
    case 'pass':
      return chalk.green('\u2713');
    case 'warn':
      return chalk.yellow('\u26A0');
    case 'fail':
      return chalk.red('\u2717');
  }
}

// --- Main Command ---

export async function runDoctor(options: DoctorOptions): Promise<void> {
  const isJson = options.format === 'json';
  const config = await loadConfig();

  const { host, port, adminKey } = config.connection;
  const cwd = process.cwd();

  const nodeResult = checkNode();
  const [
    lmxSnapshot,
    configResult,
    opisResult,
    mcpResult,
    gitResult,
    diskResult,
    diskHeadroomResult,
    accountResult,
    daemonResult,
    configDirsResult,
    lmxDiscoveryResult,
  ] = await Promise.all([
    collectLmxDoctorSnapshot(
      host,
      port,
      adminKey,
      config.connection.fallbackHosts,
      config.connection.adminKeysByHost
    ),
    checkConfig(config),
    checkOpis(cwd),
    checkMcpServers(config.mcp.servers as Parameters<typeof checkMcpServers>[0]),
    checkGit(cwd),
    checkDiskUsage(),
    checkDiskHeadroom(diskHeadroomMbToBytes(config.safety?.diskHeadroomMb)),
    checkAccount(),
    checkDaemon(),
    checkConfigDirs(),
    checkLmxDiscovery(),
  ]);

  const results: CheckResult[] = [
    nodeResult,
    lmxConnectionResultFromSnapshot(lmxSnapshot, host, port, config.connection.fallbackHosts),
    lmxDiscoveryResult,
    activeModelResultFromSnapshot(config.model.default, lmxSnapshot),
    configResult,
    configDirsResult,
    opisResult,
    mcpResult,
    gitResult,
    daemonResult,
    diskResult,
    diskHeadroomResult,
    accountResult,
  ];

  // Output
  if (isJson) {
    const passed = results.filter((r) => r.status === 'pass').length;
    const warnings = results.filter((r) => r.status === 'warn').length;
    const failures = results.filter((r) => r.status === 'fail').length;

    console.log(
      JSON.stringify(
        {
          version: VERSION,
          checks: results.map(({ fix: _fix, ...rest }) => rest),
          summary: { passed, warnings, failures },
        },
        null,
        2
      )
    );
    return;
  }

  // Text output
  console.log('');
  console.log(chalk.bold(colorizeOptaWord('Opta Doctor')));
  console.log(chalk.dim('\u2500'.repeat(30)));
  console.log('');

  for (const result of results) {
    const icon = statusIcon(result.status);
    console.log(`  ${icon} ${result.message}`);
    if (result.detail && result.status !== 'pass') {
      console.log(`    ${chalk.dim(result.detail)}`);
    }
  }

  const passed = results.filter((r) => r.status === 'pass').length;
  const warnings = results.filter((r) => r.status === 'warn').length;
  const failures = results.filter((r) => r.status === 'fail').length;

  console.log('');

  const parts: string[] = [];
  parts.push(`${passed} check${passed !== 1 ? 's' : ''} passed`);
  if (warnings > 0) parts.push(`${warnings} warning${warnings !== 1 ? 's' : ''}`);
  if (failures > 0) parts.push(`${failures} error${failures !== 1 ? 's' : ''}`);

  const summaryColor = failures > 0 ? chalk.red : warnings > 0 ? chalk.yellow : chalk.green;
  console.log('  ' + summaryColor(parts.join(', ')));
  console.log('');

  // --fix: attempt to auto-fix failed/warned checks
  if (options.fix) {
    const fixable = results.filter((r) => r.status !== 'pass' && r.fix);
    if (fixable.length === 0) {
      console.log(chalk.dim('  No auto-fixable issues found.'));
      console.log('');
      return;
    }

    console.log(chalk.bold('  Applying fixes...'));
    console.log('');

    for (const result of fixable) {
      try {
        const fixMessage = await result.fix!();
        console.log(`  ${chalk.green('\u2713')} ${result.name}: ${fixMessage}`);
      } catch (err) {
        console.log(`  ${chalk.red('\u2717')} ${result.name}: fix failed — ${errorMessage(err)}`);
      }
    }

    console.log('');
  }
}

import chalk from 'chalk';
import { loadConfig } from '../core/config.js';
import { EXIT, ExitError } from '../core/errors.js';
import { LmxApiError, LmxClient } from '../lmx/client.js';
import { errorMessage } from '../utils/errors.js';

interface EmbedOptions {
  model?: string;
  json?: boolean;
}

const EMBED_REQUEST_OPTS = { timeoutMs: 30_000, maxRetries: 0 } as const;

function usage(): void {
  console.log(chalk.dim('Usage: opta embed <text> [--model <id>] [--json]'));
}

export async function embed(input: string | string[], opts: EmbedOptions = {}): Promise<void> {
  const text = Array.isArray(input) ? input.join(' ').trim() : (input ?? '').trim();
  if (!text) {
    console.error(chalk.red('✗') + ' Text input is required.\n');
    usage();
    throw new ExitError(EXIT.MISUSE);
  }

  const config = await loadConfig();
  const resolvedModel = (
    opts.model?.trim() ||
    config.model.default ||
    'text-embedding-3-small'
  ).trim();
  const client = new LmxClient({
    host: config.connection.host,
    fallbackHosts: config.connection.fallbackHosts,
    port: config.connection.port,
    adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
  });

  try {
    const response = await client.createEmbeddings(
      {
        input: text,
        model: resolvedModel,
      },
      EMBED_REQUEST_OPTS
    );

    if (opts.json) {
      console.log(JSON.stringify(response, null, 2));
      return;
    }

    const vectors = Array.isArray(response.data) ? response.data : [];
    const dimensions = vectors[0]?.embedding?.length ?? 0;
    const totalTokens = response.usage?.total_tokens;

    console.log(chalk.green('✓') + ` Embedded 1 input using ${response.model}`);
    console.log(chalk.dim(`  vectors: ${vectors.length}`));
    if (dimensions > 0) {
      console.log(chalk.dim(`  dimensions: ${dimensions}`));
    }
    if (typeof totalTokens === 'number') {
      console.log(chalk.dim(`  tokens: ${totalTokens}`));
    }

    if (dimensions > 0) {
      const sample = vectors[0]!.embedding.slice(0, 8).map((value) => Number(value.toFixed(6)));
      const suffix = vectors[0]!.embedding.length > 8 ? ', ...' : '';
      console.log(chalk.dim(`  preview: [${sample.join(', ')}${suffix}]`));
    }
  } catch (err) {
    if (err instanceof LmxApiError && err.code === 'connection_error') {
      console.error(
        chalk.red('✗') +
          ` Unable to reach Opta LMX at ${config.connection.host}:${config.connection.port}`
      );
      console.error(chalk.dim(`  ${err.message}`));
      throw new ExitError(EXIT.NO_CONNECTION);
    }

    console.error(chalk.red('✗') + ` Failed to create embedding: ${errorMessage(err)}`);
    throw new ExitError(EXIT.ERROR);
  }
}

import chalk from 'chalk';
import { getConfigStore, loadConfig, saveConfig } from '../core/config.js';
import type { OptaConfig } from '../core/config.js';
import { EXIT, ExitError } from '../core/errors.js';
import { parseAdminKeysByHost } from '../lmx/admin-keys.js';
import { lookupContextLimit } from '../lmx/client.js';
import { normalizeConfiguredModelId } from '../lmx/model-lifecycle.js';

interface EnvCommandOptions {
  json?: boolean;
  host?: string;
  port?: string;
  adminKey?: string;
  adminKeysByHost?: string;
  model?: string;
  provider?: string;
  mode?: string;
}
type ProviderName = OptaConfig['provider']['active'];
type DefaultMode = OptaConfig['defaultMode'];

export interface EnvProfile {
  name: string;
  connection: {
    host: string;
    port: number;
    adminKey?: string;
    apiKey?: string;
    adminKeysByHost?: Record<string, string>;
    protocol?: 'http';
  };
  modelDefault: string;
  provider: ProviderName;
  defaultMode: DefaultMode;
  updatedAt: number;
}

const ENV_PROFILES_KEY = 'profiles.environments';
const ENV_CURRENT_KEY = 'profiles.activeEnvironment';
const VALID_PROVIDERS = new Set<ProviderName>(['lmx', 'anthropic', 'gemini', 'openai', 'opencode_zen']);
const VALID_MODES = new Set<DefaultMode>([
  'safe',
  'auto',
  'plan',
  'review',
  'research',
  'dangerous',
  'ci',
]);

function parsePort(value: string | undefined, fallback: number): number {
  if (!value || !value.trim()) return fallback;
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed) || parsed < 1 || parsed > 65535) {
    console.error(chalk.red('✗') + ` Invalid port: ${value}`);
    throw new ExitError(EXIT.MISUSE);
  }
  return parsed;
}

function parseProvider(value: string | undefined, fallback: ProviderName): ProviderName {
  if (!value || !value.trim()) return fallback;
  const normalized = value.trim().toLowerCase() as ProviderName;
  if (!VALID_PROVIDERS.has(normalized)) {
    console.error(chalk.red('✗') + ` Invalid provider: ${value}`);
    throw new ExitError(EXIT.MISUSE);
  }
  return normalized;
}

function parseMode(value: string | undefined, fallback: DefaultMode): DefaultMode {
  if (!value || !value.trim()) return fallback;
  const normalized = value.trim().toLowerCase() as DefaultMode;
  if (!VALID_MODES.has(normalized)) {
    console.error(chalk.red('✗') + ` Invalid mode: ${value}`);
    throw new ExitError(EXIT.MISUSE);
  }
  return normalized;
}

function sanitizeAdminKeysByHostMap(raw: unknown): Record<string, string> {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return {};
  const normalized: Record<string, string> = {};
  for (const [hostKey, keyValue] of Object.entries(raw as Record<string, unknown>)) {
    if (typeof keyValue !== 'string') continue;
    const host = hostKey.trim();
    const key = keyValue.trim();
    if (!host || !key) continue;
    normalized[host] = key;
  }
  return normalized;
}

export function normalizeEnvProfileName(name: string): string {
  return name
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9._-]/g, '');
}

function sanitizeProfiles(raw: unknown): Record<string, EnvProfile> {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return {};

  const out: Record<string, EnvProfile> = {};
  for (const [key, value] of Object.entries(raw as Record<string, unknown>)) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) continue;
    const obj = value as Record<string, unknown>;
    const host =
      typeof obj.connection === 'object' && obj.connection !== null
        ? (obj.connection as Record<string, unknown>).host
        : undefined;
    const port =
      typeof obj.connection === 'object' && obj.connection !== null
        ? (obj.connection as Record<string, unknown>).port
        : undefined;
    const adminKey =
      typeof obj.connection === 'object' && obj.connection !== null
        ? (obj.connection as Record<string, unknown>).adminKey
        : undefined;
    const apiKey =
      typeof obj.connection === 'object' && obj.connection !== null
        ? (obj.connection as Record<string, unknown>).apiKey
        : undefined;
    const adminKeysByHost =
      typeof obj.connection === 'object' && obj.connection !== null
        ? (obj.connection as Record<string, unknown>).adminKeysByHost
        : undefined;
    const modelDefault = obj.modelDefault;
    const providerRaw = obj.provider;
    const defaultMode = obj.defaultMode;
    const updatedAt = obj.updatedAt;

    if (typeof host !== 'string' || !host.trim()) continue;
    if (typeof port !== 'number' || !Number.isFinite(port)) continue;
    if (typeof modelDefault !== 'string') continue;
    if (typeof providerRaw !== 'string' || !VALID_PROVIDERS.has(providerRaw as ProviderName)) continue;
    if (typeof defaultMode !== 'string' || !VALID_MODES.has(defaultMode as DefaultMode)) continue;
    const provider = providerRaw as ProviderName;

    const normalized = normalizeEnvProfileName(typeof obj.name === 'string' ? obj.name : key);
    if (!normalized) continue;

    const normalizedModelDefault = normalizeConfiguredModelId(modelDefault);
    out[normalized] = {
      name: normalized,
      connection: {
        host: host.trim(),
        port: Math.max(1, Math.floor(port)),
        ...(typeof adminKey === 'string' && adminKey.length > 0 ? { adminKey } : {}),
        ...(typeof apiKey === 'string' && apiKey.length > 0 ? { apiKey } : {}),
        ...(() => {
          const hostKeyMap = sanitizeAdminKeysByHostMap(adminKeysByHost);
          return Object.keys(hostKeyMap).length > 0 ? { adminKeysByHost: hostKeyMap } : {};
        })(),
      },
      modelDefault: normalizedModelDefault,
      provider,
      defaultMode: defaultMode as DefaultMode,
      updatedAt:
        typeof updatedAt === 'number' && Number.isFinite(updatedAt) ? updatedAt : Date.now(),
    };
  }

  return out;
}

async function readProfiles(): Promise<Record<string, EnvProfile>> {
  const store = await getConfigStore();
  return sanitizeProfiles(store.get(ENV_PROFILES_KEY));
}

async function writeProfiles(profiles: Record<string, EnvProfile>): Promise<void> {
  const store = await getConfigStore();
  store.set(ENV_PROFILES_KEY, profiles);
}

async function getCurrentProfileName(): Promise<string | undefined> {
  const store = await getConfigStore();
  const raw = store.get(ENV_CURRENT_KEY);
  if (typeof raw !== 'string' || !raw.trim()) return undefined;
  return normalizeEnvProfileName(raw);
}

async function setCurrentProfileName(name: string): Promise<void> {
  const store = await getConfigStore();
  store.set(ENV_CURRENT_KEY, name);
}

function formatRelativeTime(timestampMs: number): string {
  const diffMs = Date.now() - timestampMs;
  const mins = Math.max(1, Math.round(diffMs / 60_000));
  if (mins < 60) return `${mins}m ago`;
  const hours = Math.round(mins / 60);
  if (hours < 48) return `${hours}h ago`;
  const days = Math.round(hours / 24);
  return `${days}d ago`;
}

function printHelp(): void {
  console.log(chalk.bold('Environment Profiles\n'));
  console.log(`  ${chalk.reset('opta env')}                         list profiles`);
  console.log(`  ${chalk.reset('opta env list')}                    list profiles`);
  console.log(
    `  ${chalk.reset('opta env show [name]')}             show a profile (or active one)`
  );
  console.log(
    `  ${chalk.reset('opta env save <name>')}             save current/overridden settings as profile`
  );
  console.log(
    `  ${chalk.reset('opta env use <name>')}              apply profile to active config`
  );
  console.log(`  ${chalk.reset('opta env delete <name>')}           remove a profile`);
  console.log('');
  console.log(
    chalk.dim(
      'Flags for save: --host --port --admin-key --admin-keys-by-host \'{\"host\":\"key\"}\' --model --provider --mode --json'
    )
  );
}

async function listProfiles(opts: EnvCommandOptions): Promise<void> {
  const profiles = await readProfiles();
  const current = await getCurrentProfileName();
  const entries = Object.values(profiles).sort((a, b) => b.updatedAt - a.updatedAt);

  if (opts.json) {
    console.log(JSON.stringify({ current, profiles: entries }, null, 2));
    return;
  }

  console.log(chalk.bold('Environment Profiles\n'));
  if (entries.length === 0) {
    console.log(chalk.dim('  No environment profiles saved yet.'));
    console.log(chalk.dim(`  Save one with ${chalk.reset('opta env save laptop')}`));
    return;
  }

  for (const profile of entries) {
    const active = current === profile.name;
    const dot = active ? chalk.green('●') : chalk.dim('○');
    const activeTag = active ? chalk.green(' active') : '';
    const keyConfigured = Boolean(profile.connection.apiKey || profile.connection.adminKey);
    const admin = keyConfigured ? 'key-set' : 'no-key';
    console.log(
      `  ${dot} ${chalk.bold(profile.name)}${activeTag} ` +
        chalk.dim(
          `(${profile.connection.host}:${profile.connection.port} · ${profile.provider} · ${profile.defaultMode} · ${admin} · ${formatRelativeTime(profile.updatedAt)})`
        )
    );
    if (profile.modelDefault) {
      console.log(chalk.dim(`     model ${profile.modelDefault}`));
    }
  }
}

async function showProfile(name: string | undefined, opts: EnvCommandOptions): Promise<void> {
  const profiles = await readProfiles();
  const current = await getCurrentProfileName();
  const resolvedName = name ? normalizeEnvProfileName(name) : current;

  if (!resolvedName) {
    console.error(chalk.red('✗') + ' No active environment profile');
    throw new ExitError(EXIT.NOT_FOUND);
  }

  const profile = profiles[resolvedName];
  if (!profile) {
    console.error(chalk.red('✗') + ` Environment profile not found: ${resolvedName}`);
    throw new ExitError(EXIT.NOT_FOUND);
  }

  if (opts.json) {
    console.log(JSON.stringify({ current, profile }, null, 2));
    return;
  }

  console.log(chalk.bold(`Environment · ${profile.name}\n`));
  console.log(`  Host:        ${profile.connection.host}`);
  console.log(`  Port:        ${profile.connection.port}`);
  console.log(`  LMX key:     ${profile.connection.apiKey || profile.connection.adminKey ? chalk.green('set') : chalk.dim('not set')}`);
  console.log(
    `  Host keys:   ${profile.connection.adminKeysByHost && Object.keys(profile.connection.adminKeysByHost).length > 0
      ? chalk.green(`${Object.keys(profile.connection.adminKeysByHost).length} configured`)
      : chalk.dim('none')}`
  );
  console.log(`  Provider:    ${profile.provider}`);
  console.log(`  Mode:        ${profile.defaultMode}`);
  console.log(`  Model:       ${profile.modelDefault || chalk.dim('(empty)')}`);
  console.log(`  Updated:     ${new Date(profile.updatedAt).toLocaleString()}`);
  if (current === profile.name) {
    console.log(chalk.green('\n  Active profile'));
  }
}

async function saveProfile(name: string | undefined, opts: EnvCommandOptions): Promise<void> {
  const profileName = normalizeEnvProfileName(name ?? '');
  if (!profileName) {
    console.error(chalk.red('✗') + ' Missing profile name');
    throw new ExitError(EXIT.MISUSE);
  }

  const config = await loadConfig();
  const host = (opts.host ?? config.connection.host).trim();
  if (!host) {
    console.error(chalk.red('✗') + ' Host cannot be empty');
    throw new ExitError(EXIT.MISUSE);
  }

  let adminKeysByHostOverride: Record<string, string> | undefined;
  if (opts.adminKeysByHost !== undefined) {
    const parsed = parseAdminKeysByHost(opts.adminKeysByHost);
    if (parsed === null) {
      console.error(chalk.red('✗') + ' Invalid admin-keys-by-host format');
      throw new ExitError(EXIT.MISUSE);
    }
    adminKeysByHostOverride = parsed;
  }

  const profile: EnvProfile = {
    name: profileName,
    connection: {
      host,
      port: parsePort(opts.port, config.connection.port),
      ...(opts.adminKey !== undefined
        ? opts.adminKey.trim()
          ? { adminKey: opts.adminKey.trim(), apiKey: opts.adminKey.trim() }
          : {}
        : config.connection.adminKey || config.connection.apiKey
          ? {
            ...(config.connection.adminKey ? { adminKey: config.connection.adminKey } : {}),
            ...(config.connection.apiKey ? { apiKey: config.connection.apiKey } : {}),
          }
          : {}),
      ...(adminKeysByHostOverride !== undefined
        ? (Object.keys(adminKeysByHostOverride).length > 0
          ? { adminKeysByHost: adminKeysByHostOverride }
          : {})
        : config.connection.adminKeysByHost && Object.keys(config.connection.adminKeysByHost).length > 0
          ? { adminKeysByHost: config.connection.adminKeysByHost }
          : {}),
    },
    modelDefault: normalizeConfiguredModelId(opts.model?.trim() ?? config.model.default),
    provider: parseProvider(opts.provider, config.provider.active),
    defaultMode: parseMode(opts.mode, config.defaultMode),
    updatedAt: Date.now(),
  };

  const profiles = await readProfiles();
  profiles[profileName] = profile;
  await writeProfiles(profiles);

  const current = await getCurrentProfileName();
  if (!current) {
    await setCurrentProfileName(profileName);
  }

  if (opts.json) {
    console.log(JSON.stringify({ saved: profileName, profile }, null, 2));
    return;
  }

  console.log(chalk.green('✓') + ` Saved environment profile ${chalk.bold(profileName)}`);
  console.log(chalk.dim(`  Use ${chalk.reset(`opta env use ${profileName}`)} to apply it`));
}

async function useProfile(name: string | undefined, opts: EnvCommandOptions): Promise<void> {
  const profileName = normalizeEnvProfileName(name ?? '');
  if (!profileName) {
    console.error(chalk.red('✗') + ' Missing profile name');
    throw new ExitError(EXIT.MISUSE);
  }

  const profiles = await readProfiles();
  const profile = profiles[profileName];
  if (!profile) {
    console.error(chalk.red('✗') + ` Environment profile not found: ${profileName}`);
    throw new ExitError(EXIT.NOT_FOUND);
  }

  const effectiveModelDefault = normalizeConfiguredModelId(profile.modelDefault);
  const updates: Record<string, unknown> = {
    'connection.host': profile.connection.host,
    'connection.port': profile.connection.port,
    'provider.active': profile.provider,
    defaultMode: profile.defaultMode,
    'model.default': effectiveModelDefault,
    'model.contextLimit': lookupContextLimit(effectiveModelDefault),
  };

  await saveConfig(updates);
  const store = await getConfigStore();
  const effectiveKey = profile.connection.apiKey ?? profile.connection.adminKey;
  if (effectiveKey) {
    store.set('connection.adminKey', profile.connection.adminKey ?? effectiveKey);
    store.set('connection.apiKey', effectiveKey);
  } else {
    store.delete('connection.adminKey');
    store.delete('connection.apiKey');
  }
  const profileHostKeys = profile.connection.adminKeysByHost ?? {};
  if (Object.keys(profileHostKeys).length > 0) {
    store.set('connection.adminKeysByHost', profileHostKeys);
  } else {
    store.delete('connection.adminKeysByHost');
  }
  await setCurrentProfileName(profile.name);

  if (opts.json) {
    console.log(JSON.stringify({ active: profile.name, applied: updates }, null, 2));
    return;
  }

  console.log(chalk.green('✓') + ` Activated environment ${chalk.bold(profile.name)}`);
  console.log(
    chalk.dim(
      `  ${profile.connection.host}:${profile.connection.port} · ${profile.provider} · ${profile.defaultMode}`
    )
  );
  if (profile.modelDefault) {
    console.log(chalk.dim(`  model ${profile.modelDefault}`));
  }
}

async function deleteProfile(name: string | undefined, opts: EnvCommandOptions): Promise<void> {
  const profileName = normalizeEnvProfileName(name ?? '');
  if (!profileName) {
    console.error(chalk.red('✗') + ' Missing profile name');
    throw new ExitError(EXIT.MISUSE);
  }

  const profiles = await readProfiles();
  if (!profiles[profileName]) {
    console.error(chalk.red('✗') + ` Environment profile not found: ${profileName}`);
    throw new ExitError(EXIT.NOT_FOUND);
  }

  Reflect.deleteProperty(profiles, profileName);
  await writeProfiles(profiles);

  const current = await getCurrentProfileName();
  const store = await getConfigStore();
  if (current === profileName) {
    const remaining = Object.keys(profiles).sort();
    if (remaining.length > 0) {
      store.set(ENV_CURRENT_KEY, remaining[0]);
    } else {
      store.delete(ENV_CURRENT_KEY);
    }
  }

  if (opts.json) {
    console.log(JSON.stringify({ deleted: profileName }, null, 2));
    return;
  }

  console.log(chalk.green('✓') + ` Deleted environment ${chalk.bold(profileName)}`);
}

export async function envCommand(
  action?: string,
  name?: string,
  opts: EnvCommandOptions = {}
): Promise<void> {
  const normalizedAction = (action ?? 'list').toLowerCase();

  switch (normalizedAction) {
    case 'help':
      printHelp();
      return;
    case 'list':
    case 'ls':
      await listProfiles(opts);
      return;
    case 'show':
    case 'current':
      await showProfile(name, opts);
      return;
    case 'save':
    case 'set':
      await saveProfile(name, opts);
      return;
    case 'use':
    case 'switch':
      await useProfile(name, opts);
      return;
    case 'delete':
    case 'remove':
    case 'rm':
      await deleteProfile(name, opts);
      return;
    default:
      console.error(chalk.red('✗') + ` Unknown env action: ${normalizedAction}`);
      throw new ExitError(EXIT.MISUSE);
  }
}

import { randomBytes } from 'node:crypto';
import chalk from 'chalk';
import { execa } from 'execa';
import { getConfigStore, loadConfig } from '../core/config.js';
import { ExitError, EXIT } from '../core/errors.js';
import { resolveRemoteHostCandidates, selectReachableRemoteHost } from './update.js';
import { homedir, isWindows } from '../platform/index.js';

const SSH_CONNECT_TIMEOUT_SECONDS = 25;

export type KeySource = 'env' | 'config' | 'unset';

interface ResolvedKey {
  key: string | null;
  source: KeySource;
}

interface SshConfig {
  host: string;
  user: string;
  identityFile?: string;
}

interface CommandResult {
  exitCode: number;
  stdout: string;
  stderr: string;
}

interface KeyCreateOptions {
  value?: string;
  remote?: boolean;
  copy?: boolean;
  json?: boolean;
}

interface KeyShowOptions {
  reveal?: boolean;
  copy?: boolean;
  json?: boolean;
}

interface KeyCopyOptions {
  json?: boolean;
}

interface ParsedRemotePath {
  configPath: string | null;
}

function quoteSh(input: string): string {
  return `'${input.replace(/'/g, `'"'"'`)}'`;
}

function expandHome(input: string): string {
  if (!input.startsWith('~')) return input;
  return homedir() + input.slice(1);
}

function isLocalHost(host: string): boolean {
  const lower = host.trim().toLowerCase();
  return lower === 'localhost' || lower === '127.0.0.1';
}

function summarizeOutput(raw: string): string {
  const line = raw
    .split('\n')
    .map((part) => part.trim())
    .find((part) => part.length > 0);
  return line ?? 'unknown error';
}

export function generateOptaInferenceKey(): string {
  return `opta_sk_${randomBytes(24).toString('base64url')}`;
}

export function maskKey(key: string): string {
  if (!key) return '(none)';
  if (key.length <= 10) return '*'.repeat(key.length);
  return `${key.slice(0, 7)}${'*'.repeat(Math.max(0, key.length - 11))}${key.slice(-4)}`;
}

export function resolveConfiguredInferenceKey(connection: { apiKey?: string }): ResolvedKey {
  const envKey = process.env['OPTA_API_KEY']?.trim();
  if (envKey) {
    return { key: envKey, source: 'env' };
  }

  const configKey = connection.apiKey?.trim();
  if (configKey) {
    return { key: configKey, source: 'config' };
  }

  return { key: null, source: 'unset' };
}

function parseRemoteConfigPath(output: string): ParsedRemotePath {
  for (const rawLine of output.split('\n')) {
    const line = rawLine.trim();
    const match = /^__LMX_CFG_PATH__:(.+)$/.exec(line);
    if (match) {
      return { configPath: match[1] ?? null };
    }
  }
  return { configPath: null };
}

async function runRemoteCommand(ssh: SshConfig, command: string): Promise<CommandResult> {
  const commandWithPath = `export PATH=/opt/homebrew/bin:/usr/local/bin:$PATH; ${command}`;
  const args: string[] = [
    '-o',
    'BatchMode=yes',
    '-o',
    `ConnectTimeout=${SSH_CONNECT_TIMEOUT_SECONDS}`,
    '-o',
    'ServerAliveInterval=5',
    '-o',
    'ServerAliveCountMax=2',
  ];

  if (ssh.identityFile) {
    args.push('-i', ssh.identityFile);
  }
  args.push(`${ssh.user}@${ssh.host}`, `bash -lc ${quoteSh(commandWithPath)}`);

  const result = await execa('ssh', args, { reject: false });
  return {
    exitCode: result.exitCode ?? 1,
    stdout: result.stdout,
    stderr: result.stderr,
  };
}

async function selectRemoteHost(
  host: string,
  fallbackHosts: readonly string[],
  sshUser: string,
  identityFile?: string
): Promise<{ selectedHost: string | null; detail: string }> {
  const candidates = resolveRemoteHostCandidates(host, fallbackHosts);
  const selection = await selectReachableRemoteHost(candidates, async (candidateHost) => {
    return runRemoteCommand(
      {
        host: candidateHost,
        user: sshUser,
        identityFile,
      },
      'echo connected'
    );
  });

  if (!selection.selectedHost) {
    const detail = selection.probes
      .map((probe) => `${probe.host}: ${summarizeOutput(probe.detail)}`)
      .join('; ');
    return { selectedHost: null, detail: detail || 'ssh probe failed' };
  }

  return { selectedHost: selection.selectedHost, detail: 'ok' };
}

async function applyRemoteInferenceKey(
  ssh: SshConfig,
  lmxPath: string,
  key: string
): Promise<{ ok: boolean; configPath?: string; message: string }> {
  const script = [
    `OPTA_LMX_PATH=${quoteSh(lmxPath)};`,
    `OPTA_INFERENCE_KEY=${quoteSh(key)};`,
    'export OPTA_LMX_PATH OPTA_INFERENCE_KEY;',
    "python3 - <<'PY'",
    'import os, re, sys',
    'from pathlib import Path',
    '',
    'lmx_path = Path(os.environ["OPTA_LMX_PATH"]).expanduser()',
    'key = os.environ["OPTA_INFERENCE_KEY"]',
    '',
    'candidates = [',
    '    lmx_path / "config" / "config.yaml",',
    '    Path.home() / ".opta-lmx" / "config.yaml",',
    '    lmx_path / "config" / "mono512-current.yaml",',
    '    lmx_path / "config" / "default-config.yaml",',
    ']',
    'target = None',
    'for c in candidates:',
    '    if c.exists():',
    '        target = c',
    '        break',
    '',
    'if target is None:',
    '    print("__LMX_CFG_ERROR__:config_not_found")',
    '    sys.exit(41)',
    '',
    'text = target.read_text(encoding="utf-8")',
    'lines = text.splitlines()',
    '',
    'security_idx = None',
    'for i, line in enumerate(lines):',
    '    if re.match(r"^\\s*security:\\s*$", line):',
    '        security_idx = i',
    '        break',
    '',
    'if security_idx is None:',
    '    lines.append("security:")',
    '    lines.append(f\'  inference_api_key: "{key}"\')',
    'else:',
    '    key_idx = None',
    '    for i, line in enumerate(lines):',
    '        if re.match(r"^\\s*inference_api_key\\s*:", line):',
    '            key_idx = i',
    '            break',
    '    if key_idx is not None:',
    '        m = re.match(r"^(\\s*inference_api_key\\s*:\\s*)(.*?)(\\s*(#.*)?)$", lines[key_idx])',
    '        if m:',
    '            lines[key_idx] = f\'{m.group(1)}"{key}"{m.group(3) or ""}\'',
    '        else:',
    '            lines[key_idx] = f\'  inference_api_key: "{key}"\'',
    '    else:',
    '        lines.insert(security_idx + 1, f\'  inference_api_key: "{key}"\')',
    '',
    'updated = "\\n".join(lines)',
    'if text.endswith("\\n"):',
    '    updated += "\\n"',
    'target.write_text(updated, encoding="utf-8")',
    'print(f"__LMX_CFG_PATH__:{target}")',
    'PY',
  ].join('\n');

  const result = await runRemoteCommand(ssh, script);
  if (result.exitCode !== 0) {
    return {
      ok: false,
      message: summarizeOutput(result.stderr || result.stdout),
    };
  }

  const parsed = parseRemoteConfigPath(`${result.stdout}\n${result.stderr}`);
  if (!parsed.configPath) {
    return {
      ok: false,
      message: 'remote config updated but path marker missing',
    };
  }

  return {
    ok: true,
    configPath: parsed.configPath,
    message: 'remote inference_api_key updated',
  };
}

async function reloadLmxConfig(
  host: string,
  port: number,
  adminKey?: string
): Promise<{ ok: boolean; message: string }> {
  if (!adminKey?.trim()) {
    return {
      ok: false,
      message: 'connection.adminKey is required to trigger /admin/config/reload',
    };
  }

  try {
    const response = await fetch(`http://${host}:${port}/admin/config/reload`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Admin-Key': adminKey.trim(),
      },
      signal: AbortSignal.timeout(5000),
    });
    if (!response.ok) {
      const body = await response.text().catch(() => '');
      return {
        ok: false,
        message: `reload failed: HTTP ${response.status} ${summarizeOutput(body || response.statusText)}`,
      };
    }
    return { ok: true, message: 'LMX config reloaded' };
  } catch (err) {
    const message = err instanceof Error ? err.message : 'reload failed';
    return { ok: false, message };
  }
}

async function verifyInferenceKey(
  host: string,
  port: number,
  key: string
): Promise<{ ok: boolean; message: string }> {
  try {
    const response = await fetch(`http://${host}:${port}/v1/models`, {
      headers: {
        Authorization: `Bearer ${key}`,
      },
      signal: AbortSignal.timeout(5000),
    });
    if (!response.ok) {
      const body = await response.text().catch(() => '');
      return {
        ok: false,
        message: `verification failed: HTTP ${response.status} ${summarizeOutput(body || response.statusText)}`,
      };
    }
    return { ok: true, message: 'key accepted by /v1/models' };
  } catch (err) {
    return {
      ok: false,
      message: err instanceof Error ? err.message : 'verification failed',
    };
  }
}

async function copyToClipboard(value: string): Promise<{ ok: boolean; message: string }> {
  const text = value.trim();
  if (!text) return { ok: false, message: 'empty key cannot be copied' };

  if (process.platform === 'darwin') {
    try {
      const result = await execa('pbcopy', [], { input: text, reject: false });
      return result.exitCode === 0
        ? { ok: true, message: 'copied to clipboard (pbcopy)' }
        : { ok: false, message: result.stderr || 'pbcopy failed' };
    } catch (err) {
      return {
        ok: false,
        message: err instanceof Error ? err.message : 'pbcopy failed',
      };
    }
  }

  if (process.platform === 'win32') {
    const windowsCandidates: Array<{ cmd: string; args: string[] }> = [
      {
        cmd: 'powershell',
        args: [
          '-NoProfile',
          '-NonInteractive',
          '-Command',
          'Set-Clipboard -Value ([Console]::In.ReadToEnd())',
        ],
      },
      {
        cmd: 'clip',
        args: [],
      },
    ];
    const attempts: string[] = [];
    for (const candidate of windowsCandidates) {
      try {
        const result = await execa(candidate.cmd, candidate.args, {
          input: text,
          reject: false,
        });
        if (result.exitCode === 0) {
          return { ok: true, message: `copied to clipboard (${candidate.cmd})` };
        }
        attempts.push(`${candidate.cmd}: ${result.stderr || `exit ${result.exitCode ?? 1}`}`);
      } catch (err) {
        attempts.push(
          `${candidate.cmd}: ${err instanceof Error ? err.message : 'failed to execute'}`
        );
      }
    }
    return { ok: false, message: `no clipboard utility succeeded (${attempts.join('; ')})` };
  }

  const linuxCandidates: Array<{ cmd: string; args: string[] }> = [
    { cmd: 'wl-copy', args: [] },
    { cmd: 'xclip', args: ['-selection', 'clipboard'] },
    { cmd: 'xsel', args: ['--clipboard', '--input'] },
  ];
  const attempts: string[] = [];
  for (const candidate of linuxCandidates) {
    try {
      const result = await execa(candidate.cmd, candidate.args, {
        input: text,
        reject: false,
      });
      if (result.exitCode === 0) {
        return { ok: true, message: `copied to clipboard (${candidate.cmd})` };
      }
      attempts.push(`${candidate.cmd}: ${result.stderr || `exit ${result.exitCode ?? 1}`}`);
    } catch (err) {
      attempts.push(
        `${candidate.cmd}: ${err instanceof Error ? err.message : 'failed to execute'}`
      );
    }
  }

  if (attempts.length > 0) {
    return { ok: false, message: `no clipboard utility succeeded (${attempts.join('; ')})` };
  }
  return { ok: false, message: 'no supported clipboard utility found' };
}

export async function keyCreate(opts?: KeyCreateOptions): Promise<void> {
  const config = await loadConfig();
  const key = opts?.value?.trim() || generateOptaInferenceKey();

  const store = await getConfigStore();
  store.set('connection.apiKey', key);

  const remoteRequested = opts?.remote !== false;
  const shouldCopy = opts?.copy !== false;
  const remoteHost = config.connection.host;
  const output: Record<string, unknown> = {
    key,
    source: 'config',
    remote: null,
    copy: null,
  };

  if (remoteRequested && !isLocalHost(remoteHost)) {
    if (isWindows) {
      output.remote = {
        ok: false,
        message:
          'remote Studio sync requires POSIX SSH shell tools; run from macOS/Linux or use --no-remote',
      };
      if (!opts?.json) {
        console.log(
          chalk.yellow('!') +
            ' Studio sync skipped on Windows: use --no-remote or run from macOS/Linux'
        );
      }
    } else {
      const selected = await selectRemoteHost(
        remoteHost,
        config.connection.fallbackHosts,
        config.connection.ssh.user,
        expandHome(config.connection.ssh.identityFile)
      );
      if (!selected.selectedHost) {
        output.remote = { ok: false, message: `ssh unavailable: ${selected.detail}` };
        if (!opts?.json) {
          console.log(chalk.yellow('!') + ` Studio sync skipped: ${selected.detail}`);
        }
      } else {
        const ssh: SshConfig = {
          host: selected.selectedHost,
          user: config.connection.ssh.user,
          identityFile: expandHome(config.connection.ssh.identityFile),
        };
        const remoteApply = await applyRemoteInferenceKey(ssh, config.connection.ssh.lmxPath, key);
        if (!remoteApply.ok) {
          output.remote = { ok: false, message: remoteApply.message };
          if (!opts?.json) {
            console.log(chalk.red('✗') + ` Studio key update failed: ${remoteApply.message}`);
          }
        } else {
          const reload = await reloadLmxConfig(
            ssh.host,
            config.connection.port,
            config.connection.adminKey
          );
          const verify = await verifyInferenceKey(ssh.host, config.connection.port, key);
          output.remote = {
            ok: remoteApply.ok && reload.ok && verify.ok,
            host: ssh.host,
            configPath: remoteApply.configPath,
            reload: reload.message,
            verify: verify.message,
          };

          if (!opts?.json) {
            console.log(chalk.green('✓') + ` Studio key synced on ${ssh.host}`);
            console.log(chalk.dim(`  Config: ${remoteApply.configPath}`));
            console.log(chalk.dim(`  Reload: ${reload.message}`));
            console.log(chalk.dim(`  Verify: ${verify.message}`));
          }
        }
      }
    }
  } else if (remoteRequested) {
    output.remote = { ok: true, message: 'remote sync skipped for localhost' };
  } else {
    output.remote = { ok: true, message: 'remote sync disabled (--no-remote)' };
  }

  if (shouldCopy) {
    const copied = await copyToClipboard(key);
    output.copy = copied;
    if (!opts?.json) {
      if (copied.ok) {
        console.log(chalk.green('✓') + ` ${copied.message}`);
      } else {
        console.log(chalk.yellow('!') + ` ${copied.message}`);
      }
    }
  }

  if (opts?.json) {
    const safeOutput = { ...output };
    if (typeof safeOutput['key'] === 'string') safeOutput['key'] = maskKey(safeOutput['key']);
    console.log(JSON.stringify(safeOutput, null, 2));
    return;
  }

  console.log('');
  console.log(chalk.bold('Opta Inference API Key'));
  console.log(`Base URL: http://${config.connection.host}:${config.connection.port}/v1`);
  console.log(`API Key:  ${maskKey(key)}`);
  console.log(
    chalk.dim('(Full key was copied to clipboard — paste it now, it will not be shown again)')
  );
  console.log(chalk.dim('Use in clients as Authorization: Bearer <API Key>'));
}

export async function keyShow(opts?: KeyShowOptions): Promise<void> {
  const config = await loadConfig();
  const resolved = resolveConfiguredInferenceKey(config.connection);

  if (!resolved.key) {
    if (opts?.json) {
      console.log(
        JSON.stringify(
          {
            key: null,
            source: resolved.source,
            configured: false,
          },
          null,
          2
        )
      );
      return;
    }
    console.log(chalk.yellow('!') + ' No inference API key configured yet.');
    console.log(chalk.dim('Run: opta key create'));
    return;
  }

  const displayKey = opts?.reveal ? resolved.key : maskKey(resolved.key);
  if (opts?.copy) {
    const copied = await copyToClipboard(resolved.key);
    if (!opts?.json) {
      if (copied.ok) console.log(chalk.green('✓') + ` ${copied.message}`);
      else console.log(chalk.yellow('!') + ` ${copied.message}`);
    }
  }

  if (opts?.json) {
    console.log(
      JSON.stringify(
        {
          key: opts?.reveal ? resolved.key : displayKey,
          source: resolved.source,
          configured: true,
        },
        null,
        2
      )
    );
    return;
  }

  console.log(`Key (${resolved.source}): ${displayKey}`);
  if (!opts?.reveal) {
    console.log(chalk.dim('Tip: use --reveal to print full key, or --copy to copy.'));
  }
}

export async function keyCopy(opts?: KeyCopyOptions): Promise<void> {
  const config = await loadConfig();
  const resolved = resolveConfiguredInferenceKey(config.connection);
  if (!resolved.key) {
    const message = 'No inference API key configured yet. Run: opta key create';
    if (opts?.json) {
      console.log(JSON.stringify({ ok: false, message }, null, 2));
    } else {
      console.log(chalk.yellow('!') + ` ${message}`);
    }
    throw new ExitError(EXIT.NOT_FOUND);
  }

  const copied = await copyToClipboard(resolved.key);
  if (opts?.json) {
    console.log(JSON.stringify(copied, null, 2));
  }

  if (copied.ok) {
    if (!opts?.json) {
      console.log(chalk.green('✓') + ` ${copied.message}`);
    }
    return;
  }

  if (!opts?.json) {
    console.log(chalk.red('✗') + ` Failed to copy key: ${copied.message}`);
  }
  throw new ExitError(EXIT.ERROR);
}

import chalk from 'chalk';
import { loadConfig, saveConfig, getConfigStore } from '../core/config.js';
import { connectMcpServer } from '../mcp/client.js';
import { errorMessage } from '../utils/errors.js';
import { createPlaywrightMcpServerConfig } from '../browser/mcp-bootstrap.js';
import type { BrowserMode } from '../browser/types.js';

interface McpListOptions {
  json?: boolean;
}

interface McpAddPlaywrightOptions {
  name?: string;
  mode?: BrowserMode;
  command?: string;
  packageName?: string;
  allowedHosts?: string[];
  blockedOrigins?: string[];
  env?: string;
}

interface McpHealthOptions {
  json?: boolean;
  watch?: number;
  probeStdio?: boolean;
  timeoutMs?: number;
}

const PLAYWRIGHT_MCP_SERVER_KEY = 'playwright';

function parseEnvPairs(raw?: string): Record<string, string> {
  const env: Record<string, string> = {};
  if (!raw) return env;

  for (const pair of raw.split(',')) {
    const idx = pair.indexOf('=');
    if (idx <= 0) continue;

    const key = pair.slice(0, idx).trim();
    const value = pair.slice(idx + 1).trim();
    if (!key || !value) continue;

    env[key] = value;
  }

  return env;
}

export async function mcpList(opts: McpListOptions): Promise<void> {
  const config = await loadConfig();
  const servers = config.mcp.servers;
  const entries = Object.entries(servers);

  if (entries.length === 0) {
    console.log(chalk.dim('No MCP servers configured.'));
    console.log(chalk.dim('\nAdd one with: opta mcp add <name> <command>'));
    return;
  }

  if (opts.json) {
    console.log(JSON.stringify(servers, null, 2));
    return;
  }

  console.log(chalk.bold(`\n${entries.length} MCP server(s):\n`));
  for (const [name, cfg] of entries) {
    const transport =
      cfg.transport === 'stdio' ? `${cfg.command} ${cfg.args.join(' ')}`.trim() : cfg.url;
    console.log(`  ${chalk.cyan(name)}  ${chalk.dim(cfg.transport)}  ${transport}`);
  }
  console.log();
}

export async function mcpAdd(name: string, command: string, opts: { env?: string }): Promise<void> {
  const parts = command.split(/\s+/);
  const cmd = parts[0]!;
  const args = parts.slice(1);

  const env = parseEnvPairs(opts.env);

  await saveConfig({
    mcp: {
      servers: {
        [name]: { transport: 'stdio', command: cmd, args, env },
      },
    },
  });

  console.log(chalk.green('\u2713') + ` Added MCP server: ${name}`);
}

export async function mcpAddPlaywright(opts: McpAddPlaywrightOptions = {}): Promise<void> {
  const name = opts.name?.trim() || PLAYWRIGHT_MCP_SERVER_KEY;
  const env = parseEnvPairs(opts.env);
  const serverConfig = await createPlaywrightMcpServerConfig({
    command: opts.command,
    packageName: opts.packageName,
    mode: opts.mode,
    allowedHosts: opts.allowedHosts,
    blockedOrigins: opts.blockedOrigins,
    env,
  });

  await saveConfig({
    mcp: {
      servers: {
        [name]: serverConfig,
      },
    },
  });

  console.log(chalk.green('\u2713') + ` Added MCP server: ${name}`);
}

export async function mcpRemove(name: string): Promise<void> {
  const store = await getConfigStore();
  const servers = (store.get('mcp.servers') as Record<string, unknown>) ?? {};

  if (!(name in servers)) {
    console.log(chalk.yellow(`MCP server "${name}" not found in config.`));
    return;
  }

  Reflect.deleteProperty(servers, name);
  store.set('mcp.servers', servers);
  console.log(chalk.green('\u2713') + ` Removed MCP server: ${name}`);
}

export async function mcpTest(name: string): Promise<void> {
  const config = await loadConfig();
  const serverConfig = config.mcp.servers[name];

  if (!serverConfig) {
    console.log(chalk.red('\u2717') + ` MCP server "${name}" not found in config.`);
    return;
  }

  console.log(chalk.dim(`Connecting to ${name}...`));
  try {
    const conn = await connectMcpServer(name, serverConfig);
    console.log(chalk.green('\u2713') + ` Connected to ${name}`);
    console.log(chalk.dim(`  ${conn.tools.length} tools available:`));
    for (const tool of conn.tools) {
      console.log(`    ${chalk.cyan(tool.name)} — ${tool.description}`);
    }
    await conn.close();
    console.log(chalk.green('\u2713') + ' Connection closed cleanly');
  } catch (err) {
    console.log(chalk.red('\u2717') + ` Failed: ${errorMessage(err)}`);
  }
}

type McpHealthStatus = 'healthy' | 'down' | 'skipped';

interface McpHealthServerResult {
  name: string;
  transport: string;
  status: McpHealthStatus;
  tools: number;
  latencyMs?: number;
  error?: string;
}

interface McpHealthSnapshot {
  generatedAt: string;
  summary: {
    total: number;
    healthy: number;
    down: number;
    skipped: number;
  };
  servers: McpHealthServerResult[];
}

async function probeServer(
  name: string,
  serverConfig: {
    transport: string;
    command?: string;
    url?: string;
    args?: string[];
    env?: Record<string, string>;
  },
  timeoutMs: number
): Promise<McpHealthServerResult> {
  const startedAt = Date.now();
  const connectPromise = connectMcpServer(
    name,
    serverConfig as Parameters<typeof connectMcpServer>[1]
  );
  let timedOut = false;
  let timeoutId: ReturnType<typeof setTimeout> | undefined;

  try {
    const timeoutPromise = new Promise<never>((_, reject) => {
      timeoutId = setTimeout(() => {
        timedOut = true;
        reject(new Error(`timeout after ${timeoutMs}ms`));
      }, timeoutMs);
    });
    const conn = await Promise.race([connectPromise, timeoutPromise]);
    const latencyMs = Date.now() - startedAt;
    const tools = conn.tools.length;
    await conn.close();
    return {
      name,
      transport: serverConfig.transport,
      status: 'healthy',
      tools,
      latencyMs,
    };
  } catch (err) {
    if (timedOut) {
      // Best effort: if connection resolves after timeout, close it.
      void connectPromise
        .then(async (conn) => {
          await conn.close();
        })
        .catch(() => {});
    }
    return {
      name,
      transport: serverConfig.transport,
      status: 'down',
      tools: 0,
      error: errorMessage(err),
    };
  } finally {
    if (timeoutId) clearTimeout(timeoutId);
  }
}

async function buildHealthSnapshot(
  opts: Pick<McpHealthOptions, 'probeStdio' | 'timeoutMs'>
): Promise<McpHealthSnapshot> {
  const config = await loadConfig();
  const servers = config.mcp?.servers ?? {};
  const entries = Object.entries(servers);

  const timeoutMs = Math.max(500, opts.timeoutMs ?? 5000);
  const probeStdio = opts.probeStdio === true;

  const probes = entries.map(async ([name, serverConfig]) => {
    if (serverConfig.transport === 'stdio' && !probeStdio) {
      return {
        name,
        transport: serverConfig.transport,
        status: 'skipped' as const,
        tools: 0,
        error: 'stdio probe disabled (use --probe-stdio)',
      };
    }
    return probeServer(name, serverConfig, timeoutMs);
  });

  const serversResult = await Promise.all(probes);

  const summary = {
    total: serversResult.length,
    healthy: serversResult.filter((r) => r.status === 'healthy').length,
    down: serversResult.filter((r) => r.status === 'down').length,
    skipped: serversResult.filter((r) => r.status === 'skipped').length,
  };

  return {
    generatedAt: new Date().toISOString(),
    summary,
    servers: serversResult,
  };
}

function formatServerLine(server: McpHealthServerResult): string {
  const statusColor =
    server.status === 'healthy' ? chalk.green('healthy') :
    server.status === 'down' ? chalk.red('down') :
    chalk.yellow('skipped');

  const latency = server.latencyMs !== undefined ? `${server.latencyMs}ms` : '-';
  const tools = `${server.tools} tool${server.tools === 1 ? '' : 's'}`;
  const error = server.error ? ` — ${server.error}` : '';
  return `  ${chalk.cyan(server.name)}  ${chalk.dim(server.transport)}  ${statusColor}  ${latency}  ${tools}${error}`;
}

function printHealthSnapshot(snapshot: McpHealthSnapshot): void {
  console.log(chalk.bold(`\nMCP health @ ${snapshot.generatedAt}\n`));
  if (snapshot.summary.total === 0) {
    console.log(chalk.dim('No MCP servers configured.\n'));
    return;
  }

  for (const server of snapshot.servers) {
    console.log(formatServerLine(server));
  }
  console.log(
    `\nSummary: ${chalk.green(`${snapshot.summary.healthy} healthy`)}, ` +
      `${chalk.red(`${snapshot.summary.down} down`)}, ` +
      `${chalk.yellow(`${snapshot.summary.skipped} skipped`)} ` +
      `(total ${snapshot.summary.total})\n`
  );
}

export async function mcpHealth(opts: McpHealthOptions = {}): Promise<void> {
  const intervalSec = Number(opts.watch ?? 0);
  const watchMode = Number.isFinite(intervalSec) && intervalSec > 0;

  if (!watchMode) {
    const snapshot = await buildHealthSnapshot(opts);
    if (opts.json) {
      console.log(JSON.stringify(snapshot, null, 2));
      return;
    }
    printHealthSnapshot(snapshot);
    return;
  }

  if (opts.json) {
    console.log(
      chalk.yellow('warning: --json with --watch prints newline-delimited JSON snapshots.')
    );
  }

  // eslint-disable-next-line no-constant-condition
  while (true) {
    const snapshot = await buildHealthSnapshot(opts);
    if (opts.json) {
      console.log(JSON.stringify(snapshot));
    } else {
      console.clear();
      printHealthSnapshot(snapshot);
      console.log(chalk.dim(`Watching every ${intervalSec}s (Ctrl+C to stop)\n`));
    }
    await new Promise((resolve) => setTimeout(resolve, Math.round(intervalSec * 1000)));
  }
}

import { basename } from 'node:path';
