interface MemorySyncOptions {
  scope?: 'all' | 'provider' | 'main' | 'atpo' | 'model';
  provider?: string;
  model?: string;
  force?: boolean;
  dryRun?: boolean;
  json?: boolean;
  policy?: 'skip' | 'append' | 'replace';
