import { getConfigDir } from '../platform/paths.js';
import { discoverLmxHosts } from '../lmx/mdns-discovery.js';
import { LmxApiError, LmxClient } from '../lmx/client.js';

// ── Onboard marker (first-run detection) ────────────────────────────────────

const ONBOARD_MARKER = join(getConfigDir(), '.onboarded');

export async function isFirstRun(): Promise<boolean> {
  try {
    await access(ONBOARD_MARKER);
    return false;
  } catch {
    return true;
  }
}

export async function markOnboarded(): Promise<void> {
  const dir = getConfigDir();
  await mkdir(dir, { recursive: true });
  await writeFile(ONBOARD_MARKER, new Date().toISOString(), 'utf-8');
}

type ProviderName = OptaConfig['provider']['active'];
type OnboardingProvider = Extract<ProviderName, 'lmx' | 'anthropic' | 'gemini' | 'openai' | 'opencode_zen'>;

function normalizeOnboardingProvider(input: string | undefined): OnboardingProvider {
  if (input === 'anthropic' || input === 'gemini' || input === 'openai' || input === 'opencode_zen') {
    return input;
  }
  return 'lmx';
}

interface ProviderFieldConfig {
  provider: OnboardingProvider;
  configured: boolean;
  storage: 'none' | 'config' | 'keychain';
  maskedSuffix?: string;
}

export interface OnboardingProfileInput {
  provider?: OnboardingProvider;
  lmxHost?: string;
  lmxPort?: number;
  lmxAdminKey?: string;
  anthropicApiKey?: string;
  geminiApiKey?: string;
  openaiApiKey?: string;
  opencodeZenApiKey?: string;
  autonomyLevel?: number;
  tuiDefault?: boolean;
  providerKeyStorage?: 'none' | 'config' | 'keychain';
}

export interface OnboardingProfileResult {
  ok: true;
  provider: OnboardingProvider;
  connection: {
    host: string;
    port: number;
  };
  autonomyLevel: number;
  tuiDefault: boolean;
  keyConfigured: ProviderFieldConfig[];
  onboarded: true;
}

interface ProviderKeyPersistenceResult {
  configValue: string;
  configured: boolean;
  storage: 'none' | 'config' | 'keychain';
  maskedSuffix?: string;
}

function clampAutonomyLevel(level: number): number {
  if (!Number.isFinite(level)) return 2;
  return Math.max(1, Math.min(5, Math.trunc(level)));
}

function normalizePort(port: number): number {
  if (!Number.isFinite(port)) return 1234;
  const intPort = Math.trunc(port);
  if (intPort < 1 || intPort > 65_535) return 1234;
  return intPort;
}

async function resolveDefaultLmxConnection(
  existing: OptaConfig | null
): Promise<{ host: string; port: number }> {
  if (existing?.connection?.host?.trim()) {
    return {
      host: existing.connection.host.trim(),
      port: normalizePort(existing.connection.port),
    };
  }

  try {
    const discovered = await discoverLmxHosts(1200);
    const first = discovered[0];
    if (first?.host?.trim()) {
      return {
        host: first.host.trim(),
        port: normalizePort(first.port),
      };
    }
  } catch {
    // Discovery is best effort.
  }

  return { host: 'localhost', port: 1234 };
}

export async function applyOnboardingProfile(
  input: OnboardingProfileInput = {}
): Promise<OnboardingProfileResult> {
  const existing = await loadConfig().catch(() => null);

  const provider: OnboardingProvider = normalizeOnboardingProvider(
    input.provider ?? existing?.provider?.active
  );
  const defaultLmxConnection = await resolveDefaultLmxConnection(existing);
  const lmxHost = input.lmxHost?.trim() || defaultLmxConnection.host;
  const lmxPort = normalizePort(input.lmxPort ?? defaultLmxConnection.port);
  const autonomyLevel = clampAutonomyLevel(input.autonomyLevel ?? existing?.autonomy?.level ?? 2);
  const tuiDefault = input.tuiDefault ?? existing?.tui?.default ?? false;

  const configured: ProviderFieldConfig[] = [];

  const anthropicApiKey = (input.anthropicApiKey ?? existing?.provider?.anthropic?.apiKey ?? '').trim();
  const geminiApiKey = (input.geminiApiKey ?? existing?.provider?.gemini?.apiKey ?? '').trim();
  const openaiApiKey = (input.openaiApiKey ?? existing?.provider?.openai?.apiKey ?? '').trim();
  const opencodeZenApiKey = (
    input.opencodeZenApiKey ??
    existing?.provider?.opencode_zen?.apiKey ??
    ''
  ).trim();

  const configPatch: Record<string, unknown> = {
    'autonomy.level': autonomyLevel,
    'tui.default': tuiDefault,
    'provider.active': provider,
  };

  if (provider === 'lmx') {
    configPatch['connection.host'] = lmxHost;
    configPatch['connection.port'] = String(lmxPort);
    if (input.lmxAdminKey !== undefined) {
      configPatch['connection.adminKey'] = input.lmxAdminKey.trim();
    }
  } else {
    const providerKeyStorage = input.providerKeyStorage ?? 'config';
    const persistProviderKey = async (
      targetProvider: OnboardingProvider,
      apiKey: string
    ): Promise<ProviderKeyPersistenceResult> => {
      const trimmed = apiKey.trim();
      if (!trimmed) {
        return {
          configValue: '',
          configured: false,
          storage: 'none',
        };
      }

      if (providerKeyStorage === 'keychain' && isKeychainAvailable()) {
        const store = async (value: string): Promise<boolean> => {
          if (targetProvider === 'anthropic') return storeAnthropicKey(value);
          if (targetProvider === 'gemini') return storeGeminiKey(value);
          if (targetProvider === 'openai') return storeOpenaiKey(value);
          return storeOpencodeZenKey(value);
        };

        const stored = await store(trimmed);
        if (stored) {
          return {
            configValue: '',
            configured: true,
            storage: 'keychain',
            maskedSuffix: trimmed.slice(-4),
          };
        }
      }

      return {
        configValue: trimmed,
        configured: true,
        storage: 'config',
        maskedSuffix: trimmed.slice(-4),
      };
    };

    if (provider === 'anthropic') {
      const persisted = await persistProviderKey('anthropic', anthropicApiKey);
      configPatch['provider.anthropic.apiKey'] = persisted.configValue;
      configured.push({
        provider: 'anthropic',
        configured: persisted.configured,
        storage: persisted.storage,
        maskedSuffix: persisted.maskedSuffix,
      });
    } else if (provider === 'gemini') {
      const persisted = await persistProviderKey('gemini', geminiApiKey);
      configPatch['provider.gemini.apiKey'] = persisted.configValue;
      configured.push({
        provider: 'gemini',
        configured: persisted.configured,
        storage: persisted.storage,
        maskedSuffix: persisted.maskedSuffix,
      });
    } else if (provider === 'openai') {
      const persisted = await persistProviderKey('openai', openaiApiKey);
      configPatch['provider.openai.apiKey'] = persisted.configValue;
      configured.push({
        provider: 'openai',
        configured: persisted.configured,
        storage: persisted.storage,
        maskedSuffix: persisted.maskedSuffix,
      });
    } else if (provider === 'opencode_zen') {
      const persisted = await persistProviderKey('opencode_zen', opencodeZenApiKey);
      configPatch['provider.opencode_zen.apiKey'] = persisted.configValue;
      configured.push({
        provider: 'opencode_zen',
        configured: persisted.configured,
        storage: persisted.storage,
        maskedSuffix: persisted.maskedSuffix,
      });
    }
  }

  await saveConfig(configPatch);

  await markOnboarded();

  return {
    ok: true,
    provider,
    connection: {
      host: lmxHost,
      port: lmxPort,
    },
    autonomyLevel,
    tuiDefault,
    keyConfigured: configured,
    onboarded: true,
  };
}

// ── Interactive prompt helpers ───────────────────────────────────────────────

/** Returns trimmed string, uses defaultValue if blank. */
async function ask(rl: readline.Interface, prompt: string, defaultValue?: string): Promise<string> {
  const hint = defaultValue ? chalk.dim(` [${defaultValue}]`) : '';
  const raw = await rl.question(`${prompt}${hint}: `);
  return raw.trim() || defaultValue || '';
}

/** Y/n prompt, defaults to yes when defaultYes is true. */
async function confirm(
  rl: readline.Interface,
  prompt: string,
  defaultYes = true
): Promise<boolean> {
  const hint = chalk.dim(defaultYes ? ' [Y/n]' : ' [y/N]');
  const raw = await rl.question(`${prompt}${hint}: `);
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) return defaultYes;
  return trimmed.startsWith('y');
}


type CloudKeyResult = {
  keyInput: string;
  keyForConfig: string;
  keyStorage: 'none' | 'config' | 'keychain';
};

async function promptProviderApiKey(
  rl: readline.Interface,
  provider: OnboardingProvider,
  label: string,
  existingKey: string,
): Promise<CloudKeyResult> {
  let keyStorage: 'none' | 'config' | 'keychain' = 'none';
  let keyInput = '';
  let keyForConfig = '';

  keyInput = await ask(rl, `  ${label} API key`, existingKey);
  const trimmed = keyInput.trim();

  if (!trimmed) {
    keyStorage = 'none';
    keyForConfig = '';
  } else if (isKeychainAvailable()) {
    const storeSecurely = await confirm(rl, '  Store key securely in OS keychain?', true);
    if (storeSecurely) {
      const store = async (value: string): Promise<boolean> => {
        if (provider === 'anthropic') return storeAnthropicKey(value);
        if (provider === 'gemini') return storeGeminiKey(value);
        if (provider === 'openai') return storeOpenaiKey(value);
        return storeOpencodeZenKey(value);
      };

      const stored = await store(trimmed);
      if (stored) {
        keyStorage = 'keychain';
        keyForConfig = '';
        console.log(chalk.green('  ✓ Key stored in keychain (not saved in plaintext config)'));
      } else {
        keyStorage = 'config';
        keyForConfig = trimmed;
        console.log(chalk.yellow('  ! Keychain write failed — saving key in config instead'));
      }
    } else {
      keyStorage = 'config';
      keyForConfig = trimmed;
    }
  } else {
    keyStorage = 'config';
    keyForConfig = trimmed;
  }

  return {
    keyInput: trimmed,
    keyForConfig,
    keyStorage,
  };
}

/** Presents a numbered list and returns the zero-based index of the chosen item. */
async function choose(
  rl: readline.Interface,
  prompt: string,
  choices: string[],
  defaultIndex = 0
): Promise<number> {
  if (prompt) console.log(prompt);
  choices.forEach((c, i) => {
    const marker = i === defaultIndex ? chalk.cyan('›') : ' ';
    console.log(`  ${marker} ${chalk.bold(String(i + 1))}. ${c}`);
  });
  const raw = await rl.question(chalk.dim(`  Choice [${defaultIndex + 1}]: `));
  const trimmed = raw.trim();
  if (!trimmed) return defaultIndex;
  const n = parseInt(trimmed, 10);
  if (isNaN(n) || n < 1 || n > choices.length) return defaultIndex;
  return n - 1;
}

// ── Main wizard ──────────────────────────────────────────────────────────────

export async function runOnboarding(): Promise<void> {
  const rl = readline.createInterface({ input, output });

  // Header
  console.log('');
  console.log(chalk.bold.hex('#8b5cf6')('  OPTA CODE'));
  console.log(chalk.bold.hex('#a855f7')('  OPTA CODE'));
  console.log('');
  console.log(chalk.bold('  Setup Wizard') + chalk.dim(' — Configure Opta CLI for first use'));
  console.log('');

  try {
    // Load existing config for pre-populated defaults
    const existing = await loadConfig().catch(() => null);

    // ── Step 1: Provider ───────────────────────────────────────────────────
    console.log(chalk.bold.hex('#8b5cf6')('Step 1/3 — AI Provider'));
    console.log(chalk.dim('  Choose how Opta connects to AI models'));
    console.log('');

    const providerChoice = await choose(
      rl,
      '',
      [
        'Local LMX  ' + chalk.dim('— Mac Studio inference server (recommended)'),
        'Anthropic  ' + chalk.dim('— Cloud API with your API key'),
        'Gemini    ' + chalk.dim('— Google OpenAI-compatible endpoint (Gemini)'),
        'OpenAI    ' + chalk.dim('— OpenAI/Codex-compatible endpoint'),
        'Opencode Zen' + chalk.dim('— Alternative provider endpoint'),
      ],
      (() => {
        const active = normalizeOnboardingProvider(existing?.provider?.active);
        if (active === 'anthropic') return 1;
        if (active === 'gemini') return 2;
        if (active === 'openai') return 3;
        if (active === 'opencode_zen') return 4;
        return 0;
      })(),
    );

    const provider: OnboardingProvider =
      providerChoice === 0
        ? 'lmx'
        : providerChoice === 2
          ? 'gemini'
          : providerChoice === 3
            ? 'openai'
            : providerChoice === 4
              ? 'opencode_zen'
              : 'anthropic';

    let lmxHost = 'localhost';
    let lmxPort = 1234;
    let lmxAdminKey = '';
    let cloudKey = '';
    let cloudKeyForConfig = '';
    let cloudKeyStorage: 'none' | 'config' | 'keychain' = 'none';

    if (provider === 'lmx') {
      console.log('');

      // Auto-discover LMX servers on LAN
      process.stdout.write(chalk.dim('  Scanning LAN for Opta-LMX servers...'));
      let discoveredHosts: Array<{ host: string; port: number; latencyMs: number }> = [];
      try {
        const { discoverLmxHosts } = await import('../lmx/mdns-discovery.js');
        discoveredHosts = await discoverLmxHosts(2000);
      } catch { /* discovery is best-effort */ }

      if (discoveredHosts.length > 0) {
        process.stdout.write(
          '\r' +
            chalk.green(`  Found ${discoveredHosts.length} LMX server${discoveredHosts.length !== 1 ? 's' : ''} on LAN`) +
            '                    \n'
        );
        for (const d of discoveredHosts) {
          console.log(
            chalk.dim(`    ${d.host}:${d.port}`) +
              chalk.dim(` (${d.latencyMs}ms)`)
          );
        }
        console.log('');

        const useDiscovered = await confirm(
          rl,
          `  Use ${discoveredHosts[0]!.host}:${discoveredHosts[0]!.port}?`,
          true
        );
        if (useDiscovered) {
          lmxHost = discoveredHosts[0]!.host;
          lmxPort = discoveredHosts[0]!.port;
        } else {
          lmxHost = await ask(rl, '  LMX host', existing?.connection?.host || 'localhost');
          const portStr = await ask(rl, '  LMX port', String(existing?.connection?.port || 1234));
          lmxPort = parseInt(portStr, 10) || 1234;
        }
      } else {
        process.stdout.write(
          '\r' + chalk.dim('  No LMX servers found on LAN — enter address manually') + '         \n'
        );
        lmxHost = await ask(rl, '  LMX host', existing?.connection?.host || 'localhost');
        const portStr = await ask(rl, '  LMX port', String(existing?.connection?.port || 1234));
        lmxPort = parseInt(portStr, 10) || 1234;
      }
      lmxAdminKey = await ask(
        rl,
        '  LMX admin key (optional)',
        existing?.connection?.adminKey || ''
      );

      const testConn = await confirm(rl, '  Test connection now?', true);
      if (testConn) {
        process.stdout.write(chalk.dim('  Checking LMX liveness…'));
        try {
          const client = new LmxClient({
            host: lmxHost,
            port: lmxPort,
            adminKey: lmxAdminKey.trim() || existing?.connection?.adminKey,
            adminKeysByHost: existing?.connection?.adminKeysByHost,
          });
          await client.health({ timeoutMs: 3_000, maxRetries: 0 });
          process.stdout.write(
            '\r' + chalk.green('  ✓ LMX reachable at ' + lmxHost + ':' + lmxPort) + '\n'
          );

          process.stdout.write(chalk.dim('  Checking admin endpoint access…'));
          try {
            await client.status({ timeoutMs: 3_000, maxRetries: 0 });
            process.stdout.write(
              '\r' + chalk.green('  ✓ Admin endpoints accessible') + '\n'
            );
          } catch (err) {
            if (
              err instanceof LmxApiError &&
              (err.code === 'unauthorized' || err.status === 401 || err.status === 403)
            ) {
              process.stdout.write(
                '\r' +
                  chalk.yellow(
                    '  ! LMX is reachable but /admin endpoints are unauthorized (invalid or missing admin key)'
                  ) +
                  '\n'
              );
              console.log(
                chalk.dim(
                  '    Set key:   opta config set connection.adminKey <key>'
                )
              );
              console.log(
                chalk.dim(
                  '    Set map:   opta config set connection.adminKeysByHost \'{"host":"key"}\''
                )
              );
              console.log(
                chalk.dim(
                  '    Clear key: opta config delete connection.adminKey'
                )
              );
            } else {
              process.stdout.write(
                '\r' +
                  chalk.yellow(
                    '  ! LMX reachable, but admin check could not be completed'
                  ) +
                  '\n'
              );
            }
          }
        } catch {
          process.stdout.write(
            '\r' +
              chalk.red('  ✗ Could not reach ' + lmxHost + ':' + lmxPort) +
              chalk.dim(' (saved anyway)') +
              '\n'
          );
        }
      }
    } else {
      console.log('');
      const existingCloudKey =
        provider === 'anthropic'
          ? existing?.provider?.anthropic?.apiKey || ''
          : provider === 'gemini'
            ? existing?.provider?.gemini?.apiKey || ''
            : provider === 'openai'
              ? existing?.provider?.openai?.apiKey || ''
              : existing?.provider?.opencode_zen?.apiKey || '';

      const cloudPromptLabel =
        provider === 'anthropic'
          ? 'Anthropic'
          : provider === 'gemini'
            ? 'Gemini'
            : provider === 'openai'
              ? 'OpenAI/Codex'
              : 'Opencode Zen';

      const keyPrompt = await promptProviderApiKey(rl, provider, cloudPromptLabel, existingCloudKey);
      cloudKey = keyPrompt.keyInput;
      cloudKeyForConfig = keyPrompt.keyForConfig;
      cloudKeyStorage = keyPrompt.keyStorage;
    }

    // ── Step 2: Preferences ────────────────────────────────────────────────
    console.log('');
    console.log(chalk.bold.hex('#8b5cf6')('Step 2/3 — Preferences'));
    console.log('');

    const autonomyChoice = await choose(
      rl,
      '  Default autonomy level',
      [
        'Supervised  ' + chalk.dim('— Ask before every write, edit, or run'),
        'Balanced    ' + chalk.dim('— Ask for risky actions only (recommended)'),
        'Autonomous  ' + chalk.dim('— Auto-approve safe operations'),
      ],
      Math.max(0, Math.min(2, (existing?.autonomy?.level ?? 2) - 1))
    );
    // autonomyChoice is 0/1/2, autonomyLevel is 1/2/3 matching the schema
    const autonomyLevel = autonomyChoice + 1;

    const tuiDefault = await confirm(
      rl,
      '  Enable TUI (full-screen mode) by default?',
      existing?.tui?.default ?? false
    );

    // ── Step 3: Review & Confirm ───────────────────────────────────────────
    console.log('');
    console.log(chalk.bold.hex('#8b5cf6')('Step 3/3 — Review & Apply'));
    console.log('');
    console.log(chalk.dim('  Settings to save:'));
    const providerLabel =
      provider === 'lmx'
        ? 'Local LMX'
        : provider === 'anthropic'
          ? 'Anthropic Cloud'
          : provider === 'gemini'
            ? 'Gemini Cloud'
            : provider === 'openai'
              ? 'OpenAI/Codex Cloud'
              : 'Opencode Zen Cloud';

    console.log(`    Provider  : ${chalk.cyan(providerLabel)}`);
    if (provider === 'lmx') {
      console.log(`    LMX host  : ${chalk.cyan(lmxHost + ':' + lmxPort)}`);
    } else {
      const suffix = cloudKey ? '••••' + cloudKey.slice(-4) : '(not set)';
      const storageLabel =
        cloudKeyStorage === 'keychain'
          ? 'stored in keychain'
          : cloudKeyStorage === 'config'
            ? 'saved in config'
            : 'not set';
      console.log(`    API key   : ${chalk.cyan(`${suffix} (${storageLabel})`)}`);
    }
    const autonomyLabels = ['Supervised', 'Balanced', 'Autonomous'];
    console.log(`    Autonomy  : ${chalk.cyan(autonomyLabels[autonomyLevel - 1])}`);
    console.log(`    TUI mode  : ${chalk.cyan(tuiDefault ? 'enabled by default' : 'disabled')}`);
    console.log('');

    const proceed = await confirm(rl, '  Save configuration?', true);

    if (!proceed) {
      console.log('');
      console.log(chalk.dim('  Setup cancelled. Run `opta onboard` again to reconfigure.'));
      rl.close();
      return;
    }

    // Persist config
    await applyOnboardingProfile({
      provider,
      lmxHost,
      lmxPort,
      lmxAdminKey: provider === 'lmx' ? lmxAdminKey : undefined,
      anthropicApiKey: provider === 'anthropic' ? cloudKeyForConfig : undefined,
      geminiApiKey: provider === 'gemini' ? cloudKeyForConfig : undefined,
      openaiApiKey: provider === 'openai' ? cloudKeyForConfig : undefined,
      opencodeZenApiKey: provider === 'opencode_zen' ? cloudKeyForConfig : undefined,
      providerKeyStorage: cloudKeyStorage,
      autonomyLevel,
      tuiDefault,
    });

    console.log('');
    console.log(chalk.green('  ✓ Configuration saved'));
    console.log('');
    console.log(chalk.bold("  You're ready to use Opta!"));
    console.log('');
    console.log(chalk.dim('  Quick start:'));
    console.log(chalk.cyan('    opta') + chalk.dim('          — Interactive session'));
    console.log(chalk.cyan('    opta do "..."') + chalk.dim(' — One-shot agent task'));
    console.log(chalk.cyan('    opta status') + chalk.dim('   — Check connection'));
    console.log('');
  } finally {
    rl.close();
  }
}

import chalk from 'chalk';
import { loadConfig } from '../core/config.js';
import { EXIT, ExitError } from '../core/errors.js';
import { LmxApiError, LmxClient } from '../lmx/client.js';
import type { LmxRerankDocumentResult } from '../lmx/client.js';
import { errorMessage } from '../utils/errors.js';

interface RerankOptions {
  documents?: string;
  model?: string;
  topK?: string;
  json?: boolean;
}

const RERANK_REQUEST_OPTS = { timeoutMs: 30_000, maxRetries: 0 } as const;

function usage(): void {
  console.log(
    chalk.dim(
      'Usage: opta rerank <query> --documents <doc1|doc2|...> [--model <id>] [--top-k <n>] [--json]'
    )
  );
}

function parseDocuments(raw: string | undefined): string[] {
  if (!raw) return [];
  return raw
    .split('|')
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function parseTopK(raw: string | undefined): number | undefined {
  if (!raw || !raw.trim()) return undefined;
  const parsed = Number.parseInt(raw.trim(), 10);
  if (!Number.isFinite(parsed) || parsed < 1) {
    throw new Error('--top-k must be a positive integer');
  }
  return parsed;
}

function formatDocumentPreview(
  result: LmxRerankDocumentResult,
  fallbackDocuments: string[]
): string {
  const text = result.document?.text ?? fallbackDocuments[result.index] ?? '';
  const normalized = text.replace(/\s+/g, ' ').trim();
  if (normalized.length <= 96) return normalized;
  return `${normalized.slice(0, 93)}...`;
}

export async function rerank(
  queryInput: string | string[],
  opts: RerankOptions = {}
): Promise<void> {
  const query = Array.isArray(queryInput) ? queryInput.join(' ').trim() : (queryInput ?? '').trim();
  if (!query) {
    console.error(chalk.red('✗') + ' Query is required.\n');
    usage();
    throw new ExitError(EXIT.MISUSE);
  }

  const documents = parseDocuments(opts.documents);
  if (documents.length === 0) {
    console.error(
      chalk.red('✗') + ' --documents is required and must include at least one document.\n'
    );
    usage();
    throw new ExitError(EXIT.MISUSE);
  }

  let topK: number | undefined;
  try {
    topK = parseTopK(opts.topK);
  } catch (err) {
    console.error(chalk.red('✗') + ` ${errorMessage(err)}\n`);
    usage();
    throw new ExitError(EXIT.MISUSE);
  }

  const config = await loadConfig();
  const resolvedModel = (opts.model?.trim() || config.model.default || 'rerank-v1').trim();
  const client = new LmxClient({
    host: config.connection.host,
    fallbackHosts: config.connection.fallbackHosts,
    port: config.connection.port,
    adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
  });

  try {
    const response = await client.rerankDocuments(
      {
        model: resolvedModel,
        query,
        documents,
        topN: topK,
      },
      RERANK_REQUEST_OPTS
    );

    if (opts.json) {
      console.log(JSON.stringify(response, null, 2));
      return;
    }

    const usageTokens = response.usage?.total_tokens;
    console.log(
      chalk.green('✓') +
        ` Reranked ${documents.length} document${documents.length === 1 ? '' : 's'} with ${response.model}`
    );
    console.log(chalk.dim(`  query: ${query}`));
    if (typeof usageTokens === 'number') {
      console.log(chalk.dim(`  tokens: ${usageTokens}`));
    }

    if (!Array.isArray(response.results) || response.results.length === 0) {
      console.log(chalk.dim('  No results returned.'));
      return;
    }

    for (const [rank, result] of response.results.entries()) {
      const score = Number.isFinite(result.relevance_score)
        ? result.relevance_score.toFixed(4)
        : 'n/a';
      const preview = formatDocumentPreview(result, documents);
      console.log(`  ${rank + 1}. [${score}] doc#${result.index + 1} ${preview}`);
    }
  } catch (err) {
    if (err instanceof LmxApiError && err.code === 'connection_error') {
      console.error(
        chalk.red('✗') +
          ` Unable to reach Opta LMX at ${config.connection.host}:${config.connection.port}`
      );
      console.error(chalk.dim(`  ${err.message}`));
      throw new ExitError(EXIT.NO_CONNECTION);
    }

    console.error(chalk.red('✗') + ` Failed to rerank documents: ${errorMessage(err)}`);
    throw new ExitError(EXIT.ERROR);
  }
}

import { execFileSync, spawn } from 'node:child_process';
import { lookup } from 'node:dns/promises';
import { isIP } from 'node:net';
import chalk from 'chalk';
import { loadConfig } from '../core/config.js';
import { OptaError, ExitError, EXIT } from '../core/errors.js';
import { createSpinner } from '../ui/spinner.js';
import { colorizeOptaWord } from '../ui/brand.js';
import { LmxApiError, LmxClient } from '../lmx/client.js';
import { errorMessage } from '../utils/errors.js';
import { sleep } from '../utils/common.js';
import { homedir, requiresPosixPlatform } from '../platform/index.js';

interface ServeOptions {
  json?: boolean;
}

const REMOTE_LAUNCHD_LABEL = 'com.opta.lmx';
const STARTUP_WAIT_MS = 90_000;
const DEFAULT_SSH_CONNECT_TIMEOUT_SECONDS = 25;
const FAST_HEALTH_REQUEST_OPTS = { timeoutMs: 2_000, maxRetries: 0 } as const;

function isAdminUnauthorized(err: unknown): boolean {
  return (
    err instanceof LmxApiError &&
    (err.code === 'unauthorized' || err.status === 401 || err.status === 403)
  );
}

export async function serve(action?: string, opts?: ServeOptions): Promise<void> {
  requiresPosixPlatform('opta serve');
  switch (action) {
    case 'start':
      await serveStart(opts);
      return;
    case 'stop':
      await serveStop(opts);
      return;
    case 'restart':
      await serveStop(opts);
      await serveStart(opts);
      return;
    case 'logs':
      await serveLogs();
      return;
    default:
      await serveStatus(opts);
  }
}

function isRemoteHost(host: string): boolean {
  return host !== '127.0.0.1' && host !== 'localhost';
}

function expandHome(path: string): string {
  if (!path.startsWith('~')) return path;
  return homedir() + path.slice(1);
}

function quoteSh(value: string): string {
  return `'${value.replace(/'/g, `'\"'\"'`)}'`;
}

function resolveHostCandidates(
  primaryHost: string,
  fallbackHosts: readonly string[] = []
): string[] {
  const seen = new Set<string>();
  const candidates: string[] = [];
  for (const host of [primaryHost, ...fallbackHosts]) {
    const value = host.trim();
    if (!value) continue;
    const key = value.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    candidates.push(value);
  }
  return candidates.length > 0 ? candidates : [primaryHost];
}

async function expandSshHostCandidates(
  primaryHost: string,
  fallbackHosts: readonly string[] = []
): Promise<string[]> {
  const base = resolveHostCandidates(primaryHost, fallbackHosts);
  const seen = new Set<string>();
  const candidates: string[] = [];

  const pushUnique = (value: string): void => {
    const normalized = value.trim();
    if (!normalized) return;
    const key = normalized.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    candidates.push(normalized);
  };

  const lookupResults = await Promise.allSettled(
    base.map(async (host) => {
      if (isIP(host) !== 0) return [] as string[];
      const addresses = await lookup(host, { all: true, verbatim: false });
      return addresses.map((entry) => entry.address);
    })
  );

  for (let i = 0; i < base.length; i++) {
    const host = base[i]!;
    pushUnique(host);
    const resolved = lookupResults[i];
    if (!resolved || resolved.status !== 'fulfilled') continue;
    for (const address of resolved.value) {
      pushUnique(address);
    }
  }

  return candidates.length > 0 ? candidates : base;
}

function resolveSshConnectTimeoutSeconds(configuredSeconds: number | undefined): number {
  return Math.max(3, Math.floor(configuredSeconds || DEFAULT_SSH_CONNECT_TIMEOUT_SECONDS));
}

function extractExecOutput(err: unknown): string | null {
  if (!err || typeof err !== 'object') return null;
  const stdout = (err as { stdout?: unknown }).stdout;
  const stderr = (err as { stderr?: unknown }).stderr;
  const outText =
    typeof stdout === 'string' ? stdout : Buffer.isBuffer(stdout) ? stdout.toString('utf8') : '';
  const errText =
    typeof stderr === 'string' ? stderr : Buffer.isBuffer(stderr) ? stderr.toString('utf8') : '';
  const merged = [errText.trim(), outText.trim()].filter(Boolean).join('\n');
  return merged || null;
}

function canImportModule(python: string, moduleName: string): boolean {
  try {
    execFileSync(python, ['-c', `import ${moduleName}`], { stdio: 'ignore', timeout: 4_000 });
    return true;
  } catch {
    return false;
  }
}

function canRunModule(python: string, moduleName: string): boolean {
  try {
    execFileSync(python, ['-m', moduleName, '--help'], { stdio: 'ignore', timeout: 6_000 });
    return true;
  } catch {
    return false;
  }
}

function resolveLocalInvocation(): { python: string; module: string } {
  const candidates = [
    process.env['OPTA_PYTHON'],
    '.venv/bin/python',
    `${homedir()}/opta-lmx/.venv/bin/python`,
    `${homedir()}/.opta-lmx/.venv/bin/python`,
    'python3',
    'python',
  ]
    .filter((value): value is string => typeof value === 'string' && value.trim().length > 0)
    .map((value) => value.trim());

  for (const python of candidates) {
    if (canImportModule(python, 'opta_lmx.main')) {
      return { python, module: 'opta_lmx.main' };
    }
  }
  for (const python of candidates) {
    if (canRunModule(python, 'opta_lmx')) {
      return { python, module: 'opta_lmx' };
    }
  }

  throw new Error(
    'No usable Python runtime found for Opta LMX. Tried .venv/bin/python, ~/opta-lmx/.venv/bin/python, python3, python'
  );
}

function buildRemoteStartScript(lmxPath: string, configuredPython: string, port: number): string {
  const repoPython = `${lmxPath}/.venv/bin/python`;
  // Resolve config file: try user-created config.yaml first, then ~/.opta-lmx, then default
  const configCandidates = [
    `${lmxPath}/config/config.yaml`,
    `$HOME/.opta-lmx/config.yaml`,
    `${lmxPath}/config/default-config.yaml`,
  ];

  return [
    'set -e',
    `if command -v launchctl >/dev/null 2>&1 && launchctl print gui/$(id -u)/${REMOTE_LAUNCHD_LABEL} >/dev/null 2>&1; then`,
    `  launchctl kickstart -k gui/$(id -u)/${REMOTE_LAUNCHD_LABEL}`,
    '  exit 0',
    'fi',
    `cd ${quoteSh(lmxPath)}`,
    'PY=""',
    'ENTRY=""',
    `if [ -x ${quoteSh(repoPython)} ] && ${quoteSh(repoPython)} -c "import opta_lmx.main" >/dev/null 2>&1; then`,
    `  PY=${quoteSh(repoPython)}`,
    '  ENTRY="opta_lmx.main"',
    `elif [ -x ${quoteSh(configuredPython)} ] && ${quoteSh(configuredPython)} -c "import opta_lmx.main" >/dev/null 2>&1; then`,
    `  PY=${quoteSh(configuredPython)}`,
    '  ENTRY="opta_lmx.main"',
    `elif [ -x ${quoteSh(configuredPython)} ] && ${quoteSh(configuredPython)} -m opta_lmx --help >/dev/null 2>&1; then`,
    `  PY=${quoteSh(configuredPython)}`,
    '  ENTRY="opta_lmx"',
    'elif command -v python3 >/dev/null 2>&1 && python3 -c "import opta_lmx.main" >/dev/null 2>&1; then',
    '  PY="python3"',
    '  ENTRY="opta_lmx.main"',
    'else',
    `  echo "No usable python runtime for Opta LMX. Tried ${repoPython}, ${configuredPython}, python3" >&2`,
    '  exit 42',
    'fi',
    `CFG=""`,
    `for _candidate in ${configCandidates.map((c) => quoteSh(c)).join(' ')}; do [ -f "$_candidate" ] && CFG="$_candidate" && break; done`,
    `if [ -n "$CFG" ] && [ "$ENTRY" = "opta_lmx.main" ]; then`,
    `  nohup env LMX_LOGGING__FILE=/tmp/opta-lmx.log "$PY" -m "$ENTRY" --config "$CFG" --host 0.0.0.0 --port ${port} >/tmp/opta-lmx.log 2>&1 &`,
    'else',
    `  nohup env LMX_LOGGING__FILE=/tmp/opta-lmx.log "$PY" -m "$ENTRY" --host 0.0.0.0 --port ${port} >/tmp/opta-lmx.log 2>&1 &`,
    'fi',
    'sleep 1',
  ].join('\n');
}

async function serveStatus(opts?: ServeOptions): Promise<void> {
  const config = await loadConfig();
  const { host, port } = config.connection;
  const client = new LmxClient({
    host,
    fallbackHosts: config.connection.fallbackHosts,
    port,
    adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
  });

  try {
    const health = await client.health(FAST_HEALTH_REQUEST_OPTS);
    const status = await client.status(FAST_HEALTH_REQUEST_OPTS);

    if (opts?.json) {
      console.log(JSON.stringify({ running: true, adminAuthorized: true, health, status }, null, 2));
      return;
    }

    console.log(chalk.green('●') + ` ${colorizeOptaWord(`Opta LMX running at ${host}:${port}`)}`);
    if (status.version) console.log(chalk.dim(`  Version: ${status.version}`));
    if (status.uptime_seconds != null)
      console.log(chalk.dim(`  Uptime:  ${formatDuration(status.uptime_seconds)}`));
    console.log(chalk.dim(`  Models:  ${status.models.length} loaded`));
  } catch (err) {
    if (isAdminUnauthorized(err)) {
      if (opts?.json) {
        console.log(
          JSON.stringify(
            {
              running: true,
              adminAuthorized: false,
              host,
              port,
              error: errorMessage(err),
            },
            null,
            2
          )
        );
        return;
      }
      console.log(
        chalk.yellow('●') +
          ` ${colorizeOptaWord(`Opta LMX is reachable at ${host}:${port}, but /admin access is unauthorized`)}`
      );
      console.log(chalk.dim(`  Check key: opta config get connection.adminKey`));
      console.log(chalk.dim(`  Check host-key map: opta config get connection.adminKeysByHost`));
      console.log(chalk.dim(`  Set key:   opta config set connection.adminKey <key>`));
      console.log(chalk.dim(`  Set map:   opta config set connection.adminKeysByHost '{"host":"key"}'`));
      console.log(chalk.dim(`  Clear key: opta config delete connection.adminKey`));
      return;
    }

    if (opts?.json) {
      console.log(JSON.stringify({ running: false, host, port }, null, 2));
      return;
    }
    console.log(
      chalk.red('●') + ` ${colorizeOptaWord(`Opta LMX is not reachable at ${host}:${port}`)}`
    );
    console.log(chalk.dim(`  Start it: opta serve start`));
  }
}

async function serveStart(opts?: ServeOptions): Promise<void> {
  const config = await loadConfig();
  const { host, port } = config.connection;
  const client = new LmxClient({
    host,
    fallbackHosts: config.connection.fallbackHosts,
    port,
    adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
  });
  const spinner = await createSpinner();

  // Check if already running
  try {
    await client.health(FAST_HEALTH_REQUEST_OPTS);
    const activeHost = client.getActiveHost();
    let adminAuthorized = true;
    try {
      await client.status(FAST_HEALTH_REQUEST_OPTS);
    } catch (err) {
      adminAuthorized = !isAdminUnauthorized(err);
    }
    console.log(
      chalk.yellow('!') +
        ` ${colorizeOptaWord(`Opta LMX is already running at ${activeHost}:${port}`)}`
    );
    if (!adminAuthorized) {
      console.log(
        chalk.yellow('!') + ' Admin endpoints are unauthorized for this CLI profile.'
      );
      console.log(chalk.dim('  Set key:   opta config set connection.adminKey <key>'));
      console.log(chalk.dim('  Set map:   opta config set connection.adminKeysByHost \'{"host":"key"}\''));
      console.log(chalk.dim('  Clear key: opta config delete connection.adminKey'));
    }
    return;
  } catch {
    // Not running — proceed with start
  }

  const isRemote = isRemoteHost(host);
  let remoteHostCandidates: string[] = [];

  spinner.start(`Starting Opta LMX on ${isRemote ? host : 'localhost'}...`);

  try {
    if (isRemote) {
      const { ssh } = config.connection;
      const identityFile = expandHome(ssh.identityFile);
      const remoteScript = buildRemoteStartScript(ssh.lmxPath, ssh.pythonPath, port);
      const hostCandidates = await expandSshHostCandidates(host, config.connection.fallbackHosts);
      remoteHostCandidates = hostCandidates;
      const sshConnectTimeoutSec = resolveSshConnectTimeoutSeconds(ssh.connectTimeoutSec);
      const failures: string[] = [];
      let startedHost: string | null = null;

      for (const candidate of hostCandidates) {
        const sshTarget = `${ssh.user}@${candidate}`;
        const args = [
          '-o',
          'BatchMode=yes',
          '-o',
          `ConnectTimeout=${sshConnectTimeoutSec}`,
          '-i',
          identityFile,
          sshTarget,
          `bash -lc ${quoteSh(remoteScript)}`,
        ];
        try {
          execFileSync('ssh', args, { timeout: 25_000, stdio: 'pipe' });
          startedHost = candidate;
          break;
        } catch (err) {
          const detail = extractExecOutput(err) ?? errorMessage(err);
          failures.push(`${candidate}: ${detail}`);
        }
      }

      if (!startedHost) {
        throw new OptaError(
          `Failed to start Opta LMX on ${host}`,
          EXIT.NO_CONNECTION,
          ['SSH launch failed on all configured hosts.', ...failures.slice(0, 4)],
          [
            `Check SSH access: ssh -i ${config.connection.ssh.identityFile} ${config.connection.ssh.user}@${host}`,
            config.connection.fallbackHosts.length > 0
              ? `Try fallback hosts: ${config.connection.fallbackHosts.join(', ')}`
              : 'Configure fallback hosts: opta config set connection.fallbackHosts hostA,hostB',
            'Check logs: opta serve logs',
          ]
        );
      }
    } else {
      const invocation = resolveLocalInvocation();
      const child = spawn(
        invocation.python,
        ['-m', invocation.module, '--host', '0.0.0.0', '--port', String(port)],
        { detached: true, stdio: 'ignore' }
      );
      child.unref();
    }

    // Poll for health (up to 90 seconds to allow remote cold starts).
    const maxWait = STARTUP_WAIT_MS;
    const interval = 1_000;
    const deadline = Date.now() + maxWait;

    while (Date.now() < deadline) {
      await sleep(interval);
      try {
        await client.health(FAST_HEALTH_REQUEST_OPTS);
        const activeHost = client.getActiveHost();
        spinner.succeed(`Opta LMX started at ${activeHost}:${port}`);

        if (opts?.json) {
          console.log(JSON.stringify({ started: true, host: activeHost, port }, null, 2));
        }
        return;
      } catch {
        // Not ready yet
      }
    }

    if (isRemote) {
      const { ssh } = config.connection;
      const identityFile = expandHome(ssh.identityFile);
      const sshConnectTimeoutSec = resolveSshConnectTimeoutSeconds(ssh.connectTimeoutSec);
      const verifyCandidates =
        remoteHostCandidates.length > 0
          ? remoteHostCandidates
          : await expandSshHostCandidates(host, config.connection.fallbackHosts);

      let remotelyHealthy = false;
      for (const candidate of verifyCandidates) {
        const sshTarget = `${ssh.user}@${candidate}`;
        const probe = `curl -fsS -m 4 http://127.0.0.1:${port}/healthz >/dev/null`;
        try {
          execFileSync(
            'ssh',
            ['-o', `ConnectTimeout=${sshConnectTimeoutSec}`, '-i', identityFile, sshTarget, probe],
            { timeout: 20_000, stdio: 'pipe' }
          );
          remotelyHealthy = true;
          break;
        } catch {
          // Try next candidate.
        }
      }

      if (remotelyHealthy) {
        spinner.fail(`Opta LMX started on ${host} but is not reachable from this machine`);
        throw new OptaError(
          `Opta LMX started remotely but LAN access failed at ${host}:${port}`,
          EXIT.NO_CONNECTION,
          [
            'Remote daemon health check succeeded via SSH localhost probe.',
            'Direct HTTP health checks from local machine timed out.',
          ],
          [
            `Check remote firewall rules for TCP ${port}`,
            `Confirm bind host in remote config includes 0.0.0.0`,
            `Temporary workaround: ssh -N -L ${port}:127.0.0.1:${port} ${ssh.user}@${host}`,
            'Then retry: opta status',
          ]
        );
      }
    }

    spinner.fail(`Opta LMX did not start within ${Math.round(maxWait / 1000)} seconds`);
    console.log(chalk.dim(`  Check logs: opta serve logs`));
    throw new ExitError(EXIT.ERROR);
  } catch (err) {
    spinner.fail('Failed to start Opta LMX');
    if (err instanceof OptaError) {
      throw err;
    }
    const detail = extractExecOutput(err);
    throw new OptaError(
      `Failed to start Opta LMX on ${host}`,
      EXIT.ERROR,
      [detail ?? errorMessage(err)],
      [
        isRemote
          ? `Check SSH access: ssh -i ${config.connection.ssh.identityFile} ${config.connection.ssh.user}@${host}`
          : 'Check Python environment',
        isRemote ? `SSH config: opta config set connection.ssh.user <user>` : '',
        isRemote ? `Verify remote runtime: opta config get connection.ssh.pythonPath` : '',
        `Verify install: pip show opta-lmx`,
        `Check logs: opta serve logs`,
      ].filter(Boolean)
    );
  }
}

async function serveStop(_opts?: ServeOptions): Promise<void> {
  const config = await loadConfig();
  const { host } = config.connection;
  const isRemote = isRemoteHost(host);
  const spinner = await createSpinner();

  spinner.start(`Stopping Opta LMX on ${isRemote ? host : 'localhost'}...`);

  try {
    if (isRemote) {
      try {
        const { ssh } = config.connection;
        const identityFile = expandHome(ssh.identityFile);
        const sshConnectTimeoutSec = resolveSshConnectTimeoutSeconds(ssh.connectTimeoutSec);
        const hostCandidates = await expandSshHostCandidates(host, config.connection.fallbackHosts);
        const stopScript = [
          `if command -v launchctl >/dev/null 2>&1; then launchctl kill SIGTERM gui/$(id -u)/${REMOTE_LAUNCHD_LABEL} >/dev/null 2>&1 || true; fi`,
          'pkill -f "python -m opta_lmx.main" >/dev/null 2>&1 || true',
          'pkill -f "python -m opta_lmx" >/dev/null 2>&1 || true',
        ].join('; ');
        for (const candidate of hostCandidates) {
          const sshTarget = `${ssh.user}@${candidate}`;
          try {
            execFileSync(
              'ssh',
              [
                '-o',
                `ConnectTimeout=${sshConnectTimeoutSec}`,
                '-i',
                identityFile,
                sshTarget,
                stopScript,
              ],
              { timeout: 20_000 }
            );
            break;
          } catch {
            // Try next host candidate.
          }
        }
      } catch {
        // pkill returns non-zero when no process found — that's fine
      }
    } else {
      try {
        execFileSync('pkill', ['-f', 'python -m opta_lmx.main'], { timeout: 5_000 });
      } catch {
        // No process to kill
      }
      try {
        execFileSync('pkill', ['-f', 'python -m opta_lmx'], { timeout: 5_000 });
      } catch {
        // No process to kill
      }
    }

    spinner.succeed('Opta LMX stopped');

    if (_opts?.json) {
      console.log(JSON.stringify({ stopped: true, host }, null, 2));
    }
  } catch (err) {
    spinner.fail('Failed to stop Opta LMX');
    throw new OptaError(
      `Failed to stop Opta LMX on ${host}`,
      EXIT.ERROR,
      [errorMessage(err)],
      [isRemote ? `SSH manually: ssh ${host}` : 'Check running processes']
    );
  }
}

async function serveLogs(): Promise<void> {
  const config = await loadConfig();
  const { host } = config.connection;
  const isRemote = isRemoteHost(host);

  try {
    let output: string;
    if (isRemote) {
      const { ssh } = config.connection;
      const identityFile = expandHome(ssh.identityFile);
      const sshConnectTimeoutSec = resolveSshConnectTimeoutSeconds(ssh.connectTimeoutSec);
      const hostCandidates = await expandSshHostCandidates(host, config.connection.fallbackHosts);
      const logsScript = [
        'set -e',
        'printed=0',
        'for f in /tmp/opta-lmx.log /tmp/opta-lmx-service.log; do',
        '  if [ -f "$f" ]; then',
        '    if [ "$printed" = "1" ]; then printf "\\n"; fi',
        '    echo "=== $f ==="',
        '    tail -50 "$f"',
        '    printed=1',
        '  fi',
        'done',
        'if [ "$printed" = "0" ]; then echo "No Opta LMX logs found under /tmp."; fi',
      ].join('\n');
      const failures: string[] = [];
      let logsOutput: string | null = null;
      for (const candidate of hostCandidates) {
        const sshTarget = `${ssh.user}@${candidate}`;
        try {
          logsOutput = execFileSync(
            'ssh',
            [
              '-o',
              `ConnectTimeout=${sshConnectTimeoutSec}`,
              '-i',
              identityFile,
              sshTarget,
              `bash -lc ${quoteSh(logsScript)}`,
            ],
            {
              timeout: 30_000,
              encoding: 'utf8',
            }
          );
          break;
        } catch (err) {
          failures.push(`${candidate}: ${extractExecOutput(err) ?? errorMessage(err)}`);
        }
      }
      if (logsOutput === null) {
        throw new OptaError('Failed to read Opta LMX logs', EXIT.ERROR, failures.slice(0, 4), [
          `SSH manually: ssh ${host}`,
        ]);
      }
      output = logsOutput;
    } else {
      const localScript = [
        'set -e',
        'printed=0',
        'for f in /tmp/opta-lmx.log /tmp/opta-lmx-service.log; do',
        '  if [ -f "$f" ]; then',
        '    if [ "$printed" = "1" ]; then printf "\\n"; fi',
        '    echo "=== $f ==="',
        '    tail -50 "$f"',
        '    printed=1',
        '  fi',
        'done',
        'if [ "$printed" = "0" ]; then echo "No Opta LMX logs found under /tmp."; fi',
      ].join('\n');
      output = execFileSync('bash', ['-lc', localScript], {
        timeout: 8_000,
        encoding: 'utf8',
      });
    }
    console.log(output);
  } catch (err) {
    if (err instanceof OptaError) {
      throw err;
    }
    throw new OptaError(
      'Failed to read Opta LMX logs',
      EXIT.ERROR,
      [errorMessage(err)],
      [isRemote ? `SSH manually: ssh ${host}` : 'Check /tmp/opta-lmx.log']
    );
  }
}

function formatDuration(seconds: number): string {
  if (seconds < 60) return `${seconds}s`;
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m`;
  const hours = Math.floor(seconds / 3600);
  const mins = Math.floor((seconds % 3600) / 60);
  return `${hours}h ${mins}m`;
}

import chalk from 'chalk';
import {
  listSessions,
  deleteSession,
  exportSession,
  searchSessions,
} from '../memory/store.js';
import { EXIT, ExitError } from '../core/errors.js';

interface SessionsOptions {
  json?: boolean;
  model?: string;
  since?: string;
  tag?: string;
  limit?: string;
}

export async function sessions(
  action?: string,
  id?: string,
  opts?: SessionsOptions
): Promise<void> {
  // Default: list sessions
  if (!action || action === 'list') {
    await listSessionsFormatted(opts);
    return;
  }

  switch (action) {
    case 'resume':
      if (!id) {
        console.error(chalk.red('✗') + ' Session ID required\n');
        console.log(chalk.dim('Usage: opta sessions resume <id>'));
        throw new ExitError(EXIT.MISUSE);
      }
      // Delegate to chat --resume
      const { startChat } = await import('./chat.js');
      await startChat({ resume: id });
      break;

    case 'delete':
    case 'rm':
      if (!id) {
        console.error(chalk.red('✗') + ' Session ID required\n');
        console.log(chalk.dim('Usage: opta sessions delete <id>'));
        throw new ExitError(EXIT.MISUSE);
      }
      await deleteSession(id);
      console.log(chalk.green('✓') + ` Deleted session ${id}`);
      break;

    case 'search':
    case 'find':
      if (!id) {
        console.error(chalk.red('✗') + ' Search query required\n');
        console.log(chalk.dim('Usage: opta sessions search <query>'));
        throw new ExitError(EXIT.MISUSE);
      }
      await searchSessionsFormatted(id, opts?.json);
      break;

    case 'export':
      if (!id) {
        console.error(chalk.red('✗') + ' Session ID required\n');
        console.log(chalk.dim('Usage: opta sessions export <id>'));
        throw new ExitError(EXIT.MISUSE);
      }
      try {
        const json = await exportSession(id);
        console.log(json);
      } catch {
        console.error(chalk.red('✗') + ` Session not found: ${id}`);
        throw new ExitError(EXIT.NOT_FOUND);
      }
      break;

    default:
      console.error(chalk.red('✗') + ` Unknown action: ${action}\n`);
      console.log(chalk.dim('Available actions: list, resume, delete, export, search'));
      throw new ExitError(EXIT.MISUSE);
  }
}

async function listSessionsFormatted(opts?: SessionsOptions): Promise<void> {
  let items = await listSessions();

  // Apply filters
  if (opts?.model) {
    const modelFilter = opts.model.toLowerCase();
    items = items.filter(s => s.model.toLowerCase().includes(modelFilter));
  }
  if (opts?.tag) {
    items = items.filter(s => s.tags?.includes(opts.tag!));
  }
  if (opts?.since) {
    const sinceDate = parseSinceDate(opts.since);
    items = items.filter(s => new Date(s.created) >= sinceDate);
  }

  const limit = opts?.limit ? parseInt(opts.limit, 10) : 20;
  items = items.slice(0, limit);

  if (items.length === 0) {
    if (opts?.json) {
      console.log(JSON.stringify([], null, 2));
      return;
    }
    console.log(chalk.dim('No sessions found. Start one with ') + chalk.cyan('opta'));
    return;
  }

  if (opts?.json) {
    console.log(JSON.stringify(items, null, 2));
    return;
  }

  // Table header
  console.log(
    chalk.bold('  ID        Title                          Model           Date         Messages')
  );

  for (const s of items) {
    const shortId = s.id.slice(0, 8).padEnd(8);
    const titleStr = s.title.slice(0, 30).padEnd(30);
    const model = s.model.slice(0, 15).padEnd(15);
    const date = formatRelativeDate(s.created).padEnd(12);
    const count = String(s.messageCount).padStart(4);
    const tags = s.tags?.length ? chalk.dim(` [${s.tags.join(', ')}]`) : '';

    console.log(`  ${shortId}  ${titleStr} ${model} ${date} ${count}${tags}`);
  }
}

async function searchSessionsFormatted(query: string, json?: boolean): Promise<void> {
  const matches = await searchSessions(query);

  if (matches.length === 0) {
    if (json) {
      console.log(JSON.stringify([], null, 2));
      return;
    }
    console.log(chalk.dim(`No sessions matching "${query}"`));
    return;
  }

  if (json) {
    console.log(JSON.stringify(matches, null, 2));
    return;
  }

  console.log(chalk.dim(`  Found ${matches.length} session${matches.length === 1 ? '' : 's'} matching "${query}":\n`));

  console.log(
    chalk.bold('  ID        Title                          Model           Date         Messages')
  );

  for (const s of matches) {
    const shortId = s.id.slice(0, 8).padEnd(8);
    const title = s.title.slice(0, 30).padEnd(30);
    const model = s.model.slice(0, 15).padEnd(15);
    const date = formatRelativeDate(s.created).padEnd(12);
    const count = String(s.messageCount).padStart(4);

    console.log(`  ${shortId}  ${title} ${model} ${date} ${count}`);
  }

  if (matches.length === 1) {
    console.log(chalk.dim(`\n  Resume with: opta sessions resume ${matches[0]!.id}`));
  }
}

/**
 * Parse a date filter string. Supports:
 * - ISO dates: "2025-01-15"
 * - Relative: "7d" (7 days ago), "2w" (2 weeks ago), "1m" (1 month ago)
 */
function parseSinceDate(input: string): Date {
  const relativeMatch = input.match(/^(\d+)([dwm])$/);
  if (relativeMatch) {
    const amount = parseInt(relativeMatch[1]!, 10);
    const unit = relativeMatch[2]!;
    const now = new Date();
    switch (unit) {
      case 'd':
        now.setDate(now.getDate() - amount);
        break;
      case 'w':
        now.setDate(now.getDate() - amount * 7);
        break;
      case 'm':
        now.setMonth(now.getMonth() - amount);
        break;
    }
    return now;
  }
  // Assume ISO date string
  const parsed = new Date(input);
  if (isNaN(parsed.getTime())) {
    throw new Error(`Invalid date format: "${input}". Use ISO (2025-01-15) or relative (7d, 2w, 1m).`);
  }
  return parsed;
}

function formatRelativeDate(iso: string): string {
  const now = Date.now();
  const then = new Date(iso).getTime();
  const diffMs = now - then;

  const minutes = Math.floor(diffMs / 60000);
  if (minutes < 1) return 'just now';
  if (minutes < 60) return `${minutes}m ago`;

  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ago`;

  const days = Math.floor(hours / 24);
  if (days === 1) return 'yesterday';
  if (days < 7) return `${days}d ago`;

  return new Date(iso).toLocaleDateString();
}

import chalk from 'chalk';
import type { SlashCommandDef, SlashContext, SlashResult } from './types.js';
import { estimateMessageTokens, estimateTokens, formatTokens } from '../../utils/tokens.js';
import { box, kv, progressBar } from '../../ui/box.js';
import { relative } from 'node:path';

const contextHandler = async (args: string, ctx: SlashContext): Promise<SlashResult> => {
  const action = args.trim().toLowerCase();

  if (action === 'map' || action === '') {
    const totalTokens = estimateMessageTokens(ctx.session.messages);
    const limit = ctx.config.model.contextLimit ?? 32768;
    const ratio = totalTokens / limit;

    const fileMap = new Map<string, number>();

    // Extract file contents from context to show weight
    // We look for <file path="...">...</file> blocks which are injected by @file
    // And also potentially tool_calls that read files
    const fileRegex = /<file path="([^"]+)">([\s\S]*?)<\/file>/g;

    for (const msg of ctx.session.messages) {
      if (typeof msg.content === 'string') {
        let match;
        while ((match = fileRegex.exec(msg.content)) !== null) {
          const path = match[1]!;
          const content = match[2]!;
          const tokens = estimateTokens(content);
          fileMap.set(path, (fileMap.get(path) ?? 0) + tokens);
        }
      } else if (Array.isArray(msg.content)) {
        for (const part of msg.content) {
          if (part.type === 'text' && part.text) {
            let match;
            while ((match = fileRegex.exec(part.text)) !== null) {
              const path = match[1]!;
              const content = match[2]!;
              const tokens = estimateTokens(content);
              fileMap.set(path, (fileMap.get(path) ?? 0) + tokens);
            }
          }
        }
      }
    }

    const lines: string[] = [];

    lines.push(chalk.bold('Context Constellation'));
    lines.push(chalk.dim('─'.repeat(40)));
    lines.push(kv('Total', `${formatTokens(totalTokens)} / ${formatTokens(limit)} tokens`));
    lines.push(`Pressure:  ${progressBar(ratio, 25)}`);
    lines.push('');

    if (fileMap.size === 0) {
      lines.push(chalk.dim('  (No explicit file blocks in memory)'));
    } else {
      lines.push(chalk.bold('Loaded Files:'));
      const sortedFiles = Array.from(fileMap.entries())
        .map(([path, tokens]) => ({ path, tokens }))
        .sort((a, b) => b.tokens - a.tokens);

      for (const f of sortedFiles) {
        const relPath = relative(process.cwd(), f.path);
        const tokenStr = formatTokens(f.tokens).padStart(5);
        const pctStr = ((f.tokens / Math.max(1, totalTokens)) * 100).toFixed(1).padStart(4) + '%';

        // Color code based on relative size
        const fRatio = f.tokens / limit;
        let color = chalk.cyan;
        if (fRatio > 0.25) color = chalk.red;
        else if (fRatio > 0.1) color = chalk.yellow;
        else if (fRatio > 0.05) color = chalk.magenta;

        lines.push(`  ${color(tokenStr)} ${chalk.dim(`[${pctStr}]`)}  ${relPath}`);
      }
    }

    console.log('\\n' + box('Context Map', lines, { width: 55 }));
    if (ratio > 0.8) {
      console.log(chalk.yellow('  \u26a0 Context pressure is high. Consider using /compact to prune memory.'));
    }

    return 'handled';
  }

  console.log(chalk.dim('  Usage: /context map'));
  return 'handled';
};

export const contextCommands: SlashCommandDef[] = [
  {
    command: 'context',
    description: 'View context token mapping and memory pressure',
    handler: contextHandler,
    category: 'session',
    usage: '/context map',
    examples: ['/context map'],
  },
];

