  try {
    const stack = await lmx.stack(FAST_SLASH_REQUEST_OPTS);

    if (json) {
      console.log(renderJson(stack));
      return 'handled';
    }

    const lines: string[] = [];

    if (stack.default_model) {
      lines.push(kv('Default', stack.default_model));
    }

    if (stack.loaded_models.length > 0) {
      lines.push(kv('Loaded', String(stack.loaded_models.length)));
      for (const id of stack.loaded_models) {
        lines.push(`  ${chalk.green('\u25cf')} ${id}`);
      }
    } else {
      lines.push(kv('Loaded', chalk.dim('(none)')));
    }

    const roleEntries = Object.entries(stack.roles);
    if (roleEntries.length > 0) {
      lines.push('');
      lines.push(chalk.dim('Role Routing:'));
      const nameW = Math.max(8, ...roleEntries.map(([n]) => n.length));
      const modelW = Math.max(14, ...roleEntries.map(([, r]) => r.resolved_model?.length ?? 0));
      lines.push(chalk.dim(`  ${'NAME'.padEnd(nameW)}  ${'RESOLVED MODEL'.padEnd(modelW)}  STATUS`));
      for (const [roleName, role] of roleEntries) {
        const modelText = role.resolved_model ?? '';
        const modelColored = role.resolved_model
          ? modelText.padEnd(modelW)
          : chalk.dim('(none)'.padEnd(modelW));
        const statusBadge = role.loaded ? chalk.green('loaded') : chalk.yellow('not loaded');
        lines.push(`  ${roleName.padEnd(nameW)}  ${modelColored}  ${statusBadge}`);
      }
    }

    const helperEntries = Object.entries(stack.helper_nodes);
    if (helperEntries.length > 0) {
      lines.push('');
      lines.push(chalk.dim('Helper Nodes:'));
      for (const [name, info] of helperEntries) {
        const rec = asObject(info);
        const status = readString(rec, 'status', 'health') ?? chalk.dim('(unknown)');
        lines.push(`  ${name.padEnd(16)}  ${status}`);
      }
    }

    console.log('\n' + box('LMX Stack', lines));
  } catch (err) {
    console.error(chalk.red('\u2717') + ` Stack query failed: ${errorMessage(err)}`);
  }
  return 'handled';
};

/**
 * Management slash commands: /config, /doctor, /mcp, /quickfix
 */

import chalk from 'chalk';
import { box, kv } from '../../ui/box.js';
import { runMenuPrompt } from '../../ui/prompt-nav.js';
import { errorMessage } from '../../utils/errors.js';
import { formatAutonomySlider } from '../../core/autonomy.js';
import type { SlashCommandDef, SlashContext, SlashResult } from './types.js';
import type { PaneMenuSection } from '../../ui/pane-menu.js';
import type { UpdateOptions } from '../update.js';

const CONFIG_SECTION_COLORS: Record<string, string> = {
  connection: '#a855f7',
  model: '#22d3ee',
  autonomy: '#0ea5e9',
  provider: '#3b82f6',
  research: '#0ea5e9',
  browser: '#14b8a6',
  learning: '#f97316',
  policy: '#ef4444',
  permissions: '#f59e0b',
  git: '#10b981',
  tui: '#8b5cf6',
  mcp: '#06b6d4',
  default: '#64748b',
};

function isSensitiveConfigKey(key: string): boolean {
  const k = key.toLowerCase();
  return (
    k.includes('apikey') ||
    k.includes('api_key') ||
    k.includes('token') ||
    k.includes('secret') ||
    k.includes('password') ||
    k.endsWith('.key') ||
    k.includes('adminkey')
  );
}

function formatConfigValueForDisplay(value: unknown, key = ''): string {
  if (value === undefined || value === null) return chalk.dim('(unset)');
  if (key && isSensitiveConfigKey(key)) {
    const raw = typeof value === 'string' ? value : JSON.stringify(value);
    if (!raw) return chalk.dim('(none)');
    return '(set)';
  }
  if (typeof value === 'string') return value.length === 0 ? chalk.dim('(empty)') : value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (Array.isArray(value)) return JSON.stringify(value);
  if (typeof value === 'object') return chalk.dim('{...}');
  // At this point value is number | boolean | bigint | symbol | undefined (non-object, non-string, non-null handled above)
  return String(value as number | boolean | bigint | symbol | undefined);
}

function summarizeConfigValue(value: unknown, maxWidth = 40, key = ''): string {
  const rendered = formatConfigValueForDisplay(value, key);
  const plain = rendered.replace(/\x1B\[[0-9;]*m/g, '');
  if (plain.length <= maxWidth) return rendered;
  return `${plain.slice(0, maxWidth - 1)}…`;
}

function parseSlashArgs(raw: string): string[] {
  const tokens: string[] = [];
  const pattern =
    /"([^"\\]*(?:\\.[^"\\]*)*)"|'([^'\\]*(?:\\.[^'\\]*)*)'|`([^`\\]*(?:\\.[^`\\]*)*)`|([^\s]+)/g;
  let match: RegExpExecArray | null;

  while ((match = pattern.exec(raw)) !== null) {
    const captured = match[1] ?? match[2] ?? match[3] ?? match[4] ?? '';
    tokens.push(captured.replace(/\\(["'`\\])/g, '$1'));
  }

  return tokens;
}

