  return homedir() + input.slice(1);
}

function isLocalHost(host: string): boolean {
  const lower = host.trim().toLowerCase();
  return lower === 'localhost' || lower === '127.0.0.1';
}

export function parseComponentList(raw?: string): UpdateComponent[] {
  // Default update scope intentionally excludes web to keep the primary
  // desktop/local runtime path fast (CLI + LMX + Plus).
  if (!raw || raw.trim() === '') return ['cli', 'lmx', 'plus'];
  const parts = raw
    .split(',')
    .map((p) => p.trim().toLowerCase())
    .filter(Boolean);

  const allowed: UpdateComponent[] = ['cli', 'lmx', 'plus', 'web'];
  const invalid = parts.filter((p) => !allowed.includes(p as UpdateComponent));
  if (invalid.length > 0) {
    throw new Error(`Invalid components: ${invalid.join(', ')}. Use: cli,lmx,plus,web`);
  }

  return [...new Set(parts as UpdateComponent[])];
}

export function resolveTargets(mode: UpdateTargetMode, remoteHost: string): UpdateTarget[] {
  switch (mode) {
    case 'local':
      return ['local'];
    case 'remote':
      return ['remote'];
    case 'both':
      return ['local', 'remote'];
    case 'auto':
    default:
      return isLocalHost(remoteHost) ? ['local'] : ['local', 'remote'];
  }
}

export function remoteConnectFailureStatus(mode: UpdateTargetMode): StepStatus {
  return mode === 'auto' ? 'skip' : 'fail';
}

export function resolveRemoteHostCandidates(
  primaryHost: string,
  fallbackHosts: readonly string[] = []
): string[] {
  const hosts = [primaryHost, ...fallbackHosts]
    .map((host) => host.trim())
    .filter((host) => host.length > 0);

  const deduped: string[] = [];
  const seen = new Set<string>();
  for (const host of hosts) {
    const key = host.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    deduped.push(host);
  }

  return deduped;
}

export async function selectReachableRemoteHost(
  hosts: readonly string[],
  probeHost: (host: string) => Promise<CommandResult>,
  options: SelectReachableRemoteHostOptions = {}
): Promise<RemoteHostSelection> {
  if (options.parallel) {
    const settled = await Promise.all(
      hosts.map(async (host) => {
        const result = await probeHost(host);
        const detail = result.stderr || result.stdout || 'ssh failed';
        return {
          host,
          exitCode: result.exitCode,
          detail,
        } satisfies RemoteHostProbe;
      })
    );

    const selected = settled.find((entry) => entry.exitCode === 0);
    return {
      selectedHost: selected?.host ?? null,
      probes: settled,
    };
  }

  const probes: RemoteHostProbe[] = [];

  for (const host of hosts) {
    const result = await probeHost(host);
    const detail = result.stderr || result.stdout || 'ssh failed';
    probes.push({
      host,
      exitCode: result.exitCode,
      detail,
    });

    if (result.exitCode === 0) {
      return {
        selectedHost: host,
        probes,
      };
    }
  }

  return {
    selectedHost: null,
    probes,
  };
}

function detectAppsRoot(startCwd: string): string | null {
  const moduleProjectRoot = resolve(fileURLToPath(new URL('../..', import.meta.url)));
  const candidates = new Set<string>([
    startCwd,
    dirname(startCwd),
    resolve(startCwd, '..', '..'),
    moduleProjectRoot,
    dirname(moduleProjectRoot),
    resolve(moduleProjectRoot, '..', '..'),
  ]);

  for (const candidate of candidates) {
    const resolved = resolve(candidate);

    if (basename(resolved) === '1-Apps') {
      return resolved;
    }

    if (basename(resolved) === '1D-Opta-CLI-TS' && basename(dirname(resolved)) === '1-Apps') {
      return dirname(resolved);
    }

    const asApps = join(resolved, '1-Apps');
    if (existsSync(asApps) && existsSync(join(asApps, '1D-Opta-CLI-TS'))) {
      return asApps;
    }

    if (existsSync(join(resolved, '1D-Opta-CLI-TS')) && existsSync(join(resolved, '1M-Opta-LMX'))) {
      return resolved;
    }
  }

  return null;
}

function deriveRemoteAppsRootFromLmxPath(lmxPath: string): string | null {
  const resolved = resolve(lmxPath);
  if (basename(resolved) === '1M-Opta-LMX') return dirname(resolved);
  const marker = '/1M-Opta-LMX';
  const idx = resolved.indexOf(marker);
  if (idx > 0) return resolved.slice(0, idx);
  return null;
}

function componentRepoPath(component: UpdateComponent, appsRoot: string): string {
  switch (component) {
    case 'cli':
      return join(appsRoot, '1D-Opta-CLI-TS');
    case 'lmx':
      return join(appsRoot, '1M-Opta-LMX');
    case 'plus':
      return join(appsRoot, '1I-OptaPlus');
    case 'web':
      return join(appsRoot, '1L-Opta-Local');
  }
}

async function runLocalCommand(
  command: string,
  cwd?: string,
  dryRun = false
): Promise<CommandResult> {
  if (dryRun) {
    return { exitCode: 0, stdout: `[dry-run] ${command}`, stderr: '' };
  }

  const result = await execa('bash', ['-lc', command], {
    cwd,
    reject: false,
  });

  return {
    exitCode: result.exitCode ?? 1,
    stdout: result.stdout,
    stderr: result.stderr,
  };
}

async function runRemoteCommand(
  ssh: SshConfig,
  command: string,
  dryRun = false
): Promise<CommandResult> {
  if (dryRun) {
    return { exitCode: 0, stdout: `[dry-run][${ssh.host}] ${command}`, stderr: '' };
  }

  const commandWithPath = `export PATH=/opt/homebrew/bin:/usr/local/bin:$PATH; ${command}`;
  const args: string[] = [
    '-o',
    'BatchMode=yes',
    '-o',
    `ConnectTimeout=${SSH_CONNECT_TIMEOUT_SECONDS}`,
    '-o',
    'ServerAliveInterval=5',
    '-o',
    'ServerAliveCountMax=2',
  ];
  if (ssh.identityFile) {
    args.push('-i', ssh.identityFile);
  }
  args.push(`${ssh.user}@${ssh.host}`, `bash -lc ${quoteSh(commandWithPath)}`);

  const result = await execa('ssh', args, { reject: false });
  return {
    exitCode: result.exitCode ?? 1,
    stdout: result.stdout,
    stderr: result.stderr,
  };
}

async function verifyRemoteCliCommands(
  ssh: SshConfig,
  dryRun: boolean
): Promise<{ status: StepStatus; message: string }> {
  if (dryRun) {
    return { status: 'ok', message: 'dry-run remote command verification' };
  }

  const commandList = REQUIRED_OPTA_COMMANDS.join(' ');
  const script = [
    'if ! command -v node >/dev/null 2>&1; then echo "__ERR__:missing-node"; exit 40; fi',
    'if ! command -v opta >/dev/null 2>&1; then echo "__ERR__:missing-opta"; exit 41; fi',
    'help="$(opta --help 2>/dev/null)" || { echo "__ERR__:help-failed"; exit 42; }',
    `missing=""; for c in ${commandList}; do echo "$help" | grep -Eq "(^|[[:space:]])$c([[:space:]]|$)" || missing="$missing $c"; done`,
    'if [ -n "$missing" ]; then echo "__MISSING__:$missing"; exit 43; fi',
    'version="$(opta --version 2>/dev/null || true)"',
    'echo "__VERSION__:$version"',
  ].join('; ');

  const result = await runRemoteCommand(ssh, script, false);
  if (result.exitCode === 40) {
    return {
      status: 'fail',
      message:
        'node runtime missing on remote host (install Node.js so /opt/homebrew/bin/opta can run)',
    };
  }
  if (result.exitCode === 41) {
    return { status: 'fail', message: 'opta command not found in PATH on remote host' };
  }
  if (result.exitCode === 42) {
    return { status: 'fail', message: 'opta --help failed on remote host' };
  }
  if (result.exitCode === 43) {
    const marker = result.stdout.split('\n').find((line) => line.startsWith('__MISSING__:'));
    const missing = marker?.replace('__MISSING__:', '').trim() ?? 'unknown';
    return { status: 'fail', message: `missing command entries in remote opta --help: ${missing}` };
  }
  if (result.exitCode !== 0) {
    return {
      status: 'fail',
      message: result.stderr || result.stdout || 'remote command verification failed',
    };
  }

  const versionMarker = result.stdout.split('\n').find((line) => line.startsWith('__VERSION__:'));
  const version = versionMarker?.replace('__VERSION__:', '').trim() || 'unknown';
  return { status: 'ok', message: `opta command available (${version})` };
}

function summarizeOutput(raw: string): string {
  const firstLine = raw
    .split('\n')
    .map((line) => line.trim())
    .find((line) => line.length > 0);
  return firstLine ?? 'unknown error';
}

export function parseRemoteLanGuardMarker(output: string): RemoteLanGuardProbe | null {
  for (const rawLine of output.split('\n')) {
    const line = rawLine.trim();
    const match = /^__LAN_GUARD__:(ok|dual_ip|unsupported):([^:]*):([^:]*):([^:]*)$/.exec(line);
    if (!match) continue;

    return {
      state: match[1] as RemoteLanGuardProbe['state'],
      ethernetIp: match[2] ?? '',
      wifiIp: match[3] ?? '',
      wifiPower: match[4] ?? '',
    };
  }

  return null;
}

function formatRemoteLanGuardContext(probe: RemoteLanGuardProbe): string {
  const ethernetIp = probe.ethernetIp || 'none';
  const wifiIp = probe.wifiIp || 'none';
  const wifiPower = probe.wifiPower || 'unknown';
  return `en0=${ethernetIp}, en1=${wifiIp}, wifi=${wifiPower}`;
}

function delayMs(ms: number): Promise<void> {
  return new Promise((resolve) => {
    setTimeout(resolve, ms);
  });
}

async function runRemoteLanStabilityGuard(
  ssh: SshConfig,
  dryRun: boolean,
  mode: UpdateTargetMode
): Promise<RemoteLanGuardResult> {
  if (dryRun) {
    return {
      status: 'ok',
      message: 'dry-run LAN guard skipped',
      canProceed: true,
    };
  }

  const probeScript = [
    'if ! command -v ipconfig >/dev/null 2>&1 || ! command -v networksetup >/dev/null 2>&1; then',
    'echo "__LAN_GUARD__:unsupported:::"; exit 0;',
    'fi;',
    'eth_ip="$(ipconfig getifaddr en0 2>/dev/null || true)";',
    'wifi_ip="$(ipconfig getifaddr en1 2>/dev/null || true)";',
    'wifi_power="$(networksetup -getairportpower en1 2>/dev/null | sed -E "s/^.*: //")";',
    'if [ -n "$eth_ip" ] && [ -n "$wifi_ip" ] && [ "$eth_ip" = "$wifi_ip" ] && [ "$wifi_power" = "On" ]; then',
    'echo "__LAN_GUARD__:dual_ip:$eth_ip:$wifi_ip:$wifi_power";',
    'else',
    'echo "__LAN_GUARD__:ok:$eth_ip:$wifi_ip:$wifi_power";',
    'fi',
  ].join(' ');

  const probe = await runRemoteCommand(ssh, probeScript, false);
  const probePayload = `${probe.stdout}\n${probe.stderr}`;
  const parsed = parseRemoteLanGuardMarker(probePayload);

  if (probe.exitCode !== 0 && !parsed) {
    return {
      status: 'skip',
      message: `LAN guard probe unavailable: ${summarizeOutput(probe.stderr || probe.stdout)}`,
      canProceed: true,
    };
  }

  if (!parsed) {
    return {
      status: 'skip',
      message: 'LAN guard marker missing; continuing without network remediation',
      canProceed: true,
    };
  }

  if (parsed.state === 'unsupported') {
    return {
      status: 'skip',
      message: 'LAN guard unsupported on remote host (missing macOS network tools)',
      canProceed: true,
    };
  }

  const context = formatRemoteLanGuardContext(parsed);
  if (parsed.state === 'ok') {
    return {
      status: 'ok',
      message: `LAN guard ok (${context})`,
      canProceed: true,
    };
  }

  const fixScript = [
    'networksetup -setairportpower en1 off;',
    'networksetup -setdhcp "Wi-Fi";',
    'echo "__LAN_GUARD_FIX__:applied"',
  ].join(' ');

  const fix = await runRemoteCommand(ssh, fixScript, false);
  let verify: CommandResult = { exitCode: 1, stdout: '', stderr: '' };
  for (let attempt = 0; attempt < 8; attempt += 1) {
    if (attempt > 0) {
      await delayMs(1500);
    }
    verify = await runRemoteCommand(ssh, 'echo "__LAN_GUARD_VERIFY__:ok"', false);
    if (verify.exitCode === 0) break;
  }

  if (verify.exitCode === 0 && fix.exitCode === 0) {
    return {
      status: 'ok',
      message: `detected dual-IP conflict (${context}); disabled Wi-Fi and reset Wi-Fi DHCP`,
      canProceed: true,
    };
  }

  if (verify.exitCode === 0 && fix.exitCode !== 0) {
    return {
      status: 'skip',
      message: `detected dual-IP conflict (${context}); connectivity recovered but fix command reported an error: ${summarizeOutput(fix.stderr || fix.stdout)}`,
      canProceed: true,
    };
  }

  const failureStatus = remoteConnectFailureStatus(mode);
  const fixDetail = summarizeOutput(fix.stderr || fix.stdout);
  const verifyDetail = summarizeOutput(verify.stderr || verify.stdout);
  const modeHint =
    mode === 'auto'
      ? 'auto mode skipped Studio updates; use --target remote once SSH is stable'
      : 'fix network path and rerun update';

  return {
    status: failureStatus,
    message: `dual-IP conflict detected (${context}); attempted auto-fix but SSH verification failed (fix=${fixDetail}; verify=${verifyDetail}) (${modeHint})`,
    canProceed: false,
  };
}

function isRecoverableGitFailure(raw: string): boolean {
  const value = raw.toLowerCase();
  return (
    value.includes('permission denied (publickey)') ||
    value.includes('could not read from remote repository') ||
    value.includes('bad object head') ||
    value.includes('repository not found')
  );
}

function handleGitPullFailure(
  result: CommandResult,
  prefix: string
): { status: StepStatus; message: string } {
  const detail = result.stderr || result.stdout;
  if (isRecoverableGitFailure(detail)) {
    return {
      status: 'skip',
      message: `${prefix} unavailable (skipped): ${summarizeOutput(detail)}`,
    };
  }

  return {
    status: 'fail',
    message: `${prefix} failed: ${detail}`,
  };
}

async function updateGitLocal(
  repoPath: string,
  noPull: boolean,
  dryRun: boolean
): Promise<{ status: StepStatus; message: string }> {
  if (!existsSync(repoPath)) {
    return { status: 'skip', message: `repo missing: ${repoPath}` };
  }
  if (!existsSync(join(repoPath, '.git'))) {
    return { status: 'skip', message: 'not a git repository (skipped pull)' };
  }

  const hasHead = await runLocalCommand(
    'git rev-parse --verify HEAD >/dev/null 2>&1',
    repoPath,
    dryRun
  );
  if (hasHead.exitCode !== 0) {
    return { status: 'skip', message: 'invalid git metadata (missing HEAD, skipped pull)' };
  }

  const dirty = await runLocalCommand('git status --porcelain', repoPath, dryRun);
  if (dirty.exitCode !== 0) {
    return {
      status: 'skip',
      message: `git status unavailable (skipped pull): ${summarizeOutput(dirty.stderr || dirty.stdout)}`,
    };
  }
  if (!dryRun && dirty.stdout.trim().length > 0) {
    return { status: 'skip', message: 'dirty working tree (skipped pull)' };
  }

  if (noPull) {
    return { status: 'ok', message: 'git pull skipped (--no-pull)' };
  }

  const pull = await runLocalCommand(
    'git fetch --all --prune && git pull --ff-only',
    repoPath,
    dryRun
  );
  if (pull.exitCode !== 0) {
    return handleGitPullFailure(pull, 'git pull');
  }

  return { status: 'ok', message: dryRun ? 'dry-run git sync' : 'git sync complete' };
}

async function updateGitRemote(
  repoPath: string,
  noPull: boolean,
  ssh: SshConfig,
  dryRun: boolean
): Promise<{ status: StepStatus; message: string }> {
  const script = [
    `if [ ! -d ${quoteSh(repoPath)} ]; then exit 24; fi`,
    `if [ ! -d ${quoteSh(join(repoPath, '.git'))} ]; then exit 26; fi`,
    `git -C ${quoteSh(repoPath)} rev-parse --verify HEAD >/dev/null 2>&1 || exit 27`,
    `status_out="$(git -C ${quoteSh(repoPath)} status --porcelain 2>/dev/null)" || exit 28`,
    'if [ -n "$status_out" ]; then exit 25; fi',
    noPull
      ? ':'
      : `git -C ${quoteSh(repoPath)} fetch --all --prune && git -C ${quoteSh(repoPath)} pull --ff-only`,
  ].join('; ');

  const result = await runRemoteCommand(ssh, script, dryRun);

  if (result.exitCode === 24) return { status: 'skip', message: `repo missing: ${repoPath}` };
  if (result.exitCode === 26)
    return { status: 'skip', message: 'not a git repository (skipped pull)' };
  if (result.exitCode === 27)
    return { status: 'skip', message: 'invalid git metadata (missing HEAD, skipped pull)' };
  if (result.exitCode === 28)
    return { status: 'skip', message: 'git status unavailable (skipped pull)' };
  if (result.exitCode === 25)
    return { status: 'skip', message: 'dirty working tree (skipped pull)' };
  if (result.exitCode !== 0) {
    return handleGitPullFailure(result, 'git sync');
  }

  return {
    status: 'ok',
    message: noPull
      ? 'git pull skipped (--no-pull)'
      : dryRun
        ? 'dry-run git sync'
        : 'git sync complete',
  };
}

async function runComponentBuildLocal(
  component: UpdateComponent,
  repoPath: string,
  dryRun: boolean,
  lmxPort: number
): Promise<{ status: StepStatus; message: string }> {
  switch (component) {
    case 'cli': {
      const cmd = CLI_UPDATE_BUILD_SCRIPT;
      const result = await runLocalCommand(cmd, repoPath, dryRun);
      if (result.exitCode !== 0) return { status: 'fail', message: result.stderr || result.stdout };
      return {
        status: 'ok',
        message: dryRun ? 'dry-run typecheck + build' : 'npm typecheck + build complete',
      };
    }
    case 'lmx': {
      const installCmd = [
        `if [ -x ${quoteSh(join(repoPath, '.venv/bin/python'))} ]; then PIPY=${quoteSh(join(repoPath, '.venv/bin/python'))};`,
        'else PIPY=python3; fi;',
        `"$PIPY" -m pip install -e ${quoteSh(repoPath)} --no-deps || "$PIPY" -m pip install ${quoteSh(repoPath)} --no-deps`,
      ].join(' ');

      const install = await runLocalCommand(installCmd, repoPath, dryRun);
      if (install.exitCode !== 0)
        return { status: 'fail', message: install.stderr || install.stdout };

      const restartCmd = [
        'pkill -f "python -m opta_lmx.main" >/dev/null 2>&1 || true;',
        'pkill -f "python -m opta_lmx" >/dev/null 2>&1 || true;',
        `if [ -x ${quoteSh(join(repoPath, '.venv/bin/python'))} ]; then PY=${quoteSh(join(repoPath, '.venv/bin/python'))};`,
        'else PY=python3; fi;',
        `nohup env LMX_LOGGING__FILE=/tmp/opta-lmx.log "$PY" -m opta_lmx.main --host 0.0.0.0 --port ${lmxPort} >/tmp/opta-lmx.log 2>&1 &`,
        'ok=0;',
        `for i in $(seq 1 45); do code=$(curl -s -o /dev/null -w "%{http_code}" http://127.0.0.1:${lmxPort}/healthz || true);`,
        'if [ "$code" = "200" ] || [ "$code" = "401" ] || [ "$code" = "403" ]; then ok=1; break; fi;',
        'sleep 1;',
        'done;',
        'if [ "$ok" = "1" ]; then true; else pgrep -f "python -m opta_lmx.main" >/dev/null 2>&1 || pgrep -f "python -m opta_lmx" >/dev/null 2>&1; fi',
      ].join(' ');

      const restart = await runLocalCommand(restartCmd, repoPath, dryRun);
      if (restart.exitCode !== 0) {
        return {
          status: 'fail',
          message: `install ok, restart/health failed: ${restart.stderr || restart.stdout}`,
        };
      }

      return {
        status: 'ok',
        message: dryRun ? 'dry-run install/restart' : 'install + restart + health check complete',
      };
    }
    case 'plus': {
      const result = await runLocalCommand('swift build', repoPath, dryRun);
      if (result.exitCode !== 0) return { status: 'fail', message: result.stderr || result.stdout };
      return { status: 'ok', message: dryRun ? 'dry-run swift build' : 'swift build complete' };
    }
    case 'web': {
      const result = await runLocalCommand(
        'if command -v pnpm >/dev/null 2>&1; then pnpm -C web run build || (pnpm -C web install --no-frozen-lockfile && pnpm -C web run build); else npm --prefix web run build || (npm --prefix web install --no-fund --no-audit && npm --prefix web run build); fi',
        repoPath,
        dryRun
      );
      if (result.exitCode !== 0) return { status: 'fail', message: result.stderr || result.stdout };
      return { status: 'ok', message: dryRun ? 'dry-run build' : 'web build complete' };
    }
  }
}

async function runComponentBuildRemote(
  component: UpdateComponent,
  repoPath: string,
  dryRun: boolean,
  ssh: SshConfig,
  lmxPort: number,
  lmxPythonPath: string
): Promise<{ status: StepStatus; message: string }> {
  let command: string;

  switch (component) {
    case 'cli':
      command = `cd ${quoteSh(repoPath)} && (${CLI_UPDATE_BUILD_SCRIPT})`;
      break;
    case 'lmx':
      command = [
        `cd ${quoteSh(repoPath)}`,
        '&& {',
        `if [ -x ${quoteSh(join(repoPath, '.venv/bin/python'))} ]; then PIPY=${quoteSh(join(repoPath, '.venv/bin/python'))};`,
        'else PIPY=python3; fi;',
        `"$PIPY" -m pip install -e ${quoteSh(repoPath)} --no-deps || "$PIPY" -m pip install ${quoteSh(repoPath)} --no-deps;`,
        `pkill -f "python -m opta_lmx.main" >/dev/null 2>&1 || true;`,
        `pkill -f "python -m opta_lmx" >/dev/null 2>&1 || true;`,
        `if [ -x ${quoteSh(lmxPythonPath)} ] && ${quoteSh(lmxPythonPath)} -c "import opta_lmx" >/dev/null 2>&1; then PY=${quoteSh(lmxPythonPath)};`,
        'elif command -v "$PIPY" >/dev/null 2>&1; then PY="$PIPY";',
        'else PY=python3; fi;',
        `nohup env LMX_LOGGING__FILE=/tmp/opta-lmx.log "$PY" -m opta_lmx.main --host 0.0.0.0 --port ${lmxPort} >/tmp/opta-lmx.log 2>&1 &`,
        'ok=0;',
        `for i in $(seq 1 45); do code=$(curl -s -o /dev/null -w "%{http_code}" http://127.0.0.1:${lmxPort}/healthz || true);`,
        'if [ "$code" = "200" ] || [ "$code" = "401" ] || [ "$code" = "403" ]; then ok=1; break; fi;',
        'sleep 1;',
        'done;',
        'if [ "$ok" = "1" ]; then true; else pgrep -f "python -m opta_lmx.main" >/dev/null 2>&1 || pgrep -f "python -m opta_lmx" >/dev/null 2>&1; fi;',
        '}',
      ].join(' ');
      break;
    case 'plus':
      command = `cd ${quoteSh(repoPath)} && swift build`;
      break;
    case 'web':
      command = [
        `cd ${quoteSh(repoPath)}`,
        '&& if command -v pnpm >/dev/null 2>&1;',
        'then pnpm -C web run build || (pnpm -C web install --no-frozen-lockfile && pnpm -C web run build);',
        'else npm --prefix web run build || (npm --prefix web install --no-fund --no-audit && npm --prefix web run build);',
        'fi',
      ].join(' ');
      break;
  }

  const result = await runRemoteCommand(ssh, command, dryRun);
  if (result.exitCode !== 0) {
    return { status: 'fail', message: result.stderr || result.stdout || 'remote command failed' };
  }

  const okMessage =
    component === 'lmx'
      ? dryRun
        ? 'dry-run install/restart'
        : 'install + restart + health check complete'
      : component === 'cli'
        ? dryRun
          ? 'dry-run typecheck + build'
          : 'typecheck + build complete'
        : dryRun
          ? 'dry-run build'
          : 'build complete';
  return { status: 'ok', message: okMessage };
}

function printHumanSummary(results: StepResult[]): void {
  console.log('');
  console.log(chalk.bold(colorizeOptaWord('Opta Update Summary')));

  for (const result of results) {
    const prefix =
      result.status === 'ok'
        ? chalk.green('✓')
        : result.status === 'skip'
          ? chalk.yellow('!')
          : chalk.red('✗');

    const targetLabel =
      result.target === 'remote' && result.host ? `${result.target}@${result.host}` : result.target;

    console.log(
      `${prefix} [${targetLabel}] ${result.component}:${result.step} — ${result.message}`
    );
  }

  const failures = results.filter((r) => r.status === 'fail').length;
  const skips = results.filter((r) => r.status === 'skip').length;
  const ok = results.filter((r) => r.status === 'ok').length;

  console.log('');
  console.log(chalk.dim(`ok=${ok} skip=${skips} fail=${failures}`));
}

function componentStep(
  target: UpdateTarget,
  component: UpdateComponent,
  step: string,
  outcome: { status: StepStatus; message: string },
  host?: string
): StepResult {
  return {
    target,
    component,
    step,
    status: outcome.status,
    message: outcome.message,
    host,
  };
}

function canProceedToBuild(gitResult: { status: StepStatus; message: string }): boolean {
  if (gitResult.status === 'fail') return false;
  if (gitResult.message.startsWith('repo missing:')) return false;
  return true;
}

export async function updateCommand(opts: UpdateOptions): Promise<void> {
  const config = await loadConfig();
  const components = parseComponentList(opts.components);
  const mode = opts.target ?? 'auto';
  const remoteHost = opts.remoteHost ?? config.connection.host;
  const targets = resolveTargets(mode, remoteHost);

  // Windows can run local updates but not SSH-based remote updates.
  if (isWindows && targets.includes('remote') && !isLocalHost(remoteHost)) {
    throw new (await import('../core/errors.js')).OptaError(
      'Remote updates via SSH are not supported on Windows.\n\n' +
        'Use --target local to update local components, or run remote updates from a macOS/Linux host.'
    );
  }
  let remoteHostUsed: string | null = null;

  const results: StepResult[] = [];
  const dryRun = Boolean(opts.dryRun);
  const noBuild = opts.build === false;
  const noPull = opts.pull === false;

  const localAppsRoot = opts.localRoot ? expandHome(opts.localRoot) : detectAppsRoot(process.cwd());

  const remoteAppsRoot = opts.remoteRoot
    ? expandHome(opts.remoteRoot)
    : deriveRemoteAppsRootFromLmxPath(config.connection.ssh.lmxPath);

  const verifyStepCount =
    targets.includes('remote') && components.includes('cli') && !isLocalHost(remoteHost) ? 1 : 0;
  const remoteGuardStepCount = targets.includes('remote') && !isLocalHost(remoteHost) ? 1 : 0;
  const localStepCount = targets.includes('local')
    ? localAppsRoot
      ? components.length * 2
      : 1
    : 0;
  const remoteStepCount = targets.includes('remote')
    ? isLocalHost(remoteHost)
      ? components.length
      : components.length * 2 + verifyStepCount + remoteGuardStepCount
    : 0;
  const progress = createSegmentedStepProgressTracker(
    [
      ...(localStepCount > 0 ? [{ key: 'local', label: 'Local', totalSteps: localStepCount }] : []),
      ...(remoteStepCount > 0
        ? [{ key: 'remote', label: 'Studio', totalSteps: remoteStepCount }]
        : []),
    ],
    'Update progress',
    !opts.json
  );
  const pushResult = (result: StepResult): void => {
    results.push(result);
    const hostSuffix = result.target === 'remote' && result.host ? `@${result.host}` : '';
    const scope = result.target === 'remote' ? 'studio' : 'local';
    progress.tick(
      result.target,
      `[${scope}] ${result.component}:${result.step}${hostSuffix} ${result.status}`
    );
  };

  if (targets.includes('local')) {
    if (!localAppsRoot) {
      pushResult({
        target: 'local',
        component: 'cli',
        step: 'discover-root',
        status: 'fail',
        message: 'could not determine local 1-Apps root; use --local-root',
      });
    } else {
      for (const component of components) {
        const repoPath = componentRepoPath(component, localAppsRoot);
        const gitResult = await updateGitLocal(repoPath, noPull, dryRun);
        pushResult(componentStep('local', component, 'git', gitResult));

        if (!canProceedToBuild(gitResult) || noBuild) {
          if (noBuild) {
            pushResult({
              target: 'local',
              component,
              step: 'build',
              status: 'skip',
              message: 'skipped (--no-build)',
            });
          }
          continue;
        }

        const buildResult = await runComponentBuildLocal(
          component,
          repoPath,
          dryRun,
          config.connection.port
        );
        pushResult(componentStep('local', component, 'build', buildResult));
      }
    }
  }

  if (targets.includes('remote')) {
    if (isLocalHost(remoteHost)) {
      remoteHostUsed = remoteHost;
      for (const component of components) {
        pushResult({
          target: 'remote',
          component,
          step: 'connect',
          status: 'skip',
          message: `remote host ${remoteHost} resolves to local; skipped`,
          host: remoteHost,
        });
      }
    } else {
      const baseSshConfig: SshConfig = {
        host: remoteHost,
        user: opts.remoteUser ?? config.connection.ssh.user,
        identityFile: expandHome(opts.identityFile ?? config.connection.ssh.identityFile),
      };

      const remoteCandidates = resolveRemoteHostCandidates(
        remoteHost,
        config.connection.fallbackHosts
      );
      const selection = await selectReachableRemoteHost(
        remoteCandidates,
        (candidateHost) =>
          runRemoteCommand(
            {
              ...baseSshConfig,
              host: candidateHost,
            },
            'echo connected',
            dryRun
          ),
        { parallel: true }
      );

      if (!selection.selectedHost) {
        const connectStatus = remoteConnectFailureStatus(mode);
        const attemptDetail =
          selection.probes.length > 0
            ? selection.probes
                .map((probe) => `${probe.host}: ${summarizeOutput(probe.detail)}`)
                .join('; ')
            : 'ssh failed';
        const attemptedHosts =
          remoteCandidates.length > 0 ? remoteCandidates.join(', ') : remoteHost;
        const connectDetail = `ssh failed for hosts (${attemptedHosts}) — ${attemptDetail}`;
        const connectMessage =
          mode === 'auto'
            ? `${connectDetail} (auto mode skipped Studio updates; use --target remote once SSH is reachable)`
            : connectDetail;
        for (const component of components) {
          pushResult({
            target: 'remote',
            component,
            step: 'connect',
            status: connectStatus,
            message: connectMessage,
            host: remoteHost,
          });
        }
      } else {
        remoteHostUsed = selection.selectedHost;
        const sshConfig: SshConfig = {
          ...baseSshConfig,
          host: selection.selectedHost,
        };

        const guardComponent = components[0] ?? 'cli';
        const guard = await runRemoteLanStabilityGuard(sshConfig, dryRun, mode);
        pushResult(
          componentStep(
            'remote',
            guardComponent,
            'network',
            {
              status: guard.status,
              message: guard.message,
            },
            sshConfig.host
          )
        );

        if (!guard.canProceed) {
          const gatedMessage = 'skipped due LAN guard failure';
          for (const component of components) {
            pushResult({
              target: 'remote',
              component,
              step: 'git',
              status: 'skip',
              message: gatedMessage,
              host: sshConfig.host,
            });

            if (noBuild) {
              pushResult({
                target: 'remote',
                component,
                step: 'build',
                status: 'skip',
                message: 'skipped (--no-build)',
                host: sshConfig.host,
              });
            } else {
              pushResult({
                target: 'remote',
                component,
                step: 'build',
                status: 'skip',
                message: gatedMessage,
                host: sshConfig.host,
              });
            }

            if (component === 'cli') {
              pushResult({
                target: 'remote',
                component,
                step: 'verify',
                status: 'skip',
                message: gatedMessage,
                host: sshConfig.host,
              });
            }
          }
        } else {
          for (const component of components) {
            const repoPath =
              component === 'lmx'
                ? config.connection.ssh.lmxPath
                : remoteAppsRoot
                  ? componentRepoPath(component, remoteAppsRoot)
                  : '';

            if (!repoPath) {
              pushResult({
                target: 'remote',
                component,
                step: 'discover-root',
                status: 'skip',
                message: 'remote path unavailable; set --remote-root for cli/plus/web',
                host: sshConfig.host,
              });
              continue;
            }

            const gitResult = await updateGitRemote(repoPath, noPull, sshConfig, dryRun);
            pushResult(componentStep('remote', component, 'git', gitResult, sshConfig.host));

            if (!canProceedToBuild(gitResult)) {
              continue;
            }

            if (noBuild) {
              pushResult({
                target: 'remote',
                component,
                step: 'build',
                status: 'skip',
                message: 'skipped (--no-build)',
                host: sshConfig.host,
              });
            } else {
              const buildResult = await runComponentBuildRemote(
                component,
                repoPath,
                dryRun,
                sshConfig,
                config.connection.port,
                config.connection.ssh.pythonPath
              );
              pushResult(componentStep('remote', component, 'build', buildResult, sshConfig.host));
            }

            if (component === 'cli') {
              const verify = await verifyRemoteCliCommands(sshConfig, dryRun);
              pushResult(componentStep('remote', component, 'verify', verify, sshConfig.host));
            }
          }
        }
      }
    }
  }

  progress.done('all update steps finished');

  if (opts.json) {
    console.log(
      JSON.stringify(
        {
          mode,
          components,
          targets,
          dryRun,
          noBuild,
          noPull,
          localAppsRoot,
          remoteHost,
          remoteHostUsed,
          remoteAppsRoot,
          results,
        },
        null,
        2
      )
    );
  } else {
    printHumanSummary(results);
  }

  let updateLogPath: string | null = null;
  const journal = config.journal;
  if (journal?.enabled) {
    try {
      const written = await writeUpdateLog({
        summary: `opta update (${mode}) — ${components.join(', ')}`,
        commandInputs: {
          components,
          mode,
          targets,
          dryRun,
          noBuild,
          noPull,
          localAppsRoot: localAppsRoot ?? '(auto-detect failed)',
          remoteHost,
          remoteHostUsed: remoteHostUsed ?? '(none)',
          remoteAppsRoot: remoteAppsRoot ?? '(auto)',
          json: Boolean(opts.json),
        },
        steps: results.map((result) => ({
          target: result.target,
          component: result.component,
          step: result.step,
          status: result.status,
          message: result.host ? `[${result.host}] ${result.message}` : result.message,
        })),
        cwd: process.cwd(),
        logsDir: journal?.updateLogsDir,
        timezone: journal?.timezone,
        author: journal?.author,
        rangeStart: 200,
        rangeEnd: 299,
        promoted: true,
        category: 'sync',
      });
      updateLogPath = written.path;
    } catch {
      // Fail-open by design: update command must not fail due to logging errors.
    }
  }

  if (!opts.json && updateLogPath) {
    console.log(chalk.dim(`Update log: ${updateLogPath}`));
  }

  const hasFailure = results.some((r) => r.status === 'fail');
  if (hasFailure) {
    throw new ExitError(EXIT.ERROR);
  }
}

import { access, mkdir, readFile, writeFile } from 'node:fs/promises';
import { join } from 'node:path';
import type { OptaConfig } from '../core/config.js';

export type MemoryScope = 'primary' | 'provider' | 'atpo' | 'legacy' | 'project';

export interface MemoryCandidate {
  path: string;
  label: string;
  scope: MemoryScope;
}

const OPTA_MEMORY_DIR = '.opta/memory';

const PROVIDER_FILE_BY_PROVIDER: Record<string, string> = {
  anthropic: 'claude.md',
  gemini: 'gemini.md',
  openai: 'codex.md',
  opencode_zen: 'opencode-zen.md',
};

/**
 * Map an active provider to its dedicated memory document name.
 */
export function getProviderMemoryFileName(provider: string): string {
  return PROVIDER_FILE_BY_PROVIDER[provider] ?? `${provider}.md`;
}

function memoryDir(cwd: string): string {
  return join(cwd, OPTA_MEMORY_DIR);
}

/**
 * Returns all memory files that can participate in prompt context.
 *
 * Priority is explicit:
 * 1. provider-specific file (claude/gemini/codex/etc.)
 * 2. model-specific override (optional)
 * 3. main.md (shared cross-model baseline)
 * 4. atpo.md (operating context)
 * 5. legacy .opta/memory.md
 * 6. CLAUDE.md project file
 */
export function buildMemoryCandidates(
  cwd: string,
  config: OptaConfig | null,
  activeModel = ''
): MemoryCandidate[] {
  const dir = memoryDir(cwd);
  const normalizedActiveProvider = (config?.provider?.active ?? 'lmx') as string;
  const providerFile = getProviderMemoryFileName(normalizedActiveProvider);

  const seen = new Set<string>();
  const candidate = (path: string, label: string, scope: MemoryScope): MemoryCandidate | null => {
    if (!path || seen.has(path)) return null;
    seen.add(path);
    return { path, label, scope };
  };

  const candidates: MemoryCandidate[] = [];

  const push = (p: MemoryCandidate | null) => {
    if (p) candidates.push(p);
  };

  // Provider-specific memory is now first-class and wins over legacy/shared context.
  push(candidate(join(dir, providerFile), providerFile, 'provider'));

  // Model-specific override when the user chooses a dedicated model document
  // naming convention (e.g., codex-gpt-5.md).
  if (activeModel.trim()) {
    const normalizedModel = activeModel.trim().replace(/[^a-zA-Z0-9._-]/g, '_');
    push(candidate(join(dir, `${normalizedModel}.md`), `${normalizedModel}.md`, 'provider'));
  }

  // Baseline memory always available across providers.
  push(candidate(join(dir, 'main.md'), 'main', 'primary'));

  // Dedicated ATPO context is separate from provider memory and only appended when present.
  push(candidate(join(dir, 'atpo.md'), 'atpo', 'atpo'));

  // Legacy fallback for installations created before scoped memory files.
  push(candidate(join(cwd, '.opta', 'memory.md'), 'legacy-memory.md', 'legacy'));
  push(candidate(join(cwd, 'CLAUDE.md'), 'CLAUDE.md', 'project'));

  return candidates;
}

/**
 * Load and combine all available memory files into a context block.
 */
export async function readSharedMemoryContext(
  cwd: string,
  config: OptaConfig | null,
  activeModel = ''
): Promise<string> {
  const candidates = buildMemoryCandidates(cwd, config, activeModel);
  const blocks: string[] = [];

  for (const { path, label, scope } of candidates) {
    const content = await safeReadFile(path);
    if (!content) continue;

    const sectionHeader =
      scope === 'provider'
        ? `## ${label.toUpperCase()} Context`
        : scope === 'atpo'
          ? '## ATPO Context'
          : '## Shared Context';

    blocks.push(`${sectionHeader}\n${content.trim()}\n`);
  }

  return blocks.join('\n');
}

/**
 * Resolve the canonical write target for save_memory.
 *
 * Preference is explicit scoped memory: provider-specific (or main for lmx),
 * then main/shared baseline, then legacy path.
 * If no scoped files exist, this creates a scoped target and a baseline main/atpo
 * scaffold so writes are immediately namespaced.
 */
export async function resolveWritableMemoryPath(cwd: string, config: OptaConfig | null): Promise<string> {
  const dir = memoryDir(cwd);
  const provider = (config?.provider?.active ?? 'lmx') as string;
  const providerFile = getProviderMemoryFileName(provider);

  const primaryCandidates = [provider === 'lmx' ? join(dir, 'main.md') : join(dir, providerFile), join(dir, 'main.md')];
  const legacyPath = join(cwd, '.opta', 'memory.md');

  for (const path of primaryCandidates) {
    try {
      await access(path);
      return path;
    } catch {
      // continue
    }
  }

  // First run / missing files: create scoped memory files and migrate legacy.
  await mkdir(dir, { recursive: true });

  const now = new Date().toISOString();
  const mainSeed = [
    '# Project Memory',
    '',
    `Provider: ${provider}`,
    `Created: ${now}`,
    '',
    '## Notes',
    '',
  ].join('\n');

  const providerSeed = [
    '# Provider Memory',
    '',
    `Provider: ${provider}`,
    `Provider profile: ${providerFile.replace('.md', '')}`,
    `Created: ${now}`,
    '',
    '## Notes',
    '',
  ].join('\n');

  const atpoSeed = [
    '# ATPO Memory',
    '',
    'Purpose: operating-memory overlay for higher-level workflows.',
    `Created: ${now}`,
    '',
    '## Notes',
    '',
  ].join('\n');

  const writeIfMissing = async (target: string, content: string): Promise<void> => {
    try {
      await access(target);
    } catch {
      await writeFile(target, content, 'utf-8');
    }
  };

  // If legacy file exists, keep it as compatibility and seed main with it when empty.
  let migratedFromLegacy = false;
  try {
    const existingLegacy = await readFile(legacyPath, 'utf-8');
    if (existingLegacy?.trim()) {
      const migrated = [mainSeed, '', '# Migration (legacy)', '', existingLegacy].join('\n');
      await writeFile(join(dir, 'main.md'), migrated, 'utf-8');
      migratedFromLegacy = true;
    }
  } catch {
    // ignore
  }

  await writeIfMissing(join(dir, 'main.md'), mainSeed);
  if (!migratedFromLegacy) {
    await writeIfMissing(join(dir, 'atpo.md'), atpoSeed);
  }
  if (provider !== 'lmx') {
    await writeIfMissing(join(dir, providerFile), providerSeed);
  }

  return provider === 'lmx' ? join(dir, 'main.md') : join(dir, providerFile);
}

/**
 * Create an optimized first-run memory scaffold.
 */
export async function ensureMemoryScaffold(cwd: string): Promise<string[]> {
  const dir = memoryDir(cwd);
  await mkdir(dir, { recursive: true });

  const targets = [
    'main.md',
    'atpo.md',
    'claude.md',
    'gemini.md',
    'codex.md',
    'opencode-zen.md',
  ];

  const existing: string[] = [];
  const now = new Date().toISOString();

  for (const file of targets) {
    const path = join(dir, file);
    try {
      await access(path);
      existing.push(`.opta/memory/${file}`);
    } catch {
      const seeded = [
        '# Model Memory',
        '',
        `Provider profile: ${file.replace('.md', '')}`,
        `Provider seed created: ${now}`,
        '',
      ].join('\n');
      await writeFile(path, seeded, 'utf-8');
      existing.push(`.opta/memory/${file}`);
    }
  }

  return existing;
}

async function safeReadFile(path: string): Promise<string | null> {
  try {
    return await readFile(path, 'utf-8');
  } catch (err) {
    const code = (err as NodeJS.ErrnoException | undefined)?.code;
    if (code === 'ENOENT' || code === 'ENOTDIR') {
      return null;
    }
    throw err;
  }
}

/**
 * agent-permissions.ts — Tool approval flow.
 *
 * Extracted from agent.ts to isolate the permission checking logic,
 * the interactive approval prompt, and the "always allow" persistence.
 */

import chalk from 'chalk';
import type { OptaConfig } from './config.js';
import { resolveBrowserPolicyConfig } from './browser-policy-config.js';
import { resolvePermission } from './tools/index.js';
import { PolicyEngine } from '../policy/engine.js';
import type { PolicyConfig } from '../policy/types.js';
import { evaluateBrowserPolicyAction, isBrowserToolName } from '../browser/policy-engine.js';
import { appendBrowserApprovalEvent, extractBrowserSessionId } from '../browser/approval-log.js';
import { loadBrowserRunCorpusAdaptationHint } from '../browser/adaptation.js';
import { safeParseJson } from '../utils/json.js';
import { runMenuPrompt } from '../ui/prompt-nav.js';
import type { OnStreamCallbacks } from './agent.js';
import type { ToolCallAccum } from './agent-streaming.js';
import type { SessionContext } from '../hooks/integration.js';
import { fireToolPre, type HookManager } from '../hooks/integration.js';

// --- Types ---

export interface ToolDecision {
  call: ToolCallAccum;
  approved: boolean;
  denialReason?: string;
  executionArgsJson?: string;
}

type PermissionResponse = 'once' | 'always' | 'deny';

interface BrowserSessionScanResult {
  sessions: Array<{
    sessionId: string;
    currentUrl?: string;
  }>;
  sessionIds: string[];
  error?: string;
}

function resolveBrowserSpawnMode(config: OptaConfig): 'isolated' | 'attach' {
  if (config.browser.attach.enabled) return 'attach';
  return config.browser.mode ?? 'isolated';
}

function resolveBrowserAttachWsEndpoint(
  config: OptaConfig,
  mode: 'isolated' | 'attach',
): string | undefined {
  if (mode !== 'attach') return undefined;
  const endpoint = config.browser.attach.wsEndpoint.trim();
  return endpoint.length > 0 ? endpoint : undefined;
}

function isShellBrowserAutomationCommand(value: unknown): boolean {
  if (typeof value !== 'string') return false;
  const command = value.toLowerCase();
  if (!command.includes('osascript')) return false;
  return (
    command.includes('application "safari"') ||
    command.includes('application "google chrome"') ||
    command.includes('application "chrome"') ||
    command.includes('document.queryselector') ||
    command.includes('javascript')
  );
}

function mapPolicyFailureMode(
  failureMode: OptaConfig['policy']['failureMode']
): PolicyConfig['failureMode'] {
  if (failureMode === 'open') return 'open';
  // Engine accepts only open|closed; degraded-safe maps to fail-closed.
  return 'closed';
}

function mapPolicyConfig(policy: OptaConfig['policy']): PolicyConfig {
  return {
    enabled: policy.enabled,
    mode: policy.mode,
    gateAllAutonomy: policy.gateAllAutonomy,
    failureMode: mapPolicyFailureMode(policy.failureMode),
    audit: {
      enabled: policy.audit.enabled,
    },
  };
}

// --- Permission Prompt ---

async function promptToolApproval(
  toolName: string,
  args: Record<string, unknown>
): Promise<PermissionResponse> {
  // Non-interactive environments (CI, piped stdin) default to deny
  if (!process.stdin.isTTY || process.env['CI'] === 'true') {
    return 'deny';
  }

  console.log();
  console.log(chalk.yellow(`  Tool: ${toolName}`));

  // Show relevant details based on tool type
  if (toolName === 'edit_file') {
    console.log(chalk.dim(`  File: ${String(args['path'])}`));
    console.log(chalk.red(`  - ${String(args['old_text']).slice(0, 100)}`));
    console.log(chalk.green(`  + ${String(args['new_text']).slice(0, 100)}`));
  } else if (toolName === 'write_file') {
    console.log(chalk.dim(`  File: ${String(args['path'])}`));
    const contentVal = args['content'];
    const content =
      typeof contentVal === 'string'
        ? contentVal
        : typeof contentVal === 'object'
          ? JSON.stringify(contentVal)
          : String(contentVal as number | boolean | bigint | null | undefined);
    console.log(chalk.dim(`  ${content.length} bytes`));
  } else if (toolName === 'run_command') {
    console.log(chalk.dim(`  $ ${String(args['command'])}`));
  } else {
    console.log(chalk.dim(`  ${JSON.stringify(args)}`));
  }

  const { select } = await import('@inquirer/prompts');
  const choice = await runMenuPrompt(
    (context) =>
      select(
        {
          message: 'Allow?',
          choices: [
            { name: 'Yes, allow this once', value: 'once' as const },
            { name: 'Always allow (persist)', value: 'always' as const },
            { name: 'Deny', value: 'deny' as const },
          ],
          default: 'once',
        },
        context
      ),
    'select'
  );

  // Back key behaves like cancel/deny for safety.
  return choice ?? 'deny';
}

async function persistToolPermissionAllow(
  toolName: string,
  config: OptaConfig,
  saveConfig: (partial: Record<string, unknown>) => Promise<void>,
  silent: boolean
): Promise<void> {
  try {
    await saveConfig({ permissions: { ...config.permissions, [toolName]: 'allow' } });
    config.permissions[toolName] = 'allow';
    if (!silent) console.log(chalk.dim(`  Permission for ${toolName} set to "allow" permanently.`));
  } catch (error) {
    if (process.env.OPTA_DEBUG) console.error('Failed to persist permission:', error);
  }
}

async function getBrowserRuntimeDaemon(config: OptaConfig, cwd: string) {
  const { getSharedBrowserRuntimeDaemon } = await import('../browser/runtime-daemon.js');
  return getSharedBrowserRuntimeDaemon({
    cwd,
    maxSessions: config.browser.runtime.maxSessions,
    persistSessions: config.browser.runtime.persistSessions,
    persistProfileContinuity: config.browser.runtime.persistProfileContinuity,
    profileRetentionPolicy: {
      retentionDays: config.browser.runtime.profileRetentionDays,
      maxPersistedProfiles: config.browser.runtime.maxPersistedProfiles,
    },
    profilePruneIntervalMs: config.browser.runtime.profilePruneIntervalHours * 60 * 60 * 1_000,
    artifactPrune: {
      enabled: config.browser.artifacts.retention.enabled,
      policy: {
        retentionDays: config.browser.artifacts.retention.retentionDays,
        maxPersistedSessions: config.browser.artifacts.retention.maxPersistedSessions,
      },
      intervalMs: config.browser.artifacts.retention.pruneIntervalHours * 60 * 60 * 1_000,
    },
    runCorpusRefresh: {
      enabled: config.browser.runtime.runCorpus.enabled,
      windowHours: config.browser.runtime.runCorpus.windowHours,
    },
  });
}

async function scanActiveBrowserSessions(
  config: OptaConfig,
  cwd: string
): Promise<BrowserSessionScanResult> {
  try {
    const daemon = await getBrowserRuntimeDaemon(config, cwd);
    // Ensure persisted sessions are recovered before scanning health.
    await daemon.start();
    const sessions = daemon
      .health()
      .sessions.filter((session) => session.status === 'open')
      .map((session) => ({
        sessionId: session.sessionId.trim(),
        currentUrl: session.currentUrl?.trim() || undefined,
      }))
      .filter((session) => session.sessionId.length > 0);
    return {
      sessions,
      sessionIds: sessions.map((session) => session.sessionId),
    };
  } catch (error) {
    return {
      sessions: [],
      sessionIds: [],
      error: error instanceof Error ? error.message : String(error),
    };
  }
}

// --- Resolve Tool Decisions ---

export interface ResolvePermissionsOptions {
  isSubAgent: boolean;
  silent: boolean;
  saveConfig: (partial: Record<string, unknown>) => Promise<void>;
  streamCallbacks?: OnStreamCallbacks;
  hooks: HookManager;
  sessionCtx: SessionContext;
}

/**
 * Resolves permissions for each tool call sequentially (prompts must be one-at-a-time).
 * Returns a ToolDecision[] indicating which calls are approved or denied.
 */
export async function resolveToolDecisions(
  toolCalls: ToolCallAccum[],
  config: OptaConfig,
  options: ResolvePermissionsOptions
): Promise<ToolDecision[]> {
  const { isSubAgent, silent, saveConfig, streamCallbacks, hooks, sessionCtx } = options;
  const decisions: ToolDecision[] = [];
  const isDangerousMode = (config.defaultMode ?? '').toLowerCase() === 'dangerous';
  let browserAdaptationHint: Awaited<ReturnType<typeof loadBrowserRunCorpusAdaptationHint>> | null =
    null;
  if (config.browser.adaptation.enabled) {
    try {
      browserAdaptationHint = await loadBrowserRunCorpusAdaptationHint(
        sessionCtx.cwd,
        config.browser.adaptation
      );
    } catch (error) {
      if (process.env.OPTA_DEBUG) {
        console.error('Failed to load browser adaptation hint:', error);
      }
    }
  }

  const policyEngine = new PolicyEngine(mapPolicyConfig(config.policy), {
    cwd: sessionCtx.cwd,
  });

  // Cache the browser session scan result for the entire turn so we call the daemon
  // at most once regardless of how many browser tool calls are in this batch.
  let _cachedBrowserSessionScan: BrowserSessionScanResult | null = null;
  async function getActiveBrowserSessionsOnce(): Promise<BrowserSessionScanResult> {
    if (_cachedBrowserSessionScan === null) {
      _cachedBrowserSessionScan = await scanActiveBrowserSessions(config, sessionCtx.cwd);
    }
    return _cachedBrowserSessionScan;
  }

  for (const call of toolCalls) {
    const parsedArgs = safeParseJson<Record<string, unknown>>(call.args, { raw: call.args });
    let parsedArgsMutated = false;
    let requiresBrowserApproval = false;
    let browserSessionId: string | undefined;
    let browserPolicyDecision: ReturnType<typeof evaluateBrowserPolicyAction> | null = null;

    const logBrowserApprovalDecision = async (decision: 'approved' | 'denied'): Promise<void> => {
      if (!requiresBrowserApproval) return;
      try {
        await appendBrowserApprovalEvent({
          cwd: sessionCtx.cwd,
          tool: call.name,
          sessionId: browserSessionId,
          decision,
          risk: browserPolicyDecision?.risk,
          actionKey: browserPolicyDecision?.actionKey,
          targetHost: browserPolicyDecision?.targetHost,
          targetOrigin: browserPolicyDecision?.targetOrigin,
          policyReason: browserPolicyDecision?.reason,
          riskEvidence: browserPolicyDecision?.riskEvidence,
        });
      } catch (error) {
        if (process.env.OPTA_DEBUG) {
          console.error('Failed to append browser approval event:', error);
        }
      }
    };

    if (config.browser.enabled && call.name === 'run_command') {
      const command = parsedArgs['command'];
      if (isShellBrowserAutomationCommand(command)) {
        decisions.push({
          call,
          approved: false,
          denialReason: 'Denied shell browser automation command; use browser_* tools instead.',
        });
        if (!silent)
          console.log(
            chalk.dim(`  ✗ ${call.name} — use browser_* tools instead of shell browser automation`)
          );
        continue;
      }
    }

    if (isBrowserToolName(call.name)) {
      browserSessionId = extractBrowserSessionId(parsedArgs);
      let activeBrowserSessions: BrowserSessionScanResult['sessions'] = [];
      if (config.browser.enabled && call.name !== 'browser_open') {
        const scanResult = await getActiveBrowserSessionsOnce();
        if (scanResult.error) {
          decisions.push({
            call,
            approved: false,
            denialReason: `Browser runtime session scan failed: ${scanResult.error}`,
          });
          if (!silent) console.log(chalk.dim(`  ✗ ${call.name} — browser session scan failed`));
          continue;
        }
        activeBrowserSessions = scanResult.sessions;

        if (scanResult.sessionIds.length === 0 && !browserSessionId) {
          if (isSubAgent) {
            decisions.push({
              call,
              approved: false,
              denialReason: 'Permission denied (sub-agent cannot prompt browser spawn).',
            });
            continue;
          }

          const spawnMode = resolveBrowserSpawnMode(config);
          const spawnWsEndpoint = resolveBrowserAttachWsEndpoint(config, spawnMode);
          if (spawnMode === 'attach' && !spawnWsEndpoint) {
            decisions.push({
              call,
              approved: false,
              denialReason:
                'Cannot spawn Opta Browser attach session: browser.attach.wsEndpoint is not configured.',
            });
            if (!silent) {
              console.log(
                chalk.dim(`  ✗ ${call.name} — browser attach requires browser.attach.wsEndpoint`)
              );
            }
            continue;
          }

          const browserOpenPermission = resolvePermission('browser_open', config);
          if (browserOpenPermission === 'deny') {
            decisions.push({
              call,
              approved: false,
              denialReason:
                'Cannot spawn Opta Browser (browser_open permission is denied by config).',
            });
            if (!silent)
              console.log(chalk.dim(`  ✗ ${call.name} — browser_open denied by configuration`));
            continue;
          }

          const spawnPromptArgs: Record<string, unknown> = {
            mode: spawnMode,
            __opta_spawn_prompt: true,
            __opta_spawn_reason: 'No active Opta Browser sessions were found in the runtime scan.',
            __opta_spawn_trigger_tool: call.name,
            __opta_session_scan_count: 0,
          };
          if (spawnWsEndpoint) {
            spawnPromptArgs['ws_endpoint'] = spawnWsEndpoint;
          }

          if (streamCallbacks?.onPermissionRequest) {
            const spawnDecision = await streamCallbacks.onPermissionRequest(
              'browser_open',
              spawnPromptArgs
            );
            if (spawnDecision === 'deny') {
              decisions.push({
                call,
                approved: false,
                denialReason: 'User declined spawning an Opta Browser session.',
              });
              continue;
            }
            if (spawnDecision === 'always' && browserOpenPermission === 'ask') {
              await persistToolPermissionAllow('browser_open', config, saveConfig, silent);
            }
          } else {
            const spawnResponse = await promptToolApproval('browser_open', spawnPromptArgs);
            if (spawnResponse === 'deny') {
              decisions.push({
                call,
                approved: false,
                denialReason: 'User declined spawning an Opta Browser session.',
              });
              continue;
            }
            if (spawnResponse === 'always' && browserOpenPermission === 'ask') {
              await persistToolPermissionAllow('browser_open', config, saveConfig, silent);
            }
          }

          try {
            const daemon = await getBrowserRuntimeDaemon(config, sessionCtx.cwd);
            const openResult = await daemon.openSession({
              sessionId: browserSessionId,
              mode: spawnMode,
              wsEndpoint: spawnWsEndpoint,
            });
            if (!openResult.ok || !openResult.data) {
              const reason =
                openResult.error?.message ?? 'Browser runtime could not open a new session.';
              decisions.push({
                call,
                approved: false,
                denialReason: `Failed to spawn Opta Browser session: ${reason}`,
              });
              if (!silent)
                console.log(chalk.dim(`  ✗ ${call.name} — failed to spawn browser session`));
              continue;
            }

            browserSessionId = openResult.data.id;
            parsedArgs['session_id'] = browserSessionId;
            parsedArgsMutated = true;
            // Always require approval when a session was spawned — user must confirm the first action
            requiresBrowserApproval = true;
            if (!silent)
              console.log(chalk.dim(`  Spawned Opta Browser session: ${browserSessionId}`));
          } catch (error) {
            decisions.push({
              call,
              approved: false,
              denialReason: `Failed to spawn Opta Browser session: ${error instanceof Error ? error.message : String(error)}`,
            });
            if (!silent) console.log(chalk.dim(`  ✗ ${call.name} — browser spawn failed`));
            continue;
          }
        } else if (!browserSessionId) {
          browserSessionId = scanResult.sessionIds[0];
          if (browserSessionId) {
            parsedArgs['session_id'] = browserSessionId;
            parsedArgsMutated = true;
            // Require approval so the user confirms the action with the auto-assigned session
            requiresBrowserApproval = true;
          }
        }
      }

      if (browserSessionId && (call.name === 'browser_click' || call.name === 'browser_type')) {
        const hasExplicitUrl =
          typeof parsedArgs['url'] === 'string' && parsedArgs['url'].trim().length > 0;
        if (!hasExplicitUrl) {
          const activeSession = activeBrowserSessions.find(
            (session) => session.sessionId === browserSessionId
          );
          if (activeSession?.currentUrl) {
            parsedArgs['url'] = activeSession.currentUrl;
            parsedArgsMutated = true;
          }
        }
      }

      browserPolicyDecision = evaluateBrowserPolicyAction(resolveBrowserPolicyConfig(config), {
        toolName: call.name,
        args: parsedArgs,
        adaptationHint: browserAdaptationHint?.policy,
      });

      if (browserPolicyDecision.decision === 'deny') {
        try {
          await appendBrowserApprovalEvent({
            cwd: sessionCtx.cwd,
            tool: call.name,
            sessionId: browserSessionId,
            decision: 'denied',
            risk: browserPolicyDecision.risk,
            actionKey: browserPolicyDecision.actionKey,
            targetHost: browserPolicyDecision.targetHost,
            targetOrigin: browserPolicyDecision.targetOrigin,
            policyReason: browserPolicyDecision.reason,
            riskEvidence: browserPolicyDecision.riskEvidence,
          });
        } catch (error) {
          if (process.env.OPTA_DEBUG) {
            console.error('Failed to append browser deny event:', error);
          }
        }
        decisions.push({
          call,
          approved: false,
          denialReason: `Denied by browser policy: ${browserPolicyDecision.reason}`,
        });
        if (!silent)
          console.log(chalk.dim(`  \u2717 ${call.name} \u2014 denied by browser policy`));
        continue;
      }

      requiresBrowserApproval = requiresBrowserApproval || browserPolicyDecision.decision === 'gate';
    }

    const policyDecision = await policyEngine.decide({
      action: call.name,
      // Dangerous mode explicitly bypasses approval prompts.
      // Mark tool calls as non-autonomous so gate-all policy does not block unattended runs.
      autonomous: !isDangerousMode,
      actor: isSubAgent ? 'sub-agent' : 'agent',
      metadata: {
        toolCallId: call.id,
      },
    });

    if (policyDecision.decision === 'deny') {
      decisions.push({
        call,
        approved: false,
        denialReason: `Denied by policy: ${policyDecision.reason}`,
      });
      if (!silent) console.log(chalk.dim(`  \u2717 ${call.name} \u2014 denied by policy`));
      continue;
    }

    const requiresApproval = policyDecision.decision === 'gate' || requiresBrowserApproval;
    const permission = resolvePermission(call.name, config);
    let executionArgsJson = parsedArgsMutated ? JSON.stringify(parsedArgs) : call.args;

    if (permission === 'deny') {
      decisions.push({
        call,
        approved: false,
        denialReason: 'Permission denied by configuration.',
      });
      if (!silent) console.log(chalk.dim(`  \u2717 ${call.name} \u2014 denied`));
      continue;
    }

    if (permission === 'ask' || requiresApproval) {
      if (isSubAgent) {
        await logBrowserApprovalDecision('denied');
        decisions.push({
          call,
          approved: false,
          denialReason: 'Permission denied (sub-agent cannot prompt user).',
        });
        continue;
      }

      if (streamCallbacks?.onPermissionRequest) {
        const decision = await streamCallbacks.onPermissionRequest(call.name, parsedArgs);
        if (decision === 'always' && permission === 'ask') {
          await persistToolPermissionAllow(call.name, config, saveConfig, silent);
        } else if (decision === 'deny') {
          await logBrowserApprovalDecision('denied');
          decisions.push({ call, approved: false, denialReason: 'User declined this action.' });
          continue;
        }
        await logBrowserApprovalDecision('approved');
      } else {
        const response = await promptToolApproval(call.name, parsedArgs);
        if (response === 'always' && permission === 'ask') {
          await persistToolPermissionAllow(call.name, config, saveConfig, silent);
        } else if (response === 'deny') {
          await logBrowserApprovalDecision('denied');
          decisions.push({ call, approved: false, denialReason: 'User declined this action.' });
          continue;
        }
        await logBrowserApprovalDecision('approved');
      }

      if (requiresBrowserApproval) {
        executionArgsJson = JSON.stringify({ ...parsedArgs, __browser_approved: true });
      }
    }

    // Fire pre-tool hook (can cancel execution)
    const preResult = await fireToolPre(hooks, call.name, executionArgsJson, sessionCtx);
    if (preResult.cancelled) {
      decisions.push({
        call,
        approved: false,
        denialReason: `Tool blocked by hook: ${preResult.reason ?? 'no reason given'}`,
      });
      if (!silent) console.log(chalk.dim(`  \u2717 ${call.name} \u2014 blocked by hook`));
      continue;
    }

    decisions.push({ call, approved: true, executionArgsJson });
  }

  return decisions;
}

/**
 * agent-setup.ts — Client creation, system prompt, config.
 *
 * Extracted from agent.ts to isolate the OpenAI client lifecycle,
 * system prompt construction, and context compaction.
 */

import type OpenAI from 'openai';
import type { OptaConfig } from './config.js';
import { debug } from './debug.js';
import { COMPACTION_PROMPT } from './context.js';
import { buildAutonomyPromptBlock } from './autonomy.js';
import type { AgentMessage } from './agent.js';

interface ToolSchemaLike {
  function: {
    name: string;
  };
}

export interface CapabilityManifestRuntimeContext {
  activeToolSchemas?: ToolSchemaLike[];
  profile?: string;
  mode?: string;
}

const CAPABILITY_MARKER = '\n\nActive capabilities:\n';

function onOff(enabled: boolean): string {
  return enabled ? 'on' : 'off';
}

export function buildCapabilityManifest(
  config: OptaConfig,
  runtime: CapabilityManifestRuntimeContext = {}
): string {
  const toolNames = new Set(
    (runtime.activeToolSchemas ?? []).map((schema) => schema.function.name)
  );
  const mode = runtime.mode ?? config.defaultMode;
  const profile = runtime.profile ?? 'default';

  const hasWebTools = toolNames.has('web_search') || toolNames.has('web_fetch');
  const hasResearchTool =
    hasWebTools || Array.from(toolNames).some((name) => name.startsWith('research_'));
  const hasBrowserTool = Array.from(toolNames).some(
    (name) => name.startsWith('browser_') || name.includes('playwright')
  );
  const hasLearningTool = [
    'save_memory',
    'learning_log',
    'learning_summary',
    'learning_retrieve',
  ].some((name) => toolNames.has(name));
  const toolCount = runtime.activeToolSchemas?.length ?? 0;

  return [
    `- session: mode=${mode}, profile=${profile}, tools=${toolCount}`,
    `- research: ${onOff(config.research.enabled)} provider=${config.research.defaultProvider} tools=${hasResearchTool ? 'yes' : 'no'}`,
    `- browser: ${onOff(config.browser.enabled)} mode=${config.browser.mode} automation=${hasBrowserTool ? 'yes' : 'no'}`,
    `- learning: ${onOff(config.learning.enabled)} capture=${config.learning.captureLevel} tool=${hasLearningTool ? 'yes' : 'no'}`,
    `- policy: ${onOff(config.policy.enabled)} mode=${config.policy.mode} gate-all=${onOff(config.policy.gateAllAutonomy)} failure=${config.policy.failureMode}`,
  ].join('\n');
}

export function injectCapabilityManifest(prompt: string, manifest: string): string {
  const markerIndex = prompt.indexOf(CAPABILITY_MARKER);
  const basePrompt = markerIndex >= 0 ? prompt.slice(0, markerIndex).trimEnd() : prompt.trimEnd();

  return `${basePrompt}${CAPABILITY_MARKER}${manifest}`;
}

// --- Provider-Based Client ---

export async function getOrCreateClient(config: OptaConfig): Promise<OpenAI> {
  const { getProvider } = await import('../providers/manager.js');
  const provider = await getProvider(config);
  debug(`Using provider: ${provider.name}`);
  const client = (await provider.getClient()) as OpenAI & { __optaProviderName?: string };
  client.__optaProviderName = provider.name;
  return client;
}

/** Reset the cached client (useful for testing). */
