export type OptaConfig = z.infer<typeof OptaConfigSchema>;

export const DEFAULT_CONFIG: OptaConfig = OptaConfigSchema.parse({});

const LOAD_CONFIG_CACHE_TTL_MS = 5_000;

interface LoadConfigCacheEntry {
  key: string;
  expiresAt: number;
  value: OptaConfig;
}

let loadConfigCache: LoadConfigCacheEntry | null = null;

function cloneConfig(config: OptaConfig): OptaConfig {
  return typeof structuredClone === 'function'
    ? structuredClone(config)
    : (JSON.parse(JSON.stringify(config)) as OptaConfig);
}

function stableStringify(value: unknown): string {
  if (Array.isArray(value)) {
    return `[${value.map((item) => stableStringify(item)).join(',')}]`;
  }
  if (value && typeof value === 'object') {
    const entries = Object.entries(value as Record<string, unknown>)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([k, v]) => `${JSON.stringify(k)}:${stableStringify(v)}`);
    return `{${entries.join(',')}}`;
  }
  return JSON.stringify(value);
}

function buildLoadConfigCacheKey(overrides?: Record<string, unknown>): string {
  const envKey = [
    process.env['OPTA_HOST'] ?? '',
    process.env['OPTA_PORT'] ?? '',
    process.env['OPTA_ADMIN_KEY'] ?? '',
    process.env[ADMIN_KEYS_BY_HOST_ENV_VAR] ?? '',
    process.env['OPTA_API_KEY'] ?? '',
    process.env['OPTA_MODEL'] ?? '',
    process.env['OPTA_DISK_HEADROOM_MB'] ?? '',
  ].join('|');
  const overrideKey = stableStringify(overrides ?? {});
  return `${envKey}::${overrideKey}`;
}

function applyProcessEnvFromConfig(config: OptaConfig): void {
  // Make the resolved key visible to components instantiated after loadConfig()
  // without threading connection.apiKey through every call site.
  const apiKey = config.connection.apiKey?.trim();
  if (apiKey && !process.env['OPTA_API_KEY']) {
    process.env['OPTA_API_KEY'] = apiKey;
  }

  if (!process.env[ADMIN_KEYS_BY_HOST_ENV_VAR]) {
    const hostMap = config.connection.adminKeysByHost;
    if (hostMap && Object.keys(hostMap).length > 0) {
      process.env[ADMIN_KEYS_BY_HOST_ENV_VAR] = JSON.stringify(hostMap);
    }
  }
}

export function clearLoadConfigCache(): void {
  loadConfigCache = null;
}

/** Canonical permission defaults derived from the Zod schema. Single source of truth. */
export const DEFAULT_PERMISSIONS: Record<string, 'allow' | 'ask' | 'deny'> =
  DEFAULT_CONFIG.permissions;

// ---------------------------------------------------------------------------
// Part D: Zod error formatting
// ---------------------------------------------------------------------------

/**
 * Convert Zod validation issues into human-readable one-liners with fix suggestions.
 *
 * Maps common Zod error codes to plain-language descriptions and appends a
 * `Try: opta config set <path> <example>` hint where possible.
 */
export function formatZodErrors(error: z.ZodError): string[] {
  return error.issues.map((issue) => {
    const path = issue.path.join('.');
    let description: string;

    switch (issue.code) {
      case 'invalid_type':
        description = `Expected ${issue.expected} but got ${issue.received}`;
        break;
      case 'too_small': {
        const minIssue = issue as z.ZodTooSmallIssue;
        description = `Must be at least ${minIssue.minimum}`;
        break;
      }
      case 'too_big': {
        const maxIssue = issue as z.ZodTooBigIssue;
        description = `Must be at most ${maxIssue.maximum}`;
        break;
      }
      case 'invalid_enum_value': {
        const enumIssue = issue as z.ZodInvalidEnumValueIssue;
        description = `Must be one of: ${enumIssue.options.join(', ')}`;
        break;
      }
      default:
        description = issue.message;
    }

    // Build a helpful suggestion with the config path
    const suggestion = path
      ? `Try: opta config set ${path} <valid-value>`
      : 'Check your config file for syntax errors';

    return `Config warning: ${path || '(root)'} ${description}. ${suggestion}`;
  });
}

// ---------------------------------------------------------------------------
// Internal: strip broken keys from a raw config object
// ---------------------------------------------------------------------------

/**
 * Given a raw config object and a list of Zod issues, delete the top-level
 * keys that contain broken values so the schema can fill them with defaults.
 * Returns a shallow clone — the original object is not mutated.
 */
function stripBrokenKeys(
  raw: Record<string, unknown>,
  issues: z.ZodIssue[]
): Record<string, unknown> {
  const clone = { ...raw };
  for (const issue of issues) {
    const topKey = issue.path[0];
    if (topKey !== undefined && typeof topKey === 'string') {
      // For nested paths (e.g. connection.port), we delete the deepest
      // leaf we can reach so the rest of the sub-tree is preserved.
      deleteNestedKey(clone, issue.path as string[]);
    } else {
      // Root-level issue — nothing we can strip
    }
  }
  return clone;
}

/**
 * Delete a deeply-nested key described by `path` from `obj`.
 * If intermediate containers become empty objects after deletion they are
 * left in place (Zod will fill defaults).
 */
function deleteNestedKey(obj: Record<string, unknown>, path: (string | number)[]): void {
  if (path.length === 0) return;
  if (path.length === 1) {
    Reflect.deleteProperty(obj, path[0] as string);
    return;
  }

  const [head, ...rest] = path;
  const child = obj[head as string];
  if (child !== null && child !== undefined && typeof child === 'object' && !Array.isArray(child)) {
    deleteNestedKey(child as Record<string, unknown>, rest);
  } else {
    // Cannot traverse further — delete the whole branch
    Reflect.deleteProperty(obj, head as string);
  }
}

// ---------------------------------------------------------------------------
// Part A: loadConfig with safeParse + self-healing
// ---------------------------------------------------------------------------

export async function loadConfig(overrides?: Record<string, unknown>): Promise<OptaConfig> {
  const cacheKey = buildLoadConfigCacheKey(overrides);
  if (
    loadConfigCache &&
    loadConfigCache.key === cacheKey &&
    loadConfigCache.expiresAt > Date.now()
  ) {
    return cloneConfig(loadConfigCache.value);
  }

  const raw: Record<string, unknown> = {};

  // 1. Load user config (~/.config/opta/config.json)
  try {
    const store = await getConfigStore();
    Object.assign(raw, store.store);
  } catch {
    // conf not available or no saved config — use defaults
  }

  // 2. Load project config (.opta/config.json via cosmiconfig)
  try {
    const { cosmiconfig } = await import('cosmiconfig');
    const explorer = cosmiconfig('opta');
    const result = await explorer.search();
    if (result?.config) {
      Object.assign(raw, result.config);
    }
  } catch {
    // No project config found
  }

  // 3. Environment variable overrides
  const connectionPatch: Record<string, unknown> = {};
  if (process.env['OPTA_HOST']) connectionPatch['host'] = process.env['OPTA_HOST'];
  if (process.env['OPTA_PORT']) connectionPatch['port'] = parseInt(process.env['OPTA_PORT'], 10);
  if (process.env['OPTA_ADMIN_KEY']) connectionPatch['adminKey'] = process.env['OPTA_ADMIN_KEY'];
  if (process.env[ADMIN_KEYS_BY_HOST_ENV_VAR]) {
    const parsedAdminKeysByHost = parseAdminKeysByHost(process.env[ADMIN_KEYS_BY_HOST_ENV_VAR]);
    if (parsedAdminKeysByHost) {
      connectionPatch['adminKeysByHost'] = parsedAdminKeysByHost;
    }
  }
  if (process.env['OPTA_API_KEY']) connectionPatch['apiKey'] = process.env['OPTA_API_KEY'];
  if (Object.keys(connectionPatch).length > 0) {
    raw['connection'] = {
      ...((raw as Record<string, Record<string, unknown>>)['connection'] ?? {}),
      ...connectionPatch,
    };
  }
  const envModel = normalizeConfiguredModelId(process.env['OPTA_MODEL']);
  if (envModel) {
    raw.model = {
      ...((raw as Record<string, Record<string, unknown>>).model ?? {}),
      default: envModel,
    };
  }
  if (process.env['OPTA_DISK_HEADROOM_MB']) {
    const parsed = Number.parseInt(process.env['OPTA_DISK_HEADROOM_MB'], 10);
    if (Number.isFinite(parsed)) {
      raw.safety = {
        ...((raw as Record<string, Record<string, unknown>>).safety ?? {}),
        diskHeadroomMb: parsed,
      };
    }
  }

  // 4. CLI flag overrides
  if (overrides) {
    Object.assign(raw, overrides);
  }

  // 5. Validate with safeParse — self-heal on failure
  const result = OptaConfigSchema.safeParse(raw);

  if (result.success) {
    const normalized = {
      ...result.data,
      model: {
        ...result.data.model,
        default: normalizeConfiguredModelId(result.data.model.default),
      },
    };
    applyProcessEnvFromConfig(normalized);
    loadConfigCache = {
      key: cacheKey,
      expiresAt: Date.now() + LOAD_CONFIG_CACHE_TTL_MS,
      value: normalized,
    };
    return cloneConfig(normalized);
  }

  // Validation failed — show human-readable warnings
  const hints = formatZodErrors(result.error);
  for (const hint of hints) {
    console.error(hint);
  }

  // Attempt self-healing: strip broken keys and re-parse with defaults
  const healed = stripBrokenKeys(raw, result.error.issues);
  const retryResult = OptaConfigSchema.safeParse(healed);

  if (retryResult.success) {
    const issueCount = result.error.issues.length;
    console.error(
      `Auto-healed ${issueCount} config issue${issueCount === 1 ? '' : 's'}. Run /quickfix for details.`
    );
    const normalized = {
      ...retryResult.data,
      model: {
        ...retryResult.data.model,
        default: normalizeConfiguredModelId(retryResult.data.model.default),
      },
    };
    applyProcessEnvFromConfig(normalized);
    loadConfigCache = {
      key: cacheKey,
      expiresAt: Date.now() + LOAD_CONFIG_CACHE_TTL_MS,
      value: normalized,
    };
    return cloneConfig(normalized);
  }

  // Still broken after stripping — fatal error
  throw new Error(
    'Config is unparseable even after removing broken fields. ' +
      'Run "opta config reset" to restore defaults.\n' +
      formatZodErrors(retryResult.error).join('\n')
  );
}

// ---------------------------------------------------------------------------
// Part B: healConfig — self-healing for malformed JSON
// ---------------------------------------------------------------------------

export interface ConfigIssue {
  path: string;
  message: string;
  suggestion: string;
  autoFixed: boolean;
}

/**
 * Inspect the persisted user config, validate it against the schema, and
 * auto-fix any fields that can be reset to their defaults.
 *
 * Returns a list of every issue found, each annotated with whether it was
 * automatically repaired.
 */
export async function healConfig(): Promise<ConfigIssue[]> {
  clearLoadConfigCache();
  const store = await getConfigStore();
  const raw = { ...store.store } as Record<string, unknown>;

  const result = OptaConfigSchema.safeParse(raw);

  if (result.success) {
    return []; // Config is healthy
  }

  const issues: ConfigIssue[] = [];

  for (const zodIssue of result.error.issues) {
    const path = zodIssue.path.join('.');
    let message: string;

    switch (zodIssue.code) {
      case 'invalid_type':
        message = `Expected ${zodIssue.expected} but got ${zodIssue.received}`;
        break;
      case 'too_small': {
        const minIssue = zodIssue as z.ZodTooSmallIssue;
        message = `Must be at least ${minIssue.minimum}`;
        break;
      }
      case 'too_big': {
        const maxIssue = zodIssue as z.ZodTooBigIssue;
        message = `Must be at most ${maxIssue.maximum}`;
        break;
      }
      case 'invalid_enum_value': {
        const enumIssue = zodIssue as z.ZodInvalidEnumValueIssue;
        message = `Must be one of: ${enumIssue.options.join(', ')}`;
        break;
      }
      default:
        message = zodIssue.message;
    }

    const suggestion = path
      ? `opta config set ${path} <valid-value>`
      : 'Run "opta config reset" to restore all defaults';

    // Attempt auto-fix: delete the broken key and see if the schema passes
    const testRaw = { ...raw };
    deleteNestedKey(testRaw, zodIssue.path as string[]);
    const testResult = OptaConfigSchema.safeParse(testRaw);

    const canAutoFix =
      testResult.success || !testResult.error.issues.some((i) => i.path.join('.') === path);

    if (canAutoFix) {
      // Apply the fix to the persisted store
      const topKey = zodIssue.path[0];
      if (topKey !== undefined && typeof topKey === 'string') {
        // Delete the broken key from the conf store
        store.delete(topKey);
      }
      // Mutate raw for subsequent iterations
      deleteNestedKey(raw, zodIssue.path as string[]);
    }

    issues.push({
      path: path || '(root)',
      message,
      suggestion,
      autoFixed: canAutoFix,
    });
  }

  return issues;
}


function getDefaultValueAtPath(path: string): unknown {
  const segments = path.split('.').filter(Boolean);
  let cursor: unknown = DEFAULT_CONFIG as unknown;
  for (const segment of segments) {
    if (!cursor || typeof cursor !== 'object' || Array.isArray(cursor)) return undefined;
    cursor = (cursor as Record<string, unknown>)[segment];
  }
  return cursor;
}

function coerceConfigValue(path: string, rawValue: unknown): unknown {
  if (typeof rawValue !== 'string') return rawValue;

  if (path === 'connection.fallbackHosts') {
    const trimmed = rawValue.trim();
    if (!trimmed) return [];
    if (trimmed.startsWith('[')) {
      try {
        const parsed: unknown = JSON.parse(trimmed);
        if (Array.isArray(parsed)) {
          return parsed.map((item) => String(item).trim()).filter((item) => item.length > 0);
        }
      } catch {
        return rawValue;
      }
    }
    return trimmed
      .split(',')
      .map((item) => item.trim())
      .filter((item) => item.length > 0);
  }

  if (path === 'connection.adminKeysByHost') {
    const parsed = parseAdminKeysByHost(rawValue);
    return parsed ?? rawValue;
  }

  const defaultValue = getDefaultValueAtPath(path);
  if (typeof defaultValue === 'boolean') {
    if (rawValue === 'true') return true;
    if (rawValue === 'false') return false;
    return rawValue;
  }

  if (typeof defaultValue === 'number') {
    const parsed = Number(rawValue);
    return Number.isFinite(parsed) ? parsed : rawValue;
  }

  return rawValue;
}

export async function saveConfig(updates: Record<string, unknown>): Promise<void> {
  clearLoadConfigCache();
  const store = await getConfigStore();

  for (const [key, rawValue] of Object.entries(updates)) {
    let value = coerceConfigValue(key, rawValue);
    if (key === 'model.default' && typeof rawValue === 'string') {
      value = normalizeConfiguredModelId(rawValue);
    } else if (
      key === 'model' &&
      rawValue &&
      typeof rawValue === 'object' &&
      !Array.isArray(rawValue)
    ) {
      const modelUpdate = { ...(rawValue as Record<string, unknown>) };
      if (typeof modelUpdate['default'] === 'string') {
        modelUpdate['default'] = normalizeConfiguredModelId(modelUpdate['default']);
      }
      value = modelUpdate;
    }
    store.set(key, value);
  }
}

let _configStore: import('conf').default | null = null;

export async function getConfigStore(): Promise<import('conf').default> {
  if (!_configStore) {
    const { default: Conf } = await import('conf');
    _configStore = new Conf({ projectName: 'opta' });
  }
  return _configStore;
}

const PORT_MIN = 1;
const PORT_MAX = 65_535;

export interface DeviceTarget {
  host: string;
  port?: number;
}

function parsePort(raw: string): number {
  const port = Number.parseInt(raw, 10);
  if (!Number.isFinite(port) || port < PORT_MIN || port > PORT_MAX) {
    throw new Error(`Invalid --device port "${raw}" (expected ${PORT_MIN}-${PORT_MAX})`);
  }
  return port;
}

function parseUrlLike(value: string): DeviceTarget | null {
  if (!value.includes('://')) return null;
  let parsed: URL;
  try {
    parsed = new URL(value);
  } catch {
    throw new Error(`Invalid --device value "${value}"`);
  }
  const host = parsed.hostname.trim();
  if (!host) throw new Error(`Invalid --device value "${value}"`);
  if (parsed.pathname && parsed.pathname !== '/') {
    throw new Error('Invalid --device value (paths are not supported)');
  }
  if (parsed.search || parsed.hash) {
    throw new Error('Invalid --device value (query/hash are not supported)');
  }
  return parsed.port ? { host, port: parsePort(parsed.port) } : { host };
}

export function parseDeviceTarget(raw: string): DeviceTarget {
  const value = raw.trim();
  if (!value) {
    throw new Error('Invalid --device value (cannot be empty)');
  }

  const urlLike = parseUrlLike(value);
  if (urlLike) return urlLike;

  const ipv6Bracket = value.match(/^\[([^[\]]+)\](?::(\d+))?$/);
  if (ipv6Bracket) {
    const host = ipv6Bracket[1]!.trim();
    if (!host) throw new Error(`Invalid --device value "${raw}"`);
    return ipv6Bracket[2] ? { host, port: parsePort(ipv6Bracket[2]) } : { host };
  }

  const hostPort = value.match(/^([^:\s]+):(\d+)$/);
  if (hostPort) {
    const host = hostPort[1]!.trim();
    if (!host) throw new Error(`Invalid --device value "${raw}"`);
    return { host, port: parsePort(hostPort[2]!) };
  }

  if (/\s/.test(value)) {
    throw new Error(`Invalid --device value "${raw}"`);
  }
  return { host: value };
}

/**
 * Apply a one-shot device target for this CLI process.
 * loadConfig() will consume these env vars as connection overrides.
 */
export function applyDeviceTargetEnv(raw: string): DeviceTarget {
  const target = parseDeviceTarget(raw);
  process.env['OPTA_HOST'] = target.host;
  if (target.port !== undefined) {
    process.env['OPTA_PORT'] = String(target.port);
  } else {
    delete process.env['OPTA_PORT'];
  }
  return target;
}

import { readFile } from 'node:fs/promises';
import { resolve, relative } from 'node:path';
import chalk from 'chalk';

export interface FileRef {
  original: string;  // @src/core/agent.ts
  path: string;      // resolved absolute path
  content: string;   // file contents
  lines: number;     // line count
}

export interface LineRange {
  path: string;
  startLine: number | null;
  endLine: number | null;
}

export function parseLineRange(ref: string): LineRange {
  const match = ref.match(/^(.+?):(\d+)(?:-(\d+))?$/);
  if (!match) return { path: ref, startLine: null, endLine: null };
  return {
    path: match[1]!,
    startLine: parseInt(match[2]!, 10),
    endLine: match[3] ? parseInt(match[3], 10) : parseInt(match[2]!, 10),
  };
}

export function extractFileRefParts(ref: string): { original: string; path: string; startLine: number | null; endLine: number | null } {
  const withoutAt = ref.startsWith('@') ? ref.slice(1) : ref;
  const range = parseLineRange(withoutAt);
  return { original: ref, ...range };
}

export async function resolveFileRefs(message: string): Promise<{ cleanMessage: string; refs: FileRef[] }> {
  // Match @path patterns (not @mentions which start with uppercase or are emails)
  const pattern = /@((?:\.{1,2}\/|[a-z_])[^\s,;:!?'")\]}>]+)/g;
  const matches = [...message.matchAll(pattern)];
  const cleanMessage = message;
  const resolvedRefs = await Promise.all(
    matches.map(async (match): Promise<FileRef | null> => {
      const refPath = match[1]!;
      const fullPath = resolve(process.cwd(), refPath);

      try {
        const content = await readFile(fullPath, 'utf-8');
        const lines = content.split('\n').length;
        return {
          original: match[0],
          path: fullPath,
          content,
          lines,
        };
      } catch {
        // File doesn't exist — leave the @reference as-is
        return null;
      }
    }),
  );

  const refs = resolvedRefs.filter((ref): ref is FileRef => ref !== null);
  for (const ref of refs) {
    console.log(chalk.dim(`  attached: ${relative(process.cwd(), ref.path)} (${ref.lines} lines)`));
  }

  return { cleanMessage, refs };
}

export function buildContextWithRefs(message: string, refs: FileRef[]): string {
  if (refs.length === 0) return message;

  let context = '';
  for (const ref of refs) {
    context += `\n\n<file path="${ref.path}">\n${ref.content}\n</file>\n`;
  }

  return message + context;
}

// --- Image Reference Support ---

const IMAGE_EXTENSIONS = new Set(['png', 'jpg', 'jpeg', 'gif', 'webp']);

export interface ImageRef {
  original: string;  // @screenshot.png
  path: string;      // resolved absolute path
  base64: string;    // base64-encoded content
  mimeType: string;  // image/png, image/jpeg, etc.
  name: string;      // filename
}

function getImageMimeType(ext: string): string {
  const mimes: Record<string, string> = {
    png: 'image/png',
    jpg: 'image/jpeg',
    jpeg: 'image/jpeg',
    gif: 'image/gif',
    webp: 'image/webp',
  };
  return mimes[ext.toLowerCase()] ?? 'application/octet-stream';
}

/**
 * Check if a path refers to an image file (by extension).
 */
export function isImagePath(path: string): boolean {
  const ext = path.split('.').pop()?.toLowerCase() ?? '';
  return IMAGE_EXTENSIONS.has(ext);
}

/**
 * Resolve @image references in a message — reads image files as base64.
 *
 * Returns the clean message (with @image refs removed) and an array of
 * ImageRef objects containing the base64 data.
 */
export async function resolveImageRefs(message: string): Promise<{ cleanMessage: string; images: ImageRef[] }> {
  const pattern = /@((?:\.{1,2}\/|[a-z_])[^\s,;:!?'")\]}>]+)/g;
  const matches = [...message.matchAll(pattern)];
  let cleanMessage = message;
  const resolvedImages = await Promise.all(
    matches.map(async (match, idx): Promise<{ index: number; image: ImageRef; bytes: number } | null> => {
      const refPath = match[1]!;
      if (!isImagePath(refPath)) return null;

      const fullPath = resolve(process.cwd(), refPath);
      const ext = refPath.split('.').pop()?.toLowerCase() ?? '';

      try {
        const data = await readFile(fullPath);
        const base64 = data.toString('base64');
        const mimeType = getImageMimeType(ext);
        const name = refPath.split('/').pop() ?? refPath;

        return {
          index: idx,
          image: {
            original: match[0],
            path: fullPath,
            base64,
            mimeType,
            name,
          },
          bytes: data.length,
        };
      } catch {
        // File doesn't exist — leave the @reference as-is
        return null;
      }
    }),
  );

  const orderedImages = resolvedImages
    .filter((entry): entry is { index: number; image: ImageRef; bytes: number } => entry !== null)
    .sort((a, b) => a.index - b.index);
  const images = orderedImages.map((entry) => entry.image);

  for (const entry of orderedImages) {
    cleanMessage = cleanMessage.replace(entry.image.original, '').trim();
    console.log(
      chalk.dim(
        `  attached image: ${relative(process.cwd(), entry.image.path)} (${(entry.bytes / 1024).toFixed(1)} KB)`,
      ),
    );
  }

  return { cleanMessage, images };
}

import { nanoid } from 'nanoid';
import { join } from 'node:path';
import { mkdir, writeFile } from 'node:fs/promises';
import type { OptaConfig } from './config.js';
import type { SubAgentTask, SubAgentResult, SubAgentContext } from './subagent.js';
import type { ToolRegistry } from '../mcp/registry.js';
import type { SubAgentProgressEvent } from './subagent-events.js';

interface DelegationPlan {
  plan: string;
  subtasks: Array<{
    task: string;
    scope?: string;
    depends_on?: number;
  }>;
}

interface DelegationOptions {
  onAgentProgress?: (event: SubAgentProgressEvent) => void;
  onAgentSpawn?: (id: string, label: string, dependsOn?: number) => void;
  onAgentDone?: (agentId: string, result: string) => void;
}

type SpawnFn = (
  task: SubAgentTask,
  config: OptaConfig,
  client: import('openai').default,
  registry: ToolRegistry,
  parentContext?: SubAgentContext
) => Promise<SubAgentResult>;

const MAX_SUBTASKS = 5;

/**
 * Build execution waves from subtask dependencies (topological sort).
 *
 * Each wave contains indices of subtasks whose dependencies are all in
 * earlier waves. Subtasks within a wave can execute in parallel.
 */
function buildWaves(subtasks: DelegationPlan['subtasks']): number[][] {
  const n = subtasks.length;
  const assigned = new Set<number>();
  const waves: number[][] = [];

  // Safety: cap iterations at n to prevent infinite loops on bad input
  for (let iter = 0; iter < n && assigned.size < n; iter++) {
    const wave: number[] = [];
    for (let i = 0; i < n; i++) {
      if (assigned.has(i)) continue;

      const dep = subtasks[i]!.depends_on;
      // No dependency, or dependency already completed in a prior wave
      if (dep === undefined || dep < 0 || dep >= n || assigned.has(dep)) {
        wave.push(i);
      }
    }

    if (wave.length === 0) {
      // Remaining tasks have circular or unresolvable dependencies — force them
      for (let i = 0; i < n; i++) {
        if (!assigned.has(i)) wave.push(i);
      }
    }

    for (const idx of wave) assigned.add(idx);
    waves.push(wave);
  }

  return waves;
}

export async function executeDelegation(
  plan: DelegationPlan,
  config: OptaConfig,
  client: import('openai').default,
  registry: ToolRegistry,
  spawnFn: SpawnFn,
  delegationOptions?: DelegationOptions,
): Promise<string> {
  if (plan.subtasks.length > MAX_SUBTASKS) {
    throw new Error(`Maximum ${MAX_SUBTASKS} subtasks allowed per delegation.`);
  }

  if (plan.subtasks.length === 0) {
    return `Delegation: ${plan.plan}\n\nNo subtasks to execute.`;
  }

  const maxConcurrent = config.subAgent?.maxConcurrent ?? 3;
  const results: (SubAgentResult | null)[] = new Array(plan.subtasks.length).fill(null);
  const lines: string[] = [];
  lines.push(`Delegation: ${plan.plan}`);
  lines.push(`Subtasks: ${plan.subtasks.length}`);
  lines.push('');

  // Build execution waves from dependency graph
  const waves = buildWaves(plan.subtasks);
  let aborted = false;

  for (const wave of waves) {
    if (aborted) break;

    // Execute all subtasks in this wave concurrently (bounded by maxConcurrent)
    const wavePromises = wave.map(async (i) => {
      const subtask = plan.subtasks[i]!;

      // Build description, injecting dependency results
      let description = subtask.task;
      if (subtask.depends_on !== undefined) {
        if (subtask.depends_on < 0 || subtask.depends_on >= plan.subtasks.length) {
          lines.push(`Warning: subtask ${i + 1} has invalid depends_on=${subtask.depends_on} (ignored).`);
        } else {
          const depResult = results[subtask.depends_on];
          if (depResult) {
            // Write handoff artifact to prevent context bloat
            const handoffDir = join(process.cwd(), '.opta', 'handoffs');
            const handoffFile = join(handoffDir, `task_${subtask.depends_on}_result.md`);
            try {
              await mkdir(handoffDir, { recursive: true });
              await writeFile(handoffFile, depResult.response, 'utf8');

              if (depResult.status === 'budget_exceeded' || depResult.status === 'timeout') {
                description = `${subtask.task}\n\nContext from previous subtask (${depResult.status} — results may be incomplete) is saved to:\n${handoffFile}\n\nYou must read this file to understand the prior context.`;
              } else {
                description = `${subtask.task}\n\nContext from previous subtask is saved to:\n${handoffFile}\n\nYou must read this file to understand the prior context.`;
              }
            } catch {
              // Fallback to inline if filesystem fails
              if (depResult.status === 'budget_exceeded' || depResult.status === 'timeout') {
                description = `${subtask.task}\n\nContext from previous subtask (${depResult.status} — results may be incomplete):\n${depResult.response}`;
              } else {
                description = `${subtask.task}\n\nContext from previous subtask:\n${depResult.response}`;
              }
            }
          }
        }
      }

      const agentTask: SubAgentTask = {
        id: nanoid(8),
        description,
        scope: subtask.scope,
        onProgress: delegationOptions?.onAgentProgress
          ? (event) => delegationOptions.onAgentProgress!(event)
          : undefined,
      };

      delegationOptions?.onAgentSpawn?.(
        agentTask.id,
        subtask.task.slice(0, 40),
        subtask.depends_on,
      );

      const result = await spawnFn(agentTask, config, client, registry);
      delegationOptions?.onAgentDone?.(agentTask.id, result.response);
      results[i] = result;
      return { index: i, result };
    });

    // Bounded concurrency: process wave in chunks of maxConcurrent
    for (let start = 0; start < wavePromises.length; start += maxConcurrent) {
      const chunk = wavePromises.slice(start, start + maxConcurrent);
      const settled = await Promise.allSettled(chunk);

      for (const outcome of settled) {
        if (outcome.status === 'fulfilled') {
          const { index, result } = outcome.value;
          const subtask = plan.subtasks[index]!;
          lines.push(`--- Subtask ${index + 1}: ${subtask.task} ---`);
          lines.push(`Status: ${result.status}`);
          lines.push(result.response);
          lines.push('');

          if (result.status === 'error') {
            lines.push(`Delegation stopped: subtask ${index + 1} failed with error.`);
            aborted = true;
          }
        } else {
          lines.push(`--- Subtask failed: ${outcome.reason} ---`);
          lines.push('');
          aborted = true;
        }
      }

      if (aborted) break;
    }
  }

  const completed = results.filter(r => r?.status === 'completed');
  const totalToolCalls = results.reduce((sum, r) => sum + (r?.toolCallCount ?? 0), 0);
  const totalDuration = results.reduce((sum, r) => sum + (r?.durationMs ?? 0), 0);

  lines.push('--- Delegation Summary ---');
  lines.push(`Completed: ${completed.length}/${plan.subtasks.length}`);
  lines.push(`Total tool calls: ${totalToolCalls}`);
  lines.push(`Total duration: ${(totalDuration / 1000).toFixed(1)}s`);

  return lines.join('\n');
}

import { mkdir, writeFile } from 'node:fs/promises';
import { join } from 'node:path';
import chalk from 'chalk';
import { confirm, input } from '@inquirer/prompts';
import { OptaConfig } from './config.js';
import { getOrCreateClient } from './agent-setup.js';
import { ensureModel } from './errors.js';
import { captureLearningEvent } from '../learning/hooks.js';
import type { AgentMessage } from './agent.js';
import { createSpinner } from '../ui/spinner.js';

/**
 * Analyzes the completed run messages to determine what went well, what struggled,
 * and what could be improved.
 */
async function analyzeRun(
    client: any,
    model: string,
    messages: AgentMessage[],
    objective: string
): Promise<{ summary: string; improvements: string[]; keyPhases: string[] }> {
    // We only care about the assistant and tool interactions
    const trace = messages
        .filter(m => m.role !== 'system')
        .map(m => {
            if (m.role === 'tool') return `[Tool Result]`;
            if (m.role === 'assistant' && m.tool_calls) {
                return `[Assistant Called Tools: ${m.tool_calls.map(tc => tc.function.name).join(', ')}]`;
            }
            return `[Assistant Output]`;
        })
        .join('\n');

    const prompt = `
You are the Opta CEO Post-Flight Analyst.
Review the following trace of an autonomous execution for the objective: "${objective}"

Trace:
${trace}

Provide a JSON object analyzing the run (NO markdown formatting, just raw JSON):
{
  "summary": "1 sentence describing how the run went overall.",
  "improvements": ["1-2 things the agent could have done faster or better"],
  "keyPhases": ["A short name for the main phase of the work done"]
}
`;

    const response = await client.chat.completions.create({
        model,
        messages: [{ role: 'user', content: prompt }],
        temperature: 0.1,
    });

    const content = response.choices[0]?.message?.content || '{}';
    try {
        const cleanContent = content.replace(/```json\n?|\n?```/g, '').trim();
        return JSON.parse(cleanContent);
    } catch {
        return { summary: "Run completed successfully.", improvements: ["Optimize tool usage sequence"], keyPhases: ["Execution"] };
    }
}

async function saveRunLog(objective: string, messages: AgentMessage[]): Promise<string> {
    const logDir = join(process.cwd(), '.opta', 'ceo-runs');
    await mkdir(logDir, { recursive: true });

    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const filename = `run-${timestamp}.md`;
    const filepath = join(logDir, filename);

    const lines = [`# CEO Run Log: ${new Date().toISOString()}`, `**Objective:** ${objective}`, ''];

    for (const m of messages) {
        if (m.role === 'system') continue;
        lines.push(`## ${m.role}`);
        if (typeof m.content === 'string' && m.content.trim()) {
            lines.push(m.content);
        }
        if (m.tool_calls && m.tool_calls.length > 0) {
            lines.push('**Tools Used:**');
            for (const tc of m.tool_calls) {
                lines.push(`- \`${tc.function.name}\``);
            }
        }
        lines.push('');
    }

    await writeFile(filepath, lines.join('\n'), 'utf-8');
    return filepath;
}

export async function runPostFlightReview(
    config: OptaConfig,
    messages: AgentMessage[],
    objective: string
): Promise<void> {
    console.log(chalk.blue.bold('\n🛬 CEO Post-Flight Review\n'));

    // 1. Generate local run log
    const logPath = await saveRunLog(objective, messages);
    console.log(chalk.dim(`  Saved Run Log to: ${logPath}\n`));

    const spinner = await createSpinner();
    spinner.start('Analyzing execution efficiency...');

    const client = await getOrCreateClient(config);
    const model = config.model.default;
    ensureModel(model);

    // 2. Self analysis
    const analysis = await analyzeRun(client, model, messages, objective);
    spinner.stop();

    console.log(chalk.cyan.bold('CEO Self-Analysis:'));
    console.log(`  • ${analysis.summary}`);
    for (const imp of analysis.improvements) {
        console.log(`  • ${chalk.yellow('Iterate:')} ${imp}`);
    }
    console.log('');

    // 3. Interactive prompt
    const review = await confirm({ message: 'Would you like to provide feedback to improve future CEO behavior?', default: true });
    if (!review) return;

    const feedback = await input({ message: chalk.dim('? ') + 'What did the CEO do well, or what should it do differently next time? ' });

    if (feedback.trim()) {
        // 4. Push to Learning Ledger
        spinner.start('Ingesting feedback to Learning Ledger...');
        await captureLearningEvent(config, {
            kind: 'reflection',
            topic: `Feedback on CEO Run: ${objective.substring(0, 40)}...`,
            content: `User feedback: ${feedback}\n\nAI Identified Improvements: ${analysis.improvements.join(', ')}`,
            tags: ['ceo', 'feedback'],
            verified: true
        });
        spinner.stop();
        console.log(chalk.green('✓') + ' Feedback ingested. The CEO will adapt in future runs.');
    }

    console.log(chalk.blue.bold('\nMission Complete.'));
}

import chalk from 'chalk';
import { input, confirm, select } from '@inquirer/prompts';
import { createSpinner } from '../ui/spinner.js';
import { OptaConfig } from './config.js';
import { getOrCreateClient } from './agent-setup.js';
import { ensureModel } from './errors.js';

export interface PreFlightResult {
    proceed: boolean;
    refinedObjective: string;
}

/**
 * Executes a transient LLM call to research the objective and return a structured JSON plan.
 */
async function analyzeObjective(
    client: any,
    model: string,
    objective: string
): Promise<{
    questions: string[];
    suggestedApproaches: { name: string; value: string; description: string }[];
    estimatedSteps: number;
    dependencies: string[];
}> {
    const prompt = `
You are Opta CEO Mode's Pre-Flight Architect.
The user wants to do the following task autonomously:
"${objective}"

Analyze this request and output a strictly valid JSON object (no markdown formatting, just the raw JSON) with the following structure:
{
  "questions": ["1-3 clarifying questions to ask the user, focusing on credentials, specific services (favor free/simple options), or tricky parameters"],
  "suggestedApproaches": [
    { "name": "Approach Name", "value": "internal_slug", "description": "Brief description of this approach" }
  ],
  "estimatedSteps": 10, // A rough integer estimate of how many tool actions this will take
  "dependencies": ["List of API keys, CLIs, or npm packages that will probably need to be installed/configured"]
}
`;

    const response = await client.chat.completions.create({
        model,
        messages: [
            { role: 'system', content: 'You are a helpful JSON-only architect.' },
            { role: 'user', content: prompt }
        ],
        temperature: 0.1,
    });

    const content = response.choices[0]?.message?.content || '{}';

    try {
        // Strip markdown JSON blocks if the model wrapped it
        const cleanContent = content.replace(/```json\n?|\n?```/g, '').trim();
        return JSON.parse(cleanContent);
    } catch {
        // Fallback if parsing fails
        return {
            questions: ["Are there any specific service boundaries or free-tier constraints I should know about?"],
            suggestedApproaches: [{ name: "Standard Autonomous Execution", value: "standard", description: "Use default tools to solve the request" }],
            estimatedSteps: 15,
            dependencies: []
        };
    }
}

export async function runPreFlightOrchestration(
    config: OptaConfig,
    objective: string
): Promise<PreFlightResult> {
    console.log(chalk.blue.bold('\n✈️  CEO Pre-Flight Checks Initiated\n'));
    const spinner = await createSpinner();

    spinner.start('Analyzing request for optimal approach & dependencies...');

    const client = await getOrCreateClient(config);
    const model = config.model.default;
    ensureModel(model);

    const analysis = await analyzeObjective(client, model, objective);
    spinner.stop();

    console.log(chalk.green('✓') + ' Analysis complete.\n');

    // --- Phase 1: Research & Approach Selection ---
    let refinedObjective = objective;

    if (analysis.questions.length > 0) {
        console.log(chalk.yellow.bold('Clarification Required:'));
        for (const q of analysis.questions) {
            const answer = await input({ message: chalk.dim('? ') + q });
            if (answer.trim()) {
                refinedObjective += `\n[Context: ${q} -> ${answer}]`;
            }
        }
        console.log('');
    }

    if (analysis.suggestedApproaches.length > 1) {
        const approach = await select({
            message: 'Select the primary approach for this autonomous run:',
            choices: analysis.suggestedApproaches
        });
        refinedObjective += `\n[Selected Approach: ${approach}]`;
        console.log('');
    }

    // --- Phase 2: Dependency & Credential Management ---
    if (analysis.dependencies.length > 0) {
        console.log(chalk.cyan.bold('Detected Dependencies / Prerequisites:'));
        for (const dep of analysis.dependencies) {
            console.log(`  • ${dep}`);
        }
        console.log(chalk.dim('\nCEO Mode will proactively attempt to handle/install these during execution where possible.'));

        const hasKeys = await confirm({ message: 'Do you have all required API keys/credentials ready in your environment?', default: true });
        if (!hasKeys) {
            console.log(chalk.yellow('Please export required keys into your terminal, or provide them when prompted by the CEO agent.\n'));
        } else {
            console.log('');
        }
    }

    // --- Phase 3: Final Outline & ETA ---
    const MinsPerStep = 0.8; // Rough estimate of 45-60s per complex tool thought/execution
    const estMins = Math.max(2, Math.ceil(analysis.estimatedSteps * MinsPerStep));

    console.log(chalk.magenta.bold('Autonomous Run Blueprint:'));
    console.log(`  • Estimated steps: ~${analysis.estimatedSteps}`);
    console.log(`  • Estimated TTL:   ~${estMins} minutes\n`);

    const proceed = await confirm({ message: chalk.bold('Ready for CEO Mode to take over?'), default: true });

    return {
        proceed,
        // Inject our distilled context into the final objective prompt
        refinedObjective: proceed ? refinedObjective : objective
    };
}

import type { OptaConfig } from './config.js';
import { errorMessage } from '../utils/errors.js';
import { estimateMessageTokens } from '../utils/tokens.js';
import { detectPhaseFromTool, type SubAgentPhase, type SubAgentProgressEvent } from './subagent-events.js';

// --- Type Definitions ---

export interface SubAgentBudget {
  maxToolCalls: number;
  maxTokens: number;
  timeoutMs: number;
}

export interface SubAgentTask {
  id: string;
  description: string;
  scope?: string;
  budget?: Partial<SubAgentBudget>;
  tools?: string[];
  mode?: string;
  onProgress?: (event: SubAgentProgressEvent) => void;
}

export interface SubAgentResult {
  taskId: string;
  status: 'completed' | 'budget_exceeded' | 'timeout' | 'cancelled' | 'error';
  response: string;
  toolCallCount: number;
  tokenEstimate: number;
  filesRead: string[];
  filesModified: string[];
  durationMs: number;
}

export interface SubAgentContext {
  parentSessionId: string;
  depth: number;
  budget: SubAgentBudget;
  parentCwd: string;
}

// --- Task 1: Budget Validation & Defaults ---

export function resolveBudget(
  overrides: Partial<SubAgentBudget>,
  config: OptaConfig
): SubAgentBudget {
  const defaults = config.subAgent.defaultBudget;
  const hardStopAt = config.safety.circuitBreaker.hardStopAt;

  const maxToolCalls = Math.min(
    overrides.maxToolCalls ?? defaults.maxToolCalls,
    hardStopAt > 0 ? hardStopAt : Infinity
  );

  return {
    maxToolCalls,
    maxTokens: overrides.maxTokens ?? defaults.maxTokens,
    timeoutMs: overrides.timeoutMs ?? defaults.timeoutMs,
  };
}

export function validateBudget(budget: SubAgentBudget): void {
  if (budget.maxToolCalls <= 0) {
    throw new Error('maxToolCalls must be positive');
  }
  if (budget.maxTokens <= 0) {
    throw new Error('maxTokens must be positive');
  }
  if (budget.timeoutMs < 5000) {
    throw new Error('timeoutMs must be at least 5000');
  }
}

// --- Task 2: Context & Depth Tracking ---

export function createSubAgentContext(
  sessionId: string,
  parentContext: SubAgentContext | undefined,
  config: OptaConfig
): SubAgentContext {
  const depth = parentContext ? parentContext.depth + 1 : 1;
  const maxDepth = config.subAgent.maxDepth;

  if (depth > maxDepth) {
    throw new Error(`Maximum sub-agent depth (${maxDepth}) exceeded`);
  }

  return {
    parentSessionId: sessionId,
    depth,
    budget: resolveBudget({}, config),
    parentCwd: parentContext?.parentCwd ?? process.cwd(),
  };
}

// --- Task 3: System Prompt Generation ---

export function buildSubAgentPrompt(
  task: string,
  cwd: string,
  maxToolCalls: number
): string {
  return `You are a focused sub-agent assistant. You have been delegated a specific task to complete independently.

Your task: ${task}

Working directory: ${cwd}

Constraints:
- You have a budget of ${maxToolCalls} tool calls. Use them efficiently.
- Be concise in your responses. Your output will be consumed by a parent agent.
- Do not ask the user questions — you are running silently.
- Focus only on the task described above.
- Do NOT spawn further sub-agents unless absolutely necessary.

When finished, provide a structured summary:
1. What you found or did (key findings, code patterns, data points).
2. Files read — list every file path you examined.
3. Files modified — list every file path you created, edited, or deleted, with a one-line description of the change.
If no files were modified, state "No files modified."`;
}

// --- Task 4: Permission Derivation for Children ---

export function deriveChildConfig(
  parentConfig: OptaConfig,
  modeOverride?: string,
  budget?: SubAgentBudget
): OptaConfig {
  const resolvedBudget = budget ?? {
    maxToolCalls: parentConfig.subAgent.defaultBudget.maxToolCalls,
    maxTokens: parentConfig.subAgent.defaultBudget.maxTokens,
    timeoutMs: parentConfig.subAgent.defaultBudget.timeoutMs,
  };

  const mode = modeOverride ??
    (parentConfig.subAgent.inheritMode ? parentConfig.defaultMode : 'safe');

  // Derive permissions: always deny ask_user for silent children
  const childPermissions = { ...parentConfig.permissions };
  childPermissions['ask_user'] = 'deny';

  return {
    ...parentConfig,
    defaultMode: mode as OptaConfig['defaultMode'],
    permissions: childPermissions,
    git: {
      autoCommit: false,
      checkpoints: false,
    },
    safety: {
      ...parentConfig.safety,
      circuitBreaker: {
        ...parentConfig.safety.circuitBreaker,
        hardStopAt: resolvedBudget.maxToolCalls,
        pauseAt: 0, // No interactive pausing for silent agents
        warnAt: 0,  // No warnings for silent agents
      },
    },
  };
}

// --- Task 5: Core spawnSubAgent Function ---

export async function spawnSubAgent(
  task: SubAgentTask,
  config: OptaConfig,
  client: import('openai').default,
  registry: import('../mcp/registry.js').ToolRegistry,
  parentContext?: SubAgentContext,
  signal?: AbortSignal
): Promise<SubAgentResult> {
  const startTime = Date.now();
  const budget = resolveBudget(task.budget ?? {}, config);

  // Mutable state captured by the builder closure
  let toolCallCount = 0;
  const filesRead: string[] = [];
  const filesModified: string[] = [];
  const messages: Array<{
    role: 'system' | 'user' | 'assistant' | 'tool';
    content: string | null;
    tool_calls?: Array<{
      id: string;
      type: 'function';
      function: { name: string; arguments: string };
    }>;
    tool_call_id?: string;
  }> = [];

  /** Build a SubAgentResult from the current closure state. */
  function buildResult(
    status: SubAgentResult['status'],
    response: string,
  ): SubAgentResult {
    return {
      taskId: task.id,
      status,
      response,
      toolCallCount,
      tokenEstimate: estimateMessageTokens(messages),
      filesRead: [...new Set(filesRead)],
      filesModified: [...new Set(filesModified)],
      durationMs: Date.now() - startTime,
    };
  }

  /** Emit a sub-agent progress event. */
  function emitPhase(phase: SubAgentPhase, toolName?: string): void {
    task.onProgress?.({
      agentId: task.id,
      phase,
      taskDescription: task.description,
      toolName,
      toolCallCount,
      elapsedMs: Date.now() - startTime,
    });
  }

  // Check if already cancelled before starting
  if (signal?.aborted) {
    emitPhase('cancelled');
    return buildResult('cancelled', 'Sub-agent cancelled before starting.');
  }

  try {
    validateBudget(budget);
  } catch (err) {
    emitPhase('error');
    return buildResult('error', `Budget validation failed: ${errorMessage(err)}`);
  }

  const childConfig = deriveChildConfig(config, task.mode, budget);
  const cwd = task.scope ?? parentContext?.parentCwd ?? process.cwd();
  const systemPrompt = buildSubAgentPrompt(task.description, cwd, budget.maxToolCalls);
  const model = config.model.default;

  // Initialize messages array with system + user messages
  messages.push(
    { role: 'system', content: systemPrompt },
    { role: 'user', content: task.description },
  );

  // Build the tool schemas to use (respect whitelist if provided)
  const toolSchemas = task.tools
    ? registry.schemas.filter(s => task.tools!.includes(s.function.name))
    : registry.schemas;

  // Import resolvePermission once outside the loop
  const { resolvePermission } = await import('./tools/index.js');

  // AbortController for cancelling inflight LLM requests on timeout or external cancellation
  const abortController = new AbortController();

  // Link external signal to internal abort
  if (signal) {
    const onAbort = () => abortController.abort();
    signal.addEventListener('abort', onAbort, { once: true });
    // Clean up listener when done (handled in finally block via clearTimeout pattern)
  }

  emitPhase('spawning');

  const runLoop = async (): Promise<SubAgentResult> => {
    while (true) {
      // Check budget before each LLM call
      if (toolCallCount >= budget.maxToolCalls) {
        const lastAssistantMsg = [...messages].reverse().find(m => m.role === 'assistant');
        emitPhase('error');
        return buildResult(
          'budget_exceeded',
          typeof lastAssistantMsg?.content === 'string'
            ? lastAssistantMsg.content
            : `Budget exceeded after ${toolCallCount} tool calls.`,
        );
      }

      emitPhase('thinking');

      const response = await client.chat.completions.create({
        model,
        messages: messages as Parameters<typeof client.chat.completions.create>[0]['messages'],
        tools: toolSchemas.length > 0
          ? toolSchemas as Parameters<typeof client.chat.completions.create>[0]['tools']
          : undefined,
        tool_choice: toolSchemas.length > 0 ? 'auto' : undefined,
      }, { signal: abortController.signal });

      const choice = response.choices[0];
      if (!choice) {
        emitPhase('error');
        return buildResult('error', 'No response from model.');
      }

      const assistantMsg = choice.message;
      const text = assistantMsg.content ?? '';
      const toolCalls = assistantMsg.tool_calls ?? [];

      // No tool calls = task complete
      if (toolCalls.length === 0) {
        emitPhase('done');
        return buildResult('completed', text);
      }

      // Add assistant message with tool calls
      messages.push({
        role: 'assistant',
        content: text || null,
        tool_calls: toolCalls.map(tc => ({
          id: tc.id,
          type: 'function' as const,
          function: { name: tc.function.name, arguments: tc.function.arguments },
        })),
      });

      // Execute each tool call
      for (const tc of toolCalls) {
        // Check if timeout has fired between tool calls
        if (abortController.signal.aborted) {
          throw new Error('TIMEOUT');
        }

        const toolName = tc.function.name;

        // Check if tool is in whitelist (if whitelist exists)
        if (task.tools && !task.tools.includes(toolName)) {
          messages.push({
            role: 'tool',
            content: `Permission denied: tool "${toolName}" is not in the allowed tool list for this sub-agent.`,
            tool_call_id: tc.id,
          });
          toolCallCount++;
          continue;
        }

        // Check permission
        const permission = resolvePermission(toolName, childConfig);
        if (permission === 'deny' || permission === 'ask') {
          // Silent agents cannot prompt: ask becomes deny
          messages.push({
            role: 'tool',
            content: 'Permission denied by configuration.',
            tool_call_id: tc.id,
          });
          toolCallCount++;
          continue;
        }

        // Emit tool phase before execution
        emitPhase(detectPhaseFromTool(toolName), toolName);

        // Execute the tool (pass context explicitly for concurrency safety)
        const result = await registry.execute(toolName, tc.function.arguments, parentContext);
        messages.push({
          role: 'tool',
          content: result,
          tool_call_id: tc.id,
        });

        toolCallCount++;

        // Track files
        try {
          const args = JSON.parse(tc.function.arguments);
          if (toolName === 'multi_edit' && Array.isArray(args.edits)) {
            for (const edit of args.edits) {
              if (edit && typeof edit.path === 'string') {
                filesModified.push(edit.path);
              }
            }
          } else {
            const path = args.path ?? args.file;
            if (path) {
              if (['read_file', 'read_project_docs'].includes(toolName)) {
                filesRead.push(String(path));
              }
              if (['edit_file', 'write_file', 'delete_file'].includes(toolName)) {
                filesModified.push(String(path));
              }
            }
          }
        } catch {
          // Ignore arg parse errors for tracking
        }

        // Check budget after each tool call
        if (toolCallCount >= budget.maxToolCalls) {
          break;
        }
      }
    }
  };

  // Wrap with timeout, always restore registry context
  let timeoutHandle: ReturnType<typeof setTimeout> | undefined;
  try {
    const result = await Promise.race([
      runLoop(),
      new Promise<SubAgentResult>((_, reject) => {
        timeoutHandle = setTimeout(() => {
          abortController.abort(); // Cancel inflight LLM request
          reject(new Error('TIMEOUT'));
        }, budget.timeoutMs);
      }),
    ]);
    return result;
  } catch (err) {
    if (err instanceof Error && err.message === 'TIMEOUT') {
      // Distinguish external cancellation from internal timeout
      if (signal?.aborted) {
        emitPhase('cancelled');
        return buildResult('cancelled', 'Sub-agent cancelled by parent.');
      }
      emitPhase('timeout');
      return buildResult('timeout', `Sub-agent timed out after ${budget.timeoutMs}ms.`);
    }

    // External cancellation may also surface as an AbortError
    if (signal?.aborted) {
      emitPhase('cancelled');
      return buildResult('cancelled', 'Sub-agent cancelled by parent.');
    }

    emitPhase('error');
    return buildResult('error', errorMessage(err));
  } finally {
    if (timeoutHandle !== undefined) clearTimeout(timeoutHandle);
  }
}

// --- Task 6: Tool Result Formatting ---

export function formatSubAgentResult(result: SubAgentResult): string {
  const statusPrefix = result.status === 'error'
    ? '[ERROR] '
    : result.status === 'budget_exceeded'
    ? '[BUDGET EXCEEDED] '
    : result.status === 'timeout'
    ? '[TIMEOUT] '
    : result.status === 'cancelled'
    ? '[CANCELLED] '
    : '';

  const lines: string[] = [];
  lines.push(`${statusPrefix}Sub-agent result (${result.toolCallCount} tool calls, ${(result.durationMs / 1000).toFixed(1)}s):`);
  lines.push('');
  lines.push(result.response);

  if (result.filesRead.length > 0) {
    lines.push('');
    lines.push(`Files read: ${result.filesRead.join(', ')}`);
  }
  if (result.filesModified.length > 0) {
    lines.push('');
    lines.push(`Files modified: ${result.filesModified.join(', ')}`);
  }

  return lines.join('\n');
}

