/**
 * Tools that can modify state, destroy data, or interact with external systems.
 * At low autonomy levels (<=2), these tools always require user confirmation
 * even if config or mode says 'allow'. This prevents accidental damage when the
 * user has explicitly chosen a conservative autonomy level.
 *
 * Security rationale: autonomy level is the user's intent for how much
 * unsupervised power the agent should have. Allowing a config override to
 * bypass that intent would violate the principle of least privilege.
 */
const DESTRUCTIVE_TOOLS: ReadonlySet<string> = new Set([
  'edit_file',
  'write_file',
  'run_command',
  'delete_file',
  'multi_edit',
  'lsp_rename',
  'spawn_agent',
  'delegate_task',
  'bg_start',
]);

export function resolvePermission(
  toolName: string,
  config: OptaConfig
): 'allow' | 'ask' | 'deny' {
  // Per-tool config overrides take highest precedence
  const configPerm = config.permissions[toolName];
  const defaultPerm = DEFAULT_PERMISSIONS[toolName];

  let resolved: 'allow' | 'ask' | 'deny';

  // If the user explicitly set a per-tool override different from defaults, use it
  if (configPerm && configPerm !== defaultPerm) {
    resolved = configPerm;
  } else {
    // Mode-level permissions (mode handles CI via the 'ci' mode)
    const mode = config.defaultMode ?? 'safe';
    const modePerm = MODE_PERMISSIONS[mode]?.[toolName];
    if (modePerm) {
      resolved = modePerm;
    } else if (toolName.startsWith('custom__')) {
      // Custom tools (custom__*) execute shell commands, so they inherit
      // run_command's mode-level permissions when no explicit override exists.
      const customModePerm = MODE_PERMISSIONS[mode]?.['run_command'];
      resolved = (customModePerm ?? configPerm ?? 'ask');
    } else {
      // Fall back to config permission or default
      resolved = (configPerm ?? defaultPerm ?? 'ask');
    }
  }

  // Autonomy floor enforcement: at low autonomy levels, destructive tools
  // must always require confirmation regardless of config or mode overrides.
  // Uses Math.floor consistent with the existing autonomy level resolution
  // convention (fractional levels resolve down to prevent escalation).
  const autonomyLevel = Math.floor(config.autonomy?.level ?? 2);
  if (autonomyLevel <= 2 && DESTRUCTIVE_TOOLS.has(toolName) && resolved === 'allow') {
    resolved = 'ask';
  }

  return resolved;
}

import { spawn, type ChildProcess } from 'node:child_process';
import { resolve as resolvePath } from 'node:path';
import { nanoid } from 'nanoid';
import type {
  BackgroundOutputChunk,
  BackgroundOutputEventPayload,
  BackgroundOutputSlice,
  BackgroundProcessSnapshot,
  BackgroundProcessState,
  BackgroundSignal,
  BackgroundStatusEventPayload,
  BackgroundStream,
} from '../protocol/v3/types.js';

export interface BackgroundManagerOptions {
  maxConcurrent: number;
  defaultTimeout: number;
  maxBufferSize: number;
}

export interface StartBackgroundProcessInput {
  sessionId: string;
  command: string;
  label?: string;
  cwd?: string;
  timeoutMs?: number;
}

export interface BackgroundOutputQuery {
  afterSeq: number;
  limit: number;
  stream: 'stdout' | 'stderr' | 'both';
}

export interface KillBackgroundResult {
  killed: boolean;
  process: BackgroundProcessSnapshot;
}

export type BackgroundManagerEvent =
  | {
      type: 'output';
      sessionId: string;
      payload: BackgroundOutputEventPayload;
    }
  | {
      type: 'status';
      sessionId: string;
      payload: BackgroundStatusEventPayload;
    };

type BackgroundEventSubscriber = (event: BackgroundManagerEvent) => void;

interface ManagedBackgroundProcess {
  processId: string;
  sessionId: string;
  pid: number;
  command: string;
  label?: string;
  cwd: string;
  state: BackgroundProcessState;
  exitCode: number | null;
  startedAtMs: number;
  endedAtMs: number | null;
  timeoutMs: number;
  child: ChildProcess;
  requestedSignal?: BackgroundSignal;
  outputs: BackgroundOutputChunk[];
  outputBytes: number;
  nextOutputSeq: number;
  timeoutHandle?: ReturnType<typeof setTimeout>;
  killEscalationHandle?: ReturnType<typeof setTimeout>;
}

function parseShellCommand(cmd: string): [string, string[]] {
  const tokens: string[] = [];
  let current = '';
  let inSingle = false;
  let inDouble = false;
  for (let i = 0; i < cmd.length; i++) {
    const ch = cmd[i];
    if (ch === "'" && !inDouble) {
      inSingle = !inSingle;
      continue;
    }
    if (ch === '"' && !inSingle) {
      inDouble = !inDouble;
      continue;
    }
    if (ch === '\\' && !inSingle && i + 1 < cmd.length) {
      current += cmd[++i];
      continue;
    }
    if ((ch === ' ' || ch === '\t') && !inSingle && !inDouble) {
      if (current) {
        tokens.push(current);
        current = '';
      }
      continue;
    }
    current += ch;
  }
  if (current) tokens.push(current);
  const [exe = '', ...args] = tokens;
  return [exe, args];
}

function reasonFromState(state: BackgroundProcessState): BackgroundStatusEventPayload['reason'] {
  switch (state) {
    case 'completed':
      return 'completed';
    case 'failed':
      return 'failed';
    case 'killed':
      return 'killed';
    case 'timeout':
      return 'timeout';
    case 'running':
      return 'running';
  }
}

export class BackgroundManager {
  private static readonly SIGTERM_GRACE_MS = 3_000;
  private static readonly SIGKILL_GRACE_MS = 5_000;

  private readonly processes = new Map<string, ManagedBackgroundProcess>();
  private readonly subscribers = new Set<BackgroundEventSubscriber>();
  private options: BackgroundManagerOptions;

  constructor(options: BackgroundManagerOptions) {
    this.options = { ...options };
  }

  updateOptions(next: BackgroundManagerOptions): void {
    this.options = { ...next };
  }

  subscribe(cb: BackgroundEventSubscriber): () => void {
    this.subscribers.add(cb);
    return () => {
      this.subscribers.delete(cb);
    };
  }

  list(sessionId?: string): BackgroundProcessSnapshot[] {
    const snapshots: BackgroundProcessSnapshot[] = [];
    for (const proc of this.processes.values()) {
      if (sessionId && proc.sessionId !== sessionId) continue;
      snapshots.push(this.toSnapshot(proc));
    }
    snapshots.sort((a, b) => {
      if (a.startedAt === b.startedAt) {
        return a.processId.localeCompare(b.processId);
      }
      return a.startedAt.localeCompare(b.startedAt);
    });
    return snapshots;
  }

  status(processId: string): BackgroundProcessSnapshot | null {
    const proc = this.processes.get(processId);
    if (!proc) return null;
    return this.toSnapshot(proc);
  }

  output(processId: string, query: BackgroundOutputQuery): BackgroundOutputSlice | null {
    const proc = this.processes.get(processId);
    if (!proc) return null;

    const matching = proc.outputs.filter((chunk) => {
      if (chunk.seq <= query.afterSeq) return false;
      if (query.stream === 'both') return true;
      return chunk.stream === query.stream;
    });
    const hasMore = matching.length > query.limit;
    const chunks = matching.slice(0, query.limit);
    const lastChunk = chunks.length > 0 ? chunks[chunks.length - 1] : undefined;
    const nextSeq = lastChunk ? lastChunk.seq : query.afterSeq;

    return {
      process: this.toSnapshot(proc),
      chunks,
      nextSeq,
      hasMore,
    };
  }

  start(input: StartBackgroundProcessInput): BackgroundProcessSnapshot {
    const running = [...this.processes.values()].filter((proc) => proc.state === 'running').length;
    if (running >= this.options.maxConcurrent) {
      throw new Error(`Max concurrent processes (${this.options.maxConcurrent}) reached`);
    }

    const processId = nanoid(8);
    const cwd = resolvePath(input.cwd ?? process.cwd());
    const timeoutMs = input.timeoutMs ?? this.options.defaultTimeout;

    const [exe, args] = parseShellCommand(input.command);
    const child = spawn(exe, args, {
      cwd,
      stdio: ['ignore', 'pipe', 'pipe'],
      detached: false,
    });

    if (!child.pid) {
      throw new Error(`Background process failed to start: ${input.command}`);
    }

    const nowMs = Date.now();
    const proc: ManagedBackgroundProcess = {
      processId,
      sessionId: input.sessionId,
      pid: child.pid,
      command: input.command,
      label: input.label,
      cwd,
      state: 'running',
      exitCode: null,
      startedAtMs: nowMs,
      endedAtMs: null,
      timeoutMs,
      child,
      outputs: [],
      outputBytes: 0,
      nextOutputSeq: 0,
    };
    this.processes.set(processId, proc);

    child.stdout?.on('data', (chunk: Buffer) => {
      this.appendOutput(proc, 'stdout', chunk.toString('utf-8'));
    });
    child.stderr?.on('data', (chunk: Buffer) => {
      this.appendOutput(proc, 'stderr', chunk.toString('utf-8'));
    });

    child.on('error', () => {
      const previous = proc.state;
      proc.state = 'failed';
      proc.endedAtMs = Date.now();
      this.clearTimers(proc);
      this.emitStatus(proc, {
        reason: 'spawn-error',
        previousState: previous,
      });
    });

    child.on('close', (code, signal) => {
      const previous = proc.state;
      if (proc.state === 'running') {
        if (proc.requestedSignal || signal) {
          proc.state = 'killed';
        } else if (code === 0) {
          proc.state = 'completed';
        } else {
          proc.state = 'failed';
        }
      }

      proc.exitCode = code;
      proc.endedAtMs = Date.now();
      this.clearTimers(proc);
      this.emitStatus(proc, {
        reason: reasonFromState(proc.state),
        previousState: previous,
        signal: proc.requestedSignal,
      });

      // Prune processes completed more than 5 minutes ago
      const COMPLETED_RETENTION_MS = 5 * 60 * 1_000;
      const cutoff = Date.now() - COMPLETED_RETENTION_MS;
      for (const [id, p] of this.processes) {
        if (p.state !== 'running' && (p.endedAtMs ?? p.startedAtMs) < cutoff) {
          this.processes.delete(id);
        }
      }
    });

    if (timeoutMs > 0) {
      proc.timeoutHandle = setTimeout(() => {
        if (proc.state !== 'running') return;
        const previous = proc.state;
        proc.state = 'timeout';
        this.emitStatus(proc, {
          reason: 'timeout',
          previousState: previous,
        });
        proc.child.kill('SIGTERM');
        proc.killEscalationHandle = setTimeout(() => {
          if (proc.state === 'running' || proc.state === 'timeout') {
            proc.child.kill('SIGKILL');
          }
        }, BackgroundManager.SIGTERM_GRACE_MS);
        proc.killEscalationHandle.unref();
      }, timeoutMs);
      proc.timeoutHandle.unref();
    }

    this.emitStatus(proc, { reason: 'started' });
    return this.toSnapshot(proc);
  }

  kill(processId: string, signal: BackgroundSignal = 'SIGTERM'): KillBackgroundResult | null {
    const proc = this.processes.get(processId);
    if (!proc) return null;
    if (proc.state !== 'running') {
      return { killed: false, process: this.toSnapshot(proc) };
    }

    proc.requestedSignal = signal;
    const killed = proc.child.kill(signal);

    if (signal !== 'SIGKILL') {
      proc.killEscalationHandle = setTimeout(() => {
        if (proc.state === 'running') {
          proc.requestedSignal = 'SIGKILL';
          proc.child.kill('SIGKILL');
        }
      }, BackgroundManager.SIGKILL_GRACE_MS);
      proc.killEscalationHandle.unref();
    }

    return { killed, process: this.toSnapshot(proc) };
  }

  killSession(sessionId: string, signal: BackgroundSignal = 'SIGTERM'): number {
    let killed = 0;
    for (const proc of this.processes.values()) {
      if (proc.sessionId !== sessionId || proc.state !== 'running') continue;
      const result = this.kill(proc.processId, signal);
      if (result?.killed) killed += 1;
    }
    return killed;
  }

  close(signal: BackgroundSignal = 'SIGTERM'): void {
    const running = [...this.processes.values()].filter((proc) => proc.state === 'running');
    for (const proc of running) {
      this.kill(proc.processId, signal);
    }
  }

  private appendOutput(
    proc: ManagedBackgroundProcess,
    stream: BackgroundStream,
    text: string
  ): void {
    if (text.length === 0) return;
    const chunk: BackgroundOutputChunk = {
      seq: ++proc.nextOutputSeq,
      ts: new Date().toISOString(),
      stream,
      text,
    };

    proc.outputs.push(chunk);
    proc.outputBytes += Buffer.byteLength(text, 'utf-8');
    while (proc.outputBytes > this.options.maxBufferSize && proc.outputs.length > 0) {
      const evicted = proc.outputs.shift();
      if (!evicted) break;
      proc.outputBytes -= Buffer.byteLength(evicted.text, 'utf-8');
    }

    this.emit({
      type: 'output',
      sessionId: proc.sessionId,
      payload: {
        processId: proc.processId,
        sessionId: proc.sessionId,
        pid: proc.pid,
        seq: chunk.seq,
        ts: chunk.ts,
        stream: chunk.stream,
        text: chunk.text,
      },
    });
  }

  private emitStatus(
    proc: ManagedBackgroundProcess,
    input: {
      reason: BackgroundStatusEventPayload['reason'];
      previousState?: BackgroundProcessState;
      signal?: BackgroundSignal;
    }
  ): void {
    this.emit({
      type: 'status',
      sessionId: proc.sessionId,
      payload: {
        process: this.toSnapshot(proc),
        reason: input.reason,
        previousState: input.previousState,
        signal: input.signal,
      },
    });
  }

  private emit(event: BackgroundManagerEvent): void {
    for (const subscriber of this.subscribers) {
      try {
        subscriber(event);
      } catch {
        // Isolate subscriber failures.
      }
    }
  }

  private toSnapshot(proc: ManagedBackgroundProcess): BackgroundProcessSnapshot {
    return {
      processId: proc.processId,
      sessionId: proc.sessionId,
      pid: proc.pid,
      command: proc.command,
      label: proc.label,
      cwd: proc.cwd,
      state: proc.state,
      exitCode: proc.exitCode,
      startedAt: new Date(proc.startedAtMs).toISOString(),
      endedAt: proc.endedAtMs ? new Date(proc.endedAtMs).toISOString() : null,
      runtimeMs: (proc.endedAtMs ?? Date.now()) - proc.startedAtMs,
      timeoutMs: proc.timeoutMs,
    };
  }

  private clearTimers(proc: ManagedBackgroundProcess): void {
    if (proc.timeoutHandle) {
      clearTimeout(proc.timeoutHandle);
      proc.timeoutHandle = undefined;
    }
    if (proc.killEscalationHandle) {
      clearTimeout(proc.killEscalationHandle);
      proc.killEscalationHandle = undefined;
    }
  }
}

import { existsSync } from 'node:fs';
import { readFile, writeFile, mkdir, rm } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { randomBytes } from 'node:crypto';
import { getDaemonDir } from '../platform/paths.js';
import { spawn } from 'node:child_process';
import { fileURLToPath } from 'node:url';
import { debug } from '../core/debug.js';
import { daemonLogsPath } from './telemetry.js';
import { diskHeadroomMbToBytes, ensureDiskHeadroom } from '../utils/disk.js';
import { restrictFileToCurrentUser } from '../platform/index.js';

export interface DaemonState {
  pid: number;
  daemonId: string;
  host: string;
  port: number;
  token: string;
  startedAt: string;
  logsPath: string;
}

const DEFAULT_HOST = '127.0.0.1';
const DEFAULT_PORT = 9999;

function envDiskHeadroomMb(): number | undefined {
  const raw = process.env['OPTA_DISK_HEADROOM_MB'];
  if (!raw) return undefined;
  const parsed = Number.parseInt(raw, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) return undefined;
  return parsed;
}

function daemonDir(): string {
  return getDaemonDir();
}

function statePath(): string {
  return join(daemonDir(), 'state.json');
}

function tokenPath(): string {
  return join(daemonDir(), 'token');
}

function pidPath(): string {
  return join(daemonDir(), 'daemon.pid');
}

async function ensureDaemonDir(): Promise<void> {
  await ensureDiskHeadroom(daemonDir(), {
    minFreeBytes: diskHeadroomMbToBytes(envDiskHeadroomMb()),
  });
  await mkdir(daemonDir(), { recursive: true });
}

export async function readDaemonState(): Promise<DaemonState | null> {
  try {
    const raw = await readFile(statePath(), 'utf-8');
    return JSON.parse(raw) as DaemonState;
  } catch {
    return null;
  }
}

export async function writeDaemonState(state: DaemonState): Promise<void> {
  await ensureDaemonDir();
  await writeFile(statePath(), JSON.stringify(state, null, 2), 'utf-8');
  await writeFile(pidPath(), String(state.pid), 'utf-8');
}

export async function clearDaemonState(): Promise<void> {
  await Promise.all([rm(statePath(), { force: true }), rm(pidPath(), { force: true })]);
}

export async function readDaemonToken(): Promise<string | null> {
  try {
    return (await readFile(tokenPath(), 'utf-8')).trim();
  } catch {
    return null;
  }
}

export async function writeDaemonToken(token: string): Promise<void> {
  await ensureDaemonDir();
  await writeFile(tokenPath(), token, { encoding: 'utf-8', mode: 0o600 });
  await restrictFileToCurrentUser(tokenPath());
}

export async function createDaemonToken(): Promise<string> {
  const token = randomBytes(24).toString('hex');
  await writeDaemonToken(token);
  return token;
}

export function defaultDaemonHost(): string {
  return DEFAULT_HOST;
}

export function defaultDaemonPort(): number {
  return DEFAULT_PORT;
}

export function isProcessRunning(pid: number): boolean {
  try {
    process.kill(pid, 0);
    return true;
  } catch {
    return false;
  }
}

async function pingDaemon(
  host: string,
  port: number,
  token: string,
  timeoutMs = 500
): Promise<boolean> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  timer.unref();
  try {
    const tokenParam = encodeURIComponent(token);
    const res = await fetch(`http://${host}:${port}/v3/health?token=${tokenParam}`, {
      signal: controller.signal,
    });
    return res.ok;
  } catch {
    return false;
  } finally {
    clearTimeout(timer);
  }
}

export async function isDaemonRunning(state?: DaemonState | null): Promise<boolean> {
  const current = state ?? (await readDaemonState());
  if (!current) return false;
  if (!isProcessRunning(current.pid)) return false;
  return pingDaemon(current.host, current.port, current.token, 800);
}

function resolveCliEntrypoint(): string {
  // In source mode this module lives at src/daemon/lifecycle.ts and the CLI entry
  // is ../index.ts. In bundled mode this chunk lives in dist/ and the entry is
  // dist/index.js (sibling, not parent).
  const selfPath = fileURLToPath(import.meta.url);
  const ext = selfPath.endsWith('.ts') ? '.ts' : '.js';
  const baseDir = dirname(selfPath);

  const sibling = join(baseDir, `index${ext}`);
  if (existsSync(sibling)) return sibling;

  const parent = join(baseDir, '..', `index${ext}`);
  if (existsSync(parent)) return parent;

  // Final fallback keeps previous behavior if the filesystem check is inconclusive.
  return parent;
}

export async function startDaemonDetached(opts?: {
  host?: string;
  port?: number;
}): Promise<DaemonState> {
  const existing = await readDaemonState();
  if (await isDaemonRunning(existing)) {
    return existing!;
  }

  const host = opts?.host ?? DEFAULT_HOST;
  const port = opts?.port ?? DEFAULT_PORT;
  const token = await createDaemonToken();
  const entry = resolveCliEntrypoint();
  const nodeArgs: string[] = [];
  if (entry.endsWith('.ts')) {
    nodeArgs.push('--import', 'tsx');
  }
  nodeArgs.push(entry, 'daemon', 'run', '--host', host, '--port', String(port), '--token', token);

  const child = spawn(process.execPath, nodeArgs, {
    detached: true,
    stdio: 'ignore',
    env: {
      ...process.env,
      OPTA_DAEMON_PROCESS: '1',
    },
  });
  child.unref();

  const started = await waitForDaemonReady(10_000);
  if (!started) {
    throw new Error('Timed out waiting for daemon to start');
  }

  const running = await readDaemonState();
  if (!running) {
    throw new Error('Daemon did not publish state');
  }
  return running;
}

async function waitForDaemonReady(timeoutMs: number): Promise<boolean> {
  const start = Date.now();
  while (Date.now() - start < timeoutMs) {
    const current = await readDaemonState();
    if (current && (await isDaemonRunning(current))) return true;
    await new Promise((resolve) => setTimeout(resolve, 120));
  }
  return false;
}

export async function ensureDaemonRunning(opts?: {
  host?: string;
  port?: number;
}): Promise<DaemonState> {
  const current = await readDaemonState();
  if (current) {
    const alive = await isDaemonRunning(current);
    if (alive) return current;
    // Crash guardian: state file exists but process is dead — clean up stale state
    debug(`Crash guardian: stale daemon state (pid=${current.pid}), restarting`);
    await clearDaemonState();
  }
  return startDaemonDetached(opts);
}

export async function stopDaemon(): Promise<boolean> {
  const state = await readDaemonState();
  if (!state) return false;

  if (!isProcessRunning(state.pid)) {
    await clearDaemonState();
    return true;
  }

  process.kill(state.pid, 'SIGTERM');
  const start = Date.now();
  while (Date.now() - start < 4000) {
    if (!isProcessRunning(state.pid)) {
      await clearDaemonState();
      return true;
    }
    await new Promise((resolve) => setTimeout(resolve, 100));
  }

  // Last resort
  process.kill(state.pid, 'SIGKILL');
  await clearDaemonState();
  return true;
}

export async function daemonStatus(): Promise<{
  running: boolean;
  state: DaemonState | null;
  logsPath: string;
}> {
  const state = await readDaemonState();
  const running = await isDaemonRunning(state);
  if (!running && state) {
    await clearDaemonState();
  }
  return {
    running,
    state: running ? state : null,
    logsPath: daemonLogsPath(),
  };
}

import { nanoid } from 'nanoid';
import { getDaemonDir } from '../platform/paths.js';
import { SessionManager } from './session-manager.js';
import { startHttpServer } from './http-server.js';
import { clearDaemonState, createDaemonToken, defaultDaemonHost, defaultDaemonPort, writeDaemonToken } from './lifecycle.js';
import { logDaemonEvent } from './telemetry.js';
import { loadConfig } from '../core/config.js';
import { resolveLmxEndpoint } from '../lmx/endpoints.js';
import { diskHeadroomMbToBytes, ensureDiskHeadroom } from '../utils/disk.js';

export interface RunDaemonOptions {
  host?: string;
  port?: number;
  token?: string;
  model?: string;
}

export async function runDaemon(options?: RunDaemonOptions): Promise<void> {
  const startupConfig = await loadConfig();
  await ensureDiskHeadroom(getDaemonDir(), {
    minFreeBytes: diskHeadroomMbToBytes(startupConfig.safety?.diskHeadroomMb),
  });

  const host = options?.host ?? defaultDaemonHost();
  const preferredPort = options?.port ?? defaultDaemonPort();
  const token = options?.token ?? await createDaemonToken();
  if (options?.token) {
    await writeDaemonToken(options.token);
  }

  const daemonId = `daemon_${nanoid(8)}`;
  const sessionManager = new SessionManager(daemonId, async () => {
    const config = await loadConfig();
    if (!options?.model) return config;
    return {
      ...config,
      model: {
        ...config.model,
        default: options.model,
      },
    };
  });
  await sessionManager.hydrateFromDisk();

  // Pre-spawn 2 idle tool workers — eliminates ~30-80 ms cold-start on the first tool call.
  sessionManager.warmUpWorkers(2);

  // Prime the LMX endpoint cache so the first agent turn resolves immediately
  // instead of waiting for the ~1.5 s probe round-trip. Fire-and-forget.
  void resolveLmxEndpoint({
    host: startupConfig.connection.host,
    fallbackHosts: startupConfig.connection.fallbackHosts,
    port: startupConfig.connection.port,
    adminKey: startupConfig.connection.adminKey,
    adminKeysByHost: startupConfig.connection.adminKeysByHost,
  }).catch(() => undefined);

  const running = await startHttpServer({
    daemonId,
    host,
    port: preferredPort,
    token,
    sessionManager,
  });

  await logDaemonEvent({
    level: 'info',
    daemonId,
    msg: 'daemon started',
    data: {
      host: running.host,
      port: running.port,
      pid: process.pid,
    },
  });

  const shutdown = async (signal: string) => {
    await logDaemonEvent({
      level: 'info',
      daemonId,
      msg: 'daemon shutting down',
      data: { signal },
    });
    try {
      await sessionManager.close();
      await running.close();
    } finally {
      await clearDaemonState();
      process.exit(0);
    }
  };

  process.on('SIGTERM', () => {
    void shutdown('SIGTERM');
  });
  process.on('SIGINT', () => {
    void shutdown('SIGINT');
  });

  // Process-level crash resilience: log but don't exit on unexpected errors.
  // Session-level errors are already isolated in session-manager.ts (try-catch
  // around processSessionQueue). These handlers catch errors that escape Fastify
  // internals or non-session codepaths.
  process.on('uncaughtException', (err) => {
    void logDaemonEvent({
      level: 'error',
      daemonId,
      msg: 'uncaught exception (daemon continuing)',
      data: { error: err.message, stack: err.stack },
    });
  });
  process.on('unhandledRejection', (reason) => {
    const message = reason instanceof Error ? reason.message : String(reason);
    void logDaemonEvent({
      level: 'error',
      daemonId,
      msg: 'unhandled rejection (daemon continuing)',
      data: { error: message },
    });
  });
}

