class LatencyWindow {
  private readonly samples: number[] = [];
  private readonly maxSamples = 100;

  record(ms: number): void {
    if (this.samples.length >= this.maxSamples) this.samples.shift();
    this.samples.push(ms);
  }

  percentile(p: number): number {
    if (this.samples.length === 0) return 0;
    const sorted = [...this.samples].sort((a, b) => a - b);
    const idx = Math.floor((p / 100) * (sorted.length - 1));
    return sorted[idx] ?? 0;
  }

  get count(): number { return this.samples.length; }
}

// Tool result cache constants
const CACHEABLE_TOOLS = new Set(['read_file', 'list_dir', 'search_files', 'find_files']);
const MTIME_TOOLS = new Set(['read_file', 'list_dir']);
const WRITE_TOOLS = new Set(['write_file', 'edit_file']);
const CACHE_MAX_SIZE = 200;
const CACHE_TTL_MS = 30_000;

interface ToolCacheEntry {
  result: string;
  cachedAt: number;
  fileMtimeMs?: number;
}
const LMX_PREFLIGHT_TIMEOUT_MS = 8_000;
const NO_MODEL_LOADED_MESSAGE = 'No Model Loaded - Use Opta Menu to begin.';

interface CodedTurnError extends Error {
  turnErrorCode?: TurnErrorCode;
}

interface ManagedSession {
  sessionId: string;
  model: string;
  title?: string;
  createdAt: string;
  updatedAt: string;
  messages: AgentMessage[];
  toolCallCount: number;
  queue: TurnQueue;
  activeTurn?: QueuedTurn;
  activeAbort?: AbortController;
  seq: number;
  toolCache: Map<string, ToolCacheEntry>;
}

type SessionSubscriber = (event: V3Envelope) => void;

export class SessionManager {
  private readonly sessions = new Map<string, ManagedSession>();
  private readonly subscribers = new Map<string, Set<SessionSubscriber>>();
  private readonly permissionCoordinator = new PermissionCoordinator();
  private readonly toolWorkers = new ToolWorkerPool();
  private preflightCache: { modelIds: string[]; cachedAt: number } | null = null;
  private readonly backgroundManager = new BackgroundManager({
    maxConcurrent: 5,
    defaultTimeout: 300_000,
    maxBufferSize: 1_048_576,
  });
  private readonly unsubscribeBackgroundEvents: () => void;
  private ingressSeq = 0;
  private evictionInterval: NodeJS.Timeout;
  private readonly latencyWindow = new LatencyWindow();

  constructor(
    private readonly daemonId: string,
    private readonly getConfig: () => Promise<OptaConfig> = async () => loadConfig()
  ) {
    this.unsubscribeBackgroundEvents = this.backgroundManager.subscribe((event) => {
      void this.handleBackgroundEvent(event);
    });
    this.evictionInterval = setInterval(() => this.evictIdleSessions(), 5 * 60 * 1000);
    this.evictionInterval.unref();
  }

  private evictIdleSessions() {
    const now = Date.now();
    for (const [sessionId, session] of this.sessions.entries()) {
      if (
        session.queue.size === 0 &&
        !session.activeTurn &&
        !this.subscribers.has(sessionId) &&
        now - new Date(session.updatedAt).getTime() > 30 * 60 * 1000
      ) {
        this.sessions.delete(sessionId);
      }
    }
  }

  async hydrateFromDisk(): Promise<void> {
    const sessionIds = await listStoredSessions();
    for (const sessionId of sessionIds) {
      const snapshot = await readSessionSnapshot(sessionId);
      if (!snapshot) continue;
      this.sessions.set(sessionId, {
        sessionId: snapshot.sessionId,
        model: snapshot.model,
        title: snapshot.title,
        createdAt: snapshot.createdAt,
        updatedAt: snapshot.updatedAt,
        messages: snapshot.messages,
        toolCallCount: snapshot.toolCallCount,
        queue: new TurnQueue(),
        seq: snapshot.seq,
        toolCache: new Map(),
      });
    }
  }

  /** Pre-spawn idle tool workers to eliminate cold-start latency on first tool call. */
  warmUpWorkers(count: number = 2): void {
    this.toolWorkers.warmUp(count);
  }

  private sessionToSnapshot(session: ManagedSession): SessionSnapshot {
    const writers = new Set<string>();
    for (const queued of session.queue.toArray()) {
      writers.add(queued.writerId);
    }
    if (session.activeTurn) writers.add(session.activeTurn.writerId);

    return {
      sessionId: session.sessionId,
      model: session.model,
      title: session.title,
      createdAt: session.createdAt,
      updatedAt: session.updatedAt,
      activeTurnId: session.activeTurn?.turnId,
      queuedTurns: session.queue.size,
      toolCallCount: session.toolCallCount,
      writerCount: writers.size,
    };
  }

  async createSession(req: CreateSessionRequest): Promise<SessionSnapshot> {
    const cfg = await this.getConfig();
    const sessionId = req.sessionId ?? nanoid(12);

    const now = new Date().toISOString();
    let existing = this.sessions.get(sessionId);
    if (!existing && (await hasSessionStore(sessionId))) {
      const snapshot = await readSessionSnapshot(sessionId);
      if (snapshot) {
        existing = {
          sessionId,
          model: snapshot.model,
          title: snapshot.title,
          createdAt: snapshot.createdAt,
          updatedAt: snapshot.updatedAt,
          messages: snapshot.messages,
          toolCallCount: snapshot.toolCallCount,
          queue: new TurnQueue(),
          seq: snapshot.seq,
          toolCache: new Map(),
        };
      }
    }

    const session = existing ?? {
      sessionId,
      model: req.model ?? cfg.model.default,
      title: req.title,
      createdAt: now,
      updatedAt: now,
      messages: this.normalizeMessages(req.messages),
      toolCallCount: 0,
      queue: new TurnQueue(),
      seq: 0,
      toolCache: new Map(),
    };

    this.sessions.set(sessionId, session);
    await this.persistSnapshot(session);
    await this.emit(session, 'session.snapshot', {
      snapshot: this.sessionToSnapshot(session),
      messages: session.messages,
    });

    return this.sessionToSnapshot(session);
  }

  async getSession(sessionId: string): Promise<SessionSnapshot | null> {
    let session = this.sessions.get(sessionId);
    if (!session && (await hasSessionStore(sessionId))) {
      const snapshot = await readSessionSnapshot(sessionId);
      if (snapshot) {
        session = {
          sessionId,
          model: snapshot.model,
          title: snapshot.title,
          createdAt: snapshot.createdAt,
          updatedAt: snapshot.updatedAt,
          messages: snapshot.messages,
          toolCallCount: snapshot.toolCallCount,
          queue: new TurnQueue(),
          seq: snapshot.seq,
          toolCache: new Map(),
        };
        this.sessions.set(sessionId, session);
      }
    }
    if (!session) return null;
    return this.sessionToSnapshot(session);
  }

  async getSessionMessages(sessionId: string): Promise<AgentMessage[] | null> {
    let session = this.sessions.get(sessionId);
    if (!session && (await hasSessionStore(sessionId))) {
      await this.getSession(sessionId); // hydrates it
      session = this.sessions.get(sessionId);
    }
    if (!session) return null;
    return session.messages;
  }

  async submitTurn(
    sessionId: string,
    payload: ClientSubmitTurn
  ): Promise<{ turnId: string; queued: number }> {
    const session = this.sessions.get(sessionId);
    if (!session) {
      throw new Error(`Session not found: ${sessionId}`);
    }

    if (payload.lastSeenSeq !== undefined && payload.lastSeenSeq < session.seq) {
      throw this.newTurnError('Session state conflict: context has been modified since last seen', 'state-conflict' as TurnErrorCode);
    }

    const turn: QueuedTurn = {
      turnId: nanoid(12),
      ingressSeq: ++this.ingressSeq,
      sessionId,
      clientId: payload.clientId,
      writerId: payload.writerId,
      content: payload.content,
      mode: payload.mode,
      metadata: payload.metadata,
      overrides: payload.overrides,
      createdAt: new Date().toISOString(),
    };

    session.queue.enqueue(turn);
    session.updatedAt = new Date().toISOString();
    await this.emit(session, 'turn.queued', {
      turnId: turn.turnId,
      writerId: turn.writerId,
      clientId: turn.clientId,
      queueSize: session.queue.size,
    });
    await this.persistSnapshot(session);

    // processSessionQueue handles all its own errors internally (try/catch in
    // the loop body emits turn.error on failure).  The void here is intentional
    // — we do not await it so the HTTP response returns immediately — but we
    // attach a catch to prevent unhandled-rejection crashes if the outer async
    // scaffolding throws before reaching the internal try/catch (e.g. a config
    // load failure before getConfig() is awaited).
    void this.processSessionQueue(sessionId).catch((err: unknown) => {
      void logDaemonEvent({
        level: 'error',
        daemonId: this.daemonId,
        sessionId,
        msg: 'processSessionQueue unhandled rejection',
        data: { message: errorMessage(err) },
      });
    });
    return { turnId: turn.turnId, queued: session.queue.size };
  }

  async cancelSessionTurns(
    sessionId: string,
    opts: { turnId?: string; writerId?: string }
  ): Promise<{ cancelledQueued: number; cancelledActive: boolean }> {
    const session = this.sessions.get(sessionId);
    if (!session) return { cancelledQueued: 0, cancelledActive: false };

    let cancelledQueued = 0;
    if (opts.turnId) {
      cancelledQueued += session.queue.cancelByTurnId(opts.turnId) ? 1 : 0;
    } else if (opts.writerId) {
      cancelledQueued += session.queue.cancelByWriter(opts.writerId);
    }

    // Active turn cancellation: cooperative abort via AbortController.
    let cancelledActive = false;
    const active = session.activeTurn;
    if (active && session.activeAbort) {
      const matchesTurn = opts.turnId ? active.turnId === opts.turnId : false;
      const matchesWriter = opts.writerId ? active.writerId === opts.writerId : false;
      if (matchesTurn || matchesWriter) {
        session.activeAbort.abort();
        cancelledActive = true;
      }
    }

    const totalCancelled = cancelledQueued + (cancelledActive ? 1 : 0);
    if (totalCancelled > 0) {
      await this.emit(session, 'session.cancelled', {
        cancelled: totalCancelled,
        turnId: opts.turnId,
        writerId: opts.writerId,
      });
      await this.persistSnapshot(session);
    }
    return { cancelledQueued, cancelledActive };
  }

  resolvePermission(
    sessionId: string,
    decision: PermissionDecision
  ): { ok: boolean; conflict: boolean; message?: string } {
    const session = this.sessions.get(sessionId);
    if (!session) return { ok: false, conflict: false, message: 'Session not found' };
    const result = this.permissionCoordinator.resolve(decision.requestId, decision.decision);
    return result;
  }

  async getEventsAfter(sessionId: string, afterSeq: number): Promise<V3Envelope[]> {
    return readSessionEventsAfter(sessionId, afterSeq);
  }

  subscribe(sessionId: string, cb: SessionSubscriber): () => void {
    const existing = this.subscribers.get(sessionId) ?? new Set<SessionSubscriber>();
    existing.add(cb);
    this.subscribers.set(sessionId, existing);
    return () => {
      const current = this.subscribers.get(sessionId);
      if (!current) return;
      current.delete(cb);
      if (current.size === 0) this.subscribers.delete(sessionId);
    };
  }

  getRuntimeStats(): {
    sessionCount: number;
    activeTurnCount: number;
    queuedTurnCount: number;
    subscriberCount: number;
    ingressSeq: number;
    toolWorkers: { workers: number; busy: number; queued: number };
    latency: { p50Ms: number; p99Ms: number; samples: number };
  } {
    let activeTurnCount = 0;
    let queuedTurnCount = 0;
    for (const session of this.sessions.values()) {
      if (session.activeTurn) activeTurnCount += 1;
      queuedTurnCount += session.queue.size;
    }
    let subscriberCount = 0;
    for (const set of this.subscribers.values()) {
      subscriberCount += set.size;
    }
    return {
      sessionCount: this.sessions.size,
      activeTurnCount,
      queuedTurnCount,
      subscriberCount,
      ingressSeq: this.ingressSeq,
      toolWorkers: this.toolWorkers.getStats(),
      latency: {
        p50Ms: this.latencyWindow.percentile(50),
        p99Ms: this.latencyWindow.percentile(99),
        samples: this.latencyWindow.count,
      },
    };
  }

  listBackgroundProcesses(sessionId?: string): BackgroundProcessSnapshot[] {
    if (sessionId && !this.sessions.has(sessionId)) {
      throw new Error(`Session not found: ${sessionId}`);
    }
    return this.backgroundManager.list(sessionId);
  }

  async startBackgroundProcess(input: {
    sessionId: string;
    command: string;
    label?: string;
    cwd?: string;
    timeoutMs?: number;
  }): Promise<BackgroundProcessSnapshot> {
    if (!this.sessions.has(input.sessionId)) {
      throw new Error(`Session not found: ${input.sessionId}`);
    }
    await this.refreshBackgroundOptions();
    return this.backgroundManager.start(input);
  }

  getBackgroundStatus(processId: string): BackgroundProcessSnapshot | null {
    return this.backgroundManager.status(processId);
  }

  getBackgroundOutput(
    processId: string,
    query: BackgroundOutputQuery
  ): BackgroundOutputSlice | null {
    return this.backgroundManager.output(processId, query);
  }

  killBackgroundProcess(
    processId: string,
    signal: BackgroundSignal = 'SIGTERM'
  ): {
    killed: boolean;
    process: BackgroundProcessSnapshot;
  } | null {
    return this.backgroundManager.kill(processId, signal);
  }

  async close(): Promise<void> {
    clearInterval(this.evictionInterval);
    this.unsubscribeBackgroundEvents();
    const cfg = await this.getConfig().catch(() => null);
    if (cfg) {
      this.backgroundManager.updateOptions({
        maxConcurrent: cfg.background.maxConcurrent,
        defaultTimeout: cfg.background.defaultTimeout,
        maxBufferSize: cfg.background.maxBufferSize,
      });
    }
    if (cfg?.background.killOnSessionEnd ?? true) {
      this.backgroundManager.close();
    }
    this.toolWorkers.close();
  }

  private normalizeMessages(raw?: unknown[]): AgentMessage[] {
    if (!Array.isArray(raw)) return [];
    return raw.filter((item): item is AgentMessage => {
      if (!item || typeof item !== 'object') return false;
      const maybe = item as Partial<AgentMessage>;
      return typeof maybe.role === 'string';
    });
  }

  private runToolWithDaemonPolicy(
    name: string,
    argsJson: string,
    signal?: AbortSignal
  ): Promise<string> {
    if (name === 'ask_user') {
      return Promise.resolve(
        'Error: ask_user is unavailable in daemon mode. Resolve permissions from an attached client instead.'
      );
    }
    return this.toolWorkers.runTool(name, argsJson, signal);
  }

  private async runToolWithCache(
    session: ManagedSession,
    name: string,
    argsJson: string,
    signal?: AbortSignal
  ): Promise<string> {
    // Write tools: execute then clear the entire session cache
    if (WRITE_TOOLS.has(name)) {
      const result = await this.runToolWithDaemonPolicy(name, argsJson, signal);
      session.toolCache.clear();
      return result;
    }

    if (!CACHEABLE_TOOLS.has(name)) {
      return this.runToolWithDaemonPolicy(name, argsJson, signal);
    }

    const key = `${name}:${argsJson}`;
    const now = Date.now();
    const cached = session.toolCache.get(key);

    if (cached) {
      if (MTIME_TOOLS.has(name) && cached.fileMtimeMs !== undefined) {
        // Validate by checking current mtime
        try {
          const args = JSON.parse(argsJson) as { path?: string };
          const filePath = args.path;
          if (filePath) {
            const stat = statSync(filePath, { throwIfNoEntry: false });
            if (stat && stat.mtimeMs === cached.fileMtimeMs) return cached.result;
            // Mtime changed — fall through to re-execute
            session.toolCache.delete(key);
          } else {
            return cached.result;
          }
        } catch {
          return cached.result;
        }
      } else if (now - cached.cachedAt < CACHE_TTL_MS) {
        return cached.result;
      } else {
        session.toolCache.delete(key);
      }
    }

    const result = await this.runToolWithDaemonPolicy(name, argsJson, signal);

    // All code below is synchronous (no awaits), so concurrent JS turns cannot
    // interleave here.  We evict as many entries as needed so that after
    // inserting the new one the map stays at or below CACHE_MAX_SIZE.
    const overflow = session.toolCache.size - CACHE_MAX_SIZE + 1; // +1 for the entry we are about to add
    if (overflow > 0) {
      // Collect all entries sorted oldest-first and delete the required count.
      const sorted = [...session.toolCache.entries()].sort((a, b) => a[1].cachedAt - b[1].cachedAt);
      for (let i = 0; i < overflow && i < sorted.length; i++) {
        session.toolCache.delete(sorted[i]![0]);
      }
    }

    let fileMtimeMs: number | undefined;
    if (MTIME_TOOLS.has(name)) {
      try {
        const args = JSON.parse(argsJson) as { path?: string };
        if (args.path) {
          const stat = statSync(args.path, { throwIfNoEntry: false });
          if (stat) fileMtimeMs = stat.mtimeMs;
        }
      } catch {
        // Ignore stat errors; cache without mtime validation
      }
    }

    session.toolCache.set(key, { result, cachedAt: now, fileMtimeMs });
    return result;
  }

  private throwIfTurnAborted(session: ManagedSession): void {
    if (!session.activeAbort?.signal.aborted) return;
    const err = new Error('Turn cancelled');
    err.name = 'AbortError';
    throw err;
  }

  private newTurnError(message: string, code?: TurnErrorCode): CodedTurnError {
    const err = new Error(message) as CodedTurnError;
    if (code) err.turnErrorCode = code;
    return err;
  }

  private normalizeErrorCode(err: unknown): string | undefined {
    if (!err || typeof err !== 'object') return undefined;
    const raw = (err as { code?: unknown }).code;
    return typeof raw === 'string' ? raw.toLowerCase() : undefined;
  }

  private inferTransportErrorCode(err: unknown, message: string): TurnErrorCode | undefined {
    const lower = message.toLowerCase();
    const code = this.normalizeErrorCode(err);

    if (
      code === 'econnrefused' ||
      lower.includes('econnrefused') ||
      lower.includes('connection refused')
    ) {
      return 'lmx-connection-refused';
    }

    if (
      code === 'econnreset' ||
      lower.includes('econnreset') ||
      lower.includes('websocket closed') ||
      lower.includes('socket closed') ||
      lower.includes('socket hang up') ||
      lower.includes('connection closed')
    ) {
      return 'lmx-ws-closed';
    }

    if (
      code === 'etimedout' ||
      code === 'esockettimedout' ||
      code === 'econnaborted' ||
      lower.includes('timed out') ||
      lower.includes('timeout')
    ) {
      return 'lmx-timeout';
    }

    return undefined;
  }

  private resolveTurnErrorCode(err: unknown, message: string): TurnErrorCode | undefined {
    if (err && typeof err === 'object') {
      const coded = (err as { turnErrorCode?: unknown }).turnErrorCode;
      if (
        coded === 'no-model-loaded' ||
        coded === 'lmx-ws-closed' ||
        coded === 'lmx-timeout' ||
        coded === 'lmx-connection-refused'
      ) {
        return coded;
      }
    }

    if (message.toLowerCase().includes('no model loaded')) return 'no-model-loaded';
    return this.inferTransportErrorCode(err, message);
  }

  private async runTurnModelPreflight(session: ManagedSession, config: OptaConfig): Promise<void> {
    if (config.provider.active !== 'lmx') return;

    this.throwIfTurnAborted(session);

    const targetModel = normalizeConfiguredModelId(session.model);
    let loadedModelIds: string[] = [];
    const now = Date.now();
    const cachedPreflight = this.preflightCache;
    if (cachedPreflight && now - cachedPreflight.cachedAt < PREFLIGHT_CACHE_TTL_MS) {
      loadedModelIds = cachedPreflight.modelIds;
    } else {
      try {
        const lmx = new LmxClient({
          host: config.connection.host,
          fallbackHosts: config.connection.fallbackHosts,
          port: config.connection.port,
          adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
          timeoutMs: LMX_PREFLIGHT_TIMEOUT_MS,
          maxRetries: 0,
        });
        const loaded = await lmx.models({
          timeoutMs: LMX_PREFLIGHT_TIMEOUT_MS,
          maxRetries: 0,
        });
        loadedModelIds = loaded.models.map((model) => model.model_id);
        this.preflightCache = { modelIds: loadedModelIds, cachedAt: now };
      } catch (err) {
        this.throwIfTurnAborted(session);
        const detail = errorMessage(err);
        const code = this.inferTransportErrorCode(err, detail) ?? 'no-model-loaded';
        throw this.newTurnError(`${NO_MODEL_LOADED_MESSAGE} LMX preflight failed: ${detail}`, code);
      }
    }

    this.throwIfTurnAborted(session);
    if (loadedModelIds.length === 0) {
      throw this.newTurnError(NO_MODEL_LOADED_MESSAGE, 'no-model-loaded');
    }

    const canonicalModelId = targetModel
      ? findMatchingModelId(targetModel, loadedModelIds)
      : undefined;
    if (!canonicalModelId) {
      if (!targetModel) {
        throw this.newTurnError(
          `${NO_MODEL_LOADED_MESSAGE} Session model is not configured.`,
          'no-model-loaded'
        );
      }
      throw this.newTurnError(
        `${NO_MODEL_LOADED_MESSAGE} Session model "${session.model}" is not loaded.`,
        'no-model-loaded'
      );
    }

    if (session.model !== canonicalModelId) {
      session.model = canonicalModelId;
      session.updatedAt = new Date().toISOString();
      await this.persistSnapshot(session);
    }
  }

  private async processSessionQueue(sessionId: string): Promise<void> {
    const session = this.sessions.get(sessionId);
    if (!session || session.activeTurn) return;

    const turn = session.queue.dequeue();
    if (!turn) return;
    session.activeTurn = turn;
    session.activeAbort = new AbortController();
    session.updatedAt = new Date().toISOString();
    await this.persistSnapshot(session);

    const turnStart = Date.now();
    let firstTokenMs: number | null = null;
    let completionTokens = 0;
    let promptTokens = 0;
    let toolCalls = 0;

    try {
      const baseCfg = await this.getConfig();
      const cfg = this.buildTurnConfig(baseCfg, session, turn);
      await this.runTurnModelPreflight(session, cfg);
      this.throwIfTurnAborted(session);

      await this.emit(session, 'turn.start', {
        turnId: turn.turnId,
        writerId: turn.writerId,
        clientId: turn.clientId,
        mode: turn.mode,
      });

      const formattedTask = this.buildTurnTask(turn.content, turn.overrides?.format);
      const run = await agentLoop(formattedTask, cfg, {
        mode: cfg.defaultMode,
        existingMessages: session.messages,
        sessionId,
        silent: true,
        signal: session.activeAbort.signal,
        toolExecutor: (name, argsJson, signal) =>
          this.runToolWithCache(session, name, argsJson, signal),
        onSubAgentSpawn: (id, label, dependsOn) => {
          const payload: AgentPhaseEventPayload = {
            turnId: turn.turnId,
            phase: 'spawn_subagent',
            agentId: id,
            agentType: label,
            dependsOn,
          };
          void this.emit(session, 'agent.phase', payload);
        },
        onSubAgentProgress: (progress) => {
          const payload: AgentPhaseEventPayload = {
            turnId: turn.turnId,
            phase: progress.phase,
            agentId: progress.agentId,
            taskDescription: progress.taskDescription,
            toolName: progress.toolName,
            toolCallCount: progress.toolCallCount,
            elapsedMs: progress.elapsedMs,
          };
          void this.emit(session, 'agent.phase', payload);
        },
        onSubAgentDone: (agentId, result) => {
          const payload: AgentPhaseEventPayload = {
            turnId: turn.turnId,
            phase: 'return_to_main',
            agentId,
            resultPreview: result.slice(0, 280),
          };
          void this.emit(session, 'agent.phase', payload);
        },
        onStream: {
          // NOTE: these streaming callbacks are synchronous, so emit() cannot
          // be awaited inline.  Events are fire-and-forget here; sequence
          // numbers assigned inside emit() may interleave if emit() is slow
          // (e.g. during a persistence flush under I/O pressure).  For strict
          // ordering guarantees, a serial emit queue would be required.
          onToken: (text) => {
            if (firstTokenMs === null) firstTokenMs = Date.now() - turnStart;
            completionTokens += Math.ceil(text.length / CHARS_PER_TOKEN);
            void this.emit(session, 'turn.token', { turnId: turn.turnId, text });
          },
          onThinking: (text) => {
            void this.emit(session, 'turn.thinking', { turnId: turn.turnId, text });
          },
          onToolStart: (name, id, args) => {
            toolCalls++;
            void this.emit(session, 'tool.start', { turnId: turn.turnId, name, id, args });
          },
          onToolEnd: (name, id, result) => {
            void this.emit(session, 'tool.end', { turnId: turn.turnId, name, id, result });
          },
          onUsage: (usage) => {
            promptTokens = usage.promptTokens;
          },
          onAtpoState: (state) => {
            if (state.status === 'intervening') {
              const payload: AtpoInterveneEventPayload = {
                turnId: turn.turnId,
                status: 'intervening',
                provider: state.provider,
                reason: state.message,
              };
              void this.emit(session, 'atpo.intervene', payload);
              return;
            }
            void this.emit(session, 'turn.progress', {
              turnId: turn.turnId,
              phase: `atpo.${state.status}`,
              message: state.message ?? null,
              provider: state.provider ?? null,
            });
          },
          onPermissionRequest: async (toolName, args) => {
            const { request, decision } = this.permissionCoordinator.request(
              sessionId,
              toolName,
              args
            );
            await this.emit(session, 'permission.request', {
              turnId: turn.turnId,
              requestId: request.requestId,
              toolName,
              args,
            });
            const resolved = await decision;
            await this.emit(session, 'permission.resolved', {
              turnId: turn.turnId,
              requestId: request.requestId,
              decision: resolved,
            });
            return resolved;
          },
        },
      });

      session.messages = run.messages;
      session.toolCallCount += run.toolCallCount;
      session.updatedAt = new Date().toISOString();

      const elapsed = (Date.now() - turnStart) / 1000;
      this.latencyWindow.record(elapsed * 1000);
      const payload: TurnDonePayload = {
        turnId: turn.turnId,
        writerId: turn.writerId,
        clientId: turn.clientId,
        stats: {
          tokens: completionTokens,
          promptTokens,
          completionTokens,
          toolCalls,
          elapsed,
          speed: elapsed > 0.1 ? completionTokens / elapsed : 0,
          firstTokenLatencyMs: firstTokenMs,
        },
      };
      await this.emit(session, 'turn.done', payload);
      await this.emit(session, 'session.updated', {
        snapshot: this.sessionToSnapshot(session),
      });
      await this.persistSnapshot(session);
    } catch (err) {
      const aborted = err instanceof Error && err.name === 'AbortError';
      const message = aborted ? 'Turn cancelled' : errorMessage(err);
      const code = aborted ? undefined : this.resolveTurnErrorCode(err, message);
      const payload: TurnErrorPayload = {
        turnId: turn.turnId,
        writerId: turn.writerId,
        clientId: turn.clientId,
        message,
      };
      if (code) {
        payload.code = code;
        if (code === 'no-model-loaded' || code === 'lmx-connection-refused' || code === 'lmx-ws-closed' || code === 'lmx-timeout') {
          this.preflightCache = null;
        }
      }

      await this.emit(session, 'turn.error', payload);
      if (!aborted) {
        await logDaemonEvent({
          level: 'error',
          daemonId: this.daemonId,
          sessionId,
          msg: 'turn processing failed',
          data: { turnId: turn.turnId, message },
        });
      }
    } finally {
      session.activeTurn = undefined;
      session.activeAbort = undefined;
      session.updatedAt = new Date().toISOString();
      await this.persistSnapshot(session);
      if (session.queue.size > 0) {
        setImmediate(() => {
          void this.processSessionQueue(sessionId);
        });
      }
    }
  }

  private async persistSnapshot(session: ManagedSession): Promise<void> {
    const stored: StoredSessionSnapshot = {
      sessionId: session.sessionId,
      model: session.model,
      title: session.title,
      createdAt: session.createdAt,
      updatedAt: session.updatedAt,
      messages: session.messages,
      toolCallCount: session.toolCallCount,
      seq: session.seq,
    };
    await writeSessionSnapshot(stored);
  }

  private async handleBackgroundEvent(event: BackgroundManagerEvent): Promise<void> {
    const session = this.sessions.get(event.sessionId);
    if (!session) return;

    if (event.type === 'output') {
      await this.emit(session, 'background.output', event.payload);
    } else {
      await this.emit(session, 'background.status', event.payload);
    }
    session.updatedAt = new Date().toISOString();
    await this.persistSnapshot(session);
  }

  private async refreshBackgroundOptions(): Promise<void> {
    const config = await this.getConfig();
    this.backgroundManager.updateOptions({
      maxConcurrent: config.background.maxConcurrent,
      defaultTimeout: config.background.defaultTimeout,
      maxBufferSize: config.background.maxBufferSize,
    });
  }

  private async emit(
    session: ManagedSession,
    event: V3Envelope['event'],
    payload: unknown
  ): Promise<void> {
    session.seq += 1;
    const envelope = makeEnvelope(
      {
        daemonId: this.daemonId,
        sessionId: session.sessionId,
        seq: session.seq,
      },
      event,
      payload
    );

    // High-frequency streaming events are delivered to live subscribers but not
    // written to disk — they are ephemeral. Reconnecting clients get the complete
    // final content from the session snapshot once the turn finishes.
    if (event !== 'turn.token' && event !== 'turn.thinking') {
      await appendSessionEvent(session.sessionId, envelope);
    }
    const watchers = this.subscribers.get(session.sessionId);
    if (watchers) {
      for (const cb of watchers) {
        try {
          cb(envelope);
        } catch {
          // Ignore subscriber errors so one bad client does not poison the session.
        }
      }
    }
  }

  private buildTurnConfig(config: OptaConfig, session: ManagedSession, turn: QueuedTurn): OptaConfig {
    const normalizedTurnMode = this.normalizeTurnMode(turn.mode);
    const overrides = turn.overrides ?? {};
    const providerOverride = this.normalizeProviderOverride(overrides.provider);
    const modelOverride = this.normalizeModelOverride(overrides.model);
    const autonomyModeOverride = this.normalizeAutonomyModeOverride(overrides.autonomyMode);
    const autonomyLevelOverride = this.normalizeAutonomyLevelOverride(overrides.autonomyLevel);

    // Model override is treated as the active session model for subsequent turns.
    if (modelOverride) {
      session.model = modelOverride;
      session.updatedAt = new Date().toISOString();
    }

    const defaultMode =
      overrides.dangerous === true
        ? 'dangerous'
        : overrides.auto === true
          ? 'auto'
          : normalizedTurnMode ?? config.defaultMode;

    const gitOverrides = {
      autoCommit: overrides.noCommit === true ? false : (config.git?.autoCommit ?? true),
      checkpoints: overrides.noCheckpoints === true ? false : (config.git?.checkpoints ?? true),
    };

    return {
      ...config,
      defaultMode,
      git: gitOverrides,
      provider: providerOverride ? { ...config.provider, active: providerOverride } : config.provider,
      model: modelOverride ? { ...config.model, default: modelOverride } : config.model,
      autonomy:
        autonomyModeOverride !== null || autonomyLevelOverride !== null
          ? {
              ...config.autonomy,
              mode: autonomyModeOverride ?? config.autonomy.mode,
              level: autonomyLevelOverride ?? config.autonomy.level,
            }
          : config.autonomy,
    };
  }

  private normalizeTurnMode(mode: QueuedTurn['mode']): OptaConfig['defaultMode'] | null {
    switch (mode) {
      case 'do':
        return 'auto';
      case 'plan':
      case 'review':
      case 'research':
        return mode;
      case 'chat':
      default:
        return null;
    }
  }

  private normalizeProviderOverride(provider?: string): OptaConfig['provider']['active'] | null {
    if (!provider) return null;
    const normalized = provider.trim().toLowerCase();
    if (!normalized) return null;
    if (!PROVIDER_OVERRIDE_SET.has(normalized)) return null;
    return normalized as OptaConfig['provider']['active'];
  }

  private normalizeModelOverride(model?: string): string | null {
    if (!model) return null;
    const normalized = normalizeConfiguredModelId(model.trim());
    return normalized || null;
  }

  private normalizeAutonomyModeOverride(mode?: string): OptaConfig['autonomy']['mode'] | null {
    if (!mode) return null;
    const normalized = mode.trim().toLowerCase();
    if (normalized === 'execution' || normalized === 'ceo') {
      return normalized;
    }
    return null;
  }

  private normalizeAutonomyLevelOverride(level?: number): number | null {
    if (typeof level !== 'number' || !Number.isFinite(level)) return null;
    const clamped = Math.max(1, Math.min(5, Math.trunc(level)));
    return clamped;
  }

  private normalizeTurnFormat(format?: string): TurnOutputFormat | null {
    if (!format) return null;
    switch (format.trim().toLowerCase()) {
      case 'markdown':
      case 'text':
      case 'json':
        return format.trim().toLowerCase() as TurnOutputFormat;
      default:
        return null;
    }
  }

  private buildTurnTask(content: string, format?: string): string {
    const normalizedFormat = this.normalizeTurnFormat(format);
    if (!normalizedFormat || normalizedFormat === 'markdown') return content;
    if (normalizedFormat === 'text') {
      return `${content}\n\nOutput requirement: respond in plain text only. Avoid markdown formatting.`;
    }
    return `${content}\n\nOutput requirement: return valid JSON only. Do not use markdown fences or explanatory prose outside JSON.`;
  }
}

import { parentPort } from 'node:worker_threads';

interface ToolJob {
  id: string;
  tool: string;
  argsJson: string;
}

let cachedExecuteTool: ((name: string, argsJson: string) => Promise<string>) | null = null;
let runtimeReady = false;

async function ensureRuntimeReady(): Promise<void> {
  if (runtimeReady) return;
  runtimeReady = true;
  if (import.meta.url.endsWith('.ts')) {
    const { register } = await import('tsx/esm/api');
    register();
  }
}

async function loadExecuteTool(): Promise<(name: string, argsJson: string) => Promise<string>> {
  if (cachedExecuteTool) return cachedExecuteTool;
  await ensureRuntimeReady();
  const mod = await import('../core/tools/executors.js');
  const executeTool = (mod as { executeTool?: (name: string, argsJson: string) => Promise<string> })
    .executeTool;
  if (typeof executeTool !== 'function') {
    throw new Error('Worker tool runtime missing executeTool export');
  }
  cachedExecuteTool = executeTool;
  return executeTool;
}

if (parentPort) {
  parentPort.on('message', (job: ToolJob) => {
    void (async () => {
      try {
        const executeTool = await loadExecuteTool();
        const result = await executeTool(job.tool, job.argsJson);
        parentPort!.postMessage({ id: job.id, ok: true, result });
      } catch (err) {
        parentPort!.postMessage({
          id: job.id,
          ok: false,
          error: err instanceof Error ? err.message : String(err),
        });
      }
    })();
  });
}

import { existsSync } from 'node:fs';
import { cpus } from 'node:os';
import { dirname, join } from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';
import { Worker } from 'node:worker_threads';
import { nanoid } from 'nanoid';

interface WorkerResponse {
  id: string;
  ok: boolean;
  result?: string;
  error?: string;
}

interface ToolJob {
  id: string;
  tool: string;
  argsJson: string;
  signal?: AbortSignal;
  aborted: boolean;
  settled: boolean;
  onAbort?: () => void;
  resolve: (value: string) => void;
  reject: (err: Error) => void;
}

interface WorkerSlot {
  worker: Worker;
  busy: boolean;
  disposed: boolean;
  currentJob?: ToolJob;
  lastIdleAt?: number;
}

function makeAbortError(message: string): Error {
  const err = new Error(message);
  err.name = 'AbortError';
  return err;
}

export class ToolWorkerPool {
  private static readonly IDLE_REAP_MS = 60_000;
  private static readonly REAPER_INTERVAL_MS = 30_000;

  private readonly maxWorkers: number;
  private readonly minWorkers: number;
  private readonly queue: ToolJob[] = [];
  private readonly workers: WorkerSlot[] = [];
  private closed = false;
  private reaperTimer: ReturnType<typeof setInterval> | null = null;

  constructor(maxWorkers: number = defaultWorkerCount(), minWorkers: number = 2) {
    this.maxWorkers = Math.max(1, maxWorkers);
    this.minWorkers = Math.min(Math.max(0, minWorkers), this.maxWorkers);
    this.startReaper();
  }

  private startReaper(): void {
    this.reaperTimer = setInterval(() => {
      this.reapIdleWorkers();
    }, ToolWorkerPool.REAPER_INTERVAL_MS);
    // Allow Node.js to exit even when the reaper timer is active
    this.reaperTimer.unref();
  }

  private reapIdleWorkers(): void {
    if (this.closed) return;
    const now = Date.now();
    const idleSlots = this.workers
      .filter((slot) => !slot.busy && !slot.disposed && slot.lastIdleAt !== undefined)
      .sort((a, b) => (a.lastIdleAt ?? 0) - (b.lastIdleAt ?? 0)); // oldest idle first

    const liveCount = this.workers.filter((s) => !s.disposed).length;
    const reaperBudget = Math.max(0, liveCount - this.minWorkers);

    let reaped = 0;
    for (const slot of idleSlots) {
      if (reaped >= reaperBudget) break;
      if ((slot.lastIdleAt ?? now) + ToolWorkerPool.IDLE_REAP_MS <= now) {
        this.detachWorker(slot);
        reaped++;
      }
    }
  }

  async runTool(tool: string, argsJson: string, signal?: AbortSignal): Promise<string> {
    if (this.closed) {
      throw new Error('Tool worker pool is closed');
    }
    if (signal?.aborted) {
      throw makeAbortError('Tool execution cancelled');
    }

    return new Promise<string>((resolve, reject) => {
      const job: ToolJob = {
        id: nanoid(10),
        tool,
        argsJson,
        signal,
        aborted: false,
        settled: false,
        resolve,
        reject,
      };

      if (signal) {
        const onAbort = () => {
          this.abortJob(job);
        };
        job.onAbort = onAbort;
        signal.addEventListener('abort', onAbort, { once: true });
      }

      this.queue.push(job);
      this.dispatch();
    });
  }

  close(): void {
    this.closed = true;
    if (this.reaperTimer !== null) {
      clearInterval(this.reaperTimer);
      this.reaperTimer = null;
    }

    while (this.queue.length > 0) {
      const job = this.queue.shift();
      if (!job) continue;
      this.rejectJob(job, new Error('Tool worker pool closed'));
    }

    const snapshots = [...this.workers];
    for (const slot of snapshots) {
      if (slot.currentJob) {
        this.rejectJob(slot.currentJob, new Error('Tool worker pool closed'));
        slot.currentJob = undefined;
      }
      this.detachWorker(slot);
    }
  }

  getStats(): { workers: number; busy: number; queued: number } {
    const workers = this.workers.length;
    const busy = this.workers.reduce((count, slot) => count + (slot.busy ? 1 : 0), 0);
    return { workers, busy, queued: this.queue.length };
  }

  /**
   * Pre-spawn idle workers so the first tool call experiences no cold-start
   * latency from Worker thread creation (~30-80 ms each).
   */
  warmUp(count: number = 2): void {
    if (this.closed) return;
    const toCreate = Math.min(count, this.maxWorkers) - this.workers.length;
    for (let i = 0; i < toCreate; i++) {
      this.createWorker();
    }
  }

  private dispatch(): void {
    if (this.closed) return;

    while (this.queue.length > 0) {
      const nextWorker = this.getIdleOrCreateWorker();
      if (!nextWorker) return;
      const nextJob = this.queue.shift();
      if (!nextJob) return;
      if (nextJob.aborted) {
        this.rejectJob(nextJob, makeAbortError('Tool execution cancelled'));
        continue;
      }
      this.assignJob(nextWorker, nextJob);
    }
  }

  private getIdleOrCreateWorker(): WorkerSlot | null {
    const idle = this.workers.find((slot) => !slot.busy && !slot.disposed);
    if (idle) return idle;
    if (this.workers.length >= this.maxWorkers) return null;
    return this.createWorker();
  }

  private createWorker(): WorkerSlot {
    const workerPath = this.resolveWorkerPath();
    const execArgv = workerPath.pathname.endsWith('.ts') ? ['--import', 'tsx'] : [];
    const worker = new Worker(workerPath, { execArgv });

    const slot: WorkerSlot = {
      worker,
      busy: false,
      disposed: false,
      lastIdleAt: Date.now(),
    };

    worker.on('message', (message: WorkerResponse) => {
      if (slot.disposed || !slot.currentJob) return;
      const job = slot.currentJob;
      if (message.id !== job.id) return;
      slot.currentJob = undefined;
      slot.busy = false;
      slot.lastIdleAt = Date.now();
      if (message.ok) {
        this.resolveJob(job, message.result ?? '');
      } else {
        this.rejectJob(job, new Error(message.error ?? 'Unknown worker error'));
      }
      this.dispatch();
    });

    worker.on('error', (err) => {
      if (slot.disposed) return;
      this.failWorker(slot, err instanceof Error ? err : new Error(String(err)));
    });

    worker.on('exit', (code) => {
      if (slot.disposed) return;
      const error =
        code === 0
          ? new Error('Worker exited before returning a result')
          : new Error(`Worker exited with code ${code}`);
      this.failWorker(slot, error);
    });

    this.workers.push(slot);
    return slot;
  }

  private assignJob(slot: WorkerSlot, job: ToolJob): void {
    slot.busy = true;
    slot.currentJob = job;
    slot.worker.postMessage({
      id: job.id,
      tool: job.tool,
      argsJson: job.argsJson,
    });
  }

  private failWorker(slot: WorkerSlot, err: Error): void {
    const job = slot.currentJob;
    slot.currentJob = undefined;
    slot.busy = false;
    if (job) {
      this.rejectJob(job, err);
    }
    this.detachWorker(slot);
    this.dispatch();
  }

  private detachWorker(slot: WorkerSlot): void {
    if (slot.disposed) return;
    slot.disposed = true;
    const idx = this.workers.indexOf(slot);
    if (idx >= 0) {
      this.workers.splice(idx, 1);
    }
    slot.worker.removeAllListeners();
    void slot.worker.terminate();
  }

  private abortJob(job: ToolJob): void {
    if (job.settled || job.aborted) return;
    job.aborted = true;

    const queuedIndex = this.queue.findIndex((item) => item.id === job.id);
    if (queuedIndex >= 0) {
      this.queue.splice(queuedIndex, 1);
      this.rejectJob(job, makeAbortError('Tool execution cancelled'));
      return;
    }

    const active = this.workers.find((slot) => slot.currentJob?.id === job.id);
    if (!active || !active.currentJob) return;
    this.rejectJob(job, makeAbortError('Tool execution cancelled'));
    active.currentJob = undefined;
    active.busy = false;
    // NOTE: detachWorker calls worker.terminate() fire-and-forget.  The OS
    // thread may still be alive for a brief period after this returns.  This
    // is an accepted limitation — Node Worker threads have no synchronous
    // termination API.  dispatch() immediately allocates a new worker slot
    // for the next queued job rather than waiting for the old one to exit.
    this.detachWorker(active);
    this.dispatch();
  }

  private resolveJob(job: ToolJob, value: string): void {
    if (job.settled) return;
    job.settled = true;
    if (job.signal && job.onAbort) {
      job.signal.removeEventListener('abort', job.onAbort);
    }
    job.resolve(value);
  }

  private rejectJob(job: ToolJob, err: Error): void {
    if (job.settled) return;
    job.settled = true;
    if (job.signal && job.onAbort) {
      job.signal.removeEventListener('abort', job.onAbort);
    }
    job.reject(err);
  }

  private resolveWorkerPath(): URL {
    const selfPath = fileURLToPath(import.meta.url);
    const ext = selfPath.endsWith('.ts') ? '.ts' : '.js';
    const baseDir = dirname(selfPath);

    // Source layout: src/daemon/worker-pool.ts -> src/daemon/worker-pool-worker.ts
    // Bundled layout: dist/chunk-*.js -> dist/daemon/worker-pool-worker.js
    const candidates = [
      join(baseDir, `worker-pool-worker${ext}`),
      join(baseDir, 'daemon', `worker-pool-worker${ext}`),
      join(baseDir, '..', 'daemon', `worker-pool-worker${ext}`),
    ];

    const found = candidates.find((p) => existsSync(p));
    return pathToFileURL(found ?? candidates[0]!);
  }
}

function defaultWorkerCount(): number {
  const envRaw = process.env['OPTA_DAEMON_TOOL_WORKERS'];
  if (envRaw) {
    const parsed = Number.parseInt(envRaw, 10);
    if (Number.isFinite(parsed) && parsed > 0) {
      return parsed;
    }
  }
  const cpuCount = cpus().length;
  return Math.max(1, Math.min(8, cpuCount - 1));
}

/**
 * Checkpoint system for Opta CLI.
 *
 * Saves git diffs as patch files after each file-modifying tool call,
 * allowing mid-task undo via `git apply -R`.
 *
 * Checkpoint directory layout:
 *   <cwd>/.opta/checkpoints/<sessionId>/
 *     index.json   — metadata for all checkpoints in this session
 *     1.patch      — diff patch for checkpoint #1
 *     2.patch      — diff patch for checkpoint #2
 *     ...
 */

import { mkdir, writeFile, readFile, rm } from 'node:fs/promises';
import { join } from 'node:path';
import { execa } from 'execa';
import { gitDiff } from './utils.js';

/**
 * Metadata for a single checkpoint.
 */
export interface Checkpoint {
  n: number;
  tool: string;
  path: string;
  timestamp: string;
}

/**
 * Shape of the index.json file stored in each session's checkpoint directory.
 */
interface CheckpointIndex {
  session: string;
  checkpoints: Checkpoint[];
}

/**
 * Returns the checkpoint directory path for a given session.
 */
function checkpointDir(cwd: string, sessionId: string): string {
  return join(cwd, '.opta', 'checkpoints', sessionId);
}

/**
 * Creates a checkpoint by saving the current diff for `filePath` as a patch file.
 *
 * No-op if the file has no changes (empty diff).
 */
export async function createCheckpoint(
  cwd: string,
  sessionId: string,
  n: number,
  tool: string,
  filePath: string,
): Promise<void> {
  const diff = await gitDiff(cwd, filePath);
  if (!diff) return; // No changes — nothing to checkpoint

  const dir = checkpointDir(cwd, sessionId);
  await mkdir(dir, { recursive: true });

  // Write the patch file.
  // execa strips the trailing newline from stdout, but git apply requires it.
  const patchContent = diff.endsWith('\n') ? diff : diff + '\n';
  const patchPath = join(dir, `${n}.patch`);
  await writeFile(patchPath, patchContent, 'utf-8');

  // Read or create index.json
  const indexPath = join(dir, 'index.json');
  let index: CheckpointIndex;
  try {
    const raw = await readFile(indexPath, 'utf-8');
    index = JSON.parse(raw) as CheckpointIndex;
  } catch (err) {
    const code = (err as NodeJS.ErrnoException | undefined)?.code;
    if (code !== 'ENOENT' && code !== 'ENOTDIR') {
      console.error(`Failed to read checkpoint index at ${indexPath}, creating new:`, err);
    }
    index = { session: sessionId, checkpoints: [] };
  }

  // Append the new checkpoint
  index.checkpoints.push({
    n,
    tool,
    path: filePath,
    timestamp: new Date().toISOString(),
  });

  await writeFile(indexPath, JSON.stringify(index, null, 2), 'utf-8');
}

/**
 * Returns all checkpoints for a session, in order.
 * Returns an empty array if the session has no checkpoints.
 */
export async function listCheckpoints(
  cwd: string,
  sessionId: string,
): Promise<Checkpoint[]> {
  const indexPath = join(checkpointDir(cwd, sessionId), 'index.json');
  try {
    const raw = await readFile(indexPath, 'utf-8');
    const index = JSON.parse(raw) as CheckpointIndex;
    return index.checkpoints;
  } catch {
    return [];
  }
}

/**
 * Undoes a checkpoint by applying its patch in reverse.
 *
 * Without `n`, undoes the last checkpoint.
 * With `n`, undoes the specific checkpoint.
 */
export async function undoCheckpoint(
  cwd: string,
  sessionId: string,
  n?: number,
): Promise<void> {
  const checkpoints = await listCheckpoints(cwd, sessionId);
  if (checkpoints.length === 0) {
    throw new Error(`No checkpoints found for session "${sessionId}"`);
  }

  const targetN = n ?? checkpoints[checkpoints.length - 1]!.n;
  const patchPath = join(checkpointDir(cwd, sessionId), `${targetN}.patch`);

  await execa('git', ['apply', '-R', patchPath], { cwd });
}

/**
 * Reads the raw patch content for a specific checkpoint.
 * Returns an empty string if the patch file does not exist.
 */
export async function readPatchContent(
  cwd: string,
  sessionId: string,
  n: number,
): Promise<string> {
  const patchPath = join(checkpointDir(cwd, sessionId), `${n}.patch`);
  try {
    return await readFile(patchPath, 'utf-8');
  } catch {
    return '';
  }
}

/**
 * Computes a diff stat summary (additions, deletions) from a patch string.
 * Returns { additions, deletions } line counts.
 */
export function patchStat(patch: string): { additions: number; deletions: number } {
  let additions = 0;
  let deletions = 0;
  for (const line of patch.split('\n')) {
    if (line.startsWith('+') && !line.startsWith('+++')) additions++;
    if (line.startsWith('-') && !line.startsWith('---')) deletions++;
  }
  return { additions, deletions };
}

/**
 * Undoes ALL checkpoints for a session, in reverse order.
 * Throws if any individual undo fails.
 */
export async function undoAllCheckpoints(
  cwd: string,
  sessionId: string,
): Promise<number> {
  const checkpoints = await listCheckpoints(cwd, sessionId);
  if (checkpoints.length === 0) {
    throw new Error(`No checkpoints found for session "${sessionId}"`);
  }

  // Undo in reverse order to avoid patch conflicts
  const reversed = [...checkpoints].reverse();
  let undone = 0;
  for (const cp of reversed) {
    const patchPath = join(checkpointDir(cwd, sessionId), `${cp.n}.patch`);
    try {
      await execa('git', ['apply', '-R', patchPath], { cwd });
      undone++;
    } catch {
      // Patch may not apply cleanly if already reverted — skip
    }
  }
  return undone;
}

/**
 * Removes all checkpoint data for a session.
 * No-op if the session directory doesn't exist.
 */
export async function cleanupCheckpoints(
  cwd: string,
  sessionId: string,
): Promise<void> {
  const dir = checkpointDir(cwd, sessionId);
  await rm(dir, { recursive: true, force: true });
}

/**
 * Auto-commit module for Opta CLI.
 *
 * Generates commit messages via the LLM and commits session changes.
 * Uses `execa` with array arguments (no shell interpolation)
 * and `reject: false` for safe error handling.
 */

import { execa } from 'execa';
import { debug } from '../core/debug.js';
import type { AgentMessage } from '../core/agent.js';

/**
 * Extracts user + assistant messages into a text summary
 * suitable for commit message generation.
 *
 * Filters to only user and assistant roles (with content),
 * truncates each message to 200 characters.
 */
export function getSessionSummary(messages: AgentMessage[]): string {
  return messages
    .filter((m) => (m.role === 'user' || m.role === 'assistant') && m.content != null)
    .map((m) => {
      const raw = m.content!;
      const content = Array.isArray(raw)
        ? raw.map((p) => (typeof p === 'string' ? p : JSON.stringify(p))).join('')
        : raw;
      const truncated = content.length > 200 ? content.slice(0, 200) + '...' : content;
      return `[${m.role}] ${truncated}`;
    })
    .join('\n');
}

/**
 * Sends a session summary to the LLM to generate a conventional commit message.
 * Falls back to a default message on error.
 */
export async function generateCommitMessage(
  messages: AgentMessage[],
  client: import('openai').default,
  model: string
): Promise<string> {
  const summary = getSessionSummary(messages);
  const fallback = 'feat: apply AI-assisted changes';

  if (!summary.trim()) return fallback;

  try {
    const response = await client.chat.completions.create({
      model,
      messages: [
        {
          role: 'system',
          content:
            'Generate a concise git commit message (max 72 chars for subject line) for these changes. Use conventional commit format (feat/fix/refactor/docs). Reply with ONLY the commit message, no explanation.',
        },
        { role: 'user', content: summary },
      ],
      max_tokens: 100,
    });

    const message = response.choices[0]?.message?.content?.trim();
    if (!message) return fallback;

    return message;
  } catch (err) {
    debug(`Failed to generate commit message: ${String(err)}`);
    return fallback;
  }
}

/**
 * Stages specified files via `git add`, verifies staged changes exist,
 * then commits with the given message.
 *
 * Returns true on success, false if nothing was staged or commit fails.
 */
export async function commitSessionChanges(
  cwd: string,
  files: string[],
  message: string
): Promise<boolean> {
  if (files.length === 0) {
    debug('commitSessionChanges: no files provided');
    return false;
  }

  // Stage the specified files
  const addResult = await execa('git', ['add', ...files], {
    cwd,
    reject: false,
  });

  if (addResult.exitCode !== 0) {
    debug(`git add failed: ${addResult.stderr}`);
    return false;
  }

  // Verify there are staged changes
  const diffResult = await execa('git', ['diff', '--cached', '--name-only'], {
    cwd,
    reject: false,
  });

  if (diffResult.exitCode !== 0 || !diffResult.stdout.trim()) {
    debug('No staged changes after git add');
    return false;
  }

  // Commit
  const commitResult = await execa('git', ['commit', '-m', message], {
    cwd,
    reject: false,
  });

  if (commitResult.exitCode !== 0) {
    debug(`git commit failed: ${commitResult.stderr}`);
    return false;
  }

  return true;
}

/**
 * Hook system for Opta CLI lifecycle events.
 *
 * Users configure shell commands that fire at lifecycle points (session start/end,
 * tool pre/post, compaction, errors). Zero hooks configured = zero cost via
 * NoOpHookManager singleton.
 */

import { execa } from 'execa';

// ── Types ───────────────────────────────────────────────────────────────

export type HookEvent =
  | 'session.start'
  | 'session.end'
  | 'tool.pre'
  | 'tool.post'
  | 'compact'
  | 'error';

export interface HookDefinition {
  event: HookEvent;
  command: string;
  matcher?: string;
  timeout?: number;
  background?: boolean;
}

export interface HookContext {
  event: HookEvent;
  session_id: string;
  cwd: string;
  tool_name?: string;
  tool_args?: string;
  tool_result?: string;
  error_message?: string;
  model?: string;
}

export interface HookResult {
  cancelled: boolean;
  reason?: string;
}

// ── Constants ───────────────────────────────────────────────────────────

const NOOP_RESULT: HookResult = Object.freeze({ cancelled: false });
const DEFAULT_TIMEOUT = 10_000;

/** Only these env vars are passed to hook subprocesses (security: prevents API key leaks). */
export const ALLOWED_ENV_KEYS = new Set([
  'PATH',
  'HOME',
  'USER',
  'SHELL',
  'TERM',
  'LANG',
  'LC_ALL',
  'NODE_ENV',
  'TMPDIR',
]);

// ── Compiled hook (internal) ────────────────────────────────────────────

interface CompiledHook extends HookDefinition {
  matcherRegex?: RegExp;
}

// ── HookManager ─────────────────────────────────────────────────────────

export class HookManager {
  protected readonly hooks: CompiledHook[];

  constructor(definitions: HookDefinition[]) {
    this.hooks = definitions.map((def) => ({
      ...def,
      matcherRegex: def.matcher ? new RegExp(def.matcher) : undefined,
    }));
  }

  /**
   * Factory: returns NoOpHookManager when no hooks are configured,
   * or a full HookManager when hooks exist.
   */
  static create(definitions?: HookDefinition[]): HookManager {
    if (!definitions || definitions.length === 0) {
      return noopSingleton;
    }
    return new HookManager(definitions);
  }

  /**
   * Fire all hooks matching the given event + context.
   * For tool.pre: non-zero exit code = cancellation.
   */
  async fire(event: HookEvent, context: HookContext): Promise<HookResult> {
    const matching = this.hooks.filter((h) => {
      if (h.event !== event) return false;
      // Matcher only applies to tool.pre / tool.post
      if (h.matcherRegex && context.tool_name) {
        return h.matcherRegex.test(context.tool_name);
      }
      // If hook has a matcher but no tool_name in context, skip
      if (h.matcherRegex && !context.tool_name) return false;
      return true;
    });

    for (const hook of matching) {
      if (hook.background) {
        // Fire and forget
        this.runHook(hook, context).catch(() => {});
        continue;
      }

      const result = await this.runHook(hook, context);
      // Only tool.pre can cancel
      if (event === 'tool.pre' && result.cancelled) {
        return result;
      }
    }

    return NOOP_RESULT;
  }

  /**
   * Execute a single hook command with env vars from context.
   */
  protected async runHook(hook: CompiledHook, context: HookContext): Promise<HookResult> {
    const env = this.buildEnv(context);
    const timeout = hook.timeout ?? DEFAULT_TIMEOUT;

    try {
      const [shell, shellFlag] = (await import('../platform/index.js')).shellArgs();
      const result = await execa(shell, [shellFlag, hook.command], {
        env,
        extendEnv: false,
        timeout,
        reject: false,
      });

      // Timeout — do not treat as cancellation
      if (result.timedOut) {
        return NOOP_RESULT;
      }

      // Only tool.pre hooks can cancel via non-zero exit
      if (context.event === 'tool.pre' && result.exitCode !== 0) {
        return {
          cancelled: true,
          reason: result.stderr?.trim() || 'Hook exited with non-zero status',
        };
      }
    } catch {
      // Timeout or other error — do not cancel, just swallow
    }

    return NOOP_RESULT;
  }

  /**
   * Build environment variables from HookContext.
   * Only passes an allowlist of safe env vars (PATH, HOME, etc.) plus OPTA_* vars.
   * This prevents leaking API keys or secrets to hook subprocesses.
   */
  protected buildEnv(context: HookContext): Record<string, string> {
    const env: Record<string, string> = {};

    // Only pass safe env vars from the allowlist
    for (const key of ALLOWED_ENV_KEYS) {
      const val = process.env[key];
      if (val !== undefined) env[key] = val;
    }

    // Also pass OPTA_* vars from process.env
    for (const [key, val] of Object.entries(process.env)) {
      if (key.startsWith('OPTA_') && val !== undefined) env[key] = val;
    }

    // Add hook-specific OPTA_ vars
    env.OPTA_EVENT = context.event;
    env.OPTA_SESSION_ID = context.session_id;
    env.OPTA_CWD = context.cwd;

    if (context.model) env['OPTA_MODEL'] = context.model;
    if (context.tool_name) env['OPTA_TOOL_NAME'] = context.tool_name;
    if (context.tool_args) env['OPTA_TOOL_ARGS'] = context.tool_args;
    if (context.tool_result) env['OPTA_TOOL_RESULT'] = context.tool_result.slice(0, 2048);
    if (context.error_message) env['OPTA_ERROR'] = context.error_message;

    return env;
  }
}

// ── NoOpHookManager ─────────────────────────────────────────────────────

export class NoOpHookManager extends HookManager {
  constructor() {
    super([]);
  }

  override fire(_event: HookEvent, _context: HookContext): Promise<HookResult> {
    return Promise.resolve(NOOP_RESULT);
  }
}

const noopSingleton = new NoOpHookManager();

#!/usr/bin/env node

import { Command, InvalidArgumentError } from 'commander';
import chalk from 'chalk';
import { VERSION } from './core/version.js';
import { EXIT, ExitError, OptaError, formatError } from './core/errors.js';
import { setVerbose, setDebug } from './core/debug.js';
import {
  parseProviderOverride,
  PROVIDER_OVERRIDE_NAMES,
  type ProviderOverrideName,
} from './utils/config-helpers.js';
import type { UpdateTargetMode } from './commands/update.js';

// --- SIGINT handler ---
export let isShuttingDown = false;

async function cleanup(): Promise<void> {
  try {
    const { shutdownProcessManager, forceKillAllProcesses } = await import('./core/tools/index.js');
    forceKillAllProcesses();
    shutdownProcessManager();
  } catch {
    // Best effort cleanup
  }
}

// Ensure unhandled promise rejections are surfaced cleanly rather than silently dying or spitting raw stack traces over the TUI.
process.on('unhandledRejection', (reason) => {
  if (isShuttingDown) return;
  const msg = reason instanceof Error ? reason.message : String(reason);
  if (msg.includes('read ECONNRESET') || msg.includes('write EPIPE')) return; // Ignore common silent network drops
  if (process.env['OPTA_DEBUG']) {
    console.error(chalk.red('\n[Unhandled Rejection]'), reason);
  }
});

process.on('uncaughtException', (err) => {
  if (isShuttingDown) return;
  if (process.env['OPTA_DEBUG']) {
    console.error(chalk.red('\n[Uncaught Exception]'), err);
  }
  process.exit(EXIT.ERROR);
});

process.on('SIGINT', () => {
  if (isShuttingDown) process.exit(EXIT.SIGINT); // Second SIGINT = force kill
  isShuttingDown = true;
  console.log('\n' + chalk.dim('Interrupted.'));

  // Grace timeout: force exit after 3 seconds if cleanup hangs
  const graceTimer = setTimeout(() => {
    process.exit(EXIT.SIGINT);
  }, 3000);
  graceTimer.unref(); // Don't keep process alive just for this timer

  void cleanup().finally(() => {
    clearTimeout(graceTimer);
    process.exit(EXIT.SIGINT);
  });
});

const program = new Command();

program
  .name('opta')
  .description('Agentic AI coding CLI powered by local LLMs')
  .version(VERSION, '-V, --version')
  .enablePositionalOptions()
  .passThroughOptions()
  .option('-v, --verbose', 'detailed output')
  .option('--debug', 'debug info including API calls')
  .option('-r, --resume <id>', 'resume a previous session')
  .option('--plan', 'plan mode — read-only, design implementation approach')
  .option('--review', 'code review mode — read-only, structured review output')
  .option('--research', 'research mode — explore ideas, gather information')
  .option('-m, --model <name>', 'override default model')
  .option('--provider <name>', 'override provider for this run (lmx|anthropic|gemini|openai|opencode_zen)', parseProviderOption)
  .option('--device <host[:port]>', 'target LLM network device host (optionally with port)')
  .option('-f, --format <type>', 'output format: text (default) or json')
  .option('--no-commit', 'disable auto-commit at task end')
  .option('--no-checkpoints', 'disable checkpoint creation')
  .option('-a, --auto', 'auto-accept file edits without prompting')
  .option('--dangerous', 'bypass all permission prompts')
  .option('--yolo', 'alias for --dangerous')
  .hook('preAction', (thisCommand) => {
    const opts = thisCommand.opts<{ verbose?: boolean; debug?: boolean }>();
    if (opts.verbose) setVerbose(true);
    if (opts.debug) setDebug(true);
  });

// Explicitly enable the 'help' command, allowing users to run `opta help`
program.addHelpCommand('help [command]', 'display help for command');

// Default action — launch chat/menu in interactive terminals, help in non-interactive contexts.
program.action(async () => {
  const opts = program.opts<ChatCommandOptions>();
  const interactive = process.stdin.isTTY && process.stdout.isTTY;
  if (!interactive && !opts.resume && !opts.plan && !opts.review && !opts.research) {
    program.outputHelp();
    return;
  }
  await applyDeviceOption(opts);
  await runChat({ ...opts, tui: true });
});

program
  .command('chat')
  .description('Start an interactive chat session')
  .option('-r, --resume <id>', 'resume a previous session')
  .option('--plan', 'plan mode — read-only, design implementation approach')
  .option('--review', 'code review mode — read-only, structured review output')
  .option('--research', 'research mode — explore ideas, gather information')
  .option('-m, --model <name>', 'override default model')
  .option('--provider <name>', 'override provider for this run (lmx|anthropic|gemini|openai|opencode_zen)', parseProviderOption)
  .option('--device <host[:port]>', 'target LLM network device host (optionally with port)')
  .option('-f, --format <type>', 'output format: text (default) or json')
  .option('--no-commit', 'disable auto-commit at task end')
  .option('--no-checkpoints', 'disable checkpoint creation')
  .option('-a, --auto', 'auto-accept file edits without prompting')
  .option('--dangerous', 'bypass all permission prompts')
  .option('--yolo', 'alias for --dangerous')
  .option('--tui', 'launch full-screen terminal UI (Ink)')
  .action(async (opts: ChatCommandOptions) => {
    await applyDeviceOption(opts);
    await runChat(opts);
  });

program
  .command('tui')
  .description('Launch full-screen terminal UI (alias for `opta chat --tui`)')
