import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { join, isAbsolute } from 'node:path';
import { hostname } from 'node:os';
import { execa } from 'execa';
import type { Session } from '../memory/store.js';

export interface SessionLogOptions {
  cwd?: string;
  logsDir?: string;
  user?: string;
  device?: string;
  timezone?: string;
  now?: Date;
}

export interface SessionLogResult {
  path: string;
  fileName: string;
}

interface FileChanges {
  created: Set<string>;
  modified: Set<string>;
  deleted: Set<string>;
}

interface DateTimeParts {
  date: string;
  time: string;
  compactTime: string;
}

const DEFAULT_LOGS_DIR = '12-Session-Logs';

function safeEnvUser(): string {
  return process.env['USER'] ?? process.env['USERNAME'] ?? 'unknown';
}

function safeDeviceName(): string {
  const raw = process.env['OPTA_DEVICE'] ?? hostname() ?? 'device';
  return raw.split('.')[0] ?? raw;
}

function toSessionText(input: Session['messages'][number]['content']): string {
  if (typeof input === 'string') return input;
  if (!Array.isArray(input)) return '';

  return input
    .map((part) => {
      if (part && typeof part === 'object' && 'type' in part && part.type === 'text' && 'text' in part) {
        const text = part.text;
        return typeof text === 'string' ? text : '';
      }
      return '';
    })
    .filter(Boolean)
    .join('\n');
}

function slugify(raw: string, fallback: string, maxLength = 48): string {
  const normalized = raw
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-{2,}/g, '-');

  if (!normalized) return fallback;
  return normalized.slice(0, maxLength).replace(/-+$/g, '') || fallback;
}

export function buildSessionLogFileName(
  parts: DateTimeParts,
  device: string,
  summary: string,
): string {
  const safeDevice = slugify(device, 'device', 24);
  const safeSummary = slugify(summary, 'session', 56);
  return `${parts.date}-${parts.compactTime}-${safeDevice}-${safeSummary}.md`;
}

function formatDuration(startIso: string | undefined, end: Date): string {
  const startMs = startIso ? Date.parse(startIso) : NaN;
  const endMs = end.getTime();
  const totalSeconds = Number.isFinite(startMs) ? Math.max(0, Math.round((endMs - startMs) / 1000)) : 0;

  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;

  return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
}

function localDateTimeParts(date: Date): DateTimeParts {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  const hour = String(date.getHours()).padStart(2, '0');
  const minute = String(date.getMinutes()).padStart(2, '0');

  return {
    date: `${year}-${month}-${day}`,
    time: `${hour}:${minute}`,
    compactTime: `${hour}${minute}`,
  };
}

function zonedDateTimeParts(date: Date, timezone?: string): DateTimeParts {
  if (!timezone || timezone === 'local') {
    return localDateTimeParts(date);
  }

  try {
    const formatter = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      hour12: false,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
    });

    const mapped = Object.fromEntries(
      formatter
        .formatToParts(date)
        .filter((part) => part.type !== 'literal')
        .map((part) => [part.type, part.value]),
    ) as Record<string, string>;

    const year = mapped['year'];
    const month = mapped['month'];
    const day = mapped['day'];
    const hour = mapped['hour'];
    const minute = mapped['minute'];

    if (!year || !month || !day || !hour || !minute) {
      return localDateTimeParts(date);
    }

    return {
      date: `${year}-${month}-${day}`,
      time: `${hour}:${minute}`,
      compactTime: `${hour}${minute}`,
    };
  } catch {
    return localDateTimeParts(date);
  }
}

async function detectRepoRoot(cwd: string): Promise<string> {
  const result = await execa('git', ['rev-parse', '--show-toplevel'], {
    cwd,
    reject: false,
  });

  if (result.exitCode === 0 && result.stdout.trim()) {
    return result.stdout.trim();
  }

  return cwd;
}

async function resolveLogsDir(baseCwd: string, configuredDir?: string): Promise<string> {
  const root = await detectRepoRoot(baseCwd);
  const dir = configuredDir?.trim() || DEFAULT_LOGS_DIR;
  return isAbsolute(dir) ? dir : join(root, dir);
}

export function parseGitStatusPorcelain(output: string): FileChanges {
  const created = new Set<string>();
  const modified = new Set<string>();
  const deleted = new Set<string>();

  for (const line of output.split('\n')) {
    if (!line.trim()) continue;
    const status = line.slice(0, 2);
    if (status.length < 2) continue;

    let file = line.slice(3).trim();
    if (!file) continue;

    if (status.includes('R') || status.includes('C')) {
      const renamedTo = file.split(' -> ').pop();
      if (renamedTo) file = renamedTo.trim();
    }

    if (status === '??' || status.includes('A')) {
      created.add(file);
      continue;
    }

    if (status.includes('D')) {
      deleted.add(file);
      continue;
    }

    modified.add(file);
  }

  return { created, modified, deleted };
}

async function collectGitChanges(cwd: string): Promise<FileChanges> {
  const result = await execa('git', ['status', '--porcelain'], {
    cwd,
    reject: false,
  });

  if (result.exitCode !== 0) {
    return { created: new Set(), modified: new Set(), deleted: new Set() };
  }

  return parseGitStatusPorcelain(result.stdout);
}

async function collectCheckpointPaths(cwd: string, sessionId: string): Promise<string[]> {
  const indexPath = join(cwd, '.opta', 'checkpoints', sessionId, 'index.json');

  try {
    const raw = await readFile(indexPath, 'utf-8');
    const parsed = JSON.parse(raw) as {
      checkpoints?: Array<{ path?: unknown }>;
    };

    return (parsed.checkpoints ?? [])
      .map((checkpoint) => checkpoint.path)
      .filter((path): path is string => typeof path === 'string' && path.trim().length > 0);
  } catch {
    return [];
  }
}

function mergeCheckpointPaths(changes: FileChanges, checkpointPaths: string[]): void {
  for (const path of checkpointPaths) {
    if (changes.created.has(path) || changes.modified.has(path) || changes.deleted.has(path)) continue;
    changes.modified.add(path);
  }
}

function markdownList(items: string[]): string {
  if (items.length === 0) return '- (none)';
  return items.map((item) => `- ${item}`).join('\n');
}

function extractIssues(session: Session): string[] {
  const issues: string[] = [];
  const issueRegex = /\b(error|failed|failure|exception|timeout|denied|invalid)\b/i;

  for (const message of session.messages ?? []) {
    const text = toSessionText(message.content).trim();
    if (!text) continue;
    if (!issueRegex.test(text)) continue;

    const compact = text.replace(/\s+/g, ' ').slice(0, 160);
    issues.push(compact);
    if (issues.length >= 5) break;
  }

  return issues;
}

function extractDecisions(session: Session): string[] {
  const decisions: string[] = [];
  const decisionRegex = /\b(decision|decided|choose|selected|plan|approach)\b/i;

  for (const message of session.messages ?? []) {
    if (message.role !== 'assistant') continue;
    const text = toSessionText(message.content).trim();
    if (!text) continue;
    if (!decisionRegex.test(text)) continue;

    const compact = text.replace(/\s+/g, ' ').slice(0, 160);
    decisions.push(compact);
    if (decisions.length >= 5) break;
  }

  return decisions;
}

function extractNextSteps(session: Session): string[] {
  const assistantMessages = (session.messages ?? []).filter((message) => message.role === 'assistant');
  const lastAssistant = assistantMessages[assistantMessages.length - 1];
  const text = lastAssistant ? toSessionText(lastAssistant.content).trim() : '';

  if (!text) {
    return ['Continue from the latest session context.'];
  }

  const compact = text.replace(/\s+/g, ' ');
  const sentence = compact.split(/(?<=[.!?])\s+/)[0] ?? compact;
  return [sentence.slice(0, 180)];
}

function renderSessionLogMarkdown(params: {
  session: Session;
  dateTime: DateTimeParts;
  user: string;
  device: string;
  duration: string;
  changes: FileChanges;
  checkpointCount: number;
}): string {
  const { session, dateTime, user, device, duration, changes, checkpointCount } = params;

  const userMessageCount = (session.messages ?? []).filter((message) => message.role === 'user').length;
  const assistantMessageCount = (session.messages ?? []).filter((message) => message.role === 'assistant').length;
  const issues = extractIssues(session);
  const decisions = extractDecisions(session);
  const nextSteps = extractNextSteps(session);

  const created = [...changes.created].sort();
  const modified = [...changes.modified].sort();
  const deleted = [...changes.deleted].sort();

  const tagLine = Array.isArray(session.tags) && session.tags.length > 0 ? session.tags.join(', ') : '(none)';

  return `---
date: ${dateTime.date}
time: ${dateTime.time}
device: ${device}
user: ${user}
model: ${session.model || 'unknown'}
duration: ${duration}
---

## Summary
- Session: ${session.id}
- Title: ${session.title || '(untitled)'}
- Messages: user=${userMessageCount}, assistant=${assistantMessageCount}
- Tool calls: ${session.toolCallCount ?? 0}

## Files Changed
### Created
${markdownList(created)}

### Modified
${markdownList(modified)}

### Deleted
${markdownList(deleted)}

## Status Changes
- Created: ${session.created || '(unknown)'}
- Updated: ${session.updated || '(unknown)'}
- Compacted: ${session.compacted ? 'yes' : 'no'}
- Checkpoints: ${checkpointCount}

## Decisions Made
${markdownList(decisions)}

## Issues Encountered
${markdownList(issues)}

## Next Steps
${markdownList(nextSteps)}

## Notes
- CWD: ${session.cwd || process.cwd()}
- Tags: ${tagLine}
`;
}

async function writeUniqueFile(dir: string, fileName: string, content: string): Promise<string> {
  const baseName = fileName.replace(/\.md$/, '');

  for (let attempt = 0; attempt < 50; attempt++) {
    const suffix = attempt === 0 ? '' : `-${attempt + 1}`;
    const candidate = join(dir, `${baseName}${suffix}.md`);

    try {
      await writeFile(candidate, content, { encoding: 'utf-8', flag: 'wx' });
      return candidate;
    } catch (err) {
      const code = (err as NodeJS.ErrnoException).code;
      if (code === 'EEXIST') continue;
      throw err;
    }
  }

  throw new Error(`Unable to create unique session log file for ${fileName}`);
}

export async function writeSessionLog(
  session: Session,
  options: SessionLogOptions = {},
): Promise<SessionLogResult> {
  const now = options.now ?? new Date();
  const timezone = options.timezone ?? 'local';
  const dateTime = zonedDateTimeParts(now, timezone);
  const user = options.user?.trim() || safeEnvUser();
  const device = options.device?.trim() || safeDeviceName();
  const baseCwd = options.cwd ?? session.cwd ?? process.cwd();
  const logsDir = await resolveLogsDir(baseCwd, options.logsDir);

  await mkdir(logsDir, { recursive: true });

  const summarySource = session.title || session.id || 'session';
  const fileName = buildSessionLogFileName(dateTime, device, summarySource);
  const changes = await collectGitChanges(baseCwd);
  const checkpointPaths = await collectCheckpointPaths(baseCwd, session.id);
  mergeCheckpointPaths(changes, checkpointPaths);

  const duration = formatDuration(session.created, now);
  const markdown = renderSessionLogMarkdown({
    session,
    dateTime,
    user,
    device,
    duration,
    changes,
    checkpointCount: checkpointPaths.length,
  });

  const path = await writeUniqueFile(logsDir, fileName, markdown);

  return {
    path,
    fileName: path.split('/').pop() ?? fileName,
  };
}

import { mkdir, readFile, readdir, writeFile } from 'node:fs/promises';
import { isAbsolute, join } from 'node:path';
import { execa } from 'execa';

export interface UpdateStep {
  target: string;
  component: string;
  step: string;
  status: string;
  message: string;
}

export interface UpdateLogInput {
  summary: string;
  commandInputs: Record<string, unknown>;
  steps: UpdateStep[];
  cwd?: string;
  logsDir?: string;
  timezone?: string;
  author?: string;
  rangeStart?: number;
  rangeEnd?: number;
  slug?: string;
  versionBefore?: string;
  versionAfter?: string;
  commit?: string;
  promoted?: boolean;
  category?: string;
  now?: Date;
}

export interface UpdateLogResult {
  id: number;
  path: string;
  fileName: string;
}

interface DateTimeParts {
  date: string;
  time: string;
}

const DEFAULT_LOGS_DIR = 'updates';

function safeAuthor(): string {
  return process.env['USER'] ?? process.env['USERNAME'] ?? 'unknown';
}

function localDateTimeParts(date: Date): DateTimeParts {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  const hour = String(date.getHours()).padStart(2, '0');
  const minute = String(date.getMinutes()).padStart(2, '0');

  return {
    date: `${year}-${month}-${day}`,
    time: `${hour}:${minute}`,
  };
}

function zonedDateTimeParts(date: Date, timezone?: string): DateTimeParts {
  if (!timezone || timezone === 'local') {
    return localDateTimeParts(date);
  }

  try {
    const formatter = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      hour12: false,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
    });

    const mapped = Object.fromEntries(
      formatter
        .formatToParts(date)
        .filter((part) => part.type !== 'literal')
        .map((part) => [part.type, part.value])
    ) as Record<string, string>;

    const year = mapped['year'];
    const month = mapped['month'];
    const day = mapped['day'];
    const hour = mapped['hour'];
    const minute = mapped['minute'];

    if (!year || !month || !day || !hour || !minute) {
      return localDateTimeParts(date);
    }

    return {
      date: `${year}-${month}-${day}`,
      time: `${hour}:${minute}`,
    };
  } catch {
    return localDateTimeParts(date);
  }
}

async function detectRepoRoot(cwd: string): Promise<string> {
  const result = await execa('git', ['rev-parse', '--show-toplevel'], {
    cwd,
    reject: false,
  });

  if (result.exitCode === 0 && result.stdout.trim()) {
    return result.stdout.trim();
  }

  return cwd;
}

async function resolveLogsDir(baseCwd: string, configuredDir?: string): Promise<string> {
  const root = await detectRepoRoot(baseCwd);
  const dir = configuredDir?.trim() || DEFAULT_LOGS_DIR;
  return isAbsolute(dir) ? dir : join(root, dir);
}

function slugify(raw: string, fallback = 'update', maxLength = 60): string {
  const normalized = raw
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-{2,}/g, '-');

  if (!normalized) return fallback;
  return normalized.slice(0, maxLength).replace(/-+$/g, '') || fallback;
}

export function buildUpdateLogFileName(id: number, date: string, slug: string): string {
  const padded = String(id).padStart(3, '0');
  const safeSlug = slugify(slug, 'update');
  return `${padded}_${date}_${safeSlug}.md`;
}

function parseExistingUpdateIds(files: string[]): number[] {
  const ids: number[] = [];

  for (const file of files) {
    const match = file.match(/^(\d{3})_\d{4}-\d{2}-\d{2}_.+\.md$/);
    if (!match) continue;

    const id = Number.parseInt(match[1]!, 10);
    if (Number.isFinite(id)) ids.push(id);
  }

  return ids;
}

export async function allocateNextUpdateId(
  dir: string,
  rangeStart = 1,
  rangeEnd = 999
): Promise<number> {
  await mkdir(dir, { recursive: true });

  const files = await readdir(dir).catch(() => [] as string[]);
  const ids = parseExistingUpdateIds(files).filter((id) => id >= rangeStart && id <= rangeEnd);
  const currentMax = ids.length > 0 ? Math.max(...ids) : rangeStart - 1;
  const next = currentMax + 1;

  if (next > rangeEnd) {
    throw new Error(`Update ID range exhausted (${rangeStart}-${rangeEnd})`);
  }

  return next;
}

async function resolveVersion(baseCwd: string): Promise<string> {
  const packagePath = join(baseCwd, 'package.json');

  try {
    const raw = await readFile(packagePath, 'utf-8');
    const parsed = JSON.parse(raw) as { version?: unknown };
    return typeof parsed.version === 'string' ? parsed.version : 'unknown';
  } catch {
    return 'unknown';
  }
}

async function resolveCommit(baseCwd: string): Promise<string> {
  const result = await execa('git', ['rev-parse', '--short', 'HEAD'], {
    cwd: baseCwd,
    reject: false,
  });

  if (result.exitCode === 0 && result.stdout.trim()) {
    return result.stdout.trim();
  }

  return 'unknown';
}

function stringifyCommandInputs(commandInputs: Record<string, unknown>): string {
  const keys = Object.keys(commandInputs).sort();
  if (keys.length === 0) return '- (none)';

  return keys
    .map((key) => {
      const value = commandInputs[key];
      if (value === undefined) return `- \`${key}\`: (unset)`;
      if (typeof value === 'object') return `- \`${key}\`: \`${JSON.stringify(value)}\``;
      return `- \`${key}\`: \`${String(value as string | number | boolean | symbol | bigint)}\``;
    })
    .join('\n');
}

function summarizeSteps(steps: UpdateStep[]): { ok: number; skip: number; fail: number } {
  let ok = 0;
  let skip = 0;
  let fail = 0;

  for (const step of steps) {
    if (step.status === 'ok') ok++;
    else if (step.status === 'skip') skip++;
    else if (step.status === 'fail') fail++;
  }

  return { ok, skip, fail };
}

function escapeCell(value: string): string {
  return value.replace(/\|/g, '\\|').replace(/\n+/g, ' ').trim();
}

function renderStepTable(steps: UpdateStep[]): string {
  if (steps.length === 0) return '- (no steps recorded)';

  const lines = [
    '| Target | Component | Step | Status | Message |',
    '| --- | --- | --- | --- | --- |',
  ];

  for (const step of steps) {
    lines.push(
      `| ${escapeCell(step.target)} | ${escapeCell(step.component)} | ${escapeCell(step.step)} | ${escapeCell(step.status)} | ${escapeCell(step.message)} |`
    );
  }

  return lines.join('\n');
}

function renderUpdateLogMarkdown(params: {
  id: number;
  dateTime: DateTimeParts;
  author: string;
  versionBefore: string;
  versionAfter: string;
  commit: string;
  promoted: boolean;
  category: string;
  summary: string;
  commandInputs: Record<string, unknown>;
  steps: UpdateStep[];
}): string {
  const {
    id,
    dateTime,
    author,
    versionBefore,
    versionAfter,
    commit,
    promoted,
    category,
    summary,
    commandInputs,
    steps,
  } = params;

  const counts = summarizeSteps(steps);

  return `---
id: ${String(id).padStart(3, '0')}
date: ${dateTime.date}
time: ${dateTime.time}
author: ${author}
version_before: ${versionBefore}
version_after: ${versionAfter}
commit: ${commit}
promoted: ${promoted}
category: ${category}
---

## Summary
- ${summary}
- Steps: total=${steps.length}, ok=${counts.ok}, skip=${counts.skip}, fail=${counts.fail}

## Command Inputs
${stringifyCommandInputs(commandInputs)}

## Step Results
${renderStepTable(steps)}
`;
}

export async function writeUpdateLog(input: UpdateLogInput): Promise<UpdateLogResult> {
  const now = input.now ?? new Date();
  const timezone = input.timezone ?? 'local';
  const dateTime = zonedDateTimeParts(now, timezone);
  const rangeStart = input.rangeStart ?? 1;
  const rangeEnd = input.rangeEnd ?? 999;
  const baseCwd = input.cwd ?? process.cwd();
  const repoRoot = await detectRepoRoot(baseCwd);
  const logsDir = await resolveLogsDir(baseCwd, input.logsDir);
  const author = input.author?.trim() || safeAuthor();
  const promoted = input.promoted ?? rangeStart >= 200;
  const category = input.category ?? (promoted ? 'promotion' : 'development');

  await mkdir(logsDir, { recursive: true });

  const versionBefore = input.versionBefore ?? (await resolveVersion(repoRoot));
  const versionAfter = input.versionAfter ?? (await resolveVersion(repoRoot));
  const commit = input.commit ?? (await resolveCommit(repoRoot));

  for (let attempt = 0; attempt < 60; attempt++) {
    const id = await allocateNextUpdateId(logsDir, rangeStart, rangeEnd);
    const slugSource = input.slug || input.summary;
    const fileName = buildUpdateLogFileName(id, dateTime.date, slugSource);
    const path = join(logsDir, fileName);

    const markdown = renderUpdateLogMarkdown({
      id,
      dateTime,
      author,
      versionBefore,
      versionAfter,
      commit,
      promoted,
      category,
      summary: input.summary,
      commandInputs: input.commandInputs,
      steps: input.steps,
    });

    try {
      await writeFile(path, markdown, { encoding: 'utf-8', flag: 'wx' });
      return { id, path, fileName };
    } catch (err) {
      const code = (err as NodeJS.ErrnoException).code;
      if (code === 'EEXIST') continue;
      throw err;
    }
  }

  throw new Error('Unable to allocate update log ID after multiple attempts');
}

/**
 * keychain/index.ts — Cross-platform secure credential store.
 *
 * Uses OS-native CLIs only. No native addons, no node-gyp.
 *
 *   macOS  → security(1) add/find/delete-generic-password
 *   Linux  → secret-tool(1) if available in PATH
 *   Windows → PowerShell DPAPI-protected local fallback store
 *   Other   → no-op (returns null / false)
 *
 * All public functions are fail-safe: errors are logged at verbose level
 * and never thrown to the caller.
 */

import { execFile as _execFile, spawn } from 'node:child_process';
import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { promisify } from 'node:util';
import { verbose } from '../core/debug.js';
import { errorMessage } from '../utils/errors.js';

const execFile = promisify(_execFile);

// ---------------------------------------------------------------------------
// Internal platform detection
// ---------------------------------------------------------------------------

const PLATFORM = process.platform;

/** Cached result for Linux secret-tool availability check. */
let _secretToolAvailable: boolean | null = null;
let _windowsFallbackWarningShown = false;

type WindowsFallbackStore = Record<string, string>;

const WINDOWS_FALLBACK_WARNING =
  '[opta] Windows keychain fallback active: using a DPAPI-protected local store (not Credential Manager).';

const WINDOWS_FALLBACK_STORE_PATH =
  process.env['OPTA_WINDOWS_KEYCHAIN_FILE'] ??
  join(
    process.env['LOCALAPPDATA'] ??
      process.env['APPDATA'] ??
      process.env['USERPROFILE'] ??
      process.cwd(),
    'opta-cli',
    'keychain-store.json'
  );

async function checkSecretToolAvailable(): Promise<boolean> {
  if (_secretToolAvailable !== null) return _secretToolAvailable;
  try {
    await execFile('which', ['secret-tool']);
    _secretToolAvailable = true;
  } catch {
    _secretToolAvailable = false;
  }
  return _secretToolAvailable;
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Returns true if the current platform has a usable keychain backend.
 *
 * - macOS: always true (security CLI is part of macOS)
 * - Windows: true (DPAPI fallback store via PowerShell)
 * - Linux: true only if secret-tool is in PATH (sync check uses cached result)
 * - Other: always false
 *
 * Note: on Linux this may return false on first call before the async check
 * completes. Call isKeychainAvailable() after at least one async operation
 * for an accurate result, or use the async variant internally.
 */
export function isKeychainAvailable(): boolean {
  if (PLATFORM === 'darwin') return true;
  if (PLATFORM === 'win32') return true;
  if (PLATFORM === 'linux') return _secretToolAvailable === true;
  return false;
}

/**
 * Retrieve a secret from the OS keychain.
 *
 * @param service  Keychain service name (e.g. 'opta-cli')
 * @param account  Account name within the service (e.g. 'anthropic-api-key')
 * @returns The stored secret string, or null if not found or on error.
 */
export async function getSecret(service: string, account: string): Promise<string | null> {
  if (PLATFORM === 'darwin') {
    return macosGetSecret(service, account);
  }
  if (PLATFORM === 'win32') {
    return windowsGetSecret(service, account);
  }
  if (PLATFORM === 'linux') {
    const available = await checkSecretToolAvailable();
    if (!available) return null;
    return linuxGetSecret(service, account);
  }
  verbose(`keychain: getSecret called on unsupported platform (${PLATFORM})`);
  return null;
}

/**
 * Store a secret in the OS keychain.
 *
 * @param service  Keychain service name
 * @param account  Account name within the service
 * @param secret   The plaintext secret to store
 */
export async function setSecret(service: string, account: string, secret: string): Promise<void> {
  if (PLATFORM === 'darwin') {
    await macosSetSecret(service, account, secret);
    return;
  }
  if (PLATFORM === 'win32') {
    await windowsSetSecret(service, account, secret);
    return;
  }
  if (PLATFORM === 'linux') {
    const available = await checkSecretToolAvailable();
    if (!available) {
      verbose('keychain: setSecret — secret-tool not available, skipping');
      return;
    }
    await linuxSetSecret(service, account, secret);
    return;
  }
  verbose(`keychain: setSecret called on unsupported platform (${PLATFORM}), skipping`);
}

/**
 * Delete a secret from the OS keychain.
 *
 * Does not throw if the secret does not exist.
 *
 * @param service  Keychain service name
 * @param account  Account name within the service
 */
export async function deleteSecret(service: string, account: string): Promise<void> {
  if (PLATFORM === 'darwin') {
    await macosDeleteSecret(service, account);
    return;
  }
  if (PLATFORM === 'win32') {
    await windowsDeleteSecret(service, account);
    return;
  }
  if (PLATFORM === 'linux') {
    const available = await checkSecretToolAvailable();
    if (!available) {
      verbose('keychain: deleteSecret — secret-tool not available, skipping');
      return;
    }
    await linuxDeleteSecret(service, account);
    return;
  }
  verbose(`keychain: deleteSecret called on unsupported platform (${PLATFORM}), skipping`);
}

// ---------------------------------------------------------------------------
// macOS implementation — security(1)
// ---------------------------------------------------------------------------

async function macosGetSecret(service: string, account: string): Promise<string | null> {
  try {
    // -w prints the password only (no other output)
    const { stdout } = await execFile('security', [
      'find-generic-password',
      '-s',
      service,
      '-a',
      account,
      '-w',
    ]);
    return stdout.trimEnd();
  } catch (err: unknown) {
    // Exit code 44 = item not found — not an error for our purposes
    const exitCode = (err as NodeJS.ErrnoException & { code?: number })?.code;
    if (exitCode !== 44) {
      verbose(`keychain(macOS): find-generic-password failed — ${errorMessage(err)}`);
    }
    return null;
  }
}

async function macosSetSecret(service: string, account: string, secret: string): Promise<void> {
  try {
    // -U updates the entry if it already exists
    await execFile('security', [
      'add-generic-password',
      '-s',
      service,
      '-a',
      account,
      '-w',
      secret,
      '-U',
    ]);
  } catch (err: unknown) {
    verbose(`keychain(macOS): add-generic-password failed — ${errorMessage(err)}`);
  }
}

async function macosDeleteSecret(service: string, account: string): Promise<void> {
  try {
    await execFile('security', ['delete-generic-password', '-s', service, '-a', account]);
  } catch (err: unknown) {
    // Exit code 44 = item not found — treat as success (idempotent delete)
    const exitCode = (err as NodeJS.ErrnoException & { code?: number })?.code;
    if (exitCode !== 44) {
      verbose(`keychain(macOS): delete-generic-password failed — ${errorMessage(err)}`);
    }
  }
}

// ---------------------------------------------------------------------------
// Linux implementation — secret-tool(1)
// ---------------------------------------------------------------------------

async function linuxGetSecret(service: string, account: string): Promise<string | null> {
  try {
    const { stdout } = await execFile('secret-tool', [
      'lookup',
      'service',
      service,
      'account',
      account,
    ]);
    return stdout.trimEnd();
  } catch (err: unknown) {
    verbose(`keychain(Linux): secret-tool lookup failed — ${errorMessage(err)}`);
    return null;
  }
}

async function linuxSetSecret(service: string, account: string, secret: string): Promise<void> {
  return new Promise<void>((resolve) => {
    try {
      // secret-tool store reads the password from stdin.
      // We use spawn (not execFile) here so we can write to stdin directly.
      const child = spawn(
        'secret-tool',
        ['store', `--label=${service}`, 'service', service, 'account', account],
        { stdio: ['pipe', 'ignore', 'ignore'] }
      );

      child.on('error', (err) => {
        verbose(`keychain(Linux): secret-tool store failed — ${err.message}`);
        resolve();
      });

      child.on('close', (code) => {
        if (code !== 0) {
          verbose(`keychain(Linux): secret-tool store exited with code ${String(code)}`);
        }
        resolve();
      });

      // Write the secret to stdin then close the pipe
      if (child.stdin) {
        child.stdin.write(secret);
        child.stdin.end();
      }
    } catch (err: unknown) {
      verbose(`keychain(Linux): secret-tool store spawn failed — ${errorMessage(err)}`);
      resolve();
    }
  });
}

async function linuxDeleteSecret(service: string, account: string): Promise<void> {
  try {
    await execFile('secret-tool', ['clear', 'service', service, 'account', account]);
  } catch (err: unknown) {
    verbose(`keychain(Linux): secret-tool clear failed — ${errorMessage(err)}`);
  }
}

// ---------------------------------------------------------------------------
// Windows implementation — DPAPI fallback store via PowerShell
// ---------------------------------------------------------------------------

function windowsStoreEntryKey(service: string, account: string): string {
  return `${service}::${account}`;
}

function warnWindowsFallbackOnce(): void {
  if (_windowsFallbackWarningShown) return;
  _windowsFallbackWarningShown = true;
  console.warn(WINDOWS_FALLBACK_WARNING);
}

async function loadWindowsFallbackStore(): Promise<WindowsFallbackStore> {
  try {
    const raw = await readFile(WINDOWS_FALLBACK_STORE_PATH, 'utf8');
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return {};
    }
    const result: WindowsFallbackStore = {};
    for (const [key, value] of Object.entries(parsed)) {
      if (typeof value === 'string') {
        result[key] = value;
      }
    }
    return result;
  } catch (err: unknown) {
    const code = (err as NodeJS.ErrnoException | null)?.code;
    if (code !== 'ENOENT') {
      verbose(`keychain(Windows): failed to read fallback store — ${errorMessage(err)}`);
    }
    return {};
  }
}

async function saveWindowsFallbackStore(store: WindowsFallbackStore): Promise<void> {
  try {
    await mkdir(dirname(WINDOWS_FALLBACK_STORE_PATH), { recursive: true });
    await writeFile(WINDOWS_FALLBACK_STORE_PATH, JSON.stringify(store, null, 2), 'utf8');
  } catch (err: unknown) {
    verbose(`keychain(Windows): failed to write fallback store — ${errorMessage(err)}`);
  }
}

async function execWindowsPowerShell(script: string, envValue: string): Promise<string | null> {
  const attempts: string[] = [];
  const candidates = ['powershell', 'pwsh'];

  for (const shell of candidates) {
    try {
      const { stdout } = await execFile(
        shell,
        ['-NoProfile', '-NonInteractive', '-Command', script],
        {
          env: {
            ...process.env,
            OPTA_KEYCHAIN_VALUE: envValue,
          },
          windowsHide: true,
        }
      );
      return stdout.trimEnd();
    } catch (err: unknown) {
      attempts.push(`${shell}: ${errorMessage(err)}`);
    }
  }

  verbose(`keychain(Windows): PowerShell execution failed — ${attempts.join('; ')}`);
  return null;
}

async function windowsEncryptSecret(secret: string): Promise<string | null> {
  return execWindowsPowerShell(
    '$secure = ConvertTo-SecureString -String $env:OPTA_KEYCHAIN_VALUE -AsPlainText -Force; ' +
      'ConvertFrom-SecureString -SecureString $secure',
    secret
  );
}

async function windowsDecryptSecret(encrypted: string): Promise<string | null> {
  return execWindowsPowerShell(
    '$secure = ConvertTo-SecureString -String $env:OPTA_KEYCHAIN_VALUE; ' +
      "$cred = New-Object System.Management.Automation.PSCredential('opta', $secure); " +
      '$cred.GetNetworkCredential().Password',
    encrypted
  );
}

async function windowsGetSecret(service: string, account: string): Promise<string | null> {
  warnWindowsFallbackOnce();
  const store = await loadWindowsFallbackStore();
  const encrypted = store[windowsStoreEntryKey(service, account)];
  if (!encrypted) return null;
  return windowsDecryptSecret(encrypted);
}

async function windowsSetSecret(service: string, account: string, secret: string): Promise<void> {
  warnWindowsFallbackOnce();
  const encrypted = await windowsEncryptSecret(secret);
  if (!encrypted) {
    verbose('keychain(Windows): encryption failed, skipping secret write');
    return;
  }
  const store = await loadWindowsFallbackStore();
  store[windowsStoreEntryKey(service, account)] = encrypted;
  await saveWindowsFallbackStore(store);
}

async function windowsDeleteSecret(service: string, account: string): Promise<void> {
  warnWindowsFallbackOnce();
  const store = await loadWindowsFallbackStore();
  Reflect.deleteProperty(store, windowsStoreEntryKey(service, account));
  await saveWindowsFallbackStore(store);
}

import { mkdir, open, readFile, unlink } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import {
  LearningLedgerEntrySchema,
  type CaptureLevel,
  type LearningEntryKind,
  type LearningLedgerEntry,
} from './types.js';
import { sleep } from '../utils/common.js';

const LEDGER_RELATIVE_PATH = join('.opta', 'learning', 'ledger.jsonl');

export interface LedgerStoreOptions {
  cwd?: string;
  lockTimeoutMs?: number;
  lockRetryMs?: number;
}

export interface LedgerReadOptions {
  cwd?: string;
}

export interface LedgerQuery {
  kinds?: LearningEntryKind[];
  captureLevels?: CaptureLevel[];
  tags?: string[];
  text?: string;
  from?: string | Date;
  to?: string | Date;
  limit?: number;
}

export function learningLedgerPath(cwd = process.cwd()): string {
  return join(cwd, LEDGER_RELATIVE_PATH);
}

function learningLedgerDir(cwd = process.cwd()): string {
  return dirname(learningLedgerPath(cwd));
}

function learningLedgerLockPath(cwd = process.cwd()): string {
  return `${learningLedgerPath(cwd)}.lock`;
}

async function acquireLock(lockPath: string, timeoutMs: number, retryMs: number) {
  const start = Date.now();
  while (true) {
    try {
      return await open(lockPath, 'wx');
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      if (err.code !== 'EEXIST') {
        throw err;
      }
      if (Date.now() - start >= timeoutMs) {
        throw new Error(`Timed out waiting for ledger lock: ${lockPath}`);
      }
      await sleep(retryMs);
    }
  }
}

function parseDate(value?: string | Date): number | undefined {
  if (value === undefined) return undefined;
  const millis = new Date(value).getTime();
  return Number.isNaN(millis) ? undefined : millis;
}

function matchesFreeText(entry: LearningLedgerEntry, rawText: string): boolean {
  const text = rawText.trim().toLowerCase();
  if (!text) return true;

  const haystack = [
    entry.id,
    entry.kind,
    entry.captureLevel,
    entry.topic,
    entry.content,
    entry.tags.join(' '),
    entry.evidence.map((item) => `${item.label} ${item.uri}`).join(' '),
  ]
    .join(' ')
    .toLowerCase();

  return text
    .split(/\s+/)
    .filter(Boolean)
    .every((token) => haystack.includes(token));
}

async function readLedgerFile(path: string): Promise<string> {
  try {
    return await readFile(path, 'utf-8');
  } catch (error) {
    const err = error as NodeJS.ErrnoException;
    if (err.code === 'ENOENT') {
      return '';
    }
    throw err;
  }
}

async function appendLedgerLine(path: string, line: string): Promise<void> {
  const handle = await open(path, 'a');
  try {
    await handle.writeFile(line, 'utf-8');
    // Ensure the append is durable before releasing the inter-process lock.
    await handle.sync();
  } finally {
    await handle.close().catch(() => {});
  }
}

export async function appendLedgerEntry(
  entry: LearningLedgerEntry,
  options: LedgerStoreOptions = {},
): Promise<void> {
  const cwd = options.cwd ?? process.cwd();
  const lockTimeoutMs = options.lockTimeoutMs ?? 5000;
  const lockRetryMs = options.lockRetryMs ?? 20;
  const ledgerPath = learningLedgerPath(cwd);
  const ledgerDir = learningLedgerDir(cwd);
  const lockPath = learningLedgerLockPath(cwd);
  const parsed = LearningLedgerEntrySchema.parse(entry);

  await mkdir(ledgerDir, { recursive: true });
  const lockHandle = await acquireLock(lockPath, lockTimeoutMs, lockRetryMs);

  try {
    await appendLedgerLine(ledgerPath, `${JSON.stringify(parsed)}\n`);
  } finally {
    await lockHandle.close().catch(() => {});
    await unlink(lockPath).catch(() => {});
  }
}

export async function readLedgerEntries(
  options: LedgerReadOptions = {},
): Promise<LearningLedgerEntry[]> {
  const cwd = options.cwd ?? process.cwd();
  const raw = await readLedgerFile(learningLedgerPath(cwd));
  if (!raw.trim()) return [];

  const lines = raw.split('\n').filter((line) => line.trim().length > 0);
  const parsed: LearningLedgerEntry[] = [];

  for (const [index, line] of lines.entries()) {
    let json: unknown;
    try {
      json = JSON.parse(line);
    } catch {
      throw new Error(`Invalid ledger entry at line ${index + 1}: malformed JSON`);
    }

    const result = LearningLedgerEntrySchema.safeParse(json);
    if (!result.success) {
      const issue = result.error.issues[0]?.message ?? 'schema mismatch';
      throw new Error(`Invalid ledger entry at line ${index + 1}: ${issue}`);
    }
    parsed.push(result.data);
  }

  return parsed;
}

export async function queryLedgerEntries(
  query: LedgerQuery = {},
  options: LedgerReadOptions = {},
): Promise<LearningLedgerEntry[]> {
  const entries = await readLedgerEntries(options);
  const fromMs = parseDate(query.from);
  const toMs = parseDate(query.to);
  const tags = query.tags ?? [];
  const kinds = query.kinds ?? [];
  const captureLevels = query.captureLevels ?? [];

  let filtered = entries.filter((entry) => {
    if (kinds.length > 0 && !kinds.includes(entry.kind)) {
      return false;
    }
    if (captureLevels.length > 0 && !captureLevels.includes(entry.captureLevel)) {
      return false;
    }
    if (tags.length > 0 && !tags.every((tag) => entry.tags.includes(tag))) {
      return false;
    }

    const ts = new Date(entry.ts).getTime();
    if (fromMs !== undefined && ts < fromMs) {
      return false;
    }
    if (toMs !== undefined && ts > toMs) {
      return false;
    }

    if (query.text && !matchesFreeText(entry, query.text)) {
      return false;
    }

    return true;
  });

  filtered = filtered.sort((a, b) => b.ts.localeCompare(a.ts));
  if (query.limit !== undefined && query.limit > 0) {
    filtered = filtered.slice(0, query.limit);
  }

  return filtered;
}

import type { LearningLedgerEntry } from './types.js';

export interface LedgerSummaryOptions {
  from?: string | Date;
  to?: string | Date;
}

function parseDate(value?: string | Date): number | undefined {
  if (value === undefined) return undefined;
  const millis = new Date(value).getTime();
  return Number.isNaN(millis) ? undefined : millis;
}

function dateKey(ts: string): string {
  return new Date(ts).toISOString().slice(0, 10);
}

export function summarizeLedgerByDate(
  entries: LearningLedgerEntry[],
  options: LedgerSummaryOptions = {},
): string {
  const fromMs = parseDate(options.from);
  const toMs = parseDate(options.to);

  const filtered = entries
    .filter((entry) => {
      const ts = new Date(entry.ts).getTime();
      if (fromMs !== undefined && ts < fromMs) return false;
      if (toMs !== undefined && ts > toMs) return false;
      return true;
    })
    .sort((a, b) => b.ts.localeCompare(a.ts));

  const lines: string[] = ['# Learning Ledger Summary', ''];
  if (filtered.length === 0) {
    lines.push('_No entries found._');
    return `${lines.join('\n')}\n`;
  }

  const grouped = new Map<string, LearningLedgerEntry[]>();
  for (const entry of filtered) {
    const key = dateKey(entry.ts);
    if (!grouped.has(key)) {
      grouped.set(key, []);
    }
    grouped.get(key)!.push(entry);
  }

  const sortedDates = Array.from(grouped.keys()).sort((a, b) =>
    b.localeCompare(a),
  );
  for (const day of sortedDates) {
    lines.push(`## ${day}`, '');
    for (const entry of grouped.get(day) ?? []) {
      lines.push(`- **${entry.kind}** ${entry.topic}`);
      lines.push(`  ${entry.content}`);
      if (entry.tags.length > 0) {
        lines.push(`  Tags: ${entry.tags.join(', ')}`);
      }
      if (entry.evidence.length > 0) {
        const refs = entry.evidence
          .map((item) => `[${item.label}](${item.uri})`)
          .join(', ');
        lines.push(`  Evidence: ${refs}`);
      }
    }
    lines.push('');
  }

  return `${lines.join('\n').trimEnd()}\n`;
}

