  presence_penalty?: number | null;
  num_ctx?: number | null;
}

type Chunk = OpenAI.Chat.Completions.ChatCompletionChunk;

const DEFAULT_WS_HANDSHAKE_TIMEOUT_MS = 5_000;
const DEFAULT_WS_IDLE_TIMEOUT_MS = 30_000;

interface LmxWsMessage {
  type?: string;
  request_id?: string;
  content?: unknown;
  model?: unknown;
  finish_reason?: unknown;
  usage?: {
    prompt_tokens?: unknown;
    completion_tokens?: unknown;
    total_tokens?: unknown;
  };
  tool_call?: {
    index?: unknown;
    id?: unknown;
    name?: unknown;
    arguments?: unknown;
  };
  error?: unknown;
}

function makeAbortError(message: string): Error {
  const err = new Error(message);
  err.name = 'AbortError';
  return err;
}

export function isAbortError(err: unknown): boolean {
  if (!(err instanceof Error)) return false;
  if (err.name === 'AbortError') return true;
  const lowered = err.message.toLowerCase();
  return lowered.includes('aborted') || lowered.includes('cancelled');
}

function coerceNumber(value: unknown, fallback: number): number {
  if (typeof value === 'number' && Number.isFinite(value)) return value;
  if (typeof value === 'string') {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) return parsed;
  }
  return fallback;
}

class AsyncChunkQueue implements AsyncIterable<Chunk> {
  private readonly items: Chunk[] = [];
  private readonly waiters: Array<{
    resolve: (value: IteratorResult<Chunk>) => void;
    reject: (err: Error) => void;
  }> = [];
  private done = false;
  private failure: Error | null = null;

  push(chunk: Chunk): void {
    if (this.done || this.failure) return;
    const waiter = this.waiters.shift();
    if (waiter) {
      waiter.resolve({ value: chunk, done: false });
      return;
    }
    this.items.push(chunk);
  }

  finish(): void {
    if (this.done || this.failure) return;
    this.done = true;
    while (this.waiters.length > 0) {
      const waiter = this.waiters.shift();
      waiter?.resolve({ value: undefined as unknown as Chunk, done: true });
    }
  }

  fail(err: Error): void {
    if (this.done || this.failure) return;
    this.failure = err;
    while (this.waiters.length > 0) {
      const waiter = this.waiters.shift();
      waiter?.reject(err);
    }
  }

  [Symbol.asyncIterator](): AsyncIterator<Chunk> {
    return {
      next: async () => {
        if (this.items.length > 0) {
          const value = this.items.shift()!;
          return { value, done: false };
        }
        if (this.failure) throw this.failure;
        if (this.done) return { value: undefined as unknown as Chunk, done: true };
        return new Promise<IteratorResult<Chunk>>((resolve, reject) => {
          this.waiters.push({ resolve, reject });
        });
      },
      return: () => {
        this.finish();
        return Promise.resolve({ value: undefined as unknown as Chunk, done: true as const });
      },
    };
  }
}

function parseWsJson(raw: RawData): LmxWsMessage | null {
  try {
    return JSON.parse(
      Buffer.isBuffer(raw)
        ? raw.toString()
        : Array.isArray(raw)
          ? Buffer.concat(raw).toString()
          : Buffer.from(raw).toString()
    ) as LmxWsMessage;
  } catch {
    return null;
  }
}

function makeChunkBase(requestId: string, model: string): Omit<Chunk, 'choices'> {
  return {
    id: requestId,
    object: 'chat.completion.chunk',
    created: Math.floor(Date.now() / 1000),
    model,
  };
}

function toContentChunk(requestId: string, model: string, content: string): Chunk {
  return {
    ...makeChunkBase(requestId, model),
    choices: [
      {
        index: 0,
        delta: { content },
        finish_reason: null,
      },
    ],
  };
}

function toToolChunk(
  requestId: string,
  model: string,
  toolCall: NonNullable<LmxWsMessage['tool_call']>
): Chunk {
  const index = coerceNumber(toolCall.index, 0);
  const hasId = typeof toolCall.id === 'string' && toolCall.id.length > 0;
  const hasName = typeof toolCall.name === 'string' && toolCall.name.length > 0;
  const hasArgs = typeof toolCall.arguments === 'string';
  const fn: { name?: string; arguments?: string } = {};
  if (hasName) fn.name = toolCall.name as string;
  if (hasArgs) fn.arguments = toolCall.arguments as string;

  return {
    ...makeChunkBase(requestId, model),
    choices: [
      {
        index: 0,
        delta: {
          tool_calls: [
            {
              index,
              ...(hasId ? { id: toolCall.id as string, type: 'function' as const } : {}),
              ...(hasName || hasArgs ? { function: fn } : {}),
            },
          ],
        },
        finish_reason: null,
      },
    ],
  };
}

function toDoneChunk(
  requestId: string,
  model: string,
  finishReason: 'length' | 'stop' | 'tool_calls' | 'content_filter' | 'function_call' | null,
  usage?: LmxWsMessage['usage']
): Chunk {
  const promptTokens = coerceNumber(usage?.prompt_tokens, 0);
  const completionTokens = coerceNumber(usage?.completion_tokens, 0);
  const totalTokens = coerceNumber(usage?.total_tokens, promptTokens + completionTokens);
  return {
    ...makeChunkBase(requestId, model),
    choices: [
      {
        index: 0,
        delta: {},
        finish_reason: finishReason,
      },
    ],
    usage: {
      prompt_tokens: promptTokens,
      completion_tokens: completionTokens,
      total_tokens: totalTokens,
    },
  };
}

function normalizeFinishReason(
  value: unknown
): 'length' | 'stop' | 'tool_calls' | 'content_filter' | 'function_call' | null {
  if (value === null) return null;
  if (
    value === 'length' ||
    value === 'tool_calls' ||
    value === 'content_filter' ||
    value === 'function_call'
  ) {
    return value;
  }
  return 'stop';
}

function buildSignal(timeoutMs: number, external?: AbortSignal): AbortSignal {
  if (!external) return AbortSignal.timeout(timeoutMs);
  return AbortSignal.any([external, AbortSignal.timeout(timeoutMs)]);
}

async function runLmxProbes(
  base: string,
  started: number,
  timeoutMs: number,
  adminKey?: string
): Promise<LmxConnectionResult> {
  // 1) Liveness
  try {
    const res = await fetch(`${base}/healthz`, {
      signal: buildSignal(timeoutMs),
    });
    if (!res.ok) {
      return {
        state: 'degraded',
        latencyMs: Date.now() - started,
        reason: `healthz_http_${res.status}`,
      };
    }
  } catch (err) {
    return {
      state: 'disconnected',
      latencyMs: Date.now() - started,
      reason: err instanceof Error ? err.message : 'healthz_failed',
    };
  }

  // 2) Readiness (best signal for UX status)
  try {
    const readyRes = await fetch(`${base}/readyz`, {
      signal: buildSignal(timeoutMs),
    });
    if (readyRes.ok) {
      const data = (await readyRes.json()) as { models_loaded?: number };
      return {
        state: 'connected',
        latencyMs: Date.now() - started,
        modelsLoaded: data.models_loaded,
      };
    }
    // No models loaded = alive but not ready
    if (readyRes.status === 503) {
      return {
        state: 'degraded',
        latencyMs: Date.now() - started,
        modelsLoaded: 0,
        reason: 'no_models_loaded',
      };
    }
  } catch {
    // Ignore and fall back to /v1/models for compatibility.
  }

  // 3) Fallback for older LMX versions
  try {
    const headers: Record<string, string> = {};
    if (adminKey) headers['X-Admin-Key'] = adminKey;
    const modelsRes = await fetch(`${base}/v1/models`, {
      signal: buildSignal(timeoutMs),
      headers,
    });
    if (!modelsRes.ok) {
      return {
        state: 'degraded',
        latencyMs: Date.now() - started,
        reason: `models_http_${modelsRes.status}`,
      };
    }
    const data = (await modelsRes.json()) as { data?: unknown[] };
    const count = Array.isArray(data.data) ? data.data.length : undefined;
    return {
      state: count && count > 0 ? 'connected' : 'degraded',
      latencyMs: Date.now() - started,
      modelsLoaded: count,
    };
  } catch (err) {
    return {
      state: 'degraded',
      latencyMs: Date.now() - started,
      reason: err instanceof Error ? err.message : 'models_failed',
    };
  }
}

async function fetchLmxDiscovery(
  host: string,
  port: number,
  timeoutMs: number
): Promise<LmxDiscoveryDoc | null> {
  const paths = ['/.well-known/opta-lmx', '/v1/discovery'];
  for (const path of paths) {
    try {
      const res = await fetch(`http://${host}:${port}${path}`, {
        signal: AbortSignal.timeout(timeoutMs),
      });
      if (!res.ok) continue;
      return (await res.json()) as LmxDiscoveryDoc;
    } catch {
      // Continue to next discovery path.
    }
  }
  return null;
}

/**
 * Probe Opta LMX reachability using the lightweight health endpoints first.
 *
 * Order:
 * 1) /healthz (liveness, unauthenticated)
 * 2) /readyz (readiness + loaded model count)
 * 3) /v1/models (fallback for older servers without /readyz)
 *
 * If the server is reachable, also fetches /.well-known/opta-lmx for
 * zero-config discovery metadata (canonical WS URL, auth profile, loaded
 * models). Failure to fetch the discovery document never degrades the
 * connection state — it is silently omitted for backward compatibility with
 * older LMX versions.
 */
export async function probeLmxConnection(
  host: string,
  port: number,
  options?: ProbeOptions
): Promise<LmxConnectionResult> {
  const timeoutMs = options?.timeoutMs ?? 2000;
  const base = `http://${host}:${port}`;
  const started = Date.now();

  const result = await runLmxProbes(
    base,
    started,
    timeoutMs,
    resolveAdminKeyForHost(host, port, {
      defaultAdminKey: options?.adminKey,
      adminKeysByHost: options?.adminKeysByHost,
    })
  );

  if (result.state !== 'disconnected') {
    const doc = await fetchLmxDiscovery(host, port, Math.min(timeoutMs, 2000));
    if (doc !== null) {
      result.discovery = doc;
    }
  }

  return result;
}

/**
 * Preferred low-latency transport for daemon-side LMX streaming.
 *
 * Uses /v1/chat/stream (WebSocket) and emits OpenAI-compatible chunks so the
 * existing stream collector can remain provider-agnostic.
 */
export function streamLmxChatWebSocket(
  host: string,
  port: number,
  request: LmxChatStreamRequest,
  options?: LmxWsStreamOptions
): AsyncIterable<Chunk> {
  if (options?.signal?.aborted) {
    throw makeAbortError('LMX stream aborted before start');
  }

  const queue = new AsyncChunkQueue();
  const url = options?.wsUrl ?? `ws://${host}:${port}/v1/chat/stream`;
  const headers: Record<string, string> = {};
  if (options?.adminKey) {
    headers['X-Admin-Key'] = options.adminKey;
  }
  const handshakeTimeoutMs = Math.max(
    0,
    options?.handshakeTimeoutMs ?? DEFAULT_WS_HANDSHAKE_TIMEOUT_MS
  );
  const idleTimeoutMs = Math.max(0, options?.idleTimeoutMs ?? DEFAULT_WS_IDLE_TIMEOUT_MS);

  const socket = new WebSocket(url, { headers });
  let requestId: string | null = null;
  let model = request.model;
  let completed = false;
  let cleaned = false;
  let sawContentChunk = false;
  let sawToolChunk = false;
  let handshakeTimer: NodeJS.Timeout | null = null;
  let idleTimer: NodeJS.Timeout | null = null;

  const closeSocket = () => {
    if (socket.readyState === WebSocket.OPEN || socket.readyState === WebSocket.CONNECTING) {
      socket.once('error', () => {
        // Suppress ws close races during teardown.
      });
      try {
        socket.close();
      } catch {
        // Ignore close races while cleaning up failure/abort paths.
      }
    }
  };

  const clearHandshakeTimer = () => {
    if (!handshakeTimer) return;
    clearTimeout(handshakeTimer);
    handshakeTimer = null;
  };

  const clearIdleTimer = () => {
    if (!idleTimer) return;
    clearTimeout(idleTimer);
    idleTimer = null;
  };

  const restartIdleTimer = () => {
    if (idleTimeoutMs <= 0) return;
    clearIdleTimer();
    idleTimer = setTimeout(() => {
      if (completed) return;
      fail(new Error(`LMX websocket idle timeout after ${idleTimeoutMs}ms`));
    }, idleTimeoutMs);
  };

  const cleanup = () => {
    if (cleaned) return;
    cleaned = true;
    clearHandshakeTimer();
    clearIdleTimer();
    socket.removeAllListeners();
    options?.signal?.removeEventListener('abort', onAbort);
  };

  const fail = (err: Error) => {
    cleanup();
    queue.fail(err);
    closeSocket();
  };

  const finish = () => {
    cleanup();
    queue.finish();
    closeSocket();
  };

  const onAbort = () => {
    const abortErr = makeAbortError('LMX stream aborted');
    if (requestId && socket.readyState === WebSocket.OPEN) {
      socket.send(
        JSON.stringify({
          type: 'chat.cancel',
          request_id: requestId,
        })
      );
    }
    fail(abortErr);
  };

  socket.once('open', () => {
    clearHandshakeTimer();
    restartIdleTimer();
    if (options?.signal?.aborted) {
      onAbort();
      return;
    }
    socket.send(
      JSON.stringify({
        type: 'chat.request',
        stream: true,
        ...request,
      })
    );
  });

  socket.on('message', (raw: RawData) => {
    if (completed) return;
    restartIdleTimer();
    const data = parseWsJson(raw);
    if (!data || typeof data.type !== 'string') return;
    if (typeof data.request_id === 'string' && data.request_id) {
      requestId = data.request_id;
    }
    if (typeof data.model === 'string' && data.model) {
      model = data.model;
    }

    if (data.type === 'chat.token') {
      if (typeof data.content !== 'string' || !data.content) return;
      sawContentChunk = true;
      queue.push(toContentChunk(requestId ?? 'chatcmpl-lmx', model, data.content));
      return;
    }

    if (data.type === 'chat.tool_call' && data.tool_call) {
      sawToolChunk = true;
      queue.push(toToolChunk(requestId ?? 'chatcmpl-lmx', model, data.tool_call));
      return;
    }

    if (
      data.type === 'chat.done' ||
      data.type === 'chat.complete' ||
      data.type === 'chat.completed' ||
      data.type === 'done'
    ) {
      completed = true;
      const finishReason = normalizeFinishReason(data.finish_reason);
      queue.push(toDoneChunk(requestId ?? 'chatcmpl-lmx', model, finishReason, data.usage));
      finish();
      return;
    }

    if (data.type === 'chat.error') {
      completed = true;
      const message =
        typeof data.error === 'string' && data.error ? data.error : 'LMX websocket error';
      fail(new Error(message));
    }
  });

  socket.once('error', (err) => {
    if (completed) return;
    fail(err instanceof Error ? err : new Error(String(err)));
  });

  socket.once('close', (code, reasonBuf) => {
    if (completed) return;
    if (options?.signal?.aborted) {
      fail(makeAbortError('LMX stream aborted'));
      return;
    }

    // Some LMX builds close cleanly (1000) immediately after final token/tool-call
    // without emitting an explicit chat.done frame.
    if (code === 1000 && (sawContentChunk || sawToolChunk)) {
      completed = true;
      queue.push(
        toDoneChunk(requestId ?? 'chatcmpl-lmx', model, sawToolChunk ? 'tool_calls' : 'stop')
      );
      finish();
      return;
    }

    const reason = Buffer.isBuffer(reasonBuf)
      ? reasonBuf.toString('utf-8')
      : String(reasonBuf ?? '');
    const details = reason ? ` (code ${code}: ${reason})` : ` (code ${code})`;
    fail(new Error(`LMX websocket stream closed unexpectedly${details}`));
  });

  if (handshakeTimeoutMs > 0) {
    handshakeTimer = setTimeout(() => {
      if (completed) return;
      fail(new Error(`LMX websocket handshake timed out after ${handshakeTimeoutMs}ms`));
    }, handshakeTimeoutMs);
  }
  options?.signal?.addEventListener('abort', onAbort, { once: true });
  return queue;
}

import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { getConfigDir } from '../platform/paths.js';

export interface EndpointScore {
  host: string;
  success: number;
  failure: number;
  lastSeenAt: string;
}

interface EndpointProfileFile {
  version: 1;
  endpoints: EndpointScore[];
}

function resolveProfilePath(path?: string): string {
  if (path && path.trim().length > 0) return path;
  const fromEnv = process.env['OPTA_LMX_ENDPOINT_PROFILE_PATH'];
  if (fromEnv && fromEnv.trim().length > 0) return fromEnv;
  return profilePath();
}

function profilePath(): string {
  return join(getConfigDir(), 'lmx-endpoints.json');
}

function normalizeHost(host: string): string {
  return host.trim().toLowerCase();
}

function profileScore(entry: EndpointScore, nowMs: number): number {
  const lastSeenMs = Date.parse(entry.lastSeenAt);
  const recencyPenalty =
    Number.isFinite(lastSeenMs) && lastSeenMs > 0
      ? Math.min(48, (nowMs - lastSeenMs) / (1000 * 60 * 60))
      : 48;
  return entry.success * 5 - entry.failure * 3 - recencyPenalty;
}

export function rankHostsByProfile(
  hosts: readonly string[],
  entries: readonly EndpointScore[],
  nowMs = Date.now()
): string[] {
  if (hosts.length <= 1 || entries.length === 0) {
    return [...hosts];
  }

  const lookup = new Map(entries.map((entry) => [normalizeHost(entry.host), entry] as const));
  return [...hosts]
    .map((host, index) => {
      const entry = lookup.get(normalizeHost(host));
      const score = entry ? profileScore(entry, nowMs) : Number.NEGATIVE_INFINITY;
      return { host, index, score };
    })
    .sort((a, b) => {
      if (a.score !== b.score) return b.score - a.score;
      return a.index - b.index;
    })
    .map((item) => item.host);
}

export async function loadEndpointProfile(path = profilePath()): Promise<EndpointScore[]> {
  const resolvedPath = resolveProfilePath(path);
  try {
    const raw = await readFile(resolvedPath, 'utf-8');
    const parsed = JSON.parse(raw) as EndpointProfileFile;
    if (!parsed || parsed.version !== 1 || !Array.isArray(parsed.endpoints)) {
      return [];
    }
    return parsed.endpoints.filter(
      (entry): entry is EndpointScore =>
        typeof entry?.host === 'string' &&
        typeof entry?.success === 'number' &&
        typeof entry?.failure === 'number' &&
        typeof entry?.lastSeenAt === 'string'
    );
  } catch {
    return [];
  }
}

async function saveEndpointProfile(entries: readonly EndpointScore[], path = profilePath()): Promise<void> {
  const resolvedPath = resolveProfilePath(path);
  await mkdir(dirname(resolvedPath), { recursive: true });
  const payload: EndpointProfileFile = {
    version: 1,
    endpoints: [...entries],
  };
  await writeFile(resolvedPath, JSON.stringify(payload, null, 2), 'utf-8');
}

export async function prioritizeHostsByProfile(
  hosts: readonly string[],
  path = profilePath()
): Promise<string[]> {
  const entries = await loadEndpointProfile(resolveProfilePath(path));
  return rankHostsByProfile(hosts, entries);
}

export async function recordEndpointProbeOutcome(
  host: string,
  success: boolean,
  path = profilePath(),
  now = new Date()
): Promise<void> {
  if (!host.trim()) return;
  const normalized = normalizeHost(host);
  const resolvedPath = resolveProfilePath(path);
  const existing = await loadEndpointProfile(resolvedPath);
  const byHost = new Map(existing.map((entry) => [normalizeHost(entry.host), entry] as const));
  const current = byHost.get(normalized) ?? {
    host,
    success: 0,
    failure: 0,
    lastSeenAt: now.toISOString(),
  };

  const updated: EndpointScore = {
    host: current.host,
    success: success ? current.success + 1 : current.success,
    failure: success ? current.failure : current.failure + 1,
    lastSeenAt: now.toISOString(),
  };
  byHost.set(normalized, updated);

  await saveEndpointProfile([...byHost.values()], resolvedPath);
}

// Backward-compatible alias used by some callers/tests.
export async function recordEndpointProbe(
  host: string,
  success: boolean,
  path = profilePath(),
  now = new Date()
): Promise<void> {
  await recordEndpointProbeOutcome(host, success, path, now);
}

import type { LmxConnectionState } from './connection.js';
import { probeLmxConnection } from './connection.js';
import { discoverLmxHosts } from './mdns-discovery.js';
import { prioritizeHostsByProfile, recordEndpointProbeOutcome } from './endpoint-profile.js';
import type { AdminKeysByHost } from './admin-keys.js';

export interface LmxEndpointConfig {
  host: string;
  port: number;
  adminKey?: string;
  adminKeysByHost?: AdminKeysByHost;
  fallbackHosts?: string[];
  /** When true (default), scan the LAN for LMX servers if no primary is configured. */
  autoDiscover?: boolean;
}

export interface ResolvedLmxEndpoint {
  host: string;
  port: number;
  source: 'primary' | 'fallback';
  state: LmxConnectionState | 'unknown';
  /** Canonical WebSocket URL from server discovery, if available. */
  wsUrl?: string;
}

interface ResolveEndpointOptions {
  timeoutMs?: number;
  signal?: AbortSignal;
  /** Delay before committing to a fallback host when primary is still in flight. */
  primaryGraceMs?: number;
}

const DEFAULT_PROBE_TIMEOUT_MS = 1_500;
const ENDPOINT_CACHE_TTL_MS = 30_000;
const DEFAULT_PRIMARY_GRACE_MS = 125;

interface CachedEndpoint {
  host: string;
  expiresAt: number;
}

const endpointCache = new Map<string, CachedEndpoint>();

interface ProbeOutcome {
  host: string;
  index: number;
  source: 'primary' | 'fallback';
  state: LmxConnectionState;
  completionOrder: number;
  wsUrl?: string;
}

function normalizeHost(host: string): string {
  return host.trim();
}

export function listCandidateHosts(config: Pick<LmxEndpointConfig, 'host' | 'fallbackHosts'>): string[] {
  const hosts = [config.host, ...(config.fallbackHosts ?? [])]
    .map(normalizeHost)
    .filter((host) => host.length > 0);

  const deduped: string[] = [];
  const seen = new Set<string>();
  for (const host of hosts) {
    const key = host.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    deduped.push(host);
  }

  return deduped;
}

function makeCacheKey(port: number, hosts: readonly string[]): string {
  return `${port}|${hosts.map((host) => host.toLowerCase()).join(',')}`;
}

function cacheEndpoint(key: string, host: string): void {
  endpointCache.set(key, {
    host,
    expiresAt: Date.now() + ENDPOINT_CACHE_TTL_MS,
  });
}

export function clearLmxEndpointCache(): void {
  endpointCache.clear();
}

function makeAbortError(message: string): Error {
  const err = new Error(message);
  err.name = 'AbortError';
  return err;
}

function selectEarliest(
  outcomes: Iterable<ProbeOutcome>,
  predicate: (outcome: ProbeOutcome) => boolean,
): ProbeOutcome | undefined {
  let selected: ProbeOutcome | undefined;
  for (const outcome of outcomes) {
    if (!predicate(outcome)) continue;
    if (!selected || outcome.completionOrder < selected.completionOrder) {
      selected = outcome;
    }
  }
  return selected;
}

export async function resolveLmxEndpoint(
  config: LmxEndpointConfig,
  options?: ResolveEndpointOptions,
): Promise<ResolvedLmxEndpoint> {
  if (options?.signal?.aborted) {
    throw makeAbortError('LMX endpoint resolution aborted');
  }

  let candidates = listCandidateHosts(config);
  const normalizedPrimary = normalizeHost(config.host);

  // Auto-discover LMX servers on the LAN when enabled and no explicit host is configured
  if (config.autoDiscover !== false && candidates.length === 0) {
    try {
      const discovered = await discoverLmxHosts(1500);
      const discoveredHosts = discovered.map((d) => d.host);
      // Rebuild candidates with discovered hosts prepended
      candidates = listCandidateHosts({
        host: discoveredHosts[0] ?? config.host,
        fallbackHosts: [...discoveredHosts.slice(1), ...(config.fallbackHosts ?? [])],
      });
    } catch { /* discovery is best-effort */ }
  }

  if (candidates.length > 1) {
    try {
      candidates = await prioritizeHostsByProfile(candidates);
    } catch {
      // Profile ranking is best-effort.
    }
  }

  const primaryHost = candidates[0] ?? (normalizedPrimary.length > 0 ? normalizedPrimary : 'localhost');
  const cacheKey = makeCacheKey(config.port, candidates);

  const cached = endpointCache.get(cacheKey);
  if (cached && cached.expiresAt > Date.now()) {
    const stillPresent = candidates.some((host) => host.toLowerCase() === cached.host.toLowerCase());
    if (stillPresent) {
      return {
        host: cached.host,
        port: config.port,
        source: cached.host.toLowerCase() === primaryHost.toLowerCase() ? 'primary' : 'fallback',
        state: 'unknown',
      };
    }
  }

  if (candidates.length === 0) {
    return {
      host: primaryHost,
      port: config.port,
      source: 'primary',
      state: 'unknown',
    };
  }

  const timeoutMs = Math.max(250, options?.timeoutMs ?? DEFAULT_PROBE_TIMEOUT_MS);
  const primaryGraceMs = Math.max(0, Math.min(timeoutMs, options?.primaryGraceMs ?? DEFAULT_PRIMARY_GRACE_MS));
  const primaryIndex = candidates.findIndex((host) => host.toLowerCase() === primaryHost.toLowerCase());
  const signal = options?.signal;

  return new Promise<ResolvedLmxEndpoint>((resolve, reject) => {
    let settled = false;
    let remaining = candidates.length;
    let completionOrder = 0;
    const outcomes = new Map<number, ProbeOutcome>();
    let pendingFallbackConnected: ProbeOutcome | undefined;
    let fallbackGraceTimer: ReturnType<typeof setTimeout> | undefined;

    const cleanup = () => {
      if (fallbackGraceTimer) {
        clearTimeout(fallbackGraceTimer);
        fallbackGraceTimer = undefined;
      }
      signal?.removeEventListener('abort', onAbort);
    };

    const settle = (endpoint: ResolvedLmxEndpoint) => {
      if (settled) return;
      settled = true;
      cleanup();
      if (endpoint.state === 'connected' || endpoint.state === 'degraded') {
        cacheEndpoint(cacheKey, endpoint.host);
      }
      resolve(endpoint);
    };

    const settleUnknownPrimary = () => {
      settle({
        host: primaryHost,
        port: config.port,
        source: 'primary',
        state: 'unknown',
      });
    };

    const settleOutcome = (outcome: ProbeOutcome) => {
      settle({
        host: outcome.host,
        port: config.port,
        source: outcome.source,
        state: outcome.state,
        wsUrl: outcome.wsUrl,
      });
    };

    const onAbort = () => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(makeAbortError('LMX endpoint resolution aborted'));
    };

    const getPrimaryOutcome = () => (primaryIndex >= 0 ? outcomes.get(primaryIndex) : undefined);

    const finalizeIfAllDone = () => {
      if (settled || remaining > 0) return;

      const primaryOutcome = getPrimaryOutcome();
      if (primaryOutcome?.state === 'connected') {
        settleOutcome(primaryOutcome);
        return;
      }

      const fallbackConnected = selectEarliest(
        outcomes.values(),
        (outcome) => outcome.source === 'fallback' && outcome.state === 'connected',
      );
      if (fallbackConnected) {
        settleOutcome(fallbackConnected);
        return;
      }

      if (primaryOutcome?.state === 'degraded') {
        settleOutcome(primaryOutcome);
        return;
      }

      const fallbackDegraded = selectEarliest(
        outcomes.values(),
        (outcome) => outcome.source === 'fallback' && outcome.state === 'degraded',
      );
      if (fallbackDegraded) {
        settleOutcome(fallbackDegraded);
        return;
      }

      settleUnknownPrimary();
    };

    const armFallbackGraceTimer = () => {
      if (settled || fallbackGraceTimer || !pendingFallbackConnected) return;
      fallbackGraceTimer = setTimeout(() => {
        fallbackGraceTimer = undefined;
        if (settled) return;

        const primaryOutcome = getPrimaryOutcome();
        if (primaryOutcome?.state === 'connected') {
          settleOutcome(primaryOutcome);
          return;
        }

        if (pendingFallbackConnected) {
          settleOutcome(pendingFallbackConnected);
        }
      }, primaryGraceMs);
    };

    const handleOutcome = (outcome: ProbeOutcome) => {
      if (settled) return;

      void recordEndpointProbeOutcome(outcome.host, outcome.state !== 'disconnected').catch(() => {
        // Endpoint profile updates are best-effort and never block resolution.
      });

      outcomes.set(outcome.index, outcome);
      remaining -= 1;

      const primaryOutcome = getPrimaryOutcome();

      if (outcome.source === 'primary') {
        if (outcome.state === 'connected') {
          settleOutcome(outcome);
          return;
        }

        if (pendingFallbackConnected && (outcome.state === 'degraded' || outcome.state === 'disconnected')) {
          settleOutcome(pendingFallbackConnected);
          return;
        }
      } else if (outcome.state === 'connected') {
        if (
          !pendingFallbackConnected
          || outcome.completionOrder < pendingFallbackConnected.completionOrder
        ) {
          pendingFallbackConnected = outcome;
        }

        if (primaryOutcome) {
          if (primaryOutcome.state === 'connected') {
            settleOutcome(primaryOutcome);
            return;
          }

          if (primaryOutcome.state === 'degraded' || primaryOutcome.state === 'disconnected') {
            settleOutcome(pendingFallbackConnected);
            return;
          }
        } else {
          armFallbackGraceTimer();
        }
      }

      finalizeIfAllDone();
    };

    signal?.addEventListener('abort', onAbort, { once: true });
    if (signal?.aborted) {
      onAbort();
      return;
    }

    for (const [index, host] of candidates.entries()) {
      const source = host.toLowerCase() === primaryHost.toLowerCase() ? 'primary' : 'fallback';
      void probeLmxConnection(host, config.port, {
        timeoutMs,
        adminKey: config.adminKey,
        adminKeysByHost: config.adminKeysByHost,
      }).then((probe) => {
        handleOutcome({
          host,
          index,
          source,
          state: probe.state,
          completionOrder: completionOrder++,
          wsUrl: probe.discovery?.endpoints?.websocket_url,
        });
      }).catch(() => {
        handleOutcome({
          host,
          index,
          source,
          state: 'disconnected',
          completionOrder: completionOrder++,
        });
      });
    }
  });
}

/**
 * Zero-config LMX auto-discovery via mDNS and LAN subnet sweep.
 *
 * Uses ONLY Node.js built-ins (dgram, os, net, http) — no external packages.
 */

import dgram from 'node:dgram';
import os from 'node:os';
import http from 'node:http';

// ── Public types ────────────────────────────────────────────────────────────

export interface DiscoveredHost {
  host: string;
  port: number;
  latencyMs: number;
  source: 'mdns' | 'sweep';
  modelCount?: number;
}

// ── mDNS PTR query ──────────────────────────────────────────────────────────

const MDNS_MULTICAST_ADDR = '224.0.0.251';
const MDNS_PORT = 5353;
const SERVICE_NAME = '_opta-lmx._tcp.local';

/** Encode a DNS domain name into label-format bytes. */
function encodeDnsName(name: string): Buffer {
  const labels = name.split('.');
  const parts: Buffer[] = [];
  for (const label of labels) {
    const encoded = Buffer.from(label, 'utf-8');
    parts.push(Buffer.from([encoded.length]), encoded);
  }
  parts.push(Buffer.from([0])); // null terminator
  return Buffer.concat(parts);
}

/** Build a minimal DNS query packet for PTR record (type=12, class=1). */
function buildMdnsQuery(): Buffer {
  // Header: 12 bytes
  const header = Buffer.alloc(12);
  header.writeUInt16BE(0x0000, 0); // Transaction ID
  header.writeUInt16BE(0x0000, 2); // Flags: standard query
  header.writeUInt16BE(1, 4);      // QDCOUNT: 1 question
  header.writeUInt16BE(0, 6);      // ANCOUNT
  header.writeUInt16BE(0, 8);      // NSCOUNT
  header.writeUInt16BE(0, 10);     // ARCOUNT

  // Question section
  const name = encodeDnsName(SERVICE_NAME);
  const qFooter = Buffer.alloc(4);
  qFooter.writeUInt16BE(12, 0);    // QTYPE: PTR
  qFooter.writeUInt16BE(1, 2);     // QCLASS: IN

  return Buffer.concat([header, name, qFooter]);
}

/** Parse a DNS name from a response buffer, handling compression pointers. */
function parseDnsName(buf: Buffer, offset: number): { name: string; newOffset: number } {
  const labels: string[] = [];
  let currentOffset = offset;
  let jumped = false;
  let returnOffset = offset;

  for (let i = 0; i < 128; i++) { // safety limit
    if (currentOffset >= buf.length) break;
    const len = buf[currentOffset]!;
    if (len === 0) {
      if (!jumped) returnOffset = currentOffset + 1;
      break;
    }
    // Compression pointer
    if ((len & 0xc0) === 0xc0) {
      if (currentOffset + 1 >= buf.length) break;
      if (!jumped) returnOffset = currentOffset + 2;
      currentOffset = ((len & 0x3f) << 8) | buf[currentOffset + 1]!;
      jumped = true;
      continue;
    }
    currentOffset++;
    if (currentOffset + len > buf.length) break;
    labels.push(buf.subarray(currentOffset, currentOffset + len).toString('utf-8'));
    currentOffset += len;
  }

  return { name: labels.join('.'), newOffset: jumped ? returnOffset : currentOffset };
}

interface MdnsResult {
  host: string;
  port: number;
}

/** Extract SRV + A records from mDNS response to find host:port. */
function parseMdnsResponse(buf: Buffer): MdnsResult[] {
  if (buf.length < 12) return [];

  const ancount = buf.readUInt16BE(6);
  const nscount = buf.readUInt16BE(8);
  const arcount = buf.readUInt16BE(10);
  const totalRecords = ancount + nscount + arcount;

  // Skip questions
  const qdcount = buf.readUInt16BE(4);
  let offset = 12;
  for (let i = 0; i < qdcount && offset < buf.length; i++) {
    const { newOffset } = parseDnsName(buf, offset);
    offset = newOffset + 4; // skip QTYPE + QCLASS
  }

  const srvRecords: Array<{ target: string; port: number }> = [];
  const aRecords = new Map<string, string>(); // name -> IP

  for (let i = 0; i < totalRecords && offset < buf.length; i++) {
    const { name, newOffset } = parseDnsName(buf, offset);
    offset = newOffset;
    if (offset + 10 > buf.length) break;

    const rtype = buf.readUInt16BE(offset);
    const rdlength = buf.readUInt16BE(offset + 8);
    offset += 10;

    if (offset + rdlength > buf.length) break;

    // SRV record (type 33)
    if (rtype === 33 && rdlength >= 6) {
      const port = buf.readUInt16BE(offset + 4);
      const { name: target } = parseDnsName(buf, offset + 6);
      srvRecords.push({ target, port });
    }

    // A record (type 1)
    if (rtype === 1 && rdlength === 4) {
      const ip = `${buf[offset]}.${buf[offset + 1]}.${buf[offset + 2]}.${buf[offset + 3]}`;
      aRecords.set(name.toLowerCase(), ip);
    }

    offset += rdlength;
  }

  const results: MdnsResult[] = [];
  for (const srv of srvRecords) {
    const ip = aRecords.get(srv.target.toLowerCase());
    if (ip) {
      results.push({ host: ip, port: srv.port });
    }
  }
  return results;
}

async function discoverViaMdns(timeoutMs: number): Promise<DiscoveredHost[]> {
  return new Promise((resolve) => {
    const hosts: DiscoveredHost[] = [];
    const seen = new Set<string>();
    const started = Date.now();

    let socket: dgram.Socket;
    try {
      socket = dgram.createSocket({ type: 'udp4', reuseAddr: true });
    } catch {
      resolve([]);
      return;
    }

    const finish = () => {
      try { socket.close(); } catch { /* ignore */ }
      resolve(hosts);
    };

    const timer = setTimeout(finish, timeoutMs);

    socket.on('error', () => {
      clearTimeout(timer);
      finish();
    });

    socket.on('message', (msg) => {
      const results = parseMdnsResponse(msg);
      for (const r of results) {
        const key = `${r.host}:${r.port}`;
        if (seen.has(key)) continue;
        seen.add(key);
        hosts.push({
          host: r.host,
          port: r.port,
          latencyMs: Date.now() - started,
          source: 'mdns',
        });
      }
    });

    socket.bind(0, () => {
      try {
        socket.addMembership(MDNS_MULTICAST_ADDR);
      } catch {
        // Some systems don't support multicast — proceed anyway
      }
      const query = buildMdnsQuery();
      socket.send(query, 0, query.length, MDNS_PORT, MDNS_MULTICAST_ADDR, (err) => {
        if (err) {
          clearTimeout(timer);
          finish();
        }
      });
    });
  });
}

// ── LAN subnet sweep ────────────────────────────────────────────────────────

const DEFAULT_LMX_PORT = 1234;
const SWEEP_CONCURRENCY = 32;

/** Get all local IPv4 addresses (non-loopback). */
function getLocalIpv4Addresses(): string[] {
  const interfaces = os.networkInterfaces();
  const addresses: string[] = [];
  for (const iface of Object.values(interfaces)) {
    if (!iface) continue;
    for (const info of iface) {
      if (info.family === 'IPv4' && !info.internal) {
        addresses.push(info.address);
      }
    }
  }
  return addresses;
}

/** Compute /24 subnet IPs from a given local address. */
function computeSubnetIps(localIp: string): string[] {
  const parts = localIp.split('.');
  if (parts.length !== 4) return [];
  const prefix = parts.slice(0, 3).join('.');
  const ips: string[] = [];
  for (let i = 1; i <= 254; i++) {
    ips.push(`${prefix}.${i}`);
  }
  return ips;
}

interface WellKnownResponse {
  name?: string;
  version?: string;
  models?: unknown;
  service?: string;
  loaded_models?: unknown[];
}

/** Probe a single IP for the LMX well-known endpoint. */
function probeLmxWellKnown(
  ip: string,
  port: number,
  probeTimeoutMs: number,
): Promise<DiscoveredHost | null> {
  const started = Date.now();
  return new Promise((resolve) => {
    const req = http.get(
      {
        hostname: ip,
        port,
        path: '/.well-known/opta-lmx',
        timeout: probeTimeoutMs,
      },
      (res) => {
        if (res.statusCode !== 200) {
          res.resume(); // drain
          resolve(null);
          return;
        }
        const chunks: Buffer[] = [];
        res.on('data', (chunk: Buffer) => chunks.push(chunk));
        res.on('end', () => {
          try {
            const body = JSON.parse(Buffer.concat(chunks).toString('utf-8')) as WellKnownResponse;
            if (body.name || body.version || body.models || body.service) {
              const modelCount = Array.isArray(body.loaded_models) ? body.loaded_models.length : undefined;
              resolve({
                host: ip,
                port,
                latencyMs: Date.now() - started,
                source: 'sweep',
                modelCount,
              });
              return;
            }
          } catch { /* not valid JSON */ }
          resolve(null);
        });
        res.on('error', () => resolve(null));
      },
    );
    req.on('error', () => resolve(null));
    req.on('timeout', () => {
      req.destroy();
      resolve(null);
    });
  });
}

async function discoverViaSubnetSweep(timeoutMs: number): Promise<DiscoveredHost[]> {
  const addresses = getLocalIpv4Addresses();
  if (addresses.length === 0) return [];

  // Collect unique candidate IPs across all local subnets
  const candidateSet = new Set<string>();
  for (const addr of addresses) {
    for (const ip of computeSubnetIps(addr)) {
      candidateSet.add(ip);
    }
  }
  const candidates = Array.from(candidateSet);

  const probeTimeoutMs = Math.min(800, timeoutMs);
  const hosts: DiscoveredHost[] = [];
  let active = 0;
  let index = 0;

  return new Promise((resolve) => {
    const overallTimer = setTimeout(() => resolve(hosts), timeoutMs);

    function scheduleNext(): void {
      while (active < SWEEP_CONCURRENCY && index < candidates.length) {
        const ip = candidates[index++]!;
        active++;
        probeLmxWellKnown(ip, DEFAULT_LMX_PORT, probeTimeoutMs).then((result) => {
          active--;
          if (result) hosts.push(result);
          if (index >= candidates.length && active === 0) {
            clearTimeout(overallTimer);
            resolve(hosts);
            return;
          }
          scheduleNext();
        }).catch(() => {
          active--;
          if (index >= candidates.length && active === 0) {
            clearTimeout(overallTimer);
            resolve(hosts);
            return;
          }
          scheduleNext();
        });
      }
    }

    scheduleNext();

    // Edge case: no candidates at all
    if (candidates.length === 0) {
      clearTimeout(overallTimer);
      resolve(hosts);
    }
  });
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Discover Opta-LMX servers on the local network.
 *
 * Runs two strategies concurrently:
 * 1. mDNS PTR query for `_opta-lmx._tcp.local`
 * 2. LAN /24 subnet sweep probing `/.well-known/opta-lmx`
 *
 * Results are merged, deduplicated by host IP, and sorted by latency.
 */
export async function discoverLmxHosts(timeoutMs = 3000): Promise<DiscoveredHost[]> {
  const mdnsTimeout = Math.min(2000, timeoutMs);
  const sweepTimeout = timeoutMs;

  const [mdnsResult, sweepResult] = await Promise.allSettled([
    discoverViaMdns(mdnsTimeout),
    discoverViaSubnetSweep(sweepTimeout),
  ]);

  const allHosts: DiscoveredHost[] = [];
  if (mdnsResult.status === 'fulfilled') allHosts.push(...mdnsResult.value);
  if (sweepResult.status === 'fulfilled') allHosts.push(...sweepResult.value);

  // Deduplicate by host IP, keeping the entry with lowest latency
  const byHost = new Map<string, DiscoveredHost>();
  for (const host of allHosts) {
    const existing = byHost.get(host.host);
    if (!existing || host.latencyMs < existing.latencyMs) {
      byHost.set(host.host, host);
    }
  }

  // Sort by latency (fastest first)
  return Array.from(byHost.values()).sort((a, b) => a.latencyMs - b.latencyMs);
}

/**
 * model-catalog.ts — User-configurable model groups for the /model picker.
 *
 * A ModelGroup is the single unit of configuration: name, label, color, patterns.
 * Groups are checked in array order; the first group whose patterns match wins.
 * Any model that matches no group falls into the last group if it has empty
 * patterns (treat it as a catch-all), or into an implicit "Other" bucket.
 *
 * Users can replace DEFAULT_GROUPS entirely via config.model.groups, or manage
 * groups with /model group commands.
 *
 * Pattern syntax (each string in the patterns array):
 *   "dolphin"          plain substring — case-insensitive contains match
 *   "/deepseek-r1/i"   regex — string wrapped in /…/flags parsed as RegExp
 */

export interface ModelGroup {
  name: string;
  label: string;
  color?: string;
  /** Plain substrings or "/regex/flags" strings. */
  patterns: string[];
}

/** Built-in groups — used when the user has not defined custom groups. */
export const DEFAULT_GROUPS: ModelGroup[] = [
  {
    name: 'jailbroken',
    label: '⚡ Jailbroken',
    color: '#f87171',
    patterns: ['dolphin', 'airoboros', 'manticore', 'samantha', 'abliterat', 'uncensored', 'wizard-vicuna', 'jailbreak'],
  },
  {
    name: 'embedding',
    label: '⊞ Embedding',
    color: '#60a5fa',
    patterns: ['embed', 'bge-', 'bge_', 'e5-', 'all-minilm', 'gte-'],
  },
  {
    name: 'vision',
    label: '◉ Vision',
    color: '#34d399',
    patterns: ['llava', 'moondream', 'minicpm-v', 'internvl', 'pixtral', 'paligemma', 'cogvlm', 'idefics', '-vl', 'vision'],
  },
  {
    name: 'reasoning',
    label: '◈ Reasoning',
    color: '#a78bfa',
    patterns: ['deepseek-r1', 'r1-distill', '-r1', 'qwq', 'thinking', 'reasoning', 'o1-', 'o3-'],
  },
  {
    name: 'coding',
    label: '⌨ Coding',
    color: '#22d3ee',
    patterns: ['coder', 'codestral', 'starcoder', 'granite-code', 'devstral', 'wizardcoder', 'codegemma', 'codellama', 'code-llama'],
  },
  {
    name: 'fast',
    label: '◌ Fast',
    color: '#fbbf24',
    patterns: ['tinyllama', 'smollm', 'orca-mini', 'phi-1.', 'phi-2', 'gemma-2b', 'gemma-2-2b', '-1b', '-2b', '-3b'],
  },
  {
    name: 'chat',
    label: '◎ Chat',
    color: '#94a3b8',
    patterns: [], // empty = catch-all
  },
];

/**
 * Compile a user-facing pattern string into a RegExp.
 *   "/deepseek-r1/i" → new RegExp("deepseek-r1", "i")
 *   "dolphin"        → /dolphin/i  (plain substring, case-insensitive)
 */
export function compilePattern(pattern: string): RegExp {
  const regexMatch = /^\/(.+)\/([gimsuy]*)$/.exec(pattern);
  if (regexMatch) {
    return new RegExp(regexMatch[1]!, regexMatch[2] || 'i');
  }
  return new RegExp(pattern.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i');
}

/**
 * Returns true if modelId matches any pattern in the group.
 * A group with empty patterns always matches (catch-all).
 */
export function groupMatches(modelId: string, group: ModelGroup): boolean {
  if (group.patterns.length === 0) return true;
  return group.patterns.some(p => compilePattern(p).test(modelId));
}

/**
 * Find the first matching group for a model ID.
 * Returns the last group if it has empty patterns (catch-all) or null if nothing matches.
 */
export function classifyModel(modelId: string, groups: ModelGroup[]): ModelGroup | null {
  for (const group of groups) {
    if (groupMatches(modelId, group)) return group;
  }
  return null;
}

/**
 * LSP Client
 *
 * Manages a single LSP server process over stdio with JSON-RPC 2.0.
 * Handles: spawn, initialize handshake, document sync, requests, shutdown.
 */

import { spawn, type ChildProcess } from 'node:child_process';
import { readFile } from 'node:fs/promises';
import type {
  Position,
  Range,
  Location,
  SymbolInformation,
  DocumentSymbol,
  Diagnostic,
  CodeAction,
  WorkspaceEdit,
} from './protocol.js';
import { uriToFilePath } from './protocol.js';
import { assertSafeExecutableCommand } from '../utils/command-safety.js';
import { errorMessage } from '../utils/errors.js';

export interface LspClientOptions {
  command: string;
  args: string[];
  rootUri: string;
  language: string;
  cwd?: string;
}

export class LspClient {
  private process: ChildProcess | null = null;
  private nextId = 1;
  private pending = new Map<
    number,
    { resolve: (value: unknown) => void; reject: (reason: unknown) => void }
  >();
  private openDocs = new Set<string>();
  private docVersions = new Map<string, number>();
  private buffer = Buffer.alloc(0);
  private readonly MAX_BUFFER_SIZE = 64 * 1024 * 1024; // 64MB
  private initialized = false;

  constructor(private opts: LspClientOptions) {}

  // --- Lifecycle ---

  async initialize(options?: { timeout?: number }): Promise<void> {
    const timeout = options?.timeout ?? 10000;

    assertSafeExecutableCommand(this.opts.command, 'LSP server');

    this.process = spawn(this.opts.command, this.opts.args, {
      stdio: ['pipe', 'pipe', 'pipe'],
      cwd: this.opts.cwd,
    });

    this.process.stdout!.on('data', (data: Buffer) => {
      this.handleData(data);
    });

    this.process.stderr!.on('data', () => {
      // Ignore stderr, but read it to prevent pipe blocking
    });

    this.process.on('exit', (_code, _signal) => {
      // Reject all pending requests
      for (const [, pending] of this.pending) {
        pending.reject(new Error('LSP server process exited'));
      }
      this.pending.clear();
      this.initialized = false;
    });

    const result = await this.sendRequest(
      'initialize',
      {
        processId: process.pid,
        rootUri: this.opts.rootUri,
        capabilities: {
          textDocument: {
            synchronization: {
              dynamicRegistration: false,
              willSave: false,
              didSave: true,
              willSaveWaitUntil: false,
            },
            definition: { dynamicRegistration: false },
            references: { dynamicRegistration: false },
            hover: { dynamicRegistration: false },
            documentSymbol: {
              dynamicRegistration: false,
              hierarchicalDocumentSymbolSupport: true,
            },
            codeAction: { dynamicRegistration: false },
            diagnostic: { dynamicRegistration: false },
            rename: { dynamicRegistration: false },
          },
          workspace: {
            symbol: { dynamicRegistration: false },
          },
        },
      },
      timeout
    );

    this.initialized = true;

    // Send initialized notification
    this.sendNotification('initialized', {});

    return result as undefined;
  }

  async shutdown(): Promise<void> {
    if (!this.process || !this.initialized) {
      if (this.process) {
        this.process.kill();
        this.process = null;
      }
      return;
    }

    try {
      await this.sendRequest('shutdown', null, 5000);
    } catch {
      // Best effort
    }

    this.sendNotification('exit', null);
    this.process.kill();
    this.process = null;
    this.initialized = false;
  }

  // --- Document Sync ---

  openDocument(uri: string, text: string): void {
    if (this.openDocs.has(uri)) return;

    this.docVersions.set(uri, 1);
    this.sendNotification('textDocument/didOpen', {
      textDocument: {
        uri,
        languageId: this.opts.language,
        version: 1,
        text,
      },
    });
    this.openDocs.add(uri);
  }

  closeDocument(uri: string): void {
    if (!this.openDocs.has(uri)) return;

    this.sendNotification('textDocument/didClose', {
      textDocument: { uri },
    });
    this.openDocs.delete(uri);
    this.docVersions.delete(uri);
  }

  notifyChange(uri: string, newText: string): void {
    if (!this.openDocs.has(uri)) return;

    const version = (this.docVersions.get(uri) ?? 1) + 1;
    this.docVersions.set(uri, version);

    this.sendNotification('textDocument/didChange', {
      textDocument: { uri, version },
      contentChanges: [{ text: newText }],
    });
  }

  isDocumentOpen(uri: string): boolean {
    return this.openDocs.has(uri);
  }

  // --- LSP Requests ---

  async definition(uri: string, position: Position): Promise<Location[]> {
    this.assertInitialized();
    await this.ensureDocumentOpen(uri);

    const result = await this.sendRequest('textDocument/definition', {
      textDocument: { uri },
      position,
    });

    return this.normalizeLocations(result);
  }

  async references(
    uri: string,
    position: Position,
    includeDeclaration = true
  ): Promise<Location[]> {
    this.assertInitialized();
    await this.ensureDocumentOpen(uri);

    const result = await this.sendRequest('textDocument/references', {
      textDocument: { uri },
      position,
      context: { includeDeclaration },
    });

    return this.normalizeLocations(result);
  }

  async hover(uri: string, position: Position): Promise<unknown> {
    this.assertInitialized();
    await this.ensureDocumentOpen(uri);

    return this.sendRequest('textDocument/hover', {
      textDocument: { uri },
      position,
    });
  }

  async workspaceSymbols(query: string): Promise<SymbolInformation[]> {
    this.assertInitialized();

    const result = await this.sendRequest('workspace/symbol', { query });
    return (result as SymbolInformation[]) ?? [];
  }

  async documentSymbols(uri: string): Promise<DocumentSymbol[]> {
    this.assertInitialized();
    await this.ensureDocumentOpen(uri);

    const result = await this.sendRequest('textDocument/documentSymbol', {
      textDocument: { uri },
    });
    return (result as DocumentSymbol[]) ?? [];
  }

  async rename(uri: string, position: Position, newName: string): Promise<WorkspaceEdit> {
    this.assertInitialized();
    await this.ensureDocumentOpen(uri);

    const result = await this.sendRequest('textDocument/rename', {
      textDocument: { uri },
      position,
      newName,
    });
    return (result as WorkspaceEdit) ?? { changes: {} };
  }

  async diagnostics(uri: string): Promise<Diagnostic[]> {
    this.assertInitialized();
    await this.ensureDocumentOpen(uri);

    try {
      const result = await this.sendRequest('textDocument/diagnostic', {
        textDocument: { uri },
      });
      return this.normalizeDiagnostics(result);
    } catch (err) {
      if (this.isMethodUnsupported(err)) {
        return [];
      }
      throw err;
    }
  }

  async codeActions(
    uri: string,
    range: Range,
    options?: { only?: string[] }
  ): Promise<CodeAction[]> {
    this.assertInitialized();
    await this.ensureDocumentOpen(uri);

    const context: { diagnostics: Diagnostic[]; only?: string[] } = {
      diagnostics: [],
    };
    if (options?.only && options.only.length > 0) {
      context.only = options.only;
    }

    try {
      const result = await this.sendRequest('textDocument/codeAction', {
        textDocument: { uri },
        range,
        context,
      });
      return this.normalizeCodeActions(result);
    } catch (err) {
      if (this.isMethodUnsupported(err)) {
        return [];
      }
      throw err;
    }
  }

  // --- Internal JSON-RPC ---

  private sendRequest(method: string, params: unknown, timeout = 10000): Promise<unknown> {
    return new Promise((resolve, reject) => {
      if (!this.process?.stdin) {
        reject(new Error('LSP server not running'));
        return;
      }

      const id = this.nextId++;
      this.pending.set(id, { resolve, reject });

      const message = JSON.stringify({
        jsonrpc: '2.0',
        id,
        method,
        params,
      });

      const header = `Content-Length: ${Buffer.byteLength(message)}\r\n\r\n`;
      this.process.stdin.write(header + message);

      // Timeout
      const timer = setTimeout(() => {
        if (this.pending.has(id)) {
          this.pending.delete(id);
          reject(new Error(`LSP request "${method}" timed out after ${timeout}ms`));
        }
      }, timeout);

      // Replace resolve/reject with timer-clearing versions
      const origResolve = resolve;
      const origReject = reject;
      this.pending.set(id, {
        resolve: (value) => {
          clearTimeout(timer);
          origResolve(value);
        },
        reject: (reason) => {
          clearTimeout(timer);
          origReject(reason);
        },
      });
    });
  }

  private sendNotification(method: string, params: unknown): void {
    if (!this.process?.stdin) return;

    const message = JSON.stringify({
      jsonrpc: '2.0',
      method,
      params,
    });

    const header = `Content-Length: ${Buffer.byteLength(message)}\r\n\r\n`;
    this.process.stdin.write(header + message);
  }

  private handleData(data: Buffer): void {
    this.buffer = Buffer.concat([this.buffer, data]);

    // Guard against unbounded buffer growth from a misbehaving LSP server
    if (this.buffer.length > this.MAX_BUFFER_SIZE) {
      this.buffer = Buffer.alloc(0);
      for (const [, pending] of this.pending) {
        pending.reject(new Error('LSP buffer overflow — server sent too much data'));
      }
      this.pending.clear();
      return;
    }

    while (true) {
      // Parse Content-Length header
      const headerEnd = this.buffer.indexOf('\r\n\r\n');
      if (headerEnd === -1) break;

      const headerStr = this.buffer.subarray(0, headerEnd).toString();
      const match = headerStr.match(/Content-Length:\s*(\d+)/i);
      if (!match) {
        // Skip invalid header
        this.buffer = this.buffer.subarray(headerEnd + 4);
        continue;
      }

      const contentLength = parseInt(match[1]!, 10);
      const totalLength = headerEnd + 4 + contentLength;

      if (this.buffer.length < totalLength) break; // Need more data

      const body = this.buffer.subarray(headerEnd + 4, totalLength).toString();
      this.buffer = this.buffer.subarray(totalLength);

      try {
        const message = JSON.parse(body) as Record<string, unknown>;
        this.handleMessage(message);
      } catch {
        // Skip malformed JSON
      }
    }
  }

  private handleMessage(message: Record<string, unknown>): void {
    // Response (has id)
    if ('id' in message && typeof message['id'] === 'number') {
      const pending = this.pending.get(message['id']);
      if (pending) {
        this.pending.delete(message['id']);
        if ('error' in message && message['error']) {
          const err = message['error'] as Record<string, unknown>;
          const errMsg = err['message'];
          pending.reject(
            new Error(
              typeof errMsg === 'string'
                ? errMsg
                : typeof errMsg === 'object'
                  ? JSON.stringify(errMsg)
                  : errMsg == null
                    ? 'LSP error'
                    : String(errMsg as number | boolean | bigint)
            )
          );
        } else {
          pending.resolve(message['result']);
        }
      }
    }
    // Notifications from server (no id) -- ignore for now
  }

  // --- Helpers ---

  private assertInitialized(): void {
    if (!this.initialized) {
      throw new Error('LSP client not initialized');
    }
  }

  private async ensureDocumentOpen(uri: string): Promise<void> {
    if (this.openDocs.has(uri)) return;
    const filePath = uriToFilePath(uri);
    let text = '';
    try {
      text = await readFile(filePath, 'utf-8');
    } catch (error) {
      const code = (error as NodeJS.ErrnoException).code;
      if (code !== 'ENOENT') {
        throw error;
      }
      // The requested path may not exist in scratch/test contexts.
      // Open an empty virtual document so symbol/definition calls still route
      // through the LSP manager without crashing.
    }
    this.openDocument(uri, text);
  }

  private normalizeLocations(result: unknown): Location[] {
    if (!result) return [];
    if (Array.isArray(result)) return result as Location[];
    // Single location result
    if (typeof result === 'object' && 'uri' in (result as Record<string, unknown>)) {
      return [result as Location];
    }
    return [];
  }

  private normalizeDiagnostics(result: unknown): Diagnostic[] {
    if (!result) return [];
    if (Array.isArray(result)) return result as Diagnostic[];

    if (typeof result === 'object' && result && 'items' in (result as Record<string, unknown>)) {
      const items = (result as Record<string, unknown>)['items'];
      if (Array.isArray(items)) return items as Diagnostic[];
    }

    return [];
  }

  private normalizeCodeActions(result: unknown): CodeAction[] {
    if (!result || !Array.isArray(result)) return [];

    return result
      .filter((entry): entry is Record<string, unknown> => !!entry && typeof entry === 'object')
      .map((entry) => {
        const title = typeof entry['title'] === 'string' ? entry['title'] : '(untitled action)';
        const kind = typeof entry['kind'] === 'string' ? entry['kind'] : undefined;
        const isPreferred = entry['isPreferred'] === true;
        const disabled =
          entry['disabled'] && typeof entry['disabled'] === 'object'
            ? { reason: String((entry['disabled'] as Record<string, unknown>)['reason'] ?? '') }
            : undefined;
        const edit =
          entry['edit'] && typeof entry['edit'] === 'object'
            ? (entry['edit'] as WorkspaceEdit)
            : undefined;
        const command =
          entry['command'] && typeof entry['command'] === 'object'
            ? (entry['command'] as { title?: string; command?: string })
            : undefined;

        return {
          title,
          kind,
          isPreferred,
          disabled,
          edit,
          command,
        };
      });
  }

  private isMethodUnsupported(err: unknown): boolean {
    const message = errorMessage(err).toLowerCase();
    return (
      message.includes('method not found') ||
      message.includes('unsupported') ||
      message.includes('not implemented')
    );
  }
}

/**
 * LSP Protocol Helpers
 *
 * Pure functions for converting between LSP types and human-readable formats.
 * No I/O, no side effects.
 */

import { relative } from 'node:path';

// --- Types ---

export interface Position {
  line: number;
  character: number;
}

export interface Range {
  start: Position;
  end: Position;
}

export interface Location {
  uri: string;
  range: Range;
}

export interface SymbolInformation {
  name: string;
  kind: number;
  location: Location;
  containerName?: string;
}

export interface DocumentSymbol {
  name: string;
  kind: number;
  range: Range;
  selectionRange: Range;
  children?: DocumentSymbol[];
}

export interface TextEdit {
  range: Range;
  newText: string;
}

export interface WorkspaceEdit {
  changes?: Record<string, TextEdit[]>;
}

export interface Diagnostic {
  range: Range;
  severity?: number;
  code?: string | number;
  source?: string;
  message: string;
}

export interface CodeActionCommand {
  title?: string;
  command?: string;
}

export interface CodeAction {
  title: string;
  kind?: string;
  isPreferred?: boolean;
  disabled?: { reason?: string };
  edit?: WorkspaceEdit;
  command?: CodeActionCommand;
}

// --- Symbol Kind Names ---

const SYMBOL_KIND_NAMES: Record<number, string> = {
  1: 'File',
  2: 'Module',
  3: 'Namespace',
  4: 'Package',
  5: 'Class',
  6: 'Method',
  7: 'Property',
  8: 'Field',
  9: 'Constructor',
  10: 'Enum',
  11: 'Interface',
  12: 'Function',
  13: 'Variable',
  14: 'Constant',
  15: 'String',
  16: 'Number',
  17: 'Boolean',
  18: 'Array',
  19: 'Object',
  20: 'Key',
  21: 'Null',
  22: 'EnumMember',
  23: 'Struct',
  24: 'Event',
  25: 'Operator',
  26: 'TypeParameter',
};

const DIAGNOSTIC_SEVERITY_NAMES: Record<number, string> = {
  1: 'Error',
  2: 'Warning',
  3: 'Information',
  4: 'Hint',
};

function symbolKindName(kind: number): string {
  return SYMBOL_KIND_NAMES[kind] ?? `Kind(${kind})`;
}

// --- URI Conversion ---

export function filePathToUri(filePath: string): string {
  // Encode path components (spaces, brackets, etc.) but not slashes
  const encoded = filePath
    .split('/')
    .map((part) => encodeURIComponent(part))
    .join('/');
  return `file://${encoded}`;
}

export function uriToFilePath(uri: string): string {
  // Strip file:// prefix and decode
  const path = uri.replace(/^file:\/\//, '');
  return decodeURIComponent(path);
}

// --- Position Conversion ---

export function toPosition(line: number, character: number): Position {
  return {
    line: Math.max(0, line - 1),
    character,
  };
}

export function toRange(
  startLine: number,
  startCharacter: number,
  endLine: number,
  endCharacter: number
): Range {
  const start = toPosition(startLine, startCharacter);
  const end = toPosition(endLine, endCharacter);
  return { start, end };
}

// --- Formatting ---

export function formatLocation(loc: Location, cwd: string): string {
  const filePath = uriToFilePath(loc.uri);
  const rel = relative(cwd, filePath);
  const line = loc.range.start.line + 1; // 0-based -> 1-based
  const char = loc.range.start.character;
  return `${rel}:${line}:${char}`;
}

export function formatLocations(locs: Location[] | null | undefined, cwd: string): string {
  if (!locs || locs.length === 0) return 'No results found.';
  return locs.map((loc) => formatLocation(loc, cwd)).join('\n');
}

export function formatHoverContent(hover: unknown): string {
  if (!hover) return 'No hover information.';

  const h = hover as Record<string, unknown>;
  const contents = h['contents'];

  if (!contents) return 'No hover information.';

  // String content
  if (typeof contents === 'string') return contents;

  // MarkupContent: { kind, value }
  if (
    typeof contents === 'object' &&
    !Array.isArray(contents) &&
    'value' in (contents as Record<string, unknown>)
  ) {
    const c = contents as Record<string, unknown>;
    // MarkedString with language: { language, value }
    const unknownToStr = (v: unknown): string =>
      typeof v === 'string'
        ? v
        : typeof v === 'object' && v !== null
          ? JSON.stringify(v)
          : String(v as number | boolean | bigint | null | undefined);
    if ('language' in c && typeof c['language'] === 'string') {
      return `\`\`\`${c['language']}\n${unknownToStr(c['value'])}\n\`\`\``;
    }
    return unknownToStr(c['value']);
  }

  const unknownToStr = (v: unknown): string =>
    typeof v === 'string'
      ? v
      : typeof v === 'object' && v !== null
        ? JSON.stringify(v)
        : String(v as number | boolean | bigint | null | undefined);

  // Array of MarkedStrings
  if (Array.isArray(contents)) {
    return contents
      .map((item: unknown) => {
        if (typeof item === 'string') return item;
        if (typeof item === 'object' && item && 'language' in item) {
          const i = item as Record<string, unknown>;
          return `\`\`\`${unknownToStr(i['language'])}\n${unknownToStr(i['value'])}\n\`\`\``;
        }
        if (typeof item === 'object' && item && 'value' in item) {
          return unknownToStr((item as Record<string, unknown>)['value']);
        }
        return unknownToStr(item);
      })
      .join('\n\n');
  }

  return unknownToStr(contents);
}

export function formatSymbolInformation(symbols: SymbolInformation[], cwd: string): string {
  if (!symbols || symbols.length === 0) return 'No symbols found.';

  return symbols
    .map((sym) => {
      const filePath = uriToFilePath(sym.location.uri);
      const rel = relative(cwd, filePath);
      const line = sym.location.range.start.line + 1;
      const kind = symbolKindName(sym.kind);
      return `${sym.name} (${kind}) — ${rel}:${line}`;
    })
    .join('\n');
}

export function formatDocumentSymbols(symbols: DocumentSymbol[], indent: number = 0): string {
  if (!symbols || symbols.length === 0) {
    return indent === 0 ? 'No symbols found.' : '';
  }

  const lines: string[] = [];
  const prefix = '  '.repeat(indent);

  for (const sym of symbols) {
    const kind = symbolKindName(sym.kind);
    const line = sym.range.start.line + 1;
    lines.push(`${prefix}${sym.name} (${kind}) — line ${line}`);
    if (sym.children && sym.children.length > 0) {
      const childText = formatDocumentSymbols(sym.children, indent + 1);
      if (childText) lines.push(childText);
    }
  }

  return lines.join('\n');
}

export function formatWorkspaceEdit(edit: WorkspaceEdit | null | undefined, cwd: string): string {
  if (!edit || !edit.changes) return 'No changes.';

  const entries = Object.entries(edit.changes);
  if (entries.length === 0) return 'No changes.';

  const lines: string[] = [];

  for (const [uri, edits] of entries) {
    const filePath = uriToFilePath(uri);
    const rel = relative(cwd, filePath);
    lines.push(`${rel}:`);
    for (const e of edits) {
      const line = e.range.start.line + 1;
      const char = e.range.start.character;
      lines.push(`  line ${line}:${char} -> "${e.newText}"`);
    }
  }

  return lines.join('\n');
}

function diagnosticSeverityName(severity?: number): string {
  if (!severity) return 'Unknown';
  return DIAGNOSTIC_SEVERITY_NAMES[severity] ?? `Severity(${severity})`;
}

export function formatDiagnostics(
  diagnostics: Diagnostic[] | null | undefined,
  cwd: string,
  uri?: string
): string {
  if (!diagnostics || diagnostics.length === 0) return 'No diagnostics found.';

  const filePrefix = uri ? `${relative(cwd, uriToFilePath(uri))}:` : '';
  return diagnostics
    .map((diag) => {
      const line = diag.range.start.line + 1;
      const char = diag.range.start.character;
      const severity = diagnosticSeverityName(diag.severity);
      const source = diag.source ? `${diag.source}` : '';
      const code = diag.code !== undefined ? `${diag.code}` : '';
      const meta = [source, code].filter(Boolean).join(':');
      return `${filePrefix}${line}:${char} [${severity}] ${diag.message}${meta ? ` (${meta})` : ''}`;
    })
    .join('\n');
}

export function formatCodeActions(
  actions: CodeAction[] | null | undefined,
  _cwd: string
): string {
  if (!actions || actions.length === 0) return 'No code actions available.';

  return actions
    .map((action, index) => {
      const details: string[] = [];
      if (action.kind) details.push(action.kind);
      if (action.isPreferred) details.push('preferred');
      if (action.disabled?.reason) details.push(`disabled: ${action.disabled.reason}`);

      if (action.edit?.changes) {
        const changedFiles = Object.keys(action.edit.changes).length;
        const totalEdits = Object.values(action.edit.changes).reduce(
          (sum, edits) => sum + edits.length,
          0
        );
        details.push(
          `${totalEdits} edit${totalEdits === 1 ? '' : 's'} in ${changedFiles} file${changedFiles === 1 ? '' : 's'}`
        );
      }

      const commandName = action.command?.command;
      if (commandName) {
        details.push(`command: ${commandName}`);
      }

      const base = `${index + 1}. ${action.title}`;
      return details.length > 0 ? `${base} (${details.join('; ')})` : base;
    })
    .join('\n');
}

import { TOOL_SCHEMAS, SUB_AGENT_TOOL_SCHEMAS, executeTool } from '../core/tools/index.js';
