interface ToolSchema {
  type: 'function';
  function: {
    name: string;
    description: string;
    parameters: Record<string, unknown>;
  };
}

export interface ToolRegistry {
  schemas: ToolSchema[];
  execute: (
    name: string,
    argsJson: string,
    parentCtx?: SubAgentContext,
    signal?: AbortSignal
  ) => Promise<string>;
  close: () => Promise<void>;
}

interface SubAgentCallbacks {
  onSubAgentSpawn?: (id: string, label: string, dependsOn?: number) => void;
  onSubAgentProgress?: (event: import('../core/subagent-events.js').SubAgentProgressEvent) => void;
  onSubAgentDone?: (agentId: string, result: string) => void;
  /** Called after each successfully executed browser action. toolName is the Playwright tool, sessionId is the parent session. */
  onBrowserEvent?: (toolName: string, sessionId: string) => void;
}

interface BuildToolRegistryOptions {
  executeLocalTool?: (name: string, argsJson: string, signal?: AbortSignal) => Promise<string>;
  onSubAgentSpawn?: (id: string, label: string, dependsOn?: number) => void;
  onSubAgentProgress?: (event: import('../core/subagent-events.js').SubAgentProgressEvent) => void;
  onSubAgentDone?: (agentId: string, result: string) => void;
  /** Called after each successfully executed browser action. Used to stream browser events over the daemon WS bus. */
  onBrowserEvent?: (toolName: string, sessionId: string) => void;
}

const PLAYWRIGHT_MCP_SERVER_KEY = 'playwright';

/**
 * Fire-and-forget dispatch of a custom DOM event to the browser's chrome overlay.
 * The overlay (injected via initScript) listens on `window` for `opta:*` events.
 * This must NEVER block tool execution — all errors are swallowed silently.
 */
function dispatchOverlayEvent(
  mcpConn: McpConnection,
  eventName: string,
  detail: Record<string, unknown>,
): void {
  const detailJson = JSON.stringify(detail);
  const expression = `window.dispatchEvent(new CustomEvent(${JSON.stringify(eventName)}, { detail: ${detailJson} }))`;
  void mcpConn.call('browser_evaluate', { expression }).catch(() => {});
}

function resolvePlaywrightAllowedHosts(browser: OptaConfig['browser']): string[] {
  const legacy = browser as typeof browser & { globalAllowedHosts?: string[] };
  const policyHosts = normalizeStringList(browser.policy?.allowedHosts);
  const hasPolicyOverride = policyHosts.some((host) => host !== '*');
  const sourceHosts = hasPolicyOverride
    ? policyHosts
    : normalizeStringList(legacy.globalAllowedHosts);

  // Preserve previous behavior: wildcard means unrestricted, so omit the flag.
  if (sourceHosts.includes('*')) return [];
  return sourceHosts;
}

function resolvePlaywrightBlockedOrigins(browser: OptaConfig['browser']): string[] {
  const legacy = browser as typeof browser & { blockedOrigins?: string[] };
  const policyBlocked = normalizeStringList(browser.policy?.blockedOrigins);
  if (policyBlocked.length > 0) return policyBlocked;
  return normalizeStringList(legacy.blockedOrigins);
}

export async function buildToolRegistry(
  config: OptaConfig,
  mode: string = 'normal',
  options?: BuildToolRegistryOptions,
): Promise<ToolRegistry> {
  const connections: McpConnection[] = [];
  const mcpSchemas: ToolSchema[] = [];
  const mcpRoutes = new Map<string, McpConnection>();

  const mergedServers = { ...(config.mcp?.servers ?? {}) };
  const browser = config.browser;
  const browserMcp = browser?.mcp;

  if (
    browser?.enabled &&
    browserMcp?.enabled &&
    !(PLAYWRIGHT_MCP_SERVER_KEY in mergedServers)
  ) {
    const browserMode = browser.attach?.enabled ? 'attach' : browser.mode;
    const allowedHosts = resolvePlaywrightAllowedHosts(browser);
    const blockedOrigins = resolvePlaywrightBlockedOrigins(browser);

    mergedServers[PLAYWRIGHT_MCP_SERVER_KEY] = await createPlaywrightMcpServerConfig({
      command: browserMcp.command,
      packageName: browserMcp.package,
      mode: browserMode,
      allowedHosts,
      blockedOrigins,
      startUrl: browser.homePage,
    });
  }

  const serverEntries = Object.entries(mergedServers);

  // Connect all MCP servers in parallel for faster startup
  const connectResults = await Promise.allSettled(
    serverEntries.map(([name, serverConfig]) =>
      connectMcpServer(name, serverConfig).then(conn => ({ name, conn }))
    )
  );

  for (const result of connectResults) {
    if (result.status === 'fulfilled') {
      const { name, conn } = result.value;
      connections.push(conn);

      for (const tool of conn.tools) {
        const namespacedName = `mcp__${name}__${tool.name}`;
        mcpSchemas.push({
          type: 'function',
          function: {
            name: namespacedName,
            description: `[${name}] ${tool.description}`,
            parameters: tool.inputSchema,
          },
        });
        mcpRoutes.set(namespacedName, conn);
      }

      debug(`MCP "${name}": ${conn.tools.length} tools registered`);
    } else {
      // Extract server name from the settled result — map index matches serverEntries order
      const idx = connectResults.indexOf(result);
      const name = serverEntries[idx]?.[0] ?? 'unknown';
      const msg = errorMessage(result.reason);
      debug(`MCP "${name}" failed to connect: ${msg}`);
      console.warn(`  MCP server "${name}" unavailable: ${msg}`);
    }
  }

  // Conditionally include sub-agent tools
  const subAgentEnabled = config.subAgent?.enabled ?? true;
  const subAgentSchemas = subAgentEnabled
    ? (SUB_AGENT_TOOL_SCHEMAS as ToolSchema[])
    : [];

  // Conditionally include LSP tools
  const lspEnabled = config.lsp?.enabled ?? true;
  const LSP_TOOL_NAMES = new Set([
    'lsp_definition', 'lsp_references', 'lsp_hover',
    'lsp_symbols', 'lsp_document_symbols', 'lsp_diagnostics',
    'lsp_code_actions', 'lsp_rename',
  ]);

  // Initialize LspManager if LSP is enabled
  let lspManager: LspManager | null = null;
  if (lspEnabled) {
    lspManager = new LspManager({
      cwd: process.cwd(),
      config: {
        enabled: true,
        servers: config.lsp?.servers ?? {},
        timeout: config.lsp?.timeout ?? 10000,
      },
    });
  }

  // Filter out LSP tools from base schemas if disabled
  const baseSchemas = lspEnabled
    ? (TOOL_SCHEMAS as ToolSchema[])
    : (TOOL_SCHEMAS as ToolSchema[]).filter(s => !LSP_TOOL_NAMES.has(s.function.name));

  // Load custom tools from .opta/tools/*.json
  const customToolDefs = await loadCustomTools(process.cwd());
  const customSchemas = customToolDefs.map(toToolSchema) as ToolSchema[];
  const customRoutes = new Map<string, CustomToolDef>();
  for (const tool of customToolDefs) {
    customRoutes.set(`custom__${tool.name}`, tool);
  }
  if (customToolDefs.length > 0) {
    debug(`Custom tools: ${customToolDefs.length} loaded (${customToolDefs.map(t => t.name).join(', ')})`);
  }

  const totalTools = baseSchemas.length + mcpSchemas.length + subAgentSchemas.length + customSchemas.length;
  const contextLimit = config.model?.contextLimit ?? 32768;
  // ~256 tokens of context per tool is a reasonable budget; exceeding this
  // means tool schemas consume too much of the model's working memory.
  const toolThreshold = Math.floor(contextLimit / 256);
  if (totalTools > toolThreshold) {
    const schemaJson = JSON.stringify(baseSchemas) + JSON.stringify(subAgentSchemas) + JSON.stringify(mcpSchemas) + JSON.stringify(customSchemas);
    const estimatedTokens = estimateTokens(schemaJson);
    console.warn(
      `  ${totalTools} tools (~${estimatedTokens} tokens) may degrade inference on ${(contextLimit / 1024).toFixed(0)}K context. Consider: lsp.enabled=false or reducing MCP servers.`
    );
  }

  const allSchemas = [...baseSchemas, ...subAgentSchemas, ...mcpSchemas, ...customSchemas];

  const WRITE_TOOL_NAMES = new Set([
    'edit_file', 'write_file', 'multi_edit', 'delete_file',
    'run_command', 'save_memory', 'bg_start', 'bg_kill',
    'spawn_agent', 'delegate_task', 'lsp_rename',
  ]);

  const filteredSchemas = mode === 'plan'
    ? allSchemas.filter(s => !WRITE_TOOL_NAMES.has(s.function.name) && !s.function.name.startsWith('custom__'))
    : allSchemas;

  // Build a self-reference for sub-agent tool execution
  const registryRef: { current: ToolRegistry | null } = { current: null };

  // Capture sub-agent callbacks from options for use inside execute() closure
  const subAgentCallbacks: SubAgentCallbacks = {
    onSubAgentSpawn: options?.onSubAgentSpawn,
    onSubAgentProgress: options?.onSubAgentProgress,
    onSubAgentDone: options?.onSubAgentDone,
    onBrowserEvent: options?.onBrowserEvent,
  };

  // TTL cache for read-only tool results (avoids redundant file reads in multi-turn convos)
  const cache = instantiateOrInvoke<ToolResultCache>(ToolResultCache);

  const registry: ToolRegistry = {
    schemas: filteredSchemas,
    async execute(name: string, argsJson: string, parentCtx?: SubAgentContext, signal?: AbortSignal): Promise<string> {
      // Check cache for read-only tools
      if (cache.isCacheable(name)) {
        const cacheKey = ToolResultCache.key(name, argsJson);
        const cached = cache.get(cacheKey);
        if (cached !== undefined) {
          debug(`Cache hit: ${name}`);
          return cached;
        }
      }

      // Flush cache on write operations
      if (cache.isWriteTool(name) && cache.size > 0) {
        debug(`Cache flush: ${name} (${cache.size} entries)`);
        cache.flush();
      }

      const mcpConn = mcpRoutes.get(name);
      if (mcpConn) {
        let args: Record<string, unknown>;
        try {
          args = JSON.parse(argsJson);
        } catch {
          return 'Error: Invalid JSON arguments';
        }
        // Strip namespace: mcp__server__toolname -> toolname
        const originalName = name.split('__').slice(2).join('__');

        // Route Playwright MCP browser calls through the policy/safety interceptor
        if (mcpConn.name === PLAYWRIGHT_MCP_SERVER_KEY && config.browser?.enabled) {
          const { interceptBrowserMcpCall, BrowserPolicyDeniedError } = await import('../browser/mcp-interceptor.js');
          const { resolveBrowserPolicyConfig } = await import('../core/browser-policy-config.js');

          // Signal the overlay that a tool is about to execute
          dispatchOverlayEvent(mcpConn, 'opta:state', { state: 'executing' });

          try {
            const result = await interceptBrowserMcpCall(
              originalName,
              args,
              {
                policyConfig: resolveBrowserPolicyConfig(config),
                sessionId: parentCtx?.parentSessionId ?? 'registry',
                // Auto-approve gate decisions so all Playwright tools are usable.
                // The policy engine still blocks denied tools; only gated tools get through.
                onGate: async (_toolName, _decision) => 'approved',
                // Compress screenshots before returning to LLM to preserve context budget.
                screenshotCompressOptions: { maxWidth: 1280, maxHeight: 720, quality: 80 },
                // Retry transient Playwright failures (e.g. element detach, timing races).
                maxRetries: 2,
                retryBackoffMs: 500,
                onBrowserEvent: subAgentCallbacks?.onBrowserEvent
                  ? (toolName, _args, _result) =>
                      subAgentCallbacks.onBrowserEvent!(toolName, parentCtx?.parentSessionId ?? 'registry')
                  : undefined,
              },
              () => mcpConn.call(originalName, args),
            );

            // Dispatch tool-specific visual events after successful execution
            if (originalName === 'browser_navigate') {
              dispatchOverlayEvent(mcpConn, 'opta:navigate', { url: String(args.url ?? '') });
            } else if (originalName === 'browser_click') {
              dispatchOverlayEvent(mcpConn, 'opta:action', { type: 'click', selector: String(args.selector ?? args.element ?? '') });
            } else if (originalName === 'browser_type' || originalName === 'browser_fill_form') {
              dispatchOverlayEvent(mcpConn, 'opta:action', { type: 'type', selector: String(args.selector ?? args.element ?? '') });
            }

            // Reset overlay to idle after successful execution
            dispatchOverlayEvent(mcpConn, 'opta:state', { state: 'idle' });

            return typeof result === 'string' ? result : JSON.stringify(result);
          } catch (err) {
            // Dispatch policy gated event or error state to the overlay
            if (err instanceof BrowserPolicyDeniedError) {
              dispatchOverlayEvent(mcpConn, 'opta:policy', { action: originalName, decision: 'gated' });
            }
            dispatchOverlayEvent(mcpConn, 'opta:state', { state: 'error' });
            return `Error: ${errorMessage(err)}`;
          }
        }

        return mcpConn.call(originalName, args);
      }

      // Route sub-agent tools (pass context explicitly for concurrency safety)
      if (name === 'spawn_agent' || name === 'delegate_task') {
        return execSubAgentTool(name, argsJson, config, registryRef.current!, parentCtx, subAgentCallbacks);
      }

      // Route LSP tools through LspManager
      if (lspManager && LSP_TOOL_NAMES.has(name)) {
        let args: Record<string, unknown>;
        try {
          args = JSON.parse(argsJson);
        } catch {
          return 'Error: Invalid JSON arguments';
        }
        const result = await lspManager.execute(name, args);
        // Cache LSP read results
        if (cache.isCacheable(name)) {
          cache.set(ToolResultCache.key(name, argsJson), result);
        }
        return result;
      }

      // Route custom tools
      const customTool = customRoutes.get(name);
      if (customTool) {
        let args: Record<string, unknown>;
        try {
          args = JSON.parse(argsJson);
        } catch {
          return 'Error: Invalid JSON arguments for custom tool';
        }
        return executeCustomTool(customTool, args);
      }

      // Execute standard tools, then notify LSP of file changes
      const localToolExecutor = options?.executeLocalTool ?? executeTool;
      const result = await localToolExecutor(name, argsJson, signal);

      // Cache read-only tool results
      if (cache.isCacheable(name)) {
        cache.set(ToolResultCache.key(name, argsJson), result);
      }

      // Notify LSP of file changes after write operations
      if (lspManager && (name === 'edit_file' || name === 'write_file' || name === 'multi_edit')) {
        try {
          const args = JSON.parse(argsJson);
          if (args.path) {
            await lspManager.notifyFileChanged(resolve(process.cwd(), String(args.path)));
          }
        } catch {
          // Best effort - don't fail the tool execution
        }
      }

      return result;
    },
    async close() {
      // Shutdown LSP servers
      if (lspManager) {
        await lspManager.shutdownAll();
      }

      for (const conn of connections) {
        try {
          await conn.close();
        } catch {
          // Best-effort cleanup
        }
      }
    },
  };

  registryRef.current = registry;
  return registry;
}

// --- Sub-Agent Tool Execution ---

/**
 * Resolve the model name to use for LMX sub-agent inference.
 *
 * When the main session is running a cloud provider model (anthropic/, zen/,
 * google/, etc.), the sub-agent cannot use that model because it connects
 * directly to LMX at config.connection.host:port/v1.
 *
 * Resolution order:
 *   1. If model is already an LMX-native HuggingFace repo (mlx-community/ etc.) → use as-is
 *   2. Query LMX admin API for the first loaded model → use that
 *   3. Fall back to config.model.default as-is
 */
async function resolveLmxModel(config: OptaConfig): Promise<string> {
  const model = config.model.default;

  // Known LMX-compatible HuggingFace org prefixes
  const LMX_ORG_PREFIXES = [
    'mlx-community', 'lmstudio-community', 'inferencerlabs',
    'unsloth', 'bartowski', 'TheBloke', 'NousResearch',
  ];

  const firstSlash = model.indexOf('/');
  const org = firstSlash > 0 ? model.slice(0, firstSlash) : '';

  if (LMX_ORG_PREFIXES.includes(org)) {
    return model; // Already a valid LMX model ID
  }

  // Model has a cloud provider prefix — query LMX for the loaded model
  try {
    const headers: Record<string, string> = {};
    const adminKey = resolveAdminKeyForHost(config.connection.host, config.connection.port, {
      defaultAdminKey: config.connection.adminKey,
      adminKeysByHost: config.connection.adminKeysByHost,
    });
    if (adminKey) {
      headers['X-Admin-Key'] = adminKey;
    }
    const resp = await fetch(
      `http://${config.connection.host}:${config.connection.port}/admin/models`,
      { headers, signal: AbortSignal.timeout(3000) },
    );
    if (resp.ok) {
      const data = await resp.json() as { loaded?: Array<{ id: string }> };
      const firstLoaded = data.loaded?.[0]?.id;
      if (firstLoaded) return firstLoaded;
    }
  } catch {
    // LMX unreachable — fall through to default
  }

  return model; // Last resort: use as-is
}

async function execSubAgentTool(
  name: string,
  argsJson: string,
  config: OptaConfig,
  registry: ToolRegistry,
  parentCtx?: SubAgentContext,
  callbacks?: SubAgentCallbacks,
): Promise<string> {
  let args: Record<string, unknown>;
  try {
    args = JSON.parse(argsJson);
  } catch {
    return 'Error: Invalid JSON arguments for sub-agent tool';
  }

  // Lazy-load sub-agent modules
  const { spawnSubAgent, formatSubAgentResult, createSubAgentContext } = await import('../core/subagent.js');
  const { nanoid } = await import('nanoid');

  // Resolve the model to use for LMX sub-agent calls first (needed for childContext).
  // If the main session switched to a cloud model (anthropic/, zen/, etc.),
  // the sub-agent must still use the LMX-loaded model — not the cloud model name.
  const lmxModel = await resolveLmxModel(config);
  const subAgentConfig = lmxModel !== config.model.default
    ? { ...config, model: { ...config.model, default: lmxModel } }
    : config;

  // Validate depth before spawning (uses explicit context, not mutable registry state)
  let childContext: SubAgentContext;
  try {
    childContext = createSubAgentContext(
      parentCtx?.parentSessionId ?? 'root',
      parentCtx,
      subAgentConfig,
    );
  } catch (err) {
    return `Error: ${errorMessage(err)}`;
  }

  // Create an OpenAI client for the sub-agent (direct LMX connection)
  const apiKey = await lmxApiKey.resolveLmxApiKeyAsync(config.connection);

  const { default: OpenAI } = await import('openai');
  const client = instantiateOrInvoke<import('openai').default>(OpenAI, {
    baseURL: `http://${config.connection.host}:${config.connection.port}/v1`,
    apiKey,
  });

  if (name === 'spawn_agent') {
    const task = String(args['task'] ?? '');
    if (!task) return 'Error: task is required for spawn_agent';

    const agentId = nanoid(8);
    callbacks?.onSubAgentSpawn?.(agentId, task.slice(0, 40), undefined);

    const result = await spawnSubAgent(
      {
        id: agentId,
        description: task,
        scope: args['scope'] ? String(args['scope']) : undefined,
        budget: args['max_tool_calls']
          ? { maxToolCalls: Number(args['max_tool_calls']) }
          : undefined,
        mode: args['mode'] ? String(args['mode']) : undefined,
        onProgress: callbacks?.onSubAgentProgress,
      },
      subAgentConfig,
      client,
      registry,
      childContext,
    );

    callbacks?.onSubAgentDone?.(agentId, result.response);
    return formatSubAgentResult(result);
  }

  if (name === 'delegate_task') {
    const { executeDelegation } = await import('../core/orchestrator.js');

    const plan = String(args['plan'] ?? '');
    if (!plan) return 'Error: plan is required for delegate_task';

    const subtasks = (args['subtasks'] as Array<{ task: string; scope?: string; depends_on?: number }>) ?? [];
    if (!Array.isArray(subtasks) || subtasks.length === 0) {
      return 'Error: subtasks array is required for delegate_task';
    }

    try {
      return await executeDelegation(
        { plan, subtasks },
        subAgentConfig,
        client,
        registry,
        (task, cfg, cli, reg) => spawnSubAgent(task, cfg, cli, reg, childContext),
        {
          onAgentSpawn: callbacks?.onSubAgentSpawn,
          onAgentProgress: callbacks?.onSubAgentProgress,
          onAgentDone: callbacks?.onSubAgentDone,
        },
      );
    } catch (err) {
      return `Error: ${errorMessage(err)}`;
    }
  }

  return `Error: Unknown sub-agent tool "${name}"`;
}

export interface AnalyticsSessionSummary {
  id: string;
  model: string;
  created: string;
  messageCount: number;
  toolCallCount: number;
  title: string;
}

export class SessionAnalytics {
  private sessions: AnalyticsSessionSummary[];

  constructor(sessions: AnalyticsSessionSummary[]) {
    this.sessions = sessions;
  }

  get totalSessions(): number {
    return this.sessions.length;
  }

  get totalMessages(): number {
    return this.sessions.reduce((sum, s) => sum + s.messageCount, 0);
  }

  get totalToolCalls(): number {
    return this.sessions.reduce((sum, s) => sum + s.toolCallCount, 0);
  }

  get avgMessagesPerSession(): number {
    if (this.sessions.length === 0) return 0;
    return this.totalMessages / this.sessions.length;
  }

  get modelBreakdown(): Record<string, number> {
    const counts: Record<string, number> = {};
    for (const s of this.sessions) {
      counts[s.model] = (counts[s.model] ?? 0) + 1;
    }
    return counts;
  }

  sessionsToday(today?: string): number {
    const d = today ?? new Date().toISOString().split('T')[0]!;
    return this.sessions.filter(s => s.created.startsWith(d)).length;
  }

  get mostUsedModel(): string {
    const breakdown = this.modelBreakdown;
    let max = 0;
    let model = 'none';
    for (const [m, count] of Object.entries(breakdown)) {
      if (count > max) {
        max = count;
        model = m;
      }
    }
    return model;
  }
}

import { mkdir, readFile, writeFile, readdir, rm } from 'node:fs/promises';
import { join } from 'node:path';
import { nanoid } from 'nanoid';
import { getSessionsDir } from '../platform/paths.js';
import { z } from 'zod';

// --- Types ---

import type { AgentMessage, ContentPart } from '../core/agent.js';

// Re-export AgentMessage from agent.ts (canonical source)
export type { AgentMessage, ContentPart };

export interface Session {
  id: string;
  created: string;
  updated: string;
  model: string;
  cwd: string;
  title: string;
  tags: string[];
  messages: AgentMessage[];
  toolCallCount: number;
  compacted: boolean;
}

// --- Zod Schema for Session Validation ---

const ContentPartSchema = z.union([
  z.object({ type: z.literal('text'), text: z.string() }),
  z.object({ type: z.literal('image_url'), image_url: z.object({ url: z.string() }) }),
]);

const AgentMessageSchema = z.object({
  role: z.enum(['system', 'user', 'assistant', 'tool']),
  content: z.union([z.string(), z.array(ContentPartSchema), z.null()]),
  tool_calls: z
    .array(
      z.object({
        id: z.string(),
        type: z.literal('function'),
        function: z.object({ name: z.string(), arguments: z.string() }),
      })
    )
    .optional(),
  tool_call_id: z.string().optional(),
});

const SessionSchema = z.object({
  id: z.string(),
  created: z.string(),
  updated: z.string(),
  model: z.string(),
  cwd: z.string(),
  title: z.string(),
  tags: z.array(z.string()).default([]),
  messages: z.array(AgentMessageSchema),
  toolCallCount: z.number(),
  compacted: z.boolean(),
});

const SEARCH_PREVIEW_MESSAGE_LIMIT = 6;
const SEARCH_PREVIEW_CHAR_LIMIT = 2000;

function parseSession(data: string): Session | null {
  try {
    const parsed: unknown = JSON.parse(data);
    const result = SessionSchema.safeParse(parsed);
    if (!result.success) return null;
    return result.data as Session;
  } catch {
    return null;
  }
}

function buildSessionSearchPreview(messages: AgentMessage[]): string {
  const previewParts: string[] = [];
  for (const message of messages) {
    if (previewParts.length >= SEARCH_PREVIEW_MESSAGE_LIMIT) break;
    if (message.role === 'system' || message.role === 'tool') continue;
    if (typeof message.content === 'string') {
      const value = message.content.trim();
      if (value.length > 0) previewParts.push(value);
      continue;
    }
    if (Array.isArray(message.content)) {
      const chunks: string[] = [];
      for (const part of message.content) {
        if (part.type !== 'text') continue;
        const value = part.text.trim();
        if (value.length > 0) chunks.push(value);
      }
      const text = chunks.join(' ').trim();
      if (text.length > 0) previewParts.push(text);
    }
  }

  if (previewParts.length === 0) return '';
  const normalized = previewParts.join('\n').replace(/\s+/g, ' ').trim();
  return normalized.slice(0, SEARCH_PREVIEW_CHAR_LIMIT);
}

export interface SessionSummary {
  id: string;
  title: string;
  tags: string[];
  model: string;
  created: string;
  messageCount: number;
  toolCallCount: number;
}

// --- Paths ---

function sessionsDir(): string {
  return getSessionsDir();
}

function sessionPath(id: string): string {
  return join(sessionsDir(), `${id}.json`);
}

// --- Session Index (fast resume) ---

const INDEX_FILE = 'index.json';

const SessionIndexSchema = z.object({
  entries: z.record(
    z.string(),
    z.object({
      title: z.string(),
      model: z.string(),
      tags: z.array(z.string()),
      created: z.string(),
      messageCount: z.number(),
      toolCallCount: z.number().optional(),
      preview: z.string().optional(),
    })
  ),
  updatedAt: z.string(),
});

export type SessionIndex = z.infer<typeof SessionIndexSchema>;

async function loadIndex(): Promise<SessionIndex> {
  try {
    const data = await readFile(join(sessionsDir(), INDEX_FILE), 'utf-8');
    const parsed: unknown = JSON.parse(data);
    const result = SessionIndexSchema.safeParse(parsed);
    if (result.success) {
      return result.data;
    }
    return { entries: {}, updatedAt: new Date().toISOString() };
  } catch {
    return { entries: {}, updatedAt: new Date().toISOString() };
  }
}

async function saveIndex(index: SessionIndex): Promise<void> {
  index.updatedAt = new Date().toISOString();
  await mkdir(sessionsDir(), { recursive: true });
  await writeFile(join(sessionsDir(), INDEX_FILE), JSON.stringify(index, null, 2));
}

export async function updateSessionIndex(id: string, session: Session): Promise<void> {
  const index = await loadIndex();
  index.entries[id] = {
    title: session.title,
    model: session.model,
    tags: session.tags,
    created: session.created,
    messageCount: session.messages.filter((m) => m.role !== 'system').length,
    toolCallCount: session.toolCallCount ?? 0,
    preview: buildSessionSearchPreview(session.messages),
  };
  await saveIndex(index);
}

export async function removeFromIndex(id: string): Promise<void> {
  const index = await loadIndex();
  Reflect.deleteProperty(index.entries, id);
  await saveIndex(index);
}

// --- CRUD ---

export async function createSession(model: string): Promise<Session> {
  const now = new Date().toISOString();
  const session: Session = {
    id: nanoid(12),
    created: now,
    updated: now,
    model,
    cwd: process.cwd(),
    title: '',
    tags: [],
    messages: [],
    toolCallCount: 0,
    compacted: false,
  };
  await saveSession(session);
  return session;
}

export async function loadSession(id: string): Promise<Session> {
  const data = await readFile(sessionPath(id), 'utf-8');
  const session = parseSession(data);
  if (!session) {
    throw new Error(`Corrupt or invalid session file: ${id}`);
  }
  return session;
}

export async function saveSession(session: Session): Promise<void> {
  session.updated = new Date().toISOString();
  const dir = sessionsDir();
  await mkdir(dir, { recursive: true });
  await writeFile(sessionPath(session.id), JSON.stringify(session, null, 2), 'utf-8');
  await updateSessionIndex(session.id, session);
}

export async function listSessions(): Promise<SessionSummary[]> {
  const dir = sessionsDir();
  let files: string[];
  try {
    files = await readdir(dir);
  } catch {
    return [];
  }

  const sessionFiles = files.filter((file) => file.endsWith('.json') && file !== INDEX_FILE);
  const index = await loadIndex();
  if (sessionFiles.length === 0) {
    if (Object.keys(index.entries).length > 0) {
      index.entries = {};
      await saveIndex(index);
    }
    return [];
  }

  const fileIds = new Set(sessionFiles.map((file) => file.slice(0, -5)));
  const summaries: SessionSummary[] = [];
  let indexMutated = false;
  const previewBackfillIds: string[] = [];

  // Remove stale index entries that no longer have a backing session file.
  for (const id of Object.keys(index.entries)) {
    if (!fileIds.has(id)) {
      Reflect.deleteProperty(index.entries, id);
      indexMutated = true;
    }
  }

  const missingIds: string[] = [];
  for (const id of fileIds) {
    const entry = index.entries[id];
    if (entry) {
      summaries.push({
        id,
        title: entry.title || '(untitled)',
        tags: entry.tags ?? [],
        model: entry.model,
        created: entry.created,
        messageCount: entry.messageCount ?? 0,
        toolCallCount: entry.toolCallCount ?? 0,
      });
      if (typeof entry.preview !== 'string') {
        previewBackfillIds.push(id);
      }
      continue;
    }
    missingIds.push(id);
  }

  // Backfill index entries from session files that are missing in index.
  if (missingIds.length > 0) {
    await Promise.all(
      missingIds.map(async (id) => {
        try {
          const data = await readFile(sessionPath(id), 'utf-8');
          const session = parseSession(data);
          if (!session) return; // Skip corrupt/invalid session files

          const messageCount = session.messages.filter((m) => m.role !== 'system').length;
          index.entries[id] = {
            title: session.title,
            model: session.model,
            tags: session.tags ?? [],
            created: session.created,
            messageCount,
            toolCallCount: session.toolCallCount ?? 0,
            preview: buildSessionSearchPreview(session.messages),
          };

          summaries.push({
            id: session.id,
            title: session.title || '(untitled)',
            tags: session.tags ?? [],
            model: session.model,
            created: session.created,
            messageCount,
            toolCallCount: session.toolCallCount ?? 0,
          });
          indexMutated = true;
        } catch {
          // Skip unreadable session files
        }
      })
    );
  }

  // Backfill search previews for legacy index entries.
  if (previewBackfillIds.length > 0) {
    await Promise.all(
      previewBackfillIds.map(async (id) => {
        try {
          const data = await readFile(sessionPath(id), 'utf-8');
          const session = parseSession(data);
          if (!session) return;
          const entry = index.entries[id];
          if (!entry) return;
          entry.preview = buildSessionSearchPreview(session.messages);
          indexMutated = true;
        } catch {
          // Skip unreadable session files
        }
      })
    );
  }

  if (indexMutated) {
    await saveIndex(index);
  }

  return summaries.sort((a, b) => b.created.localeCompare(a.created));
}

export async function deleteSession(id: string): Promise<void> {
  await rm(sessionPath(id), { force: true });
  await removeFromIndex(id);
}

export async function exportSession(id: string): Promise<string> {
  const session = await loadSession(id);
  return JSON.stringify(session, null, 2);
}

// --- Search ---

/**
 * Fuzzy search sessions by query string.
 * Matches against session ID prefix, title, model, tags, and message content.
 * Returns results sorted by relevance score (highest first).
 */
export async function searchSessions(query: string): Promise<SessionSummary[]> {
  const all = await listSessions();
  const q = query.toLowerCase();
  const index = await loadIndex();
  const previewById = new Map<string, string>();
  let indexMutated = false;

  const missingPreviewIds = all
    .filter((summary) => !index.entries[summary.id]?.preview)
    .map((summary) => summary.id);
  if (missingPreviewIds.length > 0) {
    await Promise.all(
      missingPreviewIds.map(async (id) => {
        try {
          const data = await readFile(sessionPath(id), 'utf-8');
          const session = parseSession(data);
          if (!session) return;
          const preview = buildSessionSearchPreview(session.messages);
          const entry = index.entries[id];
          if (!entry) return;
          entry.preview = preview;
          previewById.set(id, preview);
          indexMutated = true;
        } catch {
          // Skip unreadable session files
        }
      })
    );
  }

  for (const [id, entry] of Object.entries(index.entries)) {
    if (typeof entry.preview === 'string') {
      previewById.set(id, entry.preview);
    }
  }
  if (indexMutated) {
    await saveIndex(index);
  }

  const scored = all.map((summary) => {
    let score = 0;

    // Exact ID prefix match (highest priority)
    if (summary.id.toLowerCase().startsWith(q)) {
      score += 100;
    } else if (summary.id.toLowerCase().includes(q)) {
      score += 50;
    }

    // Title match
    const title = summary.title.toLowerCase();
    if (title === q) {
      score += 90;
    } else if (title.startsWith(q)) {
      score += 70;
    } else if (title.includes(q)) {
      score += 40;
    }

    // Tag match
    const tagMatch = summary.tags?.some((t) => t.toLowerCase().includes(q));
    if (tagMatch) score += 60;

    // Model match
    if (summary.model.toLowerCase().includes(q)) {
      score += 20;
    }

    // Word-level fuzzy: check if all query words appear somewhere
    const queryWords = q.split(/\s+/);
    const tagStr = (summary.tags ?? []).join(' ');
    const haystack = `${summary.id} ${summary.title} ${summary.model} ${tagStr}`.toLowerCase();
    const allWordsMatch = queryWords.every((w) => haystack.includes(w));
    if (allWordsMatch && queryWords.length > 1) {
      score += 30;
    }

    // Search indexed message preview (first N user/assistant messages).
    const preview = previewById.get(summary.id);
    if (preview && preview.toLowerCase().includes(q)) {
      score += 40;
    }

    return { session: summary, score };
  });

  return scored
    .filter((s) => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .map((s) => s.session);
}

// --- Tag & Rename ---

export async function tagSession(id: string, tags: string[]): Promise<void> {
  const session = await loadSession(id);
  session.tags = [...new Set([...session.tags, ...tags])];
  await saveSession(session);
}

export async function untagSession(id: string, tags: string[]): Promise<void> {
  const session = await loadSession(id);
  session.tags = session.tags.filter((t) => !tags.includes(t));
  await saveSession(session);
}

export async function renameSession(id: string, title: string): Promise<void> {
  const session = await loadSession(id);
  session.title = title;
  await saveSession(session);
}

// --- Helpers ---

export function generateTitle(firstMessage: string): string {
  return firstMessage.trim().slice(0, 60).replace(/\n/g, ' ');
}

import { mkdir, open, unlink } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import {
  PolicyConfigSchema,
  PolicyRequestSchema,
  type PolicyAuditEntry,
  type PolicyConfig,
  type PolicyDecisionResult,
  type PolicyRequest,
} from './types.js';
import { sleep } from '../utils/common.js';

const AUDIT_RELATIVE_PATH = join('.opta', 'policy', 'audit.jsonl');

export interface PolicyEngineOptions {
  cwd?: string;
  now?: () => Date;
  lockTimeoutMs?: number;
  lockRetryMs?: number;
}

function toErrorMessage(error: unknown): string {
  if (error instanceof Error) return error.message;
  return String(error);
}

function fallbackAction(request: unknown): string {
  if (
    request !== null &&
    request !== undefined &&
    typeof request === 'object' &&
    'action' in request &&
    typeof (request as { action?: unknown }).action === 'string'
  ) {
    return (request as { action: string }).action;
  }
  return 'unknown-action';
}

function fallbackAutonomous(request: unknown): boolean {
  if (
    request !== null &&
    request !== undefined &&
    typeof request === 'object' &&
    'autonomous' in request &&
    typeof (request as { autonomous?: unknown }).autonomous === 'boolean'
  ) {
    return (request as { autonomous: boolean }).autonomous;
  }
  return true;
}

export function policyAuditPath(cwd = process.cwd()): string {
  return join(cwd, AUDIT_RELATIVE_PATH);
}

function policyAuditDir(cwd = process.cwd()): string {
  return dirname(policyAuditPath(cwd));
}

function policyAuditLockPath(cwd = process.cwd()): string {
  return `${policyAuditPath(cwd)}.lock`;
}

async function acquireLock(lockPath: string, timeoutMs: number, retryMs: number) {
  const start = Date.now();
  while (true) {
    try {
      return await open(lockPath, 'wx');
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      if (err.code !== 'EEXIST') {
        throw err;
      }
      if (Date.now() - start >= timeoutMs) {
        throw new Error(`Timed out waiting for policy audit lock: ${lockPath}`);
      }
      await sleep(retryMs);
    }
  }
}

async function appendAuditLine(path: string, line: string): Promise<void> {
  const handle = await open(path, 'a');
  try {
    await handle.writeFile(line, 'utf-8');
    // Keep ordering + durability guarantees while lock is held.
    await handle.sync();
  } finally {
    await handle.close().catch(() => {});
  }
}

async function appendAuditEntryAtomic(
  entry: PolicyAuditEntry,
  options: PolicyEngineOptions,
): Promise<void> {
  const cwd = options.cwd ?? process.cwd();
  const timeoutMs = options.lockTimeoutMs ?? 5000;
  const retryMs = options.lockRetryMs ?? 20;
  const auditPath = policyAuditPath(cwd);
  const auditDir = policyAuditDir(cwd);
  const lockPath = policyAuditLockPath(cwd);

  await mkdir(auditDir, { recursive: true });
  const lockHandle = await acquireLock(lockPath, timeoutMs, retryMs);

  try {
    await appendAuditLine(auditPath, `${JSON.stringify(entry)}\n`);
  } finally {
    await lockHandle.close().catch(() => {});
    await unlink(lockPath).catch(() => {});
  }
}

function evaluateFullMode(
  config: PolicyConfig,
  request: PolicyRequest,
  ts: string,
): PolicyDecisionResult {
  if (!config.enabled || config.mode === 'off') {
    return {
      decision: 'allow',
      reason: 'Policy disabled or mode is off.',
      mode: config.mode,
      action: request.action,
      ts,
    };
  }

  if (config.mode === 'full' && config.gateAllAutonomy && request.autonomous) {
    return {
      decision: 'gate',
      reason: 'Full mode gate-all rule requires approval for autonomous actions.',
      mode: config.mode,
      action: request.action,
      ts,
    };
  }

  return {
    decision: 'allow',
    reason: 'Allowed by full policy mode checks.',
    mode: config.mode,
    action: request.action,
    ts,
  };
}

function shouldFailClosed(config: unknown): boolean {
  const parsed = PolicyConfigSchema.safeParse(config);
  if (parsed.success) {
    return parsed.data.failureMode === 'closed';
  }
  return true;
}

function failClosedDecision(
  request: unknown,
  ts: string,
  reason: string,
): PolicyDecisionResult {
  return {
    decision: 'deny',
    reason: `Fail-closed: ${reason}`,
    mode: 'full',
    action: fallbackAction(request),
    ts,
  };
}

function failOpenDecision(
  request: unknown,
  ts: string,
  reason: string,
): PolicyDecisionResult {
  return {
    decision: 'allow',
    reason: `Fail-open fallback: ${reason}`,
    mode: 'full',
    action: fallbackAction(request),
    ts,
  };
}

async function auditIfEnabled(
  config: PolicyConfig,
  request: PolicyRequest,
  decision: PolicyDecisionResult,
  options: PolicyEngineOptions,
): Promise<void> {
  if (!config.audit.enabled) return;

  await appendAuditEntryAtomic(
    {
      ...decision,
      autonomous: request.autonomous,
      actor: request.actor,
      metadata: request.metadata,
    },
    options,
  );
}

export async function evaluatePolicyRequest(
  configInput: PolicyConfig,
  requestInput: PolicyRequest,
  options: PolicyEngineOptions = {},
): Promise<PolicyDecisionResult> {
  const now = options.now ?? (() => new Date());
  const ts = now().toISOString();

  try {
    const parsedConfig = PolicyConfigSchema.parse(configInput);
    const parsedRequest = PolicyRequestSchema.parse(requestInput);

    const decision = evaluateFullMode(parsedConfig, parsedRequest, ts);
    await auditIfEnabled(parsedConfig, parsedRequest, decision, options);
    return decision;
  } catch (error) {
    const reason = toErrorMessage(error);
    if (shouldFailClosed(configInput)) {
      const denied = failClosedDecision(requestInput, ts, reason);
      const parsedConfig = PolicyConfigSchema.safeParse(configInput);
      if (parsedConfig.success && parsedConfig.data.audit.enabled) {
        await appendAuditEntryAtomic(
          {
            ...denied,
            autonomous: fallbackAutonomous(requestInput),
            actor: 'policy-engine',
            metadata: { error: reason },
          },
          options,
        ).catch(() => {});
      }
      return denied;
    }

    return failOpenDecision(requestInput, ts, reason);
  }
}

export class PolicyEngine {
  constructor(
    private readonly config: PolicyConfig,
    private readonly options: PolicyEngineOptions = {},
  ) {}

  async decide(request: PolicyRequest): Promise<PolicyDecisionResult> {
    return evaluatePolicyRequest(this.config, request, this.options);
  }
}

/**
 * Anthropic provider — uses the Anthropic SDK with an OpenAI-compatible wrapper.
 *
 * The agent loop uses OpenAI SDK types, so we use Anthropic's OpenAI compatibility
 * layer (@anthropic-ai/sdk provides an OpenAI-compatible client) rather than
 * converting message formats manually.
 */

import type { ProviderClient, ProviderModelInfo, ProviderHealthResult } from './base.js';
import type { OptaConfig } from '../core/config.js';
import { errorMessage } from '../utils/errors.js';
import { instantiateOrInvoke } from '../utils/newable.js';

type AnthropicKeySource = 'config' | 'env' | 'keychain' | 'cloud' | 'none';

export class AnthropicProvider implements ProviderClient {
  readonly name = 'anthropic';
  private client: import('openai').default | null = null;
  private config: OptaConfig;

  constructor(config: OptaConfig) {
    this.config = config;
  }

  private async resolveApiKey(): Promise<{ apiKey: string; source: AnthropicKeySource }> {
    const configuredKey = this.config.provider.anthropic.apiKey?.trim();
    if (configuredKey) return { apiKey: configuredKey, source: 'config' };

    const envKey = process.env['ANTHROPIC_API_KEY']?.trim();
    if (envKey) return { apiKey: envKey, source: 'env' };

    try {
      const { getAnthropicKey } = await import('../keychain/api-keys.js');
      const keychainKey = (await getAnthropicKey())?.trim();
      if (keychainKey) return { apiKey: keychainKey, source: 'keychain' };
    } catch {
      // Keychain unavailable/errored: continue and check cloud.
    }

    // 4. Opta Accounts cloud key — mirrors the LMX resolution chain so that
    //    keys stored via the Opta Accounts portal work for Anthropic too.
    try {
      const { loadAccountState } = await import('../accounts/storage.js');
      const { resolveCloudApiKey } = await import('../accounts/cloud.js');
      const state = await loadAccountState();
      const cloudKey = (await resolveCloudApiKey(state, 'anthropic'))?.trim();
      if (cloudKey) return { apiKey: cloudKey, source: 'cloud' };
    } catch {
      // Cloud lookup unavailable — fall through to none.
    }

    return { apiKey: '', source: 'none' };
  }

  async getClient(): Promise<import('openai').default> {
    if (this.client) return this.client;

    const { default: OpenAI } = await import('openai');
    const { apiKey } = await this.resolveApiKey();

    if (!apiKey) {
      throw new Error(
        'Anthropic API key required.\n\n' +
          'Set it via:\n' +
          '  opta config set provider.anthropic.apiKey sk-ant-...\n' +
          '  or export ANTHROPIC_API_KEY=sk-ant-...\n' +
          '  or opta keychain set-anthropic sk-ant-...\n' +
          '  or add an Anthropic key in your Opta Account at accounts.optalocal.com'
      );
    }

    // Use Anthropic's OpenAI-compatible endpoint
    this.client = instantiateOrInvoke<import('openai').default>(OpenAI, {
      baseURL: 'https://api.anthropic.com/v1/',
      apiKey,
      defaultHeaders: {
        'anthropic-version': '2023-06-01',
      },
    });
    return this.client;
  }

  listModels(): Promise<ProviderModelInfo[]> {
    // Anthropic doesn't have a models list endpoint; return known models
    return Promise.resolve([
      { id: 'claude-opus-4-6', name: 'Claude Opus 4.6', contextLength: 200000 },
      { id: 'claude-sonnet-4-5-20250929', name: 'Claude Sonnet 4.5', contextLength: 200000 },
      { id: 'claude-haiku-4-5-20251001', name: 'Claude Haiku 4.5', contextLength: 200000 },
    ]);
  }

  async health(): Promise<ProviderHealthResult> {
    const start = Date.now();
    const { apiKey, source } = await this.resolveApiKey();

    if (!apiKey) {
      return {
        ok: false,
        latencyMs: Date.now() - start,
        error:
          'No API key configured (checked config, ANTHROPIC_API_KEY, keychain, and Opta Accounts cloud)',
      };
    }

    if (!apiKey.startsWith('sk-ant-') && !apiKey.startsWith('sk-')) {
      const sourceLabel = source === 'none' ? 'resolved key' : `${source} key`;
      return {
        ok: false,
        latencyMs: Date.now() - start,
        error: `Invalid API key format (${sourceLabel}) — expected sk-ant-...`,
      };
    }

    try {
      // Use GET /v1/models — lightweight connectivity + auth check with zero token spend.
      // (The previous POST to /v1/messages cost tokens on every health probe.)
      const res = await fetch('https://api.anthropic.com/v1/models', {
        method: 'GET',
        headers: {
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
        },
        signal: AbortSignal.timeout(10000),
      });
      return {
        ok: res.ok,
        latencyMs: Date.now() - start,
        error: res.ok ? undefined : `HTTP ${res.status}`,
      };
    } catch (err) {
      return {
        ok: false,
        latencyMs: Date.now() - start,
        error: errorMessage(err),
      };
    }
  }
}

import type { ProviderClient, ProviderModelInfo, ProviderHealthResult } from './base.js';
import type { OptaConfig } from '../core/config.js';
import { errorMessage } from '../utils/errors.js';
import { instantiateOrInvoke } from '../utils/newable.js';

type CloudKeySource = 'config' | 'env' | 'keychain' | 'cloud' | 'none';

export class CloudProvider implements ProviderClient {
  readonly name: string;
  private client: import('openai').default | null = null;
  private config: OptaConfig;

  constructor(name: string, config: OptaConfig) {
    this.name = name;
    this.config = config;
  }

  private async resolveApiKey(): Promise<{ apiKey: string; source: CloudKeySource }> {
    const configuredProvider =
      this.name === 'gemini'
        ? this.config.provider.gemini.apiKey
        : this.name === 'openai'
          ? this.config.provider.openai.apiKey
          : this.config.provider.opencode_zen.apiKey;

    if (configuredProvider?.trim()) {
      return { apiKey: configuredProvider.trim(), source: 'config' };
    }

    const envVar =
      this.name === 'gemini'
        ? process.env['GEMINI_API_KEY']
        : this.name === 'openai'
          ? process.env['OPENAI_API_KEY']
          : process.env['OPENCODE_ZEN_API_KEY'];
    if (envVar?.trim()) {
      return { apiKey: envVar.trim(), source: 'env' };
    }

    try {
      if (this.name === 'gemini') {
        const { getGeminiKey } = await import('../keychain/api-keys.js');
        const key = (await getGeminiKey())?.trim();
        if (key) return { apiKey: key, source: 'keychain' };
      }
      if (this.name === 'openai') {
        const { getOpenaiKey } = await import('../keychain/api-keys.js');
        const key = (await getOpenaiKey())?.trim();
        if (key) return { apiKey: key, source: 'keychain' };
      }
      const { getOpencodeZenKey } = await import('../keychain/api-keys.js');
      const key = (await getOpencodeZenKey())?.trim();
      if (key) return { apiKey: key, source: 'keychain' };
    } catch {
      // Keychain unavailable — continue.
    }

    // Optional Opta Accounts cloud token source for portable key management.
    try {
      const { loadAccountState } = await import('../accounts/storage.js');
      const { resolveCloudApiKey } = await import('../accounts/cloud.js');
      const state = await loadAccountState();
      const cloudKey = (await resolveCloudApiKey(state, this.name))?.trim();
      if (cloudKey) return { apiKey: cloudKey, source: 'cloud' };
    } catch {
      // Cloud lookup unavailable.
    }

    return { apiKey: '', source: 'none' };
  }

  async getClient(): Promise<import('openai').default> {
    if (this.client) return this.client;

    const { apiKey } = await this.resolveApiKey();

    if (!apiKey) {
      const hint =
        this.name === 'gemini'
          ? 'GEMINI_API_KEY or opta config / keychain / accounts cloud'
          : this.name === 'openai'
            ? 'OPENAI_API_KEY or opta config / keychain / accounts cloud'
            : 'OPENCODE_ZEN_API_KEY or opta config / keychain / accounts cloud';
      throw new Error(`Missing API key for provider: ${this.name}. Set ${hint}.`);
    }

    const baseURL =
      this.name === 'gemini'
        ? 'https://generativelanguage.googleapis.com/v1beta/openai/'
        : this.name === 'opencode_zen'
          ? 'https://api.opencodezen.com/v1'
          : undefined;

    const { default: OpenAI } = await import('openai');
    this.client = instantiateOrInvoke<import('openai').default>(OpenAI, { apiKey, baseURL });
    return this.client;
  }

  async health(): Promise<ProviderHealthResult> {
    try {
      const start = Date.now();
      await this.getClient();
      return { ok: true, latencyMs: Date.now() - start };
    } catch (err) {
      return { ok: false, latencyMs: 0, error: errorMessage(err) };
    }
  }

  async listModels(): Promise<ProviderModelInfo[]> {
    const client = await this.getClient();
    try {
      const list = await client.models.list();
      return list.data.map((m) => ({ id: m.id, source: this.name, loaded: false }));
    } catch {
      return [];
    }
  }
}

/**
 * Provider manager — factory for selecting the active LLM provider.
 *
 * Reads config.provider.active to determine which provider to use.
 * When fallbackOnFailure is enabled, wraps LMX in a FallbackProvider
 * that auto-degrades to Anthropic on connection failure.
 * Caches provider instances by config key to avoid re-creation.
 *
 * Zero-config fallback:
 * probeProvider() performs a fast LMX health check (≤2s) before the first
 * agent turn. If LMX is unreachable it returns the first available cloud
 * provider (Anthropic/Gemini/OpenAI/Opencode Zen) using configured keys.
 */

import type { ProviderClient } from './base.js';
import type { OptaConfig } from '../core/config.js';
import { resolveLmxApiKey } from '../lmx/api-key.js';
import { verbose } from '../core/debug.js';
import { errorMessage } from '../utils/errors.js';
import { instantiateOrInvoke } from '../utils/newable.js';

let cachedProvider: ProviderClient | null = null;
let cachedProviderKey = '';

function providerCacheKey(config: OptaConfig): string {
  const active = config.provider.active;
  const fallback = config.provider.fallbackOnFailure ? '+fb' : '';
  if (active === 'lmx') {
    const fallbackHosts = config.connection.fallbackHosts
      .map((host) => host.trim().toLowerCase())
      .filter((host) => host.length > 0)
      .join(',');
    const apiKeyPrefix = resolveLmxApiKey(config.connection).slice(0, 8);
    return `lmx${fallback}|${config.connection.host}:${config.connection.port}|${fallbackHosts}|${apiKeyPrefix}`;
  }
  let apiKey = '';
  if (active === 'anthropic') apiKey = config.provider.anthropic.apiKey || process.env['ANTHROPIC_API_KEY'] || '';
  if (active === 'gemini') apiKey = config.provider.gemini.apiKey || process.env['GEMINI_API_KEY'] || '';
  if (active === 'openai') apiKey = config.provider.openai.apiKey || process.env['OPENAI_API_KEY'] || '';
  if (active === 'opencode_zen') apiKey = config.provider.opencode_zen.apiKey || process.env['OPENCODE_ZEN_API_KEY'] || '';

  return `${active}|${apiKey.slice(0, 8)}`;
}

export async function getProvider(config: OptaConfig): Promise<ProviderClient> {
  const key = providerCacheKey(config);
  if (cachedProvider && cachedProviderKey === key) {
    return cachedProvider;
  }

  const active = config.provider.active;

  if (active === 'anthropic') {
    const { AnthropicProvider } = await import('./anthropic.js');
    cachedProvider = instantiateOrInvoke<ProviderClient>(AnthropicProvider, config);
  } else if (active === 'gemini' || active === 'openai' || active === 'opencode_zen') {
    const { CloudProvider } = await import('./cloud.js');
    cachedProvider = instantiateOrInvoke<ProviderClient>(CloudProvider, active, config);
  } else {
    const { LmxProvider } = await import('./lmx.js');
    const lmx = instantiateOrInvoke<ProviderClient>(LmxProvider, config);

    if (config.provider.fallbackOnFailure) {
      const { FallbackProvider } = await import('./fallback.js');
      cachedProvider = instantiateOrInvoke<ProviderClient>(FallbackProvider, lmx, config);
    } else {
      cachedProvider = lmx;
    }
  }

  cachedProviderKey = key;
  if (!cachedProvider) throw new Error('Failed to initialize provider');
  return cachedProvider;
}

/** Reset the cached provider (useful for testing or config reload). */
export function resetProviderCache(): void {
  cachedProvider = null;
  cachedProviderKey = '';
}

/**
 * Zero-config provider probe.
 *
 * Performs a fast health check against the configured LMX endpoint
 * (≤2 second timeout). If LMX is reachable, returns the normal LMX
 * provider. If LMX is unreachable or not configured:
 *
 *   - ANTHROPIC_API_KEY is set → silently returns an Anthropic provider
 *   - No ANTHROPIC_API_KEY     → throws a descriptive error
 *
 * In verbose mode (`--verbose`), logs which path was taken.
 *
 * This is the preferred entry-point for the chat startup path so that
 * first-run users with only an Anthropic key work out of the box.
 */
export async function probeProvider(config: OptaConfig): Promise<ProviderClient> {
  const active = config.provider.active;

  // When the user has explicitly configured a cloud provider, honour that.
  if (active !== 'lmx') {
    const providerLabel = active;
    verbose(`Provider probe: user configured ${providerLabel}, skipping LMX probe`);
    if (active === 'anthropic') {
      const { AnthropicProvider } = await import('./anthropic.js');
      return instantiateOrInvoke<ProviderClient>(AnthropicProvider, config);
    }

    const { CloudProvider } = await import('./cloud.js');
    return instantiateOrInvoke<ProviderClient>(CloudProvider, active, config);
  }

  // Probe LMX with a short timeout budget so startup stays responsive.
  // We check the primary host first, then any configured fallbacks.
  const PROBE_TIMEOUT_BUDGET_MS = 2_000;
  const primaryHost = config.connection.host;
  const port = config.connection.port;
  const probeTargets = [primaryHost, ...config.connection.fallbackHosts]
    .map((host) => host.trim())
    .filter((host) => host.length > 0)
    .filter((host, index, list) => list.findIndex((item) => item.toLowerCase() === host.toLowerCase()) === index);

  const attemptedEndpoints: string[] = [];
  const probeFailures: string[] = [];
  const deadline = Date.now() + PROBE_TIMEOUT_BUDGET_MS;

  for (let index = 0; index < probeTargets.length; index += 1) {
    const host = probeTargets[index];
    if (!host) continue;
    const remainingTargets = probeTargets.length - index;
    const remainingBudgetMs = Math.max(250, deadline - Date.now());
    const timeoutMs =
      probeTargets.length === 1
        ? PROBE_TIMEOUT_BUDGET_MS
        : Math.max(250, Math.floor(remainingBudgetMs / remainingTargets));
    attemptedEndpoints.push(`${host}:${port}`);

    try {
      const { probeLmxConnection } = await import('../lmx/connection.js');
      const result = await probeLmxConnection(host, port, { timeoutMs });

      if (result.state !== 'disconnected') {
        verbose(
          `Provider probe: LMX reachable at ${host}:${port} ` +
            `(state=${result.state}, ${result.latencyMs}ms)`
        );
        // LMX is reachable — use the normal provider (with FallbackProvider if configured).
        return await getProvider(config);
      }

      const reason = result.reason ?? 'no response';
      probeFailures.push(`${host}:${port} (${reason})`);
      verbose(`Provider probe: LMX unreachable at ${host}:${port} — ${reason}`);
    } catch (err) {
      const reason = errorMessage(err);
      probeFailures.push(`${host}:${port} (${reason})`);
      verbose(`Provider probe: LMX probe threw for ${host}:${port} — ${reason}`);
    }
  }

  // LMX is unreachable — check cloud fallback keys in preference order.
  const cloudCandidates: Array<{ provider: 'anthropic' | 'gemini' | 'openai' | 'opencode_zen'; envVar: string }> = [
    { provider: 'anthropic', envVar: 'ANTHROPIC_API_KEY' },
    { provider: 'gemini', envVar: 'GEMINI_API_KEY' },
    { provider: 'openai', envVar: 'OPENAI_API_KEY' },
    { provider: 'opencode_zen', envVar: 'OPENCODE_ZEN_API_KEY' },
  ];

  for (const candidate of cloudCandidates) {
    let configured = false;
    if (candidate.provider === 'anthropic') {
      configured = !!(config.provider.anthropic.apiKey || process.env[candidate.envVar]);
    } else if (candidate.provider === 'gemini') {
      configured = !!(config.provider.gemini.apiKey || process.env[candidate.envVar]);
    } else if (candidate.provider === 'openai') {
      configured = !!(config.provider.openai.apiKey || process.env[candidate.envVar]);
    } else if (candidate.provider === 'opencode_zen') {
      configured = !!(config.provider.opencode_zen.apiKey || process.env[candidate.envVar]);
    }

    if (configured) {
      verbose(
        `Provider probe: falling back to ${candidate.provider} (LMX unreachable, key available)`
      );
      const { CloudProvider } = await import('./cloud.js');
      return instantiateOrInvoke<ProviderClient>(CloudProvider, candidate.provider, config);
    }
  }

  // No fallback available — throw machine-readable remediation metadata.
  const attemptedSummary =
    attemptedEndpoints.length > 0 ? attemptedEndpoints.join(', ') : `${primaryHost}:${port}`;
  throw new Error(
    JSON.stringify({
      code: 'lmx_unreachable',
      attemptedEndpoints,
      attemptedSummary,
      probeFailures,
      autoActions: ['discover_hosts', 'try_fallback', 'launch_onboarding'],
      humanHint: 'Run opta onboard to repair connection automatically.',
      noCloudFallbackConfigured: true,
      cloudFallbackEnvVar: ['ANTHROPIC_API_KEY', 'GEMINI_API_KEY', 'OPENAI_API_KEY', 'OPENCODE_ZEN_API_KEY'],
      target: `${primaryHost}:${port}`,
      fallbackHostsConfigured: probeTargets.length > 1,
    })
  );
}

/** Re-export types for convenience. */
export type { ProviderClient } from './base.js';

import type {
  ResearchProvider,
  ResearchProviderConfig,
  ResearchProviderHealth,
  ResearchProviderResult,
  ResearchQuery,
} from '../types.js';
import {
  asString,
  fetchJsonWithErrors,
  isRecord,
  lightweightHealthPing,
  makeProviderFailure,
  makeProviderSuccess,
  normalizeCitation,
  sanitizeTimeoutMs,
} from './shared.js';

const DEFAULT_GEMINI_BASE_URL = 'https://generativelanguage.googleapis.com/v1beta/models';
const DEFAULT_GEMINI_MODEL = 'gemini-2.0-flash';

function extractGeminiAnswer(payload: Record<string, unknown>): string {
  const candidates = Array.isArray(payload['candidates']) ? payload['candidates'] : [];
  const firstCandidate = candidates[0];
  if (!isRecord(firstCandidate)) return '';

  const content = isRecord(firstCandidate['content']) ? firstCandidate['content'] : {};
  const parts = Array.isArray(content['parts']) ? content['parts'] : [];

  const segments: string[] = [];
  for (const part of parts) {
    if (!isRecord(part)) continue;
    const text = asString(part['text']);
    if (text) segments.push(text);
  }

  return segments.join(' ').trim();
}

function extractGeminiCitations(payload: Record<string, unknown>) {
  const candidates = Array.isArray(payload['candidates']) ? payload['candidates'] : [];

  const citations = [];
  for (const candidate of candidates) {
    if (!isRecord(candidate)) continue;

    const metadata = isRecord(candidate['groundingMetadata']) ? candidate['groundingMetadata'] : {};
    const chunks = Array.isArray(metadata['groundingChunks']) ? metadata['groundingChunks'] : [];

    for (const chunk of chunks) {
      if (!isRecord(chunk)) continue;
      const web = isRecord(chunk['web']) ? chunk['web'] : {};
      const citation = normalizeCitation({
        title: web['title'],
        url: web['uri'],
        source: 'gemini',
      });
      if (citation) citations.push(citation);
    }
  }

  return citations;
}

export class GeminiResearchProvider implements ResearchProvider {
  readonly id = 'gemini' as const;
  readonly enabled: boolean;
  readonly timeoutMs: number;

  private readonly apiKey?: string;
  private readonly baseUrl: string;
  private readonly model: string;

  constructor(config: ResearchProviderConfig = {}) {
    this.enabled = config.enabled === true;
    this.timeoutMs = sanitizeTimeoutMs(config.timeoutMs);
    this.apiKey = asString(config.apiKey);
    this.baseUrl = (asString(config.baseUrl) ?? DEFAULT_GEMINI_BASE_URL).replace(/\/+$/, '');
    this.model = asString(config.model) ?? DEFAULT_GEMINI_MODEL;
  }

  async search(query: ResearchQuery): Promise<ResearchProviderResult> {
    if (!this.enabled) {
      return makeProviderFailure(this.id, 'PROVIDER_DISABLED', 'Gemini provider is disabled.', { retryable: false });
    }

    if (!this.apiKey) {
      return makeProviderFailure(this.id, 'MISSING_API_KEY', 'Gemini API key is missing.', { retryable: false });
    }

    const endpoint = `${this.baseUrl}/${this.model}:generateContent?key=${encodeURIComponent(this.apiKey)}`;

    const response = await fetchJsonWithErrors(
      this.id,
      endpoint,
      {
        method: 'POST',
        headers: {
          'content-type': 'application/json',
        },
        body: JSON.stringify({
          contents: [
            {
              role: 'user',
              parts: [{ text: query.query }],
            },
          ],
          generationConfig: {
            temperature: 0.2,
          },
        }),
        signal: AbortSignal.timeout(this.timeoutMs),
      },
    );

    if (!response.ok) {
      return {
        ok: false,
        provider: this.id,
        error: response.error,
      };
    }

    const payload = response.data;
    if (!isRecord(payload)) {
      return makeProviderFailure(this.id, 'INVALID_RESPONSE', 'Gemini payload is not an object.', { retryable: false });
    }

    const answer = extractGeminiAnswer(payload);
    const citations = extractGeminiCitations(payload);

    return makeProviderSuccess(
      this.id,
      query,
      answer || 'No summary returned by Gemini.',
      citations,
      payload,
    );
  }

  async healthCheck(): Promise<ResearchProviderHealth> {
    return lightweightHealthPing({
      provider: this.id,
      enabled: this.enabled,
      timeoutMs: Math.min(this.timeoutMs, 5_000),
      url: this.baseUrl,
    });
  }
}

import type {
  ResearchProvider,
  ResearchProviderConfig,
  ResearchProviderHealth,
  ResearchProviderResult,
  ResearchQuery,
} from '../types.js';
import {
  asString,
  extractUrlsFromText,
  fetchJsonWithErrors,
  isRecord,
  lightweightHealthPing,
  makeProviderFailure,
  makeProviderSuccess,
  normalizeCitation,
  sanitizeTimeoutMs,
} from './shared.js';

const DEFAULT_GROQ_BASE_URL = 'https://api.groq.com/openai/v1';
const DEFAULT_GROQ_MODEL = 'llama-3.3-70b-versatile';

function intentSystemPrompt(intent: ResearchQuery['intent']): string {
  switch (intent) {
    case 'coding':
      return 'Provide technically accurate and concise developer-focused research answers with source links.';
    case 'news':
      return 'Summarize timely information with clear, current source references.';
    case 'academic':
      return 'Provide evidence-focused synthesis and include relevant source links.';
    case 'general':
    default:
      return 'Provide a concise research summary and include relevant source links.';
  }
}

export class GroqResearchProvider implements ResearchProvider {
  readonly id = 'groq' as const;
  readonly enabled: boolean;
  readonly timeoutMs: number;

  private readonly apiKey?: string;
  private readonly baseUrl: string;
  private readonly model: string;

  constructor(config: ResearchProviderConfig = {}) {
    this.enabled = config.enabled === true;
    this.timeoutMs = sanitizeTimeoutMs(config.timeoutMs);
    this.apiKey = asString(config.apiKey);
    this.baseUrl = (asString(config.baseUrl) ?? DEFAULT_GROQ_BASE_URL).replace(/\/+$/, '');
    this.model = asString(config.model) ?? DEFAULT_GROQ_MODEL;
  }

  async search(query: ResearchQuery): Promise<ResearchProviderResult> {
    if (!this.enabled) {
      return makeProviderFailure(this.id, 'PROVIDER_DISABLED', 'Groq provider is disabled.', { retryable: false });
    }

    if (!this.apiKey) {
      return makeProviderFailure(this.id, 'MISSING_API_KEY', 'Groq API key is missing.', { retryable: false });
    }

    const response = await fetchJsonWithErrors(
      this.id,
      `${this.baseUrl}/chat/completions`,
      {
        method: 'POST',
        headers: {
          authorization: `Bearer ${this.apiKey}`,
          'content-type': 'application/json',
        },
        body: JSON.stringify({
          model: this.model,
          messages: [
            {
              role: 'system',
              content: intentSystemPrompt(query.intent),
            },
            {
              role: 'user',
              content: query.query,
            },
          ],
          temperature: 0.2,
        }),
        signal: AbortSignal.timeout(this.timeoutMs),
      },
    );

    if (!response.ok) {
      return {
        ok: false,
        provider: this.id,
        error: response.error,
      };
    }

    const payload = response.data;
    if (!isRecord(payload)) {
      return makeProviderFailure(this.id, 'INVALID_RESPONSE', 'Groq payload is not an object.', { retryable: false });
    }

    const choices = Array.isArray(payload['choices']) ? payload['choices'] : [];
    const firstChoice = choices[0];

    let answer = '';
    if (isRecord(firstChoice)) {
      const message = isRecord(firstChoice['message']) ? firstChoice['message'] : {};
      answer = asString(message['content']) ?? '';
    }

    const citationsFromPayload = Array.isArray(payload['citations']) ? payload['citations'] : [];
    const mappedPayloadCitations = citationsFromPayload
      .map((citation) => {
        if (!isRecord(citation)) return null;
        return normalizeCitation({
          title: citation['title'],
          url: citation['url'],
          snippet: citation['snippet'],
          source: 'groq',
        });
      })
      .filter((citation): citation is NonNullable<typeof citation> => citation !== null);

    const fallbackCitations = mappedPayloadCitations.length > 0
      ? mappedPayloadCitations
      : extractUrlsFromText(answer).map((url) => ({ url, source: 'groq' as const }));

    return makeProviderSuccess(
      this.id,
      query,
      answer || 'No summary returned by Groq.',
      fallbackCitations,
      payload,
    );
  }

  async healthCheck(): Promise<ResearchProviderHealth> {
    return lightweightHealthPing({
      provider: this.id,
      enabled: this.enabled,
      timeoutMs: Math.min(this.timeoutMs, 5_000),
      url: this.baseUrl,
    });
  }
}

import { createResearchRegistry } from './registry.js';
import { makeProviderError, makeProviderFailure, toErrorMessage } from './providers/shared.js';
import type {
  ResearchConfigInput,
  ResearchProvider,
  ResearchProviderId,
  ResearchProviderResult,
  ResearchQuery,
  ResearchQueryIntent,
  ResearchRouteAttempt,
  ResearchRouteResult,
} from './types.js';

const INTENT_FALLBACK_ORDER: Record<ResearchQueryIntent, ResearchProviderId[]> = {
  general: ['tavily', 'exa', 'brave', 'gemini', 'groq'],
  news: ['tavily', 'brave', 'exa', 'gemini', 'groq'],
  academic: ['exa', 'tavily', 'gemini', 'brave', 'groq'],
  coding: ['tavily', 'groq', 'gemini', 'exa', 'brave'],
};

export interface RouteResearchOptions {
  config?: ResearchConfigInput | Record<string, unknown> | null;
  providers?: ResearchProvider[];
  providerOrder?: ResearchProviderId[];
}

function uniqueOrder(input: ResearchProviderId[]): ResearchProviderId[] {
  const seen = new Set<ResearchProviderId>();
  const output: ResearchProviderId[] = [];

  for (const providerId of input) {
    if (seen.has(providerId)) continue;
    seen.add(providerId);
    output.push(providerId);
  }

  return output;
}

function resolveOrderedProviders(
  providers: ResearchProvider[],
  intent: ResearchQueryIntent,
  explicitOrder?: ResearchProviderId[],
): ResearchProvider[] {
  const enabledProviders = providers.filter((provider) => provider.enabled);
  if (enabledProviders.length === 0) return [];

  const providerMap = new Map<ResearchProviderId, ResearchProvider>();
  for (const provider of enabledProviders) {
    providerMap.set(provider.id, provider);
  }

  const fallbackOrder = INTENT_FALLBACK_ORDER[intent] ?? INTENT_FALLBACK_ORDER.general;
  const preferredOrder = explicitOrder && explicitOrder.length > 0
    ? uniqueOrder([...explicitOrder, ...fallbackOrder])
    : uniqueOrder([...fallbackOrder]);

  const orderedProviders: ResearchProvider[] = [];

  for (const providerId of preferredOrder) {
    const provider = providerMap.get(providerId);
    if (!provider) continue;
    orderedProviders.push(provider);
    providerMap.delete(providerId);
  }

  for (const provider of providerMap.values()) {
    orderedProviders.push(provider);
  }

  return orderedProviders;
}

async function executeWithTimeout(
  provider: ResearchProvider,
  query: ResearchQuery,
  signal?: AbortSignal
): Promise<ResearchProviderResult> {
  const timeoutMs = provider.timeoutMs > 0 ? provider.timeoutMs : 10_000;

  return new Promise<ResearchProviderResult>((resolve) => {
    let settled = false;

    const timeoutHandle = setTimeout(() => {
      if (settled) return;
      settled = true;
      resolve(
        makeProviderFailure(
          provider.id,
          'TIMEOUT',
          `Provider ${provider.id} timed out after ${timeoutMs}ms.`,
        ),
      );
    }, timeoutMs);

    const abortHandler = () => {
      if (settled) return;
      settled = true;
      clearTimeout(timeoutHandle);
      resolve(
        makeProviderFailure(
          provider.id,
          'TIMEOUT',
          `Provider ${provider.id} was aborted.`,
        ),
      );
    };

    if (signal) {
      if (signal.aborted) {
        abortHandler();
        return;
      }
      signal.addEventListener('abort', abortHandler, { once: true });
    }

    provider
      .search(query)
      .then((result) => {
        if (settled) return;
        settled = true;
        clearTimeout(timeoutHandle);
        if (signal) signal.removeEventListener('abort', abortHandler);
        resolve(result);
      })
      .catch((error: unknown) => {
        if (settled) return;
        settled = true;
        clearTimeout(timeoutHandle);
        if (signal) signal.removeEventListener('abort', abortHandler);
        resolve(
          makeProviderFailure(
            provider.id,
            'UNKNOWN_ERROR',
            `Provider threw an unexpected error: ${toErrorMessage(error, 'unknown error')}`,
          ),
        );
      });
  });
}

export async function routeResearchQuery(
  query: ResearchQuery,
  options: RouteResearchOptions = {},
  signal?: AbortSignal
): Promise<ResearchRouteResult> {
  const availableProviders = options.providers ?? createResearchRegistry(options.config);
  const orderedProviders = resolveOrderedProviders(availableProviders, query.intent, options.providerOrder);

  if (orderedProviders.length === 0) {
    return {
      ok: false,
      error: makeProviderError('router', 'NO_PROVIDERS_ENABLED', 'No enabled research providers are configured.', {
        retryable: false,
      }),
      attempts: [],
    };
  }

  const attempts: ResearchRouteAttempt[] = [];

  for (const provider of orderedProviders) {
    if (signal?.aborted) break;
    const result = await executeWithTimeout(provider, query, signal);

    if (result.ok) {
      return {
        ok: true,
        provider: result.provider,
        result: result.result,
        attempts,
      };
    }

    attempts.push({
      provider: provider.id,
      error: result.error,
    });
  }

  const attemptedProviders = attempts.map((attempt) => attempt.provider).join(', ');

  return {
    ok: false,
    error: makeProviderError(
      'router',
      'ALL_PROVIDERS_FAILED',
      attemptedProviders
        ? `All providers failed for query "${query.query}": ${attemptedProviders}.`
        : `All providers failed for query "${query.query}".`,
    ),
    attempts,
  };
}

import { mkdir, open, readFile, rename, stat, unlink, writeFile } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { getConfigDir } from '../platform/paths.js';
import { z } from 'zod';
import type { ActionEvent } from './activity.js';
import { MAX_ACTION_HISTORY } from './activity.js';
import { sleep } from '../utils/common.js';

const ActionEventSchema = z.object({
  id: z.string(),
  at: z.number(),
  sessionId: z.string(),
  kind: z.enum(['turn', 'tool', 'thinking', 'slash', 'model', 'permission', 'error', 'info']),
  status: z.enum(['running', 'ok', 'error', 'info']),
  icon: z.string(),
  label: z.string(),
  detail: z.string().optional(),
});

export const DEFAULT_ACTION_HISTORY_PATH = join(getConfigDir(), 'tui-action-history.jsonl');

export interface ActionHistoryStoreOptions {
  filePath?: string;
  maxEntries?: number;
  lockTimeoutMs?: number;
  lockRetryMs?: number;
  staleLockMs?: number;
}

function resolvePath(options: ActionHistoryStoreOptions): string {
  return options.filePath ?? DEFAULT_ACTION_HISTORY_PATH;
}

function resolveMaxEntries(options: ActionHistoryStoreOptions): number {
  const requested = options.maxEntries ?? MAX_ACTION_HISTORY;
  return Math.max(1, requested);
}

function lockPath(filePath: string): string {
  return `${filePath}.lock`;
}

async function acquireLock(path: string, timeoutMs: number, retryMs: number, staleLockMs: number) {
  const started = Date.now();
  while (true) {
    try {
      return await open(path, 'wx');
    } catch (error) {
      const err = error as NodeJS.ErrnoException;
      if (err.code !== 'EEXIST') throw err;
      try {
        const info = await stat(path);
        if (Date.now() - info.mtimeMs >= staleLockMs) {
          await unlink(path).catch(() => {});
          continue;
        }
      } catch (statError) {
        const statErr = statError as NodeJS.ErrnoException;
        if (statErr.code !== 'ENOENT') {
          // Keep retrying through transient stat/unlink issues.
        }
      }
      if (Date.now() - started >= timeoutMs) {
        throw new Error(`Timed out waiting for action history lock: ${path}`);
      }
      await sleep(retryMs);
    }
  }
}

async function readHistoryFile(filePath: string): Promise<string> {
  try {
    return await readFile(filePath, 'utf-8');
  } catch (error) {
    const err = error as NodeJS.ErrnoException;
    if (err.code === 'ENOENT') return '';
    throw err;
  }
}

function parseHistory(raw: string, maxEntries: number): ActionEvent[] {
  if (!raw.trim()) return [];
  const parsed: ActionEvent[] = [];
  const lines = raw.split('\n').filter((line) => line.trim().length > 0);
  for (const line of lines) {
    let json: unknown;
    try {
      json = JSON.parse(line);
    } catch {
      continue;
    }
    const result = ActionEventSchema.safeParse(json);
    if (!result.success) continue;
    parsed.push(result.data);
  }
  parsed.sort((a, b) => b.at - a.at);
  return parsed.slice(0, maxEntries);
}

function serializeHistory(entries: ActionEvent[]): string {
  if (entries.length === 0) return '';
  return `${entries.map((entry) => JSON.stringify(entry)).join('\n')}\n`;
}

async function writeHistoryAtomically(filePath: string, entries: ActionEvent[]): Promise<void> {
  const tempPath = `${filePath}.${process.pid}.${Date.now()}.tmp`;
  await writeFile(tempPath, serializeHistory(entries), 'utf-8');
  await rename(tempPath, filePath);
  await unlink(tempPath).catch(() => {});
}

export async function loadActionHistory(options: ActionHistoryStoreOptions = {}): Promise<ActionEvent[]> {
  const filePath = resolvePath(options);
  const maxEntries = resolveMaxEntries(options);
  const raw = await readHistoryFile(filePath);
  return parseHistory(raw, maxEntries);
}

export async function appendActionHistory(
  entry: ActionEvent,
  options: ActionHistoryStoreOptions = {},
): Promise<void> {
  const filePath = resolvePath(options);
  const maxEntries = resolveMaxEntries(options);
  const lockTimeoutMs = options.lockTimeoutMs ?? 5000;
  const lockRetryMs = options.lockRetryMs ?? 20;
  const staleLockMs = options.staleLockMs ?? 15_000;
  const parsed = ActionEventSchema.parse(entry);

  await mkdir(dirname(filePath), { recursive: true });
  const lockHandle = await acquireLock(lockPath(filePath), lockTimeoutMs, lockRetryMs, staleLockMs);
  try {
    const raw = await readHistoryFile(filePath);
    const existing = parseHistory(raw, maxEntries);
    const next = [parsed, ...existing.filter((item) => item.id !== parsed.id)].slice(0, maxEntries);
    await writeHistoryAtomically(filePath, next);
  } finally {
    await lockHandle.close().catch(() => {});
    await unlink(lockPath(filePath)).catch(() => {});
  }
}

export async function clearActionHistory(options: ActionHistoryStoreOptions = {}): Promise<void> {
  const filePath = resolvePath(options);
  const lockTimeoutMs = options.lockTimeoutMs ?? 5000;
  const lockRetryMs = options.lockRetryMs ?? 20;
  const staleLockMs = options.staleLockMs ?? 15_000;

  await mkdir(dirname(filePath), { recursive: true });
  const lockHandle = await acquireLock(lockPath(filePath), lockTimeoutMs, lockRetryMs, staleLockMs);
  try {
    await writeHistoryAtomically(filePath, []);
  } finally {
    await lockHandle.close().catch(() => {});
    await unlink(lockPath(filePath)).catch(() => {});
  }
}

/**
 * TUI Adapter — EventEmitter bridge between agentLoop() and the React/Ink TUI.
 *
 * Converts the streaming agent response into discrete events that React components
 * can subscribe to via useEffect, enabling real-time token display, tool call
 * visualization, and live stats updates.
 */

import { EventEmitter } from 'node:events';
import type { OptaConfig } from '../core/config.js';
import type { AgentLoopOptions, AgentLoopResult } from '../core/agent.js';
import type { Session } from '../memory/store.js';
import type { PermissionDecision } from './PermissionPrompt.js';
import { InsightEngine, type Insight } from '../core/insights.js';
import { errorMessage } from '../utils/errors.js';
import type { SubAgentDisplayState, SubAgentProgressEvent } from '../core/subagent-events.js';
import { probeLmxConnection } from '../lmx/connection.js';
import { resolveLmxEndpoint } from '../lmx/endpoints.js';
import type { AtpoState } from './Header.js';

/** Average characters per token for rough estimation. */
const CHARS_PER_TOKEN = 4;

/** Minimum elapsed seconds before computing tokens/sec (avoids division spikes). */
const MIN_ELAPSED_FOR_SPEED = 0.1;

// --- Event Types ---

export interface TurnStats {
  tokens: number;
  promptTokens: number;
  completionTokens: number;
  toolCalls: number;
  elapsed: number;
  speed: number;
  firstTokenLatencyMs: number | null;
}

export interface PermissionRequest {
  id: string;
  toolName: string;
  args: Record<string, unknown>;
}

export interface TuiErrorPayload {
  message: string;
  code?: string;
}

export type TuiErrorEvent = string | TuiErrorPayload;

export interface TuiEventMap {
  'token': [text: string];
  'tool:start': [name: string, id: string, args: string];
  'tool:end': [name: string, id: string, result: string];
  'thinking': [text: string];
  'turn:start': [];
  'turn:end': [stats: TurnStats];
  'turn:first-token': [latencyMs: number];
  'turn:progress': [stats: { elapsed: number; speed: number; completionTokens: number }];
  'connection:status': [status: 'checking' | 'connected' | 'disconnected' | 'error' | 'reconnecting'];
  'error': [error: TuiErrorEvent];
  'permission:request': [request: PermissionRequest];
  'permission:response': [id: string, decision: PermissionDecision];
  'title': [title: string];
  'insight': [insight: Insight];
  'subagent:spawn': [state: SubAgentDisplayState];
  'subagent:progress': [event: SubAgentProgressEvent];
  'subagent:done': [agentId: string, result: string];
  'subagent:clear': [];
  'atpo:state': [state: AtpoState];
  /** Emitted after each successfully executed Playwright MCP tool call. */
  'browser:event': [toolName: string, sessionId: string];
}

export class TuiEmitter extends EventEmitter {
  override emit<K extends keyof TuiEventMap>(event: K, ...args: TuiEventMap[K]): boolean {
    return super.emit(event, ...args);
  }

  override on<K extends keyof TuiEventMap>(event: K, listener: (...args: TuiEventMap[K]) => void): this {
    return super.on(event, listener as (...args: unknown[]) => void);
  }

  override off<K extends keyof TuiEventMap>(event: K, listener: (...args: TuiEventMap[K]) => void): this {
    return super.off(event, listener as (...args: unknown[]) => void);
  }
}

// --- Adapter: Runs agent loop and emits events ---

export interface TuiAdapterOptions {
  config: OptaConfig;
  session: Session;
}

/** Counter for unique permission request IDs. */
let permissionRequestCounter = 0;

/**
 * Run the agent loop for a user message and emit streaming events.
 *
 * This creates the onStream callbacks, passes them into agentLoop,
 * and emits higher-level events (turn:start, turn:end) around it.
 */
export async function runAgentWithEvents(
  emitter: TuiEmitter,
  task: string,
  config: OptaConfig,
  session: Session,
  images?: Array<{ base64: string; mimeType: string; name?: string }>,
  mode?: string,
): Promise<AgentLoopResult> {
  const turnStartTime = Date.now();
  let completionTokens = 0;
  let toolCallCount = 0;
  let firstTokenTime: number | null = null;
  let apiPromptTokens = 0;

  // Insight engine — observes agent events and emits ★ blocks
  const insights = new InsightEngine((insight) => {
    emitter.emit('insight', insight);
  });
  insights.setModel(config.model.default);
  insights.setContextLimit(config.model.contextLimit);

  emitter.emit('turn:start');
  insights.turnStart();

  // Progress timer: emits turn:progress every 500ms with live stats
  const progressInterval = setInterval(() => {
    const elapsed = (Date.now() - turnStartTime) / 1000;
    const speed = elapsed > MIN_ELAPSED_FOR_SPEED
      ? completionTokens / elapsed
      : 0;
    emitter.emit('turn:progress', { elapsed, speed, completionTokens });
    insights.progress(completionTokens, speed, elapsed);
  }, 500);

  const { agentLoop } = await import('../core/agent.js');

  const options: AgentLoopOptions = {
    existingMessages: session.messages,
    sessionId: session.id,
    silent: true, // We handle display in the TUI
    images,
    mode: (mode && mode !== 'normal') ? mode as 'plan' | 'review' | 'research' : undefined,
    onStream: {
      onToken(text: string) {
        // Track first token latency
        if (firstTokenTime === null) {
          firstTokenTime = Date.now();
          const latencyMs = firstTokenTime - turnStartTime;
          emitter.emit('turn:first-token', latencyMs);
          insights.firstToken(latencyMs);
        }

        completionTokens += Math.ceil(text.length / CHARS_PER_TOKEN);
        emitter.emit('token', text);
      },
      onToolStart(name: string, id: string, args: string) {
        toolCallCount++;
        emitter.emit('tool:start', name, id, args);
        insights.toolStart(name, args);
      },
      onToolEnd(name: string, id: string, result: string) {
        emitter.emit('tool:end', name, id, result);
        insights.toolEnd(name, id, result);
      },
      onThinking(text: string) {
        emitter.emit('thinking', text);
      },
      onConnectionStatus(status: 'checking' | 'connected' | 'disconnected' | 'reconnecting') {
        emitter.emit('connection:status', status as 'checking' | 'connected' | 'disconnected' | 'error');
        insights.connectionStatus(status);
      },
      onUsage(usage: { promptTokens: number; completionTokens: number }) {
        apiPromptTokens = usage.promptTokens;
      },
      onAtpoState(state: import('./Header.js').AtpoState) {
        emitter.emit('atpo:state', state);
      },
      /**
       * Bridge permission requests from the agent loop to the TUI.
       *
       * Emits a 'permission:request' event and returns a Promise that
       * resolves when the TUI sends back a 'permission:response' event.
       * This blocks the agent loop until the user makes a decision.
       */
      onPermissionRequest(toolName: string, args: Record<string, unknown>): Promise<PermissionDecision> {
        const requestId = `perm-${++permissionRequestCounter}`;

        return new Promise<PermissionDecision>((resolve) => {
          // Listen for the response matching this request ID
          const onResponse = (id: string, decision: PermissionDecision) => {
            if (id === requestId) {
              emitter.off('permission:response', onResponse);
              resolve(decision);
            }
          };
          emitter.on('permission:response', onResponse);

          // Emit the request to the TUI
          emitter.emit('permission:request', { id: requestId, toolName, args });
        });
      },
    },
    onSubAgentSpawn(id: string, label: string, dependsOn?: number) {
      const state: SubAgentDisplayState = {
        id,
        label: label.slice(0, 40),
        phase: 'spawning',
        spawnedAtMs: Date.now(),
        toolCallCount: 0,
        toolHistory: [],
        dependsOn,
      };
      emitter.emit('subagent:spawn', state);
    },
    onSubAgentProgress(event: SubAgentProgressEvent) {
      emitter.emit('subagent:progress', event);
    },
    onSubAgentDone(agentId: string, result: string) {
      emitter.emit('subagent:done', agentId, result);
    },
    onBrowserEvent(toolName: string, sessionId: string) {
      emitter.emit('browser:event', toolName, sessionId);
    },
  };

  try {
    const result = await agentLoop(task, config, options);

    clearInterval(progressInterval);

    const elapsedMs = Date.now() - turnStartTime;
    const elapsed = elapsedMs / 1000;
    const speed = elapsed > MIN_ELAPSED_FOR_SPEED
      ? completionTokens / elapsed
      : 0;
    const firstTokenLatencyMs = firstTokenTime !== null
      ? firstTokenTime - turnStartTime
      : null;

    const turnStats = {
      tokens: completionTokens,
      promptTokens: apiPromptTokens,
      completionTokens,
      toolCalls: toolCallCount,
      elapsed,
      speed,
      firstTokenLatencyMs,
    };

    insights.turnEnd(turnStats);
    emitter.emit('turn:end', turnStats);

    // Fire-and-forget: auto-generate HTML report if thresholds are met.
    // Uses dynamic import to avoid loading report code on every turn.
    import('../ui/report-trigger.js')
      .then(({ maybeGenerateReport }) =>
        maybeGenerateReport(session, turnStats, config, mode))
      .catch(() => { /* Report generation is best-effort */ });

    return result;
  } catch (err) {
    clearInterval(progressInterval);
    const errMsg = errorMessage(err);
    emitter.emit('error', errMsg);
    throw err;
  }
}

export function createTuiEmitter(): TuiEmitter {
  return new TuiEmitter();
}

/**
 * Check connectivity to the Opta-LMX server and emit connection status events.
 *
 * Emits 'connection:status' with 'checking', then 'connected' on success,
 * 'error' on non-OK response, or 'disconnected' on network failure.
 */
export async function checkConnection(emitter: TuiEmitter, config: OptaConfig): Promise<void> {
  emitter.emit('connection:status', 'checking');
  const endpoint = await resolveLmxEndpoint({
    host: config.connection.host,
    fallbackHosts: config.connection.fallbackHosts,
    port: config.connection.port,
    adminKey: config.connection.adminKey,
    adminKeysByHost: config.connection.adminKeysByHost,
  }, { timeoutMs: 1_500 });
  const result = await probeLmxConnection(
    endpoint.host,
    config.connection.port,
    {
      timeoutMs: 5000,
      adminKey: config.connection.adminKey,
      adminKeysByHost: config.connection.adminKeysByHost,
    }
  );
  if (result.state === 'connected') {
    emitter.emit('connection:status', 'connected');
  } else if (result.state === 'degraded') {
    emitter.emit('connection:status', 'error');
  } else {
    emitter.emit('connection:status', 'disconnected');
  }
}

import { useState, useCallback, useEffect, useMemo } from 'react';
import { DEFAULT_CONFIG, type OptaConfig } from '../../core/config.js';
import {
  loadKeybindings,
  mergeKeybindings,
  type KeybindingConfig,
  type KeybindingOverrides,
} from '../keybindings.js';
import type { ConnectionState } from '../utils.js';
import type { AccountState } from '../../accounts/types.js';
import type { StudioConnectivityState } from '../OptaMenuOverlay.js';
import type { ResponseIntentTone } from '../response-intent.js';
import { DEFAULT_TRIGGER_MODE_DEFINITIONS, type TriggerModeDefinition } from '../trigger-router.js';
import { homedir } from '../../platform/index.js';
import { errorMessage } from '../../utils/errors.js';

interface SkillRuntimeSettings {
  dynamicLoading: boolean;
  unloadInactive: boolean;
  ttlMinutes: number;
  maxActiveSkills: number;
}

const DEFAULT_SKILL_RUNTIME_SETTINGS: SkillRuntimeSettings = {
  dynamicLoading: true,
  unloadInactive: true,
  ttlMinutes: 30,
  maxActiveSkills: 24,
};

function isLocalHost(host: string): boolean {
  const normalized = host.trim().toLowerCase();
  return normalized === 'localhost' || normalized === '127.0.0.1' || normalized === '::1';
}

function expandHomePath(pathValue: string): string {
  if (!pathValue.startsWith('~/') && pathValue !== '~') return pathValue;
  return homedir() + pathValue.slice(1);
}

export interface UseAppConfigReturn {
  // Connection details
  connectionHost: string;
  connectionFallbackHosts: string[];
  connectionAutoDiscover: boolean;
  connectionPort: number;
  connectionAdminKey: string | undefined;
  connectionAdminKeysByHost: Record<string, string>;
  connectionSshUser: string;
  connectionSshIdentityFile: string;
  connectionSshConnectTimeoutSec: number;
  studioConnectivity: StudioConnectivityState;

  // Account
  accountState: AccountState | null;

  // Trigger/skill/response-intent config
  triggerDefinitions: TriggerModeDefinition[];
  skillRuntimeSettings: SkillRuntimeSettings;
  responseIntentTone: ResponseIntentTone;
  setResponseIntentTone: React.Dispatch<React.SetStateAction<ResponseIntentTone>>;

  // Autonomy
  setAutonomyLevel: (v: number) => void;
  setAutonomyMode: (v: 'execution' | 'ceo') => void;

  // Browser policy
  setBrowserPolicyConfig: (v: typeof DEFAULT_CONFIG.browser.policy) => void;

  // Keybinding config
  keybindingOverrides: KeybindingOverrides;
  keybindings: KeybindingConfig;

  // Context limit and registered tool count
  setContextLimit: (v: number) => void;
  setRegisteredToolCount: (v: number) => void;

  // Reconnect
  reconnectLmx: () => Promise<void>;
  // Full config snapshot + refresh
  configSnapshot: OptaConfig;
  refreshConfig: () => Promise<void>;
}

export interface UseAppConfigDeps {
  currentModel: string;
  persistenceEnabled: boolean;
  setConnectionState: (v: ConnectionState) => void;
  setCurrentModel: (v: string) => void;
  setAutonomyLevel: (v: number) => void;
  setAutonomyMode: (v: 'execution' | 'ceo') => void;
  setContextLimit: (v: number) => void;
  setRegisteredToolCount: (v: number) => void;
  setBrowserPolicyConfig: (v: typeof DEFAULT_CONFIG.browser.policy) => void;
}

export function useAppConfig(deps: UseAppConfigDeps): UseAppConfigReturn {
  const {
    currentModel,
    persistenceEnabled,
    setConnectionState,
    setCurrentModel,
    setAutonomyLevel,
    setAutonomyMode,
    setContextLimit,
    setRegisteredToolCount,
    setBrowserPolicyConfig,
  } = deps;

  // --- Connection details ---
  const [connectionHost, setConnectionHost] = useState(DEFAULT_CONFIG.connection.host);
  const [connectionFallbackHosts, setConnectionFallbackHosts] = useState<string[]>([]);
  const [connectionAutoDiscover, setConnectionAutoDiscover] = useState(
    DEFAULT_CONFIG.connection.autoDiscover
  );
  const [connectionPort, setConnectionPort] = useState(1234);
  const [connectionAdminKey, setConnectionAdminKey] = useState<string | undefined>(undefined);
  const [connectionAdminKeysByHost, setConnectionAdminKeysByHost] = useState<Record<string, string>>(
    {}
  );
  const [connectionSshUser, setConnectionSshUser] = useState('opta');
  const [connectionSshIdentityFile, setConnectionSshIdentityFile] = useState('~/.ssh/id_ed25519');
  const [connectionSshConnectTimeoutSec, setConnectionSshConnectTimeoutSec] = useState(20);
  const [studioConnectivity, setStudioConnectivity] = useState<StudioConnectivityState>('checking');

  // --- Account ---
  const [accountState, setAccountState] = useState<AccountState | null>(null);

  // --- Trigger/Skill/ResponseIntent ---
  const [triggerDefinitions, setTriggerDefinitions] = useState<TriggerModeDefinition[]>(
    DEFAULT_TRIGGER_MODE_DEFINITIONS
  );
  const [skillRuntimeSettings, setSkillRuntimeSettings] = useState<SkillRuntimeSettings>(
    DEFAULT_SKILL_RUNTIME_SETTINGS
  );
  const [responseIntentTone, setResponseIntentTone] = useState<ResponseIntentTone>(
    DEFAULT_CONFIG.tui.responseIntentTone
  );
  const [configSnapshot, setConfigSnapshot] = useState<OptaConfig>(DEFAULT_CONFIG);

  // --- Keybinding overrides ---
  const [keybindingOverrides, setKeybindingOverrides] = useState<KeybindingOverrides>({});

  // --- Context limit loading ---
  useEffect(() => {
    import('../../core/models.js')
      .then(({ getContextLimit }) => {
        setContextLimit(getContextLimit(currentModel));
      })
      .catch(() => {});
  }, [currentModel, setContextLimit]);

  // --- Registered tools count loading ---
  useEffect(() => {
    import('../../core/tools/schemas.js')
      .then(({ TOOL_SCHEMAS }) => {
        setRegisteredToolCount(TOOL_SCHEMAS.length);
      })
      .catch(() => {});
  }, [setRegisteredToolCount]);

  const applyLoadedConfig = useCallback((cfg: OptaConfig) => {
    setConnectionHost(cfg.connection.host);
    setConnectionFallbackHosts(cfg.connection.fallbackHosts);
    setConnectionAutoDiscover(cfg.connection.autoDiscover);
    setConnectionPort(cfg.connection.port);
    setConnectionAdminKey(cfg.connection.adminKey);
    setConnectionAdminKeysByHost(cfg.connection.adminKeysByHost);
    setConnectionSshUser(cfg.connection.ssh.user);
    setConnectionSshIdentityFile(cfg.connection.ssh.identityFile);
    setConnectionSshConnectTimeoutSec(cfg.connection.ssh.connectTimeoutSec);
    setAutonomyLevel(cfg.autonomy.level);
    setAutonomyMode(cfg.autonomy.mode);
    setBrowserPolicyConfig(cfg.browser.policy);
    setTriggerDefinitions(
      cfg.tui.triggerModes.length > 0
        ? cfg.tui.triggerModes
        : DEFAULT_TRIGGER_MODE_DEFINITIONS
    );
    setSkillRuntimeSettings({
      dynamicLoading: cfg.tui.skillRuntime.dynamicLoading,
      unloadInactive: cfg.tui.skillRuntime.unloadInactive,
      ttlMinutes: cfg.tui.skillRuntime.ttlMinutes,
      maxActiveSkills: cfg.tui.skillRuntime.maxActiveSkills,
    });
    setResponseIntentTone(cfg.tui.responseIntentTone);
    setConfigSnapshot(cfg);
  }, [
    setAutonomyLevel,
    setAutonomyMode,
    setBrowserPolicyConfig,
  ]);

  const refreshConfig = useCallback(async () => {
    const { loadConfig } = await import('../../core/config.js');
    const cfg = await loadConfig();
    applyLoadedConfig(cfg);
  }, [applyLoadedConfig]);

  // --- Main config loading ---
  useEffect(() => {
    void refreshConfig().catch((err: unknown) => {
      // Log to stderr so failures surface without breaking the Ink render.
      process.stderr.write(
        `[useAppConfig] Failed to apply config: ${errorMessage(err)}\n`
      );
    });
  }, [
    refreshConfig,
  ]);

  // --- Keybindings override loading ---
  useEffect(() => {
    loadKeybindings()
      .then((overrides) => {
        setKeybindingOverrides(overrides);
      })
      .catch(() => {});
  }, []);

  // --- Merged keybindings ---
  const keybindings = useMemo(() => mergeKeybindings(keybindingOverrides), [keybindingOverrides]);

  // --- Load account state on mount (skipped in test environments) ---
  useEffect(() => {
    if (!persistenceEnabled) return;
    import('../../accounts/storage.js')
      .then((mod) => mod.loadAccountState())
      .then((state) => setAccountState(state))
      .catch(() => setAccountState(null));
  }, [persistenceEnabled]);

  // --- 30-minute cloud session heartbeat — keeps last_seen_at current ---
  // Fires once immediately after account state loads (if authenticated), then every 30 min.
  useEffect(() => {
    if (!persistenceEnabled) return;
    const touch = () => {
      import('../../accounts/storage.js')
        .then((mod) => mod.loadAccountState())
        .then((state) => {
          if (!state?.session) return;
          return import('../../accounts/cloud.js').then((mod) => mod.touchSessionRecord(state));
        })
        .catch(() => undefined);
    };
    touch();
    const interval = setInterval(touch, 30 * 60 * 1000);
    return () => clearInterval(interval);
  }, [persistenceEnabled]);

  // --- 30-second LMX heartbeat — keeps connectionState current ---
  useEffect(() => {
    const checkConnection = async () => {
      try {
        const { probeLmxConnection } = await import('../../lmx/connection.js');
        const result = await probeLmxConnection(connectionHost, connectionPort, {
          timeoutMs: 2_000,
          adminKey: connectionAdminKey,
          adminKeysByHost: connectionAdminKeysByHost,
        });
        setConnectionState(result.state !== 'disconnected' ? 'connected' : 'error');
      } catch {
        setConnectionState('error');
      }
    };
    const interval = setInterval(() => {
      void checkConnection();
    }, 30_000);
    return () => clearInterval(interval);
  }, [
    connectionHost,
    connectionPort,
    connectionAdminKey,
    connectionAdminKeysByHost,
    setConnectionState,
  ]);

  // --- Studio SSH connectivity check ---
  useEffect(() => {
    if (process.env['VITEST'] === 'true' || process.env['NODE_ENV'] === 'test') {
      setStudioConnectivity('reachable');
      return;
    }

    const hosts = [connectionHost, ...connectionFallbackHosts]
      .map((host) => host.trim())
      .filter((host, index, arr) => host.length > 0 && arr.indexOf(host) === index);
    const remoteHosts = hosts.filter((host) => !isLocalHost(host));

    if (remoteHosts.length === 0) {
      setStudioConnectivity('local');
      return;
    }

    let cancelled = false;
    setStudioConnectivity('checking');

    void (async () => {
      try {
        const { execa } = await import('execa');
        const timeoutSec = Math.max(3, Math.min(120, connectionSshConnectTimeoutSec));
        const identityFile = expandHomePath(connectionSshIdentityFile);

        for (const host of remoteHosts) {
          const args = [
            '-o',
            'BatchMode=yes',
            '-o',
            `ConnectTimeout=${timeoutSec}`,
            '-o',
            'StrictHostKeyChecking=accept-new',
            '-o',
            'NumberOfPasswordPrompts=0',
          ];
          if (identityFile.trim().length > 0) {
            args.push('-i', identityFile);
          }
          args.push(`${connectionSshUser}@${host}`, 'echo opta-ssh-ok');

          const result = await execa('ssh', args, {
            reject: false,
            timeout: (timeoutSec + 5) * 1000,
          });
          if (cancelled) return;
          if (result.exitCode === 0 && result.stdout.includes('opta-ssh-ok')) {
            setStudioConnectivity('reachable');
            return;
          }
        }

        if (!cancelled) {
          setStudioConnectivity('unreachable');
        }
      } catch {
        if (!cancelled) {
          setStudioConnectivity('unreachable');
        }
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [
    connectionHost,
    connectionFallbackHosts,
    connectionSshConnectTimeoutSec,
    connectionSshIdentityFile,
    connectionSshUser,
  ]);

  // --- Reconnect LMX ---
  const reconnectLmx = useCallback(async () => {
    setConnectionState('reconnecting');
    try {
      const { resetProviderCache, probeProvider } = await import('../../providers/manager.js');
      const { loadConfig } = await import('../../core/config.js');
      resetProviderCache();
      const config = await loadConfig();
      const provider = await probeProvider(config);
      setConnectionState('connected');
      const models = await provider.listModels().catch(() => []);
      if (models.length > 0 && models[0]) {
        setCurrentModel(models[0].id);
      }
    } catch {
      setConnectionState('error');
    }
  }, [setConnectionState, setCurrentModel]);

  return {
    connectionHost,
    connectionFallbackHosts,
    connectionAutoDiscover,
    connectionPort,
    connectionAdminKey,
    connectionAdminKeysByHost,
    connectionSshUser,
    connectionSshIdentityFile,
    connectionSshConnectTimeoutSec,
    studioConnectivity,
    accountState,
    triggerDefinitions,
    skillRuntimeSettings,
    responseIntentTone,
    setResponseIntentTone,
    setAutonomyLevel,
    setAutonomyMode,
    setBrowserPolicyConfig,
    keybindingOverrides,
    keybindings,
    setContextLimit,
    setRegisteredToolCount,
    reconnectLmx,
    configSnapshot,
    refreshConfig,
  };
}

/**
 * useBrowserIntegration — Extracted from App.tsx.
 *
 * Encapsulates all browser control surface callbacks (start/pause/resume/stop/kill/status),
 * profile pruning, replay session selection and loading, and the auto-refresh effects
 * that fire when the browser-control overlay opens or when health is unknown.
 */

import { useCallback, useEffect, useMemo } from 'react';
import type { BrowserControlAction } from '../../browser/control-surface.js';
import type { UseBrowserStateReturn } from './useBrowserState.js';
import type { ActionEventKind, ActionEventStatus } from '../activity.js';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Minimal action descriptor accepted by the appendAction helper in App. */
export interface AppendActionEvent {
  kind: ActionEventKind;
  status?: ActionEventStatus;
  icon?: string;
  label: string;
  detail?: string;
}

export interface UseBrowserIntegrationOptions {
  browserControlPane: UseBrowserStateReturn['browserControlPane'];
  setBrowserControlPane: UseBrowserStateReturn['setBrowserControlPane'];
  browserReplayPane: UseBrowserStateReturn['browserReplayPane'];
  setBrowserReplayPane: UseBrowserStateReturn['setBrowserReplayPane'];
  activeOverlay: string;
  appendAction: (action: AppendActionEvent) => void;
}

export interface UseBrowserIntegrationReturn {
  runBrowserControlPaneAction: (action: BrowserControlAction) => Promise<void>;
  pruneBrowserControlProfiles: () => Promise<void>;
  refreshBrowserControlPane: () => Promise<void>;
  browserReplaySessionIds: string[];
  handleReplaySelectSession: (sessionId: string) => void;
  handleReplaySelectStep: (index: number) => void;
  handleReplaySelectDiff: (index: number) => void;
  handleReplayLoadSession: (sessionId: string) => Promise<void>;
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useBrowserIntegration({
  browserControlPane,
  setBrowserControlPane,
  browserReplayPane,
  setBrowserReplayPane,
  activeOverlay,
  appendAction,
}: UseBrowserIntegrationOptions): UseBrowserIntegrationReturn {
  // ------------------------------------------------------------------
  // runBrowserControlPaneAction
  // ------------------------------------------------------------------

  const runBrowserControlPaneAction = useCallback(
    async (action: BrowserControlAction) => {
      const runningLabel =
        action === 'status'
          ? 'Refreshing browser runtime status...'
          : `Running browser ${action}...`;
      setBrowserControlPane((prev) => ({
        ...prev,
        loading: true,
        message: runningLabel,
        messageStatus: 'running',
        lastAction: action,
      }));

      try {
        const [
          { loadConfig },
          { runBrowserControlAction },
          { readRecentBrowserApprovalEvents },
          { listBrowserProfileDirs, resolveBrowserProfileRetentionPolicy },
        ] = await Promise.all([
          import('../../core/config.js'),
          import('../../browser/control-surface.js'),
          import('../../browser/approval-log.js'),
          import('../../browser/profile-store.js'),
        ]);

        const config = await loadConfig();
        const profilePolicy = resolveBrowserProfileRetentionPolicy({
          retentionDays: config.browser.runtime.profileRetentionDays,
          maxPersistedProfiles: config.browser.runtime.maxPersistedProfiles,
        });
        const [result, approvals, profiles] = await Promise.all([
          runBrowserControlAction(action, config),
          readRecentBrowserApprovalEvents(process.cwd(), 6),
          listBrowserProfileDirs(process.cwd()),
        ]);

        setBrowserControlPane({
          loading: false,
          health: result.health,
          approvals,
          message: result.message,
          messageStatus: result.ok ? 'ok' : 'error',
          lastAction: action,
          profileRetentionDays: profilePolicy.retentionDays,
          profileMaxPersistedProfiles: profilePolicy.maxPersistedProfiles,
          profilePersistedCount: profiles.length,
        });

        if (action !== 'status' || !result.ok) {
          appendAction({
            kind: 'tool',
            status: result.ok ? 'ok' : 'error',
            icon: result.ok ? '🌐' : '⛔',
            label: `Browser ${action}`,
            detail: result.message,
          });
        }
      } catch (err) {
        const { sanitizeTerminalText } = await import('../../utils/text.js');
        const { errorMessage } = await import('../../utils/errors.js');
        const message = sanitizeTerminalText(errorMessage(err));
        setBrowserControlPane((prev) => ({
          ...prev,
          loading: false,
          message: `Browser control failed: ${message}`,
          messageStatus: 'error',
        }));
        appendAction({
          kind: 'error',
          status: 'error',
          icon: '⛔',
          label: 'Browser control failed',
          detail: message.slice(0, 120),
        });
      }
    },
    [appendAction, setBrowserControlPane],
  );

  // ------------------------------------------------------------------
  // pruneBrowserControlProfiles
  // ------------------------------------------------------------------

  const pruneBrowserControlProfiles = useCallback(async () => {
    setBrowserControlPane((prev) => ({
      ...prev,
      loading: true,
      message: 'Pruning persisted browser profiles...',
      messageStatus: 'running',
    }));

    try {
      const [
        { loadConfig },
        { runBrowserControlAction },
        { readRecentBrowserApprovalEvents },
        {
          listBrowserProfileDirs,
          pruneBrowserProfileDirs,
          resolveBrowserProfileRetentionPolicy,
        },
      ] = await Promise.all([
        import('../../core/config.js'),
        import('../../browser/control-surface.js'),
        import('../../browser/approval-log.js'),
        import('../../browser/profile-store.js'),
      ]);

      const config = await loadConfig();
      const policy = resolveBrowserProfileRetentionPolicy({
        retentionDays: config.browser.runtime.profileRetentionDays,
        maxPersistedProfiles: config.browser.runtime.maxPersistedProfiles,
      });
      const pruneResult = await pruneBrowserProfileDirs({
        cwd: process.cwd(),
        policy,
      });
      const [statusResult, approvals, profiles] = await Promise.all([
        runBrowserControlAction('status', config),
        readRecentBrowserApprovalEvents(process.cwd(), 6),
        listBrowserProfileDirs(process.cwd()),
      ]);

      const prunedLabel = pruneResult.pruned.length === 1 ? 'profile' : 'profiles';
      const message =
        pruneResult.pruned.length > 0
          ? `Pruned ${pruneResult.pruned.length} ${prunedLabel}; kept ${pruneResult.kept.length}.`
          : 'No browser profiles matched the prune policy.';

      setBrowserControlPane({
        loading: false,
        health: statusResult.health,
        approvals,
        message,
        messageStatus: pruneResult.pruned.length > 0 ? 'ok' : 'info',
        lastAction: 'status',
        profileRetentionDays: policy.retentionDays,
        profileMaxPersistedProfiles: policy.maxPersistedProfiles,
        profilePersistedCount: profiles.length,
      });

      appendAction({
        kind: 'tool',
        status: pruneResult.pruned.length > 0 ? 'ok' : 'info',
        icon: '🧹',
        label: 'Browser profiles prune',
        detail: `${pruneResult.pruned.length} pruned · ${pruneResult.kept.length} kept`,
      });
    } catch (err) {
      const { sanitizeTerminalText } = await import('../../utils/text.js');
      const { errorMessage } = await import('../../utils/errors.js');
      const message = sanitizeTerminalText(errorMessage(err));
      setBrowserControlPane((prev) => ({
        ...prev,
        loading: false,
        message: `Browser profile prune failed: ${message}`,
        messageStatus: 'error',
      }));
      appendAction({
        kind: 'error',
        status: 'error',
        icon: '⛔',
        label: 'Browser profile prune failed',
        detail: message.slice(0, 120),
      });
    }
  }, [appendAction, setBrowserControlPane]);

  // ------------------------------------------------------------------
  // refreshBrowserControlPane
  // ------------------------------------------------------------------

  const refreshBrowserControlPane = useCallback(async () => {
    await runBrowserControlPaneAction('status');
  }, [runBrowserControlPaneAction]);

  // ------------------------------------------------------------------
  // Browser replay session IDs (derived from pane state)
  // ------------------------------------------------------------------

  const browserReplaySessionIds = useMemo(() => {
    const ids = new Set<string>();
    for (const session of browserControlPane.health?.sessions ?? []) {
      if (session.sessionId) ids.add(session.sessionId);
    }
    for (const approval of browserControlPane.approvals) {
      if (approval.sessionId) ids.add(approval.sessionId);
    }
    if (browserReplayPane.selectedSessionId) ids.add(browserReplayPane.selectedSessionId);
    if (browserReplayPane.metadata?.sessionId) ids.add(browserReplayPane.metadata.sessionId);
    return [...ids].sort((left, right) => left.localeCompare(right));
  }, [
    browserControlPane.approvals,
    browserControlPane.health,
    browserReplayPane.metadata?.sessionId,
    browserReplayPane.selectedSessionId,
  ]);

  // ------------------------------------------------------------------
  // Replay callbacks
  // ------------------------------------------------------------------

  const handleReplaySelectSession = useCallback(
    (sessionId: string) => {
      setBrowserReplayPane((prev) =>
        prev.selectedSessionId === sessionId
          ? prev
          : {
              ...prev,
              selectedSessionId: sessionId,
            },
      );
    },
    [setBrowserReplayPane],
  );

  const handleReplaySelectStep = useCallback(
    (index: number) => {
      setBrowserReplayPane((prev) => {
        const maxIndex = Math.max(prev.steps.length - 1, 0);
        const clamped = Math.min(Math.max(index, 0), maxIndex);
        if (clamped === prev.selectedStepIndex) return prev;
        const step = prev.steps[clamped];
        return {
          ...prev,
          selectedStepIndex: clamped,
          stepPreview: null,
          message: step
            ? `Selected step #${step.sequence} ${step.actionType}.`
            : prev.message,
          messageStatus: 'info',
        };
      });
    },
    [setBrowserReplayPane],
  );

  const handleReplaySelectDiff = useCallback(
    (index: number) => {
      setBrowserReplayPane((prev) => {
        if (prev.visualDiffs.length === 0) return prev;
        const maxIndex = Math.max(prev.visualDiffs.length - 1, 0);
        const clamped = Math.min(Math.max(index, 0), maxIndex);
        if (clamped === prev.selectedDiffIndex) return prev;
        const diff = prev.visualDiffs[clamped];
        return {
          ...prev,
          selectedDiffIndex: clamped,
          message: diff
            ? `Selected diff #${clamped + 1}: #${diff.fromSequence} -> #${diff.toSequence} ${diff.status}.`
            : prev.message,
          messageStatus: 'info',
        };
      });
    },
    [setBrowserReplayPane],
  );

  const handleReplayLoadSession = useCallback(
    async (sessionId: string) => {
      const normalizedSessionId = sessionId.trim();
      if (!normalizedSessionId) return;

      setBrowserReplayPane((prev) => ({
        ...prev,
        loading: true,
        selectedSessionId: normalizedSessionId,
        selectedStepIndex: 0,
        selectedDiffIndex: 0,
        stepPreview: null,
        visualDiffs: [],
        message: `Loading replay for ${normalizedSessionId}...`,
        messageStatus: 'running',
      }));

      try {
        const {
          deriveBrowserReplayVisualDiffPairs,
          readBrowserReplay,
          readBrowserReplayStepArtifactPreview,
          readBrowserReplaySteps,
        } = await import('../../browser/replay.js');
        const [metadata, steps] = await Promise.all([
          readBrowserReplay(process.cwd(), normalizedSessionId),
          readBrowserReplaySteps(process.cwd(), normalizedSessionId),
        ]);
        const [stepPreview, visualDiffs] = await Promise.all([
          steps[0]
            ? readBrowserReplayStepArtifactPreview(
                process.cwd(),
                normalizedSessionId,
                steps[0],
                metadata,
              )
            : Promise.resolve(null),
          deriveBrowserReplayVisualDiffPairs(
            process.cwd(),
            normalizedSessionId,
            steps,
            metadata,
          ),
        ]);
        const hasReplay = Boolean(metadata) || steps.length > 0;
        const stepLabel = steps.length === 1 ? 'step' : 'steps';
        const message =
          steps.length > 0
            ? `Loaded ${steps.length} replay ${stepLabel} for ${normalizedSessionId}.`
            : metadata
              ? `No replay steps found for ${normalizedSessionId}.`
              : `No replay data found for ${normalizedSessionId}.`;

        setBrowserReplayPane((prev) => ({
          ...prev,
          loading: false,
          selectedSessionId: normalizedSessionId,
          metadata,
          steps,
          selectedStepIndex: 0,
          selectedDiffIndex: 0,
          stepPreview,
          visualDiffs,
          message,
          messageStatus: hasReplay ? 'ok' : 'info',
        }));

        appendAction({
          kind: 'info',
          status: hasReplay ? 'ok' : 'info',
          icon: '🎬',
          label: 'Loaded browser replay',
          detail: `${normalizedSessionId} · ${steps.length} step${steps.length === 1 ? '' : 's'}`,
        });
      } catch (err) {
        const { sanitizeTerminalText } = await import('../../utils/text.js');
        const { errorMessage } = await import('../../utils/errors.js');
        const message = sanitizeTerminalText(errorMessage(err));
        setBrowserReplayPane((prev) => ({
          ...prev,
          loading: false,
          message: `Replay load failed: ${message}`,
          messageStatus: 'error',
        }));
        appendAction({
          kind: 'error',
          status: 'error',
          icon: '⛔',
          label: 'Browser replay failed',
          detail: message.slice(0, 120),
        });
      }
    },
    [appendAction, setBrowserReplayPane],
  );

  // ------------------------------------------------------------------
  // Step artifact preview effect
  // ------------------------------------------------------------------

  useEffect(() => {
    const selectedSessionId = browserReplayPane.selectedSessionId;
    const selectedStep = browserReplayPane.steps[browserReplayPane.selectedStepIndex];
    if (!selectedSessionId || !selectedStep) {
      setBrowserReplayPane((prev) =>
        prev.stepPreview === null
          ? prev
          : {
              ...prev,
              stepPreview: null,
            },
      );
      return;
    }

    let cancelled = false;
    void (async () => {
      try {
        const { readBrowserReplayStepArtifactPreview } = await import(
          '../../browser/replay.js'
        );
        const preview = await readBrowserReplayStepArtifactPreview(
          process.cwd(),
          selectedSessionId,
          selectedStep,
          browserReplayPane.metadata,
        );
        if (cancelled) return;
        setBrowserReplayPane((prev) => {
          const currentStep = prev.steps[prev.selectedStepIndex];
          if (!currentStep) return prev;
          if (prev.selectedSessionId !== selectedSessionId) return prev;
          if (currentStep.sequence !== selectedStep.sequence) return prev;
          return {
            ...prev,
            stepPreview: preview,
          };
        });
      } catch {
        if (cancelled) return;
        setBrowserReplayPane((prev) =>
          prev.stepPreview === null
            ? prev
            : {
                ...prev,
                stepPreview: null,
              },
        );
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [
    browserReplayPane.metadata,
    browserReplayPane.selectedSessionId,
    browserReplayPane.selectedStepIndex,
    browserReplayPane.steps,
    setBrowserReplayPane,
  ]);

  // ------------------------------------------------------------------
  // Auto-refresh effects
  // ------------------------------------------------------------------

  useEffect(() => {
    if (activeOverlay !== 'browser-control') return;
    void refreshBrowserControlPane();
  }, [activeOverlay, refreshBrowserControlPane]);

  useEffect(() => {
    if (browserControlPane.health !== null) return;
    void refreshBrowserControlPane();
  }, [browserControlPane.health, refreshBrowserControlPane]);

  // ------------------------------------------------------------------
  // Return
  // ------------------------------------------------------------------

  return {
    runBrowserControlPaneAction,
    pruneBrowserControlProfiles,
    refreshBrowserControlPane,
    browserReplaySessionIds,
    handleReplaySelectSession,
    handleReplaySelectStep,
    handleReplaySelectDiff,
    handleReplayLoadSession,
  };
}

/**
 * useModelSelection — Extracted from App.tsx.
 *
 * Encapsulates model picker open/close, model switch orchestration via LMX,
 * and the context-limit loading side-effect tied to model changes.
 */

import { useCallback, useEffect } from 'react';
import type { ModelSelection } from '../ModelPicker.js';
import type { ActionEventKind, ActionEventStatus } from '../activity.js';
import type { ConnectionState } from '../utils.js';
import type { TuiMessage } from '../App.js';

// ---------------------------------------------------------------------------
// Constants (mirrored from App.tsx to keep the hook self-contained)
// ---------------------------------------------------------------------------

const MODEL_PICKER_CLIENT_TIMEOUT_MS = 60_000;
const MODEL_PICKER_LOAD_TIMEOUT_MS = 300_000;

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Minimal action descriptor accepted by the appendAction helper in App. */
export interface AppendActionEvent {
  kind: ActionEventKind;
  status?: ActionEventStatus;
  icon?: string;
  label: string;
  detail?: string;
}

export interface UseModelSelectionOptions {
  currentModel: string;
  setCurrentModel: (v: string) => void;
  setModelLoaded: (v: boolean) => void;
  setConnectionState: (v: ConnectionState) => void;
  setContextLimit: (v: number) => void;
  connectionHost: string;
  connectionFallbackHosts: string[];
  connectionPort: number;
  connectionAdminKey: string | undefined;
  appendAction: (action: AppendActionEvent) => void;
  setActiveOverlay: (v: 'none' | 'model-picker' | 'help-browser') => void;
  setMessages: React.Dispatch<React.SetStateAction<TuiMessage[]>>;
  permissionPending: unknown;
  toggleOverlay: (overlay: 'model-picker' | 'help-browser') => void;
}

export interface UseModelSelectionReturn {
  handleHelp: () => void;
  handleModelSwitch: () => void;
  handleModelPickerSelect: (selection: ModelSelection) => Promise<void>;
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useModelSelection({
  currentModel,
  setCurrentModel,
  setModelLoaded,
  setConnectionState,
  setContextLimit,
  connectionHost,
  connectionFallbackHosts,
  connectionPort,
  connectionAdminKey,
  appendAction,
  setMessages,
  permissionPending,
  toggleOverlay,
}: UseModelSelectionOptions): UseModelSelectionReturn {
  // Re-derive context limit when model changes
  useEffect(() => {
    import('../../core/models.js')
      .then(({ getContextLimit }) => {
        setContextLimit(getContextLimit(currentModel));
      })
      .catch(() => {});
  }, [currentModel, setContextLimit]);

  const handleHelp = useCallback(() => {
    if (permissionPending) return;
    toggleOverlay('help-browser');
    appendAction({ kind: 'info', status: 'info', icon: '📚', label: 'Opened Help Browser' });
  }, [permissionPending, toggleOverlay, appendAction]);

  const handleModelSwitch = useCallback(() => {
    if (permissionPending) return;
    toggleOverlay('model-picker');
    appendAction({ kind: 'model', status: 'info', icon: '🧬', label: 'Opened Model Picker' });
  }, [permissionPending, toggleOverlay, appendAction]);

  const handleModelPickerSelect = useCallback(
    async (selection: ModelSelection) => {
      appendAction({
        kind: 'model',
        status: 'running',
        icon: '🧬',
        label: 'Switching model',
        detail: selection.id,
      });

      try {
        const [
          { saveConfig },
          { LmxClient, lookupContextLimit },
          { ensureModelLoaded, findMatchingModelId, modelIdsEqual },
        ] = await Promise.all([
          import('../../core/config.js'),
          import('../../lmx/client.js'),
          import('../../lmx/model-lifecycle.js'),
        ]);

        const lmx = new LmxClient({
          host: connectionHost,
          fallbackHosts: connectionFallbackHosts,
          port: connectionPort,
          adminKey: connectionAdminKey,
          timeoutMs: MODEL_PICKER_CLIENT_TIMEOUT_MS,
        });

        let resolvedModel = selection.id;
        const loadedRes = await lmx.models().catch(() => ({ models: [] }));
        const loadedIds = loadedRes.models.map((model) => model.model_id);
        const loadedMatch = findMatchingModelId(selection.id, loadedIds);

        if (loadedMatch) {
          resolvedModel = loadedMatch;
        } else {
          try {
            resolvedModel = await ensureModelLoaded(lmx, selection.id, {
              timeoutMs: MODEL_PICKER_LOAD_TIMEOUT_MS,
            });
          } catch (err) {
            const code = (err as { code?: unknown })?.code;
            if (code === 'out_of_memory') {
              appendAction({
                kind: 'model',
                status: 'running',
                icon: '🧹',
                label: 'Memory pressure',
                detail: 'unloading other models',
              });
              for (const loadedId of loadedIds.filter(
                (id) => !modelIdsEqual(id, selection.id),
              )) {
                await lmx.unloadModel(loadedId).catch(() => null);
              }
              resolvedModel = await ensureModelLoaded(lmx, selection.id, {
                timeoutMs: MODEL_PICKER_LOAD_TIMEOUT_MS,
              });
            } else {
              throw err;
            }
          }
        }

        await saveConfig({
          model: {
            default: resolvedModel,
            contextLimit: lookupContextLimit(resolvedModel),
          },
        });

        setCurrentModel(resolvedModel);
        setModelLoaded(true);
        setConnectionState('connected');
        appendAction({
          kind: 'model',
          status: 'ok',
          icon: '✅',
          label: 'Model ready',
          detail: resolvedModel,
        });
      } catch (err) {
        const { sanitizeTerminalText } = await import('../../utils/text.js');
        const { errorMessage } = await import('../../utils/errors.js');
        const msg = sanitizeTerminalText(errorMessage(err));
        setMessages((prev) => [
          ...prev,
          {
            role: 'error',
            content: `Model switch failed: ${msg}`,
            createdAt: Date.now(),
          },
        ]);

        const lower = msg.toLowerCase();
        if (lower.includes('not loaded') && lower.includes('model')) {
          setModelLoaded(false);
        }

        appendAction({
          kind: 'model',
          status: 'error',
          icon: '⛔',
          label: 'Model switch failed',
          detail: msg.slice(0, 100),
        });
      }
    },
    [
      appendAction,
      connectionAdminKey,
      connectionFallbackHosts,
      connectionHost,
      connectionPort,
      setConnectionState,
      setCurrentModel,
      setMessages,
      setModelLoaded,
    ],
  );

  return {
    handleHelp,
    handleModelSwitch,
    handleModelPickerSelect,
  };
}

import { useState, useCallback, useEffect } from 'react';
import type { ScrollViewHandle } from '../ScrollView.js';
import type { OptaMenuResultEntry } from '../OptaMenuOverlay.js';
import type { ActionEventKind, ActionEventStatus } from '../activity.js';
import type { PermissionRequest } from '../adapter.js';
import type { PermissionDecision } from '../PermissionPrompt.js';
import type { WorkflowMode } from '../App.js';
import { ANIMATION } from '../animations.js';
import { isResponseIntentTone, type ResponseIntentTone } from '../response-intent.js';

const OPTA_MENU_ANIMATION_STEPS: number = ANIMATION.optaMenuSteps;
const OPTA_MENU_ANIMATION_FRAME_MS: number = ANIMATION.optaMenuFrameMs;

/** Ordered cycle of workflow modes (Shift+Tab). */
const WORKFLOW_MODES: WorkflowMode[] = ['normal', 'plan', 'research', 'review'];

export type ActiveOverlay =
  | 'none'
  | 'model-picker'
  | 'command-browser'
  | 'help-browser'
  | 'opta-menu'
  | 'browser-control'
  | 'action-history'
  | 'onboarding'
  | 'settings'
  | 'agent-picker'
  | 'session-browser';

export interface AppendActionEvent {
  kind: ActionEventKind;
  status?: ActionEventStatus;
  icon?: string;
  label: string;
  detail?: string;
}

export interface UseOverlayManagerOptions {
  appendAction: (event: AppendActionEvent) => void;
  scrollRef: React.RefObject<ScrollViewHandle | null>;
  permissionPending:
    | (PermissionRequest & { resolve: (decision: PermissionDecision) => void })
    | null;
  setMessages: React.Dispatch<React.SetStateAction<import('../App.js').TuiMessage[]>>;
  bypassPermissions: boolean;
  setBypassPermissions: React.Dispatch<React.SetStateAction<boolean>>;
  workflowMode: WorkflowMode;
  setWorkflowMode: React.Dispatch<React.SetStateAction<WorkflowMode>>;
  onModeChange?: (mode: WorkflowMode) => void;
  setResponseIntentTone: React.Dispatch<React.SetStateAction<ResponseIntentTone>>;
  onSettingsSave?: (changes: Record<string, unknown>) => void;
}

export interface UseOverlayManagerReturn {
  activeOverlay: ActiveOverlay;
  setActiveOverlay: React.Dispatch<React.SetStateAction<ActiveOverlay>>;
  sidebarVisible: boolean;
  setSidebarVisible: React.Dispatch<React.SetStateAction<boolean>>;
  showAgentPanel: boolean;
  setShowAgentPanel: React.Dispatch<React.SetStateAction<boolean>>;
  followMode: boolean;
  setFollowMode: React.Dispatch<React.SetStateAction<boolean>>;
  safeModeOverride: boolean;
  setSafeModeOverride: React.Dispatch<React.SetStateAction<boolean>>;
  thinkingExpanded: boolean;
  setThinkingExpanded: React.Dispatch<React.SetStateAction<boolean>>;
  /** Whether any overlay is currently active (convenience derived flag). */
  overlayActive: boolean;
  // Animation state
  optaMenuAnimationPhase: 'opening' | 'open' | 'closing';
  optaMenuAnimationFrame: number;
  optaMenuResults: OptaMenuResultEntry[];
  setOptaMenuResults: React.Dispatch<React.SetStateAction<OptaMenuResultEntry[]>>;
  // Toggle callbacks
  handleClear: () => void;
  handleToggleSidebar: () => void;
  handleScrollUp: () => void;
  handleScrollDown: () => void;
  handleExpandThinking: () => void;
  // Menu callbacks
  openOptaMenu: () => void;
  closeOptaMenu: () => void;
  // Overlay control
  closeOverlay: () => void;
  toggleOverlay: (name: Exclude<ActiveOverlay, 'none'>) => void;
  // Open handlers
  handleOpenOptaMenu: () => void;
  handleOpenBrowserControl: () => void;
  handleOpenActionHistory: () => void;
  handleOpenOnboarding: () => void;
  handleOpenSettings: () => void;
  handleOpenAgentPicker: () => void;
  handleOpenSessionBrowser: () => void;
  // Settings/mode handlers
  handleSettingsSave: (changes: Record<string, unknown>) => void;
  handleToggleSafeMode: () => void;
  handleCycleMode: () => void;
  handleToggleBypass: () => void;
  handleToggleFollow: () => void;
}

export function useOverlayManager(options: UseOverlayManagerOptions): UseOverlayManagerReturn {
  const {
    appendAction,
    scrollRef,
    permissionPending,
    setMessages,
    bypassPermissions,
    setBypassPermissions,
    workflowMode: _workflowMode,
    setWorkflowMode,
    onModeChange,
    setResponseIntentTone,
    onSettingsSave,
  } = options;

  // --- Overlay state ---
  const [sidebarVisible, setSidebarVisible] = useState(false);
  const [safeModeOverride, setSafeModeOverride] = useState(false);
  const [thinkingExpanded, setThinkingExpanded] = useState(false);
  const [showAgentPanel, setShowAgentPanel] = useState(false);
  const [activeOverlay, setActiveOverlay] = useState<ActiveOverlay>('none');
  const [followMode, setFollowMode] = useState(true);

  // --- Opta menu animation state ---
  const [optaMenuAnimationPhase, setOptaMenuAnimationPhase] = useState<
    'opening' | 'open' | 'closing'
  >('open');
  const [optaMenuAnimationFrame, setOptaMenuAnimationFrame] =
    useState<number>(OPTA_MENU_ANIMATION_STEPS);
  const [optaMenuResults, setOptaMenuResults] = useState<OptaMenuResultEntry[]>([]);

  const overlayActive = activeOverlay !== 'none';

  // --- Opta menu animation controller (open/close frames) ---
  useEffect(() => {
    if (activeOverlay !== 'opta-menu') {
      if (
        optaMenuAnimationPhase !== 'open' ||
        optaMenuAnimationFrame !== OPTA_MENU_ANIMATION_STEPS
      ) {
        setOptaMenuAnimationPhase('open');
        setOptaMenuAnimationFrame(OPTA_MENU_ANIMATION_STEPS);
      }
      return;
    }

    if (optaMenuAnimationPhase === 'open') {
      return;
    }

    if (
      optaMenuAnimationPhase === 'opening' &&
      optaMenuAnimationFrame >= OPTA_MENU_ANIMATION_STEPS
    ) {
      setOptaMenuAnimationPhase('open');
      return;
    }

    if (optaMenuAnimationPhase === 'closing' && optaMenuAnimationFrame <= 0) {
      setActiveOverlay('none');
      setOptaMenuAnimationPhase('open');
      setOptaMenuAnimationFrame(OPTA_MENU_ANIMATION_STEPS);
      return;
    }

    const delta = optaMenuAnimationPhase === 'opening' ? 1 : -1;
    const timer = setTimeout(() => {
      setOptaMenuAnimationFrame((prev) => {
        const next = prev + delta;
        if (next < 0) return 0;
        if (next > OPTA_MENU_ANIMATION_STEPS) return OPTA_MENU_ANIMATION_STEPS;
        return next;
      });
    }, OPTA_MENU_ANIMATION_FRAME_MS);

    return () => clearTimeout(timer);
  }, [activeOverlay, optaMenuAnimationFrame, optaMenuAnimationPhase]);

  // --- Toggle callbacks ---
  const handleClear = useCallback(() => setMessages([]), [setMessages]);

  const handleToggleSidebar = useCallback(() => {
    setSidebarVisible((prev) => !prev);
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '🧭',
      label: 'Sidebar toggled',
      detail: sidebarVisible ? 'off' : 'on',
    });
  }, [appendAction, sidebarVisible]);

  const handleScrollUp = useCallback(() => scrollRef.current?.scrollBy(-3), [scrollRef]);
  const handleScrollDown = useCallback(() => scrollRef.current?.scrollBy(3), [scrollRef]);
  const handleExpandThinking = useCallback(() => setThinkingExpanded((prev) => !prev), []);

  // --- Menu callbacks ---
  const openOptaMenu = useCallback(() => {
    setActiveOverlay('opta-menu');
    setOptaMenuAnimationFrame(0);
    setOptaMenuAnimationPhase('opening');
  }, []);

  const closeOptaMenu = useCallback(() => {
    setOptaMenuAnimationPhase('closing');
    setOptaMenuAnimationFrame((prev) => {
      if (prev <= 0) return 1;
      return Math.min(prev, OPTA_MENU_ANIMATION_STEPS);
    });
  }, []);

  // --- Overlay control ---
  const closeOverlay = useCallback(() => {
    if (activeOverlay === 'opta-menu') {
      closeOptaMenu();
      return;
    }
    setActiveOverlay('none');
  }, [activeOverlay, closeOptaMenu]);

  const toggleOverlay = useCallback((overlay: Exclude<ActiveOverlay, 'none'>) => {
    setActiveOverlay((prev) => (prev === overlay ? 'none' : overlay));
  }, []);

  // --- Open handlers ---
  const handleOpenOptaMenu = useCallback(() => {
    if (permissionPending) return;
    const opening = activeOverlay !== 'opta-menu' || optaMenuAnimationPhase === 'closing';
    if (opening) {
      openOptaMenu();
    } else {
      closeOptaMenu();
    }
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '🟣',
      label: opening ? 'Opened Opta Menu' : 'Closed Opta Menu',
    });
  }, [
    permissionPending,
    activeOverlay,
    optaMenuAnimationPhase,
    openOptaMenu,
    closeOptaMenu,
    appendAction,
  ]);

  const handleOpenBrowserControl = useCallback(() => {
    if (permissionPending) return;
    const opening = activeOverlay !== 'browser-control';
    toggleOverlay('browser-control');
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '🌐',
      label: opening ? 'Opened Browser Control' : 'Closed Browser Control',
    });
  }, [activeOverlay, permissionPending, toggleOverlay, appendAction]);

  const handleOpenActionHistory = useCallback(() => {
    if (permissionPending) return;
    const opening = activeOverlay !== 'action-history';
    toggleOverlay('action-history');
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '🕘',
      label: opening ? 'Opened Actions History' : 'Closed Actions History',
    });
  }, [activeOverlay, permissionPending, toggleOverlay, appendAction]);

  const handleOpenOnboarding = useCallback(() => {
    if (permissionPending) return;
    const opening = activeOverlay !== 'onboarding';
    toggleOverlay('onboarding');
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '🚀',
      label: opening ? 'Opened Setup Wizard' : 'Closed Setup Wizard',
    });
  }, [activeOverlay, permissionPending, toggleOverlay, appendAction]);

  const handleOpenSettings = useCallback(() => {
    if (permissionPending) return;
    if (activeOverlay === 'settings') return;
    setActiveOverlay('settings');
    appendAction({ kind: 'info', status: 'info', icon: '⚙️', label: 'Opened Settings' });
  }, [activeOverlay, permissionPending, appendAction]);

  const handleOpenAgentPicker = useCallback(() => {
    if (permissionPending) return;
    const opening = activeOverlay !== 'agent-picker';
    toggleOverlay('agent-picker');
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '\uD83E\uDD16',
      label: opening ? 'Opened Agent Picker' : 'Closed Agent Picker',
    });
  }, [activeOverlay, permissionPending, toggleOverlay, appendAction]);

  const handleOpenSessionBrowser = useCallback(() => {
    if (permissionPending) return;
    const opening = activeOverlay !== 'session-browser';
    toggleOverlay('session-browser');
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '\uD83D\uDCCB',
      label: opening ? 'Opened Session Browser' : 'Closed Session Browser',
    });
  }, [activeOverlay, permissionPending, toggleOverlay, appendAction]);

  // --- Settings/mode handlers ---
  const handleSettingsSave = useCallback(
    (changes: Record<string, unknown>) => {
      const toneValue = changes['tui.responseIntentTone'];
      if (isResponseIntentTone(toneValue)) {
        setResponseIntentTone(toneValue);
      }
      if (onSettingsSave) {
        onSettingsSave(changes);
        return;
      }
      import('../../core/config.js')
        .then(({ saveConfig }) => {
          saveConfig(changes).catch(() => {
            /* non-fatal */
          });
        })
        .catch(() => {
          /* ignore */
        });
    },
    [onSettingsSave, setResponseIntentTone]
  );

  const handleToggleSafeMode = useCallback(() => {
    setSafeModeOverride((prev) => !prev);
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '🛡️',
      label: 'Safe mode toggled',
      detail: safeModeOverride ? 'off' : 'on',
    });
  }, [appendAction, safeModeOverride]);

  const handleCycleMode = useCallback(() => {
    setWorkflowMode((prev) => {
      const idx = WORKFLOW_MODES.indexOf(prev);
      const next = WORKFLOW_MODES[(idx + 1) % WORKFLOW_MODES.length]!;
      onModeChange?.(next);
      return next;
    });
  }, [onModeChange, setWorkflowMode]);

  const handleToggleBypass = useCallback(() => {
    setBypassPermissions((prev) => !prev);
    appendAction({
      kind: 'permission',
      status: 'info',
      icon: '⚠️',
      label: 'Permission bypass toggled',
      detail: bypassPermissions ? 'off' : 'on',
    });
  }, [appendAction, bypassPermissions, setBypassPermissions]);

  const handleToggleFollow = useCallback(() => {
    setFollowMode((prev) => !prev);
    appendAction({
      kind: 'info',
      status: 'info',
      icon: '🧲',
      label: 'Auto follow toggled',
      detail: followMode ? 'off' : 'on',
    });
  }, [appendAction, followMode]);

  return {
    activeOverlay,
    setActiveOverlay,
    sidebarVisible,
    setSidebarVisible,
    showAgentPanel,
    setShowAgentPanel,
    followMode,
    setFollowMode,
    safeModeOverride,
    setSafeModeOverride,
    thinkingExpanded,
    setThinkingExpanded,
    overlayActive,
    // Animation state
    optaMenuAnimationPhase,
    optaMenuAnimationFrame,
    optaMenuResults,
    setOptaMenuResults,
    // Toggle callbacks
    handleClear,
    handleToggleSidebar,
    handleScrollUp,
    handleScrollDown,
    handleExpandThinking,
    // Menu callbacks
    openOptaMenu,
    closeOptaMenu,
    // Overlay control
    closeOverlay,
    toggleOverlay,
    // Open handlers
    handleOpenOptaMenu,
    handleOpenBrowserControl,
    handleOpenActionHistory,
    handleOpenOnboarding,
    handleOpenSettings,
    handleOpenAgentPicker,
    handleOpenSessionBrowser,
    // Settings/mode handlers
    handleSettingsSave,
    handleToggleSafeMode,
    handleCycleMode,
    handleToggleBypass,
    handleToggleFollow,
  };
}

import { useEffect, type MutableRefObject } from 'react';
import type { TuiEmitter, TurnStats, PermissionRequest, TuiErrorEvent } from '../adapter.js';
import type { Insight } from '../../core/insights.js';
import type { PermissionDecision } from '../PermissionPrompt.js';
import type { ConnectionState } from '../utils.js';
import type { ActionEventKind, ActionEventStatus } from '../activity.js';
import type { BrowserPendingApprovalItem } from '../BrowserControlOverlay.js';
import type { SubAgentDisplayState, SubAgentProgressEvent } from '../../core/subagent-events.js';
import type { InsightEntry } from '../InsightBlock.js';
import type { ResponseIntentTone } from '../response-intent.js';
import type { TurnActivityItem, TuiMessage } from '../App.js';
import { sanitizeTerminalText, sanitizeTerminalTokenChunk } from '../../utils/text.js';
import { estimateTokens } from '../../utils/tokens.js';
import { extractBrowserSessionId } from '../../browser/approval-log.js';
import { evaluateBrowserPolicyAction } from '../../browser/policy-engine.js';
import {
  deriveResponseIntentOutcome,
  deriveResponseIntentSentence,
} from '../response-intent.js';
import type { DEFAULT_CONFIG } from '../../core/config.js';

/** Helper to normalize error events consistently across structured and string forms. */
function parseStructuredTurnError(message: string): { code?: string; message: string } {
  const match = message.match(/^\[([a-z0-9-]+)\]\s+([\s\S]*)$/i);
  if (!match) return { message };
  return { code: match[1]?.toLowerCase(), message: match[2] ?? '' };
}

function normalizeTurnError(error: TuiErrorEvent): { displayMessage: string; code?: string; message: string } {
  if (typeof error === 'string') {
    const displayMessage = sanitizeTerminalText(error);
    const parsed = parseStructuredTurnError(displayMessage);
    return {
      displayMessage,
      code: parsed.code,
      message: parsed.message,
    };
  }

  const rawMessage = typeof error.message === 'string' && error.message.length > 0
    ? error.message
    : 'Turn failed';
  const displayMessage = sanitizeTerminalText(rawMessage);
  const parsed = parseStructuredTurnError(displayMessage);
  const code = typeof error.code === 'string' && error.code.length > 0
    ? error.code.toLowerCase()
    : parsed.code;
  return {
    displayMessage,
    code,
    message: parsed.message,
  };
}

function isModelNotLoadedError(message: string): boolean {
  const lower = message.toLowerCase();
  return lower.includes('not loaded') && lower.includes('model');
}

function isStructuredModelUnavailableCode(code?: string): boolean {
  return code === 'no-model-loaded';
}

function isStructuredTransportFailureCode(code?: string): boolean {
  return code === 'lmx-ws-closed' || code === 'lmx-timeout' || code === 'lmx-connection-refused';
}

function isTransportFailureError(message: string): boolean {
  if (isModelNotLoadedError(message)) return false;

  const lower = message.toLowerCase();
  const markers = [
    'econnrefused',
    'econnaborted',
    'enotfound',
    'ehostunreach',
    'enetunreach',
    'etimedout',
    'connection refused',
    'connection reset',
    'connection closed',
    'connection timeout',
    'connect timeout',
    'read timeout',
    'network timeout',
    'network error',
    'fetch failed',
    'socket hang up',
    'socket closed',
    'websocket',
    'transport',
    'failed to connect',
    'unable to connect',
  ];

  const patterns = [
    /\bconnection[_\s-]?error\b/,
    /\btimed?\s*out\b/,
    /\btimeout\b/,
  ];

  return markers.some((marker) => lower.includes(marker)) || patterns.some((pattern) => pattern.test(lower));
}

function isBuildErrorFailure(message: string): boolean {
  const lower = message.toLowerCase();
  return (
    lower.includes('cannot find module') ||
    lower.includes('err_module_not_found') ||
    lower.includes('cannot require')
  );
}

export interface UseStreamingEventsOptions {
  emitter: TuiEmitter | null;

  // Refs for accumulating streaming data without re-renders
  currentStreamingTextRef: MutableRefObject<string>;
  liveActivityRef: MutableRefObject<TurnActivityItem[]>;
  thinkingTextRef: MutableRefObject<string>;
  currentTurnPromptRef: MutableRefObject<string>;
  tokenFlushTimerRef: MutableRefObject<ReturnType<typeof setTimeout> | null>;
  tokenRateWindowRef: MutableRefObject<{ startedAt: number; chars: number }>;
  scrollRef: MutableRefObject<{ scrollToBottom(): void } | null>;

  // State setters for session state
  setIsLoading: (v: boolean) => void;
  setLiveActivity: React.Dispatch<React.SetStateAction<TurnActivityItem[]>>;
  setLiveStreamingText: React.Dispatch<React.SetStateAction<string>>;
  setLiveThinkingText: React.Dispatch<React.SetStateAction<string>>;
  setModelLoaded: (v: boolean) => void;
  setConnectionState: (v: ConnectionState) => void;
  setTurnPhase: (v: 'idle' | 'connecting' | 'waiting' | 'streaming' | 'tool-call' | 'done') => void;
  setToolCallCount: React.Dispatch<React.SetStateAction<number>>;
  setTokens: React.Dispatch<React.SetStateAction<number>>;
  setPromptTokens: React.Dispatch<React.SetStateAction<number>>;
  setCompletionTokens: React.Dispatch<React.SetStateAction<number>>;
  setElapsed: (v: number) => void;
  setSpeed: (v: number) => void;
  setFirstTokenLatency: (v: number | null) => void;
  setTurnSpeed: (v: number) => void;
  setTurnCompletionTokens: (v: number) => void;
  setSessionTitle: (v: string | undefined) => void;
  setMessages: React.Dispatch<React.SetStateAction<TuiMessage[]>>;
  setActiveAgents: React.Dispatch<React.SetStateAction<SubAgentDisplayState[]>>;
  setShowAgentPanel: React.Dispatch<React.SetStateAction<boolean>>;
  /** Tracks the Playwright tool name currently executing for the browser active-state indicator. */
  setActiveBrowserTool: React.Dispatch<React.SetStateAction<string | undefined>>;

  // State setters for UI chrome
  setStreamingLabel: (v: string) => void;
  setStatusActionLabel: (v: string) => void;
  setStatusActionIcon: (v: string) => void;
  setStatusActionStatus: (v: ActionEventStatus) => void;

  // State setters for insights
  setInsights: React.Dispatch<React.SetStateAction<InsightEntry[]>>;
  maxInsights: number;

  // State setters for permissions
  setPermissionPending: React.Dispatch<
    React.SetStateAction<(PermissionRequest & { resolve: (decision: PermissionDecision) => void }) | null>
  >;
  setPendingBrowserApprovals: React.Dispatch<React.SetStateAction<BrowserPendingApprovalItem[]>>;
  setAlwaysMessage: (v: string | null) => void;

  // Callbacks
  flushStreamingTextNow: () => void;
  scheduleTokenFlush: () => void;
  appendAction: (event: {
    kind: ActionEventKind;
    status?: ActionEventStatus;
    icon?: string;
    label: string;
    detail?: string;
  }) => void;
  summarizeToolArgs: (args?: Record<string, unknown>) => string | undefined;

  // Config values read during event handling
  browserPolicyConfig: typeof DEFAULT_CONFIG.browser.policy;
  responseIntentTone: ResponseIntentTone;
}

/**
 * Wires all TuiEmitter event listeners that drive the streaming agent loop
 * display. Attaches on mount (when emitter is present) and tears down on
 * unmount or when dependencies change.
 */
export function useStreamingEvents(options: UseStreamingEventsOptions): void {
  const {
    emitter,
    currentStreamingTextRef,
    liveActivityRef,
    thinkingTextRef,
    currentTurnPromptRef,
    tokenFlushTimerRef,
    tokenRateWindowRef,
    scrollRef,
    setIsLoading,
    setLiveActivity,
    setLiveStreamingText,
    setLiveThinkingText,
    setModelLoaded,
    setConnectionState,
    setTurnPhase,
    setToolCallCount,
    setTokens,
    setPromptTokens,
    setCompletionTokens,
    setElapsed,
    setSpeed,
    setFirstTokenLatency,
    setTurnSpeed,
    setTurnCompletionTokens,
    setSessionTitle,
    setMessages,
    setActiveAgents,
    setShowAgentPanel,
    setActiveBrowserTool,
    setStreamingLabel,
    setStatusActionLabel,
    setStatusActionIcon,
    setStatusActionStatus,
    setInsights,
    maxInsights,
    setPermissionPending,
    setPendingBrowserApprovals,
    setAlwaysMessage,
    flushStreamingTextNow,
    scheduleTokenFlush,
    appendAction,
    summarizeToolArgs,
    browserPolicyConfig,
    responseIntentTone,
  } = options;

  useEffect(() => {
    if (!emitter) return;

    // Track whether first token has been received this turn (for phase transition)
    let firstTokenReceived = false;
    let thinkingAnnounced = false;

    const onToken = (text: string) => {
      const safeText = sanitizeTerminalTokenChunk(text);
      if (!safeText) return;
      if (!firstTokenReceived) {
        firstTokenReceived = true;
        setModelLoaded(true);
        setConnectionState('connected');
        setTurnPhase('streaming');
        setStatusActionLabel('Streaming response');
        setStatusActionIcon('✍️');
        setStatusActionStatus('running');
      }
      currentStreamingTextRef.current += safeText;
      tokenRateWindowRef.current.chars += safeText.length;
      const windowAge = Date.now() - tokenRateWindowRef.current.startedAt;
      if (windowAge >= 500) {
        tokenRateWindowRef.current = { startedAt: Date.now(), chars: safeText.length };
      }

      if (safeText.includes('\n')) {
        flushStreamingTextNow();
      } else {
        scheduleTokenFlush();
      }
    };

    const onToolStart = (name: string, id: string, argsJson: string) => {
      flushStreamingTextNow();
      if (name.startsWith('browser_')) setActiveBrowserTool(name);
      setStreamingLabel(`running ${name}`);
      setTurnPhase('tool-call');
      let parsedArgs: Record<string, unknown> | undefined;
      try {
        parsedArgs = JSON.parse(argsJson) as Record<string, unknown>;
      } catch {
        // args may not be valid JSON
      }
      const item: TurnActivityItem = {
        type: 'tool',
        toolName: name,
        toolId: id,
        toolStatus: 'running',
        toolArgs: parsedArgs,
      };
      liveActivityRef.current = [...liveActivityRef.current, item];
      setLiveActivity([...liveActivityRef.current]);
      appendAction({
        kind: 'tool',
        status: 'running',
        icon: '🛠️',
        label: `Tool started: ${name}`,
        detail: summarizeToolArgs(parsedArgs),
      });
    };

    const onToolEnd = (name: string, id: string, result: string) => {
      flushStreamingTextNow();
      if (name.startsWith('browser_')) setActiveBrowserTool(undefined);
      setStreamingLabel('thinking');
      setTurnPhase('streaming');
      const failed = result.toLowerCase().includes('error') || result.toLowerCase().includes('failed');
      liveActivityRef.current = liveActivityRef.current.map(item =>
        item.type === 'tool' && item.toolId === id
          ? { ...item, toolStatus: failed ? 'error' as const : 'done' as const }
          : item
      );
      setLiveActivity([...liveActivityRef.current]);
      setToolCallCount(prev => prev + 1);
      appendAction({
        kind: 'tool',
        status: failed ? 'error' : 'ok',
        icon: failed ? '❌' : '✅',
        label: `Tool finished: ${name}`,
        detail: failed ? 'reported error' : 'ok',
      });
    };

    const onThinking = (text: string) => {
      const safeText = sanitizeTerminalTokenChunk(text);
      if (!safeText) return;
      thinkingTextRef.current += safeText;
      const nextThinking = thinkingTextRef.current;
      setLiveThinkingText((prev) => (prev === nextThinking ? prev : nextThinking));
      setStreamingLabel('thinking deeply');
      if (!thinkingAnnounced) {
        thinkingAnnounced = true;
        appendAction({
          kind: 'thinking',
          status: 'running',
          icon: '💭',
          label: 'Thinking deeply',
        });
      }
    };

    const onTurnStart = () => {
      setIsLoading(true);
      setActiveBrowserTool(undefined);
      liveActivityRef.current = [];
      setLiveActivity([]);
      currentStreamingTextRef.current = '';
      setLiveStreamingText('');
      thinkingTextRef.current = '';
      setLiveThinkingText('');
      firstTokenReceived = false;
      tokenRateWindowRef.current = { startedAt: Date.now(), chars: 0 };
      if (tokenFlushTimerRef.current) {
        clearTimeout(tokenFlushTimerRef.current);
        tokenFlushTimerRef.current = null;
      }
      setStreamingLabel('thinking');
      setTurnPhase('waiting');
      setFirstTokenLatency(null);
      setTurnCompletionTokens(0);
      setTurnSpeed(0);
      setInsights([]);
      thinkingAnnounced = false;
      appendAction({
        kind: 'turn',
        status: 'running',
        icon: '🧠',
        label: 'Turn started',
      });
    };

    const onTurnEnd = (stats: TurnStats) => {
      setIsLoading(false);
      setModelLoaded(true);
      setConnectionState('connected');
      setTurnPhase('done');
      setTimeout(() => setTurnPhase('idle'), 2000);

      flushStreamingTextNow();

      const finalText = currentStreamingTextRef.current;
      const finalThinking = thinkingTextRef.current;
      const toolsUsed = liveActivityRef.current.filter(a => a.type === 'tool');
      const failedToolCalls = toolsUsed.filter((tool) => tool.toolStatus === 'error').length;
      const completionTok = Math.max(
        stats.completionTokens,
        finalText ? estimateTokens(finalText) : 0,
      );
      const tokensPerSecond = stats.elapsed > 0 ? (completionTok / stats.elapsed) : 0;
      const intentOutcome = deriveResponseIntentOutcome({
        toolCallCount: toolsUsed.length,
        failedToolCallCount: failedToolCalls,
        hasVisibleOutput: finalText.trim().length > 0,
      });
      const promptIntent = deriveResponseIntentSentence({
        promptText: currentTurnPromptRef.current,
        tone: responseIntentTone,
        toolCallCount: toolsUsed.length,
        failedToolCallCount: failedToolCalls,
        hasVisibleOutput: finalText.trim().length > 0,
      });

      // Collapse live state into permanent messages (chronological order):
      // 1. Activity summary line (dim, lists tool calls + elapsed)
      // 2. Assistant response in purple box
      const newMessages: TuiMessage[] = [];

      if (toolsUsed.length > 0) {
        const byTool = new Map<string, { total: number; failed: number }>();
        for (const tool of toolsUsed) {
          const name = tool.toolName ?? 'tool';
          const prev = byTool.get(name) ?? { total: 0, failed: 0 };
          prev.total += 1;
          if (tool.toolStatus === 'error') prev.failed += 1;
          byTool.set(name, prev);
        }
        const parts = [...byTool.entries()].map(([name, info]) =>
          info.failed > 0
            ? `${name}\u00D7${info.total} (${info.failed} failed)`
            : `${name}\u00D7${info.total}`,
        );
        const suffix = failedToolCalls > 0 ? ` \u00B7 ${failedToolCalls} failed` : '';
        newMessages.push({
          role: 'activity-summary',
          content: `\u25C7 ${parts.join(' \u00B7 ')}  ${stats.elapsed.toFixed(1)}s${suffix}`,
        });
      }

      if (finalText || finalThinking) {
        const thinkTokens = finalThinking ? estimateTokens(finalThinking) : 0;
        newMessages.push({
          role: 'assistant',
          content: finalText,
          createdAt: Date.now(),
          responseMeta: {
            elapsedSec: stats.elapsed,
            tokensPerSecond,
            intent: promptIntent,
            intentTone: responseIntentTone,
            intentOutcome,
          },
          ...(finalThinking ? { thinking: { text: finalThinking, tokens: thinkTokens } } : {}),
          ...(toolsUsed.length > 0 ? { toolCalls: toolsUsed.length } : {}),
        });
      }

      if (newMessages.length > 0) {
        setMessages(prev => [...prev, ...newMessages]);
        // Scroll to bottom so new messages are visible
        setTimeout(() => scrollRef.current?.scrollToBottom(), 0);
      }

      // Clear live state
      setLiveActivity([]);
      setLiveStreamingText('');
      setLiveThinkingText('');
      currentStreamingTextRef.current = '';
      liveActivityRef.current = [];
      thinkingTextRef.current = '';
      currentTurnPromptRef.current = '';
      if (tokenFlushTimerRef.current) {
        clearTimeout(tokenFlushTimerRef.current);
        tokenFlushTimerRef.current = null;
      }

      setTokens(prev => prev + stats.tokens);
      setCompletionTokens(prev => prev + stats.completionTokens);
      setPromptTokens(prev => prev + stats.promptTokens);
      setElapsed(stats.elapsed);
      setSpeed(stats.speed);
      if (stats.firstTokenLatencyMs !== null) {
        setFirstTokenLatency(stats.firstTokenLatencyMs);
      }
      appendAction({
        kind: 'turn',
        status: 'ok',
        icon: '✅',
        label: 'Turn completed',
        detail: `${stats.elapsed.toFixed(1)}s \u00B7 ${stats.completionTokens} tok`,
      });
    };

    const onError = (error: TuiErrorEvent) => {
      setIsLoading(false);
      setTurnPhase('idle');
      // Clear any partial live state so it doesn't linger
      setLiveActivity([]);
      setLiveStreamingText('');
      setLiveThinkingText('');
      currentStreamingTextRef.current = '';
      liveActivityRef.current = [];
      thinkingTextRef.current = '';
      currentTurnPromptRef.current = '';
      if (tokenFlushTimerRef.current) {
        clearTimeout(tokenFlushTimerRef.current);
        tokenFlushTimerRef.current = null;
      }
      const normalizedError = normalizeTurnError(error);
      const modelNotLoaded = isStructuredModelUnavailableCode(normalizedError.code)
        || isModelNotLoadedError(normalizedError.message);
      const transportFailure = isStructuredTransportFailureCode(normalizedError.code)
        || isTransportFailureError(normalizedError.message);
      const buildFailure = isBuildErrorFailure(normalizedError.message);
      if (modelNotLoaded || transportFailure || buildFailure) {
        setModelLoaded(false);
      }
      if (modelNotLoaded || transportFailure || buildFailure) {
        setConnectionState('error');
      }
      setMessages(prev => [...prev, { role: 'error', content: normalizedError.displayMessage, createdAt: Date.now() }]);
      appendAction({
        kind: 'error',
        status: 'error',
        icon: '⛔',
        label: 'Turn error',
        detail: normalizedError.displayMessage.slice(0, 120),
      });
    };

    const onTitle = (title: string) => {
      setSessionTitle(title);
    };

    const onInsight = (insight: Insight) => {
      setInsights(prev => {
        const next = [...prev, insight];
        return next.length > maxInsights ? next.slice(-maxInsights) : next;
      });
    };

    const onConnectionStatus = (status: 'checking' | 'connected' | 'disconnected' | 'error' | 'reconnecting') => {
      setConnectionState(status);
      if (status === 'connected') {
        setModelLoaded(true);
      } else if (status === 'disconnected' || status === 'error' || status === 'reconnecting') {
        setModelLoaded(false);
      }
      if (status === 'disconnected' || status === 'error' || status === 'reconnecting') {
        appendAction({
          kind: 'info',
          status: status === 'error' ? 'error' : 'running',
          icon: status === 'error' ? '🚨' : '🔌',
          label: `Connection ${status}`,
        });
      }
    };

    const onFirstToken = (latencyMs: number) => {
      setFirstTokenLatency(latencyMs);
      appendAction({
        kind: 'turn',
        status: 'running',
        icon: '⚡',
        label: 'First token',
        detail: `${latencyMs}ms`,
      });
    };

    const onTurnProgress = (stats: { elapsed: number; speed: number; completionTokens: number }) => {
      setTurnSpeed(stats.speed);
      setTurnCompletionTokens(stats.completionTokens);
    };

    const onPermissionRequest = (request: PermissionRequest) => {
      flushStreamingTextNow();
      const isBrowserPermission = request.toolName.startsWith('browser_');
      const browserDecision = isBrowserPermission
        ? evaluateBrowserPolicyAction(browserPolicyConfig, {
          toolName: request.toolName,
          args: request.args,
        })
        : null;
      const requestedAt = new Date().toISOString();

      if (browserDecision) {
        const pendingItem: BrowserPendingApprovalItem = {
          requestId: request.id,
          toolName: request.toolName,
          sessionId: extractBrowserSessionId(request.args),
          requestedAt,
          risk: browserDecision.risk,
          actionKey: browserDecision.actionKey,
          targetHost: browserDecision.targetHost,
          targetOrigin: browserDecision.targetOrigin,
          policyReason: browserDecision.reason,
          riskEvidence: browserDecision.riskEvidence,
        };
        setPendingBrowserApprovals((prev) => [
          ...prev.filter((entry) => entry.requestId !== request.id),
          pendingItem,
        ]);
      }

      // Create a Promise-based bridge: the resolve function is stored in state
      // so the PermissionPrompt component can call it when the user decides.
      setPermissionPending({
        ...request,
        resolve: (decision: PermissionDecision) => {
          // Send the response back to the adapter (which unblocks the agent loop)
          emitter.emit('permission:response', request.id, decision);
          setPermissionPending(null);
          setPendingBrowserApprovals((prev) =>
            prev.filter((entry) => entry.requestId !== request.id),
          );

          // If "always" was chosen, persist the permission and show confirmation
          if (decision === 'always') {
            setAlwaysMessage(`${request.toolName} set to always allow`);
            // Clear the confirmation after 3 seconds
            setTimeout(() => setAlwaysMessage(null), 3000);
            // Persist to config asynchronously
            import('../../core/config.js').then(({ saveConfig }) => {
              saveConfig({ [`permissions.${request.toolName}`]: 'allow' }).catch(() => {
                // Config save failed — non-fatal
              });
            }).catch(() => {});
          }
        },
      });
      appendAction({
        kind: 'permission',
        status: 'running',
        icon: '🔐',
        label: `Permission requested: ${request.toolName}${browserDecision ? ` (${browserDecision.risk})` : ''}`,
      });
    };

    const onSubAgentSpawn = (state: SubAgentDisplayState) => {
      setActiveAgents(prev => [...prev.filter(a => a.id !== state.id), state]);
      setShowAgentPanel(true);
    };

    const onSubAgentProgress = (event: SubAgentProgressEvent) => {
      setActiveAgents(prev => prev.map(a =>
        a.id === event.agentId
          ? {
              ...a,
              phase: event.phase,
              currentTool: event.toolName,
              toolCallCount: event.toolCallCount,
              toolHistory: [...(a.toolHistory ?? []).slice(-4), ...(event.toolName ? [event.toolName] : [])],
            }
          : a
      ));
    };

    const onSubAgentDone = (agentId: string, result: string) => {
      setActiveAgents(prev => prev.map(a => a.id === agentId ? { ...a, phase: 'done' as const, result } : a));
      setTimeout(() => {
        setActiveAgents(prev => {
          const remaining = prev.filter(a => a.id !== agentId);
          if (remaining.length === 0) setShowAgentPanel(false);
          return remaining;
        });
      }, 3000);
    };

    emitter.on('token', onToken);
    emitter.on('tool:start', onToolStart);
    emitter.on('tool:end', onToolEnd);
    emitter.on('thinking', onThinking);
    emitter.on('turn:start', onTurnStart);
    emitter.on('turn:end', onTurnEnd);
    emitter.on('turn:first-token', onFirstToken);
    emitter.on('turn:progress', onTurnProgress);
    emitter.on('connection:status', onConnectionStatus);
    emitter.on('error', onError);
    emitter.on('permission:request', onPermissionRequest);
    emitter.on('title', onTitle);
    emitter.on('insight', onInsight);
    emitter.on('subagent:spawn', onSubAgentSpawn);
    emitter.on('subagent:progress', onSubAgentProgress);
    emitter.on('subagent:done', onSubAgentDone);

    return () => {
      emitter.off('token', onToken);
      emitter.off('tool:start', onToolStart);
      emitter.off('tool:end', onToolEnd);
      emitter.off('thinking', onThinking);
      emitter.off('turn:start', onTurnStart);
      emitter.off('turn:end', onTurnEnd);
      emitter.off('turn:first-token', onFirstToken);
      emitter.off('turn:progress', onTurnProgress);
      emitter.off('connection:status', onConnectionStatus);
      emitter.off('error', onError);
      emitter.off('permission:request', onPermissionRequest);
      emitter.off('title', onTitle);
      emitter.off('insight', onInsight);
      emitter.off('subagent:spawn', onSubAgentSpawn);
      emitter.off('subagent:progress', onSubAgentProgress);
      emitter.off('subagent:done', onSubAgentDone);
    };
  }, [emitter, flushStreamingTextNow, scheduleTokenFlush, appendAction, summarizeToolArgs, browserPolicyConfig, responseIntentTone, setActiveAgents, setActiveBrowserTool]);
}

import { useCallback, useEffect, useRef } from 'react';
import type { TuiMessage, WorkflowMode, SlashCommandResult } from '../App.js';
import type { ResponseIntentTone } from '../response-intent.js';
import type { TriggerModeDefinition } from '../trigger-router.js';
import type { ActiveOverlay } from './useOverlayManager.js';
import type { OptaMenuResultEntry } from '../OptaMenuOverlay.js';
import type { ActionEventKind, ActionEventStatus } from '../activity.js';
import { deriveResponseIntentOutcome, deriveResponseIntentSentence } from '../response-intent.js';
import { resolveTriggerRouting } from '../trigger-router.js';
import { SkillRuntime } from '../skill-runtime.js';
import { sanitizeTerminalText, trimDisplayTail } from '../../utils/text.js';
import { errorMessage } from '../../utils/errors.js';
import { estimateTokens } from '../../utils/tokens.js';

export interface SubmitResult {
  ok: boolean;
  kind: 'noop' | 'slash' | 'shell' | 'prompt';
  command?: string;
  summary: string;
  output?: string;
  error?: string;
}

interface SkillRuntimeSettings {
  dynamicLoading: boolean;
  unloadInactive: boolean;
  ttlMinutes: number;
  maxActiveSkills: number;
}

const MAX_OPTA_MENU_RESULTS = 32;

export interface UseSubmitHandlerOptions {
  appendAction: (event: {
    kind: ActionEventKind;
    status?: ActionEventStatus;
    icon?: string;
    label: string;
    detail?: string;
  }) => void;
  exit: () => void;
  isStreamingMode: boolean;
  modelLoaded: boolean;
  onMessage?: (text: string) => Promise<string>;
  onModeChange?: (mode: WorkflowMode) => void;
  onSlashCommand?: (input: string) => Promise<SlashCommandResult>;
  onSubmit?: (text: string) => void;
  requireLoadedModel: boolean;
  setWorkflowMode: React.Dispatch<React.SetStateAction<WorkflowMode>>;
  skillRuntimeSettings: SkillRuntimeSettings;
  triggerDefinitions: TriggerModeDefinition[];
  workflowMode: WorkflowMode;
  responseIntentTone: ResponseIntentTone;
  setActiveOverlay: (overlay: ActiveOverlay) => void;
  setMessages: React.Dispatch<React.SetStateAction<TuiMessage[]>>;
  setCurrentModel: (model: string) => void;
  setAutonomyLevel: (level: number) => void;
  setAutonomyMode: (mode: 'execution' | 'ceo') => void;
  setIsLoading: (loading: boolean) => void;
  setTurnPhase: (phase: 'done' | 'idle' | 'connecting' | 'waiting' | 'streaming' | 'tool-call') => void;
  setElapsed: (elapsed: number) => void;
  currentTurnPromptRef: React.MutableRefObject<string>;
  setOptaMenuResults: React.Dispatch<React.SetStateAction<OptaMenuResultEntry[]>>;
  emitter: unknown;
}

export interface UseSubmitHandlerReturn {
  handleSubmit: (text: string) => Promise<SubmitResult>;
  handleOptaMenuRunCommand: (command: string) => Promise<void>;
  upsertOptaMenuResult: (entry: OptaMenuResultEntry) => void;
}

export function useSubmitHandler(options: UseSubmitHandlerOptions): UseSubmitHandlerReturn {
  const {
    appendAction,
    exit,
    isStreamingMode,
    modelLoaded,
    onMessage,
    onModeChange,
    onSlashCommand,
    onSubmit,
    requireLoadedModel,
    setWorkflowMode,
    skillRuntimeSettings,
    triggerDefinitions,
    workflowMode,
    responseIntentTone,
    setActiveOverlay,
    setMessages,
    setCurrentModel,
    setAutonomyLevel,
    setAutonomyMode,
    setIsLoading,
    setTurnPhase,
    setElapsed,
    currentTurnPromptRef,
    setOptaMenuResults,
    emitter,
  } = options;

  const lastBrowserSessionIdRef = useRef<string | null>(null);
  const skillRuntimeRef = useRef<SkillRuntime>(new SkillRuntime());
  const optaMenuResultCounterRef = useRef(0);

  // Connection check on mount
  useEffect(() => {
    if (!emitter) return;
    import('../adapter.js').then(({ checkConnection: check }) => {
      void check;
    }).catch(() => {});
  }, [emitter]);

  const handleSubmit = useCallback(async (text: string): Promise<SubmitResult> => {
    const trimmed = text.trim();

    // Bare `/` opens the TUI command browser overlay instead of the inquirer-based browser
    if (trimmed === '/') {
      setActiveOverlay('command-browser');
      appendAction({ kind: 'slash', status: 'info', icon: '\u{1F9E9}', label: 'Opened Command Browser' });
      return {
        ok: true,
        kind: 'noop',
        summary: 'Opened command browser',
      };
    }

    // Route slash commands through the registry
    if (trimmed.startsWith('/')) {
      appendAction({ kind: 'slash', status: 'running', icon: '\u{1F9E9}', label: `Slash command: ${trimmed}` });
      if (onSlashCommand) {
        try {
          const cmdResult = await onSlashCommand(trimmed);

          // Show captured output as a system message
          const displayOutput = trimDisplayTail(sanitizeTerminalText(cmdResult.output));
          if (displayOutput.length > 0) {
            setMessages(prev => [...prev, { role: 'system', content: displayOutput, createdAt: Date.now() }]);
          }

          if (cmdResult.result === 'exit') {
            exit();
            return {
              ok: true,
              kind: 'slash',
              command: trimmed,
              summary: `Slash complete: ${trimmed}`,
              output: displayOutput,
            };
          }
          if (cmdResult.result === 'model-switched' && cmdResult.newModel) {
            setCurrentModel(cmdResult.newModel);
            appendAction({
              kind: 'model',
              status: 'ok',
              icon: '\u{1F9EC}',
              label: 'Model switched',
              detail: cmdResult.newModel,
            });
          }

          try {
            const { loadConfig } = await import('../../core/config.js');
            const refreshed = await loadConfig();
            setAutonomyLevel(refreshed.autonomy.level);
            setAutonomyMode(refreshed.autonomy.mode);
          } catch {
            // Non-fatal: keep current UI state if config refresh fails.
          }

          appendAction({ kind: 'slash', status: 'ok', icon: '\u2705', label: `Slash complete: ${trimmed}` });
          return {
            ok: true,
            kind: 'slash',
            command: trimmed,
            summary: `Slash complete: ${trimmed}`,
            output: displayOutput,
          };
        } catch {
          setMessages(prev => [...prev, { role: 'error', content: `Slash command failed: ${trimmed}`, createdAt: Date.now() }]);
          appendAction({ kind: 'slash', status: 'error', icon: '\u274C', label: `Slash failed: ${trimmed}` });
          return {
            ok: false,
            kind: 'slash',
            command: trimmed,
            summary: `Slash failed: ${trimmed}`,
            error: `Slash command failed: ${trimmed}`,
          };
        }
      }

      // Fallback: handle /exit and /quit directly if no onSlashCommand callback
      if (trimmed === '/exit' || trimmed === '/quit') {
        exit();
        return {
          ok: true,
          kind: 'slash',
          command: trimmed,
          summary: `Slash complete: ${trimmed}`,
        };
      }
    }

    // Shell command execution: !command runs asynchronously to avoid blocking TUI rendering.
    if (trimmed.startsWith('!')) {
      const cmd = trimmed.slice(1).trim();
      if (!cmd) {
        return {
          ok: true,
          kind: 'noop',
          command: trimmed,
          summary: 'Skipped empty shell command',
        };
      }
      appendAction({ kind: 'tool', status: 'running', icon: '\u{1F4BB}', label: `Shell: ${cmd}` });

      setMessages(prev => [...prev, { role: 'user', content: trimmed, createdAt: Date.now() }]);

      try {
        const { execa } = await import('execa');
        const { shellArgs } = await import('../../platform/index.js');
        const [shell, shellFlag] = shellArgs();
        const proc = await execa(shell, [shellFlag, cmd], {
          cwd: process.cwd(),
          timeout: 30000,
          reject: false,
        });
        const parts: string[] = [`$ ${cmd}`];
        if (proc.stdout?.trim()) parts.push(proc.stdout.trim());
        if (proc.stderr?.trim()) parts.push(`[stderr] ${proc.stderr.trim()}`);
        parts.push(proc.exitCode === 0 ? '\u2714 exit 0' : `\u2718 exit ${proc.exitCode}`);
        const result = parts.join('\n');
        setMessages(prev => [...prev, { role: 'system', content: sanitizeTerminalText(result), createdAt: Date.now() }]);
        const ok = proc.exitCode === 0;
        appendAction({ kind: 'tool', status: ok ? 'ok' : 'error', icon: ok ? '\u2705' : '\u274C', label: `Shell finished: ${cmd}` });
        return {
          ok,
          kind: 'shell',
          command: trimmed,
          summary: ok ? `Shell finished: ${cmd}` : `Shell failed: ${cmd}`,
          output: sanitizeTerminalText(result),
        };
      } catch (err: unknown) {
        const e = err as { status?: number; stderr?: string; stdout?: string };
        const parts: string[] = [`$ ${cmd}`];
        if (e.stdout) parts.push(e.stdout.trim());
        if (e.stderr) parts.push(e.stderr.trim());
        parts.push(`\u2718 exit ${e.status ?? 1}`);
        const errorOutput = sanitizeTerminalText(parts.join('\n'));
        setMessages(prev => [...prev, { role: 'error', content: errorOutput, createdAt: Date.now() }]);
        appendAction({ kind: 'tool', status: 'error', icon: '\u274C', label: `Shell failed: ${cmd}` });
        return {
          ok: false,
          kind: 'shell',
          command: trimmed,
          summary: `Shell failed: ${cmd}`,
          output: errorOutput,
          error: `Shell failed: ${cmd}`,
        };
      }
    }

    if (requireLoadedModel && !modelLoaded) {
      const note = 'No Model Loaded - Use Opta Menu to begin (Shift+Space \u2192 Model Manager).';
      setMessages(prev => [...prev, { role: 'error', content: note, createdAt: Date.now() }]);
      appendAction({
        kind: 'error',
        status: 'error',
        icon: '\u{1F6D1}',
        label: 'Blocked prompt',
        detail: 'model not loaded',
      });
      return {
        ok: false,
        kind: 'prompt',
        summary: 'Prompt blocked: model not loaded',
        error: note,
      };
    }

    const routing = resolveTriggerRouting({
      prompt: text,
      currentMode: workflowMode,
      definitions: triggerDefinitions,
    });
    const effectiveMode = routing.effectiveMode;

    if (effectiveMode !== workflowMode) {
      setWorkflowMode(effectiveMode);
      onModeChange?.(effectiveMode);
      appendAction({
        kind: 'info',
        status: 'info',
        icon: '\u{1F9ED}',
        label: `Mode auto-shifted to ${effectiveMode}`,
        detail: `triggered by ${routing.matchedWords.join(', ')}`,
      });
    }

    const skillSync = skillRuntimeSettings.dynamicLoading
      ? skillRuntimeRef.current.reconcile(routing.requestedSkills, {
          unloadInactive: skillRuntimeSettings.unloadInactive,
          ttlMs: skillRuntimeSettings.ttlMinutes * 60_000,
          maxActiveSkills: skillRuntimeSettings.maxActiveSkills,
        })
      : skillRuntimeRef.current.reconcile(routing.requestedSkills, {
          unloadInactive: false,
          ttlMs: skillRuntimeSettings.ttlMinutes * 60_000,
          maxActiveSkills: skillRuntimeSettings.maxActiveSkills,
        });

    if (skillSync.loaded.length > 0 || skillSync.unloaded.length > 0 || skillSync.expired.length > 0) {
      const segments: string[] = [];
      if (skillSync.loaded.length > 0) segments.push(`+${skillSync.loaded.length} loaded`);
      if (skillSync.unloaded.length > 0) segments.push(`-${skillSync.unloaded.length} unloaded`);
      if (skillSync.expired.length > 0) segments.push(`${skillSync.expired.length} expired`);
      appendAction({
        kind: 'info',
        status: 'info',
        icon: '\u{1F9F0}',
        label: 'Skill runtime updated',
        detail: segments.join(' \u00B7 '),
      });
    }

    // Check for @image references and show indicator
    const imagePattern = /@\S+\.(png|jpg|jpeg|gif|webp)/gi;
    const imageMatches = [...text.matchAll(imagePattern)];
    const hasImages = imageMatches.length > 0;
    currentTurnPromptRef.current = text;
    let outboundText = text;
    let triggerRouterStatusMessage: TuiMessage | null = null;
    let browserTriggerStatusMessage: TuiMessage | null = null;
    const activeSkills = skillSync.activeSkills;

    if (routing.matchedWords.length > 0) {
      const matched = routing.matchedWords.join(', ');
      const capabilitySummary = routing.requestedCapabilities.length > 0
        ? routing.requestedCapabilities.join(', ')
        : 'none';
      const skillSummary = activeSkills.length > 0
        ? activeSkills.join(', ')
        : 'none';

      triggerRouterStatusMessage = {
        role: 'system',
        content: `Trigger stack matched: ${matched}. Effective mode: ${effectiveMode}. Capabilities: ${capabilitySummary}. Active skills: ${skillSummary}.`,
        createdAt: Date.now(),
      };

      outboundText = `${outboundText}\n\n[System: Trigger router resolved mode "${effectiveMode}". Matched triggers: ${matched}. Active capabilities: ${capabilitySummary}. Active skills: ${skillSummary}.]`;
    }

    const browserCapabilityRequested = routing.requestedCapabilities.includes('browser');
    if (browserCapabilityRequested) {
      try {
        const [{ loadConfig }, { ensureBrowserSessionForTriggeredPrompt }] = await Promise.all([
          import('../../core/config.js'),
          import('../../browser/trigger-session.js'),
        ]);
        const config = await loadConfig();
        const ensured = await ensureBrowserSessionForTriggeredPrompt({
          prompt: text,
          config,
          preferredSessionId: lastBrowserSessionIdRef.current ?? undefined,
        });

        if (ensured.triggered && ensured.ok && ensured.sessionId) {
          lastBrowserSessionIdRef.current = ensured.sessionId;
          const sessionMode = ensured.mode ?? config.browser.mode;
          const actionLabel = ensured.reused
            ? `Reusing Opta Browser session ${ensured.sessionId}`
            : `Started Opta Browser session ${ensured.sessionId}`;
          appendAction({
            kind: 'tool',
            status: 'ok',
            icon: '\u{1F310}',
            label: actionLabel,
            detail: `mode=${sessionMode}`,
          });
          browserTriggerStatusMessage = {
            role: 'system',
            content: ensured.reused
              ? `Browser trigger detected: continuing active Opta Browser session ${ensured.sessionId} (${sessionMode}).`
              : `Browser trigger detected: started active Opta Browser session ${ensured.sessionId} (${sessionMode}).`,
            createdAt: Date.now(),
          };
          outboundText = `${outboundText}\n\n[System: Browser trigger is active. Use browser session_id "${ensured.sessionId}" for browser_navigate/browser_click/browser_type/browser_snapshot/browser_screenshot. A visible Opta Browser session is already active.]`;
        } else if (ensured.triggered && !ensured.ok) {
          appendAction({
            kind: 'tool',
            status: 'error',
            icon: '\u26A0\uFE0F',
            label: 'Browser trigger preflight failed',
            detail: ensured.message.slice(0, 100),
          });
          browserTriggerStatusMessage = {
            role: 'error',
            content: ensured.message,
            createdAt: Date.now(),
          };
        }
      } catch (err) {
        const message = `Browser trigger preflight failed: ${sanitizeTerminalText(errorMessage(err))}`;
        appendAction({
          kind: 'tool',
          status: 'error',
          icon: '\u26A0\uFE0F',
          label: 'Browser trigger preflight failed',
          detail: message.slice(0, 100),
        });
        browserTriggerStatusMessage = {
          role: 'error',
          content: message,
          createdAt: Date.now(),
        };
      }
    }

    setMessages((prev) => {
      const next = [...prev, {
        role: 'user',
        content: text,
        createdAt: Date.now(),
        ...(hasImages ? { imageCount: imageMatches.length } : {}),
      } as TuiMessage];
      if (triggerRouterStatusMessage) {
        next.push(triggerRouterStatusMessage);
      }
      if (browserTriggerStatusMessage) {
        next.push(browserTriggerStatusMessage);
      }
      return next;
    });

    if (isStreamingMode && onSubmit) {
      // Streaming mode: emitter events will update messages
      setIsLoading(true);
      setTurnPhase('waiting');
      onSubmit(outboundText);
    } else if (onMessage) {
      // Legacy mode: wait for full response
      setIsLoading(true);
      const startTime = Date.now();
      const response = await onMessage(outboundText);
      const elapsedSec = (Date.now() - startTime) / 1000;
      const safeResponse = sanitizeTerminalText(response);
      const respCompletionTokens = estimateTokens(safeResponse);
      const tokensPerSecond = elapsedSec > 0 ? (respCompletionTokens / elapsedSec) : 0;
      const intentOutcome = deriveResponseIntentOutcome({
        toolCallCount: 0,
        failedToolCallCount: 0,
        hasVisibleOutput: safeResponse.trim().length > 0,
      });
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: safeResponse,
        createdAt: Date.now(),
        responseMeta: {
          elapsedSec,
          tokensPerSecond,
          intent: deriveResponseIntentSentence({
            promptText: currentTurnPromptRef.current || text,
            tone: responseIntentTone,
            toolCallCount: 0,
            failedToolCallCount: 0,
            hasVisibleOutput: safeResponse.trim().length > 0,
          }),
          intentTone: responseIntentTone,
          intentOutcome,
        },
      }]);
      currentTurnPromptRef.current = '';
      setElapsed(elapsedSec);
      setIsLoading(false);
    }
    return {
      ok: true,
      kind: 'prompt',
      summary: 'Prompt submitted',
    };
  }, [
    appendAction,
    exit,
    isStreamingMode,
    modelLoaded,
    onMessage,
    onModeChange,
    onSlashCommand,
    onSubmit,
    requireLoadedModel,
    setWorkflowMode,
    skillRuntimeSettings,
    triggerDefinitions,
    workflowMode,
    responseIntentTone,
  ]);

  const upsertOptaMenuResult = useCallback((entry: OptaMenuResultEntry) => {
    setOptaMenuResults((prev) => {
      const next = [entry, ...prev.filter((item) => item.id !== entry.id)];
      next.sort((a, b) => b.at - a.at);
      return next.slice(0, MAX_OPTA_MENU_RESULTS);
    });
  }, [setOptaMenuResults]);

  const handleOptaMenuRunCommand = useCallback(async (command: string) => {
    const compactCommand = command.replace(/\s+/g, ' ').trim();
    const resultId = `menu-${Date.now()}-${++optaMenuResultCounterRef.current}`;
    upsertOptaMenuResult({
      id: resultId,
      at: Date.now(),
      command,
      status: 'running',
      summary: `Running ${compactCommand.slice(0, 48)}`,
    });

    const result = await handleSubmit(command);
    const normalizedOutput = result.output
      ? trimDisplayTail(sanitizeTerminalText(result.output))
      : '';
    const firstOutputLine = normalizedOutput
      .split('\n')
      .map((line) => line.trim())
      .find((line) => line.length > 0);
    const summaryBase = result.summary.replace(/\s+/g, ' ').trim();
    const outputSuffix = firstOutputLine ? ` \u00B7 ${firstOutputLine}` : '';
    const summary = `${summaryBase}${outputSuffix}`.slice(0, 120);

    upsertOptaMenuResult({
      id: resultId,
      at: Date.now(),
      command,
      status: result.ok ? 'ok' : 'error',
      summary,
      outputSnippet: normalizedOutput ? normalizedOutput.slice(0, 900) : undefined,
    });
  }, [handleSubmit, upsertOptaMenuResult]);

  return {
    handleSubmit,
    handleOptaMenuRunCommand,
    upsertOptaMenuResult,
  };
}

import type { GuidedFlowKind, StudioConnectivityState } from './types.js';

export function labelWithState(base: string, enabled: boolean): string {
  return `${base} (${enabled ? 'on' : 'off'})`;
}

export function connectivityLabel(state: StudioConnectivityState): string {
  if (state === 'reachable') return 'reachable';
  if (state === 'unreachable') return 'unreachable';
  if (state === 'local') return 'local-only';
  return 'checking';
}

export function autonomyLabel(level: number, mode: 'execution' | 'ceo'): string {
  return `L${level}/5 · profile ${mode}`;
}

export function autonomySlider(levelInput: number): string {
  const level = Math.min(5, Math.max(1, Math.floor(levelInput)));
  return `[${'■'.repeat(level)}${'□'.repeat(5 - level)}]`;
}

export function guidedFlowPrompt(kind: GuidedFlowKind): { title: string; placeholder: string; destructive: boolean } {
  if (kind === 'agent-status') {
    return { title: 'Agent run status', placeholder: 'Enter run id (e.g. run_abc123)', destructive: false };
  }
  if (kind === 'agent-start') {
    return { title: 'Start agent run', placeholder: 'Enter prompt text', destructive: false };
  }
  if (kind === 'agent-events') {
    return { title: 'Agent run events', placeholder: 'Enter run id (e.g. run_abc123)', destructive: false };
  }
  if (kind === 'agent-cancel') {
    return { title: 'Cancel agent run', placeholder: 'Enter run id to cancel', destructive: true };
  }
  if (kind === 'skill-show') {
    return { title: 'Skill detail', placeholder: 'Enter skill name/reference', destructive: false };
  }
  if (kind === 'skill-run') {
    return { title: 'Run skill', placeholder: 'Enter skill name (e.g. ai26-3c-productivity-writing-plans)', destructive: false };
  }
  if (kind === 'skill-mcp-call') {
    return { title: 'Call MCP tool', placeholder: 'Enter MCP tool name (e.g. linear.search_issues)', destructive: true };
  }
  if (kind === 'skill-openclaw') {
    return { title: 'Invoke OpenClaw tool', placeholder: 'Enter OpenClaw tool name', destructive: true };
  }
  if (kind === 'quantize-status') {
    return { title: 'Quantize job status', placeholder: 'Enter quantize job id', destructive: false };
  }
  if (kind === 'rag-query') {
    return { title: 'RAG query', placeholder: 'Enter: collection | query text', destructive: false };
  }
  if (kind === 'rag-ingest-file') {
    return { title: 'RAG ingest (file path)', placeholder: 'Enter: collection | /path/to/text-file', destructive: false };
  }
  if (kind === 'rag-context') {
    return { title: 'RAG context', placeholder: 'Enter: query text | collection1,collection2', destructive: false };
  }
  return { title: 'Delete RAG collection', placeholder: 'Enter collection name to delete', destructive: true };
}

export function quoteCliArg(value: string): string {
  return JSON.stringify(value);
}

export function parseGuidedPair(value: string): { first: string; second: string } | null {
  const delimiterIndex = value.indexOf('|');
  if (delimiterIndex < 0) return null;
  const first = value.slice(0, delimiterIndex).trim();
  const second = value.slice(delimiterIndex + 1).trim();
  if (!first || !second) return null;
  return { first, second };
}

export function buildGuidedCommand(kind: GuidedFlowKind, value: string): string | null {
  const trimmed = value.trim();
  if (!trimmed) return null;
  if (kind === 'agent-status') return `/agents status ${trimmed}`;
  if (kind === 'agent-start') return `/agents start --prompt ${quoteCliArg(trimmed)}`;
  if (kind === 'agent-events') return `/agents events ${trimmed}`;
  if (kind === 'agent-cancel') return `/agents cancel ${trimmed}`;
  if (kind === 'skill-show') return `/lmx-skills show ${trimmed}`;
  if (kind === 'skill-run') return `/lmx-skills run ${trimmed}`;
  if (kind === 'skill-mcp-call') return `/lmx-skills mcp-call ${trimmed}`;
  if (kind === 'skill-openclaw') return `/lmx-skills openclaw ${trimmed}`;
  if (kind === 'quantize-status') return `/quantize status ${trimmed}`;
  if (kind === 'rag-query') {
    const pair = parseGuidedPair(trimmed);
    if (!pair) return null;
    return `/rag query ${pair.first} ${quoteCliArg(pair.second)}`;
  }
  if (kind === 'rag-ingest-file') {
    const pair = parseGuidedPair(trimmed);
    if (!pair) return null;
    return `/rag ingest ${pair.first} --file ${quoteCliArg(pair.second)}`;
  }
  if (kind === 'rag-context') {
    const pair = parseGuidedPair(trimmed);
    if (!pair) return null;
    const collections = pair.second
      .split(',')
      .map((entry) => entry.trim())
      .filter(Boolean)
      .join(',');
    if (!collections) return null;
    return `/rag context ${quoteCliArg(pair.first)} --collections ${collections}`;
  }
  if (kind === 'rag-delete') return `/rag delete ${trimmed}`;
  return null;
}

import fg from 'fast-glob';
import { DEFAULT_IGNORE_GLOBS } from '../utils/ignore.js';

export function fuzzyMatch(query: string, target: string): boolean {
  return target.toLowerCase().includes(query.toLowerCase());
}

export function getCompletions(query: string, files: string[], limit = 15): string[] {
  return files
    .filter(f => fuzzyMatch(query, f))
    .sort((a, b) => {
      const aBase = a.split('/').pop()!.toLowerCase();
      const bBase = b.split('/').pop()!.toLowerCase();
      const q = query.toLowerCase();
      // Prioritize basename-starts-with matches
      const aStart = aBase.startsWith(q) ? 0 : 1;
      const bStart = bBase.startsWith(q) ? 0 : 1;
      if (aStart !== bStart) return aStart - bStart;
      // Then by path length (shorter = more relevant)
      return a.length - b.length;
    })
    .slice(0, limit);
}

export async function getProjectFiles(cwd: string): Promise<string[]> {
  return fg(['**/*'], {
    cwd,
    ignore: [...DEFAULT_IGNORE_GLOBS],
    onlyFiles: true,
    dot: false,
  });
}

/**
 * Get slash command completions for TAB completion in the REPL.
 * Returns matching slash commands (with leading /) for a partial input.
 */
export function getSlashCompletions(partial: string): string[] {
  // Lazy-import the command registry to avoid circular deps at module level.
  // getAllCommands is synchronous so we can use a cached reference.
  if (!_slashCommandsCache) {
    try {

      // Dynamic import is async, so we populate the cache on first call
      // and return empty on the very first invocation (edge case).
      _populateSlashCache();
      // Return empty on first call while cache is loading
      if (!_slashCommandsCache) return [];
    } catch (err) {
      console.error('Failed to get slash completions:', err);
      return [];
    }
  }

  const q = partial.startsWith('/') ? partial.slice(1).toLowerCase() : partial.toLowerCase();

  return _slashCommandsCache
    .filter(entry => entry.startsWith(q))
    .map(name => `/${name}`)
    .slice(0, 10);
}

/** Cached list of slash command names + aliases (lowercase). */
let _slashCommandsCache: string[] | null = null;

/** Eagerly populate the slash command cache. Safe to call multiple times. */
function _populateSlashCache(): void {
  // The slash command registry uses static imports and is available synchronously
  // once its module has been loaded. Since chat.ts already imports it, by the time
  // TAB completion runs in the REPL the module is warm.
  try {
    // Use a sync require-like trick: the module is already in the ESM cache
    // because chat.ts imported it. We rely on the caller having awaited the
    // async version at least once before calling getSlashCompletions.
    // This is handled by initSlashCompletionCache() below.
  } catch (err) {
    console.error('Failed to populate slash cache:', err);
  }
}

/**
 * Initialize the slash command completion cache. Must be called once
 * (asynchronously) before getSlashCompletions will return results.
 * Typically called during chat startup.
 */
export async function initSlashCompletionCache(): Promise<void> {
  try {
    const { getAllCommands } = await import('../commands/slash/index.js');
    const cmds = getAllCommands();
    const names: string[] = [];
    for (const cmd of cmds) {
      names.push(cmd.command);
      if (cmd.aliases) {
        for (const alias of cmd.aliases) {
          names.push(alias);
        }
      }
    }
    _slashCommandsCache = [...new Set(names)].sort();
  } catch (err) {
    console.error('Failed to initialize slash completion cache:', err);
    _slashCommandsCache = [];
  }
}

/**
 * REPL-level completer function suitable for use with readline.
 * Handles slash command completion and @file completion.
 */
export function replCompleter(
  line: string,
  callback: (err: null | Error, result: [string[], string]) => void,
): void {
  if (line.startsWith('/')) {
    const completions = getSlashCompletions(line);
    callback(null, [completions.length > 0 ? completions : [line], line]);
    return;
  }

  // @file completion
  const atMatch = line.match(/@(\S*)$/);
  if (atMatch) {
    const partial = atMatch[1] ?? '';
    getProjectFiles(process.cwd())
      .then(files => {
        const matches = getCompletions(partial, files, 10).map(f => line.slice(0, -atMatch[0].length) + `@${f}`);
        callback(null, [matches.length > 0 ? matches : [line], line]);
      })
      .catch((err: unknown) => {
        console.error('Failed to get project files for completion:', err);
        callback(null, [[], line]);
      });
    return;
  }

  // No completions
  callback(null, [[], line]);
}

import chalk from 'chalk';
import { getTheme } from './theme.js';
import { formatTokens } from '../utils/tokens.js';
import { stripAnsi, visibleTextWidth } from '../utils/text.js';
import { padToWidth } from '../utils/terminal-layout.js';

// --- Box Drawing ---

const BOX = { tl: '┌', tr: '┐', bl: '└', br: '┘', h: '─', v: '│', ml: '├', mr: '┤' };

/**
 * Render a bordered box with a title and content lines.
 * Width auto-sizes to the longest line (min 40), capped at terminal width.
 */
export function box(title: string, lines: string[], { width: fixedWidth }: { width?: number } = {}): string {
  const titleLen = visibleTextWidth(title);
  const maxContent = Math.max(...lines.map(l => visibleTextWidth(stripAnsi(l))), 0);
  const reportedWidth = (process.stdout.columns && process.stdout.columns > 0)
    ? process.stdout.columns
    : Number(process.env.COLUMNS || 0) || 0;
  const termWidth = reportedWidth >= 20 ? reportedWidth : 80;
  const maxWidth = Math.max(10, termWidth - 4);
  const requestedWidth = fixedWidth ?? Math.max(maxContent + 4, titleLen + 6, 40);
  const width = Math.max(10, Math.min(requestedWidth, maxWidth));
  const inner = width - 2;

  const out: string[] = [];
  // Top border with title (uses theme primary for title accent)
  const theme = getTheme();
  const borderColor = chalk.hex(theme.colors.border);
  const titlePart = title ? ` ${title} ` : '';
  const topFill = inner - visibleTextWidth(titlePart);
  out.push(
    borderColor(BOX.tl) +
    theme.primary.bold(titlePart) +
    borderColor(padToWidth('', Math.max(topFill, 0), BOX.h) + BOX.tr),
  );

  // Content lines
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]!;
    const fitted = padToWidth(line, Math.max(inner - 1, 0));
    out.push(borderColor(BOX.v) + ' ' + fitted + borderColor(BOX.v));
  }

  // Bottom border
  out.push(borderColor(BOX.bl + padToWidth('', inner, BOX.h) + BOX.br));

  return out.join('\n');
}

/**
 * Render a horizontal divider with optional label.
 */
export function divider(label?: string, width = 40): string {
  const borderColor = chalk.hex(getTheme().colors.border);
  if (!label) return borderColor(padToWidth('', width, BOX.h));
  const fill = width - visibleTextWidth(label) - 2;
  return borderColor(BOX.ml + BOX.h) + chalk.dim(` ${label} `) + borderColor(padToWidth('', Math.max(fill - 3, 0), BOX.h) + BOX.mr);
}

// --- Progress Bar ---

/**
 * Render a visual progress bar.
 * progressBar(0.41, 20) → "████████░░░░░░░░░░░░ 41%"
 */
export function progressBar(ratio: number, width = 20): string {
  const clamped = Math.max(0, Math.min(1, ratio));
  const filled = Math.round(clamped * width);
  const empty = width - filled;
  const pct = Math.round(clamped * 100);

  const theme = getTheme();
  const bar = theme.info('█'.repeat(filled)) + chalk.hex(theme.colors.border)('░'.repeat(empty));
  const color = pct > 85 ? theme.error : pct > 70 ? theme.warning : chalk.dim;
  return `${bar} ${color(`${pct}%`)}`;
}

// --- Formatting Helpers ---

/**
 * Format a token count with K suffix.
 * @deprecated Use `formatTokens` from `../utils/tokens.js` directly.
 */
export const fmtTokens = formatTokens;

/**
 * Right-pad a label to align values.
 * kv('Model', 'Qwen2.5-72B', 10) → "Model:    Qwen2.5-72B"
 */
export function kv(key: string, value: string, keyWidth = 10): string {
  const pad = Math.max(keyWidth - key.length, 0);
  return chalk.dim(key + ':') + ' '.repeat(pad + 1) + value;
}

/**
 * Status dot indicator.
 */
export function statusDot(ok: boolean): string {
  const theme = getTheme();
  return ok ? theme.success('●') : theme.error('●');
}

export class InputHistory {
  private entries: string[] = [];
  private index = -1;
  private maxSize: number;

  constructor(maxSize = 100) {
    this.maxSize = maxSize;
  }

  push(entry: string): void {
    const trimmed = entry.trim();
    if (!trimmed) return;
    // Deduplicate consecutive entries
    if (this.entries.length > 0 && this.entries[this.entries.length - 1] === trimmed) return;
    this.entries.push(trimmed);
    if (this.entries.length > this.maxSize) this.entries.shift();
    this.index = -1;
  }

  startNavigation(): void {
    this.index = this.entries.length;
  }

  previous(): string {
    if (this.entries.length === 0) return '';
    if (this.index > 0) this.index--;
    return this.entries[this.index] ?? '';
  }

  next(): string {
    if (this.entries.length === 0) return '';
    if (this.index < this.entries.length - 1) {
      this.index++;
      return this.entries[this.index]!;
    }
    this.index = this.entries.length;
    return '';
  }

  size(): number {
    return this.entries.length;
  }
}

import chalk from 'chalk';
import { probeLmxConnection } from '../lmx/connection.js';
import { resolveLmxEndpoint } from '../lmx/endpoints.js';
import { errorMessage } from '../utils/errors.js';

// --- Connection Status Indicator ---

let connectionStatus: 'connected' | 'degraded' | 'disconnected' = 'disconnected';
let connectionStatusDetail = '';
let connectionCheckInterval: ReturnType<typeof setInterval> | null = null;

export function getConnectionStatus(): 'connected' | 'degraded' | 'disconnected' {
  return connectionStatus;
}

export function getConnectionStatusDetail(): string {
  return connectionStatusDetail;
}

export function getConnectionDot(): string {
  switch (connectionStatus) {
    case 'connected':
      return chalk.green('\u25cf');
    case 'degraded':
      return chalk.yellow('\u25cf');
    case 'disconnected':
      return chalk.red('\u25cf');
  }
}

export async function checkConnection(
  host: string,
  port: number,
  fallbackHosts: string[] = [],
  adminKey?: string,
  adminKeysByHost: Record<string, string> = {}
): Promise<void> {
  try {
    const endpoint = await resolveLmxEndpoint(
      {
        host,
        fallbackHosts,
        port,
        adminKey,
        adminKeysByHost,
      },
      { timeoutMs: 1000 }
    );
    const result = await probeLmxConnection(endpoint.host, port, {
      timeoutMs: 2000,
      adminKey,
      adminKeysByHost,
    });
    if (result.state === 'connected') {
      connectionStatus = 'connected';
      connectionStatusDetail = '';
    } else if (result.state === 'degraded') {
      connectionStatus = 'degraded';
      connectionStatusDetail = result.reason ? result.reason : 'LMX reachable but not ready';
    } else {
      connectionStatus = 'disconnected';
      connectionStatusDetail = result.reason ? result.reason : 'LMX disconnected';
    }
  } catch (err) {
    // Connection failed - set status to disconnected
    // Log details for debugging if in verbose mode
    if (process.env.OPTA_DEBUG) {
      console.error('Connection check failed:', err);
    }
    connectionStatus = 'disconnected';
    connectionStatusDetail = errorMessage(err);
  }
}

/**
 * Start periodic connection checks (every 60s).
 * Returns a cleanup function to stop the interval.
 */
export function startConnectionMonitor(
  host: string,
  port: number,
  fallbackHosts: string[] = [],
  adminKey?: string,
  adminKeysByHost: Record<string, string> = {}
): () => void {
  // Run initial check immediately
  checkConnection(host, port, fallbackHosts, adminKey, adminKeysByHost).catch((err: unknown) => {
    if (process.env.OPTA_DEBUG) {
      console.error('Initial connection check failed:', err);
    }
  });

  // Set up periodic checks
  connectionCheckInterval = setInterval(() => {
    checkConnection(host, port, fallbackHosts, adminKey, adminKeysByHost).catch((err: unknown) => {
      if (process.env.OPTA_DEBUG) {
        console.error('Periodic connection check failed:', err);
      }
    });
  }, 60_000);

  return () => {
    if (connectionCheckInterval) {
      clearInterval(connectionCheckInterval);
      connectionCheckInterval = null;
    }
  };
}

// --- Input Editor ---

export interface InputEditorOptions {
  prompt: string;
  multiline?: boolean;
  mode?: 'normal' | 'shell' | 'plan' | 'auto';
}

export class InputEditor {
  private buffer = '';
  private cursor = 0;
  private options: Required<InputEditorOptions>;

  constructor(options: InputEditorOptions) {
    this.options = {
      prompt: options.prompt,
      multiline: options.multiline ?? false,
      mode: options.mode ?? 'normal',
    };
  }

  getBuffer(): string {
    return this.buffer;
  }

  getCursor(): number {
    return this.cursor;
  }

  setBuffer(text: string): void {
    this.buffer = text;
    this.cursor = text.length;
  }

  deleteBackward(): void {
    if (this.cursor === 0) return;
    this.buffer = this.buffer.slice(0, this.cursor - 1) + this.buffer.slice(this.cursor);
    this.cursor--;
  }

  deleteForward(): void {
    if (this.cursor >= this.buffer.length) return;
    this.buffer = this.buffer.slice(0, this.cursor) + this.buffer.slice(this.cursor + 1);
  }

  moveLeft(): void {
    if (this.cursor > 0) this.cursor--;
  }

  moveRight(): void {
    if (this.cursor < this.buffer.length) this.cursor++;
  }

  moveToStart(): void {
    // Move to start of current line
    const before = this.buffer.slice(0, this.cursor);
    const lastNewline = before.lastIndexOf('\n');
    this.cursor = lastNewline + 1;
  }

  moveToEnd(): void {
    // Move to end of current line
    const after = this.buffer.indexOf('\n', this.cursor);
    this.cursor = after === -1 ? this.buffer.length : after;
  }

  insertText(text: string): void {
    this.buffer = this.buffer.slice(0, this.cursor) + text + this.buffer.slice(this.cursor);
    this.cursor += text.length;
  }

  clear(): void {
    this.buffer = '';
    this.cursor = 0;
  }

  insertNewline(): void {
    if (!this.options.multiline) return;
    this.buffer = this.buffer.slice(0, this.cursor) + '\n' + this.buffer.slice(this.cursor);
    this.cursor += 1;
  }

  getLineCount(): number {
    return this.buffer.split('\n').length;
  }

  getCursorLine(): number {
    return this.buffer.slice(0, this.cursor).split('\n').length - 1;
  }

  getCursorCol(): number {
    const lines = this.buffer.slice(0, this.cursor).split('\n');
    return lines[lines.length - 1]!.length;
  }

  isShellMode(): boolean {
    return this.buffer.startsWith('!');
  }

  getShellCommand(): string | null {
    if (!this.isShellMode()) return null;
    return this.buffer.slice(1).trim();
  }

  private cancelled = false;

  handleEscape(): void {
    if (this.buffer.length > 0) {
      this.clear();
    } else {
      this.cancelled = true;
    }
  }

  shouldCancel(): boolean {
    return this.cancelled;
  }

  resetCancel(): void {
    this.cancelled = false;
  }

  private pastedContent: string | null = null;

  handlePaste(text: string): {
    isPaste: boolean;
    lineCount: number;
    abbreviated: string;
    fullContent: string;
  } {
    const lines = text.split('\n');
    const isPaste = lines.length > 1;

    if (isPaste) {
      this.pastedContent = text;
      const abbreviated = `[Pasted ~${lines.length} lines]`;
      this.insertText(abbreviated);
      return { isPaste: true, lineCount: lines.length, abbreviated, fullContent: text };
    }

    this.insertText(text);
    return { isPaste: false, lineCount: 1, abbreviated: text, fullContent: text };
  }

  getSubmitText(): string {
    if (this.pastedContent) {
      return this.buffer.replace(/\[Pasted ~\d+ lines\]/, this.pastedContent);
    }
    return this.buffer;
  }

  setMode(mode: InputEditorOptions['mode']): void {
    this.options.mode = mode ?? 'normal';
  }

  getEffectiveMode(): string {
    if (this.isShellMode()) return 'shell';
    return this.options.mode;
  }

  getPromptDisplay(): string {
    const dot = getConnectionDot();
    const detail = getConnectionStatusDetail();
    const detailSuffix =
      detail && getConnectionStatus() !== 'connected' ? chalk.dim(` (${detail.slice(0, 40)})`) : '';
    const mode = this.getEffectiveMode();
    switch (mode) {
      case 'shell':
        return `${dot} ${chalk.yellow('!')}${chalk.dim(' >')}${detailSuffix}`;
      case 'plan':
        return `${dot} ${chalk.magenta('plan')}${chalk.dim(' >')}${detailSuffix}`;
      case 'auto':
        return `${dot} ${chalk.yellow('auto')}${chalk.dim(' >')}${detailSuffix}`;
      default:
        return `${dot} ${chalk.cyan('>')}${detailSuffix}`;
    }
  }
}

import chalk from 'chalk';
import { isTTY } from './output.js';
import { visibleTextWidth } from '../utils/text.js';
import { fitTextToWidth } from '../utils/terminal-layout.js';

let renderer: ((md: string) => string) | null = null;
let rendererBackend: 'plain' | 'marked-terminal' = 'plain';

function isTableSeparator(line: string): boolean {
  const t = line.trim();
  return /^\|?\s*:?-{3,}:?\s*(\|\s*:?-{3,}:?\s*)+\|?$/.test(t);
}

function splitTableRow(line: string): string[] {
  const trimmed = line.trim().replace(/^\|/, '').replace(/\|$/, '');
  return trimmed.split('|').map((c) => c.trim());
}

function formatTableBlock(lines: string[], width: number): string[] {
  if (lines.length < 2 || !isTableSeparator(lines[1]!)) return lines;
  const rows = lines.map(splitTableRow);
  const colCount = Math.max(...rows.map((r) => r.length));
  const normalized = rows.map((r) => [...r, ...Array(Math.max(0, colCount - r.length)).fill('')]);

  const maxTotal = Math.max(20, width - 6);
  const baseCol = Math.max(4, Math.floor(maxTotal / colCount) - 3);
  const colWidths = Array.from({ length: colCount }, (_, i) =>
    Math.min(baseCol, Math.max(4, ...normalized.map((r) => visibleTextWidth(String(r[i] ?? '')))))
  );

  const render = (cells: string[]) =>
    `| ${cells.map((c, i) => fitTextToWidth(c, colWidths[i]!, { pad: true })).join(' | ')} |`;
  const rule = `|-${colWidths.map((w) => '-'.repeat(w)).join('-|-')}-|`;

  const out: string[] = [];
  out.push(render(normalized[0]!));
  out.push(rule);
  for (let i = 2; i < normalized.length; i++) out.push(render(normalized[i]!));
  return out;
}

/**
 * Format markdown pipe tables into aligned plain-text tables for terminal readability.
 */
export function formatMarkdownTables(text: string, width = 100): string {
  if (!text.includes('|')) return text;
  const lines = text.split('\n');
  const out: string[] = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]!;
    const next = lines[i + 1];
    if (line.includes('|') && next && isTableSeparator(next)) {
      const block: string[] = [line, next];
      i += 2;
      while (i < lines.length && lines[i]!.includes('|')) {
        block.push(lines[i]!);
        i++;
      }
      i -= 1;
      out.push(...formatTableBlock(block, width));
    } else {
      out.push(line);
    }
  }

  return out.join('\n');
}

function setPlainRenderer(): (md: string) => string {
  renderer = (md: string) => md;
  rendererBackend = 'plain';
  return renderer;
}

async function getRenderer(): Promise<(md: string) => string> {
  if (renderer) return renderer;

  if (!isTTY) {
    return setPlainRenderer();
  }

  try {
    const { Marked } = await import('marked');
    const { markedTerminal } = await import('marked-terminal');
    const { initShiki, highlightCodeAnsiSync } = await import('./shiki-highlighter.js');
    await initShiki();

    const marked = new Marked(
      markedTerminal({
        code: chalk.hex('#F59E0B'),
        codespan: chalk.hex('#F59E0B').bold,
        firstHeading: chalk.hex('#8B5CF6').bold.underline,
        heading: chalk.hex('#3B82F6').bold,
        strong: chalk.bold,
        em: chalk.italic,
        del: chalk.dim.strikethrough,
        blockquote: chalk.hex('#71717A').italic,
        link: chalk.hex('#3B82F6').underline,
        href: chalk.hex('#3B82F6').underline,
        listitem: chalk.reset,
        table: chalk.reset,
        hr: chalk.dim,
        paragraph: chalk.reset,
        html: chalk.dim,
        width: 100,
        reflowText: false,
        showSectionPrefix: false,
        unescape: true,
        emoji: true,
        tab: 2,
      })
    );

    // Override the code block renderer to use Shiki
    marked.use({
      renderer: {
        code(token: { text: string; lang?: string }) {
          const lang = token.lang || 'text';
          const highlighted = highlightCodeAnsiSync(token.text, lang);
          const lines = highlighted.split('\n');
          const indented = lines.map(l => '  ' + l).join('\n');
          return '\n' + indented + '\n\n';
        }
      }
    });

    renderer = (md: string) => {
      try {
        const result = marked.parse(md, { async: false });
        return typeof result === 'string' ? result : String(result);
      } catch {
        setPlainRenderer();
        return md;
      }
    };
    rendererBackend = 'marked-terminal';
    return renderer;
  } catch {
    return setPlainRenderer();
  }
}

/**
 * Render markdown text to the terminal via stdout.
 */
export async function renderMarkdown(text: string): Promise<void> {
  if (!text?.trim()) return;
  try {
    const prepared = formatMarkdownTables(text, 100);
    const render = await getRenderer();
    const result = render(prepared);
    if (result) process.stdout.write(result);
  } catch (err) {
    // Fallback: just print the raw text if markdown rendering fails
    setPlainRenderer();
    if (process.env.OPTA_DEBUG) {
      console.error(`Markdown render failed (${rendererBackend}), using plain text:`, err);
    }
    process.stdout.write(text);
  }
}

/**
 * Render markdown text to a string (for testing and programmatic use).
 */
export async function renderMarkdownToString(text: string): Promise<string> {
  if (!text?.trim()) return '';
  try {
    const prepared = formatMarkdownTables(text, 100);
    const render = await getRenderer();
    return render(prepared) || '';
  } catch (err) {
    setPlainRenderer();
    if (process.env.OPTA_DEBUG) {
      console.error(`Markdown render to string failed (${rendererBackend}):`, err);
    }
    return text;
  }
}

import { emitKeypressEvents, cursorTo, clearScreenDown } from 'node:readline';
import chalk from 'chalk';
import { colorizeOptaWord } from './brand.js';
import { fitTextToWidth, padToWidth } from '../utils/terminal-layout.js';
import { clamp } from '../utils/common.js';

type ActivePane = 'sections' | 'items';

export interface PaneMenuItem {
  id: string;
  label: string;
  description?: string;
}

export interface PaneMenuSection {
  id: string;
  label: string;
  color?: string;
  items: PaneMenuItem[];
}

export interface PaneMenuOptions {
  title: string;
  subtitle?: string;
  sections: PaneMenuSection[];
  instructions?: string;
  loop?: boolean;
  initialSectionIndex?: number;
  initialItemIndex?: number;
}

export interface PaneMenuSelection {
  sectionId: string;
  itemId: string;
  sectionIndex: number;
  itemIndex: number;
}

function moveIndex(current: number, delta: number, size: number, loop: boolean): number {
  if (size <= 0) return 0;
  if (loop) return (current + delta + size) % size;
  return clamp(current + delta, 0, size - 1);
}

function windowRange(total: number, selected: number, maxRows: number): { start: number; end: number } {
  if (total <= maxRows) return { start: 0, end: total };
  const half = Math.floor(maxRows / 2);
  const start = clamp(selected - half, 0, total - maxRows);
  return { start, end: start + maxRows };
}

function paintChip(text: string, color?: string): string {
  if (!color) return chalk.cyan(text);
  return chalk.hex(color)(text);
}

function renderFrame(
  options: PaneMenuOptions,
  sectionIndex: number,
  itemIndexes: number[],
  activePane: ActivePane,
): void {
  const columns = process.stdout.columns ?? 120;
  const rows = process.stdout.rows ?? 36;
  const sections = options.sections;
  const selectedSection = sections[sectionIndex];
  const selectedItems = selectedSection?.items ?? [];
  const itemIndex = clamp(itemIndexes[sectionIndex] ?? 0, 0, Math.max(0, selectedItems.length - 1));

  const usableColumns = Math.max(20, columns - 3);
  const minLeft = 8;
  const minRight = 10;
  let leftWidth = clamp(Math.floor(usableColumns * 0.32), minLeft, Math.min(42, Math.max(minLeft, usableColumns - minRight)));
  let rightWidth = usableColumns - leftWidth;
  if (rightWidth < minRight) {
    leftWidth = Math.max(minLeft, leftWidth - (minRight - rightWidth));
    rightWidth = usableColumns - leftWidth;
  }
  const maxRows = clamp(rows - 12, 6, 18);

  const leftRange = windowRange(sections.length, sectionIndex, maxRows);
  const rightRange = windowRange(selectedItems.length, itemIndex, maxRows);

  const title = colorizeOptaWord(options.title);
  const subtitle = options.subtitle ? chalk.dim(options.subtitle) : '';
  const instructions = options.instructions ?? '←/→ switch panes · ↑/↓ scroll (infinite) · Enter select · q exit';

  if (process.stdout.isTTY) {
    cursorTo(process.stdout, 0, 0);
    clearScreenDown(process.stdout);
  }
  const lines: string[] = [];

  lines.push(chalk.bold(title));
  if (subtitle) lines.push(subtitle);
  lines.push(chalk.dim(instructions));
  lines.push('');

  const leftHeader = fitTextToWidth('Areas', leftWidth, { pad: true });
  const rightHeader = fitTextToWidth(selectedSection?.label ?? 'Commands', rightWidth, { pad: true });
  lines.push(
    `${activePane === 'sections' ? chalk.bgMagenta.black(` ${leftHeader} `) : chalk.magenta(` ${leftHeader} `)} ` +
    `${activePane === 'items' ? chalk.bgCyan.black(` ${rightHeader} `) : chalk.cyan(` ${rightHeader} `)}`,
  );

  for (let i = 0; i < maxRows; i++) {
    const sIdx = leftRange.start + i;
    const itIdx = rightRange.start + i;
    const section = sections[sIdx];
    const item = selectedItems[itIdx];

    let left = padToWidth('', leftWidth + 2);
    if (section) {
      const raw = `${sIdx === sectionIndex ? '●' : '○'} ${section.label}`;
      const padded = ` ${fitTextToWidth(raw, leftWidth, { pad: true })} `;
      if (sIdx === sectionIndex) {
        left = activePane === 'sections'
          ? chalk.bgHex('#4c1d95').white(padded)
          : chalk.hex('#a78bfa')(padded);
      } else {
        left = paintChip(padded, section.color);
      }
    }

    let right = padToWidth('', rightWidth + 2);
    if (item) {
      const raw = `${itIdx === itemIndex ? '◆' : '·'} /${item.id} ${item.description ?? ''}`;
      const padded = ` ${fitTextToWidth(raw, rightWidth, { pad: true })} `;
      if (itIdx === itemIndex) {
        right = activePane === 'items'
          ? chalk.bgHex('#0e7490').white(padded)
          : chalk.cyan(padded);
      } else {
        right = chalk.dim(padded);
      }
    }

    lines.push(`${left} ${right}`);
  }

  const selectedItem = selectedItems[itemIndex];
  lines.push('');
  if (selectedItem) {
    lines.push(
      chalk.dim('Selected: ') +
      chalk.cyan(`/${selectedItem.id}`) +
      (selectedItem.description ? chalk.dim(` — ${selectedItem.description}`) : '')
    );
  } else {
    lines.push(chalk.dim('No commands in this area'));
  }

  process.stdout.write(`${lines.join('\n')}\n`);
}

export async function runPaneMenu(options: PaneMenuOptions): Promise<PaneMenuSelection | null> {
  const sections = options.sections.filter((s) => s.items.length > 0);
  if (!process.stdin.isTTY || sections.length === 0) return null;

  const loop = options.loop ?? true;
  let sectionIndex = clamp(options.initialSectionIndex ?? 0, 0, sections.length - 1);
  const itemIndexes = sections.map((s) => clamp(options.initialItemIndex ?? 0, 0, Math.max(0, s.items.length - 1)));
  let activePane: ActivePane = 'sections';

  emitKeypressEvents(process.stdin);
  const previousRawMode = process.stdin.isRaw ?? false;
  if (!previousRawMode) process.stdin.setRawMode(true);
  process.stdin.resume();
  // keep cursor visible during menu render for terminal stability


  return new Promise<PaneMenuSelection | null>((resolve) => {
    const cleanup = (): void => {
      process.stdin.off('keypress', onKeypress);
      if (!previousRawMode && process.stdin.isTTY) process.stdin.setRawMode(false);
    };

    const finish = (value: PaneMenuSelection | null): void => {
      cleanup();
      process.stdout.write('\n');
      resolve(value);
    };

    const onKeypress = (_str: string, key: { name?: string; ctrl?: boolean }): void => {
      const section = sections[sectionIndex]!;
      const currentItemCount = Math.max(1, section.items.length);

      if (key.ctrl && key.name === 'c') {
        finish(null);
        return;
      }

      if (key.name === 'q' || key.name === 'escape') {
        finish(null);
        return;
      }

      if (key.name === 'tab') {
        activePane = activePane === 'sections' ? 'items' : 'sections';
        renderFrame({ ...options, sections }, sectionIndex, itemIndexes, activePane);
        return;
      }

      if (key.name === 'left') {
        activePane = 'sections';
        renderFrame({ ...options, sections }, sectionIndex, itemIndexes, activePane);
        return;
      }

      if (key.name === 'right') {
        activePane = 'items';
        renderFrame({ ...options, sections }, sectionIndex, itemIndexes, activePane);
        return;
      }

      if (key.name === 'up') {
        if (activePane === 'sections') {
          sectionIndex = moveIndex(sectionIndex, -1, sections.length, loop);
        } else {
          itemIndexes[sectionIndex] = moveIndex(itemIndexes[sectionIndex] ?? 0, -1, currentItemCount, loop);
        }
        renderFrame({ ...options, sections }, sectionIndex, itemIndexes, activePane);
        return;
      }

      if (key.name === 'down') {
        if (activePane === 'sections') {
          sectionIndex = moveIndex(sectionIndex, 1, sections.length, loop);
        } else {
          itemIndexes[sectionIndex] = moveIndex(itemIndexes[sectionIndex] ?? 0, 1, currentItemCount, loop);
        }
        renderFrame({ ...options, sections }, sectionIndex, itemIndexes, activePane);
        return;
      }

      if (key.name === 'return' || key.name === 'enter') {
        if (activePane === 'sections') {
          activePane = 'items';
          renderFrame({ ...options, sections }, sectionIndex, itemIndexes, activePane);
          return;
        }
        const itemIndex = itemIndexes[sectionIndex] ?? 0;
        const item = sections[sectionIndex]!.items[itemIndex];
        if (!item) return;
        finish({
          sectionId: sections[sectionIndex]!.id,
          itemId: item.id,
          sectionIndex,
          itemIndex,
        });
      }
    };

    process.stdin.on('keypress', onKeypress);
    renderFrame({ ...options, sections }, sectionIndex, itemIndexes, activePane);
  });
}

import chalk from 'chalk';

export function renderPercentBar(percent: number, width = 20): string {
  const clamped = Math.max(0, Math.min(100, Number.isFinite(percent) ? percent : 0));
  const ratio = clamped / 100;
  const filled = Math.round(ratio * width);
  const empty = Math.max(0, width - filled);
  const pctText = `${Math.round(clamped)}%`;
  const filledBar = 'O'.repeat(filled);
  const emptyBar = 'o'.repeat(empty);
  return `${chalk.hex('#8b5cf6')(filledBar)}${chalk.hex('#312e81')(emptyBar)} ${chalk.hex('#22d3ee')(pctText)}`;
}

export interface StepProgressTracker {
  tick(message?: string): void;
  set(current: number, message?: string): void;
  done(message?: string): void;
  fail(message?: string): void;
}

export interface SegmentedStepProgressTracker {
  tick(segment: string, message?: string): void;
  set(segment: string, current: number, message?: string): void;
  done(message?: string): void;
  fail(message?: string): void;
}

interface ProgressSegmentConfig {
  key: string;
  label: string;
  totalSteps: number;
}

interface ProgressSegmentState {
  key: string;
  label: string;
  total: number;
  current: number;
  message?: string;
}

export function createStepProgressTracker(
  totalSteps: number,
  title: string,
  enabled = true,
): StepProgressTracker {
  const total = Math.max(1, totalSteps);
  let current = 0;

  const render = (symbol: string, message?: string): void => {
    if (!enabled) return;
    const percent = Math.round((Math.max(0, Math.min(total, current)) / total) * 100);
    const line = `${symbol} ${chalk.bold(title)} ${renderPercentBar(percent, 24)}${message ? ` ${chalk.dim(message)}` : ''}`;
    console.log(line);
  };

  const finishLine = (): void => {
    // no-op: keep output append-only to avoid cursor-control ANSI sequences
  };

  return {
    tick(message?: string): void {
      current = Math.min(total, current + 1);
      render(chalk.cyan('⏳'), message);
    },
    set(next: number, message?: string): void {
      current = Math.max(0, Math.min(total, next));
      render(chalk.cyan('⏳'), message);
    },
    done(message?: string): void {
      current = total;
      render(chalk.green('✓'), message ?? 'done');
      finishLine();
    },
    fail(message?: string): void {
      render(chalk.red('✗'), message ?? 'failed');
      finishLine();
    },
  };
}

export function createSegmentedStepProgressTracker(
  segments: readonly ProgressSegmentConfig[],
  title: string,
  enabled = true,
): SegmentedStepProgressTracker {
  const states = segments
    .map((segment) => ({
      key: segment.key,
      label: segment.label,
      total: Math.max(1, segment.totalSteps),
      current: 0,
      message: undefined,
    }))
    .filter((segment) => segment.key.trim().length > 0);

  const safeStates: ProgressSegmentState[] = states.length > 0
    ? states
    : [{ key: 'default', label: 'Progress', total: 1, current: 0 }];

  const total = Math.max(
    1,
    safeStates.reduce((sum, segment) => sum + segment.total, 0),
  );
  const labelWidth = Math.max(...safeStates.map((segment) => segment.label.length), 7);

  const findSegment = (key: string): ProgressSegmentState =>
    safeStates.find((segment) => segment.key === key) ?? safeStates[0]!;

  const render = (symbol: string, headline?: string): void => {
    if (!enabled) return;

    const completed = safeStates.reduce((sum, segment) => sum + segment.current, 0);
    const percent = Math.round((Math.max(0, Math.min(total, completed)) / total) * 100);
    const lines = [
      `${symbol} ${chalk.bold(title)} ${renderPercentBar(percent, 24)}${headline ? ` ${chalk.dim(headline)}` : ''}`,
      ...safeStates.map((segment) => {
        const segmentPercent = Math.round((Math.max(0, Math.min(segment.total, segment.current)) / segment.total) * 100);
        const label = segment.label.padEnd(labelWidth, ' ');
        const detail = segment.message ? ` ${chalk.dim(segment.message)}` : '';
        return `  ${chalk.bold(label)} ${renderPercentBar(segmentPercent, 24)}${detail}`;
      }),
    ];

    console.log(lines.join('\n'));
  };

  const finish = (): void => {
    // no-op: append-only output, nothing to clean up
  };

  return {
    tick(segmentKey: string, message?: string): void {
      const segment = findSegment(segmentKey);
      segment.current = Math.min(segment.total, segment.current + 1);
      segment.message = message;
      render(chalk.cyan('⏳'), message);
    },
    set(segmentKey: string, current: number, message?: string): void {
      const segment = findSegment(segmentKey);
      segment.current = Math.max(0, Math.min(segment.total, current));
      segment.message = message;
      render(chalk.cyan('⏳'), message);
    },
    done(message?: string): void {
      for (const segment of safeStates) {
        segment.current = segment.total;
      }
      render(chalk.green('✓'), message ?? 'done');
      finish();
    },
    fail(message?: string): void {
      render(chalk.red('✗'), message ?? 'failed');
      finish();
    },
  };
}

import { emitKeypressEvents } from 'node:readline';

export type MenuPromptMode = 'select' | 'search';

interface KeypressLike {
  name?: string;
  ctrl?: boolean;
  meta?: boolean;
  shift?: boolean;
}

interface BackKeyState {
  mode: MenuPromptMode;
  key?: KeypressLike;
  input?: string;
  searchTermLength: number;
}

interface BackKeyDecision {
  triggerBack: boolean;
  nextSearchTermLength: number;
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === 'string' && value.length > 0;
}

function isPrintableInput(input?: string): boolean {
  return Boolean(input && input.length > 0 && !input.startsWith('\u001b'));
}

function normalizeKeyName(key?: KeypressLike, input?: string): string | undefined {
  const name = key?.name?.toLowerCase();
  if (name) return name;
  if (!input) return undefined;

  // Some terminals emit raw escape sequences without key metadata.
  if (input === '\u001b[D') return 'left';
  if (input === '\u007f' || input === '\u0008') return 'backspace';
  if (input === '\u001b[3~') return 'delete';
  if (input === '\u001b') return 'escape';
  return undefined;
}

/**
 * Decide whether a keypress should move back to the previous menu and
 * update the tracked search-term length for search prompts.
 */
export function evaluateMenuBackKey(state: BackKeyState): BackKeyDecision {
  const keyName = normalizeKeyName(state.key, state.input);
  const hasModifier = Boolean(state.key?.ctrl || state.key?.meta);
  let nextSearchTermLength = state.searchTermLength;

  if (state.mode === 'search' && state.key?.ctrl && (keyName === 'u' || keyName === 'w')) {
    return { triggerBack: false, nextSearchTermLength: 0 };
  }

  if (state.mode === 'search' && !hasModifier && isPrintableInput(state.input)) {
    nextSearchTermLength += state.input!.length;
  }

  if (hasModifier) {
    return { triggerBack: false, nextSearchTermLength };
  }

  if (keyName === 'escape') {
    return { triggerBack: true, nextSearchTermLength: 0 };
  }

  if (keyName === 'left') {
    return { triggerBack: true, nextSearchTermLength };
  }

  if (keyName === 'backspace' || keyName === 'delete') {
    if (state.mode === 'search') {
      if (state.searchTermLength <= 0) {
        return { triggerBack: true, nextSearchTermLength: 0 };
      }
      return {
        triggerBack: false,
        nextSearchTermLength: Math.max(0, state.searchTermLength - 1),
      };
    }
    return { triggerBack: true, nextSearchTermLength };
  }

  return { triggerBack: false, nextSearchTermLength };
}

/**
 * Run an inquirer menu prompt with keyboard back-navigation:
 * - escape: cancel current menu / go back
 * - left arrow: go back to previous menu
 * - backspace/delete: go back for select menus
 * - backspace/delete: go back for search menus when search box is empty
 */
export async function runMenuPrompt<T>(
  runPrompt: (context: { signal: AbortSignal }) => Promise<T>,
  mode: MenuPromptMode,
): Promise<T | null> {
  if (!process.stdin.isTTY) {
    const controller = new AbortController();
    return runPrompt({ signal: controller.signal });
  }

  const input = process.stdin;
  const controller = new AbortController();
  let searchTermLength = 0;
  let abortedByBackKey = false;

  const onKeypress = (data: unknown, key: unknown): void => {
    const decision = evaluateMenuBackKey({
      mode,
      key: key as KeypressLike,
      input: isNonEmptyString(data) ? data : undefined,
      searchTermLength,
    });
    searchTermLength = decision.nextSearchTermLength;
    if (decision.triggerBack) {
      abortedByBackKey = true;
      controller.abort();
    }
  };

  emitKeypressEvents(input);
  input.on('keypress', onKeypress);
  try {
    return await runPrompt({ signal: controller.signal });
  } catch (err) {
    if (abortedByBackKey) return null;
    throw err;
  } finally {
    input.off('keypress', onKeypress);
  }
}

/**
 * Report Trigger — decides when to generate HTML reports and orchestrates
 * building, writing, and opening them.
 *
 * Auto-triggers for:
 *   - Benchmarks (always)
 *   - Plan mode completions (always)
 *   - Autonomous sessions above configurable thresholds (tool calls OR elapsed time)
 *
 * Also provides buildSessionReport() for the manual /report slash command.
 */

import { writeFile, mkdir } from 'node:fs/promises';
import { join } from 'node:path';
import { hostname } from 'node:os';
import { execa } from 'execa';
import {
  renderGlassReport,
  type ReportSection,
  type StatItem,
  type TimelineEvent,
} from './html-report.js';
import type { TurnStats } from '../tui/adapter.js';
import type { Session } from '../memory/store.js';
import type { OptaConfig } from '../core/config.js';
import {
  deriveResponseIntentOutcome,
  deriveResponseIntentSentence,
  type ResponseIntentOutcomeInput,
  type ResponseIntentSentenceInput,
} from '../tui/response-intent.js';

// ── Config defaults (overridden by config.reports.*) ──

const DEFAULT_TOOL_CALL_THRESHOLD = 15;
const DEFAULT_ELAPSED_THRESHOLD = 120; // seconds
const DEFAULT_OUTPUT_DIR = '.opta/reports';

export interface ReportConfig {
  enabled: boolean;
  autoOpen: boolean;
  outputDir: string;
  threshold: {
    toolCalls: number;
    elapsedSeconds: number;
  };
}

export function resolveReportConfig(config: OptaConfig): ReportConfig {
  const raw = (config as Record<string, unknown>)['reports'] as Partial<ReportConfig> | undefined;
  return {
    enabled: raw?.enabled ?? true,
    autoOpen: raw?.autoOpen ?? true,
    outputDir: raw?.outputDir ?? DEFAULT_OUTPUT_DIR,
    threshold: {
      toolCalls: raw?.threshold?.toolCalls ?? DEFAULT_TOOL_CALL_THRESHOLD,
      elapsedSeconds: raw?.threshold?.elapsedSeconds ?? DEFAULT_ELAPSED_THRESHOLD,
    },
  };
}

// ── Trigger gate ──────────────────────────────────────────────────

export type ReportTriggerReason = 'benchmark' | 'plan' | 'autonomous' | 'manual';

/**
 * Determine whether an automatic report should be generated.
 *
 * Returns the trigger reason, or null if no auto-report is warranted.
 */
export function shouldAutoReport(
  turnStats: TurnStats,
  mode: string | undefined,
  reportConfig: ReportConfig
): ReportTriggerReason | null {
  if (!reportConfig.enabled) return null;

  // Plan mode always generates a report
  if (mode === 'plan') return 'plan';

  // Autonomous threshold: tool calls OR elapsed time
  const { toolCalls, elapsedSeconds } = reportConfig.threshold;
  if (turnStats.toolCalls >= toolCalls || turnStats.elapsed >= elapsedSeconds) {
    return 'autonomous';
  }

  return null;
}

// ── Data helpers ──────────────────────────────────────────────────

function formatElapsed(seconds: number): string {
  if (seconds < 60) return `${Math.round(seconds)}s`;
  const m = Math.floor(seconds / 60);
  const s = Math.round(seconds % 60);
  return s > 0 ? `${m}m ${s}s` : `${m}m`;
}

function formatSpeed(tokensPerSec: number): string {
  if (tokensPerSec < 1) return '<1';
  return tokensPerSec.toFixed(1);
}

function formatLatency(ms: number | null): string {
  if (ms === null) return '—';
  if (ms < 1000) return `${Math.round(ms)}ms`;
  return `${(ms / 1000).toFixed(1)}s`;
}

interface GitChanges {
  created: string[];
  modified: string[];
  deleted: string[];
}

async function collectGitChanges(cwd: string): Promise<GitChanges> {
  try {
    const result = await execa('git', ['status', '--porcelain'], { cwd, reject: false });
    if (result.exitCode !== 0) return { created: [], modified: [], deleted: [] };

    const created: string[] = [];
    const modified: string[] = [];
    const deleted: string[] = [];

    for (const line of result.stdout.split('\n')) {
      if (!line.trim()) continue;
      const status = line.slice(0, 2);
      let file = line.slice(3).trim();
      if (!file) continue;

      if (status.includes('R') || status.includes('C')) {
        const parts = file.split(' -> ');
        file = parts[parts.length - 1]?.trim() ?? file;
      }

      if (status === '??' || status.includes('A')) created.push(file);
      else if (status.includes('D')) deleted.push(file);
      else modified.push(file);
    }

    return { created: created.sort(), modified: modified.sort(), deleted: deleted.sort() };
  } catch {
    return { created: [], modified: [], deleted: [] };
  }
}

function extractToolTimeline(session: Session): TimelineEvent[] {
  const events: TimelineEvent[] = [];
  const toolColors: Record<string, string> = {
    read_file: 'var(--neon-blue)',
    write_file: 'var(--neon-green)',
    edit_file: 'var(--neon-amber)',
    run_command: 'var(--neon-red)',
    search_files: 'var(--neon-cyan)',
    list_dir: 'var(--neon-blue)',
    find_files: 'var(--neon-cyan)',
    ask_user: 'var(--primary)',
  };

  let toolIndex = 0;
  for (const msg of session.messages ?? []) {
    if (msg.role === 'assistant' && msg.tool_calls) {
      for (const tc of msg.tool_calls) {
        toolIndex++;
        const name = tc.function.name;
        let detail: string | undefined;
        try {
          const args = JSON.parse(tc.function.arguments) as Record<string, unknown>;
          const path = args['path'] ?? args['file_path'] ?? args['command'] ?? args['pattern'];
          if (typeof path === 'string') {
            detail = path.length > 80 ? path.slice(0, 77) + '...' : path;
          }
        } catch {
          /* ignore parse errors */
        }

        events.push({
          time: `#${toolIndex}`,
          label: name,
          detail,
          color: toolColors[name] ?? 'var(--text-muted)',
        });
      }
    }
  }

  // Keep at most 50 events to avoid enormous timelines
  if (events.length > 50) {
    const head = events.slice(0, 25);
    const tail = events.slice(-24);
    return [
      ...head,
      { time: '...', label: `${events.length - 49} more tool calls`, color: 'var(--text-muted)' },
      ...tail,
    ];
  }

  return events;
}

function extractDecisions(session: Session): string[] {
  const decisions: string[] = [];
  const regex = /\b(decision|decided|choose|selected|plan|approach)\b/i;

  for (const msg of session.messages ?? []) {
    if (msg.role !== 'assistant') continue;
    const text = typeof msg.content === 'string' ? msg.content : '';
    if (!text || !regex.test(text)) continue;
    decisions.push(text.replace(/\s+/g, ' ').slice(0, 160));
    if (decisions.length >= 5) break;
  }

  return decisions;
}

function extractIssues(session: Session): string[] {
  const issues: string[] = [];
  const regex = /\b(error|failed|failure|exception|timeout|denied|invalid)\b/i;

  for (const msg of session.messages ?? []) {
    const text = typeof msg.content === 'string' ? msg.content : '';
    if (!text || !regex.test(text)) continue;
    issues.push(text.replace(/\s+/g, ' ').slice(0, 160));
    if (issues.length >= 5) break;
  }

  return issues;
}

function extractLastAssistantSentence(session: Session): string {
  const assistantMsgs = (session.messages ?? []).filter((m) => m.role === 'assistant');
  const last = assistantMsgs[assistantMsgs.length - 1];
  if (!last) return 'No assistant response.';
  const text = typeof last.content === 'string' ? last.content : '';
  const compact = text.replace(/\s+/g, ' ').trim();
  return compact.split(/(?<=[.!?])\s+/)[0]?.slice(0, 200) ?? compact.slice(0, 200);
}

// ── Section builders ─────────────────────────────────────────────

export function buildSessionReportSections(
  session: Session,
  turnStats: TurnStats,
  reason: ReportTriggerReason,
  gitChanges: GitChanges
): ReportSection[] {
  const sections: ReportSection[] = [];

  // Intent classification
  const intentInput: ResponseIntentOutcomeInput = {
    toolCallCount: turnStats.toolCalls,
    failedToolCallCount: 0,
    hasVisibleOutput: true,
  };
  const outcome = deriveResponseIntentOutcome(intentInput);

  // Prompt for sentence derivation
  const userMessages = (session.messages ?? []).filter((m) => m.role === 'user');
  const firstPrompt = userMessages[0]
    ? typeof userMessages[0].content === 'string'
      ? userMessages[0].content
      : ''
    : '';
  const sentenceInput: ResponseIntentSentenceInput = {
    ...intentInput,
    promptText: firstPrompt,
    tone: 'product',
  };
  const intentSentence = deriveResponseIntentSentence(sentenceInput);

  // §1 — Performance metrics
  sections.push({
    type: 'section-header',
    number: '01',
    title: 'Performance',
  });

  const stats: StatItem[] = [
    { value: String(turnStats.toolCalls), label: 'Tool Calls' },
    { value: formatElapsed(turnStats.elapsed), label: 'Duration' },
    { value: formatSpeed(turnStats.speed), label: 'Tokens/sec' },
    { value: formatLatency(turnStats.firstTokenLatencyMs), label: 'First Token' },
    { value: String(turnStats.completionTokens), label: 'Tokens' },
    { value: outcome.toUpperCase(), label: 'Outcome' },
  ];
  sections.push({ type: 'stats-grid', items: stats });

  // §2 — Session info
  sections.push({
    type: 'section-header',
    number: '02',
    title: 'Session',
  });

  sections.push({
    type: 'key-value',
    pairs: [
      { key: 'Session ID', value: session.id },
      { key: 'Title', value: session.title || '(untitled)' },
      { key: 'Model', value: session.model || 'unknown' },
      { key: 'Working Directory', value: session.cwd || process.cwd() },
      { key: 'Created', value: session.created || '—' },
      { key: 'Report Trigger', value: reason, color: 'c-violet' },
      { key: 'Intent', value: intentSentence },
    ],
  });

  // §3 — Tool timeline (only if there are tools)
  const timeline = extractToolTimeline(session);
  if (timeline.length > 0) {
    sections.push({ type: 'divider' });
    sections.push({
      type: 'section-header',
      number: '03',
      title: 'Tool Timeline',
    });
    sections.push({ type: 'timeline', events: timeline });
  }

  // §4 — File changes
  const totalChanges =
    gitChanges.created.length + gitChanges.modified.length + gitChanges.deleted.length;
  if (totalChanges > 0) {
    sections.push({ type: 'divider' });
    sections.push({
      type: 'section-header',
      number: '04',
      title: 'File Changes',
    });
    sections.push({
      type: 'file-changes',
      created: gitChanges.created,
      modified: gitChanges.modified,
      deleted: gitChanges.deleted,
    });
  }

  // §5 — Decisions
  const decisions = extractDecisions(session);
  if (decisions.length > 0) {
    sections.push({ type: 'divider' });
    sections.push({
      type: 'section-header',
      number: '05',
      title: 'Decisions Made',
    });
    sections.push({ type: 'list', items: decisions, style: 'bullet' });
  }

  // §6 — Issues
  const issues = extractIssues(session);
  if (issues.length > 0) {
    sections.push({ type: 'divider' });
    sections.push({
      type: 'section-header',
      number: '06',
      title: 'Issues Encountered',
    });
    sections.push({ type: 'list', items: issues, style: 'bullet' });
  }

  // §7 — Summary
  sections.push({ type: 'divider' });
  sections.push({
    type: 'section-header',
    number: (totalChanges > 0 ? '07' : '05').padStart(2, '0'),
    title: 'Summary',
  });
  sections.push({
    type: 'text-block',
    content: extractLastAssistantSentence(session),
  });

  return sections;
}

export function buildPlanReportSections(session: Session, turnStats: TurnStats): ReportSection[] {
  const sections: ReportSection[] = [];

  // Extract the final assistant message as the plan content
  const assistantMsgs = (session.messages ?? []).filter((m) => m.role === 'assistant');
  const planText =
    assistantMsgs.length > 0
      ? typeof assistantMsgs[assistantMsgs.length - 1]!.content === 'string'
        ? (assistantMsgs[assistantMsgs.length - 1]!.content as string)
        : ''
      : '';

  // Stats
  sections.push({
    type: 'section-header',
    number: '01',
    title: 'Plan Metrics',
  });
  sections.push({
    type: 'stats-grid',
    items: [
      { value: String(turnStats.toolCalls), label: 'Research Calls' },
      { value: formatElapsed(turnStats.elapsed), label: 'Duration' },
      { value: formatSpeed(turnStats.speed), label: 'Tokens/sec' },
      { value: String(turnStats.completionTokens), label: 'Tokens' },
    ],
  });

  // Context
  sections.push({
    type: 'section-header',
    number: '02',
    title: 'Context',
  });
  sections.push({
    type: 'key-value',
    pairs: [
      { key: 'Model', value: session.model || 'unknown' },
      { key: 'Working Directory', value: session.cwd || process.cwd() },
      { key: 'Session', value: session.id },
    ],
  });

  // Plan content
  sections.push({ type: 'divider' });
  sections.push({
    type: 'section-header',
    number: '03',
    title: 'Plan',
  });
  sections.push({
    type: 'text-block',
    content: planText.slice(0, 10_000) || 'No plan content generated.',
  });

  return sections;
}

// ── Write + Open ─────────────────────────────────────────────────

function slugify(text: string, maxLen = 48): string {
  return (
    text
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '')
      .slice(0, maxLen)
      .replace(/-+$/g, '') || 'report'
  );
}

export async function writeAndOpenReport(
  html: string,
  outputDir: string,
  slug: string,
  autoOpen: boolean
): Promise<string> {
  await mkdir(outputDir, { recursive: true });

  const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
  const fileName = `${ts}-${slug}.html`;
  const filePath = join(outputDir, fileName);

  await writeFile(filePath, html, 'utf-8');

  if (autoOpen) {
    // Fire-and-forget — don't block on browser opening
    execa('open', [filePath], { reject: false }).catch(() => {
      /* ignore */
    });
  }

  return filePath;
}

// ── Orchestrator ─────────────────────────────────────────────────

/**
 * Full orchestrator: check threshold → build sections → render → write → open.
 *
 * Called from turn:end handler in the TUI adapter or from /report slash command.
 * Returns the file path if a report was generated, or null if skipped.
 */
export async function maybeGenerateReport(
  session: Session,
  turnStats: TurnStats,
  config: OptaConfig,
  mode?: string,
  reason?: ReportTriggerReason
): Promise<string | null> {
  const rc = resolveReportConfig(config);

  // Determine reason
  const effectiveReason = reason ?? shouldAutoReport(turnStats, mode, rc);
  if (!effectiveReason) return null;

  const cwd = session.cwd || process.cwd();
  const outputDir = join(cwd, rc.outputDir);

  let sections: ReportSection[];
  let badge: string;
  let subtitle: string;

  if (effectiveReason === 'plan') {
    sections = buildPlanReportSections(session, turnStats);
    badge = 'Plan Report';
    subtitle = `Generated in ${formatElapsed(turnStats.elapsed)} with ${turnStats.toolCalls} research calls`;
  } else {
    const gitChanges = await collectGitChanges(cwd);
    sections = buildSessionReportSections(session, turnStats, effectiveReason, gitChanges);
    badge = effectiveReason === 'benchmark' ? 'Benchmark Report' : 'Session Report';
    subtitle = `${turnStats.toolCalls} tool calls in ${formatElapsed(turnStats.elapsed)} — ${formatSpeed(turnStats.speed)} tok/s`;
  }

  const title = session.title || 'Opta Session';
  const html = renderGlassReport({ title, badge, subtitle, sections });
  const slug = slugify(session.title || effectiveReason);
  const deviceName = hostname().split('.')[0] ?? 'device';

  return writeAndOpenReport(html, outputDir, `${deviceName}-${slug}`, rc.autoOpen);
}

/**
 * Manual report generation — always generates regardless of thresholds.
 * Used by /report slash command.
 */
export async function generateManualReport(
  session: Session,
  turnStats: TurnStats,
  config: OptaConfig
): Promise<string> {
  const rc = resolveReportConfig(config);
  const cwd = session.cwd || process.cwd();
  const outputDir = join(cwd, rc.outputDir);
  const gitChanges = await collectGitChanges(cwd);
  const sections = buildSessionReportSections(session, turnStats, 'manual', gitChanges);

  const title = session.title || 'Opta Session Report';
  const subtitle = `${turnStats.toolCalls} tool calls in ${formatElapsed(turnStats.elapsed)}`;
  const html = renderGlassReport({ title, badge: 'Manual Report', subtitle, sections });
  const slug = slugify(session.title || 'session-report');
  const deviceName = hostname().split('.')[0] ?? 'device';

  return writeAndOpenReport(html, outputDir, `${deviceName}-${slug}`, rc.autoOpen);
}

import { createHighlighter, type HighlighterGeneric } from 'shiki';
import { createJavaScriptRegexEngine } from '@shikijs/engine-javascript';
import chalk from 'chalk';

let highlighter: HighlighterGeneric<any, any> | null = null;
let initPromise: Promise<HighlighterGeneric<any, any>> | null = null;

const THEME = 'vitesse-dark';
const DEFAULT_LANGS = [
  'javascript', 'typescript', 'tsx', 'jsx', 'json', 'bash', 'yaml', 'python',
  'html', 'css', 'markdown', 'rust', 'go', 'cpp', 'c', 'text'
];

export async function initShiki(): Promise<void> {
  if (highlighter) return;
  if (initPromise) {
    await initPromise;
    return;
  }

  initPromise = createHighlighter({
    themes: [THEME],
    langs: DEFAULT_LANGS,
    engine: createJavaScriptRegexEngine(),
  }).then((hl) => {
    highlighter = hl;
    return hl;
  });

  await initPromise;
}

export function highlightCodeAnsiSync(code: string, lang: string): string {
  if (!highlighter) return code;

  try {
    const loadedLangs = highlighter.getLoadedLanguages();
    let targetLang = lang;
    if (!lang || !loadedLangs.includes(lang)) {
      targetLang = 'text';
    }

    if (targetLang === 'text') {
      return code;
    }

    const { tokens } = highlighter.codeToTokens(code, { lang: targetLang, theme: THEME });

    const lines = tokens.map((lineTokens) => {
      return lineTokens.map((token) => {
        let text = token.content;
        if (token.color) {
          text = chalk.hex(token.color)(text);
        }
        if (token.fontStyle && token.fontStyle & 1) { // 1 is italic
          text = chalk.italic(text);
        }
        if (token.fontStyle && token.fontStyle & 2) { // 2 is bold
          text = chalk.bold(text);
        }
        if (token.fontStyle && token.fontStyle & 4) { // 4 is underline
          text = chalk.underline(text);
        }
        return text;
      }).join('');
    });

    return lines.join('\n');
  } catch {
    return code;
  }
}

import chalk, { type ChalkInstance } from 'chalk';
import { join } from 'node:path';
import { readdir, readFile } from 'node:fs/promises';
import { getThemesDir } from '../platform/paths.js';

export interface ThemeColors {
  primary: string;
  secondary: string;
  success: string;
  error: string;
  warning: string;
  info: string;
  muted: string;
  text: string;
  border: string;
}

export interface Theme {
  name: string;
  description: string;
  colors: ThemeColors;
  primary: ChalkInstance;
  secondary: ChalkInstance;
  success: ChalkInstance;
  error: ChalkInstance;
  warning: ChalkInstance;
  info: ChalkInstance;
  muted: ChalkInstance;
  dim: ChalkInstance;
}

/** Raw theme definition before chalk instances are built. */
export interface ThemeDef {
  description: string;
  colors: ThemeColors;
}

const THEME_COLOR_KEYS: ReadonlyArray<keyof ThemeColors> = [
  'primary', 'secondary', 'success', 'error', 'warning',
  'info', 'muted', 'text', 'border',
];

const HEX_COLOR_RE = /^#[0-9a-fA-F]{6}$/;

const BUILTIN_THEMES: Record<string, ThemeDef> = {
  opta: {
    description: 'Default Opta theme — Electric Violet accent',
