      warning: '#FCD34D',
      info: '#A1A1AA',
      muted: '#52525B',
      text: '#E4E4E7',
      border: '#3F3F46',
    },
  },
  solarized: {
    description: 'Solarized Dark — warm tones',
    colors: {
      primary: '#268BD2',
      secondary: '#2AA198',
      success: '#859900',
      error: '#DC322F',
      warning: '#B58900',
      info: '#6C71C4',
      muted: '#586E75',
