    },
  },
  catppuccin: {
    description: 'Catppuccin Mocha — pastel colors',
    colors: {
      primary: '#CBA6F7',
      secondary: '#89B4FA',
      success: '#A6E3A1',
      error: '#F38BA8',
      warning: '#F9E2AF',
      info: '#74C7EC',
      muted: '#585B70',
      text: '#CDD6F4',
      border: '#45475A',
    },
  },
};

/** Merged registry: built-in + custom themes. */
let themeRegistry: Record<string, ThemeDef> = { ...BUILTIN_THEMES };
let customThemesLoaded = false;
let currentThemeName = 'opta';

// ---------------------------------------------------------------------------
// Validation
// ---------------------------------------------------------------------------

/**
 * Validate that a parsed JSON value is a well-formed theme definition.
 * Returns the validated ThemeDef or null if invalid.
 */
export function validateThemeDef(value: unknown): ThemeDef | null {
  if (typeof value !== 'object' || value === null) return null;

  const obj = value as Record<string, unknown>;

  if (typeof obj['description'] !== 'string') return null;

  const colors = obj['colors'];
  if (typeof colors !== 'object' || colors === null) return null;

  const colorsObj = colors as Record<string, unknown>;
  for (const key of THEME_COLOR_KEYS) {
    const val = colorsObj[key];
    if (typeof val !== 'string' || !HEX_COLOR_RE.test(val)) return null;
  }

  return {
    description: obj['description'],
    colors: colorsObj as unknown as ThemeColors,
  };
}

// ---------------------------------------------------------------------------
// Custom theme loading
// ---------------------------------------------------------------------------

/**
 * Directories searched for custom theme JSON files (in order).
 * Later directories win on name conflicts; custom always overrides built-in.
 */
export function getCustomThemeDirs(): string[] {
  return [
    getThemesDir(),
    join(process.cwd(), '.opta', 'themes'),
  ];
}

/**
 * Read *.json files from a single directory and return validated theme defs.
 * Silently skips files that fail to parse or validate.
 */
async function loadThemesFromDir(
  dir: string,
): Promise<Record<string, ThemeDef>> {
  const result: Record<string, ThemeDef> = {};

  let entries: string[];
  try {
    entries = await readdir(dir);
  } catch {
    // Directory does not exist or is inaccessible — not an error.
    return result;
  }

  const jsonFiles = entries.filter((f) => f.endsWith('.json'));
  for (const file of jsonFiles) {
    try {
      const raw = await readFile(join(dir, file), 'utf-8');
      const parsed: unknown = JSON.parse(raw);
      const def = validateThemeDef(parsed);
      if (def) {
        // Theme name derived from filename without .json extension.
        const name = file.replace(/\.json$/, '');
        result[name] = def;
      }
    } catch {
      // Malformed JSON — skip silently.
    }
  }

  return result;
}

/**
 * Load custom themes from all theme directories and merge them with built-in
 * themes. Custom themes override built-in themes if names conflict.
 *
 * Safe to call multiple times — only reads from disk on the first call
 * (unless `force` is true).
 *
 * @param force  Re-read from disk even if already loaded.
 * @param dirs   Override the directories to scan (for testing).
 */
export async function loadCustomThemes(
  force = false,
  dirs?: string[],
): Promise<Record<string, ThemeDef>> {
  if (customThemesLoaded && !force) return themeRegistry;

  const merged: Record<string, ThemeDef> = { ...BUILTIN_THEMES };

  for (const dir of (dirs ?? getCustomThemeDirs())) {
    const custom = await loadThemesFromDir(dir);
    Object.assign(merged, custom);
  }

  themeRegistry = merged;
  customThemesLoaded = true;
  return merged;
}

/**
 * Initialize the theme system by loading custom themes. Call once during app
 * startup. If custom theme loading fails for any reason, the built-in themes
 * remain available.
 */
export async function initThemes(): Promise<void> {
  await loadCustomThemes();
}

// ---------------------------------------------------------------------------
// Theme access (synchronous — uses the last loaded registry)
// ---------------------------------------------------------------------------

function buildTheme(name: string): Theme {
  const def = themeRegistry[name] ?? themeRegistry['opta'] ?? BUILTIN_THEMES['opta']!;
  const colors = def.colors;

  return {
    name: themeRegistry[name] ? name : 'opta',
    description: def.description,
    colors,
    primary: chalk.hex(colors.primary),
    secondary: chalk.hex(colors.secondary),
    success: chalk.hex(colors.success),
    error: chalk.hex(colors.error),
    warning: chalk.hex(colors.warning),
    info: chalk.hex(colors.info),
    muted: chalk.hex(colors.muted),
    dim: chalk.dim,
  };
}

export function getTheme(): Theme {
  return buildTheme(currentThemeName);
}

export function setTheme(name: string): void {
  if (themeRegistry[name]) {
    currentThemeName = name;
  }
}

export function listThemes(): Array<{ name: string; description: string; custom?: boolean }> {
  return Object.entries(themeRegistry).map(([name, def]) => ({
    name,
    description: def.description,
    ...(BUILTIN_THEMES[name] ? {} : { custom: true }),
  }));
}

/**
 * Reset theme registry to built-in only and clear current selection.
 * Used for testing.
 */
export function resetThemes(): void {
  themeRegistry = { ...BUILTIN_THEMES };
  customThemesLoaded = false;
  currentThemeName = 'opta';
}

import chalk from 'chalk';
import { getTheme } from './theme.js';

const TOOL_ICONS: Record<string, string> = {
  read_file: '📄',
  write_file: '✏️',
  edit_file: '🔧',
  list_dir: '📁',
  search_files: '🔍',
  find_files: '🔎',
  run_command: '⚡',
  ask_user: '💬',
};

export function formatToolCall(name: string, args: Record<string, unknown>): string {
  const icon = TOOL_ICONS[name] || '🔧';
  const theme = getTheme();
  const parts: string[] = [];
  const toStr = (v: unknown, fallback = ''): string => {
    if (v === null || v === undefined) return fallback;
    if (typeof v === 'string') return v;
    if (typeof v === 'object') return JSON.stringify(v);
    return String(v as number | boolean | bigint);
  };

  parts.push(chalk.dim('  ┌─') + ` ${icon} ${theme.primary.bold(name)}`);

  switch (name) {
    case 'read_file':
      parts.push(chalk.dim('  │ ') + theme.info(toStr(args.path)));
      if (args.offset || args.limit) {
        parts.push(
          chalk.dim('  │ ') +
            chalk.dim(
              `lines ${toStr(args.offset, '1')}-${String(((args.offset as number) ?? 0) + ((args.limit as number) ?? 0))}`
            )
        );
      }
      break;

    case 'write_file': {
      const content = toStr(args.content);
      const lineCount = content.split('\n').length;
      parts.push(
        chalk.dim('  │ ') + theme.info(toStr(args.path)) + chalk.dim(` (${lineCount} lines)`)
      );
      break;
    }

    case 'edit_file':
      parts.push(chalk.dim('  │ ') + theme.info(toStr(args.path)));
      if (args.old_text && args.new_text) {
        const oldText = toStr(args.old_text);
        const newText = toStr(args.new_text);
        const oldLines = oldText.split('\n');
        const newLines = newText.split('\n');
        parts.push(
          chalk.dim('  │ ') +
            theme.error(`- ${oldLines.length} line${oldLines.length > 1 ? 's' : ''}`) +
            chalk.dim(' → ') +
            theme.success(`+ ${newLines.length} line${newLines.length > 1 ? 's' : ''}`)
        );
        // Show compact inline diff preview (max 6 lines)
        const previewLimit = 3;
        for (let li = 0; li < Math.min(oldLines.length, previewLimit); li++) {
          parts.push(chalk.dim('  │ ') + theme.error('- ' + oldLines[li]!.slice(0, 60)));
        }
        if (oldLines.length > previewLimit) {
          parts.push(chalk.dim('  │   ...'));
        }
        for (let li = 0; li < Math.min(newLines.length, previewLimit); li++) {
          parts.push(chalk.dim('  │ ') + theme.success('+ ' + newLines[li]!.slice(0, 60)));
        }
        if (newLines.length > previewLimit) {
          parts.push(chalk.dim('  │   ...'));
        }
      }
      break;

    case 'run_command':
      parts.push(chalk.dim('  │ ') + theme.warning(`$ ${toStr(args.command)}`));
      break;

    case 'search_files':
      parts.push(chalk.dim('  │ ') + theme.warning(`/${toStr(args.pattern)}/`));
      if (args.path) parts.push(chalk.dim('  │ ') + chalk.dim(`in ${toStr(args.path)}`));
      break;

    case 'list_dir':
      parts.push(chalk.dim('  │ ') + theme.info(toStr(args.path, '.')));
      break;

    case 'ask_user':
      parts.push(chalk.dim('  │ ') + chalk.italic(toStr(args.question).slice(0, 60)));
      break;

    default:
      for (const [k, v] of Object.entries(args)) {
        const val = toStr(v).slice(0, 50);
        parts.push(chalk.dim('  │ ') + chalk.dim(`${k}: `) + val);
      }
  }

  parts.push(chalk.dim('  └─'));
  return parts.join('\n');
}

export function formatToolResult(name: string, result: string, maxLen = 300): string {
  const trimmed =
    result.length > maxLen
      ? result.slice(0, maxLen) + chalk.dim(`... (${result.length} chars total)`)
      : result;

  if (name === 'run_command') {
    return (
      chalk.dim('  ') +
      trimmed
        .split('\n')
        .map((l) => chalk.dim('  │ ') + l)
        .join('\n')
    );
  }

  return (
    chalk.dim('  ') +
    trimmed
      .split('\n')
      .slice(0, 10)
      .map((l) => chalk.dim('  │ ') + l)
      .join('\n')
  );
}

import { access, statfs } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';

const BYTES_PER_MIB = 1024 * 1024;
const MAX_SAFE_BIGINT = BigInt(Number.MAX_SAFE_INTEGER);

export const DEFAULT_DISK_HEADROOM_MB = 64;

export interface DiskHeadroom {
  path: string;
  totalBytes: number;
  freeBytes: number;
  availableBytes: number;
}

export interface DiskHeadroomOptions {
  minFreeBytes?: number;
  minFreeMb?: number;
}

function toSafeNumber(value: bigint | number): number {
  if (typeof value === 'number') {
    if (!Number.isFinite(value)) return Number.MAX_SAFE_INTEGER;
    if (value < 0) return 0;
    return Math.min(value, Number.MAX_SAFE_INTEGER);
  }
  if (value <= 0n) return 0;
  if (value > MAX_SAFE_BIGINT) return Number.MAX_SAFE_INTEGER;
  return Number(value);
}

function multiplySafe(a: number, b: number): number {
  if (!Number.isFinite(a) || !Number.isFinite(b)) return Number.MAX_SAFE_INTEGER;
  const product = a * b;
  if (!Number.isFinite(product)) return Number.MAX_SAFE_INTEGER;
  if (product < 0) return 0;
  return Math.min(product, Number.MAX_SAFE_INTEGER);
}

async function resolveExistingPath(path: string): Promise<string> {
  let current = resolve(path);
  while (true) {
    try {
      await access(current);
      return current;
    } catch {
      const parent = dirname(current);
      if (parent === current) return current;
      current = parent;
    }
  }
}

export function diskHeadroomMbToBytes(minFreeMb?: number): number {
  if (typeof minFreeMb === 'number' && Number.isFinite(minFreeMb) && minFreeMb > 0) {
    return Math.floor(minFreeMb) * BYTES_PER_MIB;
  }
  return DEFAULT_DISK_HEADROOM_MB * BYTES_PER_MIB;
}

export function isStorageRelatedError(error: unknown): boolean {
  if (!error) return false;

  const code = typeof (error as { code?: unknown }).code === 'string'
    ? (error as { code: string }).code.toUpperCase()
    : '';
  if (code === 'ENOSPC' || code === 'EDQUOT') return true;

  const message = error instanceof Error ? error.message : typeof error === 'string' ? error : '';
  const lower = message.toLowerCase();
  return (
    lower.includes('no space left on device') ||
    lower.includes('disk full') ||
    lower.includes('quota exceeded') ||
    lower.includes('insufficient storage')
  );
}

export async function readDiskHeadroom(path: string): Promise<DiskHeadroom> {
  const existingPath = await resolveExistingPath(path);
  const fsStats = await statfs(existingPath, { bigint: true });
  const blockSize = toSafeNumber(fsStats.bsize);

  return {
    path: existingPath,
    totalBytes: multiplySafe(toSafeNumber(fsStats.blocks), blockSize),
    freeBytes: multiplySafe(toSafeNumber(fsStats.bfree), blockSize),
    availableBytes: multiplySafe(toSafeNumber(fsStats.bavail), blockSize),
  };
}

export async function ensureDiskHeadroom(
  path: string,
  options: DiskHeadroomOptions = {},
): Promise<DiskHeadroom> {
  const minFreeBytes = typeof options.minFreeBytes === 'number' && Number.isFinite(options.minFreeBytes)
    ? Math.max(0, Math.floor(options.minFreeBytes))
    : diskHeadroomMbToBytes(options.minFreeMb);
  const headroom = await readDiskHeadroom(path);

  if (headroom.availableBytes < minFreeBytes) {
    const err = new Error(
      `Disk headroom below required minimum at ${headroom.path}: ${headroom.availableBytes} B available, ${minFreeBytes} B required.`,
    ) as NodeJS.ErrnoException;
    err.code = 'ENOSPC';
    throw err;
  }

  return headroom;
}

